# Spinel v2 Codegen - Ruby subset AOT compiler backend
#
# Reads text AST from spinel_parse.rb, generates standalone C code.
# Written in Spinel-compilable Ruby subset.
#
# Usage: ruby spinel_codegen.rb ast.txt output.c
#
# All data structures use parallel arrays (no arrays of objects).
# Node fields stored as parallel arrays indexed by integer node ID.

require_relative "node_table_loader"
require_relative "compiler_helpers"

class Compiler
  attr_accessor :out

  def build_output
    result = ""
    i = 0
    while i < @out_lines.length
      line = @out_lines[i]
      if line == "/*TUPLE_INSERT_POINT*/"
        if @deferred_tuple != ""
          result << @deferred_tuple
        end
      elsif line == "/*LAMBDA_INSERT_POINT*/"
        if @deferred_lambda != ""
          result << @deferred_lambda
        end
      else
        result << line
        result << 10.chr
      end
      i = i + 1
    end
    result + ""
  end

  def initialize
    @out_lines = "".split(",", -1)
    @out = ""
    @deferred_tuple = ""
    @deferred_lambda = ""
    @meth_blk_param_types = nil
    @cls_cmeth_blk_param_types = nil
    @indent = 0
    @temp_counter = 0
    @label_counter = 0
 # `--int-overflow=promote` widens int slots to bigint AFTER
 # analyze.rb's annotate_all_node_types fills the per-node type
 # cache. infer_type below uses this to override the now-stale
 # cache for arithmetic on a bigint recv. In raise / wrap modes
 # the cache is up-to-date and the override stays off.
    @int_overflow_mode = ENV["SPINEL_INT_OVERFLOW"] || "raise"

 # ---- AST node storage (parallel arrays by node ID) ----
 # Use "".split(",", -1) for StrArray init (v1 infers StrArray from split)
    @nd_type = "".split(",", -1)
    @nd_name = "".split(",", -1)
    @nd_value = []
    @nd_content = "".split(",", -1)
    @nd_flags = []
    @nd_operator = "".split(",", -1)
    @nd_binop = "".split(",", -1)
    @nd_callop = "".split(",", -1)
    @nd_unescaped = "".split(",", -1)

 # Node references (integer node IDs, -1 = nil)
    @nd_receiver = []
    @nd_arguments = []
    @nd_body = []
    @nd_block = []
    @nd_parameters = []
    @nd_predicate = []
    @nd_subsequent = []
    @nd_else_clause = []
    @nd_left = []
    @nd_right = []
    @nd_constant_path = []
    @nd_superclass = []
    @nd_rest = []
 # ParametersNode#keyword_rest -- holds a KeywordRestParameterNode
 # (def f(**kw)) or NoKeywordsParameterNode (def f(**nil)).
    @nd_keyword_rest = []
    @nd_rescue_clause = []
    @nd_ensure_clause = []
    @nd_expression = []
    @nd_target = []
    @nd_pattern = []
    @nd_key = []
    @nd_reference = []
    @nd_collection = []

 # Node array fields: stored as comma-separated ID strings
    @nd_stmts = "".split(",", -1)
    @nd_args = "".split(",", -1)
    @nd_requireds = "".split(",", -1)
    @nd_optionals = "".split(",", -1)
    @nd_keywords = "".split(",", -1)
    @nd_elements = "".split(",", -1)
    @nd_parts = "".split(",", -1)
    @nd_conditions = "".split(",", -1)
    @nd_exceptions = "".split(",", -1)
    @nd_targets = "".split(",", -1)
    @nd_rights = "".split(",", -1)
 # ParametersNode#posts -- required params after the splat
 # (def f(*r, x, y) → posts = [x, y]). Currently unused by codegen
 # (post-rest parameters aren't observed in test/), but the parser
 # emits the field so future tests get a proper AST.
    @nd_posts = "".split(",", -1)
 # AliasMethodNode / AliasGlobalVariableNode -- parallel ref slots
 # for the new and old names (SymbolNode for methods, GlobalVariableReadNode
 # for globals).
    @nd_new_name = []
    @nd_old_name = []
 # UndefNode -- comma-separated child ids for the SymbolNode names.
    @nd_names = "".split(",", -1)

 # Per-node inferred type, parallel to the other @nd_* arrays.
 # Empty string means "not yet annotated"; node_type falls back to
 # infer_type in that case (transparent during analysis). After
 # `freeze_analysis` runs, every reachable node gets a non-empty
 # entry so the codegen path becomes O(1) per node lookup instead
 # of recursively re-walking the subtree on every infer_type call.
    @nd_inferred_type = "".split(",", -1)
 # 1 once analysis has converged and freeze_analysis has filled
 # @nd_inferred_type. Switches infer_type to consult the cache
 # first; analysis iterations themselves keep recomputing because
 # cached values would otherwise pin to stale converging types.
    @analysis_frozen = 0

 # Per-scope local-decls cache populated from IR (SN/ST records).
 # Indexed by body nid; codegen reads pipe-joined name/type lists
 # to declare locals without re-running scan_locals.
    @nd_scope_names = "".split(",", -1)
    @nd_scope_types = "".split(",", -1)

    @nd_count = 0
    @root_id = 0

 # Issue: unresolved-call warnings deduped by "<mname>:<recv_type>"
 # so a hot call site that fails to resolve emits one warning, not N.
    @unresolved_call_warnings = "".split(",", -1)

 # ---- Top-level methods (parallel arrays) ----
    @meth_names = "".split(",", -1)
    @meth_param_names = "".split(",", -1)
    @meth_param_types = "".split(",", -1)
 # Per-param "deferred element" flag: "1" means at least one caller
 # passed an empty `[]` literal (or a local that itself was assigned
 # an empty literal). Used by the param body-push promotion pass
 # to decide whether the param's int_array can be safely
 # promoted to a concrete typed-array based on body usage.
    @meth_param_empty = "".split(",", -1)
    @meth_return_types = "".split(",", -1)
    @meth_body_ids = []
    @meth_has_defaults = "".split(",", -1)
    @meth_rest_index = []
    @meth_kwrest_index = []

 # ---- Classes (parallel arrays) ----
    @cls_names = "".split(",", -1)
    @cls_parents = "".split(",", -1)
 # parallel to @cls_names. Semicolon-
 # separated list of included module names per class. Populated
 # by spinel_analyze and shipped through the IR; codegen
 # resolves the names to module indices for ancestors / parents.
    @cls_includes = "".split(",", -1)
 # built-in class prefix. cls_ids
 # 0..20 are reserved for Ruby primitive classes / modules per
 # docs/CLASS-OBJECT.md (minus Method which the existing
 # register_builtin_classes pushes as a user-class entry).
 # Additional built-ins (exceptions, Encoding, etc.) follow that
 # primitive prefix. User @cls_names entries shift by
 # @builtin_class_count; modules shift after user classes. Lets
 # sp_class_for_poly
 # map primitive tags to the built-in cls_id so
 # `5.is_a?(Integer)` against a dynamic klass resolves via
 # the same sp_class_le path as user-class checks.
    @builtin_class_names    = ["BasicObject", "Object", "Kernel", "Comparable", "Enumerable",
                               "NilClass", "TrueClass", "FalseClass",
                               "Numeric", "Integer", "Float",
                               "String", "Symbol",
                               "Array", "Hash", "Range", "Time",
                               "Module", "Class", "Complex", "Proc",
 # Exception family — only relevant in value position (`raise C`,
 # `c = StandardError`, etc.). The sp_exc_class_le / sp_exc_parent_of
 # name-based hierarchy is the dispatch mechanism for rescue clauses;
 # these cls_ids just back the value-emit path so #637's
 # `takes_class(StandardError)` lands a real sp_Class struct.
                               "Exception", "StandardError",
                               "RuntimeError", "ArgumentError", "TypeError",
                               "IndexError", "KeyError",
                               "RangeError", "FloatDomainError",
                               "NameError", "NoMethodError",
                               "ZeroDivisionError",
                               "IOError", "EOFError",
                               "FrozenError",
                               "ScriptError", "NotImplementedError", "LoadError", "SyntaxError",
                               "StopIteration", "RegexpError",
                               "EncodingError", "SystemCallError",
                               "LocalJumpError", "FiberError",
                               "Encoding"]
 # -1 = no parent (root). Module entries (Kernel, Comparable,
 # Enumerable) intentionally have -1 since modules don't
 # have superclasses.
    @builtin_class_parents  = [-1, 0, -1, -1, -1,
                                1, 1, 1,
                                1, 8, 8,
                                1, 1,
                                1, 1, 1, 1,
                                1, 17, 8, 1,
                                1, 21,
                                22, 22, 22,
                                22, 26,
                                22, 28,
                                22, 30,
                                22,
                                22, 33,
                                23,
                                21, 36, 36, 36,
                                26, 22,
                                22, 22,
                                22, 22,
                                1]
 # Semicolon-separated module-name includes per built-in class.
    @builtin_class_includes = ["", "Kernel", "", "", "",
                               "", "", "",
                               "Comparable", "", "",
                               "Comparable", "Comparable",
                               "Enumerable", "Enumerable", "Enumerable", "Comparable",
                               "", "", "", "",
                               "", "",
                               "", "", "",
                               "", "",
                               "", "",
                               "", "",
                               "",
                               "", "",
                               "",
                               "", "", "", "",
                               "", "",
                               "", "",
                               "", "",
                               ""]
    @builtin_class_count = @builtin_class_names.length
 # emit-time toggle for the per-program
 # sp_class_names[] table + sp_class_to_s helper. compile_expr's
 # ConstantReadNode arm and any class.to_s lowering set this to 1
 # before generate_code finalizes -- when no Class-as-value site
 # ever fires, we elide the table to keep the small-program emit
 # tight.
    @needs_class_table = 0
 # parents / ancestors tables are emitted
 # only when something reaches for them (.superclass, .ancestors,
 # `<` / `<=`, dynamic is_a?, case-when on Class). The base
 # @needs_class_table covers the names table; these extend it.
    @needs_class_parents = 0
    @needs_class_ancestors = 0
 # Set when `rescue ExplicitClass` or `e.is_a?(C)` (where e was
 # bound by a rescue) needs to walk a class-name parent chain at
 # runtime. Gates sp_exc_parent_of + sp_exc_class_le emission.
 # Issue #627.
    @needs_exc_class_hierarchy = 0
    @cls_ivar_names = "".split(",", -1)
    @cls_ivar_types = "".split(",", -1)
 # Per-ivar flag: was the ivar's first scanned write a definite
 # literal (IntegerNode / FloatNode / StringNode / ...)? Used to
 # distinguish concrete-literal writes from best-guess inference
 # so type unification only widens to poly when both writes are
 # definite — non-recognized CallNodes default to "int" through
 # infer_ivar_init_type and a naive trust of that produces
 # spurious disagreement.
    @cls_ivar_init_definite = "".split(",", -1)
 # Per-(class, ivar) accumulator of distinct concrete writer
 # types observed by scan_writer_calls. After all writer-scan
 # iterations finish, slots with 2+ distinct entries widen to
 # poly. Observations are recorded with the scope active inside
 # scan_writer_calls (params declared with their iteratively-
 # widened ptypes), so e.g. `value` in `def write_any(value);
 # @id = value` resolves to its caller-pinned type rather than
 # the placeholder "int" outside that scope. Each entry is a
 # comma-separated list of distinct types per ivar; the outer
 # dimension is semicolon-separated and parallel to
 # `@cls_ivar_names[ci]`.
    @cls_ivar_observed_types = "".split(",", -1)
 # Memoization for `find_lv_ivar_alias_in_ast`. Keyed by
 # `"<class_idx>:<lv_name>"`, value is the resolved ivar name (or
 # `""` when the LV has multiple sources / non-ivar writes).
    @lv_alias_cache = {}
 # Top-level (script-scope) ivars. Lowered to `static` file-scope
 # globals because `main()` / top-level `def` bodies have no `self`.
    @toplevel_ivar_names = "".split(",", -1)
    @toplevel_ivar_types = "".split(",", -1)
    @cls_meth_names = "".split(",", -1)
    @cls_meth_params = "".split(",", -1)
    @cls_meth_ptypes = "".split(",", -1)
    @cls_meth_returns = "".split(",", -1)
    @cls_meth_bodies = "".split(",", -1)
    @cls_meth_defaults = "".split(",", -1)
 # Mirror of @meth_param_empty for class methods. Pipe-separated by
 # method, comma-separated by param. .
    @cls_meth_ptypes_empty = "".split(",", -1)
 # Prepend chain (issue #720): per-class mapping from a Ruby
 # method name to the ordered list of synthetic shadow names
 # registered by analyze. compile_super_expr consults this to
 # redirect super calls inside prepended methods to the next
 # shadow in the chain. See spinel_analyze.rb prep_snapshot_active.
    @cls_meth_prep_chain = "".split(",", -1)
    @cls_attr_readers = "".split(",", -1)
    @cls_attr_writers = "".split(",", -1)
    @cls_cmeth_names = "".split(",", -1)
    @cls_cmeth_params = "".split(",", -1)
    @cls_cmeth_ptypes = "".split(",", -1)
    @cls_cmeth_returns = "".split(",", -1)
    @cls_cmeth_bodies = "".split(",", -1)
    @cls_cmeth_defaults = "".split(",", -1)
    @cls_cmeth_scope_names = "".split(",", -1)
    @cls_cmeth_scope_types = "".split(",", -1)
    @cls_is_value_type = []
 # SRA (scalar replacement of aggregates) eligibility flag per class.
 # Classes marked here can have their non-escaping instances replaced
 # with individual scalar locals. Distinct from value_type: SRA allows
 # attr_writer (mutation is rewritten to per-field assignment).
    @cls_is_sra = []

 # ---- Constants (parallel arrays) ----
    @const_names = "".split(",", -1)
    @const_types = "".split(",", -1)

 # ---- Class variables (@@var) ----
 # Per-(class,name) parallel arrays. Storage is a per-class C global
 # named `cvar_<ClassName>_<var>` (var without the @@ prefix).
 # Spinel's class-var lookup does NOT walk the inheritance chain --
 # each class's @@var is independent. CRuby's hierarchy-shared cvars
 # are a known footgun (mame, ko1, et al. publicly disrecommend
 # them); the simpler per-class semantics fit Spinel's compile-time
 # storage model better. Documented in the test fixtures.
    @cvar_names = "".split(",", -1)
    @cvar_types = "".split(",", -1)
 # Compile-time literal initializer per cvar, if the class-body
 # write was `@@x = <literal>`. "" means "use type-default". This
 # is necessary because Spinel doesn't run class-body statements
 # at startup, so any initializer that's not a fold-able literal
 # leaves the cvar at its type-default until first write.
    @cvar_init_values = "".split(",", -1)
    @const_expr_ids = []
    @const_scope_names = "".split(",", -1)
 # See spinel_analyze.rb's @const_init_class for the schema.
 # Issue #646.
    @const_init_class = "".split(",", -1)

 # `redo` -- labeled-goto target stack. Each loop emitter pushes
 # a fresh label name when entering an iteration body and pops on
 # exit; a `redo` jumps to the top of the innermost label.
    @redo_label_stack = "".split(",", -1)
    @redo_label_counter = 0

 # `alias $copy $orig` -- maps new gvar name to its target.
 # Populated by collect_all from AliasGlobalVariableNode
 # statements; consulted by sanitize_gvar / scan_features /
 # infer_type so $copy and $orig share storage.
    @galias_new = "".split(",", -1)
    @galias_old = "".split(",", -1)

 # `undef foo` -- per-(class, method-name) registry of removed
 # methods. Recorded by collect_class_method_undef; compile-time
 # enforcement of "call after undef fails" is currently a
 # documented out-of-scope.
    @undef_class_idx = []
    @undef_method = "".split(",", -1)

 # `BEGIN { ... }` bodies, in source-encounter order. Hoisted to
 # the top of main() during emit_main.
    @pre_execution_blocks = []

 # `END { ... }` bodies, in source-encounter order. Each emits a
 # static C function; main() startup registers them via atexit()
 # which naturally invokes handlers LIFO -- matches CRuby's
 # reverse-of-source-order END execution.
    @post_execution_blocks = []

 # ---- Scope stack for local variables ----
    @scope_names = "".split(",", -1)
    @scope_types = "".split(",", -1)
 # Parallel to `@scope_names`: when a local was assigned directly
 # from an ivar read (`lv = @ivar`), record the ivar name here so
 # later sites that need ivar-side metadata (notably the
 # `<poly>[k]` narrowing in `compile_poly_method_call`) can
 # resolve through the alias. Empty string when the local has no
 # such alias (or had a non-ivar write since).
    @scope_ivar_alias = "".split(",", -1)

 # Type-narrow stack for `is_a?`/`kind_of?` guards. While walking
 # the then-arm of `if v.is_a?(Hash)` or the truthy branch of
 # `v.is_a?(Hash) ? a : b`, the narrowed `(var_name,
 # narrowed_type)` is pushed here; find_var_type's top-down
 # lookup picks it up so infer_type / scan / codegen see the
 # narrowed type without per-pass plumbing.
    @type_narrow_names = "".split(",", -1)
    @type_narrow_types = "".split(",", -1)
    @in_narrow_recompute = 0

    @current_class_idx = -1
    @current_method_name = ""
    @current_lexical_scope = ""
    @current_method_return = ""
    @current_method_block_param = ""
 # 1 when the wrapping C function being emitted has a `self`
 # binding (instance method, constructor synthesis). 0 for
 # class methods, module class methods, and top-level free
 # functions. Drives the bare-return-with-obj_<C>-return shape
 # in compile_return_stmt: only when has_self == 1 does a bare
 # `return` whose function returns obj_<C> lower to `return
 # self;`; otherwise it emits the type's default value.
    @current_method_has_self = 0
    @in_main = 0
    @in_loop = 0
    @hoisted_strlen_var = ""
    @hoisted_strlen_recv = ""
    @in_yield_method = 0
    @current_method_yield_arity = 1
 # Per-method `_block` C-signature projection (joined by "|").
 # Populated when entering a yield-using method emit so
 # compile_yield_stmt can coerce literal IntegerNode args to the
 # widened sp_Bigint * slot under promote-mode methods. "" means
 # no projection / mrb_int default.
    @current_method_blk_param_types = ""
    @in_gc_scope = 0
 # Set during the arity-0 instance_eval trampoline inlining so
 # receiverless calls in the spliced block body dispatch against
 # the rebound self (the .instance_eval receiver) instead of the
 # enclosing method's self.
    @instance_eval_self_var = ""
    @instance_eval_self_type = ""

 # During default-arg substitution, when the callee's default
 # expression is inlined into the caller, `self_arrow` consults
 # this override to route `self->iv_X` against the call's
 # explicit receiver instead of the caller's self.
    @self_override = ""

 # Yield/block tracking (parallel with meth_names / cls_meth_names)
    @meth_has_yield = []
    @cls_meth_has_yield = "".split(",", -1)

 # Block function accumulator (emitted before forward decls)
    @block_funcs = ""
    @block_counter = 0

 # Feature flags
    @needs_gc = 0
    @needs_system = 0
    @needs_int_array = 0
    @needs_float_array = 0
    @tuple_types = "".split(",", -1)
    @needs_str_array = 0
    @needs_str_int_hash = 0
    @needs_str_str_hash = 0
    @needs_int_str_hash = 0
    @needs_sym_int_hash = 0
    @needs_sym_str_hash = 0
    @needs_sym_intern = 0
    @needs_setjmp = 0
 # Stack of (class_var, msg_var) pairs naming the snapshot locals
 # emitted at the top of each rescue body. A bare `raise` inside a
 # rescue body re-raises with the snapshotted class+message rather
 # than fabricating a fresh RuntimeError. Empty outside any rescue.
    @rescue_cls_stack = "".split(",", -1)
    @rescue_msg_stack = "".split(",", -1)
    @rescue_depth = 0
 # Stack of ensure-clause node IDs (encoded as strings) currently in
 # scope. Each entry corresponds to an enclosing `begin..ensure..end`
 # whose body is being compiled. When `return` is emitted from inside
 # the body, each ensure body is replayed (innermost-first) before
 # the C `return`, so writebacks in `ensure` execute on early return.
    @ensure_stack = "".split(",", -1)
 # Number of `sp_exc_top++` pushes emitted along the static
 # fall-through path leading to the current emit point but not
 # yet matched by an emitted `sp_exc_top--`. An early `return`
 # emits `sp_exc_top -= N` to balance them, so the caller doesn't
 # longjmp into our stale stack frame after we've returned.
    @setjmp_depth = 0
 # Counter used to mint unique snapshot variable names
 # (`_ensure_cls_<n>`, `_ensure_msg_<n>`) for re-raising the
 # in-flight exception after an ensure body runs on the
 # exception path of a `begin..ensure..end`.
    @ensure_emit_depth = 0
    @needs_mutable_str = 0
    @needs_rb_value = 0
    @needs_regexp = 0
    @needs_rand = 0
 # sp_argv is declared in lib/sp_runtime.h as a static global,
 # zero-initialized in BSS. main() only needs to malloc + dup
 # the argv strings when user code actually reaches for ARGV;
 # otherwise the GC mark loop (sp_runtime.h, sp_mark_externals)
 # sees len=0 and skips, and the cost is zero. Flag is flipped
 # by the ARGV ConstantReadNode arm and the ARGV.length /
 # ARGV[i] dispatch sites.
    @needs_argv = 0
 # The Method class (registered by spinel_analyze's
 # register_builtin_classes) backs the `method(:sym)` /
 # `obj.method(:sym)` -> Method instance shape, plus the
 # poly_poly_hash eql? hook. When user code uses none of
 # those, the per-program emit (typedef sp_Method, struct,
 # sp_Method_gc_scan, sp_Method_new, sp_Method_initialize)
 # is DCE'd by -O3 but still costs compile time on every
 # build. Flip this when an actual usage site fires; emit
 # the Method struct + helpers only when it's set.
    @needs_method = 0
 # sp_sym_array_sort + sp_sym_sort_cmp are emitted inside the
 # @sym_names guard in emit_sym_runtime; a program that uses
 # any symbol gets the sort helpers even when nothing calls
 # `<sym_array>.sort`. Pre-scan flips this when a `.sort` /
 # `.sort!` CallNode appears so the helpers stay out of
 # programs that don't sort.
    @needs_sym_sort = 0
    @regexp_patterns = "".split(",", -1)
    @regexp_flags = "".split(",", -1)
 # Dynamic-regex (InterpolatedRegularExpressionNode) call-site cache.
 # Each AST node gets a unique idx so the emitter can produce one
 # `sp_re_dyn_<idx>` helper per source location with its own
 # function-scope cache (string key + compiled pattern). Collected
 # in scan_features so indexes are stable across compile_expr visits.
    @dyn_regex_node_ids = []
    @dyn_regex_flags = "".split(",", -1)
 # `var = /lit/` resolution. Parallel arrays: `@local_regex_names`
 # holds the local-variable name; `@local_regex_idx` holds the
 # corresponding `@regexp_patterns` index (-1 when ambig or dyn);
 # `@local_regex_call_nids` holds a single-write `Regexp.new(<dyn>)`
 # CallNode id (-1 otherwise) so regex_pat_c_expr can emit the
 # dyn-cache call from a read site.
    @local_regex_names = "".split(",", -1)
    @local_regex_idx = []
    @local_regex_call_nids = []

 # Cache for parse_id_list: AST list fields never change once loaded,
 # so the parsed IntArray can be shared across callers. The `[[0]]`
 # literal teaches Spinel that @parse_id_pool is ptr_array<int_array>;
 # slot 0 is a reserved dummy. PtrArray now scans its elements, so
 # cached IntArrays stay reachable.
    @parse_id_cache = {}
    @parse_id_pool = [[0]]

    @needs_stringio = 0
    @proc_counter = 0
    @proc_funcs = ""

 # Lambda support
    @needs_lambda = 0
    @lambda_counter = 0
    @lambda_funcs = ""
    @lambda_params = "".split(",", -1)
    @lambda_captures = "".split(",", -1)
    @lambda_capture_cell_types = "".split(",", -1)
    @lambda_var_ret_names = "".split(",", -1)
    @lambda_var_ret_types = "".split(",", -1)
    @last_lambda_ret_type = ""
 # `Klass.method(:cls_meth)` generates an adapter trampoline so the
 # Method object's `(void *self, mrb_int...)` ABI fits a class
 # method's no-self C signature. Tracks emitted (Klass, method)
 # pairs to avoid duplicate definitions.
    @cls_method_adapters = "".split(",", -1)

 # Snapshot slot/expr pair for the kwargs-as-bundle path in
 # compile_typed_call_args.
    @typed_call_bundle_slot = -1
    @typed_call_bundle_expr = ""

 # Proc closure support (Phase 2)
    @in_proc_body = 0
    @proc_captures = "".split(",", -1)
    @proc_capture_types = "".split(",", -1)

 # Fiber support
    @needs_fiber = 0
    @needs_bigint = 0
    @fiber_counter = 0
    @fiber_funcs = ""
    @in_fiber_body = 0
    @fiber_captures = "".split(",", -1)
    @fiber_capture_types = "".split(",", -1)
    @heap_promoted_names = "".split(",", -1)
    @heap_promoted_cells = "".split(",", -1)

 # Global variables ($x)
    @gvar_names = "".split(",", -1)
    @gvar_types = "".split(",", -1)

 # Poly tracking: functions with params called with different types
    @poly_funcs = "".split(",", -1)
    @poly_param_types = "".split(",", -1)

 # Method reference tracking: var_name -> method_name
    @method_ref_vars = "".split(",", -1)
    @method_ref_names = "".split(",", -1)

 # Open class tracking for built-in types
    @open_class_names = "".split(",", -1)

 # Module tracking: module_name -> body node id
    @module_names = "".split(",", -1)
    @module_includes = "".split(",", -1)
    @module_body_ids = []
 # Module-level singleton accessors :
 # `class << self; attr_accessor :foo; end` inside `module M`.
 # `@module_acc_consts[i]` is a `;`-separated list of distinct
 # constant names assigned to this slot (Stage 1: single name →
 # inline; Stage 2: multiple names → runtime sentinel switch).
 # Empty string means at least one write was non-constant — the
 # slot falls through to the un-folded path.
    @module_acc_keys = "".split(",", -1)
    @module_acc_consts = "".split(",", -1)

 # ---- FFI state (parallel arrays, populated by scan_ffi_decl) ----
 # Per-module registry:
    @ffi_modules = "".split(",", -1)          # module names that declared FFI
    @ffi_module_libs = "".split(",", -1)      # ";"-joined -l names
    @ffi_module_cflags = "".split(",", -1)    # ";"-joined cc flag strings
 # Function registry (one entry per ffi_func decl):
    @ffi_func_modules = "".split(",", -1)     # owning module name
    @ffi_func_names = "".split(",", -1)       # C symbol name
    @ffi_func_arg_types = "".split(",", -1)   # ";"-joined Spinel type tokens
    @ffi_func_ret_types = "".split(",", -1)   # single Spinel type token
    @ffi_func_arg_specs = "".split(",", -1)   # ";"-joined original specs (uint32, str, …)
    @ffi_func_ret_specs = "".split(",", -1)   # original return spec
 # Buffer registry (one entry per ffi_buffer decl):
    @ffi_buf_modules = "".split(",", -1)
    @ffi_buf_names = "".split(",", -1)
    @ffi_buf_sizes = []                   # int sizes in bytes
 # Reader registry (one entry per ffi_read_* decl):
    @ffi_reader_modules = "".split(",", -1)
    @ffi_reader_names = "".split(",", -1)
    @ffi_reader_kinds = "".split(",", -1)     # "u32", "i32", "ptr"
    @ffi_reader_offsets = []              # int byte offsets

    @pending_method_ref = ""
    @lambda_counter = 0
    @lambda_funcs = ""
    @lambda_params = "".split(",", -1)
    @lambda_captures = "".split(",", -1)
    @lambda_insert_pos = 0
    @cls_method_adapters = "".split(",", -1)

 # Snapshot slot/expr pair for the kwargs-as-bundle path in
 # compile_typed_call_args. Set per-invocation; copied into
 # locals before the slot-fill loop so nested re-entries don't
 # clobber the outer pending bundle.
    @typed_call_bundle_slot = -1
    @typed_call_bundle_expr = ""

 # Proc closure support (Phase 2)
    @in_proc_body = 0
    @proc_captures = "".split(",", -1)
    @proc_capture_types = "".split(",", -1)

 # Inline-rename map for compile_yield_method_call_stmt / _expr.
    @inline_rename_map_from = nil
    @inline_rename_map_to = nil

 # When inlining a yield-using method body in expression context,
 # any YieldNode encountered as a sub-expression (e.g. `arr.push(yield)`,
 # `yield * 2`) needs to materialize the block body's last value into
 # a temp. These fields carry the necessary block context through
 # compile_expr_remap. `_blk` is -1 when not inlining.
    @inline_yield_blk = -1
    @inline_yield_bp_names = nil

 # Symbol type Phase 2 Step 1: intern table (infrastructure only; unused yet).
    @sym_names = "".split(",", -1)

 # instance_eval block hoisting: parallel arrays indexed by synthetic
 # function id N. Each lifted block becomes a file-scope static
 # function `sp_ieval_<N>` that takes a typed `self` parameter.
 # @ieval_return_types is the inferred ctype of the lifted body's last
 # expression ("void" when assignment-only); read by
 # compile_ieval_call_expr to pick direct-call vs receiver-comma-expr
 # and by emit_ieval_func to size the function signature.
    @ieval_counter = 0
    @ieval_class_idxs = []
    @ieval_body_ids = []
    @ieval_return_types = "".split(",", -1)
 # Self-bound param per lift; emit_ieval_func seeds `lv_<name> = self;`.
    @ieval_self_param_names = "".split(",", -1)
 # Extras already land in @nd_scope_names as nil-typed locals via
 # analyze's precompute_all_scope_decls.
    @ieval_extra_param_names = "".split(",", -1)
  end

 # Backslash-n for C string literals - bootstrap-safe (avoids escape level issues)
  def bsl_n
    92.chr + "n"
  end

 # Backslash for C char literals - bootstrap-safe
  def bsl
    92.chr
  end

  def new_temp
    @temp_counter = @temp_counter + 1
    "_t" + @temp_counter.to_s
  end

  def get_body_stmts(nid)
    body = @nd_body[nid]
    if body < 0
      return []
    end
    get_stmts(body)
  end

  def get_args(nid)
 # nid is an ArgumentsNode
    if nid < 0
      return []
    end
    if @nd_type[nid] == "ArgumentsNode"
      return parse_id_list(@nd_args[nid])
    end
    result = []
    result.push(nid)
    result
  end

 # Returns 1 if @nd_block[nid] is a literal BlockNode (do/end body),
 # 0 otherwise. Pairs with find_block_arg to dispatch correctly at
 # &block-forwarding call sites (literal block vs. `&proc_var`).
  def has_literal_block(nid)
    blk = @nd_block[nid]
    (blk >= 0 && @nd_type[blk] == "BlockNode") ? 1 : 0
  end

 # Returns the inner expression of a BlockArgumentNode whose payload
 # is a captured proc local (the `&block` form). Returns -1 for
 # absent block-arg, or for shapes the codegen doesn't yet forward
 # — `&:sym` (SymbolNode) and `&nil` (NilNode), which would need
 # symbol-to-proc / nil-as-no-block lowering. Call sites fall
 # through to the no-block path in those cases.
  def find_block_arg(nid)
    blk = @nd_block[nid]
    if blk < 0
      return -1
    end
    if @nd_type[blk] != "BlockArgumentNode"
      return -1
    end
    inner = @nd_expression[blk]
    if inner < 0
      return -1
    end
    if @nd_type[inner] != "LocalVariableReadNode"
      return -1
    end
    inner
  end

 # Resolves the call-site block-forwarding expression: returns the C
 # expression for the proc to forward at a `&block`-taking call site
 # (a literal block compiles to sp_proc_new(...); a `&proc_var` is
 # the captured `sp_Proc *` local), or "" if the call site provides
 # no block.
  def block_forward_expr(nid, blk_param_types = "")
    if has_literal_block(nid) == 1
      return compile_proc_literal(nid, blk_param_types)
    end
 # Anonymous `&` forwarding (Ruby 3.1+): `inner(&)` where the
 # enclosing method declared `def outer(&)`. The BlockArgumentNode
 # carries no expression, so `find_block_arg` returns -1; we forward
 # the enclosing method's anon-block param directly.
    blk = @nd_block[nid]
    if blk >= 0 && @nd_type[blk] == "BlockArgumentNode" && @nd_expression[blk] < 0
      if @current_method_block_param != ""
        return "lv_" + @current_method_block_param
      end
    end
    ba = find_block_arg(nid)
    if ba >= 0
      return compile_expr(ba)
    end
    ""
  end

 # Returns the body node id for class ci's midx'th method, or -1
 # if midx is out of range or the body id is invalid. Centralises
 # the @cls_meth_bodies[ci].split(";", -1)[midx].to_i parse so detectors
 # don't have to inline it.
  def cls_method_body_id(ci, midx)
    bodies = @cls_meth_bodies[ci].split(";", -1)
    if midx >= bodies.length
      return -1
    end
    bid = bodies[midx].to_i
    if bid < 0
      return -1
    end
    bid
  end

 # Returns the name of the class method's single proc-typed param
 # (its `&block` slot), or "" if the signature isn't exactly one
 # proc param. Used by detectors that match the
 # `def m(&b); ...; end` shape (instance_eval trampoline today;
 # extensible to instance_exec, tap, etc.).
  def cls_method_sole_proc_param_name(ci, midx)
    pnames = cls_meth_pnames_get(ci, midx)
    ptypes = cls_meth_ptypes_get(ci, midx)
    if pnames.length != 1 || ptypes.length != 1
      return ""
    end
    if ptypes[0] != "proc"
      return ""
    end
    pnames[0]
  end

 # Detects the exact arity-0 instance_eval trampoline shape:
 # `def m(&b); instance_eval(&b); end`. Returns 1 when the
 # (ci, midx) method body is a single CallNode of `instance_eval`
 # forwarded the method's sole proc-typed param via &-arg, 0
 # otherwise. Spinel inlines these at the call site (yield-style)
 # with self rebound to the receiver — full Ruby instance_eval is
 # dynamic, but this AOT compromise covers the common DSL-trampoline
 # shape. Anything wider falls through to today's silent no-op.
  def is_instance_eval_trampoline(ci, midx)
 # AST shape gates first (no string splits — cheap reject path).
    bid = cls_method_body_id(ci, midx)
    if bid < 0
      return 0
    end
    stmts = get_stmts(bid)
    if stmts.length != 1
      return 0
    end
    s = stmts[0]
    if @nd_type[s] != "CallNode"
      return 0
    end
    if @nd_name[s] != "instance_eval"
      return 0
    end
    if @nd_receiver[s] >= 0
      return 0
    end
    inner = find_block_arg(s)
    if inner < 0
      return 0
    end
    if @nd_type[inner] != "LocalVariableReadNode"
      return 0
    end
 # Param signature gate (does the string splits) — only methods
 # that pass the AST shape get here.
    pname = cls_method_sole_proc_param_name(ci, midx)
    if pname == ""
      return 0
    end
    if @nd_name[inner] != pname
      return 0
    end
    1
  end

 # Flatten a constant reference into an internal name.
 # C -> C
 # ::C -> C
 # M::C -> M_C
 # A::B::C -> A_B_C


  def constructor_class_name(recv_nid)
    if recv_nid < 0
      return ""
    end
    rt = @nd_type[recv_nid]
    if rt == "ConstantReadNode" || rt == "ConstantPathNode"
      return resolve_const_ref_name(recv_nid)
    end
    ""
  end

  def module_name_exists(name)
    i = 0
    while i < @module_names.length
      if @module_names[i] == name
        return 1
      end
      i = i + 1
    end
    0
  end

  def const_namespace_exists(name)
    if name == ""
      return 0
    end
    if find_const_idx(name) >= 0
      return 1
    end
    if find_class_idx(name) >= 0
      return 1
    end
    if module_name_exists(name) == 1
      return 1
    end
    0
  end

 # Constant names the codegen recognises as legitimate even when no
 # user-defined class / module / constant of the same name exists.
 # These are dispatcher-handled module-like receivers (Math, File,
 # ENV, Dir, Time, Process, IO), the global ARGV, the built-in type
 # names used in `is_a?` / `case`/`when` arms, and a handful of
 # exception classes referenced by `raise` / `rescue` patterns.
  def is_known_constant_name(name)
    if const_namespace_exists(name) == 1
      return 1
    end
    if name == "ARGV" || name == "ENV" || name == "STDIN" || name == "STDOUT" || name == "STDERR"
      return 1
    end
    if name == "Math" || name == "File" || name == "Dir" || name == "Time" || name == "IO" || name == "Process" || name == "Kernel" || name == "Comparable" || name == "Enumerable" || name == "Complex"
      return 1
    end
    if name == "Object" || name == "Integer" || name == "String" || name == "Float" || name == "Symbol" || name == "Array" || name == "Hash" || name == "Range" || name == "Numeric" || name == "TrueClass" || name == "FalseClass" || name == "NilClass" || name == "Proc" || name == "Lambda" || name == "Regexp" || name == "MatchData" || name == "StringIO" || name == "Fiber" || name == "Encoding"
      return 1
    end
 # Common exception classes referenced by raise / rescue. We
 # don't model the exception hierarchy beyond name-tagging.
    if name == "StandardError" || name == "RuntimeError" || name == "ArgumentError" || name == "TypeError" || name == "NameError" || name == "NoMethodError" || name == "IndexError" || name == "KeyError" || name == "ZeroDivisionError" || name == "FloatDomainError" || name == "RangeError" || name == "IOError" || name == "Errno" || name == "NotImplementedError" || name == "StopIteration" || name == "RegexpError" || name == "FrozenError" || name == "LocalJumpError" || name == "Exception"
      return 1
    end
    0
  end

 # Mirror of spinel_analyze's is_builtin_exception_class_name -- gates
 # the compile_constructor_expr arm that lowers `CLS.new("msg")` to
 # sp_exc_new("CLS", msg).
  def is_builtin_exception_class_name(name)
    if name == "Exception" || name == "StandardError" || name == "RuntimeError"
      return 1
    end
    if name == "ArgumentError" || name == "TypeError" || name == "IndexError" || name == "KeyError"
      return 1
    end
    if name == "RangeError" || name == "FloatDomainError" || name == "NameError" || name == "NoMethodError"
      return 1
    end
    if name == "ZeroDivisionError" || name == "IOError" || name == "EOFError" || name == "FrozenError"
      return 1
    end
    if name == "NotImplementedError" || name == "StopIteration" || name == "RegexpError" || name == "LocalJumpError"
      return 1
    end
    if name == "ScriptError" || name == "LoadError" || name == "SyntaxError"
      return 1
    end
    if name == "EncodingError" || name == "SystemCallError" || name == "FiberError"
      return 1
    end
    0
  end

 # 1 if `name` is a user class that transitively inherits from a
 # built-in exception class. Mirrors spinel_analyze's helper.
  def is_user_exception_subclass(name)
    ci = find_class_idx(name)
    if ci < 0
      return 0
    end
    walk = ci
    while walk >= 0
      pname = ""
      if walk < @cls_parents.length
        pname = @cls_parents[walk]
      end
      if pname == ""
        return 0
      end
      if is_builtin_exception_class_name(pname) == 1
        return 1
      end
      walk = find_class_idx(pname)
    end
    0
  end

  def is_exception_class_name(name)
    if is_builtin_exception_class_name(name) == 1
      return 1
    end
    is_user_exception_subclass(name)
  end

 # Default message C expression for `<ExcClass>.new` with no args.
 # For user subclasses, scans the program AST for the matching
 # `class <ExcClass>` body and pulls out its `def initialize` first
 # OptionalParameterNode default (must be a string literal). Otherwise
 # falls back to the class-name string literal, matching CRuby's
 # `RuntimeError.new.message` convention.
  def exc_default_msg_expr(cname)
    def_id = find_initialize_def_for_class(0, cname)
    if def_id >= 0
      params_id = @nd_parameters[def_id]
      if params_id >= 0
        opts = parse_id_list(@nd_optionals[params_id])
        if opts.length > 0
 # OptionalParameterNode.value is stored in @nd_expression by the
 # AST loader (see compiler_helpers.rb's set_ref_field "value" arm).
          dv = @nd_expression[opts[0]]
          if dv >= 0 && @nd_type[dv] == "StringNode"
            return compile_expr(dv)
          end
        end
      end
    end
 # Fallback: class name (matches `RuntimeError.new.message`).
 # Convert C-mangled `Foo_Bar` into Ruby's `Foo::Bar` when the
 # prefix matches a registered module so namespaced exceptions
 # report the user-visible name. Underscores that don't bridge
 # a module boundary stay as-is (`My_Helper` etc.).
    "(&(\"\\xff\" \"" + cls_name_to_ruby(cname) + "\")[1])"
  end

 # Reverse the `_`-as-module-separator mangling applied by
 # collect_class_with_prefix. Walks the longest prefix that matches
 # a registered module (recursively, so a nested `Outer_Inner`
 # module-prefix unmangles further to `Outer::Inner`) and rejoins
 # the path with `::`. Underscores that don't bridge a module
 # boundary stay as-is (`My_Helper` etc.).
  def cls_name_to_ruby(cname)
    return cname unless cname.include?("_")
    parts = cname.split("_")
    best_len = 0
    try_len = parts.length - 1
    while try_len >= 1
      candidate = parts[0, try_len].join("_")
      if module_name_exists(candidate) == 1
        best_len = try_len
        try_len = 0
      else
        try_len = try_len - 1
      end
    end
    if best_len == 0
      return cname
    end
    prefix_ruby = cls_name_to_ruby(parts[0, best_len].join("_"))
    tail = parts[best_len, parts.length - best_len].join("_")
    prefix_ruby + "::" + tail
  end

 # Walk the AST from `nid` looking for a `class <cname> ... end`
 # whose body contains `def initialize`. Returns the DefNode id of
 # that initialize, or -1.
  def find_initialize_def_for_class(nid, cname)
    if nid < 0
      return -1
    end
    if @nd_type[nid] == "ClassNode"
      cpath = @nd_constant_path[nid]
      if cpath >= 0 && @nd_type[cpath] == "ConstantReadNode" && @nd_name[cpath] == cname
        body = @nd_body[nid]
        if body >= 0
          return find_initialize_def_in_body(body)
        end
      end
    end
    cs = []
    push_child_ids(nid, cs)
    k = 0
    while k < cs.length
      r = find_initialize_def_for_class(cs[k], cname)
      if r >= 0
        return r
      end
      k = k + 1
    end
    -1
  end

 # Walk the given class-body subtree looking for the first
 # `def initialize` DefNode. Returns -1 if not found.
  def find_initialize_def_in_body(nid)
    if nid < 0
      return -1
    end
    if @nd_type[nid] == "DefNode" && @nd_name[nid] == "initialize"
      return nid
    end
    cs = []
    push_child_ids(nid, cs)
    k = 0
    while k < cs.length
      r = find_initialize_def_in_body(cs[k])
      if r >= 0
        return r
      end
      k = k + 1
    end
    -1
  end

  def current_lexical_scope_name
    if @current_lexical_scope != ""
      return @current_lexical_scope
    end
    if @current_class_idx >= 0
      if @current_class_idx < @cls_names.length
        return @cls_names[@current_class_idx]
      end
      return ""
    end
    if @current_method_name != ""
      cls_idx = @current_method_name.index("_cls_")
 # CRuby returns nil when not found; spinel runtime returns -1.
      if cls_idx != nil && cls_idx >= 0
        return @current_method_name[0, cls_idx]
      end
    end
    ""
  end

  def trim_const_scope_once(name)
    if name == ""
      return ""
    end
    idx = name.rindex("_")
 # CRuby returns nil when not found; spinel runtime returns -1.
 # Treat both as "no underscore — root scope".
    if idx == nil || idx < 0
      return ""
    end
    name[0, idx]
  end

  def resolve_const_read_name(name)
    scope = current_lexical_scope_name
    while scope != ""
      cand = scope + "_" + name
      if const_namespace_exists(cand) == 1
        return cand
      end
      scope = trim_const_scope_once(scope)
    end
 # If the enclosing class includes any modules, look up the const in
 # the module's namespace. CRuby's lexical-scope chain walks Object →
 # ancestors → included modules; spinel's @cls_meth_* table doesn't
 # retain the method's original module of definition, so a `CONST`
 # reference from a method that was attached via `include` falls
 # through the lexical chain above. Walk the including class's
 # `@cls_includes` transitively so `B include A; A include X; method
 # body in B references bare N -> X::N` resolves even when the
 # directly-listed include doesn't carry N.
    if @current_class_idx >= 0
      found_inc = resolve_const_via_include_chain(@current_class_idx, name)
      if found_inc != ""
        return found_inc
      end
      found_par = resolve_const_via_parent_chain(@current_class_idx, name)
      if found_par != ""
        return found_par
      end
    end
    name
  end

 # Walk @cls_parents (superclass chain) from `class_idx`, trying each
 # ancestor's namespace plus each ancestor's includes. Mirrors CRuby's
 # constant lookup which walks the class hierarchy after lexical scope.
 # Caps depth at 16 to bail on pathological chains.
  def resolve_const_via_parent_chain(class_idx, name, depth = 16)
    if depth <= 0
      return ""
    end
    if class_idx < 0 || class_idx >= @cls_parents.length
      return ""
    end
    pname = @cls_parents[class_idx]
    if pname == ""
      return ""
    end
    cand = pname + "_" + name
    if const_namespace_exists(cand) == 1
      return cand
    end
    pi = find_class_idx(pname)
    if pi >= 0
      sub_inc = resolve_const_via_include_chain(pi, name, depth - 1)
      if sub_inc != ""
        return sub_inc
      end
      return resolve_const_via_parent_chain(pi, name, depth - 1)
    end
    ""
  end

 # Recursively walk @cls_includes from `class_idx`, trying each
 # included module's namespace for a constant named `name`. Caps at
 # depth 16 so a pathological include cycle bails instead of looping.
 # Returns the qualified `<Mod>_<name>` form on a hit, or "" on miss.
  def resolve_const_via_include_chain(class_idx, name, depth = 16)
    if class_idx < 0 || class_idx >= @cls_includes.length
      return ""
    end
    resolve_const_via_include_list(@cls_includes[class_idx], name, depth)
  end

 # Shared walker: for each entry in `incs_str`, check the joined
 # `<Mod>_<name>` namespace, then recurse into that entry's own
 # include chain (class-or-module). Handles the `B include A;
 # A include X` -> X::N path without conflating the two parent
 # tables.
  def resolve_const_via_include_list(incs_str, name, depth)
    if depth <= 0
      return ""
    end
    if incs_str == ""
      return ""
    end
    incs = incs_str.split(";", -1)
    ii = 0
    while ii < incs.length
      inc = incs[ii]
      if inc != ""
        cand = inc + "_" + name
        if const_namespace_exists(cand) == 1
          return cand
        end
        inc_cls = find_class_idx(inc)
        if inc_cls >= 0
          sub = resolve_const_via_include_list(@cls_includes[inc_cls], name, depth - 1)
          if sub != ""
            return sub
          end
        end
        if module_name_exists(inc) == 1
          sub = resolve_const_via_module_chain(inc, name, depth - 1)
          if sub != ""
            return sub
          end
        end
      end
      ii = ii + 1
    end
    ""
  end

 # Walk every @module_names slot matching `mod_name` (a module can
 # re-open and each open is a separate row, so the includes recorded
 # on each have to be tried independently). Routes through
 # resolve_const_via_include_list so module-include and class-include
 # share the same lookup recursion.
  def resolve_const_via_module_chain(mod_name, name, depth)
    if depth <= 0
      return ""
    end
    mi = 0
    while mi < @module_names.length
      if @module_names[mi] == mod_name && mi < @module_includes.length
        sub = resolve_const_via_include_list(@module_includes[mi], name, depth - 1)
        if sub != ""
          return sub
        end
      end
      mi = mi + 1
    end
    ""
  end

  def resolve_const_ref_name(nid)
    if nid < 0
      return ""
    end
    t = @nd_type[nid]
    if t == "ConstantReadNode"
      return resolve_const_read_name(@nd_name[nid])
    end
    if t == "ConstantPathNode"
      leaf = @nd_name[nid]
      parent = @nd_receiver[nid]
      if parent < 0
        return leaf
      end
      base = resolve_const_ref_name(parent)
      if base == ""
        return ""
      end
      return base + "_" + leaf
    end
    ""
  end

 # ---- Scope management ----
  def push_scope
    @scope_names.push("---")
    @scope_types.push("---")
    @scope_ivar_alias.push("---")
    0
  end

  def pop_scope
    while @scope_names.length > 0
      top_name = @scope_names.last
      if top_name == "---"
        @scope_names.pop
        @scope_types.pop
        @scope_ivar_alias.pop
        return
      end
      @scope_names.pop
      @scope_types.pop
      @scope_ivar_alias.pop
    end
  end

  def declare_var(name, vtype)
    @scope_names.push(name)
    @scope_types.push(vtype)
    @scope_ivar_alias.push("")
    0
  end

 # Emit a 1-arg `raise <arg>` -- handle three shapes:
 #   raise ClassName                       -> sp_raise("ClassName")
 #   raise <BuiltinExc>.new("msg")         -> sp_raise_cls("ClsName", "msg")
 #   raise lv                              -> sp_raise_exc(lv) when lv is
 #                                            typed sp_Exception *
 #   raise "msg"                           -> sp_raise("msg")
 # Used by both the stmt-form and expr-form raise arms.
  def emit_raise_one_arg(arg_id)
    if @nd_type[arg_id] == "ConstantReadNode"
 # `raise ArgumentError` -- raise the named class with no message.
 # sp_raise(msg) hardcodes the class to RuntimeError, so passing
 # "ArgumentError" as `msg` raises a RuntimeError-with-message,
 # which `rescue ArgumentError` doesn't catch. Route through
 # sp_raise_cls(class, msg) so the class survives. Issue #704.
      cname_cr = @nd_name[arg_id]
      if is_exception_class_name(cname_cr) == 1
        @needs_exc_class_hierarchy = 1
        emit("  sp_raise_cls(\"" + cname_cr + "\", " + exc_default_msg_expr(cname_cr) + ");")
        return
      end
      emit("  sp_raise(\"" + cname_cr + "\");")
      return
    end
 # `raise <BuiltinExc>.new(<msg>)` -- ConstantReadNode is the exc
 # class, msg comes from the .new args.
    if @nd_type[arg_id] == "CallNode" && @nd_name[arg_id] == "new"
      r_inner = @nd_receiver[arg_id]
      if r_inner >= 0 && @nd_type[r_inner] == "ConstantReadNode"
        cname_inner = @nd_name[r_inner]
        if is_exception_class_name(cname_inner) == 1
          @needs_exc_class_hierarchy = 1
          args_id_inner = @nd_arguments[arg_id]
          if args_id_inner >= 0
            aa_inner = get_args(args_id_inner)
            if aa_inner.length >= 1
              emit("  sp_raise_cls(\"" + cname_inner + "\", " + compile_expr(aa_inner[0]) + ");")
              return
            end
          end
          emit("  sp_raise(\"" + cname_inner + "\");")
          return
        end
      end
    end
 # `raise lv` where lv is typed `exception` (sp_Exception *): emit
 # sp_raise_exc directly so cls + msg both flow through.
    if @nd_type[arg_id] == "LocalVariableReadNode"
      lname = @nd_name[arg_id]
      lv_t = find_var_type(lname)
      if lv_t == "exception"
        emit("  sp_raise_exc(lv_" + lname + ");")
        return
      end
    end
 # `raise <CallNode that returned exception>`: result is sp_Exception*.
 # Hoist into temp for safety (single eval) then sp_raise_exc.
    if @nd_type[arg_id] == "CallNode" && infer_type(arg_id) == "exception"
      tmp_re = new_temp
      emit("  sp_Exception *" + tmp_re + " = " + compile_expr(arg_id) + ";")
      emit("  sp_raise_exc(" + tmp_re + ");")
      return
    end
 # Fallback: raise <msg-expression>; sp_raise treats as RuntimeError.
    emit("  sp_raise(" + compile_expr(arg_id) + ");")
  end

 # Emit a bare `raise` (no message arg). Inside a rescue body the
 # snapshotted class+message is re-raised; outside any rescue it
 # falls back to a fresh RuntimeError, matching CRuby.
  def emit_bare_raise
    if @rescue_cls_stack.length > 0
      rcls = @rescue_cls_stack.last
      rmsg = @rescue_msg_stack.last
      emit("  sp_raise_cls(" + rcls + ", " + rmsg + ");")
    else
      emit("  sp_raise(\"RuntimeError\");")
    end
  end

 # Record / clear an ivar alias for a local variable. Walks the
 # `@scope_*` parallel stacks like `set_var_type` does. `iname` is
 # the source ivar name (e.g. `@fetch`); pass `""` to clear.
  def set_var_ivar_alias(name, iname)
    i = @scope_names.length - 1
    while i >= 0
      if @scope_names[i] == name
        @scope_ivar_alias[i] = iname
        return
      end
      i = i - 1
    end
  end

  def find_var_ivar_alias(name)
    i = @scope_names.length - 1
    while i >= 0
      if @scope_names[i] == name
        return @scope_ivar_alias[i]
      end
      i = i - 1
    end
    ""
  end

  def find_var_type(name)
 # Type-narrow override : walk top-down so the
 # innermost is_a? guard wins. Skipped for the unscoped global
 # call (e.g. ivar lookups) — narrows are about local var typing.
    i = @type_narrow_names.length - 1
    while i >= 0
      if @type_narrow_names[i] == name
        return @type_narrow_types[i]
      end
      i = i - 1
    end
    i = @scope_names.length - 1
    while i >= 0
      if @scope_names[i] == name
        return @scope_types[i]
      end
      i = i - 1
    end
    ""
  end

 # Push / pop on the is_a? narrow stack. Codegen pushes during
 # body-stmt walks where a `raise unless x.is_a?(C)` guard
 # eliminates the non-C path; the rest of the StatementsNode sees
 # `x` as `C` via find_var_type's narrow-first lookup, so
 # `compile_call_expr`'s `recv_type == "poly"` check resolves to
 # the concrete obj_<C> path and emits a monomorphic dispatch
 # (vs. the full cls_id-switch). Issue #493.
  def push_type_narrow(var_name, narrow_type)
    @type_narrow_names.push(var_name)
    @type_narrow_types.push(narrow_type)
  end

  def pop_type_narrow
    @type_narrow_names.pop
    @type_narrow_types.pop
  end

 # Like find_var_type but bypasses the is_a? narrow stack — returns
 # the var's declared (C-level) type. Used by call-site arg lowering
 # to detect cases where the narrow says "string" but the underlying
 # storage is still sp_RbVal, so the arg needs an unbox cast.
  def find_var_declared_type(name)
    i = @scope_names.length - 1
    while i >= 0
      if @scope_names[i] == name
        return @scope_types[i]
      end
      i = i - 1
    end
    ""
  end

 # ---- is_a? type narrowing ----
 # `<expr>.is_a?(<Class>)` (or kind_of?) used as the predicate of
 # an if / ternary lets us treat <expr> as <Class>'s type inside
 # the then-arm. The four entry points (push, pop,
 # narrow_type_for_class, parse_is_a_predicate) are called from
 # both inference and codegen sides — keep the API tiny so the
 # narrow context can be plumbed through without leaking state.



 # Map a Ruby class name to spinel's static type tag for narrowing.
 # Returns "" when the class doesn't have a concrete spinel type
 # we can narrow to (and the call site should leave the var type
 # alone). The first set is concrete primitives — narrow gives a
 # real type win. The Hash / Array group widens to the catch-all
 # poly_* variant since spinel doesn't track a single "any hash"
 # type, but `poly_hash` / `poly_array` reaches every receiver-
 # method dispatch the narrowed var participates in.

 # Static evaluation of `<expr>.is_a?(<Class>)` /
 # `.kind_of?(<Class>)` when expr's static type already proves the
 # answer. Returns "TRUE" / "FALSE" / "" (= dynamic). Used at
 # IfNode emit sites to skip the dead arm so the C compiler doesn't
 # type-check a recursion call whose argument types don't match.
  def static_is_a_value(pred_id)
    if pred_id < 0
      return ""
    end
    if @nd_type[pred_id] != "CallNode"
      return ""
    end
    pname = @nd_name[pred_id]
    if pname != "is_a?" && pname != "kind_of?"
      return ""
    end
    expr = @nd_receiver[pred_id]
    if expr < 0
      return ""
    end
    args = @nd_arguments[pred_id]
    if args < 0
      return ""
    end
    arg_ids = get_args(args)
    if arg_ids.length < 1
      return ""
    end
    arg0 = arg_ids[0]
    cname = ""
    if @nd_type[arg0] == "ConstantReadNode"
      cname = @nd_name[arg0]
    elsif @nd_type[arg0] == "ConstantPathNode"
      cname = resolve_const_ref_name(arg0)
    end
    if cname == ""
      return ""
    end
    expr_t = infer_type(expr)
    is_a_static_eval(expr_t, cname)
  end

  def is_a_static_eval(expr_t, cname)
    eb = base_type(expr_t)
    if eb == "poly"
      return ""
    end
 # Concrete primitives: positive answer wins, otherwise narrow
 # to the right tag.
    if cname == "Symbol"
      if eb == "symbol"
        return "TRUE"
      end
      return is_a_static_negative(eb)
    end
    if cname == "String"
      if eb == "string" || eb == "mutable_str"
        return "TRUE"
      end
      return is_a_static_negative(eb)
    end
    if cname == "Integer" || cname == "Numeric"
      if eb == "int"
        return "TRUE"
      end
      if cname == "Numeric" && eb == "float"
        return "TRUE"
      end
      return is_a_static_negative(eb)
    end
    if cname == "Float"
      if eb == "float"
        return "TRUE"
      end
      return is_a_static_negative(eb)
    end
    if cname == "TrueClass" || cname == "FalseClass"
      if eb == "bool"
        return ""  # value-dependent, leave dynamic
      end
      return is_a_static_negative(eb)
    end
    if cname == "NilClass"
      if eb == "nil"
        return "TRUE"
      end
      return is_a_static_negative(eb)
    end
    if cname == "Hash"
      if is_hash_type(eb) == 1
        return "TRUE"
      end
      return is_a_static_negative(eb)
    end
    if cname == "Array"
      if is_array_type(eb) == 1
        return "TRUE"
      end
      return is_a_static_negative(eb)
    end
    if cname == "Proc"
      if eb == "proc" || eb == "lambda"
        return "TRUE"
      end
      return is_a_static_negative(eb)
    end
    if cname == "Range"
      if eb == "range"
        return "TRUE"
      end
      return is_a_static_negative(eb)
    end
    if cname == "Encoding"
      if eb == "encoding"
        return "TRUE"
      end
      return is_a_static_negative(eb)
    end
 # User-defined class
    if find_class_idx(cname) >= 0
      if is_obj_type(eb) == 1
        ecname = eb[4, eb.length - 4]
        if is_class_or_ancestor(ecname, cname) == 1
          return "TRUE"
        end
        return "FALSE"
      end
      return is_a_static_negative(eb)
    end
    ""
  end

 # When the receiver's static type is a non-poly concrete tag, we
 # can safely declare any non-matching is_a? as FALSE. Used by the
 # primitive class branches above.
  def is_a_static_negative(eb)
    if eb == "poly" || eb == ""
      return ""
    end
    "FALSE"
  end

 # Codegen-side mirrors of the analyze helpers
 # (narrow_type_for_class / parse_is_a_predicate /
 # body_definitely_raises? / parse_raise_guard_narrow). The
 # analyze pass already pushes narrows during fixpoint walks so
 # callee param types widen correctly; codegen has to push them
 # again at emit time so `find_var_type` returns the narrowed
 # type for a LocalVariableReadNode inside the post-guard
 # sibling scope. Without this, the dispatch fall-through at
 # `compile_call_expr`'s `recv_type == "poly"` branch never
 # collapses the cls_id-switch to the single narrowed-class arm.
 # Issue #493.
  def narrow_type_for_class(cname)
    if cname == "Symbol"
      return "symbol"
    end
    if cname == "Integer" || cname == "Numeric"
      return "int"
    end
    if cname == "Float"
      return "float"
    end
    if cname == "String"
      return "string"
    end
    if cname == "TrueClass" || cname == "FalseClass"
      return "bool"
    end
    if cname == "NilClass"
      return "nil"
    end
    if cname == "Proc"
      return "proc"
    end
    if cname == "Range"
      return "range"
    end
    if cname == "Encoding"
      return "encoding"
    end
    if find_class_idx(cname) >= 0
      return "obj_" + cname
    end
    ""
  end

 # Recognize `<lv> == nil`, `<lv> != nil`, `<lv>.nil?` predicates
 # for flow-sensitive narrowing in if/ternary arms. Returns
 # [var_name, then_is_nil] where then_is_nil is "nil" when the
 # then-arm sees `<lv>` as nil (i.e. `== nil` / `.nil?`) or
 # "non_nil" when the then-arm sees it as non-nil (i.e. `!= nil`).
 # Returns ["", ""] when the predicate doesn't match.
  def parse_nil_check_predicate(pred_id)
    if pred_id < 0
      return ["", ""]
    end
    pt = @nd_type[pred_id]
    if pt != "CallNode"
      return ["", ""]
    end
    pname = @nd_name[pred_id]
    if pname == "nil?"
      recv_nc = @nd_receiver[pred_id]
      if recv_nc >= 0 && @nd_type[recv_nc] == "LocalVariableReadNode"
        return [@nd_name[recv_nc], "nil"]
      end
      return ["", ""]
    end
    if pname == "==" || pname == "!="
      recv_nc = @nd_receiver[pred_id]
      args_nc = @nd_arguments[pred_id]
      if recv_nc < 0 || args_nc < 0
        return ["", ""]
      end
      arg_ids_nc = get_args(args_nc)
      if arg_ids_nc.length < 1
        return ["", ""]
      end
 # Either side may be the nil; the other must be a bare LV read.
      lv_side = -1
      if @nd_type[recv_nc] == "LocalVariableReadNode" && @nd_type[arg_ids_nc[0]] == "NilNode"
        lv_side = recv_nc
      elsif @nd_type[arg_ids_nc[0]] == "LocalVariableReadNode" && @nd_type[recv_nc] == "NilNode"
        lv_side = arg_ids_nc[0]
      end
      if lv_side < 0
        return ["", ""]
      end
      tag = pname == "==" ? "nil" : "non_nil"
      return [@nd_name[lv_side], tag]
    end
    ["", ""]
  end

  def parse_is_a_predicate(pred_id)
    if pred_id < 0
      return ["", ""]
    end
    if @nd_type[pred_id] == "AndNode"
      l_isa = parse_is_a_predicate(@nd_left[pred_id])
      if l_isa[0] != ""
        return l_isa
      end
      r_isa = parse_is_a_predicate(@nd_right[pred_id])
      if r_isa[0] != ""
        return r_isa
      end
      return ["", ""]
    end
    if @nd_type[pred_id] != "CallNode"
      return ["", ""]
    end
    pname = @nd_name[pred_id]
    if pname != "is_a?" && pname != "kind_of?"
      return ["", ""]
    end
    expr = @nd_receiver[pred_id]
    if expr < 0 || @nd_type[expr] != "LocalVariableReadNode"
      return ["", ""]
    end
    args = @nd_arguments[pred_id]
    if args < 0
      return ["", ""]
    end
    arg_ids = get_args(args)
    if arg_ids.length < 1
      return ["", ""]
    end
    arg0 = arg_ids[0]
    cname = ""
    if @nd_type[arg0] == "ConstantReadNode"
      cname = @nd_name[arg0]
    elsif @nd_type[arg0] == "ConstantPathNode"
      cname = resolve_const_ref_name(arg0)
    end
    if cname == ""
      return ["", ""]
    end
    nt = narrow_type_for_class(cname)
    if nt == ""
      return ["", ""]
    end
    [@nd_name[expr], nt]
  end

  def body_definitely_raises?(body_id)
    if body_id < 0
      return 0
    end
    stmts_r = get_stmts(body_id)
    if stmts_r.length == 0
      return 0
    end
    last = stmts_r[stmts_r.length - 1]
    if @nd_type[last] != "CallNode"
      return 0
    end
    if @nd_name[last] != "raise"
      return 0
    end
    1
  end

  def parse_raise_guard_narrow(nid)
    if nid < 0
      return ["", ""]
    end
    t = @nd_type[nid]
    if t == "UnlessNode"
      body_u = @nd_body[nid]
      if body_definitely_raises?(body_u) == 0
        return ["", ""]
      end
      return parse_is_a_predicate(@nd_predicate[nid])
    end
    if t == "IfNode"
      pred_i = @nd_predicate[nid]
      if pred_i < 0 || @nd_type[pred_i] != "CallNode" || @nd_name[pred_i] != "!"
        return ["", ""]
      end
      inner_i = @nd_receiver[pred_i]
      if inner_i < 0
        return ["", ""]
      end
      body_i = @nd_body[nid]
      if body_definitely_raises?(body_i) == 0
        return ["", ""]
      end
      sub_i = @nd_subsequent[nid]
      else_i = @nd_else_clause[nid]
      if sub_i >= 0 || else_i >= 0
        return ["", ""]
      end
      return parse_is_a_predicate(inner_i)
    end
    ["", ""]
  end

 # Nil-guard narrow helpers (parse_nil_predicate /
 # body_definitely_exits? / infer_nil_guard_narrow_type /
 # parse_nil_guard_var / scan_back_writer_narrow_for) moved
 # to compiler_helpers.rb -- shared with spinel_analyze.rb.

 # Try to evaluate a predicate expression at compile time. Returns
 # "TRUE" / "FALSE" when the result is known statically; "" when it
 # depends on runtime state. Currently handles `<typed>.is_a?(Klass)` /
 # `kind_of?(Klass)` / `instance_of?(Klass)` where the receiver's
 # static type clearly does or does not match the queried class —
 # this lets compile_if_expr / infer_type(IfNode) skip the dead arm
 # so the typed-friendly arm doesn't get widened to poly via unify.

  def set_var_type(name, vtype)
    i = @scope_names.length - 1
    while i >= 0
      if @scope_names[i] == name
 # When the declared slot is a *_poly_hash variant, a subsequent
 # narrower-shape assignment (`<str_poly_hash slot> = StrStrHash.dup`
 # — the analyzer widened the slot's C type at declaration time to
 # accommodate later poly-value writes, but the initial RHS is the
 # narrower StrStrHash) must not collapse the tracked type back to
 # the narrower variant. The C slot's storage type is fixed at
 # declaration; downstream emit sites (bracket_assign, etc.) read
 # the tracked type to pick the right runtime helper, and dispatching
 # on the narrower variant against a wider slot tries to call
 # sp_StrStrHash_set against an sp_StrPolyHash * — hard cc error.
 # Issue #613.
        cur = @scope_types[i]
        if (cur == "str_poly_hash" && vtype == "str_str_hash") ||
           (cur == "str_poly_hash" && vtype == "str_int_hash") ||
           (cur == "sym_poly_hash" && vtype == "sym_str_hash") ||
           (cur == "sym_poly_hash" && vtype == "sym_int_hash") ||
           (cur == "poly_poly_hash" && (vtype == "str_str_hash" || vtype == "str_int_hash" || vtype == "sym_str_hash" || vtype == "sym_int_hash" || vtype == "int_str_hash" || vtype == "str_poly_hash" || vtype == "sym_poly_hash"))
          return
        end
        @scope_types[i] = vtype
        return
      end
      i = i - 1
    end
  end

 # Wrap a narrower-hash RHS C expression to match a wider *_poly_hash
 # slot. The set_var_type sticky guard above keeps the slot's tracked
 # type at the wider variant; this helper produces the matching
 # runtime conversion at the assignment site. Without it, the LV-write
 # emit produces `lv_merged = sp_StrStrHash_dup(...)` against an
 # `sp_StrPolyHash *` slot — different struct layouts (vals[] of
 # `const char **` vs `sp_RbVal *`), so reads through the slot return
 # garbage even when -Werror is off. Issue #614.
 # Cross-variant hash converter at call boundary. Returns the C
 # expression for promoting `src_var` (typed `src_t`) into a hash
 # of `dst_t`, or "" when no converter is available. Currently
 # covers conversions into str_poly_hash from the four source
 # variants: str_int_hash, str_str_hash, sym_int_hash, sym_str_hash,
 # sym_poly_hash. Symmetric directions (into sym_poly_hash from
 # str-keyed variants) are absent because spinel's str_poly_hash
 # is the canonical wide-keyed shape.
  def hash_variant_convert(src_t, dst_t, src_var)
    if dst_t == "str_poly_hash"
      if src_t == "str_int_hash"
        @needs_str_poly_hash = 1
        @needs_str_int_hash = 1
        @needs_rb_value = 1
        return "sp_StrPolyHash_from_str_int_hash(" + src_var + ")"
      end
      if src_t == "str_str_hash"
        @needs_str_poly_hash = 1
        @needs_str_str_hash = 1
        @needs_rb_value = 1
        return "sp_StrPolyHash_from_str_str_hash(" + src_var + ")"
      end
      if src_t == "sym_int_hash"
        @needs_str_poly_hash = 1
        @needs_sym_int_hash = 1
        @needs_rb_value = 1
        return "sp_StrPolyHash_from_sym_int_hash(" + src_var + ")"
      end
      if src_t == "sym_str_hash"
        @needs_str_poly_hash = 1
        @needs_sym_str_hash = 1
        @needs_rb_value = 1
        return "sp_StrPolyHash_from_sym_str_hash(" + src_var + ")"
      end
      if src_t == "sym_poly_hash"
        @needs_str_poly_hash = 1
        @needs_sym_poly_hash = 1
        @needs_rb_value = 1
        return "sp_StrPolyHash_from_sym_poly_hash(" + src_var + ")"
      end
    end
    if dst_t == "sym_poly_hash"
      if src_t == "sym_int_hash"
        @needs_sym_poly_hash = 1
        @needs_sym_int_hash = 1
        @needs_rb_value = 1
        return "sp_SymIntHash_to_sym_poly(" + src_var + ")"
      end
      if src_t == "sym_str_hash"
        @needs_sym_poly_hash = 1
        @needs_sym_str_hash = 1
        @needs_rb_value = 1
        return "sp_SymStrHash_to_sym_poly(" + src_var + ")"
      end
    end
    ""
  end

  def widen_hash_assign(val, vt, rhs_t)
    if vt == "str_poly_hash" && rhs_t == "str_str_hash"
      @needs_str_poly_hash = 1
      @needs_str_str_hash = 1
      @needs_rb_value = 1
      return "sp_StrPolyHash_from_str_str_hash(" + val + ")"
    end
    if vt == "str_poly_hash" && rhs_t == "str_int_hash"
      @needs_str_poly_hash = 1
      @needs_str_int_hash = 1
      @needs_rb_value = 1
      return "sp_StrPolyHash_from_str_int_hash(" + val + ")"
    end
    val
  end

 # ---- Class/Method lookup (all parallel arrays) ----
  def find_regexp_index(nid)
    if @nd_type[nid] == "RegularExpressionNode"
      pat = @nd_unescaped[nid]
      i = 0
      while i < @regexp_patterns.length
        if @regexp_patterns[i] == pat
          return i
        end
        i = i + 1
      end
      return -1
    end
 # `Regexp.new("lit")` / `Regexp.compile("lit")` resolves to the same
 # pattern table, so `Regexp.new("foo").match?(s)` and the LV-bound
 # form `pat = Regexp.new("foo"); pat.match?(s)` both dispatch through
 # `sp_re_pat_<i>` instead of falling through to unresolved-call.
    rxlit_cg = regexp_new_literal_pattern(nid)
    if rxlit_cg != ""
      ci = 0
      while ci < @regexp_patterns.length
        if @regexp_patterns[ci] == rxlit_cg
          return ci
        end
        ci = ci + 1
      end
      return -1
    end
 # A constant initialized to a regex literal forwards to the
 # underlying pattern, so `RX = /pat/; RX.match?(s)` and
 # `s =~ RX` dispatch to the engine instead of falling through
 # to the literal-`(-1)` / `sp_str_include` fallbacks.
 # Also unwrap `.freeze` (`PATTERN = /pat/.freeze`) — Prism wraps
 # the literal in a `freeze` CallNode whose receiver is the
 # RegularExpressionNode. .
    if @nd_type[nid] == "ConstantReadNode"
      cname = resolve_const_ref_name(nid)
      if cname != ""
        ci = find_const_idx(cname)
        if ci >= 0 && ci < @const_expr_ids.length
          eid = @const_expr_ids[ci]
          if eid >= 0 && @nd_type[eid] == "CallNode" && @nd_name[eid] == "freeze"
            recv_freeze = @nd_receiver[eid]
            if recv_freeze >= 0
              eid = recv_freeze
            end
          end
          if eid >= 0 && @nd_type[eid] == "RegularExpressionNode"
            return find_regexp_index(eid)
          end
 # `RE = Regexp.new("lit")` — recurse so the CallNode arm below
 # resolves it through the same static pattern table as `RE = /lit/`.
          if eid >= 0 && regexp_new_literal_pattern(eid) != ""
            return find_regexp_index(eid)
          end
        end
      end
    end
 # A local variable with exactly one write to a regex literal is
 # also resolvable. Multi-write or non-regex-write names were
 # marked ambiguous (-1) by scan_features.
    if @nd_type[nid] == "LocalVariableReadNode"
      lname = @nd_name[nid]
      i = 0
      while i < @local_regex_names.length
        if @local_regex_names[i] == lname
          return @local_regex_idx[i]
        end
        i = i + 1
      end
    end
    -1
  end

 # Returns a C expression evaluating to a `mrb_regexp_pattern *`, or "" if
 # the node isn't a regex source. Static literals resolve to their
 # pre-compiled `sp_re_pat_<i>` global; InterpolatedRegularExpressionNode
 # gets a runtime `sp_re_runtime_compile(...)` call. Centralizes the
 # dispatch so each =~/match?/match/gsub/sub/scan/split call site doesn't
 # have to repeat the InterpolatedRegex check.
  def regex_pat_c_expr(nid)
    ridx = find_regexp_index(nid)
    if ridx >= 0
 # Issue #846: if the pre-compile failed (the literal came from
 # `Regexp.new("[bad")` whose pattern is invalid), raise the
 # captured error message now — from inside the user's begin/
 # rescue scope where setjmp is active.
      @needs_exc_class_hierarchy = 1
      return "(sp_re_pat_err_" + ridx.to_s + " ? (sp_raise_cls(\"RegexpError\", sp_re_pat_err_" + ridx.to_s + "), (mrb_regexp_pattern *)NULL) : sp_re_pat_" + ridx.to_s + ")"
    end
    if @nd_type[nid] == "InterpolatedRegularExpressionNode"
      @needs_regexp = 1
      return compile_expr(nid)
    end
 # `Regexp.new(<dyn>)` / `Regexp.compile(<dyn>)` inline at the call
 # site -- the per-call-site `sp_re_dyn_<idx>` cache compiles the
 # arg string on first hit and reuses on subsequent identical inputs.
    if regexp_new_dynamic?(nid) == 1
      idx = find_dyn_regex_index(nid)
      if idx >= 0
        a0 = regexp_new_call_arg_id(nid)
        if a0 >= 0
          @needs_regexp = 1
          return "sp_re_dyn_" + idx.to_s + "(" + compile_expr(a0) + ")"
        end
      end
    end
 # LV bound by a single write to `Regexp.new(<dyn>)` -- look up the
 # CallNode and emit the dyn-cache call here. The arg's free
 # variables (params, ivars, surrounding LVs) are still in scope at
 # the read site in C terms, so re-evaluation produces the same
 # pattern string the write site would have, provided the user
 # hasn't mutated those free variables between write and read.
    if @nd_type[nid] == "LocalVariableReadNode"
      cn_lv = find_local_regex_dyn_call_nid(@nd_name[nid])
      if cn_lv >= 0
        idx_lv = find_dyn_regex_index(cn_lv)
        if idx_lv >= 0
          a0_lv = regexp_new_call_arg_id(cn_lv)
          if a0_lv >= 0
            @needs_regexp = 1
            return "sp_re_dyn_" + idx_lv.to_s + "(" + compile_expr(a0_lv) + ")"
          end
        end
      end
    end
    ""
  end

 # Returns the CallNode id of a single-write `Regexp.new(<dyn>)` RHS
 # for a local variable, or -1 if the LV isn't dyn-bound or is
 # ambiguous (multiple writes).
  def find_local_regex_dyn_call_nid(lname)
    i = 0
    while i < @local_regex_names.length
      if @local_regex_names[i] == lname
        if i < @local_regex_call_nids.length
          return @local_regex_call_nids[i]
        end
        return -1
      end
      i = i + 1
    end
    -1
  end

 # Maps Prism's regex flag bits to the engine's `RE_FLAG_*` values and
 # returns a C bitwise-OR string ("0", "1", "1|6", etc.). Single source
 # of truth used by both the static-regex collector arm in scan_features
 # and the per-call-site helper emitted by emit_dyn_regex_helpers.
 # Prism: IGNORE_CASE=4, EXTENDED=8, MULTI_LINE=16.
 # Engine: IGNORECASE=1, MULTILINE=2, DOTALL=4, EXTENDED=8.
 # Ruby's /m (dot-matches-newline) maps to MULTILINE|DOTALL = 6.

 # Mirror of `regexp_new_call_arg_id` from spinel_analyze.rb -- returns
 # the AST node id of the single argument for a `Regexp.new(<arg>)` /
 # `Regexp.compile(<arg>)` shape, -1 otherwise. See analyze-side
 # comment for the strict arity rationale.
  def regexp_new_call_arg_id(nid)
    if @nd_type[nid] != "CallNode"
      return -1
    end
    mn = @nd_name[nid]
    if mn != "new" && mn != "compile"
      return -1
    end
    if @nd_block[nid] >= 0
      return -1
    end
    recv = @nd_receiver[nid]
    if recv < 0
      return -1
    end
    if @nd_type[recv] != "ConstantReadNode"
      return -1
    end
    if @nd_name[recv] != "Regexp"
      return -1
    end
    args_id = @nd_arguments[nid]
    if args_id < 0
      return -1
    end
    arg_ids = get_args(args_id)
    if arg_ids.length != 1
      return -1
    end
    arg_ids[0]
  end

 # Mirror of `regexp_new_literal_pattern` from spinel_analyze.rb.
  def regexp_new_literal_pattern(nid)
    a0 = regexp_new_call_arg_id(nid)
    if a0 < 0
      return ""
    end
    if @nd_type[a0] != "StringNode"
      return ""
    end
    @nd_content[a0]
  end

 # Mirror of `regexp_new_dynamic?` from spinel_analyze.rb. Used to
 # dispatch the dyn-cache emit in `regex_pat_c_expr`.
  def regexp_new_dynamic?(nid)
    a0 = regexp_new_call_arg_id(nid)
    if a0 < 0
      return 0
    end
    if @nd_type[a0] == "StringNode"
      return 0
    end
    1
  end

 # Index of an InterpolatedRegularExpressionNode in @dyn_regex_node_ids,
 # or -1 if scan_features hasn't registered it (defensive — should not
 # happen for any reachable node).
  def find_dyn_regex_index(nid)
    i = 0
    while i < @dyn_regex_node_ids.length
      if @dyn_regex_node_ids[i] == nid
        return i
      end
      i = i + 1
    end
    -1
  end

  def find_class_idx(name)
    i = 0
    while i < @cls_names.length
      if @cls_names[i] == name
        return i
      end
      i = i + 1
    end
    -1
  end

 # Walk @cls_parents starting from `child_idx` and return 1 if we
 # ever land on `ancestor_idx`. Used by `is_a?(<Klass>)` on poly
 # receivers to enumerate descendant cls_ids — `recv.is_a?(C)` is
 # true when recv's class is C or any subclass of C, so we OR
 # together every cls_id whose parent chain reaches C.
  def cls_is_descendant(child_idx, ancestor_idx)
    ck = child_idx
    while ck >= 0
      pname = @cls_parents[ck]
      if pname == ""
        return 0
      end
      pi = find_class_idx(pname)
      if pi < 0
        return 0
      end
      if pi == ancestor_idx
        return 1
      end
      ck = pi
    end
    0
  end

  def find_method_idx(name)
    i = 0
    while i < @meth_names.length
      if @meth_names[i] == name
        return i
      end
      i = i + 1
    end
    -1
  end

  def method_rest_index(mi)
    if mi >= 0 && mi < @meth_rest_index.length
      return @meth_rest_index[mi]
    end
    -1
  end

  def method_kwrest_index(mi)
    if mi >= 0 && mi < @meth_kwrest_index.length
      return @meth_kwrest_index[mi]
    end
    -1
  end

  def find_const_idx(name)
    i = 0
    while i < @const_names.length
      if @const_names[i] == name
        return i
      end
      i = i + 1
    end
    -1
  end

 # ---- Class variable helpers ----
 # Qualified name for a class-var slot: `<ClassName>_<var>` where
 # <var> drops the leading @@. Codegen emits one C global named
 # `cvar_<qname>` per registered cvar.
  def cvar_qname(class_idx, var_name)
    cls = "Toplevel"
    if class_idx >= 0
      cls = @cls_names[class_idx]
    end
    bare = var_name
    if bare.length >= 2 && bare[0, 2] == "@@"
      bare = bare[2, bare.length - 2]
    end
    cls + "_" + bare
  end

  def find_cvar_idx(qname)
    i = 0
    while i < @cvar_names.length
      if @cvar_names[i] == qname
        return i
      end
      i = i + 1
    end
    -1
  end

 # Register or update a cvar's inferred type. Called from
 # collect_cvars during the pre-pass and (defensively) again from
 # compile_stmt when the write fires.
  def register_cvar(qname, t)
    ci = find_cvar_idx(qname)
    if ci >= 0
 # Widen on type disagreement: int + string -> poly. Conservative
 # for v1 -- when the gap matters we'll revisit.
      if @cvar_types[ci] != t && @cvar_types[ci] != "poly" && t != ""
        @cvar_types[ci] = "poly"
      end
      return ci
    end
    @cvar_names.push(qname)
    @cvar_types.push(t)
    @cvar_init_values.push("")
    @cvar_names.length - 1
  end

 # Try to compile-time fold a class-body cvar initializer. If the
 # value is a simple literal (Integer/Float/String/Symbol/True/
 # False/Nil), capture it as the static decl's initializer so the
 # cvar enters the program with the source's value rather than the
 # type default. Spinel doesn't run class-body statements at
 # startup, so without this fold a `class C; @@x = 42; end` leaves
 # cvar_C_x at 0 until the first write fires.

 # If the constant's initializer is a simple literal, return the
 # corresponding C expression. Otherwise return "" so callers fall
 # back to cst_<name> lookup. Enables propagation of:
 # N = 10 → 10 at use sites
 # PI = 3.14 → 3.14
 # GREETING = "hi" → ("\xff" "hi" + 1)
 # OK = true → TRUE
  def const_literal_c_value(ci)
    if ci < 0 || ci >= @const_expr_ids.length
      return ""
    end
    eid = @const_expr_ids[ci]
    if eid < 0
      return ""
    end
    et = @nd_type[eid]
    if et == "IntegerNode"
      return @nd_value[eid].to_s
    end
    if et == "FloatNode"
      return @nd_content[eid]
    end
    if et == "StringNode"
      return c_string_literal(@nd_content[eid])
    end
    if et == "TrueNode"
      return "TRUE"
    end
    if et == "FalseNode"
      return "FALSE"
    end
    if et == "NilNode"
      return "0"
    end
    if et == "SymbolNode"
      return compile_symbol_literal(@nd_content[eid])
    end
    ""
  end

 # Find method in class (search parent chain)
  def cls_find_method(ci, mname)
    names = @cls_meth_names[ci].split(";", -1)
    j = 0
    while j < names.length
      if names[j] == mname
        return j
      end
      j = j + 1
    end
 # Check parent
    if @cls_parents[ci] != ""
      pi = find_class_idx(@cls_parents[ci])
      if pi >= 0
        return cls_find_method(pi, mname)
      end
    end
    -1
  end

 # Walk the parent chain looking for a method named `mname`.
 # Returns the class index that defines it (the owner), or -1.
 # `kind` selects @cls_cmeth_names ("cmeth") or @cls_meth_names
 # ("imeth"). Used by the dispatch lowering to find the static
 # owner before deciding whether a cls_id switch is needed.
  def cls_method_owner_for(ci, mname, kind)
    if ci < 0
      return -1
    end
    if kind == "cmeth"
      mnames = @cls_cmeth_names[ci].split(";", -1)
    else
      mnames = @cls_meth_names[ci].split(";", -1)
    end
    cj = 0
    while cj < mnames.length
      if mnames[cj] == mname
        return ci
      end
      cj = cj + 1
    end
    if @cls_parents[ci] != ""
      pi = find_class_idx(@cls_parents[ci])
      if pi >= 0
        return cls_method_owner_for(pi, mname, kind)
      end
    end
    -1
  end

 # Enumerate descendants of inner_ci (including inner_ci itself)
 # whose method owner differs from base_owner. Each entry is
 # encoded `<descendant_ci>,<owner_ci>` separated by `;`. Empty
 # string when no overrides exist (caller stays on the
 # static-dispatch path). `kind` is "cmeth" or "imeth".
  def cls_method_override_descendants(inner_ci, base_owner, mname, kind)
    out = ""
    ck = 0
    while ck < @cls_names.length
      if ck == inner_ci || cls_is_descendant(ck, inner_ci) == 1
        ow = cls_method_owner_for(ck, mname, kind)
        if ow >= 0 && ow != base_owner
          if out != ""
            out = out + ";"
          end
          out = out + ck.to_s + "," + ow.to_s
        end
      end
      ck = ck + 1
    end
    out
  end

 # Whether all imeth overrides in `pairs_str` have a param-type
 # signature compatible with `base_ptypes` (and same length).
 # Used as a gate on the cls_id-switch dispatch — without this,
 # an override declared with narrower param types than the base
 # would emit a C call site that doesn't match its signature.
  def cls_imeth_override_ptypes_match(pairs_str, mname, base_ptypes)
    pairs = pairs_str.split(";", -1)
    pi = 0
    while pi < pairs.length
      p = pairs[pi].split(",", -1)
      cand_owner = p[1].to_i
      cand_midx = cls_find_method_direct(cand_owner, mname)
      cand_pt = cls_meth_ptypes_get(cand_owner, cand_midx)
      if cand_pt.length != base_ptypes.length
        return 0
      end
      k = 0
      while k < base_ptypes.length
        if cand_pt[k] != base_ptypes[k]
          return 0
        end
        k = k + 1
      end
      pi = pi + 1
    end
    1
  end

 # `<arr>.method(:op)` for built-in array types: which (recv_type,
 # mname) pairs we can lower into a Method-dispatch adapter. Limited
 # to int_array's bracket ops + push for now (the optcarrot CPU
 # memory-mapping shape `@ram.method(:[]=)`); extend the body to
 # cover more (recv_type, mname) pairs as workloads need them.
  def builtin_array_method_supported(recv_type, mname)
    if recv_type == "int_array"
      if mname == "[]" || mname == "[]=" || mname == "push"
        return 1
      end
    end
    0
  end

  def builtin_array_type_pfx(recv_type)
    if recv_type == "int_array"
      return "IntArray"
    end
    ""
  end

 # Emit a per-(array_type, mname) trampoline that fits the Method
 # dispatch ABI `(void *self, mrb_int...) -> mrb_int`. The body
 # forwards to the corresponding `sp_<Pfx>_<op>` runtime function;
 # write-style ops (`[]=`, `push`) return the rhs the way Ruby's
 # bracket-write does. Idempotent: re-emitting the same key is a
 # no-op. Reuses @cls_method_adapters with a `@@`-prefixed key so
 # it cannot collide with a user-class method adapter entry.
  def emit_builtin_array_method_adapter(recv_type, mname)
    key = "@@" + recv_type + "::" + mname
    k = 0
    while k < @cls_method_adapters.length
      if @cls_method_adapters[k] == key
        return
      end
      k = k + 1
    end
    @cls_method_adapters.push(key)
    pfx = builtin_array_type_pfx(recv_type)
    if pfx == ""
      return
    end
    cast = "(sp_" + pfx + " *)"
    adapter_name = "sp_" + pfx + "_" + sanitize_name(mname) + "_builtin_method_adapter"
    promote_abi_b = (@int_overflow_mode == "promote") ? 1 : 0
    if promote_abi_b == 1
      @needs_bigint = 1
      slot_c_b = "sp_Bigint *"
      unbox_i = "sp_bigint_to_int(_i)"
      unbox_v = "sp_bigint_to_int(_v)"
      ret_box_v = "_v"
    else
      slot_c_b = "mrb_int"
      unbox_i = "_i"
      unbox_v = "_v"
      ret_box_v = "_v"
    end
    if recv_type == "int_array" && mname == "[]"
      @lambda_funcs << "static "
      @lambda_funcs << slot_c_b
      @lambda_funcs << " "
      @lambda_funcs << adapter_name
      @lambda_funcs << "(void *_self, "
      @lambda_funcs << slot_c_b
      @lambda_funcs << " _i) {\n"
      if promote_abi_b == 1
        @lambda_funcs << "  return sp_bigint_new_int(sp_IntArray_get("
        @lambda_funcs << cast
        @lambda_funcs << "_self, "
        @lambda_funcs << unbox_i
        @lambda_funcs << "));\n"
      else
        @lambda_funcs << "  return sp_IntArray_get("
        @lambda_funcs << cast
        @lambda_funcs << "_self, "
        @lambda_funcs << unbox_i
        @lambda_funcs << ");\n"
      end
      @lambda_funcs << "}\n"
      return
    end
    if recv_type == "int_array" && mname == "[]="
      @lambda_funcs << "static "
      @lambda_funcs << slot_c_b
      @lambda_funcs << " "
      @lambda_funcs << adapter_name
      @lambda_funcs << "(void *_self, "
      @lambda_funcs << slot_c_b
      @lambda_funcs << " _i, "
      @lambda_funcs << slot_c_b
      @lambda_funcs << " _v) {\n"
      @lambda_funcs << "  sp_IntArray_set("
      @lambda_funcs << cast
      @lambda_funcs << "_self, "
      @lambda_funcs << unbox_i
      @lambda_funcs << ", "
      @lambda_funcs << unbox_v
      @lambda_funcs << ");\n"
      @lambda_funcs << "  return "
      @lambda_funcs << ret_box_v
      @lambda_funcs << ";\n"
      @lambda_funcs << "}\n"
      return
    end
    if recv_type == "int_array" && mname == "push"
      @lambda_funcs << "static "
      @lambda_funcs << slot_c_b
      @lambda_funcs << " "
      @lambda_funcs << adapter_name
      @lambda_funcs << "(void *_self, "
      @lambda_funcs << slot_c_b
      @lambda_funcs << " _v) {\n"
      @lambda_funcs << "  sp_IntArray_push("
      @lambda_funcs << cast
      @lambda_funcs << "_self, "
      @lambda_funcs << unbox_v
      @lambda_funcs << ");\n"
      @lambda_funcs << "  return "
      @lambda_funcs << ret_box_v
      @lambda_funcs << ";\n"
      @lambda_funcs << "}\n"
      return
    end
    nil
  end

 # Emit a one-off adapter that wraps `sp_<Klass>_cls_<mname>` so the
 # Method dispatch ABI `(void *self, mrb_int...)` works on a class
 # method (which has no self param). Idempotent: re-emitting the
 # same (Klass, mname) pair is a no-op. Buffered into @lambda_funcs
 # so the function lands at the same insertion point as lambdas
 # (before main, after forward declarations of every cls method).
  def emit_cls_method_adapter(ci, mname)
    cname = @cls_names[ci]
    key = cname + "::" + mname
    k = 0
    while k < @cls_method_adapters.length
      if @cls_method_adapters[k] == key
        return
      end
      k = k + 1
    end
    @cls_method_adapters.push(key)

    cmnames = @cls_cmeth_names[ci].split(";", -1)
    cm_returns = @cls_cmeth_returns[ci].split(";", -1)
    j = 0
    while j < cmnames.length
      if cmnames[j] == mname
        break
      end
      j = j + 1
    end
    rt = "int"
    if j < cm_returns.length
      rt = cm_returns[j]
    end
    pt_list = cls_cmeth_ptypes_get(ci, j)
    base_name = "sp_" + cname + "_cls_" + sanitize_name(mname)
    adapter_name = "sp_" + cname + "_" + sanitize_name(mname) + "_cls_method_adapter"
 # Method ABI in promote mode is `(void *, sp_Bigint *...) -> sp_Bigint*`.
 # In raise/wrap mode it's `(void *, mrb_int...) -> mrb_int`.
 # The adapter unwraps incoming sp_Bigint* args to whatever the
 # callee param expects, and (re)wraps the callee return to match
 # the ABI return type.
    promote_abi = (@int_overflow_mode == "promote") ? 1 : 0
    if promote_abi == 1
      @needs_bigint = 1
      adapter_rt_c = "sp_Bigint *"
      slot_c = "sp_Bigint *"
    else
      adapter_rt_c = "mrb_int"
      slot_c = "mrb_int"
    end
    sig = adapter_rt_c + " " + adapter_name + "(void *_unused"
    body_args = ""
    pi2 = 0
    while pi2 < pt_list.length
      sig = sig + ", " + slot_c + " _a" + pi2.to_s
      arg_expr = "_a" + pi2.to_s
      param_b = base_type(pt_list[pi2])
      if promote_abi == 1
 # Slot is sp_Bigint*. Unwrap to mrb_int when the callee
 # param expects a non-bigint primitive.
        if param_b == "int" || param_b == "symbol" || param_b == "bool"
          arg_expr = "sp_bigint_to_int(_a" + pi2.to_s + ")"
        end
      else
        if param_b == "bigint"
          arg_expr = "sp_bigint_new_int(_a" + pi2.to_s + ")"
          @needs_bigint = 1
        end
      end
      if pi2 == 0
        body_args = arg_expr
      else
        body_args = body_args + ", " + arg_expr
      end
      pi2 = pi2 + 1
    end
    sig = sig + ")"
    @lambda_funcs << "static "
    @lambda_funcs << sig
    @lambda_funcs << " {\n"
    if rt == "void"
      @lambda_funcs << "  "
      @lambda_funcs << base_name
      @lambda_funcs << "("
      @lambda_funcs << body_args
      @lambda_funcs << ");\n"
      if promote_abi == 1
        @lambda_funcs << "  return sp_bigint_new_int(0);\n"
      else
        @lambda_funcs << "  return 0;\n"
      end
    elsif promote_abi == 1
      if base_type(rt) == "bigint"
        @lambda_funcs << "  return "
        @lambda_funcs << base_name
        @lambda_funcs << "("
        @lambda_funcs << body_args
        @lambda_funcs << ");\n"
      else
        @lambda_funcs << "  return sp_bigint_new_int((mrb_int)"
        @lambda_funcs << base_name
        @lambda_funcs << "("
        @lambda_funcs << body_args
        @lambda_funcs << "));\n"
      end
    else
      if base_type(rt) == "bigint"
        @lambda_funcs << "  return sp_bigint_to_int("
        @lambda_funcs << base_name
        @lambda_funcs << "("
        @lambda_funcs << body_args
        @lambda_funcs << "));\n"
      else
        @lambda_funcs << "  return "
        @lambda_funcs << base_name
        @lambda_funcs << "("
        @lambda_funcs << body_args
        @lambda_funcs << ");\n"
      end
    end
    @lambda_funcs << "}\n"
    nil
  end


  def cls_method_return(ci, mname, kind = "imeth")
    if ci < 0
      return "int"
    end
    if kind == "cmeth"
      names = @cls_cmeth_names[ci].split(";", -1)
      returns = @cls_cmeth_returns[ci].split(";", -1)
    else
      names = @cls_meth_names[ci].split(";", -1)
      returns = @cls_meth_returns[ci].split(";", -1)
    end
    j = 0
    while j < names.length
      if names[j] == mname
        if j < returns.length
          return returns[j]
        end
        return "int"
      end
      j = j + 1
    end
    if @cls_parents[ci] != ""
      pi = find_class_idx(@cls_parents[ci])
      if pi >= 0
        return cls_method_return(pi, mname, kind)
      end
    end
    "int"
  end

 # Get ivar type from class
  def cls_ivar_type(ci, iname)
    names = @cls_ivar_names[ci].split(";", -1)
    types = @cls_ivar_types[ci].split(";", -1)
    own_t = ""
    j = 0
    while j < names.length
      if names[j] == iname
        if j < types.length
          own_t = types[j]
        else
          own_t = "int"
        end
        break
      end
      j = j + 1
    end
    parent_t = ""
    if @cls_parents[ci] != ""
      pi = find_class_idx(@cls_parents[ci])
      if pi >= 0 && ivar_in_chain(pi, iname) == 1
        parent_t = cls_ivar_type(pi, iname)
      end
    end
 # The struct embeds parent ivars at the parent's recorded type
 # (`emit_class_fields` skips own copies that are also in the
 # parent chain). When the parent has the same ivar, the parent's
 # type is what the C struct field actually has — so any access
 # through `self->iv_X` must agree with that, regardless of what
 # this child's own table happened to record. Defer to the parent
 # type when both classes know the ivar.
    if parent_t != ""
      return parent_t
    end
    if own_t != ""
      return own_t
    end
    "int"
  end

 # ---- Emit helpers ----
  def emit(s)
    ind = ""
    j = 0
    while j < @indent
      ind = ind + "  "
      j = j + 1
    end
    @out_lines.push(ind + s)
  end

  def emit_raw(s)
    @out_lines.push(s)
  end


 # ---- Type inference ----
 # `node_type` is the codegen's interface to per-AST-node types.
 # When the cache has been pre-filled (analyze→codegen split path)
 # this is an O(1) array read. Otherwise it's a transparent forward
 # to infer_type. We do NOT lazily fill the cache from emission paths
 # because emission can mutate analysis state (auto_register_attr_*,
 # @needs_* side-flags, etc.) and a cached value would freeze before
 # those mutations land.

  def infer_type(nid)
    if nid < 0
      return "void"
    end
 # `<poly>[idx]` — analyze may cache an optimistic concrete type
 # (e.g. "int" picked from one observed elem kind), but
 # compile_poly_method_call's actual emit widens to sp_RbVal
 # whenever its narrow_int check fails (e.g. block-param recv).
 # When the cache disagrees with the emit, downstream consumers
 # (compile_arg0_as_int for `>>` / `<<`, ...) skip the unbox and
 # produce `int >> sp_RbVal` in C — fails C compile. Compute the
 # answer that mirrors the actual emit, before honouring the
 # cache.
    pa = poly_aref_call_type(nid)
    if pa != ""
      return pa
    end
 # Sibling-scope narrow override: when the active narrow stack
 # narrows `x` to `obj_<C>` and this CallNode is `x.attr` where
 # `attr` is an attr_reader on `C`, the cached type (filled by
 # analyze's walk_and_cache before the narrow was active) is
 # stale. Resolve the attr_reader directly off the narrowed
 # class's ivar table and return its type, bypassing the cache.
 # Issue #493. Cheap: only fires when narrow is non-empty AND
 # the node is `LV(narrowed_name).attr_reader_name`.
    if @type_narrow_names.length > 0 && @nd_type[nid] == "CallNode"
      narrow_recv_id = @nd_receiver[nid]
      if narrow_recv_id >= 0 && @nd_type[narrow_recv_id] == "LocalVariableReadNode"
        narrow_lvname = @nd_name[narrow_recv_id]
        narrow_t_lookup = ""
        ki_nt = @type_narrow_names.length - 1
        while ki_nt >= 0
          if @type_narrow_names[ki_nt] == narrow_lvname
            narrow_t_lookup = @type_narrow_types[ki_nt]
            ki_nt = -1
          else
            ki_nt = ki_nt - 1
          end
        end
        if is_obj_type(narrow_t_lookup) == 1
          ncname_nt = narrow_t_lookup[4, narrow_t_lookup.length - 4]
          nci_nt = find_class_idx(ncname_nt)
          if nci_nt >= 0
            mname_nt = @nd_name[nid]
            if cls_has_attr_reader(nci_nt, mname_nt) == 1
              return cls_ivar_type(nci_nt, "@" + mname_nt)
            end
          end
        end
      end
    end
 # Specialization-scope override: when a class method body
 # (e.g. `def self.from_row(row)`) is reused across multiple
 # subclass specializations, the per-call-site specialization
 # narrows the `row` param to `obj_<CommentRow>` / `obj_<ArticleRow>`
 # etc. via declare_var in emit_class_level_method. But the
 # @nd_inferred_type cache was populated once during analyze with
 # the unspecialized union (often "int" — the unconstrained fallback),
 # so `row.commenter` reads back as int and the boxer dispatch
 # picks sp_box_int on a string field. Re-resolve `LV.attr_reader`
 # against the active scope when the scope's declared type is a
 # concrete obj_<C> that the analyze-time union missed.
    if @nd_type[nid] == "CallNode"
      cmt_recv_id = @nd_receiver[nid]
      if cmt_recv_id >= 0 && @nd_type[cmt_recv_id] == "LocalVariableReadNode"
        cmt_lvname = @nd_name[cmt_recv_id]
        cmt_scope_t = find_var_type(cmt_lvname)
        if is_obj_type(cmt_scope_t) == 1
          cmt_cname = cmt_scope_t[4, cmt_scope_t.length - 4]
          cmt_ci = find_class_idx(cmt_cname)
          if cmt_ci >= 0
            cmt_mname = @nd_name[nid]
            if cls_has_attr_reader(cmt_ci, cmt_mname) == 1
              return cls_ivar_type(cmt_ci, "@" + cmt_mname)
            end
          end
        end
 # Int LV recv with user-class attr_reader: codegen's
 # compile_int_class_fallback_expr picks the FIRST class in
 # @cls_names that defines the attr_reader and emits
 # `((sp_C *)lv)->iv_X` directly. Mirror that pick here so the
 # boxer dispatch at the attr_writer call site (line 22838)
 # gets the matching ivar type instead of the int fallback.
 # Without this, `self.attr = lv.attr` where lv is mrb_int and
 # the user class has attr_reader emits `sp_box_int(<const char *>)`
 # -- the residual #694 / #700 shape A.
 #
 # Restrict to scope == "int" (matches compile_int_class_fallback_expr's
 # gate). Poly LV recv goes through the cls_id-switch dispatch,
 # which box-per-arm produces sp_RbVal -- infer_type stays at the
 # cached "poly" / "int" default and the boxer at the writer
 # call site noop's (box_value_to_poly("poly", val) = val).
 # Filter out primitive-shared method names so a real int LV
 # calling a shared op (`s.index(...)`) doesn't get rerouted.
        if cmt_scope_t == "int" && primitive_method_shared_with_user_class(@nd_name[nid]) == 0
          cmt_mname2 = @nd_name[nid]
          ci2 = 0
          while ci2 < @cls_names.length
            if cls_has_attr_reader(ci2, cmt_mname2) == 1
              return cls_ivar_type(ci2, "@" + cmt_mname2)
            end
            ci2 = ci2 + 1
          end
        end
      end
    end
 # Cache lookup. analyze.rb's annotate_all_node_types fills
 # @nd_inferred_type for every reachable node OUTSIDE block bodies
 # (block-iteration scope is iterator-specific and dispatched at
 # emit time, so block-body nodes are intentionally left empty
 # for codegen's own infer_type to handle).
    cached = @nd_inferred_type[nid]
    if cached != ""
 # LocalVariableReadNode: a `<lv> == nil ? T : F` ternary's else
 # arm pushes a narrowed type onto @type_narrow_names; the cache
 # was filled by annotate_all_node_types without seeing the
 # narrow, so consult find_var_type whenever a narrow for this
 # var is in effect. Same pattern as the existing `is_a?`-based
 # narrowing.
      if @nd_type[nid] == "LocalVariableReadNode" && @type_narrow_names.length > 0
        lv_name_nch = @nd_name[nid]
        ni_nch = @type_narrow_names.length - 1
        while ni_nch >= 0
          if @type_narrow_names[ni_nch] == lv_name_nch
            return @type_narrow_types[ni_nch]
          end
          ni_nch = ni_nch - 1
        end
      end
      return cached
    end
    t = @nd_type[nid]
    if t == "SuperNode" || t == "ForwardingSuperNode"
 # `super` returns whatever the parent's same-named method
 # returns. Walk to the parent's `find_method_owner`-resolved
 # method and read its return type.
      if @current_class_idx >= 0 && @current_method_name != ""
 # Prepend chain redirect (issue #720): when inside a prepended
 # method or a shadow, super dispatches to a synthetic on the
 # same class. Mirror the spinel_analyze.rb arm.
        prep_target_st = prep_super_target(@current_class_idx, @current_method_name)
        if prep_target_st != ""
          ret_pt = cls_method_return(@current_class_idx, prep_target_st)
          if ret_pt != ""
            return ret_pt
          end
        end
        super_mname_st = prep_super_parent_mname(@current_class_idx, @current_method_name)
        parent_name_st = @cls_parents[@current_class_idx]
        if parent_name_st != ""
          parent_ci_st = find_class_idx(parent_name_st)
          if parent_ci_st >= 0
            owner_st = find_method_owner(parent_ci_st, super_mname_st)
            if owner_st != ""
              ret_st = cls_method_return(find_class_idx(owner_st), super_mname_st)
              if ret_st != ""
                return ret_st
              end
            end
          end
        end
      end
      return "int"
    end
 # Leaf literal-shaped nodes. analyze caches these for nearly
 # every reachable site, but ieval bodies (instance_eval-rewritten
 # method calls) aren't visited by walk_and_cache, so the fallback
 # has to handle them or compile_call would mis-type a "/" arg as
 # int and dispatch sp_int_to_s on a string.
    if t == "IntegerNode"
      return "int"
    end
    if t == "FloatNode"
      return "float"
    end
    if t == "StringNode" || t == "SourceFileNode" || t == "NumberedReferenceReadNode" || t == "InterpolatedStringNode" || t == "InterpolatedSymbolNode" || t == "BackReferenceReadNode" || t == "XStringNode" || t == "InterpolatedXStringNode"
      return "string"
    end
    if t == "SourceEncodingNode"
      return "encoding"
    end
    if t == "SymbolNode"
      return "symbol"
    end
    if t == "MatchWriteNode"
      return "int"
    end
    if t == "TrueNode" || t == "FalseNode"
      return "bool"
    end
    if t == "NilNode"
      return "nil"
    end
    if t == "ArrayNode"
      return infer_array_elem_type(nid)
    end
    if t == "HashNode"
      if is_int_array_lowered_hash(nid) == 1
        return infer_int_keyed_hash_as_array_type(nid)
      end
      return infer_hash_val_type(nid)
    end
    if t == "RangeNode"
      return "range"
    end
    if t == "RescueModifierNode"
 # `expr rescue fallback` — unify the types of the two branches.
 # The fallback always runs on error, so prefer its type when the
 # main branch is a noreturn-shaped expression like a bare `raise`
 # (whose compile_expr returns the int literal `0`).
      t1 = infer_type(@nd_expression[nid])
      t2 = infer_type(@nd_else_clause[nid])
      if t1 == t2
        return t1
      end
      if t2 != "void" && t2 != "nil"
        return t2
      end
      return t1
    end
    if t == "ReturnNode"
 # `return X` evaluated in expression position — same shape as
 # collect_return_types' ReturnNode arm in spinel_analyze.rb.
 # Without this case the universal `"int"` fallback fires; in
 # practice that's demoted by unify_return_type's int-as-sentinel
 # logic when paired with a concrete type from collect_return_types,
 # but returning the actual arg type makes infer_type semantically
 # correct and resilient to future sentinel-handling changes.
 # `return a, b` materializes as a fixed-arity tuple; bare `return`
 # contributes "nil" matching CRuby.
      args_id = @nd_arguments[nid]
      if args_id >= 0
        arg_ids = get_args(args_id)
        if arg_ids.length == 1
          return infer_type(arg_ids[0])
        end
        if arg_ids.length > 1
          return tuple_type_from_elems(arg_ids)
        end
      end
      return "nil"
    end
    if t == "BeginNode"
 # Method bodies that end in `def f; X; rescue; Y; end` need
 # the method's inferred return type to unify both branches.
 # Without this arm spinel falls back to int (the default), and
 # string-returning rescue bodies fail C compilation when the
 # ret_tmp slot's type doesn't match the value being assigned.
      types_b = "".split(",", -1)
      bodies_b = begin_node_arm_bodies(nid)
      bi = 0
      while bi < bodies_b.length
        bstmts = get_stmts(bodies_b[bi])
        if bstmts.length > 0
          types_b.push(infer_type(bstmts.last))
        end
        bi = bi + 1
      end
      if types_b.length > 0
        return unify_return_type(types_b)
      end
      return "void"
    end
    if t == "LocalVariableReadNode"
      vt = find_var_type(@nd_name[nid])
      if vt != ""
        return vt
      end
      return "int"
    end
    if t == "LocalVariableWriteNode"
 # `var = expr` used as an expression — the value of the
 # expression is the assigned slot's value (after any boxing
 # done by the LocalVariableWriteNode emit path). Reporting the
 # slot type lets compile_cond_expr know to wrap with
 # sp_poly_truthy when the slot is poly (e.g.
 # `if (sprite = arr[i])` where sprite is a sp_RbVal local).
      vt = find_var_type(@nd_name[nid])
      if vt != ""
        return vt
      end
      return infer_type(@nd_expression[nid])
    end
    if t == "IndexOrWriteNode" || t == "IndexAndWriteNode" || t == "IndexOperatorWriteNode"
 # `recv[k] ||= v` (etc.) as an expression value. The result type
 # is the recv's element type — same shape as Hash#[] / Array#[]
 # — so callers like LocalVariableWriteNode can pick the right
 # local slot type via the same lookup that `recv[k]` would use.
      iow_recv_t = @nd_receiver[nid]
      if iow_recv_t >= 0
        rt_iow_t = infer_type(iow_recv_t)
        leaf_iow = hash_leaf_type(rt_iow_t)
        if leaf_iow != ""
          return leaf_iow
        end
        if rt_iow_t == "int_array" || rt_iow_t == "float_array" || rt_iow_t == "str_array" || rt_iow_t == "sym_array"
          return elem_type_of_array(rt_iow_t)
        end
 # poly_array elements are sp_RbVal; chained IndexOrWriteNode
 # over a poly_array recv (or a poly-typed recv that carries a
 # poly_array at runtime) returns the element value as poly so
 # the next chain link sees an sp_RbVal, not the int default.
        if rt_iow_t == "poly_array" || rt_iow_t == "poly"
          return "poly"
        end
      end
      return "int"
    end
    if t == "GlobalVariableReadNode"
 # `alias $copy $orig` -- a $copy read must look up $orig's
 # registered type so the C codegen sees the correct format
 # specifier when interpolating or printing.
      gname = resolve_gvar_alias(@nd_name[nid])
      gi = 0
      while gi < @gvar_names.length
        if @gvar_names[gi] == gname
          return @gvar_types[gi]
        end
        gi = gi + 1
      end
      return "int"
    end
    if t == "InstanceVariableOrWriteNode" || t == "InstanceVariableAndWriteNode"
 # `(@x ||= expr)` / `(@x &&= expr)` evaluates to @x's slot type
 # (union of the prior value and the rhs, but Spinel widens those
 # via update_ivar_type already, so reading the slot type is the
 # same answer).
      if @current_class_idx >= 0
        return cls_ivar_type(@current_class_idx, @nd_name[nid])
      end
      return "int"
    end
    if t == "InstanceVariableReadNode"
      if @current_class_idx >= 0
        return cls_ivar_type(@current_class_idx, @nd_name[nid])
      end
 # Inside a module class method (`def self.foo` in `module M`,
 # compiled as the top-level `M_cls_foo`), an ivar read like
 # `@slots` resolves to `cst_M_slots` — already handled by
 # compile_expr's matching arm. Mirror that resolution here so
 # infer_type returns the slot's recorded hash/array type
 # instead of the "int" default, which would otherwise route
 # `@slots[k]` through the int-bit-extract codegen even though
 # the storage is a hash.
      mi3 = 0
      while mi3 < @module_names.length
        mmod = @module_names[mi3]
        if mmod != "" && @current_method_name.start_with?(mmod + "_cls_")
          iname = @nd_name[nid]
          cname3 = mmod + "_" + iname[1, iname.length - 1]
          ci3 = find_const_idx(cname3)
          if ci3 >= 0
            return @const_types[ci3]
          end
        end
        mi3 = mi3 + 1
      end
      tit = toplevel_ivar_type(@nd_name[nid])
      if tit != ""
        return tit
      end
      return "int"
    end
    if t == "ClassVariableReadNode"
      qname = cvar_qname(@current_class_idx, @nd_name[nid])
      ci = find_cvar_idx(qname)
      if ci >= 0
        return @cvar_types[ci]
      end
      return "int"
    end
    if t == "ClassVariableWriteNode"
 # `@@x = expr` as an expression returns the assigned value, so
 # the static type is the rhs's type. Without this case the
 # caller's `infer_type` falls through to the default (int) and
 # surrounding code -- e.g. a method whose body's last
 # expression is `@@x = v` -- gets `mrb_int` as the inferred
 # return, producing a const char* / mrb_int mismatch when v
 # is a string.
      return infer_type(@nd_expression[nid])
    end
    if t == "ConstantReadNode"
      if @nd_name[nid] == "ARGV"
        return "argv"
      end
      rname = resolve_const_read_name(@nd_name[nid])
      ci = find_const_idx(rname)
      if ci >= 0
        return @const_types[ci]
      end
      cx = find_class_idx(rname)
      if cx >= 0
 # a class constant in value position is
 # a sp_Class value carrying its cls_id. Other call sites that
 # still want the "this name is a class, not a value" signal
 # (constructor lookups, class-method dispatch) consult
 # find_class_idx directly via constructor_class_name and
 # never call infer_type on the receiver.
        return "class"
      end
      return "int"
    end
    if t == "ConstantPathNode"
      cpname = resolve_const_ref_name(nid)
      if cpname != ""
        ci = find_const_idx(cpname)
        if ci >= 0
          return @const_types[ci]
        end
        cx = find_class_idx(cpname)
        if cx >= 0
 # class constant in value position.
          return "class"
        end
      end
      parent = @nd_receiver[nid]
      if parent >= 0
        rname = resolve_const_ref_name(parent)
        if rname == "Float"
          return "float"
        end
        if rname == "Math"
          return "float"
        end
      end
      return "int"
    end
    if t == "CallNode"
 # CallNode falls here only on cache miss. analyze's
 # walk_and_cache covers ~99% of CallNodes; the remaining
 # misses are:
 # - bare `new` in an inherited class method body —
 # resolution depends on the calling subclass at emit time,
 # not the lexical class, so analyze can't safely cache)
 # - block bodies of proc / lambda / Fiber.new / Proc.new
 # (skipped because the param's runtime type depends on the
 # caller, and codegen's compile_lambda_def hardcodes the
 # param as int regardless)
 # Bare `new` resolves via current_class_method_owning_class so
 # subclass-context-sensitive constructions land on the right
 # class. Everything else defaults to "int" — for proc/lambda
 # block bodies that matches compile_lambda_def's hardcoded
 # param type.
      if @nd_name[nid] == "new" && @nd_receiver[nid] < 0
        implicit = current_class_method_owning_class
        if implicit != ""
          return "obj_" + implicit
        end
      end
 # Bare class-method call inside a class-method body (`def
 # self.last; all[-1]; end` — both `all` and `last` are cmeths
 # on the same class hierarchy). analyze skips the cache for
 # these nodes (see analyze's walk_and_cache skip_cache arm)
 # because inherited bodies share AST node ids across subclass
 # copies; the resolution must follow the *current* emit-time
 # @current_class_idx, not whichever class walked last during
 # annotate. Mirror analyze's @cls_cmeth_returns lookup so the
 # cache-miss path picks up the subclass's override. Issue #523.
      if @nd_receiver[nid] < 0 && @current_class_idx >= 0 && @current_method_has_self == 0
        mn_cmeth = @nd_name[nid]
        cmnames_cm_dispatch = @cls_cmeth_names[@current_class_idx].split(";", -1)
        cmreturns_cm_dispatch = @cls_cmeth_returns[@current_class_idx].split(";", -1)
        kk_cm = 0
        while kk_cm < cmnames_cm_dispatch.length
          if cmnames_cm_dispatch[kk_cm] == mn_cmeth && kk_cm < cmreturns_cm_dispatch.length
            return cmreturns_cm_dispatch[kk_cm]
          end
          kk_cm = kk_cm + 1
        end
      end
 # Comparison / boolean operators always return bool, regardless
 # of recv type. scan_lambda_ret_types calls infer_type on a
 # lambda body's last expr — when that's `a > b` inside a
 # lambda body that walk_and_cache skipped, the cache misses
 # and this fallback used to default to "int", which made the
 # outer `.to_s` emit `sp_int_to_s(...)` instead of the bool
 # ternary `(... ? "true" : "false")`.
      cmp_mname = @nd_name[nid]
      if cmp_mname == "block_given?"
        cmp_recv = @nd_receiver[nid]
        if cmp_recv < 0 || (cmp_recv >= 0 && @nd_type[cmp_recv] == "SelfNode")
          return "bool"
        end
      end
      if cmp_mname == "<" || cmp_mname == ">" || cmp_mname == "<=" || cmp_mname == ">=" || cmp_mname == "==" || cmp_mname == "!=" || cmp_mname == "===" || cmp_mname == "eql?" || cmp_mname == "equal?" || cmp_mname == "is_a?" || cmp_mname == "kind_of?" || cmp_mname == "instance_of?" || cmp_mname == "respond_to?" || cmp_mname == "include?" || cmp_mname == "start_with?" || cmp_mname == "end_with?" || cmp_mname == "match?" || cmp_mname == "empty?" || cmp_mname == "nil?" || cmp_mname == "zero?" || cmp_mname == "even?" || cmp_mname == "odd?" || cmp_mname == "frozen?"
        return "bool"
      end
 # `+` on string recv returns string — walk_and_cache skips
 # block bodies of `each`-family / proc / lambda, so a chained
 # concat like `puts k + ": " + v.to_s` inside a hash `.each do
 # |k, v|` block hits this cache-miss path. Without this arm
 # infer_type fell back to the "int" default below, the inner
 # `k + ": "` got typed as int, and `puts` lowered to
 # `printf("%lld", (long long)(string_call + int_call))` — both
 # the cast and the raw `+` between pointers fail C compile.
      if cmp_mname == "+"
        cm_recv = @nd_receiver[nid]
        if cm_recv >= 0
          cm_rt = infer_type(cm_recv)
          if cm_rt == "string" || cm_rt == "mutable_str"
            return "string"
          end
        end
      end
 # `.to_s` returns string regardless of recv (the only exception
 # is `obj.to_s` falling through to a user-defined `to_s` that
 # returned something else — rare; the cache covers that case).
      if cmp_mname == "to_s"
        return "string"
      end
 # `lv.call(...)` / `lv.()` on a lambda local — recover the
 # lambda's recorded return type from @lambda_var_ret_*.
 # walk_and_cache skips lambda bodies, so the call itself isn't
 # cached; without this the outer `.to_s` (etc.) would default
 # to "int" and emit sp_int_to_s on a bool/string return.
      if cmp_mname == "call" || cmp_mname == "[]"
        cmp_recv = @nd_receiver[nid]
        if cmp_recv >= 0 && @nd_type[cmp_recv] == "LocalVariableReadNode"
          lrt = lambda_var_ret_type(@nd_name[cmp_recv])
          if lrt != ""
            return lrt
          end
        end
      end
 # Generic `obj.method(...)` cache-miss path: when the recv is
 # statically a user-class instance and the class defines a method
 # of that name, route through cls_method_return so the now-
 # promoted return type flows up. Without this, promote-mode CallNodes
 # that walk_and_cache skipped (or that annotated as stale "int"
 # before the promote sweep) silently default to "int" and the
 # outer return / arith arms double-wrap with sp_bigint_new_int.
      cmp_recv_obj = @nd_receiver[nid]
      if cmp_recv_obj >= 0
        cmp_recv_t_obj = base_type(infer_type(cmp_recv_obj))
        if is_obj_type(cmp_recv_t_obj) == 1
          cmp_cn_obj = cmp_recv_t_obj[4, cmp_recv_t_obj.length - 4]
          cmp_ci_obj = find_class_idx(cmp_cn_obj)
          if cmp_ci_obj >= 0
            cmp_names_obj = @cls_meth_names[cmp_ci_obj].split(";", -1)
            cmp_returns_obj = @cls_meth_returns[cmp_ci_obj].split(";", -1)
            cmp_jj_obj = 0
            while cmp_jj_obj < cmp_names_obj.length
              if cmp_names_obj[cmp_jj_obj] == cmp_mname && cmp_jj_obj < cmp_returns_obj.length
                cmp_ret_obj = cmp_returns_obj[cmp_jj_obj]
                if cmp_ret_obj != ""
                  return cmp_ret_obj
                end
              end
              cmp_jj_obj = cmp_jj_obj + 1
            end
          end
        end
      end
      return "int"
    end
    if t == "IfNode"
      then_type = "nil"
      body = @nd_body[nid]
      if body >= 0
        stmts = get_stmts(body)
        if stmts.length > 0
          then_type = infer_type(stmts.last)
        end
      end
      else_type = "nil"
      sub = @nd_subsequent[nid]
      if sub >= 0
        if @nd_type[sub] == "ElseNode"
          ebody = @nd_body[sub]
          if ebody >= 0
            es = get_stmts(ebody)
            if es.length > 0
              else_type = infer_type(es.last)
            end
          end
        else
 # elsif chain — recurse
          else_type = infer_type(sub)
        end
      end
      types = "".split(",", -1)
      types.push(then_type)
      types.push(else_type)
      return unify_return_type(types)
    end
    if t == "CaseMatchNode"
      types = "".split(",", -1)
      conds = parse_id_list(@nd_conditions[nid])
      k = 0
      while k < conds.length
        inid = conds[k]
        if @nd_type[inid] == "InNode"
          ibody = @nd_body[inid]
          if ibody >= 0
            is = get_stmts(ibody)
            if is.length > 0
              types.push(infer_type(is.last))
            end
          end
        end
        k = k + 1
      end
      ec = @nd_else_clause[nid]
      if ec >= 0
        ebody = @nd_body[ec]
        if ebody >= 0
          es = get_stmts(ebody)
          if es.length > 0
            types.push(infer_type(es.last))
          end
        end
      end
      if types.length > 0
        return unify_return_type(types)
      end
      return "int"
    end
    if t == "CaseNode"
      types = "".split(",", -1)
      conds = parse_id_list(@nd_conditions[nid])
      k = 0
      while k < conds.length
        wid = conds[k]
        if @nd_type[wid] == "WhenNode"
          wbody = @nd_body[wid]
          if wbody >= 0
            ws = get_stmts(wbody)
            if ws.length > 0
              types.push(infer_type(ws.last))
            end
          end
        end
        k = k + 1
      end
      ec = @nd_else_clause[nid]
      if ec >= 0
        ebody = @nd_body[ec]
        if ebody >= 0
          es = get_stmts(ebody)
          if es.length > 0
            types.push(infer_type(es.last))
          end
        end
      end
      if types.length > 0
        return unify_return_type(types)
      end
      return "int"
    end
    if t == "AndNode"
      return "bool"
    end
    if t == "OrNode"
      return or_result_type(nid)
    end
    if t == "ParenthesesNode"
      body = @nd_body[nid]
      if body >= 0
        stmts = get_stmts(body)
        if stmts.length > 0
          return infer_type(stmts.last)
        end
      end
      return "void"
    end
    if t == "SelfNode"
      if @current_class_idx >= 0
        return "obj_" + @cls_names[@current_class_idx]
      end
      st = find_var_type("__self_type")
      if st != ""
        return st
      end
      return "int"
    end
    if t == "LambdaNode"
 # Record return type if inside a variable assignment context
      lbody = @nd_body[nid]
      if lbody >= 0
        lbs = get_stmts(lbody)
        if lbs.length > 0
          lrt = infer_type(lbs.last)
          @last_lambda_ret_type = lrt
        end
      end
      return "lambda"
    end
    "int"
  end

  def infer_array_elem_type(nid)
    infer_array_elem_type_from_ids(parse_id_list(@nd_elements[nid]))
  end

 # Body of infer_array_elem_type, parameterised on the list of value
 # node ids. Lets a {0=>v0,1=>v1,...} HashNode lowered to an Array
 # share the same type-inference logic by feeding in [v0, v1, ...]
 # without needing an actual ArrayNode to host them.
  def infer_array_elem_type_from_ids(elems)
    if elems.length > 0
      et = infer_type(elems[0])
      if et == "symbol"
 # Check if ALL elements are symbols
        all_sym = 1
        k = 1
        while k < elems.length
          if infer_type(elems[k]) != "symbol"
            all_sym = 0
          end
          k = k + 1
        end
        if all_sym == 1
          return "sym_array"
        end
        return "poly_array"
      end
      if et == "string"
 # Check if ALL elements are strings
        all_str = 1
        k = 1
        while k < elems.length
          if infer_type(elems[k]) != "string"
            all_str = 0
          end
          k = k + 1
        end
        if all_str == 1
          return "str_array"
        end
        return "poly_array"
      end
      if et == "float"
 # Check if ALL elements are float
        all_float = 1
        k = 1
        while k < elems.length
          if infer_type(elems[k]) != "float"
            all_float = 0
          end
          k = k + 1
        end
        if all_float == 1
          return "float_array"
        end
      end
 # Check if all elements are the same obj type → ptr_array
      if is_obj_type(et) == 1
        all_same = 1
        k = 1
        while k < elems.length
          if infer_type(elems[k]) != et
            all_same = 0
          end
          k = k + 1
        end
        if all_same == 1
          @needs_gc = 1
          return et + "_ptr_array"
        end
        return "poly_array"
      end
 # Check if all elements are the same array type → array of arrays
      if et == "int_array" || et == "str_array" || et == "float_array" || et == "sym_array"
        all_same = 1
        k = 1
        while k < elems.length
          if infer_type(elems[k]) != et
            all_same = 0
          end
          k = k + 1
        end
        if all_same == 1
          @needs_gc = 1
          return et + "_ptr_array"
        end
        return "poly_array"
      end
 # Nested-deeper case: elements are themselves a typed
 # ptr_array (`int_array_ptr_array`, etc.) or already
 # poly_array. Spinel doesn't have a typed
 # `<X>_ptr_array_ptr_array` slot, so box each level via
 # poly_array — sp_box_*_array on each push, and the
 # poly-builtin dispatch on `[]` recurses into the next
 # level.
      if is_ptr_array_type(et) == 1 || et == "poly_array"
        @needs_gc = 1
        @needs_rb_value = 1
        return "poly_array"
      end
 # Hash literals as elements (`[{n: 3}, {n: 1}]`): each
 # element is a heap-allocated hash pointer. Spinel has no
 # typed `<hash>_ptr_array` slot, so box via poly_array;
 # sp_box_hash_to_poly is called on each push and the
 # poly-builtin dispatch on `arr[i]` recovers the hash.
 # Without this arm, the array's inferred type fell back to
 # `int_array` (the bottom of this function), and
 # `sp_IntArray_push` was called with a hash pointer —
 # int-from-pointer C-compile error.
      if is_hash_type(et) == 1
        @needs_gc = 1
        @needs_rb_value = 1
        return "poly_array"
      end
 # Proc / lambda literals as elements (`[proc { ... }, proc { ... }]`):
 # see the analyzer's mirror branch. Spinel has no typed
 # `proc_ptr_array` slot, so box via poly_array — sp_box_proc on
 # each push.
      if et == "proc" || et == "lambda"
        @needs_gc = 1
        @needs_rb_value = 1
        return "poly_array"
      end
 # `String.new` (and locals widened to mutable_str via `s = ""; s << ...`)
 # produces sp_String* values. Lower an all-mutable_str literal to a
 # mutable_str_ptr_array — a sp_PtrArray of sp_String* — so the generic
 # `<X>_ptr_array` codegen path (length/push/pop/[]) works without
 # truncating the pointer to int. Mirrors the analyzer's arm; issue #519.
      if et == "mutable_str"
        all_same = 1
        k = 1
        while k < elems.length
          if infer_type(elems[k]) != "mutable_str"
            all_same = 0
          end
          k = k + 1
        end
        if all_same == 1
          @needs_gc = 1
          return "mutable_str_ptr_array"
        end
        @needs_gc = 1
        @needs_rb_value = 1
        return "poly_array"
      end
 # Check if elements have mixed types
      k = 1
      while k < elems.length
        et2 = infer_type(elems[k])
        if et2 != et
 # Under promote mode int / bigint share IntArray storage (the
 # literal-side codegen unboxes any sp_Bigint* element via
 # sp_bigint_to_int before the push). Stale-int cache on an arith
 # CallNode whose actual emit is bigint shows up here as et2=int
 # while a sibling LV read sees et=bigint -- recognize the pair
 # as compatible instead of widening to poly_array.
          if @int_overflow_mode == "promote" && (et == "int" || et == "bigint") && (et2 == "int" || et2 == "bigint")
 # compatible; continue
          else
            return "poly_array"
          end
        end
        k = k + 1
      end
    end
    "int_array"
  end

 # Detects a Hash literal whose keys are the consecutive non-negative
 # integers 0, 1, ..., N-1 in source order. Such a literal is
 # semantically equivalent to the Array `[v0, v1, ..., vN-1]` for the
 # common `H[k]` lookup pattern, so we lower it to an Array
 # internally — no `int_<X>_hash` runtime type needed. Detection is
 # AST-shape only (IntegerNode key with literal value `k` at index
 # `k`); any deviation (gap, duplicate, non-integer key, splat) opts
 # back into the regular hash codegen.
  def is_int_array_lowered_hash(nid)
    if @nd_type[nid] != "HashNode"
      return 0
    end
    elems = parse_id_list(@nd_elements[nid])
    if elems.length == 0
      return 0
    end
    k = 0
    while k < elems.length
      eid = elems[k]
      if @nd_type[eid] != "AssocNode"
        return 0
      end
      kid = @nd_key[eid]
      if kid < 0 || @nd_type[kid] != "IntegerNode"
        return 0
      end
      if @nd_value[kid].to_i != k
        return 0
      end
      k = k + 1
    end
    1
  end

 # Returns the array type the lowered HashNode evaluates to. Same
 # logic as infer_array_elem_type but reads each AssocNode's value.
  def infer_int_keyed_hash_as_array_type(nid)
    elems = parse_id_list(@nd_elements[nid])
    vids = []
    k = 0
    while k < elems.length
      vids.push(@nd_expression[elems[k]])
      k = k + 1
    end
    infer_array_elem_type_from_ids(vids)
  end

  def infer_hash_val_type(nid)
    elems = parse_id_list(@nd_elements[nid])
    if elems.length > 0
      eid = elems[0]
      if @nd_type[eid] == "AssocNode"
        first_vt = infer_type(@nd_expression[eid])
 # Check if all values have the same type. Treat int and bigint
 # as compatible under promote mode (both lower to mrb_int slot
 # storage with sp_bigint_to_int unboxing at the set/get sites)
 # so a `{n:, sum: 18}` literal where n is bigint and 18 is an
 # int literal stays sym_int_hash instead of escalating to
 # sym_poly_hash and mismatching the analyzer's scan_locals slot.
        first_vt_norm = (first_vt == "bigint") ? "int" : first_vt
        all_same = 1
        k = 1
        while k < elems.length
          eid2 = elems[k]
          if @nd_type[eid2] == "AssocNode"
            vt2 = infer_type(@nd_expression[eid2])
            vt2_norm = (vt2 == "bigint") ? "int" : vt2
            if vt2_norm != first_vt_norm
              all_same = 0
            end
          end
          k = k + 1
        end
 # Detect all-symbol keys → sym_int_hash variant for int-valued
 # hashes. (sym_str_hash etc. not yet implemented; they fall
 # through to str_str_hash with sym_to_s wrapping at hash sites.)
        all_sym_keys = 1
        kk = 0
        while kk < elems.length
          ekid = elems[kk]
          if @nd_type[ekid] == "AssocNode"
            kid = @nd_key[ekid]
            if kid < 0 || @nd_type[kid] != "SymbolNode"
              all_sym_keys = 0
            end
          end
          kk = kk + 1
        end
        all_int_keys = 1
        ki = 0
        while ki < elems.length
          ekid2 = elems[ki]
          if @nd_type[ekid2] == "AssocNode"
            kid2 = @nd_key[ekid2]
            if kid2 < 0 || @nd_type[kid2] != "IntegerNode"
              all_int_keys = 0
            end
          end
          ki = ki + 1
        end
        if all_same == 1
          if first_vt == "string"
            if all_int_keys == 1
              return "int_str_hash"
            end
            if all_sym_keys == 1
              return "sym_str_hash"
            end
            return "str_str_hash"
          end
          if all_sym_keys == 1 && (first_vt == "int" || first_vt == "bigint" || first_vt == "bool" || first_vt == "nil")
            return "sym_int_hash"
          end
 # Symbol values get sym_poly_hash storage so dig / lookup
 # preserves the SP_TAG_SYM tag. Issue #555 case 07.
          if all_sym_keys == 1 && first_vt == "symbol"
            @needs_rb_value = 1
            return "sym_poly_hash"
          end
 # Every value already inferred as poly (the slot was
 # widened upstream — typically an ivar that
 # finalize_ivar_heterogeneity widened on a sibling-writer
 # disagreement). Use the same poly-hash storage as the
 # mixed-types `else` branch — every value carries its
 # own tag.
          if first_vt == "poly"
            if all_sym_keys == 1
              return "sym_poly_hash"
            end
            return "str_poly_hash"
          end
 # Inner hash/array values need a poly outer so each pointer
 # can carry its own cls_id through SP_TAG_OBJ.
          if is_hash_type(first_vt) == 1 || is_array_type(first_vt) == 1
            if all_sym_keys == 1
              return "sym_poly_hash"
            end
            if all_int_keys == 0
              return "str_poly_hash"
            end
          end
        else
 # Mixed value types: use a *_poly_hash so each slot carries its
 # own tag (sp_RbVal) rather than coercing everything to one type.
          if all_sym_keys == 1
            return "sym_poly_hash"
          end
 # Mixed-shape keys (IntegerNode + SymbolNode etc.): no single
 # *_poly_hash variant can carry them. Use poly_poly_hash where
 # both key and value are sp_RbVal. Mirrors the analyzer arm.
 # Issue #536: `{ 0 => false, a: 1 }` segfaulted because
 # str_poly_hash was selected and the integer key was passed
 # directly to `sp_StrPolyHash_set` (which dereferences a
 # `const char *`).
          all_str_keys_check = 1
          ksk = 0
          while ksk < elems.length
            ekks = elems[ksk]
            if @nd_type[ekks] == "AssocNode"
              kids = @nd_key[ekks]
              if kids < 0 || (@nd_type[kids] != "StringNode" && @nd_type[kids] != "InterpolatedStringNode" && @nd_type[kids] != "SymbolNode")
                all_str_keys_check = 0
              end
            end
            ksk = ksk + 1
          end
          if all_str_keys_check == 0
            @needs_rb_value = 1
            @needs_poly_poly_hash = 1
            return "poly_poly_hash"
          end
          return "str_poly_hash"
        end
      end
    end
    "str_int_hash"
  end


  def is_class_or_ancestor(cname, target)
    if cname == target
      return 1
    end
    ci = find_class_idx(cname)
    if ci >= 0
      if @cls_parents[ci] != ""
        return is_class_or_ancestor(@cls_parents[ci], target)
      end
    end
    0
  end

 # `is_descendant(child, ancestor)` — 1 iff `child` is a strict
 # (proper) descendant of `ancestor` in the class hierarchy; 0
 # otherwise (including when they're identical). Wraps
 # is_class_or_ancestor, which is descendant-OR-EQUAL.
  def is_descendant(child, ancestor)
    if child == ancestor
      return 0
    end
    is_class_or_ancestor(child, ancestor)
  end

 # `is_value_type_class(cname)` — 1 iff `cname` is a user class
 # marked value-type (stack-allocated, no subclasses by design,
 # no `cls_id` field on the struct). emit_class_fields gates the
 # cls_id emission on the inverse of this; runtime cls_id checks
 # must guard against value-type recvs to avoid referencing a
 # nonexistent struct member.
  def is_value_type_class(cname)
    ci = find_class_idx(cname)
    if ci >= 0 && @cls_is_value_type[ci] == 1
      return 1
    end
    0
  end

  def is_operator_name(name)
    if name == "+"
      return 1
    end
    if name == "-"
      return 1
    end
    if name == "*"
      return 1
    end
    if name == "/"
      return 1
    end
    if name == "%"
      return 1
    end
    if name == "<"
      return 1
    end
    if name == ">"
      return 1
    end
    if name == "<="
      return 1
    end
    if name == ">="
      return 1
    end
    if name == "=="
      return 1
    end
    if name == "!="
      return 1
    end
    if name == "<=>"
      return 1
    end
    0
  end

  def is_obj_type(t)
    if t == nil
      return 0
    end
    if t.length > 4
      if t[0] == "o"
        if t[1] == "b"
          if t[2] == "j"
            if t[3] == "_"
              return 1
            end
          end
        end
      end
    end
    0
  end

 # Check if type is a ptr_array (e.g., "obj_Planet_ptr_array")
  def is_ptr_array_type(t)
    if t != nil && t.length > 10
      if t.end_with?("_ptr_array")
        return 1
      end
    end
    0
  end

 # Get element class type from ptr_array type (e.g., "obj_Planet_ptr_array" → "obj_Planet")
  def elem_type_of_array(t)
    if t == "int_array"
      return "int"
    end
    if t == "str_array"
      return "string"
    end
    if t == "float_array"
      return "float"
    end
    if t == "sym_array"
      return "symbol"
    end
    if t == "poly_array"
      return "poly"
    end
    if is_ptr_array_type(t) == 1
      return ptr_array_elem_type(t)
    end
    "int"
  end

  def ptr_array_elem_type(t)
    if is_ptr_array_type(t) == 1
      return t[0, t.length - 10]
    end
    ""
  end

 # ---- Tuple type helpers ----
  def is_tuple_type(t)
    if t != nil && t.length > 6
      if t[0] == "t" && t[1] == "u" && t[2] == "p" && t[3] == "l" && t[4] == "e" && t[5] == ":"
 # Exclude ptr_array of tuples
        if is_ptr_array_type(t) == 1
          return 0
        end
        return 1
      end
    end
    0
  end

  def tuple_elem_types_str(t)
 # "tuple:int,string" → "int,string"
    t[6, t.length - 6]
  end

  def tuple_elem_type_at(t, idx)
    parts = tuple_elem_types_str(t).split(",", -1)
    if idx < parts.length
      return parts[idx]
    end
    "int"
  end

  def tuple_arity(t)
    tuple_elem_types_str(t).split(",", -1).length
  end

 # Issue #878: dirname of the source file path baked into the
 # AST. Memoized; the parser writes the same toplevel path into
 # every SourceFileNode's content (require/require_relative are
 # inlined at parse time so we lose per-site source mapping --
 # same documented limitation as __FILE__). For files passed as
 # a relative path, the result is also relative.
  def source_file_dirname
    if @source_file_dirname_cache != nil
      return @source_file_dirname_cache
    end
 # Parser emits SOURCE_FILE near the top of the AST. Fall back
 # to scanning for SourceFileNode (set by `__FILE__`) for older
 # AST files that predate the SOURCE_FILE prelude.
    path = ""
    if @source_file_path != nil
      path = @source_file_path
    end
    if path == ""
      i = 0
      while i < @nd_type.length
        if @nd_type[i] == "SourceFileNode"
          path = @nd_content[i]
          i = @nd_type.length
        else
          i = i + 1
        end
      end
    end
    if path == ""
      @source_file_dirname_cache = "."
      return @source_file_dirname_cache
    end
    last_slash = -1
    j = 0
    while j < path.length
      if path[j] == "/"
        last_slash = j
      end
      j = j + 1
    end
    if last_slash < 0
      @source_file_dirname_cache = "."
    elsif last_slash == 0
      @source_file_dirname_cache = "/"
    else
      @source_file_dirname_cache = path[0, last_slash]
    end
    @source_file_dirname_cache
  end

  def tuple_c_name(t)
 # "tuple:int,string" → "sp_Tuple_int_string". base_type strips
 # nullable `?` suffixes: a tuple of int? has the same C storage
 # as a tuple of int (mrb_int either way; the nil sentinel lives
 # in-band as SP_INT_NIL). Without this an int_array#pop return
 # widens the surrounding tuple type to `sp_Tuple_int?_...` whose
 # `?` is an illegal C identifier char. #832 follow-up.
    parts = tuple_elem_types_str(t).split(",", -1)
    out = "".split(",", -1)
    k = 0
    while k < parts.length
      out.push(base_type(parts[k]))
      k = k + 1
    end
    "sp_Tuple_" + out.join("_")
  end

 # Whether a tuple element type must be traced by the GC scan function.
 # Scalars (int/float/bool/symbol) are pure values; pointer-to-GC-object
 # element types must be marked, otherwise the GC frees the inner object
 # while the tuple keeps a dangling pointer.
  def tuple_field_needs_mark(et)
    if gc_trace_kind(et) != "none"
      return 1
    end
    0
  end

 # Returns the scan function name for the tuple, or "NULL" if no field
 # requires marking.
  def tuple_scan_name(t)
    parts = tuple_elem_types_str(t).split(",", -1)
    fi = 0
    while fi < parts.length
      if tuple_field_needs_mark(parts[fi]) == 1
        return tuple_c_name(t) + "_scan"
      end
      fi = fi + 1
    end
    "NULL"
  end

  def register_tuple_type(t)
    if is_tuple_type(t) == 1
      k = 0
      found = 0
      while k < @tuple_types.length
        if @tuple_types[k] == t
          found = 1
        end
        k = k + 1
      end
      if found == 0
        @tuple_types.push(t)
      end
    end
  end

 # Build "tuple:T0,T1,..." from a list of element node ids and register it.
  def tuple_type_from_elems(elems)
    parts = "".split(",", -1)
    k = 0
    while k < elems.length
      parts.push(infer_type(elems[k]))
      k = k + 1
    end
    tt = "tuple:" + parts.join(",")
    register_tuple_type(tt)
    tt
  end

 # Type for the splat target in `a, *b = rhs`. Returns the rhs's array
 # type (so `b` is a typed-array of the same element type).
  def splat_rest_type(val_id)
    if val_id < 0
      return "int_array"
    end
    rt = infer_type(val_id)
    if rt == "int_array" || rt == "str_array" || rt == "float_array" || rt == "sym_array" || rt == "poly_array"
      return rt
    end
    if is_ptr_array_type(rt) == 1
      return rt
    end
    "int_array"
  end

  def is_splat_with_target(nid)
    if nid < 0
      return 0
    end
    if @nd_type[nid] != "SplatNode"
      return 0
    end
    if @nd_expression[nid] < 0
      return 0
    end
    1
  end

  def type_is_pointer(t)
    if is_nullable_type(t) == 1
      t = base_type(t)
    end
 # Raw C pointer (FFI). Intentionally NOT a GC pointer — foreign
 # pointers are user-managed and the GC must not trace or free them.
    if t == "ptr"
      return 0
    end
    if t == "int_array"
      return 1
    end
    if t == "float_array"
      return 1
    end
    if is_ptr_array_type(t) == 1
      return 1
    end
    if t == "str_array"
      return 1
    end
    if t == "str_int_hash"
      return 1
    end
    if t == "str_str_hash"
      return 1
    end
    if t == "int_str_hash"
      return 1
    end
    if t == "int_int_hash"
      return 1
    end
    if t == "sym_int_hash"
      return 1
    end
    if t == "sym_str_hash"
      return 1
    end
    if t == "str_poly_hash"
      return 1
    end
    if t == "sym_poly_hash"
      return 1
    end
    if t == "poly_poly_hash"
      return 1
    end
    if t == "sym_array"
      return 1
    end
    if t == "poly_array"
      return 1
    end
    if t == "lambda"
      return 1
    end
    if t == "mutable_str"
      return 1
    end
    if t == "string"
      return 1
    end
    if t == "fiber" || t == "bigint"
      return 1
    end
    if t == "proc"
      return 1
    end
    if t == "exception"
      return 1
    end
    if t == "stringscanner"
      return 1
    end
    if is_obj_type(t) == 1
      cname = t[4, t.length - 4]
      ci = find_class_idx(cname)
      if ci >= 0 && @cls_is_value_type[ci] == 1
        return 0
      end
      return 1
    end
    if is_tuple_type(t) == 1
      return 1
    end
    0
  end

 # Check if evaluating an expression might trigger GC allocation
  def expr_may_gc(nid)
    if nid < 0
      return 0
    end
    t = @nd_type[nid]
    if t == "IntegerNode" || t == "FloatNode" || t == "StringNode"
      return 0
    end
    if t == "SymbolNode" || t == "TrueNode" || t == "FalseNode" || t == "NilNode"
      return 0
    end
    if t == "LocalVariableReadNode" || t == "SelfNode"
      return 0
    end
    if t == "InstanceVariableReadNode" || t == "ConstantReadNode"
      return 0
    end
    1
  end

  def is_nullable_type(t)
    if t.length > 1 && t[t.length - 1] == "?"
      return 1
    end
    0
  end

 # Empty `[]` / `{}` literals need deferred element-type resolution
 # — the type can only be settled by later writes. This helper
 # distinguishes `[]` from `[1, 2, 3]` so the promotion machinery
 # can recognize "writes haven't fixed the element type yet, so a
 # later push can still pick it".
  def is_empty_hash_literal(nid)
    if nid < 0
      return 0
    end
    if @nd_type[nid] != "HashNode"
      return 0
    end
    elems = parse_id_list(@nd_elements[nid])
    if elems.length == 0
      return 1
    end
    0
  end

  def is_empty_array_literal(nid)
    if nid < 0
      return 0
    end
    if @nd_type[nid] != "ArrayNode"
      return 0
    end
    elems = parse_id_list(@nd_elements[nid])
    if elems.length == 0
      return 1
    end
    0
  end

 # `[]` / `[].dup` — an empty array whose static element type is
 # ambiguous. When this is the tail of a block whose result becomes
 # the inner storage of a nested array (`Array.new(N) { [].dup }`,
 # `(0..N).map { [].dup }`), defaulting to `int_array` is unsafe:
 # later pushes of pointer-typed values (3-tuples, IntArrays, etc.)
 # silently truncate the pointer to mrb_int. Use `poly_array` for
 # the inner container instead so push goes through sp_PolyArray
 # (with sp_RbVal slots) and the runtime cls_id dispatch in
 # sp_poly_shl handles any pushed kind correctly.
  def is_empty_array_or_dup(nid)
    if is_empty_array_literal(nid) == 1
      return 1
    end
    if nid < 0
      return 0
    end
    if @nd_type[nid] != "CallNode"
      return 0
    end
    if @nd_name[nid] != "dup"
      return 0
    end
    recv = @nd_receiver[nid]
    if recv < 0
      return 0
    end
    is_empty_array_literal(recv)
  end

 # `[nil] * N` / `[0] * N` is a sized empty default — the elements
 # come from `nil`/`0`, so the array's effective element type is the
 # same as `[]`'s default (int_array). Used by writer-scan and the
 # expected-type-aware compile path so a later typed `arr[i] = obj`
 # write can promote / direct-allocate the right kind of container.
  def is_sized_empty_array_default(nid)
    if nid < 0
      return 0
    end
    if @nd_type[nid] != "CallNode" || @nd_name[nid] != "*"
      return 0
    end
    arr_recv = @nd_receiver[nid]
    if arr_recv < 0 || @nd_type[arr_recv] != "ArrayNode"
      return 0
    end
    recv_elems = parse_id_list(@nd_elements[arr_recv])
 # Restrict to single-element [nil] or [0] literals — the emit
 # paths in compile_expr_for_expected_type / emit_constructor /
 # compile_stmt all multiply by N (the multiplier) and fill with
 # NULL/0, so a multi-element literal would produce length=N
 # instead of length=N*elements, and a non-zero integer literal
 # would silently lose its value. The Gemini review on
 # caught both gaps. Stay tight: only the canonical
 # `[nil] * N` and `[0] * N` shapes.
    if recv_elems.length != 1
      return 0
    end
    ti = recv_elems[0]
    if ti < 0
      return 0
    end
    if @nd_type[ti] == "NilNode"
      return 1
    end
    if @nd_type[ti] == "IntegerNode" && @nd_value[ti].to_i == 0
      return 1
    end
    0
  end

  def base_type(t)
    if t.length > 1 && t[t.length - 1] == "?"
      return t[0, t.length - 1]
    end
    t
  end

 # Scalar nullable types use a reserved sentinel value rather than
 # the NULL pointer encoding of `is_nullable_pointer_type`. For int?
 # the sentinel is SP_INT_NIL (INT64_MIN); future float?/sym?/bool?
 # variants slot in here as the runtime helpers land. Keeps the two
 # nullable encodings (NULL-for-pointer / sentinel-for-scalar) on
 # separate predicates so call-site emit picks the right path.
  def is_scalar_nullable_type(t)
    bt = base_type(t)
    if bt == "int"
      return is_nullable_type(t)
    end
    0
  end

  def is_nullable_pointer_type(t)
 # Pointer types that can represent nil as NULL
    bt = base_type(t)
    if bt == "ptr"
      return 1
    end
    if bt == "regexp"
      return 1
    end
    if bt == "string" || bt == "mutable_str"
      return 1
    end
    if bt == "int_array" || bt == "str_array" || bt == "float_array" || bt == "sym_array"
      return 1
    end
    if bt == "str_int_hash" || bt == "str_str_hash"
      return 1
    end
    if bt == "sym_int_hash" || bt == "sym_str_hash" || bt == "sym_array"
      return 1
    end
    if bt == "str_poly_hash" || bt == "sym_poly_hash"
      return 1
    end
    if bt == "stringio" || bt == "lambda" || bt == "poly_array"
      return 1
    end
    if is_ptr_array_type(bt) == 1
      return 1
    end
    if bt == "fiber" || bt == "bigint" || bt == "exception"
      return 1
    end
    if is_obj_type(bt) == 1
      return 1
    end
    if is_tuple_type(bt) == 1
      return 1
    end
    0
  end

 # True when class `ci` (or any of its parents) has registered `bname` as
 # an attr_writer / attr_accessor or a struct field — i.e. `obj.bname = v`
 # may safely become a direct field write.
  def cls_has_attr_writer(ci, bname)
    if ci < 0
      return 0
    end
    writers = @cls_attr_writers[ci].split(";", -1)
    wi = 0
    while wi < writers.length
      if writers[wi] == bname
        return 1
      end
      wi = wi + 1
    end
    if @cls_parents[ci] != ""
      pi = find_class_idx(@cls_parents[ci])
      if pi >= 0
        return cls_has_attr_writer(pi, bname)
      end
    end
    0
  end

  def is_value_type_obj(t)
    if is_obj_type(t) == 1
      cname = t[4, t.length - 4]
      ci = find_class_idx(cname)
      if ci >= 0 && @cls_is_value_type[ci] == 1
        return 1
      end
    end
    0
  end

 # ---- C type mapping ----
  def c_type(t)
    if is_nullable_type(t) == 1
      t = base_type(t)
    end
    if t == "range"
      return "sp_Range"
    end
    if t == "time"
      return "sp_Time"
    end
    if t == "complex"
      return "sp_Complex"
    end
    if t == "rational"
      return "sp_Rational"
    end
    if t == "int"
      return "mrb_int"
    end
 # Compiled regex pattern. The runtime helpers (sp_re_match_p,
 # sp_re_match etc.) take this pointer; a `regexp` local lets a
 # branch-built pattern survive as a real C value instead of
 # being dropped into the @local_regex_idx side-channel (which
 # can only carry a single static or dyn-cache index).
    if t == "regexp"
      return "mrb_regexp_pattern *"
    end
 # StringScanner is a builtin reference type whose impl lives
 # in lib/sp_strscan.c — the C type is just a pointer to the
 # opaque sp_StringScanner struct declared in sp_runtime.h.
    if t == "stringscanner"
      return "sp_StringScanner *"
    end
 # FFI raw C pointer (void *). See type_is_pointer for GC rules.
    if t == "ptr"
      return "void *"
    end
    if t == "bigint"
      return "sp_Bigint *"
    end
 # First-class exception object: heap-allocated sp_Exception
 # { cls_name; msg }.
    if t == "exception"
      return "sp_Exception *"
    end
    if t == "float"
      return "mrb_float"
    end
    if t == "bool"
      return "mrb_bool"
    end
    if t == "string"
      return "const char *"
    end
    if t == "symbol"
      return "sp_sym"
    end
    if t == "mutable_str"
      return "sp_String *"
    end
    if t == "void"
      return "mrb_int"
    end
    if t == "nil"
      return "mrb_int"
    end
    if t == "int_array"
      return "sp_IntArray *"
    end
    if t == "float_array"
      return "sp_FloatArray *"
    end
    if is_ptr_array_type(t) == 1
      return "sp_PtrArray *"
    end
    if t == "str_array"
      return "sp_StrArray *"
    end
    if t == "str_int_hash"
      return "sp_StrIntHash *"
    end
    if t == "str_str_hash"
      return "sp_StrStrHash *"
    end
    if t == "int_str_hash"
      return "sp_IntStrHash *"
    end
    if t == "int_int_hash"
      return "sp_IntIntHash *"
    end
    if t == "sym_int_hash"
      return "sp_SymIntHash *"
    end
    if t == "sym_str_hash"
      return "sp_SymStrHash *"
    end
    if t == "str_poly_hash"
      return "sp_StrPolyHash *"
    end
    if t == "sym_poly_hash"
      return "sp_SymPolyHash *"
    end
    if t == "poly_poly_hash"
      @needs_poly_poly_hash = 1
      @needs_rb_value = 1
      return "sp_PolyPolyHash *"
    end
    if t == "sym_array"
 # sym_array is an IntArray internally (sp_sym = mrb_int)
      return "sp_IntArray *"
    end
    if is_tuple_type(t) == 1
      return tuple_c_name(t) + " *"
    end
    if t == "fiber"
      return "sp_Fiber *"
    end
    if t == "poly"
      return "sp_RbVal"
    end
    if t == "class"
 # class object as value. Carries the class
 # id so `c.to_s` can index sp_class_names[].
      @needs_class_table = 1
      return "sp_Class"
    end
    if t == "encoding"
      return "sp_Encoding"
    end
    if t == "proc"
      return "sp_Proc *"
    end
    if t == "stringio"
      return "sp_StringIO *"
    end
    if t == "poly_array"
      return "sp_PolyArray *"
    end
    if t == "lambda"
      return "sp_Val *"
    end
    if is_obj_type(t) == 1
      cname = t[4, t.length - 4]
      ci = find_class_idx(cname)
      if ci >= 0 && @cls_is_value_type[ci] == 1
        return "sp_" + cname
      end
      return "sp_" + cname + " *"
    end
    "mrb_int"
  end

  def c_default_val(t)
    if is_nullable_type(t) == 1
 # Scalar-nullable types use a sentinel encoding, not NULL.
 # `int?` defaults to SP_INT_NIL; future int? siblings slot in here
 # before the NULL fallback.
      if is_scalar_nullable_type(t) == 1
        return "SP_INT_NIL"
      end
 # Value-type classes (`obj_<C>?` where C is a value type) lower
 # to a struct, not a pointer — `NULL` is an invalid initializer.
 # Fall through to the value-type branch below by stripping `?`.
      bt_n = base_type(t)
      if is_value_type_obj(bt_n) == 1
        return "{0}"
      end
 # Issue #915: nullable poly / untyped lowers to sp_RbVal (a
 # struct); the function-return-type fallback was emitting bare
 # NULL which doesn't unify with sp_RbVal.
      if bt_n == "poly" || bt_n == "untyped"
        return "sp_box_nil()"
      end
      return "NULL"
    end
 # NOTE: nullable returns above, so rest handles base types only
    if t == "range"
      return "((sp_Range){0,0})"
    end
    if t == "time"
      return "((sp_Time){0,0,0})"
    end
    if t == "complex"
      return "((sp_Complex){0,0})"
    end
    if t == "int"
      return "0"
    end
    if t == "regexp"
      return "NULL"
    end
    if t == "ptr"
      return "NULL"
    end
    if t == "bigint"
      return "NULL"
    end
    if t == "exception"
      return "NULL"
    end
    if t == "float"
      return "0.0"
    end
    if t == "bool"
      return "FALSE"
    end
    if t == "string"
      return "(&(\"\\xff\")[1])"
    end
    if t == "symbol"
      return "((sp_sym)-1)"
    end
    if t == "mutable_str"
      return "NULL"
    end
    if t == "void"
      return "0"
    end
    if t == "nil"
      return "0"
    end
    if t == "poly"
      return "sp_box_nil()"
    end
    if t == "class"
 # -1 is the "no class" sentinel; sp_class_to_s
 # returns "" for it. Locals declared `sp_Class lv_x = ((sp_Class){-1})`
 # are equivalent to nil for to_s purposes.
      return "((sp_Class){-1LL})"
    end
    if t == "encoding"
      return "((sp_Encoding){NULL})"
    end
    if t == "stringio"
      return "NULL"
    end
    if t == "proc"
      return "NULL"
    end
    if type_is_pointer(t) == 1
      return "NULL"
    end
    if is_value_type_obj(t) == 1
      return "{0}"
    end
    "0"
  end

  def c_return_default(t)
 # Like c_default_val but for return statements (compound literal for value types)
    bt = base_type(t)
    if is_value_type_obj(bt) == 1
      return "(" + c_type(bt) + "){0}"
    end
    c_default_val(t)
  end

 # PM_RANGE_FLAGS_EXCLUDE_END = 4: bit 2 set means `...` (exclusive).
  def range_excl_end(rid)
    if (@nd_flags[rid] & 4) != 0
      return 1
    end
    return 0
  end

  def sanitize_name(name)
    if name == "<=>"
      return "_cmp"
    end
    if name == "<="
      return "_le"
    end
    if name == ">="
      return "_ge"
    end
    if name == "<<"
      return "_lshift"
    end
    if name == ">>"
      return "_rshift"
    end
    if name == "<"
      return "_lt"
    end
    if name == ">"
      return "_gt"
    end
    if name == "+"
      return "_plus"
    end
    if name == "-"
      return "_minus"
    end
    if name == "*"
      return "_mul"
    end
    if name == "/"
      return "_div"
    end
    if name == "=="
      return "_eq_eq"
    end
    if name == "!="
      return "_neq"
    end
    if name == "[]"
      return "_aref"
    end
    if name == "[]="
      return "_aset"
    end
    result = ""
    i = 0
    while i < name.length
      ch = name[i]
      if ch == "?"
        result = result + "_p"
      else
        if ch == "!"
          result = result + "_bang"
        else
          if ch == "="
            result = result + "_eq"
          else
            result = result + ch
          end
        end
      end
      i = i + 1
    end
 # Issue #772: C keywords would produce illegal C function names if
 # used as method names (e.g. `def for` -> `sp_X_for`, which is a
 # C `for` keyword in the function-name position). Suffix `_kw` to
 # disambiguate. Covers all C11 keywords commonly hit by
 # define_method experiments.
    if result == "for" || result == "while" || result == "do" || result == "return" ||
       result == "if" || result == "else" || result == "switch" || result == "case" ||
       result == "default" || result == "break" || result == "continue" ||
       result == "goto" || result == "auto" || result == "register" || result == "static" ||
       result == "extern" || result == "typedef" || result == "struct" || result == "union" ||
       result == "enum" || result == "const" || result == "volatile" || result == "restrict" ||
       result == "inline" || result == "void" || result == "char" || result == "short" ||
       result == "int" || result == "long" || result == "float" || result == "double" ||
       result == "signed" || result == "unsigned" || result == "sizeof"
      result = result + "_kw"
    end
    result
  end

  def sanitize_ivar(name)
 # @x → iv_x, x → iv_x
    if name.length > 0 && name[0] == "@"
      return "iv_" + name[1, name.length - 1]
    end
    "iv_" + name
  end

  def toplevel_ivar_type(name)
    i = 0
    while i < @toplevel_ivar_names.length
      if @toplevel_ivar_names[i] == name
        return @toplevel_ivar_types[i]
      end
      i = i + 1
    end
    ""
  end

 # Resolves an ivar lhs / rhs C expression. Three cases:
 #   - inside a module class method (def self.X on a module),
 #     `@x` lowers to the module's `cst_<Mod>_<x>` static --
 #     module class methods have no instance, so `self->iv_x`
 #     would dangle.
 #   - at script-toplevel script scope where the ivar was
 #     registered as a toplevel slot, `iv_<name>` (no self).
 #   - otherwise, `self->iv_<name>` (or `self.iv_<name>` for
 #     value-typed self).
  def ivar_lhs(name)
    mod_slot = module_ivar_const_lhs(name)
    if mod_slot != ""
      return mod_slot
    end
    if @current_class_idx < 0 && toplevel_ivar_type(name) != ""
      return sanitize_ivar(name)
    end
    self_arrow + sanitize_ivar(name)
  end

 # When the current emit scope is a module class method
 # (`def self.X` on a module), the bare `@count` ivar maps to
 # the module's `cst_<Mod>_<name>` static slot rather than a
 # nonexistent `self->iv_count`. Returns the C expression or ""
 # when the current scope isn't a module class method or no
 # matching const is registered.
  def module_ivar_const_lhs(name)
    if @current_method_name == ""
      return ""
    end
    mi = 0
    while mi < @module_names.length
      mmod = @module_names[mi]
      if mmod != "" && @current_method_name.start_with?(mmod + "_cls_")
        cname = mmod + "_" + name[1, name.length - 1]
        if find_const_idx(cname) >= 0
          return "cst_" + cname
        end
      end
      mi = mi + 1
    end
    ""
  end


 # Walk the program for ivar nodes at script scope. Class/Module bodies
 # are skipped — their ivars belong to the enclosing class. Top-level
 # `def` bodies ARE walked: in Ruby, `def foo; @x; end` at script scope
 # shares the same `main` ivar that bare `@x` writes.

  def sanitize_gvar(name)
 # `alias $copy $orig` -- transparently rewrite `$copy` to `$orig`
 # everywhere it appears so the C output uses one storage slot
 # for both names. Compile-time only; matches CRuby's
 # `$copy and $orig share storage` semantics for the static-alias
 # case.
    name = resolve_gvar_alias(name)
 # $last → gv_last, $1 → gv_1
    if name.length > 0 && name[0] == "$"
      suf = name[1, name.length - 1]
 # Issue #831: punctuation globals like `$!`, `$;`, `$,`, `$/`,
 # `$:`, `$\\`, `$<`, `$>` would emit `gv_!`, etc., which aren't
 # valid C identifiers. Map each punctuation char to a stable
 # word so the same Ruby global maps to one C name throughout.
      mapped = ""
      i_sg = 0
      while i_sg < suf.length
        c_sg = suf[i_sg]
        if (c_sg >= "a" && c_sg <= "z") || (c_sg >= "A" && c_sg <= "Z") || (c_sg >= "0" && c_sg <= "9") || c_sg == "_"
          mapped = mapped + c_sg
        else
          mapped = mapped + "_" + gvar_punct_word(c_sg)
        end
        i_sg = i_sg + 1
      end
      return "gv_" + mapped
    end
    "gv_" + name
  end

 # Issue #910: build a str_str_hash inline from a HashNode or
 # KeywordHashNode arg whose keys are all string literals and
 # whose values are all string literals. Returns the emitted
 # temp var name, or "" when the arg doesn't match the shape.
  def sub_hash_arg_str_str(arg_nid)
    return "" if arg_nid < 0
    at = @nd_type[arg_nid]
    if at == "KeywordHashNode"
      elems_sh = parse_id_list(@nd_elements[arg_nid])
    elsif at == "HashNode"
      elems_sh = parse_id_list(@nd_elements[arg_nid])
    else
      return ""
    end
    return "" if elems_sh.length == 0
 # All keys+values must be string literals (StringNode) for the
 # str_str_hash representation. Mixed-type would need str_poly_hash.
    i_sh = 0
    while i_sh < elems_sh.length
      e_sh = elems_sh[i_sh]
      return "" if @nd_type[e_sh] != "AssocNode"
      k_sh = @nd_key[e_sh]
      v_sh = @nd_expression[e_sh]
      return "" if k_sh < 0 || v_sh < 0
      return "" if @nd_type[k_sh] != "StringNode"
      return "" if @nd_type[v_sh] != "StringNode"
      i_sh = i_sh + 1
    end
    @needs_str_str_hash = 1
    tmp_sh = new_temp
    emit("  sp_StrStrHash *" + tmp_sh + " = sp_StrStrHash_new();")
    j_sh = 0
    while j_sh < elems_sh.length
      e_sh2 = elems_sh[j_sh]
      k_sh2 = @nd_key[e_sh2]
      v_sh2 = @nd_expression[e_sh2]
      emit("  sp_StrStrHash_set(" + tmp_sh + ", " + compile_expr(k_sh2) + ", " + compile_expr(v_sh2) + ");")
      j_sh = j_sh + 1
    end
    tmp_sh
  end

 # Map an obj_StringScanner method call to the runtime helper
 # in libspinel_rt.a. Returns the C expression, or "" for an
 # unknown method (the caller then falls through to the standard
 # user-class dispatch).
  def strscan_runtime_call(mname, rc, nid)
    if mname == "scan"
      return "sp_StringScanner_scan(" + rc + ", " + strscan_pat_arg(nid) + ")"
    end
    if mname == "check"
      return "sp_StringScanner_check(" + rc + ", " + strscan_pat_arg(nid) + ")"
    end
    if mname == "scan_until"
      return "sp_StringScanner_scan_until(" + rc + ", " + strscan_pat_arg(nid) + ")"
    end
    if mname == "matched"
      return "sp_StringScanner_matched(" + rc + ")"
    end
    if mname == "matched?"
      return "sp_StringScanner_matched_p(" + rc + ")"
    end
    if mname == "pos"
      return "sp_StringScanner_pos(" + rc + ")"
    end
    if mname == "pos="
      return "sp_StringScanner_pos_set(" + rc + ", " + compile_arg0_as_int(nid) + ")"
    end
    if mname == "eos?"
      return "sp_StringScanner_eos_p(" + rc + ")"
    end
    if mname == "getch"
      return "sp_StringScanner_getch(" + rc + ")"
    end
    if mname == "peek"
      return "sp_StringScanner_peek(" + rc + ", " + compile_arg0_as_int(nid) + ")"
    end
    if mname == "unscan"
      return "sp_StringScanner_unscan(" + rc + ")"
    end
    if mname == "rest"
      return "sp_StringScanner_rest(" + rc + ")"
    end
    if mname == "rest_size"
      return "sp_StringScanner_rest_size(" + rc + ")"
    end
    if mname == "rest?"
      return "sp_StringScanner_rest_p(" + rc + ")"
    end
    if mname == "terminate"
      return "sp_StringScanner_terminate(" + rc + ")"
    end
    if mname == "string"
      return "sp_StringScanner_string(" + rc + ")"
    end
    if mname == "pre_match"
      return "sp_StringScanner_pre_match(" + rc + ")"
    end
    if mname == "post_match"
      return "sp_StringScanner_post_match(" + rc + ")"
    end
    if mname == "reset"
      return "sp_StringScanner_reset(" + rc + ")"
    end
    ""
  end

 # Resolve a regex arg to its compiled mrb_regexp_pattern * expr.
 # scan / check / scan_until all take a single regex; route through
 # the standard regex_pat_c_expr helper. Falls back to NULL for
 # malformed calls so the runtime helpers see "no match".
  def strscan_pat_arg(nid)
    args_id_ss = @nd_arguments[nid]
    return "NULL" if args_id_ss < 0
    a_ss = get_args(args_id_ss)
    return "NULL" if a_ss.length == 0
    pat = regex_pat_c_expr(a_ss[0])
    pat == "" ? compile_expr(a_ss[0]) : pat
  end

 # Check whether the format string uses only plain `%s`
 # placeholders (and literals / `%%`). Used to short-circuit
 # `"fmt" % str_array` to the simpler strarr helper instead of
 # boxing through poly_array.
  def str_format_only_simple_s_p(s)
    i = 0
    while i < s.length
      if s[i] == "%"
        i = i + 1
        if i >= s.length
          return 0
        end
        if s[i] == "%"
          i = i + 1
          next
        end
        if s[i] == "s"
          i = i + 1
          next
        end
        return 0
      end
      i = i + 1
    end
    1
  end

  def gvar_punct_word(c)
    return "bang" if c == "!"
    return "semi" if c == ";"
    return "comma" if c == ","
    return "slash" if c == "/"
    return "colon" if c == ":"
    return "bslash" if c == "\\"
    return "lt" if c == "<"
    return "gt" if c == ">"
    return "eq" if c == "="
    return "qmark" if c == "?"
    return "amp" if c == "&"
    return "quote" if c == "'"
    return "btick" if c == "`"
    return "tilde" if c == "~"
    return "plus" if c == "+"
    return "minus" if c == "-"
    return "at" if c == "@"
    return "star" if c == "*"
    return "dollar" if c == "$"
    "x"
  end

  def resolve_gvar_alias(name)
    i = 0
    while i < @galias_new.length
      if @galias_new[i] == name
        return @galias_old[i]
      end
      i = i + 1
    end
    name
  end

 # ---- Array type helpers ----
 # Box a per-element get expression into an sp_RbVal for the
 # heterogeneous Array#+ path. The element type comes from the
 # source array's static type. poly_array elements already are
 # sp_RbVal; primitive families need sp_box_*; ptr_array uses
 # the element's runtime cls_id (sp_obj_cls_id_of).
  def elem_to_poly_box(arr_t, elem_expr)
    bt = base_type(arr_t)
    if bt == "poly_array"
      return elem_expr
    end
    if bt == "int_array"
      return "sp_box_int(" + elem_expr + ")"
    end
    if bt == "str_array"
      return "sp_box_str(" + elem_expr + ")"
    end
    if bt == "float_array"
      return "sp_box_float(" + elem_expr + ")"
    end
    if bt == "sym_array"
      return "sp_box_sym((sp_sym)(" + elem_expr + "))"
    end
    if is_ptr_array_type(bt) == 1
      return "({ void *_p = (void *)(" + elem_expr + "); sp_box_obj(_p, sp_obj_cls_id_of(_p)); })"
    end
    elem_expr
  end

  def array_c_prefix(t)
    if t == "str_array"
      return "StrArray"
    end
    if t == "float_array"
      return "FloatArray"
    end
    if t == "poly_array"
      return "PolyArray"
    end
    if is_ptr_array_type(t) == 1
      return "PtrArray"
    end
    "IntArray"
  end

 # The canonical "is this an array type?" check. Use this when you need
 # to dispatch a method that's defined for every typed array — `+`,
 # `concat`, `shuffle`, `each_with_object`, `flat_map`, etc. Covers the
 # 5 typed arrays (int/str/float/sym/poly) and any *_ptr_array.
  def is_array_type(t)
    if is_nullable_type(t) == 1
      t = base_type(t)
    end
    if t == "int_array" || t == "str_array" || t == "float_array" || t == "sym_array" || t == "poly_array"
      return 1
    end
    if is_ptr_array_type(t) == 1
      return 1
    end
    0
  end

  def is_hash_type(t)
    if is_nullable_type(t) == 1
      t = base_type(t)
    end
    if t == "str_int_hash" || t == "str_str_hash" || t == "int_str_hash" || t == "int_int_hash"
      return 1
    end
    if t == "sym_int_hash" || t == "sym_str_hash"
      return 1
    end
    if t == "str_poly_hash" || t == "sym_poly_hash"
      return 1
    end
    if t == "poly_poly_hash"
      return 1
    end
    0
  end

  def cls_id_for_hash_type(at)
    if at == "str_int_hash"
      return "SP_BUILTIN_STR_INT_HASH"
    end
    if at == "str_str_hash"
      return "SP_BUILTIN_STR_STR_HASH"
    end
    if at == "int_str_hash"
      return "SP_BUILTIN_INT_STR_HASH"
    end
    if at == "sym_int_hash"
      return "SP_BUILTIN_SYM_INT_HASH"
    end
    if at == "sym_str_hash"
      return "SP_BUILTIN_SYM_STR_HASH"
    end
    if at == "str_poly_hash"
      return "SP_BUILTIN_STR_POLY_HASH"
    end
    if at == "sym_poly_hash"
      return "SP_BUILTIN_SYM_POLY_HASH"
    end
    if at == "poly_poly_hash"
      return "SP_BUILTIN_POLY_POLY_HASH"
    end
    ""
  end

  def hash_leaf_type(recv_type)
    if recv_type == "str_int_hash" || recv_type == "sym_int_hash"
      return "int"
    end
    if recv_type == "str_str_hash" || recv_type == "sym_str_hash" || recv_type == "int_str_hash"
      return "string"
    end
    if recv_type == "str_poly_hash" || recv_type == "sym_poly_hash" || recv_type == "poly_poly_hash"
      return "poly"
    end
    ""
  end

 # Hash#clear: emit a GCC compound expression that wipes the
 # open-addressing probe table back to its post-_new shape, sets
 # len = 0, and yields the receiver (Hash#clear returns self).
 # The per-variant empty-slot marker differs: sym-keyed and
 # int-keyed variants store the key inline (-1 sentinel for sym,
 # used[]/occ[] bitmap for int), str-keyed variants use NULL.
  def hash_clear_c_expr(t, rc)
    if t == "sym_int_hash" || t == "sym_str_hash" || t == "sym_poly_hash"
      return "({ for (mrb_int _i = 0; _i < (" + rc + ")->cap; _i++) (" + rc + ")->keys[_i] = -1; (" + rc + ")->len = 0; (" + rc + "); })"
    end
    if t == "str_int_hash" || t == "str_str_hash" || t == "str_poly_hash"
      return "({ for (mrb_int _i = 0; _i < (" + rc + ")->cap; _i++) (" + rc + ")->keys[_i] = NULL; (" + rc + ")->len = 0; (" + rc + "); })"
    end
    if t == "int_str_hash" || t == "int_int_hash" || t == "int_poly_hash"
      return "({ memset((" + rc + ")->used, 0, (" + rc + ")->cap); (" + rc + ")->len = 0; (" + rc + "); })"
    end
    if t == "poly_poly_hash"
      return "({ memset((" + rc + ")->occ, 0, (" + rc + ")->cap); (" + rc + ")->len = 0; (" + rc + "); })"
    end
    ""
  end

 # Per-variant info for the shared Hash#fetch(k) { block } arm.
 # Returns a 4-tuple [value_type, value_c_type, has_key_fn,
 # get_fn] or nil for unsupported variants. The block-form
 # arm uses these to emit the runtime check + dispatch.
  def hash_fetch_block_info(t)
    if t == "sym_int_hash";  return ["int", "mrb_int", "sp_SymIntHash_has_key", "sp_SymIntHash_get"]; end
    if t == "sym_str_hash";  return ["string", "const char *", "sp_SymStrHash_has_key", "sp_SymStrHash_get"]; end
    if t == "sym_poly_hash"; return ["poly", "sp_RbVal", "sp_SymPolyHash_has_key", "sp_SymPolyHash_get"]; end
    if t == "str_int_hash";  return ["int", "mrb_int", "sp_StrIntHash_has_key", "sp_StrIntHash_get"]; end
    if t == "str_str_hash";  return ["string", "const char *", "sp_StrStrHash_has_key", "sp_StrStrHash_get"]; end
    if t == "str_poly_hash"; return ["poly", "sp_RbVal", "sp_StrPolyHash_has_key", "sp_StrPolyHash_get"]; end
    nil
  end


 # CRuby returns nil for static mismatches (e.g. `{a: 1}.dig("a")`)
 # since no key compares equal — Hash#dig short-circuits to nil here.
  def hash_key_matches_recv(recv_type, key_type)
    if recv_type.start_with?("sym_") && key_type == "symbol"
      return 1
    end
    if recv_type.start_with?("str_") && key_type == "string"
      return 1
    end
    if recv_type.start_with?("int_") && key_type == "int"
      return 1
    end
    0
  end

 # The four typed arrays that have set-op runtime helpers
 # (sp_*_intersect / _union / _difference). poly_array and ptr_array
 # are deliberately excluded — element equality isn't available there.
  def is_typed_array_type(t)
    t == "int_array" || t == "sym_array" || t == "str_array" || t == "float_array"
  end

 # Returns "" to fall through to the literal C operator; otherwise the
 # typed-array helper call. `op` is one of "intersect"/"union"/"difference".
 # `lt` is the pre-computed receiver type from the caller.
  def compile_array_setop_expr(nid, recv, op, lt)
    if !is_typed_array_type(lt)
      if is_array_type(lt) == 1
        $stderr.puts "warning: Array set-op '" + op + "' is not supported on " + lt + " (falling through)"
      end
      return ""
    end
    args_id = @nd_arguments[nid]
    if args_id < 0
      return ""
    end
    aargs = get_args(args_id)
    if aargs.length == 0
      return ""
    end
 # Strict equality (not is_array_type): nullable variants and
 # cross-type RHS aren't handled by the helpers, and the fall-through
 # would emit a C arithmetic/bitwise op on array pointers.
    rt = infer_type(aargs[0])
    if rt != lt
      $stderr.puts "warning: Array set-op '" + op + "' RHS type " + rt + " does not match LHS " + lt + " (falling through)"
      return ""
    end
    mark_array_runtime_needs(lt)
    "sp_" + array_c_prefix(lt) + "_" + op + "(" + compile_expr_gc_rooted(recv) + ", " + compile_arg0(nid) + ")"
  end

 # Set the right @needs_<runtime> flag for the given array type.
  def mark_array_runtime_needs(t)
    if t == "float_array"
      @needs_float_array = 1
    elsif t == "str_array"
      @needs_str_array = 1
    elsif t == "poly_array"
      @needs_rb_value = 1
    else
      @needs_int_array = 1
    end
  end

 # ---- Collection pass ----
 # Returns the module-singleton-accessor index for "<Module>.<accessor>",
 # or -1 if not registered.
  def find_module_acc_idx(key)
    i = 0
    while i < @module_acc_keys.length
      if @module_acc_keys[i] == key
        return i
      end
      i = i + 1
    end
    -1
  end

 # Walk the AST for `Module.accessor = RHS` writes where
 # (Module, accessor) was registered in `collect_module` as a
 # singleton accessor. Accumulates the set of distinct
 # ConstantReadNode RHSes; the lowering paths read this list to
 # choose:
 # - 0 entries: never written, falls through (un-folded)
 # - 1 entry: Stage 1, inline `<resolved>.<method>` directly
 # - 2+ entries: Stage 2, sentinel switch over the union
 # A non-constant RHS poisons the slot with a `?` sentinel marker
 # so the lowering paths treat it as un-folded.

 # Returns the resolved constant list for this (module, accessor):
 # `<Name1>;<Name2>;...` for foldable, `""` if never written, `"?"`
 # if poisoned (non-constant RHS).
  def module_acc_resolved(mod_name, accessor)
    idx = find_module_acc_idx(mod_name + "." + accessor)
    if idx < 0
      return ""
    end
    @module_acc_consts[idx]
  end

 # Sentinel value for Stage 2 switch dispatch. Each module's index in
 # `@module_names` doubles as its sentinel id; reading `Module` as a
 # value lowers to this integer.

 # Look up the return type of a `<class_or_module>.<mname>`
 # singleton method, walking @meth_* (module / synthetic top-level
 # form) and @cls_cmeth_* (in-class `def self.X`). Returns "" when
 # the method isn't registered. Used by the module-dispatch ternary
 # default-tail and per-arm boxing paths.
  def lookup_cls_meth_return(cn, mname)
    mid = find_method_idx(cn + "_cls_" + mname)
    if mid >= 0
      return @meth_return_types[mid]
    end
    cci = find_class_idx(cn)
    if cci >= 0
      cmnames = @cls_cmeth_names[cci].split(";", -1)
      ki = 0
      while ki < cmnames.length
        if cmnames[ki] == mname
          cmrets = @cls_cmeth_returns[cci].split(";", -1)
          if ki < cmrets.length
            return cmrets[ki]
          end
        end
        ki = ki + 1
      end
    end
    ""
  end

  def module_sentinel(mname)
 # Module-singleton accessors hold either a module reference (rare)
 # or a class reference (the strategy-pattern shape: `Disp.adapter
 # = A` / `Disp.adapter = B`). Both must produce *distinct* sentinel
 # values so the dispatch ternary's per-candidate `slot == sentinel`
 # arms don't all collapse to the same comparison. the
 # class case used to fall through to 0 here, leaving every
 # candidate's `slot == 0` arm matching the never-written default
 # and the rest of the chain unreachable.
    i = 0
    while i < @module_names.length
      if @module_names[i] == mname
        return i + 1
      end
      i = i + 1
    end
    ci = find_class_idx(mname)
    if ci >= 0
 # Reserve [1 .. @module_names.length] for module sentinels and
 # offset class sentinels above that range so the two namespaces
 # don't collide.
      return @module_names.length + 1 + ci
    end
    0
  end

 # Identifies the method body we're currently emitting, formatted for
 # diagnostic messages. Library-style methods with no concrete caller
 # default their params to `mrb_int` and surface as a flood of
 # "cannot resolve call to ... on int" lines; without context the
 # user can't tell which def the warning came from. Returns
 # "Foo#bar" for an instance method, "Foo.bar" for a class method
 # (incl. module class methods stored as @meth_names with a
 # `<Mod>_cls_<m>` form), or "(top level)" outside any def.
  def current_method_context_str
    if @current_class_idx >= 0 && @current_class_idx < @cls_names.length
      sep = "."
      if @current_method_has_self == 1
        sep = "#"
      end
      return @cls_names[@current_class_idx] + sep + @current_method_name
    end
    if @current_method_name != ""
      ix_cls = @current_method_name.index("_cls_")
 # CRuby returns nil when not found; spinel runtime returns -1.
      if ix_cls != nil && ix_cls > 0
        return @current_method_name[0, ix_cls] + "." +
               @current_method_name[ix_cls + 5, @current_method_name.length - (ix_cls + 5)]
      end
      return @current_method_name
    end
    "(top level)"
  end

 # Print a stderr warning the first time we see an unresolved call to
 # `mname` with the given receiver-type tag in the current method
 # context. Subsequent identical warnings are suppressed so a
 # silent-fallthrough call inside a hot loop emits one line, not a
 # torrent. Dedupe key includes the method context so the same shape
 # of unresolved call in two different defs each produces its own
 # line — the prior key (`mname:recv_tag`) collapsed them and made
 # library-method-with-no-caller diagnostics opaque. The warning is
 # informational only — codegen continues and emits `0` for the
 # call's C expression (the historical silent-no-op behaviour) so
 # existing tests/benches whose outputs happen to coincide with `0`
 # keep compiling.
  def warn_unresolved_call(mname, recv_tag)
    ctx = current_method_context_str
    key = mname + ":" + recv_tag + ":" + ctx
    i = 0
    while i < @unresolved_call_warnings.length
      if @unresolved_call_warnings[i] == key
        return
      end
      i = i + 1
    end
    @unresolved_call_warnings.push(key)
    $stderr.puts "warning: in " + ctx + ": cannot resolve call to '" + mname + "' on " + recv_tag + " (emitting 0)"
  end

 # Same dedupe pattern as warn_unresolved_call but for unknown
 # ConstantReadNode names. Reuses @unresolved_call_warnings so a
 # single program with both an undefined method and an undefined
 # constant produces two distinct warnings, not interleaved noise.
  def warn_unresolved_const(rname)
    ctx = current_method_context_str
    key = "_const_:" + rname + ":" + ctx
    i = 0
    while i < @unresolved_call_warnings.length
      if @unresolved_call_warnings[i] == key
        return
      end
      i = i + 1
    end
    @unresolved_call_warnings.push(key)
    $stderr.puts "warning: in " + ctx + ": uninitialized constant '" + rname + "' (emitting 0)"
  end

 # Issue #646: warn when a class's body reads a top-level const that
 # the program assigns via `<const> = <ThisClass>.new(...)` — i.e.
 # the read happens during the const's own RHS evaluation. The slot
 # is NULL during init; any `.method` / `->iv_` deref will segfault.
 # Pattern-match the const-init RHS for `<ThisClass>.new` (the
 # canonical shape that triggers the bug). Dedupes through the same
 # warning stash as warn_unresolved_call / warn_unresolved_const.
  def warn_self_ref_const_init(rname)
    if @current_class_idx < 0
      return
    end
    cur_cname = @cls_names[@current_class_idx]
    ci_self = find_const_idx(rname)
    if ci_self < 0 || ci_self >= @const_expr_ids.length
      return
    end
    eid_self = @const_expr_ids[ci_self]
    if eid_self < 0
      return
    end
 # RHS must be a `<Class>.new(...)` shape: CallNode with mname
 # "new" whose recv is a ConstantReadNode naming the current
 # class.
    if @nd_type[eid_self] != "CallNode"
      return
    end
    if @nd_name[eid_self] != "new"
      return
    end
    recv_self = @nd_receiver[eid_self]
    if recv_self < 0 || @nd_type[recv_self] != "ConstantReadNode"
      return
    end
    if @nd_name[recv_self] != cur_cname
      return
    end
    key_self = "_self_ref_:" + rname + ":" + cur_cname
    j_self = 0
    while j_self < @unresolved_call_warnings.length
      if @unresolved_call_warnings[j_self] == key_self
