 # reachable as ieval body return types -- their inference returns
 # one of the cases above, or "void". If a new shape appears here,
 # extend the table rather than routing through c_type (see the WHY
 # in this method's docstring).
    "void"
  end

  def emit_ieval_func(n, ci, bid)
    cname = @cls_names[ci]
    ret_type = "void"
    if n < @ieval_return_types.length
      rt = @ieval_return_types[n]
      if rt != ""
        ret_type = rt
      end
    end
    sig_ret = ieval_sig_ret(ret_type)
    @current_class_idx = ci
    @current_method_name = "__sp_ieval_" + n.to_s
    @current_method_return = ret_type
    @indent = 1
    @in_gc_scope = 0
    @in_yield_method = 0

    if @cls_is_value_type[ci] == 1
      emit_raw("static " + sig_ret + " sp_ieval_" + n.to_s + "(sp_" + cname + " self) {")
    else
      emit_raw("static " + sig_ret + " sp_ieval_" + n.to_s + "(sp_" + cname + " *self) {")
    end

    push_scope
    if bid >= 0
      declare_method_locals(bid, "".split(",", -1))
 # Seed self-bound param (analyze declared it as obj_<C>).
      spn = ""
      if n < @ieval_self_param_names.length
        spn = @ieval_self_param_names[n]
      end
      if spn != ""
        emit("  lv_" + spn + " = self;")
      end
 # declare_method_locals already emits SP_GC_SAVE when the body
 # has pointer locals; only emit again if it didn't.
      if @needs_gc == 1 && @in_gc_scope == 0
        emit("  SP_GC_SAVE();")
        @in_gc_scope = 1
      end
      if @needs_gc == 1
        if @cls_is_value_type[ci] == 0
          emit("  SP_GC_ROOT(self);")
        else
          emit_gc_root_for_expr("self", "obj_" + cname)
        end
      end
      compile_body_return(bid, ret_type)
    end
    pop_scope

    @current_class_idx = -1
    @current_method_name = ""
    @indent = 0
    emit_raw("}")
    emit_raw("")
  end



 # Walk class bodies, module bodies, and the top-level statement
 # list for class-var writes; register each (class-or-Toplevel,
 # name) pair so the static-declaration pass can emit
 # `static <type> cvar_<qname> = <default>;` ahead of the functions
 # that touch it.
 #
 # Module-scope and top-level `@@x = ...` writes belong to the
 # `Toplevel` namespace -- spinel models cvars per-class, modules
 # don't have a cls_id of their own, and tying them to "Toplevel"
