 # Emit a direct call to the FFI function indexed by `fi`. Each
 # argument is cast to its declared C type so type mismatches fail
 # loudly at compile time and we sidestep -Wconversion noise.
  def compile_ffi_func_call(nid, fi)
    fname = @ffi_func_names[fi]
    arg_specs_str = @ffi_func_arg_specs[fi]
    arg_specs = []
    if arg_specs_str != ""
      arg_specs = arg_specs_str.split(";", -1)
    end
    args_id = @nd_arguments[nid]
    call_args = []
    if args_id >= 0
      call_args = get_args(args_id)
    end
    if call_args.length != arg_specs.length
      $stderr.puts "FFI error: " + fname + ": expected " + arg_specs.length.to_s + " args, got " + call_args.length.to_s
      exit(1)
    end
    result = fname + "("
    k = 0
    while k < call_args.length
      if k > 0
        result = result + ", "
      end
      spec = arg_specs[k]
      ctype = ffi_c_type_of(spec)
 # `:str` forwards the raw `const char *` directly — casting would
 # discard `const` and trigger a warning. When the arg's static
 # type is poly (sp_RbVal), extract `.v.s` (issue #502). The
 # ternary on infer_type is inlined rather than bound to a local
 # because adding fresh locals here trips self-host scan_locals;
 # see feedback_self_host_recursive_fn_arm.
      if spec == "str"
        if infer_type(call_args[k]) == "poly"
          @needs_rb_value = 1
          result = result + "(" + compile_expr(call_args[k]) + ").v.s"
        else
          result = result + compile_expr(call_args[k])
        end
      elsif spec == "ptr"
        if infer_type(call_args[k]) == "poly"
          @needs_rb_value = 1
          result = result + "((void *)(" + compile_expr(call_args[k]) + ").v.p)"
        elsif infer_type(call_args[k]) == "bigint" || expr_emit_is_bigint(call_args[k]) == 1
          @needs_bigint = 1
          result = result + "((void *)(uintptr_t)sp_bigint_to_int((sp_Bigint *)" + compile_expr(call_args[k]) + "))"
        else
          result = result + "((void *)(uintptr_t)" + compile_expr(call_args[k]) + ")"
        end
      elsif spec == "float_array" || spec == "int_array"
 # Zero-copy bulk transfer (#474). The Spinel Array's contiguous
 # storage lives at `.data`; we hand the raw pointer to C with
 # call-duration lifetime (same contract as `:str`). Cast hides
 # the mrb_float/mrb_int -> double/int64_t typedef-vs-spelling
 # mismatch (both widths match on every supported target).
        result = result + "((" + ctype + ")(" + compile_expr(call_args[k]) + ")->data)"
      else
