    if kind == "ptr"
      return "((void *)(*((void * *)((char *)" + buf_expr + " + " + off.to_s + "))))"
    end
    "((mrb_int)(*((" + ctype + " *)((char *)" + buf_expr + " + " + off.to_s + "))))"
  end

