          fi = fi + 1
        end
        @deferred_tuple << "typedef struct { "
        @deferred_tuple << fields
        @deferred_tuple << " } "
        @deferred_tuple << name
        @deferred_tuple << ";\n"
 # GC scan function — only emit when at least one field is a GC ref.
 # Without this the tuple's children are collected while the tuple
 # itself is still alive, leaving dangling pointers in the fields.
        needs_scan = 0
        fi = 0
        while fi < parts.length
          if tuple_field_needs_mark(parts[fi]) == 1
            needs_scan = 1
          end
          fi = fi + 1
        end
        if needs_scan == 1
          body = ""
          fi = 0
          while fi < parts.length
            if tuple_field_needs_mark(parts[fi]) == 1
              field = "_t->_" + fi.to_s
              stmt = gc_mark_stmt_for_expr(field, parts[fi])
              if stmt != ""
                body = body + " " + stmt
              end
            end
            fi = fi + 1
          end
          @deferred_tuple << "static void " + name + "_scan(void *_p) { " + name + " *_t = (" + name + " *)_p;" + body + " }\n"
        end
        k = k + 1
      end
    end
    0
  end

 # ============================================================
 # Emission
 # ============================================================
 #
 # End of pre-emission analysis. From here down, the codegen
 # consumes the tables built above and writes C: header, runtime
 # blocks, struct/forward decls, class methods, top-level methods,
 # main(). emit_header is the entry point; generate_code (above)
 # orchestrates the order.
  def emit_header
    emit_raw("/* Generated by Spinel v2 AOT compiler */")
    emit_raw("#include <stdio.h>")
    emit_raw("#include <stdlib.h>")
    emit_raw("#include <string.h>")
    emit_raw("#include <math.h>")
    emit_raw("#include <stdbool.h>")
    emit_raw("#include <stdint.h>")
    emit_raw("#include <ctype.h>")
    emit_raw("#include <stdarg.h>")
    emit_raw("#include <time.h>")
    emit_raw("")
    emit_raw("typedef int64_t mrb_int;")
    emit_raw("typedef double mrb_float;")
    emit_raw("typedef bool mrb_bool;")
    emit_raw("#ifndef TRUE")
    emit_raw("#define TRUE true")
    emit_raw("#endif")
    emit_raw("#ifndef FALSE")
    emit_raw("#define FALSE false")
    emit_raw("#endif")
    emit_raw("")
    emit_raw("static inline mrb_int sp_idiv(mrb_int a, mrb_int b) {")
    emit_raw("  mrb_int q = a / b; mrb_int r = a % b;")
    emit_raw("  if ((r != 0) && ((r ^ b) < 0)) q--;")
    emit_raw("  return q;")
    emit_raw("}")
    emit_raw("static inline mrb_int sp_imod(mrb_int a, mrb_int b) {")
    emit_raw("  mrb_int r = a % b;")
    emit_raw("  if ((r != 0) && ((r ^ b) < 0)) r += b;")
    emit_raw("  return r;")
    emit_raw("}")
    emit_raw("")
    emit_raw("static mrb_int sp_gcd(mrb_int a,mrb_int b){if(a<0)a=-a;if(b<0)b=-b;while(b){mrb_int t=b;b=a%b;a=t;}return a;}")
    emit_raw("static mrb_int sp_int_clamp(mrb_int v,mrb_int lo,mrb_int hi){return v<lo?lo:v>hi?hi:v;}")
    emit_raw("static const char*sp_int_chr(mrb_int n){char*s=(char*)malloc(2);s[0]=(char)n;s[1]=0;return s;}")
    emit_raw("typedef struct{mrb_int first;mrb_int last;}sp_Range;")
    emit_raw("static sp_Range sp_range_new(mrb_int f,mrb_int l){sp_Range r;r.first=f;r.last=l;return r;}")
    if @needs_system == 1
      emit_raw("static int sp_last_status = 0;")
    end
    emit_raw("")
  end



 # Symbol-keyed hash with integer values. Keys are sp_sym (mrb_int);
 # the empty-slot sentinel is -1 (= invalid sp_sym, same as default).
  def emit_sym_int_hash_runtime
    emit_raw("typedef struct{sp_sym*keys;mrb_int*vals;sp_sym*order;mrb_int len;mrb_int cap;mrb_int mask;mrb_int default_v;}sp_SymIntHash;")
    emit_raw("static void sp_SymIntHash_fin(void*p){sp_SymIntHash*h=(sp_SymIntHash*)p;free(h->keys);free(h->vals);free(h->order);}")
    emit_raw("static sp_SymIntHash*sp_SymIntHash_new(void){sp_SymIntHash*h=(sp_SymIntHash*)sp_gc_alloc(sizeof(sp_SymIntHash),sp_SymIntHash_fin,NULL);h->cap=16;h->mask=15;h->keys=(sp_sym*)malloc(sizeof(sp_sym)*h->cap);for(mrb_int i=0;i<h->cap;i++)h->keys[i]=-1;h->vals=(mrb_int*)calloc(h->cap,sizeof(mrb_int));h->order=(sp_sym*)malloc(sizeof(sp_sym)*h->cap);h->len=0;h->default_v=0;return h;}")
    emit_raw("static sp_SymIntHash*sp_SymIntHash_new_with_default(mrb_int d){sp_SymIntHash*h=sp_SymIntHash_new();h->default_v=d;return h;}")
    emit_raw("static void sp_SymIntHash_grow(sp_SymIntHash*h){mrb_int oc=h->cap;sp_sym*ok=h->keys;mrb_int*ov=h->vals;h->cap*=2;h->mask=h->cap-1;h->keys=(sp_sym*)malloc(sizeof(sp_sym)*h->cap);for(mrb_int i=0;i<h->cap;i++)h->keys[i]=-1;h->vals=(mrb_int*)calloc(h->cap,sizeof(mrb_int));h->order=(sp_sym*)realloc(h->order,sizeof(sp_sym)*h->cap);h->len=0;for(mrb_int i=0;i<oc;i++){if(ok[i]>=0){mrb_int idx=(mrb_int)(((mrb_int)ok[i])&h->mask);while(h->keys[idx]>=0)idx=(idx+1)&h->mask;h->keys[idx]=ok[i];h->vals[idx]=ov[i];h->len++;}}free(ok);free(ov);}")
    emit_raw("static mrb_int sp_SymIntHash_get(sp_SymIntHash*h,sp_sym k){if(!h)return 0;mrb_int idx=(mrb_int)(((mrb_int)k)&h->mask);while(h->keys[idx]>=0){if(h->keys[idx]==k)return h->vals[idx];idx=(idx+1)&h->mask;}return h->default_v;}")
    emit_raw("static void sp_SymIntHash_set(sp_SymIntHash*h,sp_sym k,mrb_int v){if(h->len*2>=h->cap)sp_SymIntHash_grow(h);mrb_int idx=(mrb_int)(((mrb_int)k)&h->mask);while(h->keys[idx]>=0){if(h->keys[idx]==k){h->vals[idx]=v;return;}idx=(idx+1)&h->mask;}h->keys[idx]=k;h->vals[idx]=v;h->order[h->len]=k;h->len++;}")
    emit_raw("static mrb_bool sp_SymIntHash_has_key(sp_SymIntHash*h,sp_sym k){mrb_int idx=(mrb_int)(((mrb_int)k)&h->mask);while(h->keys[idx]>=0){if(h->keys[idx]==k)return TRUE;idx=(idx+1)&h->mask;}return FALSE;}")
 # Hash#value? -- scan stored values for v. O(n) per CRuby. Issue #738.
    emit_raw("static mrb_bool sp_SymIntHash_has_value(sp_SymIntHash*h,mrb_int v){for(mrb_int i=0;i<h->len;i++)if(sp_SymIntHash_get(h,h->order[i])==v)return TRUE;return FALSE;}")
    emit_raw("static mrb_int sp_SymIntHash_length(sp_SymIntHash*h){return h->len;}")
    emit_raw("static void sp_SymIntHash_delete(sp_SymIntHash*h,sp_sym k){mrb_int idx=(mrb_int)(((mrb_int)k)&h->mask);while(h->keys[idx]>=0){if(h->keys[idx]==k){h->keys[idx]=-1;h->vals[idx]=0;h->len--;mrb_int j=(idx+1)&h->mask;while(h->keys[j]>=0){mrb_int nj=(mrb_int)(((mrb_int)h->keys[j])&h->mask);if((j>idx&&(nj<=idx||nj>j))||(j<idx&&nj<=idx&&nj>j)){h->keys[idx]=h->keys[j];h->vals[idx]=h->vals[j];h->keys[j]=-1;h->vals[j]=0;idx=j;}j=(j+1)&h->mask;}{mrb_int oi=0;while(oi<=h->len){if(h->order[oi]==k){while(oi<h->len){h->order[oi]=h->order[oi+1];oi++;}break;}oi++;}}return;}idx=(idx+1)&h->mask;}}")
    emit_raw("static sp_IntArray*sp_SymIntHash_keys(sp_SymIntHash*h){sp_IntArray*a=sp_IntArray_new();for(mrb_int i=0;i<h->len;i++)sp_IntArray_push(a,(mrb_int)h->order[i]);return a;}")
    emit_raw("static sp_IntArray*sp_SymIntHash_values(sp_SymIntHash*h){sp_IntArray*a=sp_IntArray_new();for(mrb_int i=0;i<h->len;i++)sp_IntArray_push(a,sp_SymIntHash_get(h,h->order[i]));return a;}")
    emit_raw("static sp_SymIntHash*sp_SymIntHash_dup(sp_SymIntHash*h){sp_SymIntHash*r=sp_SymIntHash_new();r->default_v=h->default_v;for(mrb_int i=0;i<h->len;i++)sp_SymIntHash_set(r,h->order[i],sp_SymIntHash_get(h,h->order[i]));return r;}")
 # Issue #738: Hash#to_a as poly_array of poly_array pairs.
 # Each inner pair is [sym, int] boxed via sp_box_*.
    emit_raw("static sp_PolyArray*sp_SymIntHash_to_a(sp_SymIntHash*h){sp_PolyArray*r=sp_PolyArray_new();for(mrb_int i=0;i<h->len;i++){sp_PolyArray*p=sp_PolyArray_new();sp_PolyArray_push(p,sp_box_sym(h->order[i]));sp_PolyArray_push(p,sp_box_int(sp_SymIntHash_get(h,h->order[i])));sp_PolyArray_push(r,sp_box_poly_array(p));}return r;}")
    emit_raw("static sp_PolyPolyHash*sp_SymIntHash_invert(sp_SymIntHash*h){sp_PolyPolyHash*r=sp_PolyPolyHash_new();for(mrb_int i=0;i<h->len;i++)sp_PolyPolyHash_set(r,sp_box_int(sp_SymIntHash_get(h,h->order[i])),sp_box_sym(h->order[i]));return r;}")
    emit_raw("static sp_SymIntHash*sp_SymIntHash_merge(sp_SymIntHash*a,sp_SymIntHash*b){sp_SymIntHash*r=sp_SymIntHash_new();r->default_v=a->default_v;for(mrb_int i=0;i<a->len;i++)sp_SymIntHash_set(r,a->order[i],sp_SymIntHash_get(a,a->order[i]));if(b){for(mrb_int i=0;i<b->len;i++)sp_SymIntHash_set(r,b->order[i],sp_SymIntHash_get(b,b->order[i]));}return r;}")
    emit_raw("static mrb_bool sp_SymIntHash_eq(sp_SymIntHash*a,sp_SymIntHash*b){if(!a||!b)return a==b;if(a->len!=b->len)return FALSE;for(mrb_int i=0;i<a->len;i++){sp_sym k=a->order[i];if(!sp_SymIntHash_has_key(b,k))return FALSE;if(sp_SymIntHash_get(a,k)!=sp_SymIntHash_get(b,k))return FALSE;}return TRUE;}")
 # Hash inspect — Ruby's modern shorthand `{k: v, ...}`. All keys
 # in a sym_int_hash are valid identifier symbols (the parser only
 # routes literal symbol keys here), so the bare-name form always
 # round-trips correctly.
    emit_raw("static const char*sp_SymIntHash_inspect(sp_SymIntHash*h){sp_String*s=sp_String_new(\"{\");for(mrb_int i=0;i<h->len;i++){if(i>0)sp_String_append(s,\", \");sp_String_append(s,sp_sym_to_s(h->order[i]));sp_String_append(s,\": \");sp_String_append(s,sp_int_to_s(sp_SymIntHash_get(h,h->order[i])));}sp_String_append(s,\"}\");return s->data;}")
 # sym_array.tally — emitted alongside sp_SymIntHash because the
 # helper depends on the typedef. sym_array storage is sp_IntArray
 # (sym ids stored as mrb_int); cast each element to sp_sym for the
 # hash key. sp_SymIntHash_get returns 0 for missing keys (line 10176)
 # so the has_key? guard is redundant — drop it for two lookups per
 # element instead of three.
    emit_raw("static sp_SymIntHash*sp_SymArray_tally(sp_IntArray*a){sp_SymIntHash*h=sp_SymIntHash_new();for(mrb_int i=0;i<a->len;i++){sp_sym k=(sp_sym)a->data[a->start+i];sp_SymIntHash_set(h,k,sp_SymIntHash_get(h,k)+1);}return h;}")
 # Cross-variant merge: sym_poly_hash receiver merging in a
 # sym_int_hash arg boxes each int value into sp_RbVal so the
 # result's poly slots are populated correctly. Sibling of
 # sp_SymPolyHash_merge_str (#515). Issue #559.
    emit_raw("static sp_SymPolyHash*sp_SymPolyHash_merge_int(sp_SymPolyHash*a,sp_SymIntHash*b){sp_SymPolyHash*r=sp_SymPolyHash_new();for(mrb_int i=0;i<a->len;i++)sp_SymPolyHash_set(r,a->order[i],sp_SymPolyHash_get(a,a->order[i]));for(mrb_int i=0;i<b->len;i++)sp_SymPolyHash_set(r,b->order[i],sp_box_int(sp_SymIntHash_get(b,b->order[i])));return r;}")
 # Convert a sym_int_hash to a sym_poly_hash by boxing each
 # int value via sp_box_int. Mirrors sp_SymStrHash_to_sym_poly
 # for the cross-variant Hash#merge path (issue #661).
    emit_raw("static sp_SymPolyHash*sp_SymIntHash_to_sym_poly(sp_SymIntHash*h){sp_SymPolyHash*r=sp_SymPolyHash_new();for(mrb_int i=0;i<h->len;i++)sp_SymPolyHash_set(r,h->order[i],sp_box_int(sp_SymIntHash_get(h,h->order[i])));return r;}")
    emit_raw("")
  end

 # Symbol-keyed hash with string values.
  def emit_sym_str_hash_runtime
    emit_raw("typedef struct{sp_sym*keys;const char**vals;sp_sym*order;mrb_int len;mrb_int cap;mrb_int mask;const char*default_v;}sp_SymStrHash;")
    emit_raw("static void sp_SymStrHash_fin(void*p){sp_SymStrHash*h=(sp_SymStrHash*)p;free(h->keys);free(h->vals);free(h->order);}")
    emit_raw("static sp_SymStrHash*sp_SymStrHash_new(void){sp_SymStrHash*h=(sp_SymStrHash*)sp_gc_alloc(sizeof(sp_SymStrHash),sp_SymStrHash_fin,NULL);h->cap=16;h->mask=15;h->keys=(sp_sym*)malloc(sizeof(sp_sym)*h->cap);for(mrb_int i=0;i<h->cap;i++)h->keys[i]=-1;h->vals=(const char**)calloc(h->cap,sizeof(const char*));h->order=(sp_sym*)malloc(sizeof(sp_sym)*h->cap);h->len=0;h->default_v=NULL;return h;}")
    emit_raw("static sp_SymStrHash*sp_SymStrHash_new_with_default(const char*d){sp_SymStrHash*h=sp_SymStrHash_new();h->default_v=d;return h;}")
    emit_raw("static void sp_SymStrHash_grow(sp_SymStrHash*h){mrb_int oc=h->cap;sp_sym*ok=h->keys;const char**ov=h->vals;h->cap*=2;h->mask=h->cap-1;h->keys=(sp_sym*)malloc(sizeof(sp_sym)*h->cap);for(mrb_int i=0;i<h->cap;i++)h->keys[i]=-1;h->vals=(const char**)calloc(h->cap,sizeof(const char*));h->order=(sp_sym*)realloc(h->order,sizeof(sp_sym)*h->cap);h->len=0;for(mrb_int i=0;i<oc;i++){if(ok[i]>=0){mrb_int idx=(mrb_int)(((mrb_int)ok[i])&h->mask);while(h->keys[idx]>=0)idx=(idx+1)&h->mask;h->keys[idx]=ok[i];h->vals[idx]=ov[i];h->len++;}}free(ok);free(ov);}")
    emit_raw("static const char*sp_SymStrHash_get(sp_SymStrHash*h,sp_sym k){if(!h)return NULL;mrb_int idx=(mrb_int)(((mrb_int)k)&h->mask);while(h->keys[idx]>=0){if(h->keys[idx]==k)return h->vals[idx];idx=(idx+1)&h->mask;}return h->default_v;}")
    emit_raw("static void sp_SymStrHash_set(sp_SymStrHash*h,sp_sym k,const char*v){if(h->len*2>=h->cap)sp_SymStrHash_grow(h);mrb_int idx=(mrb_int)(((mrb_int)k)&h->mask);while(h->keys[idx]>=0){if(h->keys[idx]==k){h->vals[idx]=v;return;}idx=(idx+1)&h->mask;}h->keys[idx]=k;h->vals[idx]=v;h->order[h->len]=k;h->len++;}")
    emit_raw("static mrb_bool sp_SymStrHash_has_key(sp_SymStrHash*h,sp_sym k){mrb_int idx=(mrb_int)(((mrb_int)k)&h->mask);while(h->keys[idx]>=0){if(h->keys[idx]==k)return TRUE;idx=(idx+1)&h->mask;}return FALSE;}")
    emit_raw("static mrb_int sp_SymStrHash_length(sp_SymStrHash*h){return h->len;}")
    emit_raw("static void sp_SymStrHash_delete(sp_SymStrHash*h,sp_sym k){mrb_int idx=(mrb_int)(((mrb_int)k)&h->mask);while(h->keys[idx]>=0){if(h->keys[idx]==k){h->keys[idx]=-1;h->vals[idx]=NULL;h->len--;mrb_int j=(idx+1)&h->mask;while(h->keys[j]>=0){mrb_int nj=(mrb_int)(((mrb_int)h->keys[j])&h->mask);if((j>idx&&(nj<=idx||nj>j))||(j<idx&&nj<=idx&&nj>j)){h->keys[idx]=h->keys[j];h->vals[idx]=h->vals[j];h->keys[j]=-1;h->vals[j]=NULL;idx=j;}j=(j+1)&h->mask;}{mrb_int oi=0;while(oi<=h->len){if(h->order[oi]==k){while(oi<h->len){h->order[oi]=h->order[oi+1];oi++;}break;}oi++;}}return;}idx=(idx+1)&h->mask;}}")
    emit_raw("static sp_IntArray*sp_SymStrHash_keys(sp_SymStrHash*h){sp_IntArray*a=sp_IntArray_new();for(mrb_int i=0;i<h->len;i++)sp_IntArray_push(a,(mrb_int)h->order[i]);return a;}")
    emit_raw("static sp_StrArray*sp_SymStrHash_values(sp_SymStrHash*h){sp_StrArray*a=sp_StrArray_new();for(mrb_int i=0;i<h->len;i++)sp_StrArray_push(a,sp_SymStrHash_get(h,h->order[i]));return a;}")
    emit_raw("static mrb_bool sp_SymStrHash_has_value(sp_SymStrHash*h,const char*v){if(!h||!v)return FALSE;for(mrb_int i=0;i<h->len;i++){const char*x=sp_SymStrHash_get(h,h->order[i]);if(x&&strcmp(x,v)==0)return TRUE;}return FALSE;}")
    emit_raw("static sp_SymStrHash*sp_SymStrHash_dup(sp_SymStrHash*h){sp_SymStrHash*r=sp_SymStrHash_new();r->default_v=h->default_v;for(mrb_int i=0;i<h->len;i++)sp_SymStrHash_set(r,h->order[i],sp_SymStrHash_get(h,h->order[i]));return r;}")
    emit_raw("static sp_PolyArray*sp_SymStrHash_to_a(sp_SymStrHash*h){sp_PolyArray*r=sp_PolyArray_new();for(mrb_int i=0;i<h->len;i++){sp_PolyArray*p=sp_PolyArray_new();sp_PolyArray_push(p,sp_box_sym(h->order[i]));sp_PolyArray_push(p,sp_box_str(sp_SymStrHash_get(h,h->order[i])));sp_PolyArray_push(r,sp_box_poly_array(p));}return r;}")
    emit_raw("static sp_PolyPolyHash*sp_SymStrHash_invert(sp_SymStrHash*h){sp_PolyPolyHash*r=sp_PolyPolyHash_new();for(mrb_int i=0;i<h->len;i++)sp_PolyPolyHash_set(r,sp_box_str(sp_SymStrHash_get(h,h->order[i])),sp_box_sym(h->order[i]));return r;}")
    emit_raw("static sp_SymStrHash*sp_SymStrHash_merge(sp_SymStrHash*a,sp_SymStrHash*b){sp_SymStrHash*r=sp_SymStrHash_new();r->default_v=a->default_v;for(mrb_int i=0;i<a->len;i++)sp_SymStrHash_set(r,a->order[i],sp_SymStrHash_get(a,a->order[i]));for(mrb_int i=0;i<b->len;i++)sp_SymStrHash_set(r,b->order[i],sp_SymStrHash_get(b,b->order[i]));return r;}")
    emit_raw("static mrb_bool sp_SymStrHash_eq(sp_SymStrHash*a,sp_SymStrHash*b){if(!a||!b)return a==b;if(a->len!=b->len)return FALSE;for(mrb_int i=0;i<a->len;i++){sp_sym k=a->order[i];if(!sp_SymStrHash_has_key(b,k))return FALSE;if(!sp_str_eq(sp_SymStrHash_get(a,k),sp_SymStrHash_get(b,k)))return FALSE;}return TRUE;}")
 # Issue #851: inspect for sym_str_hash, rendered with Ruby's
 # `{:k=>"v", ...}` shorthand (sym keys, str values).
    emit_raw("static const char*sp_SymStrHash_inspect(sp_SymStrHash*h){sp_String*s=sp_String_new(\"{\");if(h){for(mrb_int i=0;i<h->len;i++){if(i>0)sp_String_append(s,\", \");sp_String_append(s,sp_sym_to_s(h->order[i]));sp_String_append(s,\": \");sp_String_append(s,sp_str_inspect(sp_SymStrHash_get(h,h->order[i])));}}sp_String_append(s,\"}\");return s->data;}")
 # Cross-variant merge: when a `sym_str_hash` and a `sym_poly_hash`
 # are merged in either direction, both result paths return a
 # fresh sym_poly_hash with the str entries boxed via sp_box_str.
 # Issue #515.
    emit_raw("static sp_SymPolyHash*sp_SymStrHash_to_sym_poly(sp_SymStrHash*h){sp_SymPolyHash*r=sp_SymPolyHash_new();for(mrb_int i=0;i<h->len;i++)sp_SymPolyHash_set(r,h->order[i],sp_box_str(sp_SymStrHash_get(h,h->order[i])));return r;}")
    emit_raw("static sp_SymPolyHash*sp_SymPolyHash_merge_str(sp_SymPolyHash*a,sp_SymStrHash*b){sp_SymPolyHash*r=sp_SymPolyHash_new();for(mrb_int i=0;i<a->len;i++)sp_SymPolyHash_set(r,a->order[i],sp_SymPolyHash_get(a,a->order[i]));for(mrb_int i=0;i<b->len;i++)sp_SymPolyHash_set(r,b->order[i],sp_box_str(sp_SymStrHash_get(b,b->order[i])));return r;}")
    emit_raw("")
  end

 # Symbol type Phase 2, Step 1: collect all SymbolNode content strings
 # into @sym_names as a separate pass (dedup, stable order).

 # Symbol type Phase 2, Step 2: emit the intern table and helpers.
 # SymbolNode now compiles to sp_sym values that index into sp_sym_names.
 # emit the per-program sp_class_names[]
 # table + sp_class_to_s helper. Class ids match the index
 # ordering of @cls_names. Indexed lookups (`sp_class_to_s`)
 # bound-check + return "" for the -1 sentinel that
 # c_default_val("class") emits.
 #
 # The original attempt at this cluster gated emission on
 # @needs_class_table (set by compile_expr's class-const arm),
 # but that flag toggles only after generate_code has already
 # called this function -- so the gate was always 0 at emit
 # time. The simple fix: emit whenever any user class exists.
 # For programs that never reach for a Class value the dead
 # `sp_class_to_s` is `__attribute__((unused))` and
 # link-eliminated, so the only residual cost is the names
 # array (~one cache line for typical small programs, ~1KB at
 # spinel_codegen scale).
  def emit_class_runtime
 # When the program has no Class-value usage, skip the heavy
 # table + helpers but emit a 1-line stub for sp_class_to_s.
 # sp_runtime.h's sp_poly_to_s / sp_poly_inspect chain
 # forward-declares sp_class_to_s and references it in inline
 # bodies; -O2+ DCE's the unused chain, but the
 # codegen-emitted .c is built with -Werror and trips
 # "warning: 'sp_class_to_s' used but never defined" without
 # a definition.
    if @needs_class_table == 0
      emit_raw("static const char *sp_class_to_s(sp_Class c){(void)c;return \"\";}")
 # Exception-class hierarchy helpers stand alone (don't need
 # sp_class_names[]), so emit them even when the rest of the
 # class-runtime cluster is skipped. Issue #627.
      emit_exc_class_hierarchy_helpers
      return
    end
    emit_raw("/* sp_Class names table */")
 # Phase 3 Tier 4: unified cls_id space prefixed with
 # built-in primitives (cls_ids 0..BC-1), then user classes
 # (BC..BC+N-1), then modules (BC+N..BC+N+M-1).
    total_count = unified_class_count
    emit_raw("#define SP_CLASS_COUNT " + total_count.to_s)
    arr_len = total_count
    if arr_len == 0
      arr_len = 1
    end
    line = "static const char *const sp_class_names[" + arr_len.to_s + "] = {"
    bi = 0
    while bi < @builtin_class_names.length
      if bi > 0
        line = line + ","
      end
      line = line + c_string_literal(@builtin_class_names[bi])
      bi = bi + 1
    end
    i = 0
    while i < @cls_names.length
      if @builtin_class_count + i > 0
        line = line + ","
      end
      line = line + c_string_literal(@cls_names[i])
      i = i + 1
    end
    mi = 0
    while mi < @module_names.length
      if @builtin_class_count + @cls_names.length + mi > 0
        line = line + ","
      end
      line = line + c_string_literal(@module_names[mi])
      mi = mi + 1
    end
    if total_count == 0
      line = line + "\"\""
    end
    line = line + "};"
    emit_raw(line)
    emit_raw("static const char *sp_class_to_s(sp_Class c) __attribute__((unused));")
    emit_raw("static const char *sp_class_to_s(sp_Class c){if(c.cls_id>=0&&c.cls_id<SP_CLASS_COUNT)return sp_class_names[c.cls_id];return \"\";}")
 # equality between Class values is by
 # cls_id. Same struct shape on both sides since sp_Class is
 # a single-int wrapper -- a direct field compare is enough.
    emit_raw("static mrb_bool sp_class_eq(sp_Class a, sp_Class b) __attribute__((unused));")
    emit_raw("static mrb_bool sp_class_eq(sp_Class a, sp_Class b){return a.cls_id == b.cls_id;}")
 # parents + flat ancestors tables.
 # Gated on the pre-scan flags (scan_for_class_hierarchy_usage
 # in generate_code) so programs that never reach for
 # .superclass / .ancestors / dynamic is_a? / case-when-on-Class
 # don't pay for the tables + helpers. Programs that do use
 # them keep the full emission unchanged. The basic
 # sp_class_to_s + sp_class_names + sp_class_eq above stay
 # always-emitted because sp_runtime.h's sp_poly_to_s
 # forward-declares sp_class_to_s for its SP_TAG_CLASS arm.
    if @needs_class_parents == 1 && unified_class_count > 0
      parents_line = "static const mrb_int sp_class_parents[" + unified_class_count.to_s + "] __attribute__((unused)) = {"
 # Built-in parents per the design doc table.
      bi_pl = 0
      while bi_pl < @builtin_class_count
        if bi_pl > 0
          parents_line = parents_line + ","
        end
        parents_line = parents_line + @builtin_class_parents[bi_pl].to_s + "LL"
        bi_pl = bi_pl + 1
      end
      pi_pl = 0
      while pi_pl < @cls_names.length
        if @builtin_class_count + pi_pl > 0
          parents_line = parents_line + ","
        end
        ppname = @cls_parents[pi_pl]
        ppidx = -1
        if ppname != ""
          ppidx_internal = find_class_idx(ppname)
          if ppidx_internal >= 0
            ppidx = cls_id_for_user_internal(ppidx_internal)
          else
 # Parent name might be a built-in (e.g., `class Foo < Numeric`)
            ppidx = builtin_class_id_for_name(ppname)
          end
        end
        parents_line = parents_line + ppidx.to_s + "LL"
        pi_pl = pi_pl + 1
      end
 # Modules have no superclass: emit -1 for each module entry.
      mi_pl = 0
      while mi_pl < @module_names.length
        if @builtin_class_count + @cls_names.length + mi_pl > 0
          parents_line = parents_line + ","
        end
        parents_line = parents_line + "-1LL"
        mi_pl = mi_pl + 1
      end
      parents_line = parents_line + "};"
      emit_raw(parents_line)
    end
    if @needs_class_parents == 1 && unified_class_count > 0
      emit_raw("static sp_Class sp_class_superclass(sp_Class c) __attribute__((unused));")
      emit_raw("static sp_Class sp_class_superclass(sp_Class c){if(c.cls_id<0||c.cls_id>=SP_CLASS_COUNT)return (sp_Class){-1};return (sp_Class){sp_class_parents[c.cls_id]};}")
    end
    if @needs_class_ancestors == 1 && unified_class_count > 0
 # Compute ancestors per class at codegen time (Ruby side),
 # emit as a flat array + per-class offset table. Lookup is
 # `sp_class_ancestors_flat[sp_class_ancestors_off[cid] ..
 # sp_class_ancestors_off[cid+1]]`. Matches the Ruby MRO:
 # class includes (reverse order) interleave between the
 # class and its parent chain.
      off = []
      flat = []
      ai = 0
      total_ai = unified_class_count
      while ai < total_ai
        off.push(flat.length)
        acc = compute_ancestors_for_unified(ai)
        aj = 0
        while aj < acc.length
          flat.push(acc[aj])
          aj = aj + 1
        end
        ai = ai + 1
      end
      off.push(flat.length)
      off_line = "static const mrb_int sp_class_ancestors_off[" + (unified_class_count + 1).to_s + "] __attribute__((unused)) = {"
      oi = 0
      while oi < off.length
        if oi > 0
          off_line = off_line + ","
        end
        off_line = off_line + off[oi].to_s + "LL"
        oi = oi + 1
      end
      off_line = off_line + "};"
      emit_raw(off_line)
 # Even an empty flat array would be valid as a C declaration
 # with [0], but ISO C forbids zero-length brace-enclosed
 # initializers in some compilers' stricter modes; guard with
 # a 1-slot sentinel when @cls_names happens to be empty (the
 # outer `@cls_names.length == 0` early return makes this dead
 # in practice, but keep the emit defensible).
      flat_n = flat.length
      if flat_n == 0
        flat_n = 1
      end
      flat_line = "static const mrb_int sp_class_ancestors_flat[" + flat_n.to_s + "] __attribute__((unused)) = {"
      fi = 0
      while fi < flat.length
        if fi > 0
          flat_line = flat_line + ","
        end
        flat_line = flat_line + flat[fi].to_s + "LL"
        fi = fi + 1
      end
      if flat.length == 0
        flat_line = flat_line + "-1LL"
      end
      flat_line = flat_line + "};"
      emit_raw(flat_line)
      emit_raw("static mrb_bool sp_class_le(sp_Class child, sp_Class anc) __attribute__((unused));")
      emit_raw("static mrb_bool sp_class_le(sp_Class child, sp_Class anc){if(child.cls_id<0||child.cls_id>=SP_CLASS_COUNT)return FALSE;mrb_int s=sp_class_ancestors_off[child.cls_id];mrb_int e=sp_class_ancestors_off[child.cls_id+1];for(mrb_int k=s;k<e;k++){if(sp_class_ancestors_flat[k]==anc.cls_id)return TRUE;}return FALSE;}")
      emit_raw("static mrb_bool sp_class_lt(sp_Class child, sp_Class anc) __attribute__((unused));")
      emit_raw("static mrb_bool sp_class_lt(sp_Class child, sp_Class anc){if(child.cls_id==anc.cls_id)return FALSE;return sp_class_le(child,anc);}")
      emit_raw("static sp_PolyArray *sp_class_ancestors_arr(sp_Class c) __attribute__((unused));")
      emit_raw("static sp_PolyArray *sp_class_ancestors_arr(sp_Class c){sp_PolyArray*r=sp_PolyArray_new();if(c.cls_id<0||c.cls_id>=SP_CLASS_COUNT)return r;mrb_int s=sp_class_ancestors_off[c.cls_id];mrb_int e=sp_class_ancestors_off[c.cls_id+1];for(mrb_int k=s;k<e;k++){sp_Class el={sp_class_ancestors_flat[k]};sp_PolyArray_push(r,sp_box_class(el));}return r;}")
    end
    emit_exc_class_hierarchy_helpers
    if @needs_class_for_poly == 1
 # Tier 4: recover the cls_id of a poly value. Each primitive
 # tag maps to the corresponding built-in cls_id (Integer=9,
 # Float=10, String=11, Symbol=12, NilClass=5, TrueClass=6,
 # FalseClass=7); SP_TAG_OBJ with built-in negative cls_id
 # maps to Array / Hash / Range / Time / Proc. SP_TAG_CLASS
 # returns itself; SP_TAG_OBJ with non-negative cls_id is a
 # user-class instance.
      enc_cls_id = builtin_class_id_for_name("Encoding")
      emit_raw("static sp_Class sp_class_for_poly(sp_RbVal v) __attribute__((unused));")
      emit_raw("static sp_Class sp_class_for_poly(sp_RbVal v){switch(v.tag){case SP_TAG_NIL:return (sp_Class){5};case SP_TAG_BOOL:return (sp_Class){v.v.b?6:7};case SP_TAG_INT:return (sp_Class){9};case SP_TAG_FLT:return (sp_Class){10};case SP_TAG_STR:return (sp_Class){11};case SP_TAG_SYM:return (sp_Class){12};case SP_TAG_CLASS:return (sp_Class){(mrb_int)v.cls_id};case SP_TAG_ENCODING:return (sp_Class){" + enc_cls_id.to_s + "};case SP_TAG_OBJ:if(v.cls_id>=0)return (sp_Class){(mrb_int)v.cls_id};switch(v.cls_id){case SP_BUILTIN_INT_ARRAY:case SP_BUILTIN_STR_ARRAY:case SP_BUILTIN_FLT_ARRAY:case SP_BUILTIN_SYM_ARRAY:case SP_BUILTIN_PTR_ARRAY:case SP_BUILTIN_POLY_ARRAY:return (sp_Class){13};case SP_BUILTIN_STR_INT_HASH:case SP_BUILTIN_STR_STR_HASH:case SP_BUILTIN_INT_STR_HASH:case SP_BUILTIN_SYM_INT_HASH:case SP_BUILTIN_SYM_STR_HASH:case SP_BUILTIN_STR_POLY_HASH:case SP_BUILTIN_SYM_POLY_HASH:case SP_BUILTIN_POLY_POLY_HASH:return (sp_Class){14};case SP_BUILTIN_RANGE:return (sp_Class){15};case SP_BUILTIN_TIME:return (sp_Class){16};case SP_BUILTIN_PROC:return (sp_Class){20};default:return (sp_Class){-1};}}return (sp_Class){-1};}")
    end
    emit_raw("")
  end

 # Exception class-name parent walker. `rescue ParentClass` and
 # `e.is_a?(ParentClass)` need to know that `class B < A` makes
 # any `raise B` instance match a `rescue A`. The walker takes
 # class names (not cls_ids) because the rescue path tracks
 # sp_last_exc_cls as a string -- the raised class might not be
 # in the codegen-emitted sp_class_names[] table (e.g. when the
 # raised class is one of the built-in CRuby exception classes
 # like StandardError that spinel doesn't track as a user class).
 # Issue #627. Independent of @needs_class_table since the walker
 # uses inline strcmp / no sp_class_names lookup.
  def emit_exc_class_hierarchy_helpers
    if @needs_exc_class_hierarchy == 0
      return
    end
    emit_raw("static const char *sp_exc_parent_of(const char *cls) __attribute__((unused));")
    ep_body = "static const char *sp_exc_parent_of(const char *cls){"
 # Built-in exception class hierarchy. Matches MRI's
 # Exception class chain that user code routinely names in
 # `rescue` / `raise` clauses without ever defining them.
    builtin_parents = [
      ["StandardError", "Exception"],
      ["RuntimeError", "StandardError"],
      ["ArgumentError", "StandardError"],
      ["TypeError", "StandardError"],
      ["IndexError", "StandardError"],
      ["KeyError", "IndexError"],
      ["RangeError", "StandardError"],
      ["FloatDomainError", "RangeError"],
      ["NameError", "StandardError"],
      ["NoMethodError", "NameError"],
      ["ZeroDivisionError", "StandardError"],
      ["IOError", "StandardError"],
      ["EOFError", "IOError"],
      ["FrozenError", "RuntimeError"],
      ["NotImplementedError", "ScriptError"],
      ["ScriptError", "Exception"],
      ["LoadError", "ScriptError"],
      ["SyntaxError", "ScriptError"],
      ["StopIteration", "IndexError"],
      ["RegexpError", "StandardError"],
      ["EncodingError", "StandardError"],
      ["SystemCallError", "StandardError"],
      ["LocalJumpError", "StandardError"],
      ["FiberError", "StandardError"],
      ["Exception", ""],
    ]
    bp = 0
    while bp < builtin_parents.length
      cname_bp = builtin_parents[bp][0]
      pname_bp = builtin_parents[bp][1]
      if pname_bp == ""
        ep_body = ep_body + "if(strcmp(cls,\"" + cname_bp + "\")==0)return NULL;"
      else
        ep_body = ep_body + "if(strcmp(cls,\"" + cname_bp + "\")==0)return \"" + pname_bp + "\";"
      end
      bp = bp + 1
    end
 # User exception classes (and any user class -- the walker is
 # name-based so it works uniformly). Emit each (cname, parent)
 # pair from @cls_names + @cls_parents.
    uc = 0
    while uc < @cls_names.length
      pname_uc = ""
      if uc < @cls_parents.length
        pname_uc = @cls_parents[uc]
      end
      if pname_uc != ""
        ep_body = ep_body + "if(strcmp(cls,\"" + @cls_names[uc] + "\")==0)return \"" + pname_uc + "\";"
      end
      uc = uc + 1
    end
    ep_body = ep_body + "return NULL;}"
    emit_raw(ep_body)
    emit_raw("static mrb_bool sp_exc_class_le(const char *cls, const char *target) __attribute__((unused));")
    emit_raw("static mrb_bool sp_exc_class_le(const char *cls, const char *target){if(!cls||!target)return FALSE;if(strcmp(cls,target)==0)return TRUE;const char *cur=cls;int depth=0;while(cur&&depth<32){cur=sp_exc_parent_of(cur);if(!cur)return FALSE;if(strcmp(cur,target)==0)return TRUE;depth++;}return FALSE;}")
  end

 # unified cls_id space layout.
 # The emit-side cls_id is global: built-ins occupy
 # [0 .. builtin_class_count - 1], user classes
 # [BC .. BC + N - 1], modules [BC + N .. BC + N + M - 1].
 # Internal Ruby indices into @cls_names / @module_names stay
 # 0-based; conversion happens through the helpers below.
  def cls_id_for_user_internal(internal_ci)
    @builtin_class_count + internal_ci
  end

  def cls_id_for_module_internal(internal_mi)
    @builtin_class_count + @cls_names.length + internal_mi
  end

 # Returns -1 when name doesn't match a built-in.
  def builtin_class_id_for_name(name)
    bi = 0
    while bi < @builtin_class_names.length
      if @builtin_class_names[bi] == name
        return bi
      end
      bi = bi + 1
    end
    -1
  end

 # Public-facing: name -> emit cls_id, searching built-ins
 # first, then user classes, then modules. Returns -1 on miss.
  def unified_cls_id_for_name(name)
    bi = builtin_class_id_for_name(name)
    if bi >= 0
      return bi
    end
    ci = find_class_idx(name)
    if ci >= 0
      return cls_id_for_user_internal(ci)
    end
    mi = find_module_idx_local(name)
    if mi >= 0
      return cls_id_for_module_internal(mi)
    end
    -1
  end

 # unified cls_id space spans
 # @cls_names (0 .. N-1) followed by @module_names
 # (N .. N+M-1). Helpers below resolve names and ids in that
 # combined view; the standalone find_class_idx still works
 # for class-only lookups.
  def unified_class_count
    @builtin_class_count + @cls_names.length + @module_names.length
  end

  def find_module_idx_local(name)
    mi = 0
    while mi < @module_names.length
      if @module_names[mi] == name
        return mi
      end
      mi = mi + 1
    end
    -1
  end

  def find_class_or_module_unified_idx(name)
    return unified_cls_id_for_name(name)
  end

  def acc_includes(acc, uid)
    k = 0
    while k < acc.length
      if acc[k] == uid
        return 1
      end
      k = k + 1
    end
    0
  end

 # MRO over unified cls_id space.
 # Three ranges:
 # [0 .. BC-1] -> built-in (table-driven, hardcoded
 # parents + includes per design doc)
 # [BC .. BC+N-1] -> user class (walk @cls_parents +
 # @cls_includes)
 # [BC+N .. BC+N+M-1] -> module (just self, modules don't
 # include other modules in our model)
  def compute_ancestors_for_unified(uid)
    if uid < 0 || uid >= unified_class_count
      return []
    end
    acc = []
    if uid < @builtin_class_count
 # Built-in. Walk hardcoded parent + includes per the design
 # doc table. Same MRO shape as the user-class arm.
      cur = uid
      acc.push(cur)
      incs_str = @builtin_class_includes[cur]
      incs = incs_str.split(";", -1)
      j = incs.length - 1
      while j >= 0
        if incs[j] != ""
          mod_uid = unified_cls_id_for_name(incs[j])
          if mod_uid >= 0
            sub = compute_ancestors_for_unified(mod_uid)
            sj = 0
            while sj < sub.length
              if acc_includes(acc, sub[sj]) == 0
                acc.push(sub[sj])
              end
              sj = sj + 1
            end
          end
        end
        j = j - 1
      end
      pp = @builtin_class_parents[cur]
      if pp >= 0
        psub = compute_ancestors_for_unified(pp)
        pj = 0
        while pj < psub.length
          if acc_includes(acc, psub[pj]) == 0
            acc.push(psub[pj])
          end
          pj = pj + 1
        end
      end
      return acc
    end
    if uid >= @builtin_class_count + @cls_names.length
 # Module entry. Just itself.
      acc.push(uid)
      return acc
    end
 # User class. Walk down: self, includes (reverse), parent's
 # ancestors. Internal index is uid - BC; cls_id emitted for
 # the entry stays unified (uid).
    cur_internal = uid - @builtin_class_count
    acc.push(uid)
    incs_str = ""
    if cur_internal < @cls_includes.length
      incs_str = @cls_includes[cur_internal]
    end
    incs = incs_str.split(";", -1)
    j = incs.length - 1
    while j >= 0
      if incs[j] != ""
        mod_uid = unified_cls_id_for_name(incs[j])
        if mod_uid >= 0
          sub = compute_ancestors_for_unified(mod_uid)
          sj = 0
          while sj < sub.length
            if acc_includes(acc, sub[sj]) == 0
              acc.push(sub[sj])
            end
            sj = sj + 1
          end
        end
      end
      j = j - 1
    end
    pname = @cls_parents[cur_internal]
    if pname != ""
      pp_uid = -1
      pp_internal = find_class_idx(pname)
      if pp_internal >= 0
        pp_uid = cls_id_for_user_internal(pp_internal)
      else
 # Parent is a built-in class (StandardError / Object /
 # Numeric / etc.). find_class_idx only walks the user
 # table — fall through to the unified name table so the
 # MRO picks up the built-in ancestor chain.
        pp_uid = unified_cls_id_for_name(pname)
      end
      if pp_uid >= 0
        psub = compute_ancestors_for_unified(pp_uid)
        pj = 0
        while pj < psub.length
          if acc_includes(acc, psub[pj]) == 0
            acc.push(psub[pj])
          end
          pj = pj + 1
        end
      end
    end
    acc
  end

 # Kept for any callers that still want a class-only view; routes
 # through the unified MRO so behavior stays consistent.
  def compute_ancestors_for_class(ci)
    compute_ancestors_for_unified(cls_id_for_user_internal(ci))
  end

  def emit_sym_runtime
    if @sym_names.length > 0
      emit_raw("/* sp_sym intern table */")
      emit_raw("#define SP_SYM_COUNT " + @sym_names.length.to_s)
      line = "static const char *const sp_sym_names[" + @sym_names.length.to_s + "] = {"
      i = 0
      while i < @sym_names.length
        if i > 0
          line = line + ","
        end
        line = line + c_string_literal(@sym_names[i])
        i = i + 1
      end
      line = line + "};"
      emit_raw(line)
      if @needs_sym_intern == 1
 # Dynamic intern pool: String#to_sym at runtime.
        emit_raw("static const char **sp_sym_dyn_names = NULL;")
        emit_raw("static mrb_int sp_sym_dyn_count = 0;")
        emit_raw("static mrb_int sp_sym_dyn_cap = 0;")
        emit_raw("static sp_sym sp_sym_intern(const char *s) __attribute__((unused));")
        emit_raw("static sp_sym sp_sym_intern(const char *s){mrb_int i;for(i=0;i<SP_SYM_COUNT;i++){if(strcmp(sp_sym_names[i],s)==0)return (sp_sym)i;}for(i=0;i<sp_sym_dyn_count;i++){if(strcmp(sp_sym_dyn_names[i],s)==0)return (sp_sym)(SP_SYM_COUNT+i);}if(sp_sym_dyn_count>=sp_sym_dyn_cap){sp_sym_dyn_cap=sp_sym_dyn_cap?sp_sym_dyn_cap*2:8;sp_sym_dyn_names=(const char**)realloc(sp_sym_dyn_names,sizeof(char*)*sp_sym_dyn_cap);}{size_t sl=strlen(s);char*dup=(char*)malloc(sl+1);memcpy(dup,s,sl+1);sp_sym_dyn_names[sp_sym_dyn_count]=dup;}return (sp_sym)(SP_SYM_COUNT+sp_sym_dyn_count++);}")
        emit_raw("static const char *sp_sym_to_s(sp_sym id) __attribute__((unused));")
        emit_raw("static const char *sp_sym_to_s(sp_sym id){if(id<0)return \"\";if(id<SP_SYM_COUNT)return sp_sym_names[id];mrb_int idx=(mrb_int)id-SP_SYM_COUNT;if(idx>=sp_sym_dyn_count)return \"\";return sp_sym_dyn_names[idx];}")
      else
        emit_raw("static const char *sp_sym_to_s(sp_sym id) __attribute__((unused));")
        emit_raw("static const char *sp_sym_to_s(sp_sym id){if(id>=0&&id<SP_SYM_COUNT)return sp_sym_names[id];return \"\";}")
      end
 # Emit SPS_<name> defines for symbols that form valid C identifiers.
      i = 0
      while i < @sym_names.length
        nm = @sym_names[i]
        if sym_is_c_ident(nm) == 1
          emit_raw("#define SPS_" + nm + " ((sp_sym)" + i.to_s + ")")
        end
        i = i + 1
      end
 # Sort comparator for sym arrays: lexical by symbol name.
      if @needs_sym_sort == 1
        emit_raw("static int sp_sym_sort_cmp(const void*a,const void*b) __attribute__((unused));")
        emit_raw("static int sp_sym_sort_cmp(const void*a,const void*b){return strcmp(sp_sym_to_s(*(const sp_sym*)a),sp_sym_to_s(*(const sp_sym*)b));}")
        emit_raw("static void sp_sym_array_sort(sp_IntArray*a) __attribute__((unused));")
        emit_raw("static void sp_sym_array_sort(sp_IntArray*a){qsort(a->data+a->start,a->len,sizeof(mrb_int),sp_sym_sort_cmp);}")
      end
    else
 # No symbols used at all -- emit a 1-line stub.
 # sp_runtime.h's poly_to_s / poly_puts / poly_inspect /
 # SymArray_inspect chain references sp_sym_to_s in inline
 # bodies; -O2+ DCE's them when unused, but -Werror trips
 # on "used but never defined" without a definition. The
 # stub is statically dead (no SP_TAG_SYM values exist when
 # no symbol is ever boxed).
      emit_raw("static const char *sp_sym_to_s(sp_sym id){(void)id;return \"\";}")
    end
    emit_raw("")
    if @needs_sym_int_hash == 1
      emit_sym_int_hash_runtime
    end
    if @needs_sym_str_hash == 1
      emit_sym_str_hash_runtime
    end
 # Sym-key -> str-key converters: emit when both the source sym-keyed
 # variant and the destination str_poly_hash are in use. Lets
 # cross-key-shape merge sites (`{:a => 1}.merge({"b" => 2})`) compose
 # both sides into a single str_poly_hash via sp_StrPolyHash_merge.
 # Sym keys go through sp_sym_to_s; values are boxed to sp_RbVal.
    if @needs_str_poly_hash == 1
      if @needs_sym_int_hash == 1
        emit_raw("static sp_StrPolyHash*sp_StrPolyHash_from_sym_int_hash(sp_SymIntHash*h){sp_StrPolyHash*r=sp_StrPolyHash_new();if(!h)return r;r->default_v=sp_box_int(h->default_v);for(mrb_int i=0;i<h->len;i++){sp_sym k=h->order[i];sp_StrPolyHash_set(r,sp_sym_to_s(k),sp_box_int(sp_SymIntHash_get(h,k)));}return r;}")
      end
      if @needs_sym_str_hash == 1
        emit_raw("static sp_StrPolyHash*sp_StrPolyHash_from_sym_str_hash(sp_SymStrHash*h){sp_StrPolyHash*r=sp_StrPolyHash_new();if(!h)return r;if(h->default_v)r->default_v=sp_box_str(h->default_v);for(mrb_int i=0;i<h->len;i++){sp_sym k=h->order[i];sp_StrPolyHash_set(r,sp_sym_to_s(k),sp_box_str(sp_SymStrHash_get(h,k)));}return r;}")
      end
      if @needs_sym_poly_hash == 1
        emit_raw("static sp_StrPolyHash*sp_StrPolyHash_from_sym_poly_hash(sp_SymPolyHash*h){sp_StrPolyHash*r=sp_StrPolyHash_new();if(!h)return r;r->default_v=h->default_v;for(mrb_int i=0;i<h->len;i++){sp_sym k=h->order[i];sp_StrPolyHash_set(r,sp_sym_to_s(k),sp_SymPolyHash_get(h,k));}return r;}")
      end
    end
  end

 # Index of symbol name in @sym_names, or -1 if not found.
  def sym_name_index(name)
    i = 0
    while i < @sym_names.length
      if @sym_names[i] == name
        return i
      end
      i = i + 1
    end
    -1
  end

 # Compile an expression in a string-context. Wraps with sp_sym_to_s
 # when the expression has type "symbol", otherwise returns the raw
 # expression. Used at boundaries where Symbol values flow into APIs
 # that still expect const char * (catch/throw tag, hash key, etc.).
  def compile_expr_as_string(nid)
    s = compile_expr(nid)
    t = infer_type(nid)
    if t == "symbol"
      return "sp_sym_to_s(" + s + ")"
    end
    if t == "encoding"
      return "sp_encoding_name(" + s + ")"
    end
 # Issue #651: a poly-typed value (commonly an ivar inferred as
 # poly because a `kwarg: nil`-defaulted param writes it) flowing
 # into a setter that expects `const char *` (sp_StrStrHash_set,
 # sp_SymStrHash_set, ...) needs the unboxed string payload. The
 # is_a?(String)-narrowed read site already does this; extend to
 # the un-narrowed shape so the typed-hash setter type-checks.
    if t == "poly"
      @needs_rb_value = 1
      return "(" + s + ").v.s"
    end
    s
  end

 # Compile a symbol literal (by name) to a sp_sym C expression.
 # Prefers SPS_<name> for valid-C-identifier names, otherwise emits
 # the raw integer cast.
  def compile_symbol_literal(name)
    idx = sym_name_index(name)
    if idx < 0
 # Should not happen — collect_sym_names has already run.
      return "sp_sym_intern(" + c_string_literal(name) + ")"
    end
    if sym_is_c_ident(name) == 1
      return "SPS_" + name
    end
    "((sp_sym)" + idx.to_s + ")"
  end

 # True (1) iff s is a non-empty valid C identifier: [A-Za-z_][A-Za-z0-9_]*
  def sym_is_c_ident(s)
    if s.length == 0
      return 0
    end
    i = 0
    while i < s.length
      ch = s[i]
      ok = 0
      if ch == "_"
        ok = 1
      end
      if ch >= "A" && ch <= "Z"
        ok = 1
      end
      if ch >= "a" && ch <= "z"
        ok = 1
      end
      if i > 0 && ch >= "0" && ch <= "9"
        ok = 1
      end
      if ok == 0
        return 0
      end
      i = i + 1
    end
    1
  end

  def emit_regexp_runtime
 # Common regexp types and helpers are in sp_runtime.h
 # Common regexp types and helpers are in sp_runtime.h
 # Only emit program-specific pattern globals and init here
 # Emit compiled pattern globals
    i = 0
    while i < @regexp_patterns.length
      pat = @regexp_patterns[i]
      flags = @regexp_flags[i]
      emit_raw("static mrb_regexp_pattern *sp_re_pat_" + i.to_s + ";")
 # Issue #846: per-slot startup error message. If the pattern
 # came from `Regexp.new("literal")` and failed to compile,
 # the message is stashed here for a deferred raise from the
 # first use site (where the user's begin/rescue is active).
      emit_raw("static const char *sp_re_pat_err_" + i.to_s + " = NULL;")
      i = i + 1
    end
    emit_raw("")
    emit_raw("static void sp_re_init(void) {")
 # Use the quiet startup handler so a bad pattern doesn't
 # terminate sp_re_init (which runs before main()'s setjmp).
    emit_raw("  sp_re_set_error_handler(sp_re_startup_error_handler);")
    i = 0
    while i < @regexp_patterns.length
      pat = @regexp_patterns[i]
      flags = @regexp_flags[i]
      cpat = ""
      pi = 0
      while pi < pat.length
        ch = pat[pi]
        if ch == 92.chr
          cpat = cpat + 92.chr + 92.chr
        elsif ch == 34.chr
          cpat = cpat + 92.chr + 34.chr
        elsif ch == 10.chr
 # Embedded newlines / tabs / CRs in /x patterns must be
 # encoded as escape sequences; emitting them raw produces an
 # unterminated C string literal.
          cpat = cpat + 92.chr + "n"
        elsif ch == 13.chr
          cpat = cpat + 92.chr + "r"
        elsif ch == 9.chr
          cpat = cpat + 92.chr + "t"
        else
          cpat = cpat + ch
        end
        pi = pi + 1
      end
 # Byte count, not character count — `re_compile` reads `pat`
 # as a byte buffer, and a UTF-8 char class (`[₀₁₂…]`) has
 # `pat.length < pat.bytesize`. Truncating to char count cuts
 # off a multi-byte char mid-sequence and the engine reports
 # "unterminated character class". .
      emit_raw("  sp_re_startup_err = NULL;")
      emit_raw("  if (setjmp(sp_re_startup_jmp) == 0) {")
      emit_raw("    sp_re_pat_" + i.to_s + " = re_compile(\"" + cpat + "\", " + pat.bytesize.to_s + ", " + flags + ");")
      emit_raw("  } else {")
      emit_raw("    sp_re_pat_" + i.to_s + " = NULL;")
      emit_raw("    sp_re_pat_err_" + i.to_s + " = sp_re_startup_err;")
      emit_raw("  }")
      i = i + 1
    end
 # Restore the default handler now that pre-compile is done; from
 # this point on a compile failure (per-call-site sp_re_dyn_<N>)
 # raises a catchable RegexpError via sp_raise_cls.
    emit_raw("  sp_re_set_error_handler(sp_re_default_error_handler);")
    emit_raw("}")
    emit_raw("")
  end

 # Per-call-site cached helper for InterpolatedRegularExpressionNode.
 # Each AST source location gets a `sp_re_dyn_<idx>(const char *new_pat)`
 # function with its own function-scope statics for the cached pattern
 # string and compiled engine pattern. On a cache hit (strcmp match) we
 # return the existing pattern; on a miss we re_free the old one and
 # recompile with the call-site's baked flags. This bounds heap to one
 # `mrb_regexp_pattern` per call site (count fixed at AOT compile time)
 # and matches Ruby's per-source-location dynamic-regexp cache. The old
 # `sp_re_runtime_compile` leaked a fresh pattern every evaluation.
  def emit_dyn_regex_helpers
    i = 0
    while i < @dyn_regex_node_ids.length
      flags = @dyn_regex_flags[i]
      emit_raw("static mrb_regexp_pattern *sp_re_dyn_" + i.to_s + "(const char *new_pat) {")
      emit_raw("  static char *cached_str = NULL;")
      emit_raw("  static mrb_regexp_pattern *cached_pat = NULL;")
      emit_raw("  if (cached_str != NULL && strcmp(cached_str, new_pat) == 0) return cached_pat;")
      emit_raw("  re_free(cached_pat);")
      emit_raw("  free(cached_str);")
      emit_raw("  cached_str = strdup(new_pat);")
      emit_raw("  cached_pat = re_compile(new_pat, (int64_t)strlen(new_pat), " + flags + ");")
      emit_raw("  return cached_pat;")
      emit_raw("}")
      emit_raw("")
      i = i + 1
    end
  end

 # ---- Struct emission ----
  def emit_global_constants
 # Emit file-scope constant declarations (initialized in main).
 # Poly-typed consts can't use the runtime-call default
 # (sp_box_nil() isn't a constant expression at file scope), so
 # emit a struct initializer pinning the tag to SP_TAG_NIL.
    i = 0
    while i < @const_names.length
      ctp = c_type(@const_types[i])
      if @const_types[i] == "poly"
        emit_raw("static " + ctp + " cst_" + @const_names[i] + " = {SP_TAG_NIL, 0, {0}};")
      else
        emit_raw("static " + ctp + " cst_" + @const_names[i] + " = " + c_default_val(@const_types[i]) + ";")
      end
 # Issue #646: per-const in-progress flag for consts whose init
 # RHS is `<Class>.new(...)`. Set around the assignment in main;
 # read sites of this const inside the class hierarchy raise
 # NameError when the flag is set (slot is NULL during init).
      if i < @const_init_class.length && @const_init_class[i] != ""
        emit_raw("static int sp_init_in_progress_" + @const_names[i] + " = 0;")
      end
      i = i + 1
    end
    if @const_names.length > 0
      emit_raw("")
    end
 # Emit file-scope class-variable declarations. One C global per
 # (class, name) pair, named `cvar_<ClassName>_<var>`; populated
 # by the ClassVariable*WriteNode codegen arms. If the class-body
 # initializer was a simple literal, collect_cvars folded it into
 # @cvar_init_values; otherwise we fall back to the type default
 # and the cvar is undefined-acting until the first runtime write.
    i = 0
    while i < @cvar_names.length
      ctp = c_type(@cvar_types[i])
      init = @cvar_init_values[i]
      if init == ""
        init = c_default_val(@cvar_types[i])
      end
      emit_raw("static " + ctp + " cvar_" + @cvar_names[i] + " = " + init + ";")
      i = i + 1
    end
    if @cvar_names.length > 0
      emit_raw("")
    end
 # Storage for module-level singleton accessors whose resolved
 # set has 2+ candidates. The slot stores the assigned module's
 # sentinel (mrb_int from `module_sentinel`); the write site
 # emits `slot = N;` and the chain dispatch reads back via a
 # sentinel switch.
    j = 0
    emitted = 0
    while j < @module_acc_keys.length
      consts = @module_acc_consts[j]
 # Emit the sentinel slot whenever the accessor resolved to
 # one or more concrete constants. Even the single-candidate
 # case needs the slot: assignments write to it
 # (sp_module_<Mod>_<acc> = sentinel) and reads from `.nil?`
 # / `.is_a?` need to compare against 0 (unassigned).
      if consts != "" && consts != "?"
        key = @module_acc_keys[j]
 # key shape is "<Mod>.<accessor>"; turn the dot into an
 # underscore for the C identifier.
        dot = key.index(".")
        mod = key[0, dot]
        acc = key[dot + 1, key.length - dot - 1]
        emit_raw("static mrb_int sp_module_" + mod + "_" + sanitize_name(acc) + " = 0;")
        emitted = 1
      end
      j = j + 1
    end
    if emitted == 1
      emit_raw("")
    end
  end


  def self_arrow
 # `@self_override` lets default-arg substitution redirect `self`
 # to an explicit receiver expression: when a callee's default
 # expression is inlined into the caller, `self` would otherwise
 # resolve to the caller's `self`, but the default was authored
 # against the callee's instance. Store the bare expression
 # (e.g. `lv_f`) and append the arrow / dot here.
    if @self_override != nil && @self_override != ""
      if @current_class_idx >= 0 && @cls_is_value_type[@current_class_idx] == 1
        return @self_override + "."
      end
      return @self_override + "->"
    end
    if @current_class_idx >= 0
      if @cls_is_value_type[@current_class_idx] == 1
        return "self."
      end
    end
    "self->"
  end

 # The C expression that should be used wherever bare `self`
 # would normally appear (e.g. as the first arg to a same-class
 # method dispatch). Defaults to `"self"`; default-arg inlining
 # overrides it via `@self_override`.
  def self_expr
    if @self_override != nil && @self_override != ""
      return @self_override
    end
    "self"
  end








 # Walk `nid`'s subtree and collect every `Cls.new(...)` class name
 # into `out`. Used by detect_poly_returned_types to enumerate the
 # classes returned (directly or via a temp) from a poly-returning
 # method body.


 # Track classes whose instances flow into a poly-typed param
 # slot at any call site. The boxing helper `sp_box_obj(p, ci)`
 # takes `void *p`; a value-type-eligible class would emit
 # `sp_box_obj(sp_<C>_new(...), ci)` or `sp_box_obj(local, ci)`
 # where `local` is the value-type struct, feeding a
 # struct-by-value into a `void *` slot — a C type error.
 # Excluding such classes from the value-type optimization keeps
 # `<C>` heap-allocated, so the boxing argument is always a
 # stable pointer.
 #
 # Surfaces when kwargs widening collapses two or more concrete
 # obj-typed call sites for the same kwarg into "poly" — at that
 # point the call site starts boxing the instance, hitting the
 # same struct-by-void-* mismatch the ptr_array / poly-return
 # passes already guard against.




 # Build the set of class indices whose instances are captured by a
 # `method(:foo)` / `<obj>.method(:foo)` and end up stored in a
 # heap-allocated Method's `@self_obj`. Such classes must stay
 # heap-allocated — value-type optimization would put `self` on the
 # caller's stack, and the captured pointer would dangle when the
 # binding method returns. .
 #
 # The walk needs scope set up so `infer_type` on a chained
 # `<recv>.method(:foo)` can resolve `<recv>` (a local, an ivar via
 # attr_reader, or a chained call) back to its `obj_<X>` type.





 # Return "static inline " for short methods so gcc has permission
 # to inline them, or "static " otherwise. Body of ≤ 3 statements,
 # no yield, and not self-recursive are considered inlineable.

  def method_linkage_named(body_id, has_yield, mname)
    if has_yield == 1
      return "static "
    end
    if body_id < 0
      return "static inline "
    end
    stmts = get_stmts(body_id)
    if stmts.length > 3
      return "static "
    end
 # Avoid inlining self-recursive methods: static inline on a recursive
 # function can blow up code size and hurt performance (gcc tries
 # to inline harder than it should).
    if mname != "" && node_calls_name?(body_id, mname) == 1
      return "static "
    end
    "static inline "
  end

 # Return 1 if any CallNode in the subtree invokes mname.
  def node_calls_name?(nid, mname)
    if nid < 0
      return 0
    end
    if @nd_type[nid] == "CallNode" && @nd_name[nid] == mname
      return 1
    end
    if @nd_receiver[nid] >= 0
      if node_calls_name?(@nd_receiver[nid], mname) == 1
        return 1
      end
    end
    args_id = @nd_arguments[nid]
    if args_id >= 0
      arr = get_args(args_id)
      k = 0
      while k < arr.length
        if node_calls_name?(arr[k], mname) == 1
          return 1
        end
        k = k + 1
      end
    end
    if @nd_body[nid] >= 0
      if node_calls_name?(@nd_body[nid], mname) == 1
        return 1
      end
    end
    stmts = parse_id_list(@nd_stmts[nid])
    k = 0
    while k < stmts.length
      if node_calls_name?(stmts[k], mname) == 1
        return 1
      end
      k = k + 1
    end
    if @nd_subsequent[nid] >= 0
      if node_calls_name?(@nd_subsequent[nid], mname) == 1
        return 1
      end
    end
    0
  end

 # Should the emit pipeline skip class ci's struct + constructor +
 # gc_scan + initialize? Currently only Method (the built-in
 # registered by spinel_analyze) qualifies, and only when no usage
 # site triggered @needs_method. Programs that never reach for
 # `method(:sym)` / `Method.new` / hash literals get ~25 lines of
 # dead C trimmed from their .c output.
  def cls_emit_skipped(ci)
    if ci < 0 || ci >= @cls_names.length
      return 0
    end
    if @cls_names[ci] == "Method" && @needs_method == 0
      return 1
    end
    0
  end

  def emit_class_structs
 # Forward declare typedefs
    i = 0
    while i < @cls_names.length
      if cls_emit_skipped(i) == 0
        emit_raw("typedef struct sp_" + @cls_names[i] + "_s sp_" + @cls_names[i] + ";")
      end
      i = i + 1
    end
    if @cls_names.length > 0
      emit_raw("")
    end
 # Struct definitions, ordered so a class with a value-type ivar of
 # type X is emitted after X (C requires the embedded struct's full
 # definition to be visible). Pointer-typed ivars only need the
 # forward typedef above, so they impose no ordering constraint.
    @struct_emitted = []
    i = 0
    while i < @cls_names.length
      @struct_emitted.push(0)
      i = i + 1
    end
    i = 0
    while i < @cls_names.length
      if cls_emit_skipped(i) == 0
        emit_class_struct_with_deps(i)
      end
      i = i + 1
    end
  end

  def emit_class_struct_with_deps(ci)
    if @struct_emitted[ci] == 1
      return
    end
    if cls_emit_skipped(ci) == 1
      return
    end
    @struct_emitted[ci] = 1
 # Walk this class and all its ancestors (whose ivars are flattened
 # into this struct by emit_parent_fields) and emit any value-type
 # field's class struct first.
    ai = ci
    while ai >= 0
      emit_value_type_field_deps(ci, ai)
      if @cls_parents[ai] != ""
        ai = find_class_idx(@cls_parents[ai])
      else
        ai = -1
      end
    end
    emit_raw("struct sp_" + @cls_names[ci] + "_s {")
    emit_class_fields(ci)
    emit_raw("};")
    emit_raw("")
  end

  def emit_value_type_field_deps(orig_ci, ai)
    types = @cls_ivar_types[ai].split(";", -1)
    j = 0
    while j < types.length
      emit_value_type_field_dep(orig_ci, types[j])
      j = j + 1
    end
  end

  def emit_value_type_field_dep(orig_ci, t)
    if is_value_type_obj(t) == 1
      cname = t[4, t.length - 4]
      di = find_class_idx(cname)
      if di >= 0 && di != orig_ci
        emit_class_struct_with_deps(di)
      end
    end
  end

 # a class is a layout-root iff it has no parent in
 # @cls_names (either no declared parent, or its declared parent
 # is a built-in like StandardError that spinel doesn't emit as
 # a sp_<C> struct). Layout-roots own the cls_id slot at offset
 # 0; subclasses pick it up through parent-fields-first walking.
  def is_layout_root(ci)
    if @cls_parents[ci] == ""
      return 1
    end
    if find_class_idx(@cls_parents[ci]) < 0
      return 1
    end
    0
  end

  def emit_class_fields(ci)
 # per-instance cls_id as the first field on a
 # root-of-its-tree non-value-type class. Subclasses inherit
 # the slot via parent-fields-first ordering, so a cast
 # `sp_Child *` -> `sp_Base *` preserves the cls_id at the
 # same offset and `self->cls_id` reads it correctly from a
 # parent-typed pointer. Value-types are excluded (no
 # heap-allocated instance, no subclasses by design). A class
 # whose declared parent isn't in @cls_names (built-in like
 # StandardError that spinel doesn't model as a sp_* struct)
 # is effectively a root for layout purposes -- treat the same.
    if @cls_is_value_type[ci] == 0 && is_layout_root(ci) == 1
      emit_raw("  mrb_int cls_id;")
    end
 # Parent fields first
    if @cls_parents[ci] != ""
      pi = find_class_idx(@cls_parents[ci])
      if pi >= 0
        emit_parent_fields(pi)
      end
    end
 # Own fields (skip those inherited from parent)
    names = @cls_ivar_names[ci].split(";", -1)
    types = @cls_ivar_types[ci].split(";", -1)
    j = 0
    while j < names.length
      iname = names[j]
      itype = "int"
      if j < types.length
        itype = types[j]
      end
 # Skip if in parent chain
      if @cls_parents[ci] != ""
        pi = find_class_idx(@cls_parents[ci])
        if pi >= 0
          if ivar_in_chain(pi, iname) == 1
            j = j + 1
            next
          end
        end
      end
      fname = sanitize_ivar(iname)
      emit_raw("  " + c_type(itype) + " " + fname + ";")
      j = j + 1
    end
  end

  def emit_parent_fields(ci)
    if @cls_parents[ci] != ""
      pi = find_class_idx(@cls_parents[ci])
      if pi >= 0
        emit_parent_fields(pi)
      end
    end
 # cls_id at the root of the parent chain. See
 # emit_class_fields' comment for the offset-preservation
 # rationale.
    if @cls_is_value_type[ci] == 0 && is_layout_root(ci) == 1
      emit_raw("  mrb_int cls_id;")
    end
    names = @cls_ivar_names[ci].split(";", -1)
    types = @cls_ivar_types[ci].split(";", -1)
    j = 0
    while j < names.length
      iname = names[j]
      itype = "int"
      if j < types.length
        itype = types[j]
      end
      if @cls_parents[ci] != ""
        pi = find_class_idx(@cls_parents[ci])
        if pi >= 0
          if ivar_in_chain(pi, iname) == 1
            j = j + 1
            next
          end
        end
      end
      fname = sanitize_ivar(iname)
      emit_raw("  " + c_type(itype) + " " + fname + ";")
      j = j + 1
    end
  end

  def ivar_in_chain(ci, iname)
    names = @cls_ivar_names[ci].split(";", -1)
    k = 0
    while k < names.length
      if names[k] == iname
        return 1
      end
      k = k + 1
    end
    if @cls_parents[ci] != ""
      pi = find_class_idx(@cls_parents[ci])
      if pi >= 0
        return ivar_in_chain(pi, iname)
      end
    end
    0
  end

  def ivar_is_gc_ptr(t)
    if t == "poly"
      return 1
    end
    if is_obj_type(t) == 1
      if is_value_type_obj(t) == 1
        return 0
      end
      return 1
    end
    if type_is_pointer(t) == 1
      return 1
    end
    0
  end

  def ivar_needs_gc_mark(t)
    if gc_trace_kind(t) != "none"
      return 1
    end
    0
  end

  def value_type_scan_class_name(t)
    bt = base_type(t)
    if is_value_type_obj(bt) == 1
      return bt[4, bt.length - 4]
    end
    ""
  end

  def value_type_needs_gc_scan(t)
    cname = value_type_scan_class_name(t)
    if cname == ""
      return 0
    end
    ci = find_class_idx(cname)
    if ci >= 0 && class_has_ptr_ivars(ci) == 1
      return 1
    end
    0
  end

  def gc_trace_kind(t)
    bt = base_type(t)
    if bt == "poly"
      return "poly"
    end
    if value_type_needs_gc_scan(bt) == 1
      return "value_type"
    end
    if type_is_pointer(bt) == 1
      return "ptr"
    end
    "none"
  end

  def emit_gc_root_line(stmt, raw)
    if raw == 1
      emit_raw("  " + stmt)
    else
      emit("  " + stmt)
    end
    0
  end

  def emit_value_type_field_roots(expr, t, raw, global)
    cname = value_type_scan_class_name(t)
    if cname == ""
      return
    end
    ci = find_class_idx(cname)
    if ci < 0
      return
    end
    names = @cls_ivar_names[ci].split(";", -1)
    types = @cls_ivar_types[ci].split(";", -1)
    j = 0
    while j < names.length
      if j < types.length
        emit_gc_root_for_expr_impl(expr + "." + sanitize_ivar(names[j]), types[j], raw, global)
      end
      j = j + 1
    end
    0
  end

  def emit_gc_root_for_expr_impl(expr, t, raw, global)
    kind = gc_trace_kind(t)
    if kind == "ptr"
      if global == 1
        emit_gc_root_line("_sp_gc_root_push((void**)&" + expr + ");", raw)
      else
        emit_gc_root_line("SP_GC_ROOT(" + expr + ");", raw)
      end
    elsif kind == "value_type"
      emit_value_type_field_roots(expr, t, raw, global)
    end
    0
  end

  def gc_mark_stmt_for_expr(expr, t)
    kind = gc_trace_kind(t)
    if kind == "poly"
      return "sp_mark_rbval(" + expr + ");"
    end
    if kind == "value_type"
      cname = value_type_scan_class_name(t)
      return "sp_" + cname + "_gc_scan(&" + expr + ");"
    end
    if kind == "ptr"
      return "if (" + expr + ") sp_gc_mark((void *)" + expr + ");"
    end
    ""
  end

  def emit_gc_root_for_expr(expr, t)
    emit_gc_root_for_expr_impl(expr, t, 0, 0)
  end

  def emit_raw_gc_root_for_expr(expr, t)
    emit_gc_root_for_expr_impl(expr, t, 1, 0)
  end

  def emit_global_gc_roots_for_expr(expr, t)
    emit_gc_root_for_expr_impl(expr, t, 0, 1)
  end

  def type_needs_gc_root(t)
    kind = gc_trace_kind(t)
    if kind == "ptr" || kind == "value_type"
      return 1
    end
    0
  end

  def class_has_ptr_ivars(ci)
    names = @cls_ivar_names[ci].split(";", -1)
    types = @cls_ivar_types[ci].split(";", -1)
    j = 0
    while j < names.length
      if j < types.length
        if ivar_needs_gc_mark(types[j]) == 1
          return 1
        end
      end
      j = j + 1
    end
    if @cls_parents[ci] != ""
      pi = find_class_idx(@cls_parents[ci])
      if pi >= 0
        return class_has_ptr_ivars(pi)
      end
    end
    0
  end

 # Clear each GC-traced field on the class chain. Called right after
 # SP_POOL_NEW + SP_GC_ROOT(self) to defuse the recycled-slot
 # stale-pointer hazard: if a sub-allocation in the initialize
 # body triggers GC before the body writes every pointer ivar,
 # the gc_scan callback would otherwise mark the prior tenant's
 # freed pointers and crash inside sp_gc_mark.
  def emit_clear_ptr_ivars_for_new(ci)
    emit_clear_ptr_ivars_chain(ci)
  end

  def emit_clear_ptr_ivars_chain(ci)
    if @cls_parents[ci] != ""
      pi = find_class_idx(@cls_parents[ci])
      if pi >= 0
        emit_clear_ptr_ivars_chain(pi)
      end
    end
    names = @cls_ivar_names[ci].split(";", -1)
    types = @cls_ivar_types[ci].split(";", -1)
    j = 0
    while j < names.length
      if j < types.length
 # Skip ivars already cleared by the parent chain walk above.
 # The struct field uses the parent's declared type (parent-fields-
 # first layout in emit_class_fields skips child-side dups), so the
 # parent's init is the one that matches the actual slot type. A
 # second init from the child side reads the child's narrower type
 # table and emits e.g. `NULL` for an sp_RbVal slot — a C type error.
        in_parent = 0
        if @cls_parents[ci] != ""
          pi_dup = find_class_idx(@cls_parents[ci])
          if pi_dup >= 0 && ivar_in_chain(pi_dup, names[j]) == 1
            in_parent = 1
          end
        end
        if in_parent == 0
          kind = gc_trace_kind(types[j])
          field = "self->" + sanitize_ivar(names[j])
          if kind == "poly"
            emit_raw("  " + field + " = sp_box_nil();")
          elsif kind == "ptr"
            emit_raw("  " + field + " = NULL;")
          elsif kind == "value_type"
            emit_raw("  " + field + " = (" + c_type(types[j]) + "){0};")
          end
        end
      end
      j = j + 1
    end
  end

  def emit_gc_mark_ivar(field, t)
    stmt = gc_mark_stmt_for_expr(field, t)
    if stmt != ""
      emit_raw("  " + stmt)
    end
  end

  def emit_gc_scan_function_prototypes
    emitted_proto = 0
    i = 0
    while i < @cls_names.length
      if cls_emit_skipped(i) == 0 && class_has_ptr_ivars(i) == 1
        emit_raw("static void sp_" + @cls_names[i] + "_gc_scan(void *p);")
        emitted_proto = 1
      end
      i = i + 1
    end
    if emitted_proto == 1
      emit_raw("")
    end
  end

  def emit_gc_scan_functions
    i = 0
    while i < @cls_names.length
      if cls_emit_skipped(i) == 1
        i = i + 1
        next
      end
      if class_has_ptr_ivars(i) == 1
        cname = @cls_names[i]
        emit_raw("static void sp_" + cname + "_gc_scan(void *p) {")
        emit_raw("  sp_" + cname + " *self = (sp_" + cname + " *)p;")
        names = @cls_ivar_names[i].split(";", -1)
        types = @cls_ivar_types[i].split(";", -1)
        j = 0
        while j < names.length
          if j < types.length
 # Skip ivars inherited from parent — emit_class_struct
 # also skips them on the child, so the struct field type
 # comes from the parent's recorded type, and re-emitting
 # here under the child's type info can produce a wrong
 # mark (e.g. parent says int_array, child has widened to
 # poly, struct field is sp_RbVal). The parent walk below
 # marks them via the parent's type.
            skip_inherited = 0
            if @cls_parents[i] != ""
              parent_idx = find_class_idx(@cls_parents[i])
              if parent_idx >= 0
                if ivar_in_chain(parent_idx, names[j]) == 1
                  skip_inherited = 1
                end
              end
            end
            if skip_inherited == 0 && ivar_needs_gc_mark(types[j]) == 1
              emit_gc_mark_ivar("self->" + sanitize_ivar(names[j]), types[j])
            end
          end
          j = j + 1
        end
 # Also scan parent fields
        if @cls_parents[i] != ""
          pi = find_class_idx(@cls_parents[i])
          if pi >= 0
            pnames = @cls_ivar_names[pi].split(";", -1)
            ptypes = @cls_ivar_types[pi].split(";", -1)
            pj = 0
            while pj < pnames.length
              if pj < ptypes.length
                if ivar_needs_gc_mark(ptypes[pj]) == 1
                  emit_gc_mark_ivar("self->" + sanitize_ivar(pnames[pj]), ptypes[pj])
                end
              end
              pj = pj + 1
            end
          end
        end
        emit_raw("}")
        emit_raw("")
      end
      i = i + 1
    end
  end

 # ---- Forward declarations ----
  def emit_forward_decls
 # ARGV (sp_argv) is declared in lib/sp_runtime.h so the runtime's
 # sp_re_mark_globals can mark its strings during GC; emit_main
 # fills in `sp_argv.len = argc - 1; sp_argv.data = ...` from main().

 # Emit block helper functions accumulated during collection
    if @block_funcs != ""
      emit_raw(@block_funcs)
    end
 # Top-level methods
    i = 0
    while i < @meth_names.length
      yp = ""
      if @meth_has_yield[i] == 1
        yp = yield_params_suffix(i)
      end
      emit_raw(method_linkage_named(@meth_body_ids[i], @meth_has_yield[i], @meth_names[i]) + c_type(@meth_return_types[i]) + " sp_" + sanitize_name(@meth_names[i]) + "(" + method_params_decl(i) + yp + ");")
      i = i + 1
    end
 # Class methods
    i = 0
    while i < @cls_names.length
      if cls_emit_skipped(i) == 1
        i = i + 1
        next
      end
      cname = @cls_names[i]
 # Pin @current_class_idx during this forward-decl emit pass
 # so block_params_csig_for_body's infer_type calls (on
 # `@ivar` reads inside yield arg expressions) resolve
 # against this class's ivar table. Otherwise ivars infer
 # to the int default and yields like `yield k, @data[k]`
 # lower to `(mrb_int, mrb_int)` in the decl while the impl
 # emit lowers to `(string, sp_RbVal)` — and the C
 # declaration/definition signatures mismatch.
      saved_ci_decl = @current_class_idx
      @current_class_idx = i
 # Constructor
      init_idx = cls_find_method_direct(i, "initialize")
      if @cls_is_value_type[i] == 1
        emit_raw("static sp_" + cname + " sp_" + cname + "_new(" + constructor_params_decl(i) + ");")
      else
        emit_raw("static sp_" + cname + " *sp_" + cname + "_new(" + constructor_params_decl(i) + ");")
      end
      if init_idx >= 0
        emit_raw("static inline void sp_" + cname + "_initialize(sp_" + cname + " *self" + init_params_decl(i) + ");")
      end
 # Instance methods
      mnames = @cls_meth_names[i].split(";", -1)
      returns = @cls_meth_returns[i].split(";", -1)
      bids = @cls_meth_bodies[i].split(";", -1)
      j = 0
      while j < mnames.length
        if mnames[j] != "initialize"
          rt = "int"
          if j < returns.length
            rt = returns[j]
          end
          yp = ""
          if cls_method_has_yield(i, j) == 1
            yp = yield_params_suffix_cls(i, j)
          end
          sp = " *self"
          if @cls_is_value_type[i] == 1
            sp = " self"
          end
          bid_j = j < bids.length ? bids[j].to_i : -1
          emit_raw(method_linkage_named(bid_j, cls_method_has_yield(i, j), mnames[j]) + c_type(rt) + " sp_" + cname + "_" + sanitize_name(mnames[j]) + "(sp_" + cname + sp + method_with_self_params(i, j) + yp + ");")
        end
        j = j + 1
      end
 # Class methods
      cmnames = @cls_cmeth_names[i].split(";", -1)
      cm_returns = @cls_cmeth_returns[i].split(";", -1)
      j = 0
      while j < cmnames.length
 # Skip forward decls for dead cls methods so the linker
 # doesn't see "declared here" without a definition — the
 # corresponding emit_class_methods skip would otherwise
 # leave the prototype dangling.
        if cls_cmeth_is_live(i, cmnames[j]) == 0
          j = j + 1
        else
          rt = "int"
          if j < cm_returns.length
            rt = cm_returns[j]
          end
          emit_raw("static " + c_type(rt) + " sp_" + cname + "_cls_" + sanitize_name(cmnames[j]) + "(" + cls_method_params_decl(i, j) + ");")
          j = j + 1
        end
      end
      @current_class_idx = saved_ci_decl
      i = i + 1
    end
 # Hoisted instance_eval block functions: emit prototypes here. v1
 # fired only on top-level call sites, where the call always followed
 # the corresponding `static void sp_ieval_<N>(...)` definition (both
 # land in `emit_main` / after `emit_class_methods`). Now that ivar
 # receivers can put the call inside a class method body — emitted
 # before `emit_ieval_funcs` runs — the call would be an implicit
 # declaration without these prototypes.
    n = 0
    while n < @ieval_class_idxs.length
      icn = @cls_names[@ieval_class_idxs[n]]
      proto_ret = "void"
      if n < @ieval_return_types.length
        rt_ie = @ieval_return_types[n]
        if rt_ie != "" && rt_ie != "void"
          proto_ret = ieval_sig_ret(rt_ie)
        end
      end
      if @cls_is_value_type[@ieval_class_idxs[n]] == 1
        emit_raw("static " + proto_ret + " sp_ieval_" + n.to_s + "(sp_" + icn + " self);")
      else
        emit_raw("static " + proto_ret + " sp_ieval_" + n.to_s + "(sp_" + icn + " *self);")
      end
      n = n + 1
    end
    emit_raw("")
  end

  def yield_params_suffix(mi)
    bid = mi >= 0 && mi < @meth_body_ids.length ? @meth_body_ids[mi] : -1
    csig = block_params_csig_for_body(bid, method_yield_arity(mi))
    pd = method_params_decl(mi)
    if pd == ""
      return "void (*_block)(" + csig + ", void*), void *_benv"
    end
    return ", void (*_block)(" + csig + ", void*), void *_benv"
  end

  def yield_params_suffix_cls(ci, midx)
 # For class instance methods (always have self first)
    bid = -1
    if ci >= 0 && ci < @cls_meth_bodies.length
      bodies = @cls_meth_bodies[ci].split(";", -1)
      if midx >= 0 && midx < bodies.length
        bid = bodies[midx].to_i
      end
    end
    csig = block_params_csig_for_body(bid, cls_method_yield_arity(ci, midx))
    return ", void (*_block)(" + csig + ", void*), void *_benv"
  end

 # Build the block fn-pointer C signature from the yield call
 # sites' inferred arg types. block_params_csig alone returns
 # `mrb_int, mrb_int, ...` regardless of what's yielded; this
 # variant inspects the body so a method that yields (String,
 # sp_RbVal) gets `void (*)(const char *, sp_RbVal, void *)` —
 # matching the emitted `_block(lv_k, lv_v, _benv)` call site.
 #
 # Called BEFORE the function's scope has been pushed, so
 # locally-declared vars referenced in yield args (`yield k, v`
 # where `k`, `v` were assigned from typed expressions) are not
 # in @scope_names. Run scan_locals on the body and push a
 # temporary scope so body_yield_arg_types' infer_type calls
 # resolve those reads. Re-runs at both forward-decl emit time
 # and impl emit time; results converge once @meth_* / @cls_*
 # tables stabilize through the type-inference fixpoint.
 # Look up the analyze-projected block param types ("int|bigint|...")
 # for the method whose body_id == bid. Searches top-level methods
 # first, then class instance methods, then class methods. Returns
 # "" if no projection was stored (the body isn't a yield-using
 # method or analyze populated only "" for it).
  def blk_param_types_for_body(bid)
    if bid < 0
      return ""
    end
    if @meth_blk_param_types != nil
      mi_b = 0
      while mi_b < @meth_body_ids.length
        if @meth_body_ids[mi_b] == bid
          if mi_b < @meth_blk_param_types.length
            return @meth_blk_param_types[mi_b]
          end
          return ""
        end
        mi_b = mi_b + 1
      end
    end
    if @cls_cmeth_blk_param_types != nil
      flat_idx_cm = 0
      ci_cm = 0
      while ci_cm < @cls_names.length
        cm_bodies_b = ci_cm < @cls_cmeth_bodies.length ? @cls_cmeth_bodies[ci_cm].split(";", -1) : "".split(",", -1)
        midx_cm_b = 0
        while midx_cm_b < cm_bodies_b.length
          if cm_bodies_b[midx_cm_b].to_i == bid
            if flat_idx_cm < @cls_cmeth_blk_param_types.length
              return @cls_cmeth_blk_param_types[flat_idx_cm]
            end
            return ""
          end
          flat_idx_cm = flat_idx_cm + 1
          midx_cm_b = midx_cm_b + 1
        end
        ci_cm = ci_cm + 1
      end
    end
    ""
  end

  def block_params_csig_for_body(bid, arity)
    if bid < 0 || arity <= 0
      return block_params_csig(arity)
    end
 # Analyze-side projection: @meth_blk_param_types is populated by
 # infer_proc_blk_param_types with per-position yield-arg types
 # ("int" / "bigint") for top-level yield-using methods. When the
 # body's bid matches a yield method's body id, prefer that
 # projection -- it cross-checks promote-mode arith / IntegerNode
 # shapes that walk_and_cache's cache may have left as stale "int".
 # Issue #664 promote-mode tail.
    pre = blk_param_types_for_body(bid)
    if pre != ""
      pre_parts = pre.split("|", -1)
      parts_pre = "".split(",", -1)
      k_pre = 0
      while k_pre < arity
        t_pre = k_pre < pre_parts.length ? pre_parts[k_pre] : "int"
        if t_pre == "" || t_pre == "int"
          parts_pre.push("mrb_int")
        elsif t_pre == "bigint"
          parts_pre.push("sp_Bigint *")
        else
          parts_pre.push(c_type(t_pre))
        end
        k_pre = k_pre + 1
      end
      return parts_pre.join(", ")
    end
    types = "".split(",", -1)
    k = 0
    while k < arity
      types.push("")
      k = k + 1
    end
    push_scope
    lnames = "".split(",", -1)
    ltypes = "".split(",", -1)
    sn_b = @nd_scope_names[bid]
    if sn_b != ""
      lnames = sn_b.split("|", -1)
      ltypes = @nd_scope_types[bid].split("|", -1)
    end
    j = 0
    while j < lnames.length
      declare_var(lnames[j], ltypes[j])
      j = j + 1
    end
 # Also declare the enclosing method's params — they're stored
 # separately from @nd_scope_names but are very much in scope for
 # any yield args. Without this, a `def f(n); yield n; end` lookup
 # of n via infer_type falls back to "int" (the default), masking
 # the param's promote-mode bigint slot and emitting a stale
 # `_block(mrb_int, ...)` signature.
    pi_byc = 0
    while pi_byc < @meth_body_ids.length
      if @meth_body_ids[pi_byc] == bid
        pnames_byc = @meth_param_names[pi_byc].split(",", -1)
        ptypes_byc = @meth_param_types[pi_byc].split(",", -1)
        pp_byc = 0
        while pp_byc < pnames_byc.length
          if pp_byc < ptypes_byc.length && pnames_byc[pp_byc] != ""
            declare_var(pnames_byc[pp_byc], ptypes_byc[pp_byc])
          end
          pp_byc = pp_byc + 1
        end
        pi_byc = @meth_body_ids.length
      else
        pi_byc = pi_byc + 1
      end
    end
 # Class instance methods: same lookup via the per-class tables.
    ci_byc2 = 0
    while ci_byc2 < @cls_meth_bodies.length
      bodies_byc2 = @cls_meth_bodies[ci_byc2].split(";", -1)
      midx_byc2 = 0
      while midx_byc2 < bodies_byc2.length
        if bodies_byc2[midx_byc2].to_i == bid
          pt_byc2 = cls_meth_ptypes_get(ci_byc2, midx_byc2)
          all_params_byc2 = @cls_meth_params[ci_byc2].split("|", -1)
          if midx_byc2 < all_params_byc2.length
            pnames_byc2 = all_params_byc2[midx_byc2].split(",", -1)
            pp_byc2 = 0
            while pp_byc2 < pnames_byc2.length
              if pp_byc2 < pt_byc2.length && pnames_byc2[pp_byc2] != ""
                declare_var(pnames_byc2[pp_byc2], pt_byc2[pp_byc2])
              end
              pp_byc2 = pp_byc2 + 1
            end
          end
          ci_byc2 = @cls_meth_bodies.length
          midx_byc2 = bodies_byc2.length
        else
          midx_byc2 = midx_byc2 + 1
        end
      end
      ci_byc2 = ci_byc2 + 1
    end
    body_yield_arg_types(bid, types)
    pop_scope
    parts = "".split(",", -1)
    k = 0
    while k < arity
      t = types[k]
      if t == "" || t == "int"
        parts.push("mrb_int")
      else
        parts.push(c_type(t))
      end
      k = k + 1
    end
    parts.join(", ")
  end

 # Walk `nid` for YieldNode, accumulating the per-position arg
 # type into `types`. Stops at nested DefNode boundaries (those
 # introduce a new method scope with its own yield arity).
 # Mirrors body_max_yield_arity's traversal shape.
  def body_yield_arg_types(nid, types)
    if nid < 0
      return
    end
    if @nd_type[nid] == "YieldNode"
      if @nd_arguments[nid] >= 0
        args = get_args(@nd_arguments[nid])
        k = 0
        while k < args.length
          if k < types.length
            at = infer_type(args[k])
            if types[k] == ""
              types[k] = at
            elsif types[k] != at
              types[k] = unify_call_types(types[k], at, args[k])
            end
          end
          k = k + 1
        end
      end
      return
    end
    if @nd_type[nid] == "DefNode"
      return
    end
 # When descending into a CallNode that holds a block (each, map,
 # etc.), the block's params shadow outer same-named locals.
 # Without pushing them into scope, `yield x` inside the block sees
 # outer x (often promoted to bigint) and infers wrongly. Push a
 # frame with the block param types resolved against the iterator's
 # element type so the yield arm's infer_type picks them up.
    pushed_byat_scope = 0
    if @nd_type[nid] == "CallNode" && @nd_block[nid] >= 0
      blk_byat = @nd_block[nid]
      bp_byat = @nd_parameters[blk_byat]
      if bp_byat >= 0
        inner_byat = @nd_parameters[bp_byat]
        if inner_byat >= 0
          reqs_byat = parse_id_list(@nd_requireds[inner_byat])
          if reqs_byat.length > 0
            recv_byat = @nd_receiver[nid]
            recv_t_byat = recv_byat >= 0 ? infer_type(recv_byat) : ""
            elem_t_byat = recv_t_byat == "" ? "int" : iter_elem_type(recv_t_byat)
            if elem_t_byat == "" || elem_t_byat == "void"
              elem_t_byat = "int"
            end
            push_scope
            pushed_byat_scope = 1
            bpi_byat = 0
            while bpi_byat < reqs_byat.length
              bn_byat = @nd_name[reqs_byat[bpi_byat]]
              if bn_byat != "" && bn_byat != "_"
                declare_var(bn_byat, elem_t_byat)
              end
              bpi_byat = bpi_byat + 1
            end
          end
        end
      end
    end
    cs = []
    push_child_ids(nid, cs)
    k = 0
    while k < cs.length
      body_yield_arg_types(cs[k], types)
      k = k + 1
    end
    if pushed_byat_scope == 1
      pop_scope
    end
  end

  def cls_method_has_yield(ci, midx)
    ystr = @cls_meth_has_yield[ci].split(";", -1)
    if midx < ystr.length
      if ystr[midx] == "1"
        return 1
      end
    end
    0
  end

 # Max number of args used in any `yield` inside the top-level method
 # at @meth_body_ids[mi]. Floor of 1 — yield-using methods always have
 # at least one mrb_int slot (the no-arg `yield` form is padded to 0).
  def method_yield_arity(mi)
    if mi < 0 || mi >= @meth_body_ids.length
      return 1
    end
    body_max_yield_arity(@meth_body_ids[mi], 1)
  end

 # Same as method_yield_arity, but resolved through the class method
 # body table @cls_meth_bodies (parallel to @cls_meth_has_yield).
  def cls_method_yield_arity(ci, midx)
    if ci < 0 || midx < 0
      return 1
    end
    bodies = @cls_meth_bodies[ci].split(";", -1)
    if midx >= bodies.length
      return 1
    end
    bid = bodies[midx].to_i
    body_max_yield_arity(bid, 1)
  end

 # Comma-joined string of `arity` mrb_int slots — the variable-arity
 # portion of the `_block` function-pointer signature.
  def block_params_csig(arity)
    csig = "mrb_int"
    k = 1
    while k < arity
      csig = csig + ", mrb_int"
      k = k + 1
    end
    csig
  end

 # Returns 1 if the (ci, midx) method declares a `&block` parameter,
 # 0 otherwise. Ruby syntax requires `&block` to be the trailing
 # param, so we check only the last slot — a proc-typed slot in any
 # other position is a positional proc argument, not a block param.
 # Mirrors cls_method_has_yield: call sites use it to decide whether
 # to omit the trailing &block slot from default-padding.
  def cls_method_has_block_param(ci, midx)
    pts = cls_meth_ptypes_get(ci, midx)
    (pts.length > 0 && pts.last == "proc") ? 1 : 0
  end

 # Returns the name of a method's `&block` parameter (the trailing
 # proc-typed slot in pnames), or "" if the method doesn't take
 # one. Ruby syntax requires `&block` to be the trailing param, so
 # a proc-typed slot in any other position is a positional proc
 # argument. Mirrors cls_method_has_block_param's trailing-only
 # check. Used at method-emit time to set @current_method_block_param
 # so block_given? can resolve to (lv_<name> != NULL).
  def find_block_param_name(pnames, ptypes)
    if ptypes.length > 0 && ptypes.last == "proc"
      return pnames.last
    end
    ""
  end

  def cls_find_method_direct(ci, mname)
    mnames = @cls_meth_names[ci].split(";", -1)
    j = 0
    while j < mnames.length
      if mnames[j] == mname
        return j
      end
      j = j + 1
    end
    -1
  end

 # Helpers for the per-method split-join boilerplate around
 # @cls_meth_ptypes / @cls_cmeth_ptypes / @cls_meth_params /
 # @cls_cmeth_params. Each table stores per-class strings where
 # methods are pipe-separated (`|`) and per-method names/types
 # are comma-separated (`,`). Without these, every read site
 # opens with two split() calls + bound checks and every write
 # site closes with two join() calls.
  def cls_meth_ptypes_get(ci, midx)
    if ci < 0 || ci >= @cls_meth_ptypes.length || midx < 0
      return "".split(",", -1)
    end
    all = @cls_meth_ptypes[ci].split("|", -1)
    if midx >= all.length
      return "".split(",", -1)
    end
    all[midx].split(",", -1)
  end


  def cls_meth_pnames_get(ci, midx)
    if ci < 0 || ci >= @cls_meth_params.length || midx < 0
      return "".split(",", -1)
    end
    all = @cls_meth_params[ci].split("|", -1)
    if midx >= all.length
      return "".split(",", -1)
    end
    all[midx].split(",", -1)
  end

  def cls_cmeth_ptypes_get(ci, midx)
    if ci < 0 || ci >= @cls_cmeth_ptypes.length || midx < 0
      return "".split(",", -1)
    end
    all = @cls_cmeth_ptypes[ci].split("|", -1)
    if midx >= all.length
      return "".split(",", -1)
    end
    all[midx].split(",", -1)
  end


  def cls_cmeth_pnames_get(ci, midx)
    if ci < 0 || ci >= @cls_cmeth_params.length || midx < 0
      return "".split(",", -1)
    end
    all = @cls_cmeth_params[ci].split("|", -1)
    if midx >= all.length
      return "".split(",", -1)
    end
    all[midx].split(",", -1)
  end

 # Walk the inheritance chain starting at class `ci` looking for the
 # first ancestor that defines `mname` directly. Returns that class's
 # name, or "" if no ancestor defines it. Used by the
 # `method(:foo)` codegen to build the C symbol of the bound function:
 # an inherited method's generated C function lives under the
 # *defining* class (`sp_Parent_foo`), not the receiver's own class
 # (`sp_Child_foo`), so `&sp_Child_foo` would be an unresolved symbol
 # at link time. When this returns "" the codegen falls back to a
 # null fn_ptr — Ruby's NoMethodError-on-invoke equivalent. .
  def find_defining_class_name(ci, mname)
    walker = ci
    while walker >= 0
      if cls_find_method_direct(walker, mname) >= 0
        return @cls_names[walker]
      end
      if @cls_parents[walker] == ""
        return ""
      end
      walker = find_class_idx(@cls_parents[walker])
    end
    ""
  end

  def method_params_decl(mi)
    mfullname = @meth_names[mi]
    pnames = @meth_param_names[mi].split(",", -1)
    ptypes = @meth_param_types[mi].split(",", -1)
 # Check for open class method
    oc_self = ""
    if mfullname.start_with?("__oc_Integer_")
      oc_self = "mrb_int self"
    end
    if mfullname.start_with?("__oc_String_")
      oc_self = "const char * self"
    end
    if mfullname.start_with?("__oc_Float_")
      oc_self = "mrb_float self"
    end
    if oc_self != ""
      if pnames.length == 0
        return oc_self
      end
      result = oc_self
      j = 0
      while j < pnames.length
        result = result + ", "
        pt = "int"
        if j < ptypes.length
          pt = ptypes[j]
        end
        result = result + c_type(pt) + " lv_" + pnames[j]
        j = j + 1
      end
      return result
    end
    if pnames.length == 0
      if @meth_has_yield[mi] == 1
        return ""
      end
      return "void"
    end
    result = ""
    j = 0
    while j < pnames.length
      if j > 0
        result = result + ", "
      end
      pt = "int"
      if j < ptypes.length
        pt = ptypes[j]
      end
      result = result + c_type(pt) + " lv_" + pnames[j]
      j = j + 1
    end
    result
  end

  def find_init_class(ci)
 # Find which class in the chain has initialize
    init_idx = cls_find_method_direct(ci, "initialize")
    if init_idx >= 0
      return ci
    end
    if @cls_parents[ci] != ""
      pi = find_class_idx(@cls_parents[ci])
      if pi >= 0
        return find_init_class(pi)
      end
    end
    -1
  end

  def constructor_params_decl(ci)
    init_ci = find_init_class(ci)
    if init_ci < 0
      return "void"
    end
    init_idx = cls_find_method_direct(init_ci, "initialize")
    pnames = cls_meth_pnames_get(init_ci, init_idx)
    ptypes = cls_meth_ptypes_get(init_ci, init_idx)
    if pnames.length == 0
      return "void"
    end
    result = ""
    j = 0
    while j < pnames.length
      if j > 0
        result = result + ", "
      end
      pt = "int"
      if j < ptypes.length
        pt = ptypes[j]
      end
      result = result + c_type(pt) + " lv_" + pnames[j]
      j = j + 1
    end
    result
  end

  def init_params_decl(ci)
    init_ci = find_init_class(ci)
    if init_ci < 0
      return ""
    end
    init_idx = cls_find_method_direct(init_ci, "initialize")
    if init_idx < 0
      return ""
    end
    pnames = cls_meth_pnames_get(init_ci, init_idx)
    ptypes = cls_meth_ptypes_get(init_ci, init_idx)
    result = ""
    j = 0
    while j < pnames.length
      pt = "int"
      if j < ptypes.length
        pt = ptypes[j]
      end
      result = result + ", " + c_type(pt) + " lv_" + pnames[j]
      j = j + 1
    end
    result
  end

  def method_with_self_params(ci, midx)
    pnames = cls_meth_pnames_get(ci, midx)
    ptypes = cls_meth_ptypes_get(ci, midx)
    result = ""
    j = 0
    while j < pnames.length
      pt = "int"
      if j < ptypes.length
        pt = ptypes[j]
      end
      result = result + ", " + c_type(pt) + " lv_" + pnames[j]
      j = j + 1
    end
    result
  end

  def cls_method_params_decl(ci, midx)
    pnames = cls_cmeth_pnames_get(ci, midx)
    ptypes = cls_cmeth_ptypes_get(ci, midx)
    if pnames.length == 0
      return "void"
    end
    result = ""
    j = 0
    while j < pnames.length
      if j > 0
        result = result + ", "
      end
      pt = "int"
      if j < ptypes.length
        pt = ptypes[j]
      end
      result = result + c_type(pt) + " lv_" + pnames[j]
      j = j + 1
    end
    result
  end

 # ---- Emit class methods ----
 # Tier 5: dynamic `<Class>.new` over a sp_Class value.
 # Per-user-class adapter + function-pointer table indexed by
 # unified cls_id. Adapters cover only the no-arg shape (the
 # most common case for `klass.new` from a Class-typed local in
 # delegated_type / STI style code). Classes whose initialize
 # requires positional args without defaults get a nil-returning
 # placeholder; callers that need arg-passing still go through
 # the static `Foo.new(...)` dispatch unchanged.
  def emit_class_new_dispatch
    if @cls_names.length == 0
      return
    end
    has_any_no_arg = 0
    i = 0
    while i < @cls_names.length
      if cls_supports_noarg_new(i) == 1
        has_any_no_arg = 1
        i = @cls_names.length
      else
        i = i + 1
      end
    end
    if has_any_no_arg == 0
      return
    end
 # Per-class adapters: only emit for classes that actually
 # support a no-arg constructor. Other slots default to
 # `sp_class_new_nil_fallback` (declared inline below).
    emit_raw("/* sp_Class new-dispatch table Tier 5) */")
    emit_raw("typedef sp_RbVal (*sp_class_new_fn)(void);")
    emit_raw("static sp_RbVal sp_class_new_nil_fallback(void) __attribute__((unused));")
    emit_raw("static sp_RbVal sp_class_new_nil_fallback(void){return sp_box_nil();}")
    i = 0
    while i < @cls_names.length
      if cls_supports_noarg_new(i) == 1
        cname = @cls_names[i]
        uid = cls_id_for_user_internal(i)
        emit_raw("static sp_RbVal sp_" + cname + "_new_dispatch_adapter(void) __attribute__((unused));")
        emit_raw("static sp_RbVal sp_" + cname + "_new_dispatch_adapter(void){return sp_box_obj(sp_" + cname + "_new(), " + uid.to_s + ");}")
      end
      i = i + 1
    end
 # Table indexed by unified cls_id. Built-ins (0..BC-1) and
 # modules (>=BC+N) point at the nil fallback so calling
 # `Integer.new` returns nil rather than miscompiling.
    table_line = "static const sp_class_new_fn sp_class_constructors[SP_CLASS_COUNT] __attribute__((unused)) = {"
    bi = 0
    while bi < @builtin_class_count
      if bi > 0
        table_line = table_line + ","
      end
      table_line = table_line + "sp_class_new_nil_fallback"
      bi = bi + 1
    end
    ui = 0
    while ui < @cls_names.length
      if @builtin_class_count + ui > 0
        table_line = table_line + ","
      end
      if cls_supports_noarg_new(ui) == 1
        table_line = table_line + "sp_" + @cls_names[ui] + "_new_dispatch_adapter"
      else
        table_line = table_line + "sp_class_new_nil_fallback"
      end
      ui = ui + 1
    end
    mi = 0
    while mi < @module_names.length
      if @builtin_class_count + @cls_names.length + mi > 0
        table_line = table_line + ","
      end
      table_line = table_line + "sp_class_new_nil_fallback"
      mi = mi + 1
    end
    table_line = table_line + "};"
    emit_raw(table_line)
    emit_raw("static sp_RbVal sp_class_new_dispatch(sp_Class c) __attribute__((unused));")
    emit_raw("static sp_RbVal sp_class_new_dispatch(sp_Class c){if(c.cls_id<0||c.cls_id>=SP_CLASS_COUNT)return sp_box_nil();return sp_class_constructors[c.cls_id]();}")
    emit_raw("")
  end

 # Tier 5: does class ci support a no-arg `new()` call? Either
 # no initialize defined (default Ruby new takes no args), or
 # initialize has zero params, or every param has a default.
 # Value-type classes are excluded -- their constructor returns
 # a struct (not a pointer), which sp_box_obj can't carry.
  def cls_supports_noarg_new(ci)
    if ci < 0 || ci >= @cls_names.length
      return 0
    end
    if @cls_is_value_type[ci] == 1
      return 0
    end
 # Walk the inheritance chain: M_Sub doesn't define initialize
 # itself but inherits initialize(x) from Base. sp_M_Sub_new's
 # signature comes from the inherited initialize, so the
 # no-arg adapter would mismatch unless we check the
 # parent-chain owner.
 # Walk the inheritance chain: M_Sub doesn't define initialize
 # itself but inherits initialize(x) from Base. sp_M_Sub_new's
 # signature comes from the inherited initialize, so we
 # consult the owner of the chain.
    init_ci = find_init_class(ci)
    if init_ci < 0
      return 1
    end
    init_idx = cls_find_method_direct(init_ci, "initialize")
    if init_idx < 0
      return 1
    end
    pnames = cls_meth_pnames_get(init_ci, init_idx)
 # Only emit the adapter when the constructor's emitted
 # signature is truly zero-arg. Even an all-default-args
 # initialize (`def initialize(hash = {})`) still produces a
 # constructor whose C signature lists every param; default
 # filling happens at the static call site via
 # compile_call_args_with_defaults, not in the constructor
 # itself. The adapter would compile a no-arg call against a
 # one-arg sp_<C>_new and fail. Future tiers can synthesize
 # per-class arg-bridging helpers; the MVP stays conservative.
    if pnames.length == 0
      return 1
    end
    0
  end

  def emit_class_methods
    i = 0
    while i < @cls_names.length
      if cls_emit_skipped(i) == 1
        i = i + 1
        next
      end
      emit_constructor(i)
      mnames = @cls_meth_names[i].split(";", -1)
      returns = @cls_meth_returns[i].split(";", -1)
      all_params = @cls_meth_params[i].split("|", -1)
      all_ptypes = @cls_meth_ptypes[i].split("|", -1)
      bodies = @cls_meth_bodies[i].split(";", -1)
      j = 0
      while j < mnames.length
        if mnames[j] != "initialize"
          rt = "int"
          if j < returns.length
            rt = returns[j]
          end
          bid = -1
          if j < bodies.length
            bid = bodies[j].to_i
          end
          pnames = "".split(",", -1)
          ptypes = "".split(",", -1)
          if j < all_params.length
            pnames = all_params[j].split(",", -1)
          end
          if j < all_ptypes.length
            ptypes = all_ptypes[j].split(",", -1)
          end
          emit_instance_method(i, mnames[j], pnames, ptypes, rt, bid)
        end
        j = j + 1
      end
 # Class methods
      cmnames = @cls_cmeth_names[i].split(";", -1)
      cm_returns = @cls_cmeth_returns[i].split(";", -1)
      cm_params = @cls_cmeth_params[i].split("|", -1)
      cm_ptypes = @cls_cmeth_ptypes[i].split("|", -1)
      cm_bodies = @cls_cmeth_bodies[i].split(";", -1)
 # Per-(class, cmj) scope tables for inherited bodies — see the
 # analyze-side comment on @cls_cmeth_scope_names. Empty fallback
 # when analyze hasn't populated it (legacy compatibility).
      cm_scope_names = @cls_cmeth_scope_names[i].split(";", -1)
      cm_scope_types = @cls_cmeth_scope_types[i].split(";", -1)
      j = 0
      while j < cmnames.length
        rt = "int"
        if j < cm_returns.length
          rt = cm_returns[j]
        end
        bid = -1
        if j < cm_bodies.length
          bid = cm_bodies[j].to_i
        end
        pnames = "".split(",", -1)
        ptypes = "".split(",", -1)

        if j < cm_params.length
          pnames = cm_params[j].split(",", -1)
        end
        if j < cm_ptypes.length
          ptypes = cm_ptypes[j].split(",", -1)
        end
        scope_n_j = ""
        scope_t_j = ""
        if j < cm_scope_names.length
          scope_n_j = cm_scope_names[j]
        end
        if j < cm_scope_types.length
          scope_t_j = cm_scope_types[j]
        end
 # Dead-code-eliminate cls methods with no call site. An
 # unused `def self.factory(attrs); new(attrs); ...; end`
 # would emit a body whose `sp_<this>_new(args)` may not
 # match the defining class's actual constructor arity /
 # types — spinel can't infer types for an uncalled method,
 # so the body fails to C-compile. compute_live_cls_methods
 # ran before emit and seeded live entries from explicit
 # `<Class>.<m>(...)` call sites + transitive self/bare calls
 # within live cls method bodies.
        if cls_cmeth_is_live(i, cmnames[j]) == 0
          j = j + 1
        else
          emit_class_level_method(i, cmnames[j], pnames, ptypes, rt, bid, scope_n_j, scope_t_j)
          j = j + 1
        end
      end
      i = i + 1
    end
  end

 # Dead-code elimination for class methods. An uncalled
 # `def self.factory(attrs); new(attrs); ...; end` on a parent
 # class whose own `initialize` has different arity would emit a
 # body that doesn't C-compile (`sp_<class>_new(args)` against a
 # 0-arg constructor; or, with a default-arg `initialize`,
 # against a typed param the uncalled method itself can't have
 # inferred). The reachability set seeds from explicit
 # `<Class>.<m>(...)` call sites in the AST, then propagates
 # through bare/self calls inside live cls method bodies; anything
 # not reached is skipped at forward-decl + body emit time.
 #
 # Live entries are stored as `<ClassName>::<methodName>` joined
 # by `;` in @cls_cmeth_live. Idempotent: marking an already-live
 # entry is a no-op.

  def cls_meth_is_live(ci, mname)
    if ci < 0 || ci >= @cls_names.length
      return 0
    end
    if @cls_meth_live == nil || @cls_meth_live == ""
      return 0
    end
    needle = ";" + @cls_names[ci] + "::" + mname + ";"
    haystack = ";" + @cls_meth_live + ";"
    if haystack.include?(needle)
      return 1
    end
    0
  end
  def cls_cmeth_is_live(ci, mname)
    if ci < 0 || ci >= @cls_names.length
      return 0
    end
    if @cls_cmeth_live == nil || @cls_cmeth_live == ""
      return 0
    end
 # Sentinel-bracketed lookup so "Foo::bar" doesn't match
 # "Foo::barbaz". `String#include?` returns a clean true/false in
 # both CRuby and spinel; `String#index` works in CRuby but in
 # spinel returns mrb_int (-1 / 0+) and `ix == nil` compiles to
 # `ix == 0`, misclassifying the first-listed entry as missing.
    needle = ";" + @cls_names[ci] + "::" + mname + ";"
    haystack = ";" + @cls_cmeth_live + ";"
    if haystack.include?(needle)
      return 1
    end
    0
  end


 # Walk the subtree at `nid`, marking cls methods reached by:
 # - `<Const>.<m>(...)` (any context)
 # - `self.<m>(...)` (only when ctx_ci >= 0, i.e.
 # we're walking inside a cls method body of class ctx_ci)
 # - bare `<m>(...)` with no recv (ditto; `<m>` resolves to
 # a cls method on ctx_ci if one exists with that name)
 #
 # ctx_ci is propagated unchanged through normal nodes, but cleared
 # to -1 when descending into a DefNode body (a nested method has
 # its own scope; bare calls there resolve to top-level methods or
 # to that DefNode's own class context, neither of which we want
 # to attribute to the outer cls method).

  def emit_constructor_param_roots(ci, init_idx)
    if init_idx < 0
      return
    end
    all_params_str = @cls_meth_params[ci].split("|", -1)
    all_ptypes_str = @cls_meth_ptypes[ci].split("|", -1)
    if init_idx >= all_params_str.length
      return
    end
    cp_names = all_params_str[init_idx].split(",", -1)
    cp_types = "".split(",", -1)
    if init_idx < all_ptypes_str.length
      cp_types = all_ptypes_str[init_idx].split(",", -1)
    end
    cpi = 0
    while cpi < cp_names.length
      if cpi < cp_types.length
        emit_raw_gc_root_for_expr("lv_" + cp_names[cpi], cp_types[cpi])
      end
      cpi = cpi + 1
    end
  end

  def emit_constructor(ci)
    saved_gc_scope = @in_gc_scope
    cname = @cls_names[ci]
    init_idx = cls_find_method_direct(ci, "initialize")
    if @cls_is_value_type[ci] == 1
      emit_raw("static sp_" + cname + " sp_" + cname + "_new(" + constructor_params_decl(ci) + ") {")
      emit_raw("  sp_" + cname + " self = {0};")
      @in_gc_scope = 0
      emit_constructor_param_roots(ci, init_idx)
    else
 # Per-class free-list pool. Unmarked instances are pushed onto a
 # bounded pool by sp_gc_collect (via the recycle hook in sp_gc_hdr)
 # instead of free()d, and re-used by future sp_<Class>_new calls.
 # Cap is uniform across classes (SP_POOL_MAX envvar, default 1M);
 # SP_POOL_REPORT=1 dumps per-class stats at exit.
      emit_raw("SP_POOL_DEFINE(" + cname + ")")
      emit_raw("static inline sp_" + cname + " *sp_" + cname + "_new(" + constructor_params_decl(ci) + ") {")
      emit_raw("  SP_GC_SAVE();")
      @in_gc_scope = 1
      emit_constructor_param_roots(ci, init_idx)
      scan_fn = "NULL"
      if class_has_ptr_ivars(ci) == 1
        scan_fn = "sp_" + cname + "_gc_scan"
      end
      emit_raw("  sp_" + cname + " *self = SP_POOL_NEW(" + cname + ", " + scan_fn + ");")
 # tag the freshly-allocated instance with its
 # concrete class id so a parent-method's `self.class.<cmeth>`
 # path can read self->cls_id at runtime and switch to the
 # subclass's override. Unified cls_id: the emitted id is
 # BC + internal_ci so it sits past the built-in prefix.
      emit_raw("  self->cls_id = " + cls_id_for_user_internal(ci).to_s + "LL;")
      emit_raw("  SP_GC_ROOT(self);")
 # Pool-recycled slots keep the previous tenant's pointer ivars.
 # If the initialize body's RHS triggers GC (e.g. `@flat = []` ->
 # sp_FloatArray_new -> sp_gc_alloc) before each pointer ivar is
 # assigned, the gc_scan callback walks a stale pointer from the
 # prior tenant and crashes. Clear every pointer ivar declared on
 # this class (incl. inherited ones) up front so gc_scan's
 # `if (self->iv_X)` guard short-circuits until the body fills the
 # slot. The poly ivar case is symmetric: a stale sp_RbVal carries
 # a stale .v.p, so reset it to a tagged nil that sp_mark_rbval
 # treats as inert.
      emit_clear_ptr_ivars_for_new(ci)
    end

    init_ci = find_init_class(ci)

    if init_idx >= 0
      bodies = @cls_meth_bodies[ci].split(";", -1)
      bid = -1
      if init_idx < bodies.length
        bid = bodies[init_idx].to_i
      end
      if bid == -2
 # Synthetic struct constructor
        all_params = @cls_meth_params[ci].split("|", -1)
        pnames2 = "".split(",", -1)
        if init_idx < all_params.length
          pnames2 = all_params[init_idx].split(",", -1)
        end
        sk = 0
        while sk < pnames2.length
          sa = "->"
          if @cls_is_value_type[ci] == 1
            sa = "."
          end
          emit_raw("  self" + sa + sanitize_ivar(pnames2[sk]) + " = lv_" + pnames2[sk] + ";")
          sk = sk + 1
        end
      end
      if bid >= 0
        @current_class_idx = ci
 # Pin the synthesized sp_<C>_new function's return type so
 # a bare `return` inside the initialize body lowers to
 # `return self;` (the partially-initialized instance)
 # rather than the default `return 0;` — the latter would
 # silently NULL the pointer-returning constructor for the
 # heap-allocated shape. Value-type constructors return a
 # struct; leave at "" so the bare-return path falls
 # through to its existing 0 default.
        saved_method_return = @current_method_return
        saved_has_self = @current_method_has_self
        @current_method_has_self = 1
        if @cls_is_value_type[ci] == 1
          @current_method_return = ""
        else
          @current_method_return = "obj_" + cname
        end
        pnames = cls_meth_pnames_get(ci, init_idx)
        ptypes = cls_meth_ptypes_get(ci, init_idx)
        push_scope
        k = 0
        while k < pnames.length
          pt = "int"
          if k < ptypes.length
            pt = ptypes[k]
          end
          declare_var(pnames[k], pt)
          k = k + 1
        end
 # Declare any local variables used inside initialize so that
 # `x = 1; @a = x` style bodies don't reference an undeclared lv_x.
        declare_method_locals(bid, pnames)
        stmts = get_stmts(bid)
        stmts.each { |sid|
 # Bare `super` parses as ForwardingSuperNode; `super(args)`
 # parses as SuperNode. Both need to call the parent's
 # initialize. For ForwardingSuperNode we forward the
 # current method's params.
          is_super = (@nd_type[sid] == "SuperNode" || @nd_type[sid] == "ForwardingSuperNode")
          if is_super
            if @cls_parents[ci] != ""
 # When the immediate parent is an "abstract" class
 # (no own `initialize`, e.g. `class ApplicationRecord
 # < ActiveRecord::Base`), the void `_initialize`
 # wrapper is never emitted for it — a literal
 # `sp_<parent>_initialize(...)` call here would be
 # an undefined reference at link time. Walk via
 # find_init_class to skip over abstract ancestors
 # and call the nearest emitted wrapper.
              pi_imm = find_class_idx(@cls_parents[ci])
              pi = pi_imm
              if pi_imm >= 0
                pi = find_init_class(pi_imm)
                if pi < 0
                  pi = pi_imm
                end
              end
              if pi >= 0
 # Look up the parent's init signature so we can cast
 # each forwarded arg to the parent's declared type
 # when it differs (parent's param-type inference may
 # not see this child's type narrowing).
                p_pnames = "".split(",", -1)
                p_ptypes = "".split(",", -1)
                p_init_idx = cls_find_method_direct(pi, "initialize")
                if p_init_idx >= 0
                  p_all_params = @cls_meth_params[pi].split("|", -1)
                  p_all_ptypes = @cls_meth_ptypes[pi].split("|", -1)
                  if p_init_idx < p_all_params.length
                    p_pnames = p_all_params[p_init_idx].split(",", -1)
                  end
                  if p_init_idx < p_all_ptypes.length
                    p_ptypes = p_all_ptypes[p_init_idx].split(",", -1)
                  end
                end
                super_args = ""
                if @nd_type[sid] == "ForwardingSuperNode"
 # Forward the current init's params 1:1.
                  fk = 0
                  while fk < pnames.length
                    if fk > 0
                      super_args = super_args + ", "
                    end
                    arg_expr = "lv_" + pnames[fk]
                    if fk < p_ptypes.length && fk < ptypes.length
                      if p_ptypes[fk] != ptypes[fk] && p_ptypes[fk] != ""
                        arg_expr = "(" + c_type(p_ptypes[fk]) + ")" + arg_expr
                      end
                    end
                    super_args = super_args + arg_expr
                    fk = fk + 1
                  end
                else
                  args_id = @nd_arguments[sid]
                  ak = 0
                  if args_id >= 0
                    arg_ids = get_args(args_id)
                    while ak < arg_ids.length
                      if ak > 0
                        super_args = super_args + ", "
                      end
                      arg_expr2 = compile_expr(arg_ids[ak])
                      if ak < p_ptypes.length
                        at_arg = infer_type(arg_ids[ak])
                        if p_ptypes[ak] != at_arg && p_ptypes[ak] != ""
 # int -> bigint: box via sp_bigint_new_int. A raw cast would
 # produce a NULL pointer for literal 0 / negative ints and
 # garbage for nonzero literals (interprets the int as a heap
 # address). Same shape on the inverse path: bigint -> int
 # unbox via sp_bigint_to_int.
                          if base_type(p_ptypes[ak]) == "bigint" && base_type(at_arg) == "int"
                            @needs_bigint = 1
                            arg_expr2 = "sp_bigint_new_int(" + arg_expr2 + ")"
                          elsif base_type(p_ptypes[ak]) == "int" && base_type(at_arg) == "bigint"
                            @needs_bigint = 1
                            arg_expr2 = "sp_bigint_to_int((sp_Bigint *)" + arg_expr2 + ")"
                          else
                            arg_expr2 = "(" + c_type(p_ptypes[ak]) + ")" + arg_expr2
                          end
                        end
                      end
                      super_args = super_args + arg_expr2
                      ak = ak + 1
                    end
                  end
 # Explicit `super(...)` with fewer args than the
 # parent expects (e.g. `super()` against
 # `def initialize(_attrs = {})`). Ruby fills
 # missing trailing slots from the parent's
 # defaults; the C signature has no defaults, so
 # pad with c_default_val per param type to
 # satisfy gcc's argument count.
                  while ak < p_ptypes.length
                    if super_args != ""
                      super_args = super_args + ", "
                    end
                    super_args = super_args + c_default_val(p_ptypes[ak])
                    ak = ak + 1
                  end
                end
                target_parent_name = @cls_names[pi]
                emit_raw("  sp_" + target_parent_name + "_initialize((sp_" + target_parent_name + " *)self" + (super_args != "" ? ", " + super_args : "") + ");")
              end
            end
          end
          if @nd_type[sid] == "InstanceVariableWriteNode"
            ivar_name = @nd_name[sid]
            ivar = sanitize_ivar(ivar_name)
            expr_id_iv = @nd_expression[sid]
 # Chained `@a = @b = ... = expr` inside `def initialize`.
 # Delegate to compile_stmt's IVW path so the rhs is
 # evaluated once via compile_chained_ivar_writes; the
 # local emit_raw special-cases below assume a non-chained
 # rhs and would otherwise re-evaluate side-effecting
 # CallNodes per slot.
            if @nd_type[expr_id_iv] == "InstanceVariableWriteNode"
              compile_stmt(sid)
            else
 # Match the special-case in compile_stmt: empty `{}` / `[]`
 # assigned to an ivar promoted by scan_writer_calls needs
 # the matching container constructor.
              ivt = cls_ivar_type(@current_class_idx, ivar_name)
              iv_ctor = ""
              if is_empty_hash_literal(expr_id_iv) == 1 && ivt != "" && ivt != "str_int_hash"
                if ivt == "str_str_hash"
                  @needs_str_str_hash = 1
                  iv_ctor = "sp_StrStrHash_new()"
                elsif ivt == "int_str_hash"
                  @needs_int_str_hash = 1
                  iv_ctor = "sp_IntStrHash_new()"
                elsif ivt == "sym_int_hash"
                  @needs_sym_int_hash = 1
                  iv_ctor = "sp_SymIntHash_new()"
                elsif ivt == "sym_str_hash"
                  @needs_sym_str_hash = 1
                  iv_ctor = "sp_SymStrHash_new()"
                elsif ivt == "str_poly_hash"
                  iv_ctor = "sp_StrPolyHash_new()"
                elsif ivt == "sym_poly_hash"
                  iv_ctor = "sp_SymPolyHash_new()"
                elsif ivt == "poly_poly_hash"
                  iv_ctor = "sp_PolyPolyHash_new()"
                end
              end
              if iv_ctor == "" && is_empty_array_literal(expr_id_iv) == 1 && ivt != ""
                iv_ctor = empty_array_new_for_type(ivt)
              end
              if iv_ctor != ""
                @needs_gc = 1
                emit_raw("  " + self_arrow + ivar + " = " + iv_ctor + ";")
              elsif (ivt == "poly_array" || is_ptr_array_type(ivt) == 1) && is_sized_empty_array_default(expr_id_iv) == 1
 # `@arr = [nil] * N` with @arr already widened to
 # poly_array (or ptr_array) via writer-scan. The
 # default `*` codegen produces an sp_IntArray that
 # mismatches the slot type; emit a sized PolyArray
 # of sp_box_nil() (or PtrArray of NULLs) inline.
                @needs_gc = 1
                cnt_e_iv = compile_arg0(expr_id_iv)
                tmp_iv = new_temp
                if ivt == "poly_array"
                  @needs_rb_value = 1
                  emit_raw("  sp_PolyArray *" + tmp_iv + " = sp_PolyArray_new();")
                  emit_raw("  { mrb_int _n = " + cnt_e_iv + "; for (mrb_int _i = 0; _i < _n; _i++) sp_PolyArray_push(" + tmp_iv + ", sp_box_nil()); }")
                else
                  emit_raw("  sp_PtrArray *" + tmp_iv + " = sp_PtrArray_new();")
                  emit_raw("  { mrb_int _n = " + cnt_e_iv + "; for (mrb_int _i = 0; _i < _n; _i++) sp_PtrArray_push(" + tmp_iv + ", NULL); }")
                end
                emit_raw("  " + self_arrow + ivar + " = " + tmp_iv + ";")
              elsif ivt == "poly" && is_sized_empty_array_default(expr_id_iv) == 1
 # `@arr = [nil] * N` against a poly slot. Build a
 # sized PolyArray and box it so the runtime storage
 # supports heterogeneous writes via the poly-recv
 # `[]=` dispatch.
                @needs_gc = 1
                @needs_rb_value = 1
                cnt_e_iv = compile_arg0(expr_id_iv)
                tmp_iv = new_temp
                emit_raw("  sp_PolyArray *" + tmp_iv + " = sp_PolyArray_new();")
                emit_raw("  { mrb_int _n = " + cnt_e_iv + "; for (mrb_int _i = 0; _i < _n; _i++) sp_PolyArray_push(" + tmp_iv + ", sp_box_nil()); }")
                emit_raw("  " + self_arrow + ivar + " = sp_box_poly_array(" + tmp_iv + ");")
              elsif ivt == "poly_array" && @nd_type[expr_id_iv] == "ArrayNode"
 # Non-empty array literal `[a, b, ...]` going into a
 # poly_array slot. compile_array_literal infers a typed
 # storage (ptr_array of one class for homogeneous obj
 # literals, etc.) — emit a fresh PolyArray with each
 # element boxed instead.
                @needs_gc = 1
                @needs_rb_value = 1
                tmp_iv = new_temp
                emit_raw("  sp_PolyArray *" + tmp_iv + " = sp_PolyArray_new();")
                elems_iv = parse_id_list(@nd_elements[expr_id_iv])
                ek = 0
                while ek < elems_iv.length
                  eid = elems_iv[ek]
                  et = infer_type(eid)
 # 3D+ shape: nested ArrayNode with ptr_array elem
 # type → recompile as poly_array so cls_id chain
 # stays tagged through every level.
                  if @nd_type[eid] == "ArrayNode" && (is_ptr_array_type(et) == 1 || et == "poly_array")
                    inner_iv = compile_array_literal_as_poly(eid)
                    emit_raw("  sp_PolyArray_push(" + tmp_iv + ", sp_box_poly_array(" + inner_iv + "));")
                  elsif is_ptr_array_type(et) == 1
 # Same 3D+ erasure but the element is a non-ArrayNode
 # expression (e.g. `Array.new(N) { ... }` returning a
 # typed `<X>_ptr_array`). Convert at runtime so each
 # inner element keeps its real cls_id —
 # `arr[b][i][j]` chains correctly.
                    ev = compile_expr(eid)
                    inner_t_iv = ptr_array_elem_type(et)
                    conv_iv = new_temp
                    ii_iv = new_temp
                    emit_raw("  sp_PolyArray *" + conv_iv + " = sp_PolyArray_new();")
                    emit_raw("  for (mrb_int " + ii_iv + " = 0; " + ii_iv + " < sp_PtrArray_length(" + ev + "); " + ii_iv + "++) {")
                    inner_get_iv = "(" + c_type(inner_t_iv) + ")sp_PtrArray_get(" + ev + ", " + ii_iv + ")"
                    emit_raw("    sp_PolyArray_push(" + conv_iv + ", " + box_value_to_poly(inner_t_iv, inner_get_iv) + ");")
                    emit_raw("  }")
                    emit_raw("  sp_PolyArray_push(" + tmp_iv + ", sp_box_poly_array(" + conv_iv + "));")
                  else
                    ev = compile_expr(eid)
                    ebox = et == "poly" ? ev : box_value_to_poly(et, ev)
                    emit_raw("  sp_PolyArray_push(" + tmp_iv + ", " + ebox + ");")
                  end
                  ek = ek + 1
                end
                emit_raw("  " + self_arrow + ivar + " = " + tmp_iv + ";")
              else
 # Same poly-slot boxing as the general
 # InstanceVariableWriteNode emit path: initialize
 # bodies can introduce one of the disagreeing
 # writes to a multi-typed ivar.
                if ivt == "poly"
                  val = box_expr_to_poly(expr_id_iv)
                elsif ivt == "bigint" && infer_type(expr_id_iv) == "int"
 # `--int-overflow=promote` rewrites every int slot to
 # bigint, but initialize bodies often seed the ivar with
 # a literal int (`@n = 0`). Coerce via sp_bigint_new_int
 # so the C compile sees a sp_Bigint * on both sides.
                  @needs_bigint = 1
                  val = "sp_bigint_new_int(" + compile_expr(expr_id_iv) + ")"
                else
                  val = compile_expr(expr_id_iv)
                end
                emit_raw("  " + self_arrow + ivar + " = " + val + ";")
              end
            end
          else
            if is_super == false
 # Compile other statements (e.g., method calls like @arr[0] = val)
              compile_stmt(sid)
            end
          end
        }
        pop_scope
        @current_class_idx = -1
        @current_method_return = saved_method_return
        @current_method_has_self = saved_has_self
      end
    else
 # No own initialize - call parent's if it exists
      if init_ci >= 0
        if init_ci != ci
          parent_name = @cls_names[init_ci]
 # Build param forwarding: forward all constructor params to parent init
          pi_params = @cls_meth_params[init_ci].split("|", -1)
          pi_idx = cls_find_method_direct(init_ci, "initialize")
          pnames = "".split(",", -1)
          if pi_idx >= 0
            if pi_idx < pi_params.length
              pnames = pi_params[pi_idx].split(",", -1)
            end
          end
          fwd = ""
          pk = 0
          while pk < pnames.length
            if pk > 0
              fwd = fwd + ", "
            end
            fwd = fwd + "lv_" + pnames[pk]
            pk = pk + 1
          end
          emit_raw("  sp_" + parent_name + "_initialize((sp_" + parent_name + " *)self" + (fwd != "" ? ", " + fwd : "") + ");")
        end
      end
    end

    if @cls_is_value_type[ci] == 0
      emit_raw("  SP_GC_RESTORE();")
    end
    emit_raw("  return self;")
    emit_raw("}")
    emit_raw("")
    @in_gc_scope = saved_gc_scope

 # Initialize function (for super calls) - always uses *self (pointer)
    if init_idx >= 0
      saved_vt = @cls_is_value_type[ci]
      @cls_is_value_type[ci] = 0
      emit_raw("static inline void sp_" + cname + "_initialize(sp_" + cname + " *self" + init_params_decl(ci) + ") {")
      bodies = @cls_meth_bodies[ci].split(";", -1)
      bid = -1
      if init_idx < bodies.length
        bid = bodies[init_idx].to_i
      end
      if bid >= 0
 # This wrapper has C return type `void`. Pin
 # @current_method_return so a bare `return` inside the
 # body lowers to the void shape (`return;`) instead of
 # leaking whatever was set during the prior _new emission.
        saved_method_return = @current_method_return
        saved_has_self2 = @current_method_has_self
        @current_method_has_self = 1
        @current_method_return = "void"
        @current_class_idx = ci
 # Reset @in_gc_scope to 0 so declare_method_locals'
 # `@in_gc_scope == 0` guard fires and emits the
 # `SP_GC_SAVE()` that early-`return` paths' matching
 # `SP_GC_RESTORE()` (compile_return_stmt) refers to. The
 # value inherited from emit_constructor above could be 1
 # (stale from a heap constructor's body) and would
 # otherwise leave `_gc_saved` undeclared.
        saved_in_gc_scope2 = @in_gc_scope
        @in_gc_scope = 0
        pnames = cls_meth_pnames_get(ci, init_idx)
        ptypes = cls_meth_ptypes_get(ci, init_idx)
        push_scope
        k = 0
        while k < pnames.length
          pt = "int"
          if k < ptypes.length
            pt = ptypes[k]
          end
          declare_var(pnames[k], pt)
          k = k + 1
        end
 # Declare locals so non-ivar statements (`x = 1`) and
 # expressions that reference them compile.
        declare_method_locals(bid, pnames)
        stmts = get_stmts(bid)
        stmts.each { |sid|
 # SuperNode (`super(...)`) and ForwardingSuperNode (bare
 # `super`) are emitted directly above as the parent
 # `_initialize` call. Skip them here so compile_stmt
 # doesn't emit a dummy `0;` for the AST node.
          if @nd_type[sid] != "SuperNode" && @nd_type[sid] != "ForwardingSuperNode"
            compile_stmt(sid)
          end
        }
        pop_scope
        @current_class_idx = -1
        @current_method_return = saved_method_return
        @current_method_has_self = saved_has_self2
        @in_gc_scope = saved_in_gc_scope2
      end
      emit_raw("}")
      emit_raw("")
      @cls_is_value_type[ci] = saved_vt
    end
  end

  def emit_instance_method(ci, mname, pnames, ptypes, rt, bid)
    cname = @cls_names[ci]
    @current_class_idx = ci
    @current_method_name = mname
    @current_method_return = rt
    @current_method_block_param = find_block_param_name(pnames, ptypes)
    @current_method_has_self = 1
    @indent = 1
    @in_gc_scope = 0

    midx = cls_find_method_direct(ci, mname)
    if midx >= 0
      if cls_method_has_yield(ci, midx) == 1
        @in_yield_method = 1
        @current_method_yield_arity = cls_method_yield_arity(ci, midx)
        cm_bodies_cur = @cls_meth_bodies[ci].split(";", -1)
        bid_cur = midx < cm_bodies_cur.length ? cm_bodies_cur[midx].to_i : -1
        @current_method_blk_param_types = blk_param_types_for_body(bid_cur)
      else
        @in_yield_method = 0
        @current_method_blk_param_types = ""
      end
    end

    yp = ""
    if @in_yield_method == 1
      yp = yield_params_suffix_cls(ci, midx)
    end
    cm_linkage = method_linkage_named(bid, @in_yield_method, mname)
    if @cls_is_value_type[ci] == 1
      emit_raw(cm_linkage + c_type(rt) + " sp_" + cname + "_" + sanitize_name(mname) + "(sp_" + cname + " self" + build_params_str(pnames, ptypes) + yp + ") {")
    else
      emit_raw(cm_linkage + c_type(rt) + " sp_" + cname + "_" + sanitize_name(mname) + "(sp_" + cname + " *self" + build_params_str(pnames, ptypes) + yp + ") {")
    end

    push_scope
    j = 0
    while j < pnames.length
      pt = "int"
      if j < ptypes.length
        pt = ptypes[j]
      end
      declare_var(pnames[j], pt)
      j = j + 1
    end

 # trampoline (`def m(&b); instance_eval(&b); end`):
 # the body is dead at runtime — every call site `recv.m { ... }`
 # gets splice-rewritten by try_yield_or_trampoline_dispatch.
 # Skipping the body compilation avoids the warn-and-emit-0
 # fallback that compile_no_recv_call_expr would hit for the dead
 # `instance_eval(&block)` call inside (which would otherwise fire
 # one warning per trampoline definition every codegen run). The
 # fallback `return c_return_default(rt);` below still provides a
 # syntactically-valid but unreachable C body for the linker.
    is_tramp = 0
    if midx >= 0
      if is_instance_eval_trampoline(ci, midx) == 1
        is_tramp = 1
      end
    end
 # stub uncalled methods so an inferred-int param
 # doesn't fail C-compile against a narrower ivar slot.
    is_dead = 0
    if cls_meth_is_live(ci, mname) == 0
      is_dead = 1
    end
    if is_dead == 1
 # Mark every param as `(void)`-cast so -Wunused doesn't fire,
 # then return the default.
      jd = 0
      while jd < pnames.length
        emit("  (void)lv_" + pnames[jd] + ";")
        jd = jd + 1
      end
    elsif bid >= 0 && is_tramp == 0
      declare_method_locals(bid, pnames)
      if @in_gc_scope == 0
        if @needs_gc == 1
          emit("  SP_GC_SAVE();")
          @in_gc_scope = 1
        end
      end
      if @in_gc_scope == 1
        if @cls_is_value_type[ci] == 0
          emit("  SP_GC_ROOT(self);")
        else
          emit_gc_root_for_expr("self", "obj_" + cname)
        end
        j = 0
        while j < pnames.length
          if j < ptypes.length
            emit_gc_root_for_expr("lv_" + pnames[j], ptypes[j])
          end
          j = j + 1
        end
      end
      compile_body_return(bid, rt)
    end

    pop_scope
    @current_class_idx = -1
    @current_method_name = ""
    @current_method_block_param = ""
    @in_yield_method = 0
    @current_method_yield_arity = 1
    @indent = 0
    emit_raw("  return " + c_return_default(rt) + ";")
    emit_raw("}")
    emit_raw("")
  end

  def emit_class_level_method(ci, mname, pnames, ptypes, rt, bid, scope_n = "", scope_t = "")
    cname = @cls_names[ci]
    @current_class_idx = ci
    @current_method_name = mname
    @current_method_return = rt
    @current_method_block_param = find_block_param_name(pnames, ptypes)
    @current_method_has_self = 0
    @indent = 1
    @in_gc_scope = 0

    emit_raw("static " + c_type(rt) + " sp_" + cname + "_cls_" + sanitize_name(mname) + "(" + build_params_decl(pnames, ptypes) + ") {")

    push_scope
    j = 0
    while j < pnames.length
      pt = "int"
      if j < ptypes.length
        pt = ptypes[j]
      end
      declare_var(pnames[j], pt)
      j = j + 1
    end

    if bid >= 0
 # Prefer per-(ci, cmj) scope tables when analyze populated
 # them. Inherited cmeth bodies share the AST bid across
 # subclasses, so the per-bid @nd_scope_names entry was last-
 # class-wins; the per-(ci, cmj) entry is subclass-specific.
      if scope_n != "" || scope_t != ""
        declare_method_locals_from(scope_n, scope_t, pnames)
      else
        declare_method_locals(bid, pnames)
      end
      if @in_gc_scope == 0
        if @needs_gc == 1
          emit("  SP_GC_SAVE();")
          @in_gc_scope = 1
        end
      end
      if @in_gc_scope == 1
        j = 0
        while j < pnames.length
          if j < ptypes.length
            emit_gc_root_for_expr("lv_" + pnames[j], ptypes[j])
          end
          j = j + 1
        end
      end
      compile_body_return(bid, rt)
    end

    pop_scope
    @current_class_idx = -1
    @current_method_name = ""
    @current_method_block_param = ""
    @indent = 0
    emit_raw("  return " + c_return_default(rt) + ";")
    emit_raw("}")
    emit_raw("")
  end

 # Variant of declare_method_locals that takes precomputed
 # scope tables (in the same "|"-joined format as
 # @nd_scope_names) instead of looking them up by bid. Used by
 # the cmeth emit path to plumb per-(ci, cmj) tables through.
  def declare_method_locals_from(sn, st, params)
    lnames = "".split(",", -1)
    ltypes = "".split(",", -1)
    if sn != ""
      lnames = sn.split("|", -1)
      ltypes = st.split("|", -1)
    end
    j = 0
    while j < lnames.length
      declare_var(lnames[j], ltypes[j])
      j = j + 1
    end
    has_gc_locals = 0
    j = 0
    while j < lnames.length
      if type_needs_gc_root(ltypes[j]) == 1
        has_gc_locals = 1
      end
      j = j + 1
    end
    if has_gc_locals == 1
      if @needs_gc == 1 && @in_gc_scope == 0
        emit("  SP_GC_SAVE();")
        @in_gc_scope = 1
      end
    end
    j = 0
    while j < lnames.length
      emit("  " + c_type(ltypes[j]) + " lv_" + lnames[j] + " = " + c_default_val(ltypes[j]) + ";")
      j = j + 1
    end
    if has_gc_locals == 1
      if @needs_gc == 1
        emit_gc_roots(lnames, ltypes)
      end
    end
  end

  def build_params_str(pnames, ptypes)
    result = ""
    j = 0
    while j < pnames.length
      pt = "int"
      if j < ptypes.length
        pt = ptypes[j]
      end
      result = result + ", " + c_type(pt) + " lv_" + pnames[j]
      j = j + 1
    end
    result
  end

  def build_params_decl(pnames, ptypes)
    if pnames.length == 0
      return "void"
    end
    result = ""
    j = 0
    while j < pnames.length
      if j > 0
        result = result + ", "
      end
      pt = "int"
      if j < ptypes.length
        pt = ptypes[j]
      end
      result = result + c_type(pt) + " lv_" + pnames[j]
      j = j + 1
    end
    result
  end

 # Builds the trailing portion of a call-args list — each non-empty
 # piece prefixed with ", ", empties skipped. Returns "" when all
 # are empty. Mirrors build_params_str: callers concatenate the
 # result onto a self/recv prefix to form the full arg list.
 #
 # `yargs` carries the trailing yield ABI args (`_block, _benv`) when
 # the callee declares `yield` but the call site doesn't pass a
 # literal block. Without it, methods with both `&block` and `yield`
 # in their body get a 3-arg call against a 5-arg signature and clang
 # fails the build. Mirrors the `, NULL, NULL` shape that the
 # top-level no-recv path appends in compile_no_recv_call_expr.
  def build_call_tail(ca, bp, yargs = "")
    result = ""
    if ca != ""
      result = result + ", " + ca
    end
    if bp != ""
      result = result + ", " + bp
    end
    if yargs != ""
      result = result + yargs
    end
    result
  end

 # Returns the trailing yield-ABI args (`, NULL, NULL`) when an
 # instance method declares `yield` in its body but the call site
 # doesn't inline (no literal block — those route through
 # compile_yield_call_stmt and bypass the C call entirely). The
 # callee's C signature is `..., _block, _benv` whenever
 # cls_method_has_yield is set; omitting these triggers
 # "too few arguments to function call" at clang time.
  def cls_call_yargs(ci, midx)
    if ci < 0 || midx < 0
      return ""
    end
    if cls_method_has_yield(ci, midx) == 1
      return ", NULL, NULL"
    end
    ""
  end

 # ---- Emit top-level methods ----
  def emit_toplevel_methods
    i = 0
    while i < @meth_names.length
      emit_toplevel_method(i)
      i = i + 1
    end
  end

 # `END { ... }` -- one zero-arg static C function per registered
 # PostExecutionNode body. main() registers them via atexit() at
 # startup. atexit invokes handlers LIFO, matching CRuby's
 # reverse-of-source-order END execution.
  def emit_post_execution_funcs
    pe = 0
    while pe < @post_execution_blocks.length
      bnid = @post_execution_blocks[pe]
      emit_raw("static void sp_end_block_" + pe.to_s + "(void) {")
      @indent = 1
      @in_main = 1
      push_scope
      if bnid >= 0
        compile_stmt(bnid)
      end
      pop_scope
      @in_main = 0
      emit_raw("}")
      emit_raw("")
      pe = pe + 1
    end
  end

  def emit_toplevel_method(mi)
    mfullname = @meth_names[mi]
    @current_method_name = mfullname
    @current_method_return = @meth_return_types[mi]
    @current_method_has_self = 0
    @indent = 1
    @in_main = 0
    @in_gc_scope = 0

 # Check if this is an open class method
    oc_type = ""
    if mfullname.start_with?("__oc_Integer_")
      oc_type = "int"
    end
    if mfullname.start_with?("__oc_String_")
      oc_type = "string"
    end
    if mfullname.start_with?("__oc_Float_")
      oc_type = "float"
    end

    if @meth_has_yield[mi] == 1
      @in_yield_method = 1
      @current_method_yield_arity = method_yield_arity(mi)
      @current_method_blk_param_types = blk_param_types_for_body(@meth_body_ids[mi])
    else
      @in_yield_method = 0
      @current_method_blk_param_types = ""
    end

    pnames = @meth_param_names[mi].split(",", -1)
    ptypes = @meth_param_types[mi].split(",", -1)
    @current_method_block_param = find_block_param_name(pnames, ptypes)

    yp = ""
    if @meth_has_yield[mi] == 1
      yp = yield_params_suffix(mi)
    end

 # Reset @heap_promoted_names at method boundary. The list
 # tracks fiber-capture heap cells that live in the EMITTING
 # function's local C scope; leaking it across methods makes
 # sibling methods see `(*_hcell_<name>_<n>)` references to
 # cells that exist only in the original method. Issue #564.
    saved_hp_names_len_mb = @heap_promoted_names.length
    saved_hp_cells_len_mb = @heap_promoted_cells.length
    if oc_type != ""
 # Open class method: self is primitive type
      rt = @meth_return_types[mi]
      self_ctype = c_type(oc_type)
      pdecl = ""
      if pnames.length > 0
        pdecl = build_params_decl(pnames, ptypes)
        pdecl = self_ctype + " self, " + pdecl
      else
        pdecl = self_ctype + " self"
      end
      emit_raw(method_linkage_named(@meth_body_ids[mi], @meth_has_yield[mi], mfullname) + c_type(rt) + " sp_" + sanitize_name(mfullname) + "(" + pdecl + ") {")
      push_scope
      declare_var("__self_type", oc_type)
    else
      emit_raw(method_linkage_named(@meth_body_ids[mi], @meth_has_yield[mi], mfullname) + c_type(@meth_return_types[mi]) + " sp_" + sanitize_name(mfullname) + "(" + method_params_decl(mi) + yp + ") {")
      push_scope
    end

    j = 0
    while j < pnames.length
      pt = "int"
      if j < ptypes.length
        pt = ptypes[j]
      end
      declare_var(pnames[j], pt)
      j = j + 1
    end

    bid = @meth_body_ids[mi]
    if bid >= 0
      declare_method_locals(bid, pnames)
      if @in_gc_scope == 0
        if @needs_gc == 1
          emit("  SP_GC_SAVE();")
          @in_gc_scope = 1
        end
      end
      if @in_gc_scope == 1
        j = 0
        while j < pnames.length
          if j < ptypes.length
            emit_gc_root_for_expr("lv_" + pnames[j], ptypes[j])
          end
          j = j + 1
        end
      end
      compile_body_return(bid, @meth_return_types[mi])
    end

    rt = @meth_return_types[mi]
    pop_scope
 # Restore @heap_promoted_names to the pre-method baseline so
 # the next method doesn't see this method's fiber-capture
 # cells. Issue #564.
    while @heap_promoted_names.length > saved_hp_names_len_mb
      @heap_promoted_names.pop
    end
    while @heap_promoted_cells.length > saved_hp_cells_len_mb
      @heap_promoted_cells.pop
    end
    @current_method_name = ""
    @current_method_block_param = ""
    @in_yield_method = 0
    @current_method_yield_arity = 1
    @indent = 0
    emit_raw("  return " + c_return_default(rt) + ";")
    emit_raw("}")
    emit_raw("")
  end

  def declare_method_locals(bid, params)
 # Read precomputed scope decls from analyze (SN/ST IR records).
 # analyze ran scan_locals + the full 3-pass refinement (incl.
 # lambda upgrade) for this body's bid; codegen just declares
 # the resulting (lnames, ltypes) pair.
    sn = @nd_scope_names[bid]
    st = @nd_scope_types[bid]
    lnames = "".split(",", -1)
    ltypes = "".split(",", -1)
    if sn != ""
      lnames = sn.split("|", -1)
      ltypes = st.split("|", -1)
    end
    j = 0
    while j < lnames.length
      declare_var(lnames[j], ltypes[j])
      j = j + 1
    end
 # Emit declarations and GC rooting for pointer locals
    has_gc_locals = 0
    j = 0
    while j < lnames.length
      if type_needs_gc_root(ltypes[j]) == 1
        has_gc_locals = 1
      end
      j = j + 1
    end
    if has_gc_locals == 1
      if @needs_gc == 1 && @in_gc_scope == 0
        emit("  SP_GC_SAVE();")
        @in_gc_scope = 1
      end
    end
 # When the body uses setjmp/longjmp (begin/rescue/retry, the
 # implicit raise-handler around `raise X unless Y`, etc.), locals
 # modified inside the setjmp scope MUST be volatile -- the C
 # standard allows the compiler to keep non-volatile locals in
 # registers across the setjmp/longjmp pair, so longjmp's unwind
 # may not see the updated register values. The retry-counter
 # in begin/rescue/retry loops is the canonical victim:
 # `i += 1; raise; rescue; retry unless i == 7` hung because
 # lv_i was register-cached and the longjmp-restored value never
 # reached 7. Issue #548 (`begin..retry` hang).
 #
 # Mirrors the volatile-prefix logic for top-level locals at
 # line ~10192 -- there `@needs_setjmp` reflects the whole
 # program; here we pre-scan this body for begin/rescue/retry/
 # raise so methods that don't use setjmp pay no perf cost.
    body_setjmp = body_uses_setjmp?(bid)
    j = 0
    while j < lnames.length
 # Only non-pointer locals get the volatile qualifier. Pointer
 # locals are GC-rooted via SP_GC_ROOT which keeps them stable
 # across collection; the volatile-discarded warnings on
 # `sp_str_length(lv_volatile_str)` etc. would escalate to
 # -Werror failures in the test harness if we marked every
 # pointer local volatile too. The retry-counter case (#548)
 # is `mrb_int`, which this arm covers.
      vol = ""
      if body_setjmp == 1 && type_is_pointer(ltypes[j]) == 0
        vol = "volatile "
      end
      emit("  " + vol + c_type(ltypes[j]) + " lv_" + lnames[j] + " = " + c_default_val(ltypes[j]) + ";")
      j = j + 1
    end
    if has_gc_locals == 1
      if @needs_gc == 1
        emit_gc_roots(lnames, ltypes)
      end
    end
  end

 # Pre-scan a method body for shapes that emit setjmp/longjmp:
 # BeginNode + rescue (compile_begin_stmt's main path), RetryNode,
 # bare `raise X unless Y` / `raise X if !Y` modifier patterns.
 # Used to decide whether locals need the `volatile` qualifier
 # to survive longjmp unwinds. Issue #548.
  def body_uses_setjmp?(nid)
    if nid < 0
      return 0
    end
    t = @nd_type[nid]
    if t == "DefNode" || t == "ClassNode" || t == "ModuleNode"
      return 0
    end
    if t == "BeginNode"
      if @nd_rescue_clause[nid] >= 0 || @nd_ensure_clause[nid] >= 0
        return 1
      end
    end
    if t == "RetryNode"
      return 1
    end
    if t == "CallNode" && @nd_name[nid] == "raise"
      return 1
    end
 # push_child_ids already includes @nd_body, @nd_stmts, and
 # every other AST link -- recursing on those separately would
 # 2x-fan-out per level and explode exponentially on deep bodies
 # like spinel_codegen.rb itself.
    cs_setjmp = []
    push_child_ids(nid, cs_setjmp)
    k = 0
    while k < cs_setjmp.length
      if body_uses_setjmp?(cs_setjmp[k]) == 1
        return 1
      end
      k = k + 1
    end
    0
  end

  def emit_gc_roots(lnames, ltypes)
    j = 0
    while j < lnames.length
      emit_gc_root_for_expr("lv_" + lnames[j], ltypes[j])
      j = j + 1
    end
  end

 # Returns 1 if `nid` is an explicit literal value (not a placeholder or
 # inferred fallback). Used by scan_locals to distinguish a genuine int
 # write like `x = 1` from a defaulted "int" from an unresolved read.
  def is_literal_value_expr(nid)
    if nid < 0
      return 0
    end
    t = @nd_type[nid]
    if t == "IntegerNode"
      return 1
    end
    if t == "FloatNode"
      return 1
    end
    if t == "StringNode"
      return 1
    end
    if t == "SymbolNode"
      return 1
    end
    if t == "TrueNode" || t == "FalseNode"
      return 1
    end
    0
  end



  def not_in(name, arr)
    k = 0
    while k < arr.length
      if arr[k] == name
        return 0
      end
      k = k + 1
    end
    1
  end

 # Scan locals introduced by constant-initializer RHS expressions —
 # those run inside main() before the user stmts, so any block
 # params they introduce (`FRAME = [...].map { |n| ... }` and the
 # multi-write form `A, B = [...].map { |n| ... }`) need their
 # `lv_<bp>` decls in main's scope. Covers both `@const_expr_ids`
 # (single-const inits) and `@multi_const_inits` (the multi-write
 # form, where the RHS lives on a MultiWriteNode).
  def emit_toplevel_ivar_decls
    i = 0
    while i < @toplevel_ivar_names.length
      type = @toplevel_ivar_types[i]
      cname = sanitize_ivar(@toplevel_ivar_names[i])
      ct = c_type(type)
      if type == "string"
        emit_raw("static " + ct + " " + cname + " = \"\";")
      elsif type == "float"
        emit_raw("static " + ct + " " + cname + " = 0.0;")
      elsif type_is_pointer(type) == 1
        emit_raw("static " + ct + " " + cname + " = NULL;")
        @needs_gc = 1
      else
        emit_raw("static " + ct + " " + cname + " = 0;")
      end
      i = i + 1
    end
  end

 # ---- Main emission ----
 # Emit the cls_id-aware obj hash/eql dispatch shims that
 # sp_PolyPolyHash uses for OBJ-tag keys. The default runtime
 # behavior is pointer identity; this dispatch overrides it for
 # classes whose `eql?` semantics are content-based:
 #
 # - sp_Method (when the class is in scope): equal iff bound
 # receiver + fn_ptr match — covers `obj.method(:foo)` dedup.
 # - sp_IntArray (SP_BUILTIN_INT_ARRAY = -1): element-wise content
 # compare — covers `entries[[a, b]] ||= ...` array-keyed Hash
 # patterns.
  def emit_method_eql_dispatch
    return unless @needs_poly_poly_hash == 1
    has_method = find_class_idx("Method") >= 0
 # Tier 4: unified cls_id stamped on boxed instances. Compare
 # against that rather than the internal index.
    method_cid = has_method ? cls_id_for_user_internal(find_class_idx("Method")).to_s : ""
    emit_raw("static mrb_int sp_method_obj_hash_dispatch(int cls_id, void *p) {")
    if has_method
      emit_raw("  if (cls_id == " + method_cid + ") {")
      emit_raw("    sp_Method *m = (sp_Method *)p;")
      emit_raw("    return ((mrb_int)(uintptr_t)m->iv_self_obj * 31) ^ (mrb_int)m->iv_fn_ptr;")
      emit_raw("  }")
    end
    emit_raw("  if (cls_id == SP_BUILTIN_INT_ARRAY) {")
    emit_raw("    sp_IntArray *a = (sp_IntArray *)p;")
    emit_raw("    mrb_int h = 5381;")
    emit_raw("    for (mrb_int i = 0; i < a->len; i++) h = ((h << 5) + h) ^ sp_IntArray_get(a, i);")
    emit_raw("    return h;")
    emit_raw("  }")
    emit_raw("  return (mrb_int)((uintptr_t)p);")
    emit_raw("}")
    emit_raw("static mrb_bool sp_method_obj_eql_dispatch(int cls_id, void *a, void *b) {")
    if has_method
      emit_raw("  if (cls_id == " + method_cid + ") {")
      emit_raw("    sp_Method *ma = (sp_Method *)a;")
      emit_raw("    sp_Method *mb = (sp_Method *)b;")
      emit_raw("    return ma->iv_self_obj == mb->iv_self_obj && ma->iv_fn_ptr == mb->iv_fn_ptr;")
      emit_raw("  }")
    end
    emit_raw("  if (cls_id == SP_BUILTIN_INT_ARRAY) {")
    emit_raw("    sp_IntArray *aa = (sp_IntArray *)a;")
    emit_raw("    sp_IntArray *bb = (sp_IntArray *)b;")
    emit_raw("    if (aa->len != bb->len) return FALSE;")
    emit_raw("    for (mrb_int i = 0; i < aa->len; i++) if (sp_IntArray_get(aa, i) != sp_IntArray_get(bb, i)) return FALSE;")
    emit_raw("    return TRUE;")
    emit_raw("  }")
    emit_raw("  return FALSE;")
    emit_raw("}")
  end

 # Walk the AST looking for `ARGV` references (ConstantReadNode
 # named "ARGV"). Flips @needs_argv so emit_main's init gate
 # has the right value before it runs. Single global name, so
 # the scan is a flat tree walk -- linear in AST size.
 # Issue #727: pre-scan for `def method_missing` definitions and
 # warn that they won't fire at runtime. Spinel resolves call
 # targets statically; an unresolved call emits 0 and prints
 # "cannot resolve ..." rather than dispatching through
 # method_missing. The user's hook never runs, but the def itself
 # compiles silently, so without this pre-pass there's no signal
 # that the contract is broken until a confused 0 surfaces.
  def scan_for_method_missing(nid)
    if nid < 0
      return
    end
    if @nd_type[nid] == "DefNode" && @nd_name[nid] == "method_missing"
      $stderr.puts "warning: `def method_missing' is not dispatched in spinel; unresolved calls still emit 0 and print a 'cannot resolve' warning"
      return
    end
    cs = []
    push_child_ids(nid, cs)
    k = 0
    while k < cs.length
      scan_for_method_missing(cs[k])
      k = k + 1
    end
  end

  def scan_for_argv(nid)
    if nid < 0
      return
    end
    if @needs_argv == 1
      return
    end
    if @nd_type[nid] == "ConstantReadNode" && @nd_name[nid] == "ARGV"
      @needs_argv = 1
      return
    end
    cs = []
    push_child_ids(nid, cs)
    k = 0
    while k < cs.length
      scan_for_argv(cs[k])
      k = k + 1
    end
  end

 # Return 1 if the AST rooted at `nid` reads any LocalVariableReadNode
 # whose name appears in `main_lnames` (main()'s declared locals).
 #
 # Used by emit_main to detect single-target top-level constants whose
 # initializer depends on a local that hasn't been assigned yet at the
 # const-init pre-loop. Without this guard, codegen plants
 #   cst_X = lv_y.iv_z;
 # at the top of main, before `lv_y = sp_Y_new()` runs — so the chain
 # reads from a zero-init struct (silently returns 0, or SIGSEGVs when
 # the call reaches FFI). matz/spinel#647; sibling of #630 (multi-write
 # fix in 9ac50a6).
  def expr_reads_main_local(nid, main_lnames)
    if nid < 0
      return 0
    end
    if @nd_type[nid] == "LocalVariableReadNode"
      nm = @nd_name[nid]
      li = 0
      while li < main_lnames.length
        if main_lnames[li] == nm
          return 1
        end
        li = li + 1
      end
      return 0
    end
    cs = []
    push_child_ids(nid, cs)
    k = 0
    while k < cs.length
      if expr_reads_main_local(cs[k], main_lnames) == 1
        return 1
      end
      k = k + 1
    end
    0
  end

 # Walk the AST looking for class-hierarchy usage patterns
 # (`<klass>.superclass`, `.ancestors`, `<`, `<=`, dynamic
 # is_a? / kind_of? / instance_of?, case-when on a Class const).
 # Flips @needs_class_parents / @needs_class_ancestors /
 # @needs_class_for_poly so emit_class_runtime can gate the
 # corresponding tables + helpers. The compile-side arms set
 # the same flags but run after emit_class_runtime, so this
 # scan is what makes the gate effective. Programs that never
 # reach for hierarchy queries trim ~15 lines of tables +
 # helpers from their .c (parents/ancestors arrays + le/lt/
 # ancestors_arr/for_poly bodies).
  def scan_for_class_hierarchy_usage(nid)
    if nid < 0
      return
    end
    t_ch = @nd_type[nid]
 # Any RescueNode means we'll need the exception-class hierarchy
 # walker -- the rescue dispatch uses it for `rescue ParentClass`,
 # and any `e.is_a?(X)` inside the body also needs it. Conservative
 # (bare `rescue` doesn't strictly need the helper, but the cost
 # is a couple-hundred bytes of dead code on programs without
 # is_a? on the bound var). Issue #627.
    if t_ch == "RescueNode"
      @needs_exc_class_hierarchy = 1
    end
    if @needs_class_parents == 1 && @needs_class_ancestors == 1 && @needs_class_for_poly == 1 && @needs_exc_class_hierarchy == 1
      return
    end
    if t_ch == "ConstantReadNode"
      cname_ch = @nd_name[nid]
 # ConstantReadNode resolving to a class / module / built-in
 # class name lowers to a sp_Class value (`((sp_Class){<id>})`),
 # which needs sp_class_names + sp_class_to_s for .to_s and
 # the rest of the basic helpers.
      if find_class_idx(cname_ch) >= 0 || find_module_idx_local(cname_ch) >= 0 || builtin_class_id_for_name(cname_ch) >= 0
        @needs_class_table = 1
      end
    end
    if t_ch == "CallNode"
      mname_ch = @nd_name[nid]
      if mname_ch == "superclass"
        @needs_class_parents = 1
      end
      if mname_ch == "ancestors"
        @needs_class_ancestors = 1
      end
      if mname_ch == "class"
 # `.class` lowers to a sp_Class literal -- the names
 # table plus sp_class_to_s back the .to_s / .name / .inspect
 # chain that typically follows.
        @needs_class_table = 1
      end
      if mname_ch == "sort" || mname_ch == "sort!"
 # `.sort` / `.sort!` on a sym_array compiles via
 # sp_sym_array_sort + sp_sym_sort_cmp. Pre-scan flips
 # @needs_sym_sort conservatively on any .sort / .sort!
 # call -- false positives (sort on int / str / float
 # arrays) cost a 4-line dead helper that -O2 DCE
 # removes; missing the trigger breaks the link.
        @needs_sym_sort = 1
      end
      if mname_ch == "to_s" || mname_ch == "name" || mname_ch == "inspect"
 # Static recv check is too brittle pre-inference; flag
 # @needs_class_table conservatively when these mnames
 # appear with a recv that could be a Class value
 # (ConstantReadNode or a chained .class call).
        recv_to_s = @nd_receiver[nid]
        if recv_to_s >= 0
          rty_to_s = @nd_type[recv_to_s]
          if rty_to_s == "ConstantReadNode" || rty_to_s == "ConstantPathNode"
            @needs_class_table = 1
          elsif rty_to_s == "CallNode" && @nd_name[recv_to_s] == "class"
            @needs_class_table = 1
          end
        end
      end
      if mname_ch == "==" || mname_ch == "!=" || mname_ch == "eql?"
 # sp_class_eq fires when an operand is a Class value;
 # pre-scan flags conservatively on ConstantReadNode
 # operands.
        recv_eq = @nd_receiver[nid]
        if recv_eq >= 0 && (@nd_type[recv_eq] == "ConstantReadNode" || @nd_type[recv_eq] == "ConstantPathNode")
          @needs_class_table = 1
        end
        args_id_eq = @nd_arguments[nid]
        if args_id_eq >= 0
          aa_eq = get_args(args_id_eq)
          if aa_eq.length > 0 && (@nd_type[aa_eq[0]] == "ConstantReadNode" || @nd_type[aa_eq[0]] == "ConstantPathNode")
            @needs_class_table = 1
          end
        end
      end
      if mname_ch == "is_a?" || mname_ch == "kind_of?" || mname_ch == "instance_of?"
        args_id_ch = @nd_arguments[nid]
        if args_id_ch >= 0
          aa_ch = get_args(args_id_ch)
          if aa_ch.length > 0
            arg_t_ch = @nd_type[aa_ch[0]]
 # Dynamic klass (non-Const recv) routes through
 # sp_class_for_poly + sp_class_le at runtime.
            if arg_t_ch != "ConstantReadNode" && arg_t_ch != "ConstantPathNode"
              @needs_class_for_poly = 1
              @needs_class_ancestors = 1
            end
          end
        end
      end
      if mname_ch == "<" || mname_ch == "<=" || mname_ch == ">" || mname_ch == ">="
 # Heuristic: ConstantReadNode / ConstantPathNode operand
 # suggests class compare; numeric `<` etc. on locals
 # doesn't trigger the hierarchy emit.
        recv_ch = @nd_receiver[nid]
        if recv_ch >= 0 && (@nd_type[recv_ch] == "ConstantReadNode" || @nd_type[recv_ch] == "ConstantPathNode")
          @needs_class_ancestors = 1
        end
        args_id_ch2 = @nd_arguments[nid]
        if args_id_ch2 >= 0
          aa_ch2 = get_args(args_id_ch2)
          if aa_ch2.length > 0 && (@nd_type[aa_ch2[0]] == "ConstantReadNode" || @nd_type[aa_ch2[0]] == "ConstantPathNode")
            @needs_class_ancestors = 1
          end
        end
      end
    end
    if t_ch == "CaseNode"
 # case-when with a ConstantReadNode in a WhenNode arm could
 # be `case obj when SomeClass` on a poly subject -- the
 # codegen path routes through sp_class_le(sp_class_for_poly).
      conds_ch = parse_id_list(@nd_conditions[nid])
      kch = 0
      while kch < conds_ch.length
        wid_ch = conds_ch[kch]
        if @nd_type[wid_ch] == "WhenNode"
          wconds_ch = parse_id_list(@nd_conditions[wid_ch])
          wkch = 0
          while wkch < wconds_ch.length
            wt_ch = @nd_type[wconds_ch[wkch]]
            if wt_ch == "ConstantReadNode" || wt_ch == "ConstantPathNode"
              @needs_class_for_poly = 1
              @needs_class_ancestors = 1
            end
            wkch = wkch + 1
          end
        end
        kch = kch + 1
      end
    end
    cs_ch = []
    push_child_ids(nid, cs_ch)
    k_ch = 0
    while k_ch < cs_ch.length
      scan_for_class_hierarchy_usage(cs_ch[k_ch])
      k_ch = k_ch + 1
    end
  end

 # Walk the AST looking for usage sites that would emit
 # sp_Method-typed code. Flips @needs_method before
 # emit_class_structs / emit_class_methods run, so the Method
 # struct + helpers stay out of programs that never use it.
 # Pre-scan covers the patterns the codegen actually emits:
 # - `method(:sym)` (bare bind)
 # - `<recv>.method(:sym)` (bound bind)
 # - `Method.new(...)` (explicit construction)
 # - poly_poly_hash usage (sp_method_obj_hash_dispatch
 # / _eql_dispatch call into
 # sp_Method)
 # The codegen-side arms also flip the flag, but most of them
 # run after emit_class_methods -- the pre-scan is what makes
 # the gate effective.
  def scan_for_method_usage(nid)
    if nid < 0
      return
    end
    if @needs_method == 1
      return
    end
    if @nd_type[nid] == "CallNode"
      mname_sm = @nd_name[nid]
      if mname_sm == "method"
        @needs_method = 1
        return
      end
      recv_sm = @nd_receiver[nid]
      if recv_sm >= 0 && @nd_type[recv_sm] == "ConstantReadNode" && @nd_name[recv_sm] == "Method"
        @needs_method = 1
        return
      end
    end
    if @nd_type[nid] == "ConstantReadNode" && @nd_name[nid] == "Method"
      @needs_method = 1
      return
    end
 # Hash literals are a conservative trigger: emit_method_eql_dispatch
 # gets armed when any access infers as poly_poly_hash, and the
 # dispatch shim references sp_Method to recover bound-receiver /
 # fn_ptr identity for Method-typed keys. The HashNode literal may
 # eventually narrow to a monomorphic variant (str_int_hash, etc.)
 # and not actually trigger poly_poly_hash, but pre-scan can't see
 # that decision -- it runs before inference settles. Over-emitting
 # Method here costs ~25 lines of dead C that -O3 DCE's away; the
 # alternative (missing the trigger) breaks the link.
    if @nd_type[nid] == "HashNode"
      @needs_method = 1
      return
    end
    cs = []
    push_child_ids(nid, cs)
    k = 0
    while k < cs.length
      scan_for_method_usage(cs[k])
      k = k + 1
    end
  end

 # Pre-scan for container method calls whose full poly-recv
 # arm set references typedefs that wouldn't otherwise be
 # emitted. Currently arms:
 #   - dig (#555 case 07) -- emit_dig_step's Sym-keyed hash
 #     arms reference SymIntHash / SymStrHash / SymPolyHash
 #     typedefs.
 #   - include? (#558) -- emit_poly_builtin_dispatch's arg-
 #     keyed include? arms reference the same Sym-keyed and
 #     Str-poly-keyed typedefs.
 # Both pass-side `@needs_` flips run after the typedef-emit
 # pass; this pre-scan sets them ahead of time.
  def scan_for_container_typedef_usage(nid)
    if nid < 0
      return
    end
    if @nd_type[nid] == "CallNode" && @nd_name[nid] == "dig"
      args_id_sd = @nd_arguments[nid]
      if args_id_sd >= 0
        aa_sd = get_args(args_id_sd)
        if aa_sd.length >= 2
 # emit_dig_step branches on the key type and emits arms for
 # all hash variants matching that key family. Conservatively
 # arm all variants so the runtime typedefs are present.
          ki_sd = 1
          while ki_sd < aa_sd.length
            kt_sd = infer_type(aa_sd[ki_sd])
            if kt_sd == "symbol"
              @needs_sym_int_hash = 1
              @needs_sym_str_hash = 1
              @needs_sym_poly_hash = 1
            elsif kt_sd == "string"
              @needs_str_poly_hash = 1
            end
            ki_sd = ki_sd + 1
          end
        end
      end
    end
 # `recv.each { ... }` may lower to compile_each_block's
 # rt == "poly" arm, which dispatches on cls_id across every
 # built-in container variant -- including all 8 Hash variants
 # (key-value pair iteration packs into a per-iteration PolyArray).
 # Arm every hash typedef so the dispatch arm's `sp_StrIntHash *`
 # etc. casts have a definition. Issue #603 -- pre-fix, the
 # dispatch was emitted referencing `sp_SymStrHash` etc. but the
 # typedef pass had already run with the flag still 0.
 #
 # The poly-vs-narrow distinction depends on the analyzer's
 # final fixpointed param types, which `scan_for_container_typedef_usage`
 # doesn't have scope-context to resolve here. Take the
 # conservative route: any `each` call with a block flags all
 # 8 hash typedefs. The bloat is bounded (only the typedef +
 # the unconditional helpers, ~1KB of generated C) and only
 # programs that contain `.each` calls are affected.
    if @nd_type[nid] == "CallNode" && @nd_name[nid] == "each" && @nd_receiver[nid] >= 0 && @nd_block[nid] >= 0
      @needs_str_int_hash = 1
      @needs_str_str_hash = 1
      @needs_int_str_hash = 1
      @needs_sym_int_hash = 1
      @needs_sym_str_hash = 1
      @needs_str_poly_hash = 1
      @needs_sym_poly_hash = 1
      @needs_poly_poly_hash = 1
      @needs_rb_value = 1
      @needs_poly_array = 1
      @needs_gc = 1
    end
 # `recv.include?(arg)` on a poly-typed recv similarly emits
 # arms across all matching Array / Hash variants in
 # emit_poly_builtin_dispatch. Arm the sym-keyed hash typedefs
 # when the arg is a symbol so the dispatch compiles even when
 # the program never instantiated SymStrHash directly.
 # Issue #558.
    if @nd_type[nid] == "CallNode" && @nd_name[nid] == "include?"
      args_id_si = @nd_arguments[nid]
      if args_id_si >= 0
        aa_si = get_args(args_id_si)
        if aa_si.length >= 1
          at_si = infer_type(aa_si[0])
          if at_si == "symbol"
            @needs_sym_int_hash = 1
            @needs_sym_str_hash = 1
            @needs_sym_poly_hash = 1
          elsif at_si == "string" || at_si == "mutable_str"
            @needs_str_poly_hash = 1
          end
        end
      end
    end
    cs_sd = []
    push_child_ids(nid, cs_sd)
    k_sd = 0
    while k_sd < cs_sd.length
      scan_for_container_typedef_usage(cs_sd[k_sd])
      k_sd = k_sd + 1
    end
  end

  def emit_main
    stmts = get_body_stmts(@root_id)
 # Pre-scan the entire AST for ARGV ConstantReadNode references
 # so @needs_argv lands before emit_main writes the init line.
 # The compile-side arms (compile_expr's ARGV branch, the
 # ARGV.length / [] dispatch) flip the flag too, but they run
 # after the init line has already been emitted -- this scan
 # is what makes the gate actually effective.
    scan_for_argv(@root_id)
    emit_raw("int main(int argc,char**argv){")
 # Gate the ARGV ingest: sp_argv is BSS-zero-initialized
 # (len=0, data=NULL), and sp_mark_externals' loop reads
 # `sp_argv.len` first so an unused-ARGV program never
 # touches the NULL data pointer. Programs that don't
 # reference ARGV save the per-startup malloc + strdup loop.
    if @needs_argv == 1
      emit_raw("  sp_argv.len=argc-1;sp_argv.data=(const char**)malloc(sizeof(const char*)*(argc>1?argc-1:1));{int _i;for(_i=0;_i<sp_argv.len;_i++)sp_argv.data[_i]=sp_str_dup_external(argv[_i+1]);}")
    end
 # Populate $PROGRAM_NAME / $0 from argv[0] at startup. Ruby's
 # canonical autorun guard (`if __FILE__ == $PROGRAM_NAME`) reads
 # the script's argv-passed path; without this init it stays the
 # empty default and the guard never fires.
    gi_pn = 0
    while gi_pn < @gvar_names.length
      pn_name = @gvar_names[gi_pn]
      if (pn_name == "$PROGRAM_NAME" || pn_name == "$0") && @gvar_types[gi_pn] == "string"
        emit_raw("  " + sanitize_gvar(pn_name) + " = (argc > 0) ? argv[0] : \"\";")
      end
      gi_pn = gi_pn + 1
    end
    if @needs_rand == 1
      emit_raw("  srand((unsigned)time(NULL));")
    end
 # Issue #781 / #846: sp_re_init swaps in a quiet startup handler
 # for the pre-compile pass and restores sp_re_default_error_handler
 # before returning. No separate install step needed here.
    if @needs_regexp == 1
      emit_raw("  sp_re_init();")
    end
 # poly_poly_hash uses sp_obj_hash_hook / sp_obj_eql_hook for cls_id-
 # aware OBJ-tag dispatch. The hooks default to identity; install
 # the codegen-emitted dispatch shim so equivalent
 # `obj.method(:foo)` instances (fresh allocations, but same iv_self_obj
 # + iv_fn_ptr) dedup as eql? in @cache[m] ||= m style use, and
 # IntArray keys (e.g. `entries[[a, b]] ||= ...`) compare by
 # element-wise content rather than pointer identity.
    if @needs_poly_poly_hash == 1
      emit_raw("  sp_obj_hash_hook = sp_method_obj_hash_dispatch;")
      emit_raw("  sp_obj_eql_hook = sp_method_obj_eql_dispatch;")
    end

    @in_main = 1
    @indent = 1
    push_scope
 # Pointer-typed toplevel ivars get rooted before SAVE so they live
 # for the program's lifetime.
    ti = 0
    while ti < @toplevel_ivar_names.length
      tivar = sanitize_ivar(@toplevel_ivar_names[ti])
      ttype = @toplevel_ivar_types[ti]
      emit_global_gc_roots_for_expr(tivar, ttype)
      ti = ti + 1
    end
    if @needs_gc == 1
      emit("  SP_GC_SAVE();")
    end

 # Read precomputed main-scope decls from analyze (SN/ST records
 # at @root_id). analyze ran the full 4-pass scope refinement
 # (incl. lambda upgrade and bigint promotion) so codegen just
 # declares the resulting (lnames, ltypes) pair.
    sn = @nd_scope_names[@root_id]
    st = @nd_scope_types[@root_id]
    lnames = "".split(",", -1)
    ltypes = "".split(",", -1)
    if sn != ""
      lnames = sn.split("|", -1)
      ltypes = st.split("|", -1)
    end
    j = 0
    while j < lnames.length
      declare_var(lnames[j], ltypes[j])
      j = j + 1
    end

    j = 0
    while j < lnames.length
      ctp = c_type(ltypes[j])
 # Pointer locals: GC-rooted via SP_GC_ROOT, which keeps them
 # stable across collection and (incidentally) across longjmp.
 # Volatile is only required for non-pointer scalars modified
 # inside a setjmp scope. Tagging pointer locals volatile too
 # would trigger -Wdiscarded-qualifiers cascade through the
 # runtime helper signatures (sp_str_length, sp_IntArray_length,
 # etc.) without affecting correctness. Mirrors the per-method
 # logic in declare_method_locals (#548).
      if type_needs_gc_root(ltypes[j]) == 1
        emit("  " + ctp + " lv_" + lnames[j] + " = " + c_default_val(ltypes[j]) + ";")
        emit_gc_root_for_expr("lv_" + lnames[j], ltypes[j])
      else
        vol = ""
        if @needs_setjmp == 1
          vol = "volatile "
        end
        emit("  " + vol + ctp + " lv_" + lnames[j] + " = " + c_default_val(ltypes[j]) + ";")
      end
      j = j + 1
    end

 # Compute deferred const inits: a top-level `CONST = recv.method`
 # whose RHS reads from a main local must wait for the body to run,
 # otherwise the pre-emit below plants `cst_X = lv_y.iv_z;` before
 # `lv_y = sp_Y_new()` and reads from a zero-init struct
 # (matz/spinel#647). The single-target sibling of #630 (9ac50a6
 # multi-write fix): there the push was skipped entirely; here the
 # const must still be declared but the init emit moves to source
 # order, handled in the body-stmt loop below.
    defer_const_init = "".split(",", -1)
    dci = 0
    while dci < @const_names.length
      defer_const_init.push("0")
      dci = dci + 1
    end
    dci = 0
    while dci < @const_names.length
      scope_dci = ""
      if dci < @const_scope_names.length
        scope_dci = @const_scope_names[dci]
      end
      if scope_dci == "" && dci < @const_expr_ids.length
        eid_dci = @const_expr_ids[dci]
        if eid_dci >= 0 && expr_reads_main_local(eid_dci, lnames) == 1
          defer_const_init[dci] = "1"
        end
      end
      dci = dci + 1
    end

 # Constants (initialize global declarations)
    i = 0
    while i < @const_names.length
 # expr_id == -1 means this constant came from a `A, B, C = expr`
 # multi-write: its value is computed by the deferred init block
 # below, not from a single per-target expression.
      if i < @const_expr_ids.length && @const_expr_ids[i] >= 0 && defer_const_init[i] != "1"
        old_scope = @current_lexical_scope
        if i < @const_scope_names.length
          @current_lexical_scope = @const_scope_names[i]
        else
          @current_lexical_scope = ""
        end
 # When refine_module_ivar_types widened the const type
 # from the empty-hash default `str_int_hash` to a more
 # specific shape (sym_str_hash etc.), emit the matching
 # `sp_<Hash>_new()` directly instead of falling through to
 # compile_expr's default `sp_StrIntHash_new()`. Same for
 # empty-array refinement.
        val = ""
        ct_init = @const_types[i]
        eid_init = @const_expr_ids[i]
        if is_empty_hash_literal(eid_init) == 1
          if ct_init == "sym_int_hash"
            val = "sp_SymIntHash_new()"
            @needs_sym_int_hash = 1
          elsif ct_init == "sym_str_hash"
            val = "sp_SymStrHash_new()"
            @needs_sym_str_hash = 1
          elsif ct_init == "str_str_hash"
            val = "sp_StrStrHash_new()"
            @needs_str_str_hash = 1
          elsif ct_init == "int_str_hash"
            val = "sp_IntStrHash_new()"
            @needs_int_str_hash = 1
          elsif ct_init == "sym_poly_hash"
            val = "sp_SymPolyHash_new()"
            @needs_sym_poly_hash = 1
          elsif ct_init == "str_poly_hash"
            val = "sp_StrPolyHash_new()"
            @needs_str_poly_hash = 1
          elsif ct_init == "poly_poly_hash"
            val = "sp_PolyPolyHash_new()"
            @needs_poly_poly_hash = 1
            @needs_rb_value = 1
          end
        elsif is_empty_array_literal(eid_init) == 1
          if ct_init == "float_array"
            val = "sp_FloatArray_new()"
            @needs_float_array = 1
          elsif ct_init == "str_array"
            val = "sp_StrArray_new()"
            @needs_str_array = 1
          elsif ct_init == "sym_array"
            val = "sp_IntArray_new()"
          elsif ct_init == "poly_array"
            val = "sp_PolyArray_new()"
            @needs_rb_value = 1
          end
        end
 # Issue #646: when the init RHS is `<Class>.new(...)`, set the
 # per-const in-progress flag for the duration of the call so any
 # read of this const inside the call chain raises NameError
 # instead of derefing the NULL slot. SET before compile_expr
 # (so any setup temps it emits also fall under the flag — the
 # actual sp_<Class>_new() runs when the cst_X assignment fires);
 # CLEAR after the assignment.
        guarded_646 = (i < @const_init_class.length && @const_init_class[i] != "")
        if guarded_646
          emit("  sp_init_in_progress_" + @const_names[i] + " = 1;")
        end
        if val == ""
          val = compile_expr(eid_init)
        end
        @current_lexical_scope = old_scope
        emit("  cst_" + @const_names[i] + " = " + val + ";")
        if guarded_646
          emit("  sp_init_in_progress_" + @const_names[i] + " = 0;")
        end
        emit_gc_root_for_expr("cst_" + @const_names[i], @const_types[i])
      end
      i = i + 1
    end

 # Multi-write constant initializers: `A, B, C = rhs` evaluates
 # rhs once and assigns each element. ArrayNode literals split
 # element-wise; otherwise we evaluate to a temp and index it
 # (currently only int_array supported, which covers the
 # optcarrot CLK_1..CLK_8 = (1..8).map {...} pattern).
    if @multi_const_inits != nil
      mci = 0
      while mci < @multi_const_inits.length
        parts = @multi_const_inits[mci].split("|", -1)
        scope_n = parts[0]
        mw_id = parts[1].to_i
        targets = parse_id_list(@nd_targets[mw_id])
        val_id = @nd_expression[mw_id]
        old_scope = @current_lexical_scope
        @current_lexical_scope = scope_n
        if val_id >= 0 && @nd_type[val_id] == "ArrayNode"
          elems = parse_id_list(@nd_elements[val_id])
          ti2 = 0
          while ti2 < targets.length
            tid = targets[ti2]
            if @nd_type[tid] == "ConstantTargetNode" && ti2 < elems.length
              cn = @nd_name[tid]
              if scope_n != ""
                cn = scope_n + "_" + cn
              end
              ev = compile_expr(elems[ti2])
              emit("  cst_" + cn + " = " + ev + ";")
            end
            ti2 = ti2 + 1
          end
        else
          rhs_t = infer_type(val_id)
          if rhs_t == "int_array"
            tmp_n = new_temp
            emit("  sp_IntArray *" + tmp_n + " = " + compile_expr(val_id) + ";")
            ti3 = 0
            while ti3 < targets.length
              tid = targets[ti3]
              if @nd_type[tid] == "ConstantTargetNode"
                cn = @nd_name[tid]
                if scope_n != ""
                  cn = scope_n + "_" + cn
                end
                emit("  cst_" + cn + " = sp_IntArray_get(" + tmp_n + ", " + ti3.to_s + ");")
              end
              ti3 = ti3 + 1
            end
          end
 # ptr_array RHS (e.g., `A, B = [1,6].map { (0..n).map { ... } }`
 # whose outer map returns int_array_ptr_array). Each target
 # is a class-typed (here IntArray*) element of the PtrArray.
          if is_ptr_array_type(rhs_t) == 1
            elem_pt = ptr_array_elem_type(rhs_t)
            tmp_n = new_temp
            emit("  sp_PtrArray *" + tmp_n + " = " + compile_expr(val_id) + ";")
            ti3 = 0
            while ti3 < targets.length
              tid = targets[ti3]
              if @nd_type[tid] == "ConstantTargetNode"
                cn = @nd_name[tid]
                if scope_n != ""
                  cn = scope_n + "_" + cn
                end
                emit("  cst_" + cn + " = (" + c_type(elem_pt) + ")sp_PtrArray_get(" + tmp_n + ", " + ti3.to_s + ");")
              end
              ti3 = ti3 + 1
            end
          end
        end
        @current_lexical_scope = old_scope
        mci = mci + 1
      end
    end

    emit_raw("")

 # Pre-scan: map lambda variable names to their return types
    scan_lambda_ret_types(stmts)

 # `BEGIN { ... }` hoist: each PreExecutionNode body runs at the
 # very top of main, in source-encounter order, BEFORE any other
 # top-level statements. Bodies were collected by collect_all.
    pi = 0
    while pi < @pre_execution_blocks.length
      bnid = @pre_execution_blocks[pi]
      if bnid >= 0
        compile_stmt(bnid)
      end
      pi = pi + 1
    end

 # `END { ... }` register-atexit: each PostExecutionNode body
 # was emitted as a static `sp_end_block_<n>` function during
 # emit_post_execution_funcs. We register them in source order;
 # atexit invokes handlers LIFO, matching CRuby's reverse-order
 # END semantics.
    pe = 0
    while pe < @post_execution_blocks.length
      emit("  atexit(sp_end_block_" + pe.to_s + ");")
      pe = pe + 1
    end

 # Compile main statements. ConstantWriteNode is normally skipped
 # because the const-init pre-loop above already emitted it. The
 # exception is constants flagged in defer_const_init[]: those have
 # an RHS that reads from a main local, so the pre-loop deliberately
 # left them out and we emit them here in source order.
    stmts.each { |sid|
      if @nd_type[sid] != "DefNode"
        if @nd_type[sid] != "ClassNode"
          if @nd_type[sid] != "ConstantWriteNode"
            compile_stmt(sid)
          else
            cwn_name = @nd_name[sid]
            cwn_idx = -1
            ck = 0
            while ck < @const_names.length
              if @const_names[ck] == cwn_name
                scope_ck = ""
                if ck < @const_scope_names.length
                  scope_ck = @const_scope_names[ck]
                end
                if scope_ck == ""
                  cwn_idx = ck
                  break
                end
              end
              ck = ck + 1
            end
            if cwn_idx >= 0 && cwn_idx < defer_const_init.length && defer_const_init[cwn_idx] == "1"
              eid_b = @const_expr_ids[cwn_idx]
              if eid_b >= 0
                old_scope_b = @current_lexical_scope
                @current_lexical_scope = ""
                val_b = compile_expr(eid_b)
                @current_lexical_scope = old_scope_b
 # promote-mode: rhs may be bigint but const slot is int.
 # Unbox via sp_bigint_to_int so the static int slot stays
 # consistent.
                ct_def = @const_types[cwn_idx]
                if ct_def == "int" && (infer_type(eid_b) == "bigint" || expr_emit_is_bigint(eid_b) == 1)
                  @needs_bigint = 1
                  val_b = "sp_bigint_to_int((sp_Bigint *)" + val_b + ")"
                end
                emit("  cst_" + cwn_name + " = " + val_b + ";")
                emit_gc_root_for_expr("cst_" + cwn_name, @const_types[cwn_idx])
              end
            end
          end
        end
      end
    }

    emit_raw("  return 0;")
    emit_raw("}")

    pop_scope
    @in_main = 0

 # Accumulate lambda and fiber functions into deferred buffer
    if @lambda_funcs != ""
      @deferred_lambda << @lambda_funcs
    end
    if @fiber_funcs != ""
      @deferred_lambda << @fiber_funcs
    end
    0
  end

  def unwrap_single_parentheses_node(nid)
    if nid >= 0 && @nd_type[nid] == "ParenthesesNode"
      body = @nd_body[nid]
      if body >= 0
        stmts = get_stmts(body)
        if stmts.length == 1
          return stmts[0]
        end
      end
    end
    nid
  end

  def regex_match_call_node?(nid)
    call_nid = unwrap_single_parentheses_node(nid)
    call_nid >= 0 && @nd_type[call_nid] == "CallNode" && @nd_name[call_nid] == "=~"
  end

 # Compile a node for use as a C scalar condition. Value-type objects
 # are passed by value (a struct), and C rejects them as scalars in
 # `if (...)` etc. In Ruby every non-nil/non-false object is truthy,
 # so wrap the expression in a comma operator that evaluates it for
 # side effects then yields 1.
  def compile_cond_expr(nid)
    expr = compile_expr(nid)
    t = infer_type(nid)
    if t == "poly"
      return "sp_poly_truthy(" + expr + ")"
    end
    if t == "bool"
      return expr
    end
 # Legacy =~ truthy specialization -- no longer needed in steady
 # state since the operator returns poly (sp_RbVal nil/Integer)
 # and the t == "poly" arm above absorbs it. Kept as a safety net
 # for any pre-poly call site that still surfaces an int-typed =~.
    if regex_match_call_node?(nid)
      return "(" + expr + " >= 0)"
    end
 # `()` (empty parens) infers as "void" and lowers compile_expr
 # to "0". CRuby treats `()` as nil -- `while ()` never enters
 # the loop body. Without this arm, the catch-all `((expr),
 # TRUE)` flipped the empty-parens condition to always-true and
 # the loop hung. Issue #548.
    if t == "void" || t == "nil"
      return "FALSE"
    end
 # `int?` uses the SP_INT_NIL sentinel, not NULL — comparing the
 # mrb_int slot to NULL warns -Wint-conversion and is semantically
 # wrong (SP_INT_NIL is INT64_MIN, not 0). Route through the
 # scalar-nullable arm.
    if is_scalar_nullable_type(t) == 1
      return "(!sp_int_is_nil(" + expr + "))"
    end
    if is_nullable_type(t) == 1
      return "(" + expr + " != NULL)"
    end
    if nid >= 0 && is_value_type_obj(t) == 1
      return "((" + expr + "), 1)"
    end
    truthy_c_expr(t, expr)
  end

  def truthy_node_expr(nid, t, expr)
 # Same poly-first ordering as compile_cond_expr: with =~ now
 # typed poly, the type-based dispatch (sp_poly_truthy via
 # truthy_c_expr) handles nil correctly. The legacy `>= 0` arm
 # only fires if t isn't poly -- a pre-poly call site that
 # somehow surfaces an int-typed =~.
    if t == "poly"
      return truthy_c_expr(t, expr)
    end
    if regex_match_call_node?(nid)
      return "(" + expr + " >= 0)"
    end
    truthy_c_expr(t, expr)
  end

  def truthy_c_expr(t, expr)
    if t == "poly"
      return "sp_poly_truthy(" + expr + ")"
    end
    if t == "bool"
      return expr
    end
    if t == "nil"
      return "FALSE"
    end
 # See compile_cond_expr -- `int?` uses SP_INT_NIL, not NULL.
    if is_scalar_nullable_type(t) == 1
      return "(!sp_int_is_nil(" + expr + "))"
    end
    if is_nullable_type(t) == 1 || type_is_pointer(t) == 1
      return "(" + expr + " != NULL)"
    end
    "((" + expr + "), TRUE)"
  end

 # Issue #660 helper. If left_nid is `hash[k]` on a typed-hash recv
 # with a non-poly value type, return "<Class>|<value_type>" so
 # compile_or can rewrite to `has_key ? get : rhs`. Returns ""
 # for shapes that should keep the legacy truthy lowering (poly
 # hash variants already return sp_box_nil on miss; non-hash
 # receivers have their own truthy semantics).
  def lhs_typed_hash_get_for_or(left_nid)
    if left_nid < 0 || @nd_type[left_nid] != "CallNode"
      return ""
    end
    if @nd_name[left_nid] != "[]"
      return ""
    end
    recv_nid_oh = @nd_receiver[left_nid]
    args_id_oh = @nd_arguments[left_nid]
    if recv_nid_oh < 0 || args_id_oh < 0
      return ""
    end
    aargs_oh = get_args(args_id_oh)
    if aargs_oh.length != 1
      return ""
    end
    rt_oh = base_type(infer_type(recv_nid_oh))
    if rt_oh == "str_int_hash"
      return "StrIntHash|int|str"
    elsif rt_oh == "str_str_hash"
      return "StrStrHash|string|str"
    elsif rt_oh == "sym_int_hash"
      return "SymIntHash|int|sym"
    elsif rt_oh == "sym_str_hash"
      return "SymStrHash|string|sym"
    elsif rt_oh == "int_str_hash"
      return "IntStrHash|string|int"
    end
    ""
  end

  def or_result_type(nid)
    lt = infer_type(@nd_left[nid])
    rt = infer_type(@nd_right[nid])
    if lt == rt
      return lt
    end
    if lt == "nil"
      return rt
    end
    if rt == "nil"
      if is_nullable_pointer_type(lt) == 1 && is_nullable_type(lt) == 0
        return lt + "?"
      end
      return lt
    end
    "poly"
  end

 # ---- Expression compiler ----
  def compile_expr(nid)
    if nid < 0
      return "0"
    end
    t = @nd_type[nid]
    if t == "YieldNode" && @inline_yield_blk >= 0
 # Yield used as a sub-expression inside an inlined yield-using
 # method body (`arr.push(yield)`, `yield * 2`, etc.). Materialize
 # the block body's last value into a temp and return that temp.
 # The @inline_yield_blk guard restricts this expansion to the
 # inlining window; outside of it, YieldNode in expression context
 # is meaningless and falls through to the default int-0.
      empty_map = "".split(",", -1)
      return compile_yield_inline_expr(nid, @inline_yield_blk, @inline_yield_bp_names, empty_map, empty_map)
    end
    if t == "UnsupportedNode"
 # The parser emitted this sentinel because it hit a Prism node
 # type it doesn't know how to serialize. ImaginaryNode and
 # RationalNode are now supported as proper nodes (#840 #841),
 # so anything that hits this arm is a genuine unsupported Ruby
 # construct; hard-error so the user gets a precise location.
      kind_us = @nd_content[nid]
      $stderr.puts "Spinel: cannot compile " + kind_us + " at line " + @nd_value[nid].to_s + " (unsupported Ruby syntax)"
      exit(1)
    end
    if t == "IntegerNode"
 # Suffix with `LL` so the literal is `long long` rather than
 # `int` in the emitted C. Without it, an expression of int
 # literals whose product exceeds int32 (e.g. APU mixer
 # constant `24329 * 256 * 500 = 3,114,112,000`) overflows
 # at constant-folding time and the C compiler emits a wrong
 # value. Plain literals at runtime sites get implicitly
 # promoted to mrb_int (= long long) on assignment, but
 # constant-init expressions are evaluated by the C compiler
 # using the literals' declared type.
      return @nd_value[nid].to_s + "LL"
    end
    if t == "FloatNode"
      return @nd_content[nid]
    end
 # Issue #840: ImaginaryNode `Ni` -- sp_Complex literal (re=0, im=N).
 # The wrapped numeric is the imaginary coefficient.
    if t == "ImaginaryNode"
      inner_im = @nd_expression[nid]
      if inner_im < 0
 # `numeric` parser field maps onto @nd_expression via the same
 # set_ref_field used for AssocNode/CapturePattern. If unset,
 # default to 1i.
        return "((sp_Complex){0.0, 1.0})"
      end
      inner_t = @nd_type[inner_im]
      if inner_t == "FloatNode"
        return "((sp_Complex){0.0, " + @nd_content[inner_im] + "})"
      end
 # IntegerNode coefficient -- cast to mrb_float for the im slot.
      return "((sp_Complex){0.0, (mrb_float)" + @nd_value[inner_im].to_s + "LL})"
    end
 # Issue #841: RationalNode `N/Mr` -- sp_Rational literal.
    if t == "RationalNode"
      return "((sp_Rational){" + @nd_rat_num[nid] + "LL, " + @nd_rat_den[nid] + "LL})"
    end
    if t == "StringNode"
      return c_string_literal(@nd_content[nid])
    end
    if t == "SymbolNode"
      return compile_symbol_literal(@nd_content[nid])
    end
    if t == "InterpolatedStringNode"
      return compile_interpolated(nid)
    end
    if t == "InterpolatedSymbolNode"
 # `:"foo_#{x}"` -- assemble via the same parts loop as
 # InterpolatedStringNode. CRuby returns a Symbol; Spinel returns
 # the string form because dynamic symbol interning isn't
 # supported (sp_sym ids are reserved for compile-time literals).
 # Use sites that accept either string or symbol -- puts, ==,
 # string interpolation -- behave identically.
      return compile_interpolated(nid)
    end
    if t == "BackReferenceReadNode"
 # `$&`, `$~`, `$'`, `$`, `$+`. Spinel populates sp_re_match_str /
 # _pre / _post in sp_re_set_captures alongside sp_re_captures
 # (used by NumberedReferenceReadNode for $1..$9). Each accessor
 # is null-guarded so unused reads return "" -- matches CRuby's
 # post-no-match behavior. $~ falls back to $& since Spinel
 # has no MatchData wrapper to expose. $+ walks the captures
 # backward via sp_re_last_paren_match.
      n = @nd_name[nid]
      if n == "$&" || n == "$~"
        return "(sp_re_match_str ? sp_re_match_str : \"\")"
      end
      if n == "$`"
        return "(sp_re_match_pre ? sp_re_match_pre : \"\")"
      end
      if n == "$'"
        return "(sp_re_match_post ? sp_re_match_post : \"\")"
      end
      if n == "$+"
        return "(sp_re_last_paren_match() ? sp_re_last_paren_match() : \"\")"
      end
      $stderr.puts "Spinel: BackReferenceReadNode `" + n + "` not supported"
      exit(1)
    end
    if t == "InterpolatedRegularExpressionNode"
 # `/foo_#{x}/` -- pattern is only known at execution time, so we
 # can't pre-compile to an sp_re_pat_<i> global. The pattern string
 # is built via compile_interpolated and passed to a per-call-site
 # cached helper `sp_re_dyn_<idx>` (emitted by emit_dyn_regex_helpers).
 # The helper compares the new pattern bytes to its cached key and
 # only re_free+recompile on miss, so heap is bounded to one engine
 # pattern per source location regardless of how many times the
 # site evaluates. Flags are baked into the helper at emission time.
      @needs_regexp = 1
      pat_c = compile_interpolated(nid)
      idx = find_dyn_regex_index(nid)
      return "sp_re_dyn_" + idx.to_s + "(" + pat_c + ")"
    end
    if t == "NumberedReferenceReadNode"
 # Issue #848: an out-of-range or unmatched capture should be
 # nil (NULL on the C side), not "". Return the raw slot so
 # downstream NULL-safe paths (.inspect, puts, ||) treat it as
 # nil. sp_re_captures[N] is NULL when the group didn't match
 # OR when N exceeds the pattern's capture count.
      num = @nd_value[nid]
      if num >= 1 && num <= 9
        return "sp_re_captures[" + num.to_s + "]"
      end
      return "NULL"
    end
    if t == "MatchWriteNode"
 # $1 = ... pattern match
      return compile_expr(@nd_receiver[nid])
    end
    if t == "TrueNode"
      return "TRUE"
    end
    if t == "FalseNode"
      return "FALSE"
    end
    if t == "NilNode"
      return "0"
    end
    if t == "SelfNode"
      return self_expr
    end
    if t == "LocalVariableReadNode"
      vn_lvr = @nd_name[nid]
      base_lvr = fiber_var_ref(vn_lvr)
 # Poly local narrowed to a primitive via a preceding guard
 # (`return X if h.nil?` for int-or-nil — #550; `if x.is_a?(C)`
 # then-arm body — #612). The base C ref is the sp_RbVal slot;
 # unbox via the matching union field so a typed callee
 # (sp_re_escape's `const char *`, arithmetic operators on
 # int, etc.) reads the unboxed value directly. obj_<C>
 # narrows over poly locals continue through the dispatch-
 # level paths that already handle them (#493).
      narrow_lvr = find_var_type(vn_lvr)
      declared_lvr = find_var_declared_type(vn_lvr)
 # Inlined yield-method body: declare_var pushes the renamed
 # `<name>_y1` local into scope_names, but the LV-read still
 # carries the original AST name (`content`). compile_if_stmt's
 # is_a? narrow push uses the AST name too, so find_var_type
 # picks up the narrow correctly, but find_var_declared_type
 # falls through to "" because scope_names only has the renamed
 # entry. Walk the inline rename map and retry under the
 # renamed name so the unbox arm fires inside the y1
 # specialization. Issue #624.
      if declared_lvr == "" && @inline_rename_map_from != nil
        ki = 0
        while ki < @inline_rename_map_from.length
          if @inline_rename_map_from[ki] == vn_lvr
            declared_lvr = find_var_declared_type(@inline_rename_map_to[ki])
            ki = @inline_rename_map_from.length
          else
            ki = ki + 1
          end
        end
      end
      if declared_lvr == "poly"
        if narrow_lvr == "int"
          return "(" + base_lvr + ").v.i"
        end
        if narrow_lvr == "string" || narrow_lvr == "mutable_str"
          return "(" + base_lvr + ").v.s"
        end
        if narrow_lvr == "float"
          return "(" + base_lvr + ").v.f"
        end
        if narrow_lvr == "bool"
          return "(" + base_lvr + ").v.b"
        end
        if narrow_lvr == "symbol"
          return "(sp_sym)(" + base_lvr + ").v.i"
        end
      end
      return base_lvr
    end
    if t == "InstanceVariableReadNode"
      return ivar_lhs(@nd_name[nid])
    end
    if t == "ClassVariableReadNode"
 # `@@var` -- reads the per-(class,name) C global registered
 # by collect_cvars. @current_class_idx is set during class
 # body and class/instance method compilation, so the lookup
 # resolves to whichever class's body or method we're in.
      return "cvar_" + cvar_qname(@current_class_idx, @nd_name[nid])
    end
    if t == "ClassVariableWriteNode"
 # Expression-form write: `def tick; @@x = @@x + 1; end` --
 # the method body's last expression is the write, and
 # CRuby returns the assigned value. Emits the C-comma
 # form so the assignment fires AND the value is the
 # result, matching the InstanceVariableWriteNode pattern
 # at line 14780.
      qname = cvar_qname(@current_class_idx, @nd_name[nid])
      val = compile_expr(@nd_expression[nid])
      val_t = infer_type(@nd_expression[nid])
      register_cvar(qname, val_t)
      return "(cvar_" + qname + " = " + val + ")"
    end
    if t == "ClassVariableOperatorWriteNode" || t == "ClassVariableOrWriteNode" || t == "ClassVariableAndWriteNode"
 # Expression form (`x = (@@y op= v)` or last stmt of a
 # class method body). Run the statement-style emit for the
 # side effect, then surface the cvar's post-assign value.
      compile_stmt(nid)
      qname_e = cvar_qname(@current_class_idx, @nd_name[nid])
      return "cvar_" + qname_e
    end
    if t == "InstanceVariableWriteNode"
 # Same poly-slot boxing as the statement-form emit.
 # Expression form (`x = (@y = expr)`) is rarer but reaches
 # the same slot through a different compile path.
      iname_w = @nd_name[nid]
      ivt_w = ""
      if @current_class_idx >= 0
        ivt_w = cls_ivar_type(@current_class_idx, iname_w)
      end
      if ivt_w == "poly"
        val = box_expr_to_poly(@nd_expression[nid])
      else
        val = compile_expr(@nd_expression[nid])
      end
 # Check if in module method
      mi3 = 0
      while mi3 < @module_names.length
        mmod = @module_names[mi3]
        if mmod != ""
          if @current_method_name.start_with?(mmod + "_cls_")
            cname3 = mmod + "_" + iname_w[1, iname_w.length - 1]
            ci3 = find_const_idx(cname3)
            if ci3 >= 0
              return "(cst_" + cname3 + " = " + val + ")"
            end
          end
        end
        mi3 = mi3 + 1
      end
      return "(" + ivar_lhs(iname_w) + " = " + val + ")"
    end
    if t == "InstanceVariableOrWriteNode" || t == "InstanceVariableAndWriteNode"
 # Expression form of `@x ||= …` / `@x &&= …`. Method bodies
 # whose last statement is one of these reach `compile_expr`
 # via the return-value path, so we need a value-producing
 # form. Run the statement-style emit for the side effect, then
 # surface `@x`'s post-assign value as the expression result.
      compile_stmt(nid)
      return ivar_lhs(@nd_name[nid])
    end
 # `(a, b = 10, 11)` used as an expression -- CRuby returns the
 # RHS array. Pre-fix compile_expr fell through to "0" and the
 # outer subscript / chained read read the wrong value. Issue
 # #554. Only the all-int homogeneous RHS shape is handled
 # here; other shapes still fall through to the default and
 # the warning surfaces at the consumer site.
    if t == "MultiWriteNode"
      val_id_mw = @nd_expression[nid]
      targets_mw = parse_id_list(@nd_targets[nid])
      if val_id_mw >= 0 && @nd_type[val_id_mw] == "ArrayNode"
        elems_mw = parse_id_list(@nd_elements[val_id_mw])
        all_int_mw = 1
        all_str_mw = 1
        kmw = 0
        while kmw < elems_mw.length
          et_mw = infer_type(elems_mw[kmw])
          if et_mw != "int"
            all_int_mw = 0
          end
          if et_mw != "string"
            all_str_mw = 0
          end
          kmw = kmw + 1
        end
        rhs_tmps = "".split(",", -1)
        rhs_ts = "".split(",", -1)
        kmw = 0
        while kmw < elems_mw.length
          et_mw = infer_type(elems_mw[kmw])
          tmp_mw = new_temp
          emit("  " + c_type(et_mw) + " " + tmp_mw + " = " + compile_expr(elems_mw[kmw]) + ";")
          rhs_tmps.push(tmp_mw)
          rhs_ts.push(et_mw)
          kmw = kmw + 1
        end
        @needs_gc = 1
        arr_tmp = new_temp
        if all_int_mw == 1
          @needs_int_array = 1
          emit("  sp_IntArray *" + arr_tmp + " = sp_IntArray_new();")
          kmw = 0
          while kmw < rhs_tmps.length
            emit("  sp_IntArray_push(" + arr_tmp + ", " + rhs_tmps[kmw] + ");")
            kmw = kmw + 1
          end
        elsif all_str_mw == 1
          @needs_str_array = 1
          emit("  sp_StrArray *" + arr_tmp + " = sp_StrArray_new();")
          kmw = 0
          while kmw < rhs_tmps.length
            emit("  sp_StrArray_push(" + arr_tmp + ", " + rhs_tmps[kmw] + ");")
            kmw = kmw + 1
          end
        else
          @needs_rb_value = 1
          emit("  sp_PolyArray *" + arr_tmp + " = sp_PolyArray_new();")
          kmw = 0
          while kmw < rhs_tmps.length
            emit("  sp_PolyArray_push(" + arr_tmp + ", " + box_value_to_poly(rhs_ts[kmw], rhs_tmps[kmw]) + ");")
            kmw = kmw + 1
          end
        end
        kmw = 0
        while kmw < targets_mw.length
          if kmw < rhs_tmps.length
            emit_multi_write_target(targets_mw[kmw], rhs_tmps[kmw], rhs_ts[kmw])
          end
          kmw = kmw + 1
        end
        return arr_tmp
      end
 # `(a, b = call_returning_typed_array)[i]` -- the RHS is a
 # CallNode (or anything not ArrayNode) whose static type is a
 # typed array. Evaluate the RHS into a single temp, destructure
 # the targets through array `_get`, and surface the temp as the
 # expression value so the outer `[i]` lands on a real array
 # instead of the int 0 fallback that the old "return 0" emit
 # produced (which segv'd in `sp_IntArray_get(0, 0)`). Issue
 # #584; sibling shape to the ArrayNode arm above.
      if val_id_mw >= 0
        val_t_mw_e = infer_type(val_id_mw)
        if is_array_type(val_t_mw_e) == 1
          @needs_gc = 1
          rhs_arr_tmp = new_temp
          emit("  " + c_type(val_t_mw_e) + " " + rhs_arr_tmp + " = " + compile_expr(val_id_mw) + ";")
          if type_needs_transient_root(val_t_mw_e) == 1
            emit("  SP_GC_ROOT(" + rhs_arr_tmp + ");")
          end
          elem_t_mw = elem_type_of_array(val_t_mw_e)
          pfx_mw = array_c_prefix(val_t_mw_e)
          kmw_e = 0
          while kmw_e < targets_mw.length
            slot_expr_mw = "sp_" + pfx_mw + "_get(" + rhs_arr_tmp + ", " + kmw_e.to_s + "LL)"
            emit_multi_write_target(targets_mw[kmw_e], slot_expr_mw, elem_t_mw)
            kmw_e = kmw_e + 1
          end
          return rhs_arr_tmp
        end
      end
      compile_multi_write(nid)
      return "0"
    end
    if t == "LocalVariableWriteNode"
 # `local = expr` used as an expression (e.g. inside a chained
 # `@a = local = expr` write, or `if (sprite = arr[i])` in a
 # conditional). Without this branch compile_expr falls through
 # and returns the default "0", which silently zeroed the outer
 # write — every `@_p_nz = ___a__ = __data__` in optcarrots
 # OptimizedCodeBuilder CPU output became `iv__p_nz = 0`.
 # Lower as a parenthesized C-style assignment, boxing scalar
 # RHS into poly when the local slot is poly (mirrors compile_stmt
 # InstanceVariableWriteNode logic).
      val = compile_expr(@nd_expression[nid])
      lname2 = @nd_name[nid]
      vt = find_var_type(lname2)
      rhs_t = infer_type(@nd_expression[nid])
      if vt == "poly" && rhs_t != "" && rhs_t != "poly"
        val = box_value_to_poly(rhs_t, val)
      end
 # promote-mode bigint slot: coerce an int rhs (literal, mrb_int-
 # returning call like `gets.to_i`) before the C-level assign.
 # Mirrors compile_stmt's LVW arm.
      if vt == "bigint" && rhs_t == "int"
        @needs_bigint = 1
        val = "sp_bigint_new_int(" + val + ")"
      elsif vt == "int" && rhs_t == "bigint"
        @needs_bigint = 1
        val = "sp_bigint_to_int((sp_Bigint *)" + val + ")"
      end
      return "(" + fiber_var_ref(lname2) + " = " + val + ")"
    end
    if t == "LocalVariableOperatorWriteNode"
 # `local OP= expr` used as an expression (e.g. ORA's
 # `@_p_nz = ___a__ |= __data__`). Same shape as the chained
 # write above — without this, the op-assign drops out and the
 # outer write zeroes the ivar.
      op = @nd_binop[nid]
      val = compile_expr(@nd_expression[nid])
      vref = fiber_var_ref(@nd_name[nid])
      vt = find_var_type(@nd_name[nid])
 # Obj-typed local: dispatch via user-defined operator instead
 # of emitting raw C `OP=` (pointer arithmetic on an obj slot).
      disp = obj_op_dispatch_expr(vt, vref, op, val)
      if disp != ""
        return "(" + vref + " = " + disp + ")"
      end
 # promote-mode bigint local: raw C `OP=` on a sp_Bigint *
 # pointer would be illegal arithmetic. Route through the
 # sp_bigint_<op> helpers. Mirrors the InstanceVariableOperator
 # WriteNode arm below.
      if base_type(vt) == "bigint"
        @needs_bigint = 1
        rhs_t_lov = infer_type(@nd_expression[nid])
        if rhs_t_lov != "bigint" && expr_emit_is_bigint(@nd_expression[nid]) == 1
          rhs_t_lov = "bigint"
        end
        rhs_big_lov = rhs_t_lov == "bigint" ? "(sp_Bigint *)(" + val + ")" : "sp_bigint_new_int(" + val + ")"
        if op == "+"
          return "(" + vref + " = sp_bigint_add((sp_Bigint *)" + vref + ", " + rhs_big_lov + "))"
        end
        if op == "-"
          return "(" + vref + " = sp_bigint_sub((sp_Bigint *)" + vref + ", " + rhs_big_lov + "))"
        end
        if op == "*"
          return "(" + vref + " = sp_bigint_mul((sp_Bigint *)" + vref + ", " + rhs_big_lov + "))"
        end
        if op == "/"
          return "(" + vref + " = sp_bigint_div((sp_Bigint *)" + vref + ", " + rhs_big_lov + "))"
        end
        if op == "%"
          return "(" + vref + " = sp_bigint_mod((sp_Bigint *)" + vref + ", " + rhs_big_lov + "))"
        end
        if op == "&"
          return "(" + vref + " = sp_bigint_and((sp_Bigint *)" + vref + ", " + rhs_big_lov + "))"
        end
        if op == "|"
          return "(" + vref + " = sp_bigint_or((sp_Bigint *)" + vref + ", " + rhs_big_lov + "))"
        end
        if op == "^"
          return "(" + vref + " = sp_bigint_xor((sp_Bigint *)" + vref + ", " + rhs_big_lov + "))"
        end
        if op == "<<" || op == ">>"
          shamt_lov = rhs_t_lov == "bigint" ? "sp_bigint_to_int(" + rhs_big_lov + ")" : "(" + val + ")"
          h_lov = op == "<<" ? "sp_bigint_shl" : "sp_bigint_shr"
          return "(" + vref + " = " + h_lov + "((sp_Bigint *)" + vref + ", " + shamt_lov + "))"
        end
      end
      return "(" + vref + " " + op + "= " + val + ")"
    end
    if t == "InstanceVariableOperatorWriteNode"
 # `@x OP= expr` used as an expression — typically the RHS of a
 # chained ivar write like `@b = @a &= 0x80`. Without this arm
 # compile_expr falls through to the catch-all `0`, so the inner
 # `@a &=` write never emits and the outer `@b = ...` zeros the
 # slot. Mirror the LocalVariableOperatorWriteNode shape — return
 # a parenthesized C-style compound assignment so the side effect
 # fires AND the value is the result.
      op_iow = @nd_binop[nid]
      val_iow = compile_expr(@nd_expression[nid])
      lhs_iow = ivar_lhs(@nd_name[nid])
      ivar_t_iow = ""
      if @current_class_idx >= 0
        ivar_t_iow = cls_ivar_type(@current_class_idx, @nd_name[nid])
      end
      disp_iow = obj_op_dispatch_expr(ivar_t_iow, lhs_iow, op_iow, val_iow, infer_type(@nd_expression[nid]))
      if disp_iow != ""
        return "(" + lhs_iow + " = " + disp_iow + ")"
      end
 # promote-mode bigint ivar: route arithmetic/bitwise through
 # sp_bigint_* helpers. Mirrors the compile_stmt InstanceVariable
 # OperatorWriteNode arm but returning the new slot value as the
 # expression's value.
      if ivar_t_iow == "bigint"
        @needs_bigint = 1
        rhs_t_iow = infer_type(@nd_expression[nid])
        rhs_big_iow = rhs_t_iow == "bigint" ? "(sp_Bigint *)(" + val_iow + ")" : "sp_bigint_new_int(" + val_iow + ")"
        big_op_iow = ""
        if op_iow == "+"
          big_op_iow = "sp_bigint_add"
        elsif op_iow == "-"
          big_op_iow = "sp_bigint_sub"
        elsif op_iow == "*"
          big_op_iow = "sp_bigint_mul"
        elsif op_iow == "/"
          big_op_iow = "sp_bigint_div"
        elsif op_iow == "%"
          big_op_iow = "sp_bigint_mod"
        end
        if big_op_iow != ""
          return "(" + lhs_iow + " = " + big_op_iow + "((sp_Bigint *)" + lhs_iow + ", " + rhs_big_iow + "))"
        end
        if op_iow == "&" || op_iow == "|" || op_iow == "^" || op_iow == "<<" || op_iow == ">>"
 # Promote-mode op-assign on a bigint ivar: route through the
 # sp_bigint_<op> helpers so both `bigint &= int` and
 # `bigint &= bigint_expr` shapes type-check. The legacy inline
 # `sp_bigint_to_int(lhs) <op> sp_bigint_to_int(rhs)` only
 # handled the int-rhs case cleanly; a bigint-emitting rhs (a
 # `^` chain etc.) left the rhs as sp_Bigint * and the inline
 # `&` rejected at C compile.
          rhs_big_iow_arg = rhs_big_iow
          if op_iow == "<<" || op_iow == ">>"
            shamt_iow = rhs_t_iow == "bigint" ? "sp_bigint_to_int(" + rhs_big_iow + ")" : "(" + val_iow + ")"
            helper_iow = op_iow == "<<" ? "sp_bigint_shl" : "sp_bigint_shr"
            return "(" + lhs_iow + " = " + helper_iow + "((sp_Bigint *)" + lhs_iow + ", " + shamt_iow + "))"
          end
          big_bitop_iow = op_iow == "&" ? "sp_bigint_and" : (op_iow == "|" ? "sp_bigint_or" : "sp_bigint_xor")
          return "(" + lhs_iow + " = " + big_bitop_iow + "((sp_Bigint *)" + lhs_iow + ", " + rhs_big_iow_arg + "))"
        end
      end
      return "(" + lhs_iow + " " + op_iow + "= " + val_iow + ")"
    end
    if t == "LocalVariableOrWriteNode"
 # `local ||= expr` in expression context. Lower as
 # `(local = local ? local : expr)` so the side effect runs
 # only on a falsy current value.
      vref = fiber_var_ref(@nd_name[nid])
      val = compile_expr(@nd_expression[nid])
      lvw_t_or = find_var_declared_type(@nd_name[nid])
      rhs_t_or = infer_type(@nd_expression[nid])
      if lvw_t_or == "poly" || is_scalar_nullable_type(lvw_t_or) == 1
        cond_or = truthy_c_expr(lvw_t_or, vref)
        val_or = (lvw_t_or == "poly" && rhs_t_or != "" && rhs_t_or != "poly") ? box_value_to_poly(rhs_t_or, val) : val
        return "(" + vref + " = " + cond_or + " ? " + vref + " : (" + val_or + "))"
      end
      return "(" + vref + " = " + vref + " ? " + vref + " : (" + val + "))"
    end
    if t == "LocalVariableAndWriteNode"
 # `local &&= expr` in expression context.
      vref = fiber_var_ref(@nd_name[nid])
      val = compile_expr(@nd_expression[nid])
      lvw_t_an = find_var_declared_type(@nd_name[nid])
      rhs_t_an = infer_type(@nd_expression[nid])
      if lvw_t_an == "poly" || is_scalar_nullable_type(lvw_t_an) == 1
        cond_an = truthy_c_expr(lvw_t_an, vref)
        val_an = (lvw_t_an == "poly" && rhs_t_an != "" && rhs_t_an != "poly") ? box_value_to_poly(rhs_t_an, val) : val
        return "(" + vref + " = " + cond_an + " ? (" + val_an + ") : " + vref + ")"
      end
      return "(" + vref + " = " + vref + " ? (" + val + ") : " + vref + ")"
    end
    if t == "IndexOrWriteNode"
 # `recv[k] ||= v` used as an expression (`x = recv[k] ||= v`,
 # method-body return, parenthesized chain like
 # `(@h[k] ||= []) << v`). Lower the get-then-set into a
 # stmt-level emit and return the temp holding the resulting
 # value (existing on hit, freshly-stored rhs on miss). Without
 # this branch the expression-form falls through to the default
 # catch-all and silently emits `0` as the value, collapsing
 # any subsequent chain.
      recv_iow = @nd_receiver[nid]
      args_iow = @nd_arguments[nid]
      if recv_iow >= 0 && args_iow >= 0
        rt_iow = infer_type(recv_iow)
        if rt_iow == "poly_poly_hash"
          rc_iow = compile_expr_gc_rooted(recv_iow)
          arg_ids_iow = get_args(args_iow)
          tg = compile_poly_poly_index_or_assign_to_temp(nid, rc_iow, arg_ids_iow)
          return tg
        end
        if rt_iow == "sym_poly_hash" || rt_iow == "str_poly_hash"
          rc_iow = compile_expr_gc_rooted(recv_iow)
          arg_ids_iow = get_args(args_iow)
          tg = compile_typed_poly_hash_index_or_assign_to_temp(nid, rc_iow, arg_ids_iow, rt_iow)
          return tg
        end
        if rt_iow == "poly_array"
          rc_iow = compile_expr_gc_rooted(recv_iow)
          arg_ids_iow = get_args(args_iow)
          tg = compile_typed_array_index_or_assign_to_temp(nid, rc_iow, arg_ids_iow, rt_iow)
          return tg
        end
        if rt_iow == "poly"
 # `<poly>[i] ||= v` — recv carries a poly_array at runtime
 # (the typical mid-chain shape, e.g. `(@h[k] ||= [])[i] ||=
 # ...`). Inline the cls_id guard + auto-grow set so the
 # chain produces an sp_RbVal value even when the initial
 # `[]` literal was empty.
          rc_iow = compile_expr_gc_rooted(recv_iow)
          tg = compile_poly_value_array_index_or_assign_to_temp(nid, rc_iow)
          return tg
        end
      end
    end
    if t == "ConstantReadNode"
      if @nd_name[nid] == "ARGV"
        @needs_argv = 1
        return "sp_argv"
      end
      rname = resolve_const_read_name(@nd_name[nid])
      ci = find_const_idx(rname)
      if ci >= 0
 # Propagate simple literal constants to their use sites.
        lv = const_literal_c_value(ci)
        if lv != ""
          return lv
        end
 # Issue #646: detect the self-referential init shape — a class
 # whose `initialize` reads a top-level const that's being
 # initialized via `<const> = <ThisClass>.new(...)`. Warn at
 # compile time AND, when the const has a per-const in-progress
 # flag (set by emit_main around the assignment), wrap the read
 # with a runtime check that raises NameError if the flag is
 # set. Matches MRI semantics rather than the silent partial-init
 # segfault.
        warn_self_ref_const_init(rname)
        if ci < @const_init_class.length && @const_init_class[ci] != ""
          @needs_setjmp = 1
 # sp_raise_cls never returns (longjmp), but C still requires
 # a value-typed dead branch for the comma operator. Use a
 # compound literal of the const's type so both struct and
 # pointer slots type-check ((sp_App){0} for value-types,
 # (sp_App *){0} effectively NULL for heap classes).
          dead_default_csr = "(" + c_type(@const_types[ci]) + "){0}"
          return "(sp_init_in_progress_" + rname + " ? (sp_raise_cls(\"NameError\", \"uninitialized constant " + rname + "\"), " + dead_default_csr + ") : cst_" + rname + ")"
        end
        return "cst_" + rname
      end
 # a class constant in value position
 # (`c = Foo`, `f(Foo)`, hash value, etc.) lowers to a
 # sp_Class compound literal carrying the class id. The
 # cls_id is just the class's index in @cls_names; the
 # generated sp_class_names[] table indexes by that. Class
 # constants used as method-call receivers are handled by
 # constructor_class_name / cls_method_owner_for without ever
 # going through compile_expr on the receiver, so this
 # branch only ever fires in a true value-position site.
 # built-in class const (Integer,
 # String, Array, ...) lowers to the reserved cls_id so
 # dynamic is_a?(Integer) on a poly primitive recv resolves
 # via the same sp_class_le path.
      bi = builtin_class_id_for_name(rname)
      if bi >= 0
        @needs_class_table = 1
        return "((sp_Class){" + bi.to_s + "LL})"
      end
      cls_idx = find_class_idx(rname)
      if cls_idx >= 0
        @needs_class_table = 1
        return "((sp_Class){" + cls_id_for_user_internal(cls_idx).to_s + "LL})"
      end
 # module name in value position.
      mod_idx = find_module_idx_local(rname)
      if mod_idx >= 0
        @needs_class_table = 1
        return "((sp_Class){" + cls_id_for_module_internal(mod_idx).to_s + "LL})"
      end
 # Built-in module-like constants (Math, File, ENV, …) and
 # registered classes / modules legitimately reach here as a
 # method-call receiver and don't need their own value at the
 # use site. Any other unresolved constant: warn and emit 0,
 # paired with the warn-and-emit-0 fallback at unresolved method
 # call sites (b17ec47). Hard error here used to be the design
 # but it bails on programs whose unsupported
 # idioms (e.g. `CLK_1, ..., CLK_8 = (1..8).map { ... }` —
 # constants registered by a multi-assign-from-Range#map shape
 # spinel doesn't yet detect) would otherwise compile silently
 # to wrong-but-running C. Warn keeps the diagnostic surface
 # consistent: every unresolved name produces one stderr line
 # plus a `0` placeholder, leaving the user a clear punch list.
 # Built-in Ruby pseudo-constants spinel-the-runtime can answer
 # without a per-host build step. spinel uses the host platform
 # detected by the C preprocessor at build time. Issue #890.
      if rname == "RUBY_VERSION"
        return "(&(\"\\xff\" \"4.0.0\")[1])"
      end
      if rname == "RUBY_ENGINE"
        return "(&(\"\\xff\" \"spinel\")[1])"
      end
      if rname == "RUBY_PLATFORM"
        return "sp_ruby_platform_str()"
      end
      if is_known_constant_name(rname) == 0
 # Uninitialised constant — raise NameError at runtime (CRuby
 # behaviour). Stmt-expression so the call site still gets an
 # expression value of the inferred type (the cast is reached
 # only after sp_raise_cls's longjmp, so it's dead code that
 # has to type-check).
        @needs_setjmp = 1
        rt_uc = infer_type(nid)
        return "({ sp_raise_cls(\"NameError\", \"uninitialized constant " + rname + "\"); " + c_default_val(rt_uc) + "; })"
      end
      return rname
    end
    if t == "ConstantPathNode"
      cpname = resolve_const_ref_name(nid)
      if cpname != ""
        ci = find_const_idx(cpname)
        if ci >= 0
          return "cst_" + cpname
        end
 # Nested user class as a value (`M::Inner`, `ActiveRecord::Base`).
 # The qualified name resolves to a registered user class, so emit
 # the sp_Class compound literal — same shape as ConstantReadNode's
 # flat user-class arm. Issue #637 shape B.
        cls_idx_cpn = find_class_idx(cpname)
        if cls_idx_cpn >= 0
          @needs_class_table = 1
          return "((sp_Class){" + cls_id_for_user_internal(cls_idx_cpn).to_s + "LL})"
        end
        mod_idx_cpn = find_module_idx_local(cpname)
        if mod_idx_cpn >= 0
          @needs_class_table = 1
          return "((sp_Class){" + cls_id_for_module_internal(mod_idx_cpn).to_s + "LL})"
        end
        bi_cpn = builtin_class_id_for_name(cpname)
        if bi_cpn >= 0
          @needs_class_table = 1
          return "((sp_Class){" + bi_cpn.to_s + "LL})"
        end
      end
      if @nd_receiver[nid] >= 0
        rname = resolve_const_ref_name(@nd_receiver[nid])
        nname = @nd_name[nid]
 # Built-in constants
        if rname == "Float"
          if nname == "INFINITY"
            return "(1.0/0.0)"
          end
          if nname == "NAN"
            return "(0.0/0.0)"
          end
        end
        if rname == "Integer"
          if nname == "MAX"
            return "INT64_MAX"
          end
        end
        if rname == "Math"
          if nname == "PI"
            return "3.14159265358979323846"
          end
          if nname == "E"
            return "2.71828182845904523536"
          end
        end
 # File::SEPARATOR / ALT_SEPARATOR / PATH_SEPARATOR. Issue #891.
        if rname == "File"
          if nname == "SEPARATOR"
            return "(&(\"\\xff\" \"/\")[1])"
          end
          if nname == "ALT_SEPARATOR"
            return "sp_str_empty"
          end
          if nname == "PATH_SEPARATOR"
            return "(&(\"\\xff\" \":\")[1])"
          end
        end
        if cpname != ""
          return cpname
        end
      end
      return @nd_name[nid]
    end
    if t == "LambdaNode"
      return compile_lambda_expr(nid)
    end
    if t == "CallNode"
      return compile_call_expr(nid)
    end
    if t == "IfNode"
      return compile_if_expr(nid)
    end
    if t == "UnlessNode"
      return compile_unless_expr(nid)
    end
    if t == "AndNode"
      left_nid = @nd_left[nid]
      right_nid = @nd_right[nid]
      lt = infer_type(left_nid)
      rt = infer_type(right_nid)
      le = compile_expr(left_nid)
      re = compile_expr(right_nid)
      le_t = truthy_node_expr(left_nid, lt, le)
      re_t = truthy_node_expr(right_nid, rt, re)
      return "(" + le_t + " && " + re_t + ")"
    end
    if t == "OrNode"
      left_nid = @nd_left[nid]
      right_nid = @nd_right[nid]
      lt = infer_type(left_nid)
      rt = infer_type(right_nid)
      ot = or_result_type(nid)
 # Issue #660: `hash[k] || rhs` where the hash is a typed
 # (non-poly) variant lowers the lhs to `sp_*Hash_get(h, k)` which
 # returns the value type's zero (0 / "") on missing key. The truthy
 # check on that zero is always TRUE (`((expr), TRUE)`), so the rhs
 # arm is unreachable -- diverging from MRI's nil-default semantics.
 #
 # Special-case the shape: when the lhs is a CallNode `[]` on a
 # typed-hash receiver, gate the ternary on `has_key`, not on the
 # value's truthiness. The lhs is evaluated only when the key is
 # present, so the call is single-eval safe. Poly-hash variants
 # already return sp_box_nil on miss; skip them.
      hash_or = lhs_typed_hash_get_for_or(left_nid)
      if hash_or != ""
        recv_nid_or = @nd_receiver[left_nid]
        rc_or = compile_expr(recv_nid_or)
        parts_or = hash_or.split("|", -1)
        cls_or = parts_or[0]
        val_t_or = parts_or[1]
        key_kind_or = parts_or[2]
 # Reuse the per-recv-kind key coercer helpers so a sym->str
 # widening (StrIntHash key from a SymbolNode arg) lands the
 # same emit as the standalone `h[k]` call.
        if key_kind_or == "str"
          key_or = compile_str_arg0(left_nid)
        elsif key_kind_or == "sym"
          key_or = compile_arg0_as_sym(left_nid)
        elsif key_kind_or == "int"
          key_or = compile_arg0_as_int(left_nid)
        else
          args_id_or_fallback = @nd_arguments[left_nid]
          aa_or_fallback = get_args(args_id_or_fallback)
          key_or = compile_expr(aa_or_fallback[0])
        end
        right_expr = compile_expr(right_nid)
        if ot == "poly"
          @needs_rb_value = 1
          lhs_box_or = box_value_to_poly(val_t_or, "sp_" + cls_or + "_get(" + rc_or + ", " + key_or + ")")
          right_box_or = base_type(rt) == "poly" ? right_expr : box_value_to_poly(rt, right_expr)
        else
          lhs_box_or = "sp_" + cls_or + "_get(" + rc_or + ", " + key_or + ")"
          right_box_or = right_expr
        end
        return "(sp_" + cls_or + "_has_key(" + rc_or + ", " + key_or + ") ? " + lhs_box_or + " : " + right_box_or + ")"
      end
      if ot != "bool" || lt != "bool" || rt != "bool"
        if ot == "poly"
          @needs_rb_value = 1
        end
        left_tmp = new_temp
        emit("  " + c_type(lt) + " " + left_tmp + " = " + compile_expr(left_nid) + ";")
        left_expr = left_tmp
        right_expr = compile_expr(right_nid)
        if ot == "poly"
          left_expr = box_value_to_poly(lt, left_expr)
          right_expr = box_value_to_poly(rt, right_expr)
        elsif base_type(lt) != base_type(ot)
          left_expr = c_default_val(ot)
        elsif base_type(rt) != base_type(ot)
          if rt == "nil"
            right_expr = c_default_val(ot)
          end
        end
        return "(" + truthy_node_expr(left_nid, lt, left_tmp) + " ? " + left_expr + " : " + right_expr + ")"
      end
      return "(" + compile_expr(left_nid) + " || " + compile_expr(right_nid) + ")"
    end
    if t == "ParenthesesNode"
      body = @nd_body[nid]
      if body >= 0
        stmts = get_stmts(body)
        if stmts.length == 1
          return compile_expr(stmts[0])
        end
        if stmts.length > 1
 # Multi-statement parens like `(stmt1; stmt2; ... ; expr)`
 # in expression context. We must NOT lower this to a C
 # comma-expression `(a, b, c)` because Cs `expr1 + expr2`
 # has unspecified evaluation order between operands, and
 # if either side has side effects (e.g. RTSs `(___sp__ =
 # ___sp__+1 & 0xff; __ram__[0x100+sp])`), GCC can reorder
 # so the increments fire out of order and the byte pulls
 # come from the wrong stack slots.
 # Strategy: emit the leading statements via emit() so they
 # are sequenced C statements. Then evaluate the final
 # expression and BIND it to a temp before returning, so
 # that an enclosing expression (e.g. `parens1 + parens2`)
 # cant interleave additional side effects from another
 # parens between this ones evaluation and use.
 # Leading statements must use compile_stmt so side-effecting
 # calls that return "0" via compile_expr (puts, print, raise,
 # writer assignments, ...) actually emit their effect rather
 # than degenerating to ` 0;`.
          k = 0
          while k < stmts.length - 1
            compile_stmt(stmts[k])
            k = k + 1
          end
          last_t = infer_type(stmts.last)
          if last_t == "void"
 # Final statement has no value — emit it for its effect and
 # report 0 as the parens' value.
            compile_stmt(stmts.last)
            return "0"
          end
          last_expr = compile_expr(stmts.last)
          tmp = new_temp
          emit("  " + c_type(last_t) + " " + tmp + " = " + last_expr + ";")
          return tmp
        end
      end
      return "0"
    end
    if t == "ArrayNode"
      return compile_array_literal(nid)
    end
    if t == "HashNode"
      return compile_hash_literal(nid)
    end
    if t == "RangeNode"
 # Endless `1..` / beginless `..5` ranges encode unbounded
 # sides as sentinel mins / maxs so include? / cover? give
 # the right answer (`(1..).include?(2.4)` -> true). Iteration
 # over an endless range is still an infinite loop (not
 # special-cased here). Issue #555 case 12.
      left_e = @nd_left[nid]
      right_e = @nd_right[nid]
      left_c = (left_e >= 0 && @nd_type[left_e] != "NilNode") ? compile_expr(left_e) : "INT64_MIN"
      right_c = (right_e >= 0 && @nd_type[right_e] != "NilNode") ? compile_expr(right_e) : "INT64_MAX"
      return "sp_range_new(" + left_c + ", " + right_c + ")"
    end
    if t == "DefinedNode"
 # `defined?(expr)` resolves to a tag string ("local-variable",
 # "instance-variable", "constant", "method", "expression") or
 # nil (emitted as the C NULL `const char*`). Compile-time
 # resolution covers the most common shapes; everything else
 # falls through to "expression". Issue #711.
      inner_d = @nd_expression[nid]
      if inner_d < 0
        return "((const char*)0)"
      end
      it_d = @nd_type[inner_d]
      if it_d == "LocalVariableReadNode"
 # @scope_names holds bare param/local names plus "---" frames.
        lname_d = @nd_name[inner_d]
        i_d = @scope_names.length - 1
        found_d = 0
        while i_d >= 0
          if @scope_names[i_d] == lname_d
            found_d = 1
            i_d = -1
          else
            i_d = i_d - 1
          end
        end
        if found_d == 1
          return "\"local-variable\""
        end
        return "((const char*)0)"
      end
      if it_d == "InstanceVariableReadNode"
 # Use the slot's recorded type: nil means scan_ivars added the
 # slot but no write was ever observed (matches CRuby's "ivar
 # exists but was never set" -> defined? is nil). Any other
 # recorded type means at least one writer exists at compile
 # time, so we treat the ivar as defined.
        iname_d = @nd_name[inner_d]
        defined_iv = 0
        if @current_class_idx >= 0
          it_d2 = cls_ivar_type(@current_class_idx, iname_d)
          if it_d2 != "nil" && it_d2 != ""
            defined_iv = 1
          end
        end
        if defined_iv == 0 && toplevel_ivar_type(iname_d) != "" && toplevel_ivar_type(iname_d) != "nil"
          defined_iv = 1
        end
        if defined_iv == 1
          return "\"instance-variable\""
        end
        return "((const char*)0)"
      end
      if it_d == "ConstantReadNode"
        cname_d = @nd_name[inner_d]
        if find_const_idx(cname_d) >= 0 || find_class_idx(cname_d) >= 0 || builtin_class_id_for_name(cname_d) >= 0
          return "\"constant\""
        end
        return "((const char*)0)"
      end
      if it_d == "CallNode" && @nd_receiver[inner_d] < 0
        mname_d = @nd_name[inner_d]
        if find_method_idx(mname_d) >= 0
          return "\"method\""
        end
        return "((const char*)0)"
      end
      if it_d == "NilNode"
        return "\"expression\""
      end
      if it_d == "TrueNode" || it_d == "FalseNode" || it_d == "SelfNode"
        return "\"expression\""
      end
      return "\"expression\""
    end
    if t == "RescueModifierNode"
      @needs_setjmp = 1
      tmp = new_temp
      rt = infer_type(nid)
      emit("  " + c_type(rt) + " " + tmp + " = " + c_default_val(rt) + ";")
      emit("  sp_exc_top++;")
      emit("  if (setjmp(sp_exc_stack[sp_exc_top-1]) == 0) {")
      emit("    " + tmp + " = " + compile_expr_for_expected_type(@nd_expression[nid], rt) + ";")
      emit("    sp_exc_top--;")
      emit("  } else {")
      emit("    sp_exc_top--;")
      emit("    " + tmp + " = " + compile_expr_for_expected_type(@nd_else_clause[nid], rt) + ";")
      emit("  }")
      return tmp
    end
    if t == "XStringNode"
      return "sp_backtick(" + c_string_literal(@nd_content[nid]) + ")"
    end
    if t == "InterpolatedXStringNode"
      interp = compile_interpolated(nid)
      return "sp_backtick(" + interp + ")"
    end
    if t == "GlobalVariableReadNode"
      gname = @nd_name[nid]
      if gname == "$stderr"
        return "0"
      end
      if gname == "$stdout"
        return "0"
      end
      if gname == "$?"
        return "sp_last_status"
      end
 # Regex match globals -- Prism delivers `$~`, `$&`, `$``, `$'`, `$+`
 # as GlobalVariableReadNode rather than BackReferenceReadNode.
 # spinel populates sp_re_match_str / _pre / _post in
 # sp_re_set_captures; $~ falls back to $& since there's no
 # MatchData wrapper. Null-guards match the BackReferenceReadNode
 # arm above so unused reads return "" (CRuby returns nil for
 # post-no-match $~; that divergence is the same one this arm
 # already had for the BackReferenceReadNode path). $+ walks the
 # captures backward via sp_re_last_paren_match. The English-name
 # aliases ($LAST_MATCH_INFO, $LAST_PAREN_MATCH) are intentionally
 # not auto-resolved here -- in CRuby they require `require 'English'`
 # and arriving without that should match CRuby's "unset global" nil.
      if gname == "$&" || gname == "$~"
        return "(sp_re_match_str ? sp_re_match_str : \"\")"
      end
      if gname == "$`"
        return "(sp_re_match_pre ? sp_re_match_pre : \"\")"
      end
      if gname == "$'"
        return "(sp_re_match_post ? sp_re_match_post : \"\")"
      end
      if gname == "$+"
        return "(sp_re_last_paren_match() ? sp_re_last_paren_match() : \"\")"
      end
 # Issue #831: `$!` is the currently-rescued exception. Return
 # its message string when in a rescue (depth > 0) else NULL,
 # so `$!.inspect` reads as "nil" outside rescue and round-trips
 # the message inside one.
      if gname == "$!"
        return "(sp_exc_top > 0 ? sp_exc_msg[sp_exc_top-1] : (const char *)0)"
      end
 # Punctuation globals beyond $! / $/ etc. that spinel doesn't
 # have a runtime view for: read as NULL string (Ruby's nil) so
 # compilation succeeds and `.inspect` round-trips through
 # sp_str_inspect's NULL handler to "nil".
      if gname == "$;" || gname == "$,"
        return "(const char *)0"
      end
      if gname == "$/"
        return "\"\\n\""
      end
 # General global variable
      return sanitize_gvar(gname)
    end
    if t == "SourceLineNode"
      return @nd_value[nid].to_s
    end
    if t == "SourceFileNode"
 # __FILE__ — parser populated @nd_content with the toplevel
 # script path. (Inlined-require call sites all see the same
 # path; documented limitation in test/source_file.rb.)
      return c_string_literal(@nd_content[nid])
    end
    if t == "SourceEncodingNode"
 # __ENCODING__ — Spinel sources are UTF-8, represented as a
 # small Encoding value so `.class` and `.name` match Ruby.
      return "sp_encoding_utf8()"
    end
    if t == "ArgumentsNode"
      arg_ids = parse_id_list(@nd_args[nid])
      if arg_ids.length > 0
        return compile_expr(arg_ids[0])
      end
      return "0"
    end
    if t == "StatementsNode"
      stmts = parse_id_list(@nd_stmts[nid])
      if stmts.length > 0
        return compile_expr(stmts.last)
      end
      return "0"
    end
    if t == "EmbeddedStatementsNode"
 # `"#{expr1; expr2; ...; exprN}"` -- the interpolation's value
 # is the LAST statement in Ruby; intermediate statements run for
 # their side effects. Emit each leading stmt and return the
 # tail's expression. Issue #729.
      body = @nd_body[nid]
      if body >= 0
        stmts = get_stmts(body)
        if stmts.length > 0
          k_es = 0
          while k_es < stmts.length - 1
            compile_stmt(stmts[k_es])
            k_es = k_es + 1
          end
          return compile_expr(stmts[stmts.length - 1])
        end
      end
      return "0"
    end
    if t == "BeginNode"
 # `puts (begin ... rescue ... end)` -- begin/rescue used as
 # an expression. Same return-capture pattern as
 # compile_body_return_inner's BeginNode arm. Issue #704.
      rt_bn = infer_type(nid)
      rc_id_bn = @nd_rescue_clause[nid]
      ec_id_bn = @nd_ensure_clause[nid]
      if rc_id_bn < 0 && ec_id_bn < 0
 # Bare `begin ... end` with no rescue / ensure -- evaluate the
 # body's last expression. compile_body_into emits the body and
 # captures the last expr into ret_tmp.
        ret_tmp_bn = new_temp
        emit("  " + c_type(rt_bn) + " " + ret_tmp_bn + " = " + c_default_val(rt_bn) + ";")
        compile_body_into(@nd_body[nid], ret_tmp_bn, rt_bn)
        return ret_tmp_bn
      end
      if rc_id_bn >= 0 && body_has_retry(@nd_body[rc_id_bn]) == 0
 # Single-setjmp rescue: capture begin body's last expression OR
 # rescue arm's last expression into ret_tmp. When ensure is
 # present, run the ensure body for side effects after the
 # rescue chain -- its value is discarded per Ruby semantics.
        @needs_setjmp = 1
        ret_tmp_bn = new_temp
        emit("  " + c_type(rt_bn) + " " + ret_tmp_bn + " = " + c_default_val(rt_bn) + ";")
        emit("  sp_exc_top++;")
        emit("  if (setjmp(sp_exc_stack[sp_exc_top-1]) == 0) {")
        @indent = @indent + 1
        else_id_bn = @nd_else_clause[nid]
        if else_id_bn >= 0
          compile_stmts_body(@nd_body[nid])
          else_body_bn = @nd_body[else_id_bn]
          if else_body_bn >= 0
            compile_body_into(else_body_bn, ret_tmp_bn, rt_bn)
          end
        else
          compile_body_into(@nd_body[nid], ret_tmp_bn, rt_bn)
        end
        emit("  sp_exc_top--;")
        @indent = @indent - 1
        emit("  } else {")
        @indent = @indent + 1
        emit("  sp_exc_top--;")
        compile_rescue_chain_into(rc_id_bn, ret_tmp_bn, rt_bn)
        @indent = @indent - 1
        emit("  }")
        if ec_id_bn >= 0
 # ensure body's value is discarded; emit as side-effecting stmts.
          compile_stmts_body(@nd_body[ec_id_bn])
        end
        return ret_tmp_bn
      end
 # retry shapes: fall back to stmt form (no capture).
      compile_begin_stmt(nid)
      return c_default_val(rt_bn)
    end
    if t == "CaseNode"
 # Case as expression: use a temp var and compile each branch as assignment
      rt = infer_type(nid)
      tmp = new_temp
      emit("  " + c_type(rt) + " " + tmp + " = " + c_default_val(rt) + ";")
      pred = @nd_predicate[nid]
      if pred >= 0
        pred_type = infer_type(pred)
        pred_val = compile_expr(pred)
        ptmp = new_temp
        if pred_type == "string"
          emit("  const char *" + ptmp + " = " + pred_val + ";")
        elsif is_obj_type(pred_type) == 1
 # See compile_case_stmt — route the temp declaration through
 # c_type so value-type classes get `sp_<X>` (no pointer) and
 # standard heap classes get `sp_<X> *`. compile_when_conds then
 # resolves `when ClassName` against the right shape.
          emit("  " + c_type(pred_type) + " " + ptmp + " = " + pred_val + ";")
        elsif pred_type == "poly"
 # Poly scrutinee -- `case x when Range; ...` against a sp_RbVal
 # variable. Without this arm, the temp fell through to the
 # `mrb_int` default below and `sp_class_for_poly(_t)` got an
 # int instead of sp_RbVal. Issue #604: case/when bound to a
 # local result temp split the result type from the scrutinee
 # type; the result-temp (rt) is what new_temp/c_default_val
 # uses, but the scrutinee temp must follow pred_type.
          @needs_rb_value = 1
          emit("  sp_RbVal " + ptmp + " = " + pred_val + ";")
        elsif pred_type == "bigint"
 # promote-mode-widened scrutinee: when-arms compare against
 # int literals / ranges, so unbox to mrb_int up front and
 # treat the temp as int for the when dispatch.
          @needs_bigint = 1
          emit("  mrb_int " + ptmp + " = sp_bigint_to_int((sp_Bigint *)" + pred_val + ");")
          pred_type = "int"
        else
          emit("  " + c_type(pred_type) + " " + ptmp + " = " + pred_val + ";")
        end
        conds = parse_id_list(@nd_conditions[nid])
        k = 0
        while k < conds.length
          wid = conds[k]
          if @nd_type[wid] == "WhenNode"
            kw = "if"
            if k > 0
              kw = "} else if"
            end
            cond_str = compile_when_conds(wid, ptmp, pred_type)
            emit("  " + kw + " (" + cond_str + ") {")
            wbody = @nd_body[wid]
            if wbody >= 0
              ws = get_stmts(wbody)
              if ws.length > 0
                i = 0
                while i < ws.length - 1
                  compile_stmt(ws[i])
                  i = i + 1
                end
                emit("    " + tmp + " = " + box_when_arm_to_target(ws.last, rt) + ";")
              end
            end
          end
          k = k + 1
        end
      else
 # Bare case (no predicate)
        conds = parse_id_list(@nd_conditions[nid])
        k = 0
        while k < conds.length
          wid = conds[k]
          if @nd_type[wid] == "WhenNode"
            kw = "if"
            if k > 0
              kw = "} else if"
            end
            wconds = parse_id_list(@nd_conditions[wid])
            cexpr = "0"
            if wconds.length > 0
              cexpr = compile_expr(wconds.first)
            end
            emit("  " + kw + " (" + cexpr + ") {")
            wbody = @nd_body[wid]
            if wbody >= 0
              ws = get_stmts(wbody)
              if ws.length > 0
                i = 0
                while i < ws.length - 1
                  compile_stmt(ws[i])
                  i = i + 1
                end
                emit("    " + tmp + " = " + box_when_arm_to_target(ws.last, rt) + ";")
              end
            end
          end
          k = k + 1
        end
      end
      ec = @nd_else_clause[nid]
      if ec >= 0
        emit("  } else {")
        ebody = @nd_body[ec]
        if ebody >= 0
          es = get_stmts(ebody)
          if es.length > 0
            i = 0
            while i < es.length - 1
              compile_stmt(es[i])
              i = i + 1
            end
            emit("    " + tmp + " = " + box_when_arm_to_target(es.last, rt) + ";")
          end
        end
      end
      conds2 = parse_id_list(@nd_conditions[nid])
      if conds2.length > 0
        emit("  }")
      end
      return tmp
    end
    if t == "SuperNode" || t == "ForwardingSuperNode"
      return compile_super_expr(nid, t)
    end
    "0"
  end

 # `super` / `super(...)` in a non-`initialize` instance method.
 # — without this the call fell through to `0`.
 # `super` inside `initialize` is handled in the constructor synth
 # path (lines ~19041) and doesn't reach compile_expr.
  def compile_super_expr(nid, t)
    if @current_class_idx < 0 || @current_method_name == ""
      return "0"
    end
    mname_su = @current_method_name
 # Prepend chain redirect (issue #720). When inside an active
 # prepended method or a shadow, super dispatches to a synthetic
 # method on the same class instead of walking the parent chain.
    prep_target_name = prep_super_target(@current_class_idx, mname_su)
    if prep_target_name != ""
      blk_pr = @nd_block[nid]
      if blk_pr >= 0 && @nd_type[blk_pr] == "BlockNode"
        $stderr.puts "warning: super { block } from a prepended method is not yet supported (issue #720 v1); falling back to bare super"
      end
      return compile_super_prep_call(nid, t, @current_class_idx, prep_target_name, mname_su)
    end
 # When the current method is a shadow at chain index 0 (no more
 # on-class shadows), super falls through to the parent class,
 # but the parent-side lookup must use the original user mname,
 # not the synthetic name. For non-shadows this is a no-op.
    parent_lookup_mname = prep_super_parent_mname(@current_class_idx, mname_su)
    parent_name = @cls_parents[@current_class_idx]
    if parent_name == ""
      return "0"
    end
    parent_ci = find_class_idx(parent_name)
    if parent_ci < 0
      return "0"
    end
    owner_su = find_method_owner(parent_ci, parent_lookup_mname)
    if owner_su == ""
      return "0"
    end
 # `super { ... }` carries a literal block. The parent method declares
 # `_block, _benv` in its C signature when its body yields, so a plain
 # `sp_Parent_test(self)` call type-checks too few arguments. Inline
 # the parent body in place and substitute `yield` with the block body
 # — same model the regular literal-block call path uses
 # (compile_yield_call_expr). Issue #665.
    blk_su = @nd_block[nid]
    if blk_su >= 0 && @nd_type[blk_su] == "BlockNode"
      owner_ci_su = find_class_idx(owner_su)
      if owner_ci_su >= 0
        midx_su = cls_find_method_direct(owner_ci_su, parent_lookup_mname)
        if midx_su >= 0
          return compile_super_with_block_inline(nid, t, owner_ci_su, midx_su, blk_su)
        end
      end
    end
    cast_self = "(sp_" + owner_su + " *)self"
    args_c = ""
    if t == "ForwardingSuperNode"
 # Forward every formal param of the current method by name.
      cur_params = @cls_meth_params[@current_class_idx].split("|", -1)
      midx_cur = cls_find_method_direct(@current_class_idx, mname_su)
      if midx_cur >= 0 && midx_cur < cur_params.length
        pn_list = cur_params[midx_cur].split(",", -1)
        pi_su = 0
        while pi_su < pn_list.length
          if pn_list[pi_su] != ""
            args_c = args_c + ", lv_" + pn_list[pi_su]
          end
          pi_su = pi_su + 1
        end
      end
    else
 # SuperNode: explicit `super(arg1, arg2, ...)` — use the arg list.
      args_id_su = @nd_arguments[nid]
      if args_id_su >= 0
        a_ids = get_args(args_id_su)
        ai_su = 0
        while ai_su < a_ids.length
          args_c = args_c + ", " + compile_expr(a_ids[ai_su])
          ai_su = ai_su + 1
        end
      end
    end
 # Pad the trailing `_block, _benv` yield-ABI slots when the parent's
 # body yields — the literal-block case is handled above, so on this
 # branch we always pass NULL/NULL for the block slot. Issue #665.
    yargs_su = ""
    owner_ci_su2 = find_class_idx(owner_su)
    if owner_ci_su2 >= 0
      midx_su2 = cls_find_method_direct(owner_ci_su2, parent_lookup_mname)
      yargs_su = cls_call_yargs(owner_ci_su2, midx_su2)
    end
    "sp_" + owner_su + "_" + sanitize_name(parent_lookup_mname) + "(" + cast_self + args_c + yargs_su + ")"
  end

 # Emit a super call routed through the prepend chain. target_name
 # is a synthetic shadow on the current class ci. Same-class call
 # so the self cast is `(sp_<ci> *)self`. Args are forwarded the
 # same way as a regular super.
  def compile_super_prep_call(nid, t, ci, target_name, cur_mname)
    cname = @cls_names[ci]
    if @cls_is_value_type[ci] == 1
      cast_self = "self"
    else
      cast_self = "self"
    end
    args_c = ""
    if t == "ForwardingSuperNode"
      cur_params = @cls_meth_params[ci].split("|", -1)
      midx_cur = cls_find_method_direct(ci, cur_mname)
      if midx_cur >= 0 && midx_cur < cur_params.length
        pn_list = cur_params[midx_cur].split(",", -1)
        pi_pr = 0
        while pi_pr < pn_list.length
          if pn_list[pi_pr] != ""
            args_c = args_c + ", lv_" + pn_list[pi_pr]
          end
          pi_pr = pi_pr + 1
        end
      end
    else
      args_id_pr = @nd_arguments[nid]
      if args_id_pr >= 0
        a_ids_pr = get_args(args_id_pr)
        ai_pr = 0
        while ai_pr < a_ids_pr.length
          args_c = args_c + ", " + compile_expr(a_ids_pr[ai_pr])
          ai_pr = ai_pr + 1
        end
      end
    end
    yargs_pr = ""
    midx_target = cls_find_method_direct(ci, target_name)
    if midx_target >= 0
      yargs_pr = cls_call_yargs(ci, midx_target)
    end
    "sp_" + cname + "_" + target_name + "(" + cast_self + args_c + yargs_pr + ")"
  end

 # `super { ... }` lowering. Mirrors compile_yield_call_expr but reads
 # the inlined body / params / locals from the parent class's method
 # tables (owner_ci, midx) rather than the top-level @meth_* tables.
 # The block body replaces `yield` inside the parent body via the
 # standard compile_stmt_with_block walker; the result temp captures
 # the parent body's last expression so super's value can be
 # propagated through enclosing expressions. Issue #665.
  def compile_super_with_block_inline(nid, t, owner_ci, midx, blk)
    bp_names = "".split(",", -1)
    bp_id = @nd_parameters[blk]
    if bp_id >= 0
      inner_bp = @nd_parameters[bp_id]
      if inner_bp >= 0
        reqs_bp = parse_id_list(@nd_requireds[inner_bp])
        kbp = 0
        while kbp < reqs_bp.length
          bp_names.push(@nd_name[reqs_bp[kbp]])
          kbp = kbp + 1
        end
      end
    end
    arg_ids_sw = []
    if t == "SuperNode"
      args_id_sw = @nd_arguments[nid]
      if args_id_sw >= 0
        arg_ids_sw = get_args(args_id_sw)
      end
    end
    pnames = cls_meth_pnames_get(owner_ci, midx)
    ptypes = cls_meth_ptypes_get(owner_ci, midx)
    @block_counter = @block_counter + 1
    suffix_sw = "_s" + @block_counter.to_s
    map_from_sw = "".split(",", -1)
    map_to_sw = "".split(",", -1)
    cur_params_for_fwd = "".split(",", -1)
    if t == "ForwardingSuperNode"
      cur_params_all = @cls_meth_params[@current_class_idx].split("|", -1)
      midx_cur_sw2 = cls_find_method_direct(@current_class_idx, @current_method_name)
      if midx_cur_sw2 >= 0 && midx_cur_sw2 < cur_params_all.length
        cur_params_for_fwd = cur_params_all[midx_cur_sw2].split(",", -1)
      end
    end
    kp_sw = 0
    while kp_sw < pnames.length
      pt_sw = "int"
      if kp_sw < ptypes.length
        pt_sw = ptypes[kp_sw]
      end
      tname_sw = pnames[kp_sw] + suffix_sw
      val_sw = c_default_val(pt_sw)
      if t == "ForwardingSuperNode"
        if kp_sw < cur_params_for_fwd.length && cur_params_for_fwd[kp_sw] != ""
          val_sw = "lv_" + cur_params_for_fwd[kp_sw]
        end
      else
        if kp_sw < arg_ids_sw.length
          val_sw = compile_expr(arg_ids_sw[kp_sw])
          arg_t_sw = infer_type(arg_ids_sw[kp_sw])
          if base_type(pt_sw) == "bigint" && arg_t_sw == "int"
            @needs_bigint = 1
            val_sw = "sp_bigint_new_int(" + val_sw + ")"
          elsif base_type(pt_sw) == "int" && arg_t_sw == "bigint"
            @needs_bigint = 1
            val_sw = "sp_bigint_to_int((sp_Bigint *)" + val_sw + ")"
          end
        end
      end
      emit("  " + c_type(pt_sw) + " lv_" + tname_sw + " = " + val_sw + ";")
      map_from_sw.push(pnames[kp_sw])
      map_to_sw.push(tname_sw)
      declare_var(tname_sw, pt_sw)
      kp_sw = kp_sw + 1
    end
    bid_sw = -1
    bodies_sw = @cls_meth_bodies[owner_ci].split(";", -1)
    if midx < bodies_sw.length
      bid_sw = bodies_sw[midx].to_i
    end
    if bid_sw >= 0
      flocals_n_sw = "".split(",", -1)
      flocals_t_sw = "".split(",", -1)
      sn_sw = @nd_scope_names[bid_sw]
      if sn_sw != ""
        flocals_n_sw = sn_sw.split("|", -1)
        flocals_t_sw = @nd_scope_types[bid_sw].split("|", -1)
      end
      kf_sw = 0
      while kf_sw < flocals_n_sw.length
 # Issue #810: bound the type lookup. If the scope name list is
 # longer than the type list (mismatched serialization), fall back
 # to "int" so we don't pass nil through c_type / c_default_val
 # and crash.
        t_sw = "int"
        if kf_sw < flocals_t_sw.length
          t_sw = flocals_t_sw[kf_sw]
        end
        tname_lv = flocals_n_sw[kf_sw] + suffix_sw
        emit("  " + c_type(t_sw) + " lv_" + tname_lv + " = " + c_default_val(t_sw) + ";")
        map_from_sw.push(flocals_n_sw[kf_sw])
        map_to_sw.push(tname_lv)
        declare_var(tname_lv, t_sw)
        declare_var(flocals_n_sw[kf_sw], t_sw)
        kf_sw = kf_sw + 1
      end
    end
    rt_sw = "int"
    returns_sw = @cls_meth_returns[owner_ci].split(";", -1)
    if midx < returns_sw.length
      rt_sw = returns_sw[midx]
    end
    result_tmp_sw = new_temp
    emit("  " + c_type(rt_sw) + " " + result_tmp_sw + " = " + c_return_default(rt_sw) + ";")
    saved_rmf_sw = @inline_rename_map_from
    saved_rmt_sw = @inline_rename_map_to
    @inline_rename_map_from = map_from_sw
    @inline_rename_map_to = map_to_sw
    if bid_sw >= 0
      stmts_sw = get_stmts(bid_sw)
      ns_sw = stmts_sw.length
      ks_sw = 0
      while ks_sw < ns_sw - 1
        compile_stmt_with_block(stmts_sw[ks_sw], blk, bp_names, map_from_sw, map_to_sw)
        ks_sw = ks_sw + 1
      end
      if ns_sw > 0
        last_sw = stmts_sw.last
        last_ty_sw = @nd_type[last_sw]
        if last_ty_sw == "YieldNode" || last_ty_sw == "IfNode" || last_ty_sw == "CaseNode" ||
           last_ty_sw == "WhileNode" || last_ty_sw == "BeginNode" || last_ty_sw == "ReturnNode" ||
           last_ty_sw == "LocalVariableWriteNode" || last_ty_sw == "InstanceVariableWriteNode" ||
           last_ty_sw == "ClassVariableWriteNode" || last_ty_sw == "GlobalVariableWriteNode"
          compile_stmt_with_block(last_sw, blk, bp_names, map_from_sw, map_to_sw)
        else
          last_val_sw = compile_expr_remap(last_sw, map_from_sw, map_to_sw)
          last_t_sw = infer_type(last_sw)
          if base_type(rt_sw) == "bigint" && last_t_sw == "int"
            @needs_bigint = 1
            last_val_sw = "sp_bigint_new_int(" + last_val_sw + ")"
          elsif base_type(rt_sw) == "int" && last_t_sw == "bigint"
            @needs_bigint = 1
            last_val_sw = "sp_bigint_to_int((sp_Bigint *)" + last_val_sw + ")"
          end
          emit("  " + result_tmp_sw + " = " + last_val_sw + ";")
        end
      end
    end
    @inline_rename_map_from = saved_rmf_sw
    @inline_rename_map_to = saved_rmt_sw
    result_tmp_sw
  end

  def c_string_literal(s)
 # Issue #722: NUL-containing literals can't ride the static
 # `(&("\xff" "...")[1])` form: sp_str_byte_len falls back to
 # strlen for that marker and stops at the embedded NUL, so
 # downstream `.length` / `.bytes` would report a short length.
 # Emit a heap-allocated copy with sp_str_set_len recording the
 # full byte length. NUL inside literals is rare; the per-call
 # alloc is acceptable.
    has_nul = 0
    nul_check_i = 0
    while nul_check_i < s.length
      if s[nul_check_i] == 0.chr
        has_nul = 1
        nul_check_i = s.length
      end
      nul_check_i = nul_check_i + 1
    end
    if has_nul == 1
 # Build the C string literal with `\000` escapes, then wrap
 # in a stmt-expression that allocates a GC string and copies.
 # High bytes (>= 0x80) escape via `\xHH` for the same
 # source-encoding reason as the static path below.
      inner = ""
      ii = 0
      while ii < s.length
        ch = s[ii]
        if ch == bsl
          inner = inner + bsl + bsl
        elsif ch == "\""
          inner = inner + bsl + "\""
        elsif ch == 10.chr
          inner = inner + bsl_n
        elsif ch == 13.chr
          inner = inner + bsl + "r"
        elsif ch == 9.chr
          inner = inner + bsl + "t"
        elsif ch == 0.chr
          inner = inner + bsl + "000"
        elsif ch.ord >= 0x80
          hex = "0123456789ABCDEF"
          cb2 = 0
          while cb2 < ch.bytesize
            bb2 = ch.getbyte(cb2)
            inner = inner + bsl + "x" + hex[(bb2 >> 4) & 0xF] + hex[bb2 & 0xF]
            cb2 = cb2 + 1
          end
          if ii + 1 < s.length
            nb = s[ii + 1].getbyte(0)
            if (nb >= 48 && nb <= 57) || (nb >= 65 && nb <= 70) || (nb >= 97 && nb <= 102)
              inner = inner + "\" \""
            end
          end
        else
          inner = inner + ch
        end
        ii = ii + 1
      end
      n = s.length.to_s
      return "({ char *_s = sp_str_alloc(" + n + "); memcpy(_s, \"" + inner + "\", " + n + "); _s[" + n + "] = 0; sp_str_set_len(_s, " + n + "); (const char *)_s; })"
    end
 # Input `s` is the runtime Ruby string content (already-cooked: any
 # backslash in `s` is a literal backslash, NOT an escape introducer).
 # We C-escape the small set that needs it: backslash, double-quote,
 # newline, carriage return, tab. Bytes >= 0x80 are escaped as
 # `\xHH` (and string-concat-broken so subsequent hex digits don't
 # extend the escape) — clang's -Winvalid-source-encoding rejects
 # raw high bytes in source files.
    result = "\""
    i = 0
    while i < s.length
      ch = s[i]
      if ch == bsl
        result = result + bsl + bsl
      else
        if ch == "\""
          result = result + bsl + "\""
        else
          if ch == 10.chr
            result = result + bsl_n
          else
            if ch == 13.chr
              result = result + bsl + "r"
            else
              if ch == 9.chr
                result = result + bsl + "t"
              else
                if ch == 0.chr
 # NUL byte inside the literal. Octal `\000` always
 # consumes exactly 3 digits so a following digit char doesn't
 # extend the escape. sp_str_byte_len falls back to strlen for
 # static literals so the in-string-NUL length still reports
 # short; full length-preserving static literals would need a
 # new marker -- deferred.
                  result = result + bsl + "000"
                else
                  bv = ch.ord
                  if bv >= 0x80
 # Multi-byte / high-byte: emit one `\xHH` per UTF-8 byte so
 # the source-encoding warning doesn't fire and the output
 # round-trips byte-for-byte.
                    hex = "0123456789ABCDEF"
                    cb = 0
                    while cb < ch.bytesize
                      bb = ch.getbyte(cb)
                      result = result + bsl + "x" + hex[(bb >> 4) & 0xF] + hex[bb & 0xF]
                      cb = cb + 1
                    end
 # Break out of the escape with a string concat so a
 # following hex digit ('0'-'9' / 'a'-'f' / 'A'-'F')
 # doesn't get absorbed into the \xHH sequence.
                    if i + 1 < s.length
                      nb = s[i + 1].getbyte(0)
                      if (nb >= 48 && nb <= 57) || (nb >= 65 && nb <= 70) || (nb >= 97 && nb <= 102)
                        result = result + "\" \""
                      end
                    end
                  else
                    result = result + ch
                  end
                end
              end
            end
          end
        end
      end
      i = i + 1
    end
 # Prepend 0xff marker byte so GC can identify static literals.
 # Return form: (&("\xff" "content")[1]) — same pointer value as the
 # legacy ("\xff" "content" + 1) idiom, but uses array indexing so
 # clang doesn't flag it under -Wstring-plus-int.
    "(&(\"\\xff\" " + result + "\")[1])"
  end

  def compile_interpolated(nid)
    parts = parse_id_list(@nd_parts[nid])
    if parts.length == 0
      return "(&(\"\\xff\")[1])"
    end
    fmt = ""
    arg_exprs = "".split(",", -1)
    parts.each { |pid|
      if @nd_type[pid] == "StringNode"
        fmt = fmt + escape_c_format(@nd_content[pid])
      else
        if @nd_type[pid] == "EmbeddedStatementsNode"
          body = @nd_body[pid]
          if body >= 0
            stmts = get_stmts(body)
            if stmts.length > 0
 # Emit each leading stmt for side effects; the
 # interpolation's value is the LAST stmt. Issue #729.
              k_es2 = 0
              while k_es2 < stmts.length - 1
                compile_stmt(stmts[k_es2])
                k_es2 = k_es2 + 1
              end
              inner = stmts[stmts.length - 1]
              it = infer_type(inner)
              if it == "int"
                fmt = fmt + "%lld"
                arg_exprs.push("(long long)" + compile_expr(inner))
              elsif it == "bigint"
 # promote-mode interpolation of an Integer LV: route
 # through sp_bigint_to_s so the displayed value is the
 # bigint's decimal repr, not a pointer cast to long long.
                @needs_bigint = 1
                fmt = fmt + "%s"
                arg_exprs.push("sp_bigint_to_s((sp_Bigint *)" + compile_expr(inner) + ")")
              else
                if it == "float"
 # CRuby's Float#to_s (which is what `"#{x}"` calls)
 # always preserves the decimal point: `4.0` -> `"4.0"`,
 # not `"4"`. printf %g drops the trailing zero. Route
 # through sp_float_to_s for parity.
                  fmt = fmt + "%s"
                  arg_exprs.push("sp_float_to_s(" + compile_expr(inner) + ")")
                else
                  if it == "string"
                    fmt = fmt + "%s"
                    arg_exprs.push(compile_expr(inner))
                  else
                    if it == "bool"
                      fmt = fmt + "%s"
                      arg_exprs.push("(" + compile_expr(inner) + " ? \"true\" : \"false\")")
                    else
                      if it == "poly"
                        fmt = fmt + "%s"
                        arg_exprs.push("sp_poly_to_s(" + compile_expr(inner) + ")")
                      elsif it == "class"
 # string-interpolated sp_Class
 # value -> the class's name via the
 # sp_class_names[] table.
                        @needs_class_table = 1
                        fmt = fmt + "%s"
                        arg_exprs.push("sp_class_to_s(" + compile_expr(inner) + ")")
                      elsif it == "encoding"
                        fmt = fmt + "%s"
                        arg_exprs.push("sp_encoding_name(" + compile_expr(inner) + ")")
                      elsif it == "symbol"
 # Symbol values carry the sp_sym int id;
 # interpolation must render the registered
 # name, mirroring Symbol#to_s. Without this
 # arm the default int path printed the raw
 # id. Issue #633.
                        fmt = fmt + "%s"
                        arg_exprs.push("sp_sym_to_s(" + compile_expr(inner) + ")")
                      elsif it == "exception"
 # `"#{e}"` on an sp_Exception * implicitly calls
 # to_s, which returns the message. Without this
 # arm the default int path printed the pointer as
 # a long long.
                        fmt = fmt + "%s"
                        arg_exprs.push("sp_exc_message(" + compile_expr(inner) + ")")
                      else
                        fmt = fmt + "%lld"
                        arg_exprs.push("(long long)" + compile_expr(inner))
                      end
                    end
                  end
                end
              end
            end
          end
        end
      end
    }
    result = "sp_sprintf(\"" + fmt + "\""
    j = 0
    while j < arg_exprs.length
      result = result + ", " + arg_exprs[j]
      j = j + 1
    end
    result + ")"
  end

  def escape_c_format(s)
    result = ""
    i = 0
    while i < s.length
      ch = s[i]
      if ch == "%"
        result = result + "%%"
      else
        if ch == bsl
          result = result + bsl + bsl
        else
          if ch == "\""
            result = result + bsl + "\""
          else
            if ch == 10.chr
              result = result + bsl_n
            else
              if ch == 9.chr
                result = result + bsl + "t"
              else
                result = result + ch
              end
            end
          end
        end
      end
      i = i + 1
    end
    result
  end

 # True if `t` is a GC-allocated pointer that could be swept by
 # sp_gc_collect if held only as a C-stack temp when the collector
 # runs mid-expression.
  def type_needs_transient_root(t)
    if t == ""
      return 0
    end
    if is_nullable_type(t) == 1
      t = base_type(t)
    end
    if value_type_needs_gc_scan(t) == 1
      return 1
    end
    if t == "string" || t == "mutable_str"
      return 1
    end
    if t == "int_array" || t == "str_array" || t == "float_array" || t == "sym_array"
      return 1
    end
    if t == "str_int_hash" || t == "str_str_hash" || t == "int_str_hash" || t == "sym_int_hash" || t == "sym_str_hash"
      return 1
    end
    if t == "str_poly_hash" || t == "sym_poly_hash"
      return 1
    end
    if is_ptr_array_type(t) == 1
      return 1
    end
    if is_obj_type(t) == 1
      return type_is_pointer(t)
    end
    if is_tuple_type(t) == 1
      return 1
    end
    if t == "stringio" || t == "fiber" || t == "bigint" || t == "lambda" || t == "poly_array"
      return 1
    end
    0
  end

 # Compile `nid`, and if it's a call expression whose result is a
 # GC-allocated pointer, bind that result to a rooted temp variable
 # so a subsequent mid-expression sp_gc_collect cannot sweep it.
 # For non-call expressions (locals, ivars, literals) rooting is
 # either already in place or unnecessary.
  def compile_expr_gc_rooted(nid)
    val = compile_expr(nid)
    if nid < 0
      return val
    end
    if @nd_type[nid] != "CallNode"
      return val
    end
    t = infer_type(nid)
    if type_needs_transient_root(t) == 0
      return val
    end
    @needs_gc = 1
    tmp = new_temp
    emit("  " + c_type(t) + " " + tmp + " = " + val + ";")
    emit_gc_root_for_expr(tmp, t)
    tmp
  end

  def compile_arg0(nid)
    args_id = @nd_arguments[nid]
    if args_id >= 0
      arg_ids = get_args(args_id)
      if arg_ids.length > 0
        return compile_expr(arg_ids[0])
      end
    end
    "0"
  end

 # Returns 1 if `nid` is a CallNode whose receiver AND first argument
 # are both ArrayNode literals (`[...]` or `%i[...]` / `%w[...]`).
 # Used by the int_array-vs-sym_array equality guard so that
 # `[0,0,0] == %i[a a a]` short-circuits to FALSE without disturbing
 # the widened-element-type case where the static type comes from a
 # mutated local (issue #555).
  def both_array_literals?(nid)
    recv = @nd_receiver[nid]
    if recv < 0
      return 0
    end
    args_id = @nd_arguments[nid]
    if args_id < 0
      return 0
    end
    arg_ids = get_args(args_id)
    if arg_ids.length == 0
      return 0
    end
    if @nd_type[recv] != "ArrayNode"
      return 0
    end
    if @nd_type[arg_ids[0]] != "ArrayNode"
      return 0
    end
    1
  end

 # Compile the first argument expecting a symbol-typed key for
 # sym_*_hash lookups. A SymbolNode literal already compiles to a
 # raw `SPS_<name>` (sp_sym); a poly-typed argument (e.g. an
 # `is_a?(Symbol)`-narrowed local that still carries the sp_RbVal
 # tag at C-level) needs `.v.i` extracted so the call matches the
 # `sp_sym` (long-int) parameter signature.
  def compile_arg0_as_sym(nid)
    args_id = @nd_arguments[nid]
    if args_id >= 0
      arg_ids = get_args(args_id)
      if arg_ids.length > 0
        a0 = arg_ids[0]
        e = compile_expr(a0)
        at = infer_type(a0)
        if at == "poly"
          return "(sp_sym)(" + e + ").v.i"
        end
        return e
      end
    end
    "0"
  end

  def compile_system_call(nid)
    @needs_system = 1
    args_id = @nd_arguments[nid]
    arg_ids = []
    if args_id >= 0
      arg_ids = get_args(args_id)
    end
    if arg_ids.length <= 1
      return "({ fflush(NULL); sp_last_status = system(" + compile_arg0(nid) + "); sp_last_status == 0; })"
    end

    argv = ""
    i = 0
    while i < arg_ids.length
      if i > 0
        argv = argv + ", "
      end
      argv = argv + compile_expr(arg_ids[i])
      i += 1
    end
    argv = argv + ", NULL"
    "sp_system_args(" + arg_ids.length.to_s + ", (const char*[]){" + argv + "})"
  end

 # Emit `lv_<bp> = <rhs>;` honoring promote-mode widening: if the
 # block param's outer scope slot is bigint while the underlying
 # iterator value is mrb_int, wrap through sp_bigint_new_int.
 # Returns nothing — used for inline assignments inside emit_*
 # block helpers where the LV is the function-level slot (not a
 # block-scoped fresh decl).
  def emit_block_lv_assign_int(bp, rhs_int_expr)
    slot_t = find_var_type(bp)
    if slot_t == "bigint"
      @needs_bigint = 1
      emit("    lv_" + bp + " = sp_bigint_new_int(" + rhs_int_expr + ");")
    else
      emit("    lv_" + bp + " = " + rhs_int_expr + ";")
    end
  end

 # Like compile_arg0, but unboxes the result to mrb_int when the
 # argument's static type is poly. Use at call sites that pass the
 # arg directly to a C function expecting `mrb_int` (sp_IntArray_get,
 # sp_IntArray_push integer-element variants, runtime helpers that
 # take an int index, etc.). Without unboxing, gcc rejects passing
 # `sp_RbVal` to a `mrb_int` parameter.
  def compile_arg0_as_int(nid)
    args_id = @nd_arguments[nid]
    if args_id >= 0
      arg_ids = get_args(args_id)
      if arg_ids.length > 0
        ce = compile_expr(arg_ids[0])
 # `--int-overflow=promote` rewrites every int local to bigint;
 # array indices, sp_*_get / _set, and other int-expecting C
 # helpers still need an `mrb_int` here. Unbox through
 # sp_bigint_to_int so the index is a native int even when the
 # source expression came from a promoted slot. Cover both
 # direct-type (infer_type) and stale-cache cases (a method call
 # returning bigint that infer_type still reports as "int").
        at_a0i = infer_type(arg_ids[0])
        if at_a0i == "bigint" || expr_emit_is_bigint(arg_ids[0]) == 1
          @needs_bigint = 1
          return "sp_bigint_to_int((sp_Bigint *)" + ce + ")"
        end
        if at_a0i == "poly"
          return "(" + ce + ").v.i"
        end
        return ce
      end
    end
    "0"
  end

 # Compile `nid` as an mrb_int expression, unboxing the result via
 # `.v.i` when the static type is poly. Mirrors compile_arg0_as_int
 # for arbitrary expression positions (not just the first arg). Use
 # at int-expecting C call sites whose source-level operand may now
 # be poly because of nullable widenings like #532's `String#index`.
  def compile_expr_as_int(nid)
    ce = compile_expr(nid)
    if infer_type(nid) == "poly"
      return "(" + ce + ").v.i"
    end
 # `--int-overflow=promote` widens int slots to bigint; many
 # int-expecting C call sites (array indices, hash keys, range
 # endpoints, ...) still need a raw mrb_int. Mirror compile_arg0
 # _as_int's bigint arm so promote mode flows the unbox through
 # the broader expr path.
    if infer_type(nid) == "bigint"
      @needs_bigint = 1
      return "sp_bigint_to_int((sp_Bigint *)" + ce + ")"
    end
    ce
  end

 # Like compile_arg0, but coerces a poly arg to mrb_float through
 # sp_poly_to_f, which dispatches on the runtime tag (INT->cast,
 # FLT->v.f, etc.). Use at call sites that pass the arg directly to
 # a C function expecting `mrb_float` (sp_FloatArray_sum's init,
 # etc.). Without coercion, gcc rejects passing `sp_RbVal` to a
 # `mrb_float` parameter; a tag-blind `(arg).v.f` would also misread
 # the union for INT-tagged poly values.
  def compile_arg0_as_float(nid)
    args_id = @nd_arguments[nid]
    if args_id >= 0
      arg_ids = get_args(args_id)
      if arg_ids.length > 0
        ce = compile_expr(arg_ids[0])
        at_a0f = infer_type(arg_ids[0])
        if at_a0f == "poly"
          return "sp_poly_to_f(" + ce + ")"
        end
 # `--int-overflow=promote` widens int to sp_Bigint *; a float
 # context (FFI :float arg, Math.sin operand, etc.) needs the
 # mrb_float scalar. Unbox via sp_bigint_to_int and let the
 # implicit int -> double conversion finish the cast.
        if at_a0f == "bigint" || expr_emit_is_bigint(arg_ids[0]) == 1
          @needs_bigint = 1
          return "(mrb_float)sp_bigint_to_int((sp_Bigint *)" + ce + ")"
        end
        return ce
      end
    end
    "0"
  end

 # Like compile_arg0, but converts symbol-typed arg to const char *
 # (sp_sym_to_s wrap). Use for callsites that need a string key.
  def compile_str_arg0(nid)
    args_id = @nd_arguments[nid]
    if args_id >= 0
      arg_ids = get_args(args_id)
      if arg_ids.length > 0
        return compile_expr_as_string(arg_ids[0])
      end
    end
    "0"
  end


 # --- Fiber capture helpers ---

  def fiber_capture_index(name)
    i = 0
    while i < @fiber_captures.length
      if @fiber_captures[i] == name
        return i
      end
      i = i + 1
    end
    -1
  end

  def proc_capture_index(name)
    i = 0
    while i < @proc_captures.length
      if @proc_captures[i] == name
        return i
      end
      i = i + 1
    end
    -1
  end

  def heap_promoted_cell(name)
    i = 0
    while i < @heap_promoted_names.length
      if @heap_promoted_names[i] == name
        return @heap_promoted_cells[i]
      end
      i = i + 1
    end
    ""
  end

  def fiber_var_ref(name)
    if @in_fiber_body == 1
      if fiber_capture_index(name) >= 0
        return "(*_cap->" + name + ")"
      end
    end
    if @in_proc_body == 1
      if proc_capture_index(name) >= 0
        return "(*_cap->" + name + ")"
      end
 # Inside a proc body, captures only come via _cap->. Heap-promoted
 # cells from outer functions are not visible here.
      return "lv_" + name
    end
 # /: when inside an inlined yield-method body,
 # local references go through this hot path. The inliner stashes
 # its rename suffix in @inline_rename_map_from / _to so a CallNode
 # whose recv falls through to compile_expr (instead of
 # compile_expr_remap) still picks up the renamed local.
    if @inline_rename_map_from != nil
      ki = 0
      while ki < @inline_rename_map_from.length
        if @inline_rename_map_from[ki] == name
          return "lv_" + @inline_rename_map_to[ki]
        end
        ki = ki + 1
      end
    end
    cell = heap_promoted_cell(name)
    if cell != "" && find_var_type(name) != ""
      return "(*" + cell + ")"
    end
    "lv_" + name
  end


 # Detect whether a Fiber.new block body references `self` — directly
 # (`SelfNode`), via `@ivar` reads/writes, or via a no-receiver method
 # call inside a class body. Used by `compile_fiber_new` to decide
 # whether to thread an explicit `self` capture through the fiber's
 # `_cap` struct so the body's emitted C can resolve `self->iv_X` and
 # `sp_<Class>_<method>(self)` call sites without the surrounding
 # method's `self` parameter.
  def fiber_body_uses_self(nid)
    if nid < 0
      return 0
    end
    t = @nd_type[nid]
    if t == "SelfNode"
      return 1
    end
    if t == "InstanceVariableReadNode" || t == "InstanceVariableWriteNode"
      return 1
    end
    if t == "InstanceVariableOperatorWriteNode" || t == "InstanceVariableTargetNode"
      return 1
    end
    if t == "InstanceVariableAndWriteNode" || t == "InstanceVariableOrWriteNode"
      return 1
    end
 # Stop at nested lambda/fiber boundaries (their own body captures self separately)
    if t == "LambdaNode"
      return 0
    end
    if t == "CallNode"
      mn = @nd_name[nid]
      if mn == "new"
        rv = @nd_receiver[nid]
        if rv >= 0 && constructor_class_name(rv) == "Fiber"
          return 0
        end
      end
 # Bare (no receiver) call inside class context implicitly uses self
      if @nd_receiver[nid] < 0 && @current_class_idx >= 0
        return 1
      end
    end
    if @nd_body[nid] >= 0
      if fiber_body_uses_self(@nd_body[nid]) == 1
        return 1
      end
    end
    if @nd_receiver[nid] >= 0
      if fiber_body_uses_self(@nd_receiver[nid]) == 1
        return 1
      end
    end
    if @nd_expression[nid] >= 0
      if fiber_body_uses_self(@nd_expression[nid]) == 1
        return 1
      end
    end
    if @nd_predicate[nid] >= 0
      if fiber_body_uses_self(@nd_predicate[nid]) == 1
        return 1
      end
    end
    if @nd_subsequent[nid] >= 0
      if fiber_body_uses_self(@nd_subsequent[nid]) == 1
        return 1
      end
    end
    if @nd_else_clause[nid] >= 0
      if fiber_body_uses_self(@nd_else_clause[nid]) == 1
        return 1
      end
    end
    if @nd_arguments[nid] >= 0
      if fiber_body_uses_self(@nd_arguments[nid]) == 1
        return 1
      end
    end
    if @nd_rescue_clause[nid] >= 0
      if fiber_body_uses_self(@nd_rescue_clause[nid]) == 1
        return 1
      end
    end
    if @nd_ensure_clause[nid] >= 0
      if fiber_body_uses_self(@nd_ensure_clause[nid]) == 1
        return 1
      end
    end
    stmts_list = parse_id_list(@nd_stmts[nid])
    k = 0
    while k < stmts_list.length
      if fiber_body_uses_self(stmts_list[k]) == 1
        return 1
      end
      k = k + 1
    end
    args_list = parse_id_list(@nd_args[nid])
    k = 0
    while k < args_list.length
      if fiber_body_uses_self(args_list[k]) == 1
        return 1
      end
      k = k + 1
    end
    conds_list = parse_id_list(@nd_conditions[nid])
    k = 0
    while k < conds_list.length
      if fiber_body_uses_self(conds_list[k]) == 1
        return 1
      end
      k = k + 1
    end
    elems_list = parse_id_list(@nd_elements[nid])
    k = 0
    while k < elems_list.length
      if fiber_body_uses_self(elems_list[k]) == 1
        return 1
      end
      k = k + 1
    end
    blk = @nd_block[nid]
    if blk >= 0
      if @nd_body[blk] >= 0
        if fiber_body_uses_self(@nd_body[blk]) == 1
          return 1
        end
      end
    end
    0
  end

  def scan_fiber_free_vars(nid, params, locals, free_vars, free_var_types)
    if nid < 0
      return
    end
    t = @nd_type[nid]
    if t == "LocalVariableReadNode" || t == "LocalVariableTargetNode"
      vn = @nd_name[nid]
      if not_in(vn, params) == 1 && not_in(vn, locals) == 1 && not_in(vn, free_vars) == 1
        vt = find_var_type(vn)
        if vt != ""
          free_vars.push(vn)
          free_var_types.push(vt)
        end
      end
      return
    end
    if t == "LocalVariableWriteNode"
      vn = @nd_name[nid]
      if not_in(vn, params) == 1 && not_in(vn, locals) == 1 && not_in(vn, free_vars) == 1
        vt = find_var_type(vn)
        if vt != ""
          free_vars.push(vn)
          free_var_types.push(vt)
        end
      end
 # Also scan the expression
      scan_fiber_free_vars(@nd_expression[nid], params, locals, free_vars, free_var_types)
      return
    end
    if t == "LocalVariableOperatorWriteNode"
      vn = @nd_name[nid]
      if not_in(vn, params) == 1 && not_in(vn, locals) == 1 && not_in(vn, free_vars) == 1
        vt = find_var_type(vn)
        if vt != ""
          free_vars.push(vn)
          free_var_types.push(vt)
        end
      end
      scan_fiber_free_vars(@nd_expression[nid], params, locals, free_vars, free_var_types)
      return
    end
 # Stop at nested lambda/fiber boundaries (they handle their own captures)
    if t == "LambdaNode"
      return
    end
    if t == "CallNode"
 # Stop at nested Fiber.new block bodies
      mn = @nd_name[nid]
      if mn == "new"
        rv = @nd_receiver[nid]
        if rv >= 0 && constructor_class_name(rv) == "Fiber"
          return
        end
      end
    end
 # Recurse into children (follow scan_locals_children pattern)
    if @nd_body[nid] >= 0
      scan_fiber_free_vars(@nd_body[nid], params, locals, free_vars, free_var_types)
    end
    if @nd_receiver[nid] >= 0
      scan_fiber_free_vars(@nd_receiver[nid], params, locals, free_vars, free_var_types)
    end
    if @nd_expression[nid] >= 0
      scan_fiber_free_vars(@nd_expression[nid], params, locals, free_vars, free_var_types)
    end
    if @nd_predicate[nid] >= 0
      scan_fiber_free_vars(@nd_predicate[nid], params, locals, free_vars, free_var_types)
    end
    if @nd_subsequent[nid] >= 0
      scan_fiber_free_vars(@nd_subsequent[nid], params, locals, free_vars, free_var_types)
    end
    if @nd_else_clause[nid] >= 0
      scan_fiber_free_vars(@nd_else_clause[nid], params, locals, free_vars, free_var_types)
    end
    if @nd_arguments[nid] >= 0
      scan_fiber_free_vars(@nd_arguments[nid], params, locals, free_vars, free_var_types)
    end
    if @nd_rescue_clause[nid] >= 0
      scan_fiber_free_vars(@nd_rescue_clause[nid], params, locals, free_vars, free_var_types)
    end
    if @nd_ensure_clause[nid] >= 0
      scan_fiber_free_vars(@nd_ensure_clause[nid], params, locals, free_vars, free_var_types)
    end
 # Stmts list
    stmts_list = parse_id_list(@nd_stmts[nid])
    k = 0
    while k < stmts_list.length
      scan_fiber_free_vars(stmts_list[k], params, locals, free_vars, free_var_types)
      k = k + 1
    end
 # Args list
    args_list = parse_id_list(@nd_args[nid])
    k = 0
    while k < args_list.length
      scan_fiber_free_vars(args_list[k], params, locals, free_vars, free_var_types)
      k = k + 1
    end
 # Conditions list
    conds_list = parse_id_list(@nd_conditions[nid])
    k = 0
    while k < conds_list.length
      scan_fiber_free_vars(conds_list[k], params, locals, free_vars, free_var_types)
      k = k + 1
    end
 # Elements list
    elems_list = parse_id_list(@nd_elements[nid])
    k = 0
    while k < elems_list.length
      scan_fiber_free_vars(elems_list[k], params, locals, free_vars, free_var_types)
      k = k + 1
    end
 # InterpolatedStringNode parts
    parts_list = parse_id_list(@nd_parts[nid])
    k = 0
    while k < parts_list.length
      scan_fiber_free_vars(parts_list[k], params, locals, free_vars, free_var_types)
      k = k + 1
    end
 # Block body (for non-Fiber.new blocks)
    blk = @nd_block[nid]
    if blk >= 0
      if @nd_body[blk] >= 0
        scan_fiber_free_vars(@nd_body[blk], params, locals, free_vars, free_var_types)
      end
    end
  end

  def compile_fiber_new(nid)
    @needs_fiber = 1
    blk = @nd_block[nid]
    if blk < 0
      return "NULL"
    end
 # Get block parameter name
    bp = ""
    bparams = @nd_parameters[blk]
    if bparams >= 0
 # BlockParametersNode → inner ParametersNode
      inner = @nd_parameters[bparams]
      if inner >= 0
        reqs = parse_id_list(@nd_requireds[inner])
        if reqs.length > 0
          bp = @nd_name[reqs[0]]
        end
      end
      if bp == ""
 # Try direct requireds (in case it's ParametersNode directly)
        reqs = parse_id_list(@nd_requireds[bparams])
        if reqs.length > 0
          bp = @nd_name[reqs[0]]
        end
      end
    end

    body = @nd_body[blk]
 # Read precomputed body locals (analyze ran scan_locals with
 # exactly this exclusion: the block's syntactic required params).
    all_names = "".split(",", -1)
    all_types = "".split(",", -1)
    all_plist = "".split(",", -1)
    if bp != ""
      all_plist.push(bp)
    end
    if body >= 0
      sn_b = @nd_scope_names[body]
      if sn_b != ""
        all_names = sn_b.split("|", -1)
        all_types = @nd_scope_types[body].split("|", -1)
      end
    end

 # Split into captures (exist in outer scope) vs true locals
    free_vars = "".split(",", -1)
    free_var_types = "".split(",", -1)
    local_names = "".split(",", -1)
    local_types = "".split(",", -1)
    k = 0
    while k < all_names.length
      outer_type = find_var_type(all_names[k])
      if outer_type != ""
 # Variable exists in outer scope → capture
        free_vars.push(all_names[k])
        free_var_types.push(outer_type)
      else
 # True local variable
        local_names.push(all_names[k])
        local_types.push(all_types[k])
      end
      k = k + 1
    end

 # Also scan for read-only captures (variables read but not written in body)
    if body >= 0
      scan_fiber_free_vars(body, all_plist, all_names, free_vars, free_var_types)
    end

 # Capture `self` when the body references the enclosing instance
 # (explicit `self`, ivar reads/writes, or no-receiver method calls
 # that resolve to `self.<m>`). Without this, `_fiber_body_N`'s
 # emitted body references a `self` that isn't a parameter and won't
 # compile. Only add the capture inside an instance-method context;
 # value-type classes pass `self` by value, and that path needs a
 # different capture shape we don't generate yet.
    self_captured = 0
    if @current_class_idx >= 0 && @cls_is_value_type[@current_class_idx] != 1
      if body >= 0 && fiber_body_uses_self(body) == 1
        self_type = "obj_" + @cls_names[@current_class_idx]
        free_vars.push("self")
        free_var_types.push(self_type)
        self_captured = 1
      end
    end

    fid = @fiber_counter
    @fiber_counter = @fiber_counter + 1
    fname = "_fiber_body_" + fid.to_s
    cap_name = "_fiber_cap_" + fid.to_s

 # Build capture struct typedef if needed
    cap_typedef = ""
    if free_vars.length > 0
      cap_typedef = "typedef struct {"
      k = 0
      while k < free_vars.length
        cap_typedef = cap_typedef + " " + c_type(free_var_types[k]) + " *" + free_vars[k] + ";"
        k = k + 1
      end
      cap_typedef = cap_typedef + " } " + cap_name + ";" + 10.chr
    end

 # Compile fiber body function
    fbody = "static void " + fname + "(sp_Fiber *_fb) {" + 10.chr
    if free_vars.length > 0
      fbody = fbody + "  " + cap_name + " *_cap = (" + cap_name + "*)_fb->user_data;" + 10.chr
    end
    if bp != ""
      fbody = fbody + "  sp_RbVal lv_" + bp + " = _fb->resumed_value;" + 10.chr
    end

 # Save/restore compiler state
    saved_out = @out_lines
    saved_indent = @indent
    saved_in_fiber_body = @in_fiber_body
    saved_fiber_captures = @fiber_captures
    saved_fiber_capture_types = @fiber_capture_types
    saved_hp_names_len = @heap_promoted_names.length
    saved_hp_cells_len = @heap_promoted_cells.length
    saved_self_override = @self_override
    @out_lines = "".split(",", -1)
    @indent = 1
    @in_fiber_body = 1
    @fiber_captures = free_vars
    @fiber_capture_types = free_var_types
    if self_captured == 1
      @self_override = "(*_cap->self)"
    end

    push_scope
    if bp != ""
      declare_var(bp, "poly")
    end
    if body >= 0
 # Declare only true locals (not captured vars)
      lk = 0
      while lk < local_names.length
        declare_var(local_names[lk], local_types[lk])
        emit("  " + c_type(local_types[lk]) + " lv_" + local_names[lk] + " = " + c_default_val(local_types[lk]) + ";")
        lk = lk + 1
      end

      stmts = get_stmts(body)
      if stmts.length > 0
        i = 0
        while i < stmts.length - 1
          compile_stmt(stmts[i])
          i = i + 1
        end
        last = stmts.last
 # Compile last as statement for side effects, then capture value
        last_type = infer_type(last)
        if last_type == "void"
 # Side-effect-only stmt (puts, print, etc.) — compile_expr would drop the call
          compile_stmt(last)
          emit("  _fb->yielded_value = sp_box_nil();")
        else
          last_t_check = @nd_type[last]
          if last_t_check == "LocalVariableWriteNode" || last_t_check == "LocalVariableOperatorWriteNode" ||
             last_t_check == "InstanceVariableWriteNode" || last_t_check == "InstanceVariableOperatorWriteNode" ||
             last_t_check == "InstanceVariableOrWriteNode" || last_t_check == "InstanceVariableAndWriteNode"
            compile_stmt(last)
            emit("  _fb->yielded_value = sp_box_nil();")
          else
            last_val = compile_expr(last)
            emit("  _fb->yielded_value = " + box_val_to_poly(last_val, last_type) + ";")
          end
        end
      end
    end
    pop_scope

    fbody = fbody + @out_lines.join(10.chr) + 10.chr
    fbody = fbody + "}" + 10.chr
    @fiber_funcs << cap_typedef
    @fiber_funcs << fbody

    @out_lines = saved_out
    @indent = saved_indent
    @in_fiber_body = saved_in_fiber_body
    @fiber_captures = saved_fiber_captures
    @fiber_capture_types = saved_fiber_capture_types
    @self_override = saved_self_override
 # Restore heap promoted lists to saved length
    while @heap_promoted_names.length > saved_hp_names_len
      @heap_promoted_names.pop
    end
    while @heap_promoted_cells.length > saved_hp_cells_len
      @heap_promoted_cells.pop
    end

 # If no captures, return simple expression
    if free_vars.length == 0
      return "sp_Fiber_new(" + fname + ")"
    end

 # Heap-promote captured variables (allocate cells if not already promoted).
 # Track this fiber's cell-per-capture in a local map so a cross-method
 # `self` capture (different C function each time) doesn't accidentally
 # reuse a stale `_hcell_self_<n>` from a sibling fiber site that lives
 # in a different C scope.
    local_cells = "".split(",", -1)
    k = 0
    while k < free_vars.length
      vn = free_vars[k]
      cell = ""
      if vn == "self"
 # `self` resolves to the enclosing C function's parameter, which
 # differs per method (e.g. `sp_X_new`'s `self` and `sp_X_initialize`'s
 # `self` are distinct C variables). Skip the persistent
 # @heap_promoted_names lookup — its cells live in another scope.
        cell = "_hcell_self_" + fid.to_s
        ct = c_type(free_var_types[k])
        emit("  " + ct + " *" + cell + " = (" + ct + "*)sp_gc_alloc(sizeof(" + ct + "), NULL, NULL);")
        emit("  *" + cell + " = self;")
      else
        already_promoted = 0
 # Check outer scope heap promotions
        ci = 0
        while ci < @heap_promoted_names.length
          if @heap_promoted_names[ci] == vn
            already_promoted = 1
            cell = @heap_promoted_cells[ci]
          end
          ci = ci + 1
        end
 # Check if variable is already a heap pointer from enclosing fiber capture
        if already_promoted == 0 && @in_fiber_body == 1 && fiber_capture_index(vn) >= 0
 # Reuse the enclosing fiber's capture pointer (_cap->vn is already a heap cell)
          cell = "_cap->" + vn
          @heap_promoted_names.push(vn)
          @heap_promoted_cells.push(cell)
          already_promoted = 1
        end
        if already_promoted == 0
          cell = "_hcell_" + vn + "_" + fid.to_s
          ct = c_type(free_var_types[k])
          emit("  " + ct + " *" + cell + " = (" + ct + "*)sp_gc_alloc(sizeof(" + ct + "), NULL, NULL);")
          emit("  *" + cell + " = " + fiber_var_ref(vn) + ";")
          @heap_promoted_names.push(vn)
          @heap_promoted_cells.push(cell)
        end
      end
      local_cells.push(cell)
      k = k + 1
    end

 # Heap-allocate capture struct
    tmp_fb = "_tmpfb_" + fid.to_s
    cap_ptr = "_cap_ptr_" + fid.to_s
    emit("  " + cap_name + " *" + cap_ptr + " = (" + cap_name + "*)sp_gc_alloc(sizeof(" + cap_name + "), NULL, NULL);")
    k = 0
    while k < free_vars.length
      vn = free_vars[k]
      cell = local_cells[k]
      emit("  " + cap_ptr + "->" + vn + " = " + cell + ";")
      k = k + 1
    end
    emit("  sp_Fiber *" + tmp_fb + " = sp_Fiber_new(" + fname + ");")
    emit("  " + tmp_fb + "->user_data = " + cap_ptr + ";")
    tmp_fb
  end

 # Returns the C expression for a CallNode. Symmetric with
 # `infer_call_type` (which returns the call's C type) — see the
 # docstring there for the maintenance rule on adding new shapes.
 # Branch order in this function mirrors infer_call_type's order so
 # the two stay diff-able.
  def compile_call_expr(nid)
    mname = @nd_name[nid]
    recv = @nd_receiver[nid]

 # Safe navigation `recv&.method`: short-circuit to nil when recv
 # is nil. The result type is nullable (T? where T is the method's
 # normal return type). Three cases:
 # - Statically-nil recv (`nil&.foo`): emit a nil-valued constant
 #   matching the call's inferred return type. No method dispatch,
 #   no warning.
 # - Dynamically-nullable recv: emit `(recv ? method_call : nil)`.
 #   Defer to the regular dispatch via the existing pipeline for
 #   the non-nil branch.
 # - Non-nullable recv: `&.` is equivalent to `.` here; fall through.
    if recv >= 0 && @nd_callop[nid] == "&."
      recv_t_sn = infer_type(recv)
      if @nd_type[recv] == "NilNode" || recv_t_sn == "nil"
 # Statically nil — entire expression is nil. Pick a C constant
 # appropriate for the inferred result type. infer_type already
 # widens the call's return to "nil" via the matching analyze arm.
        ret_t_sn = infer_type(nid)
        return c_default_val(ret_t_sn)
      end
      if is_nullable_pointer_type(recv_t_sn) == 1 || is_scalar_nullable_type(recv_t_sn) == 1
        recv_tmp_sn = new_temp
        recv_c_sn = compile_expr(recv)
        ret_t_sn = infer_type(nid)
        nil_v_sn = c_default_val(ret_t_sn)
        recv_ct_sn = c_type(recv_t_sn)
 # Temporarily strip the `&.` so the nested compile_call_expr
 # call for the non-nil branch dispatches as a regular method
 # call (`.`). Restore afterwards. The runtime check below
 # ensures the nested dispatch only fires when recv is non-nil.
        saved_callop_sn = @nd_callop[nid]
        @nd_callop[nid] = ""
 # Narrow recv's type to the non-nullable base so the nested
 # dispatch picks the right arm (e.g. str_str_hash, not str_str_hash?).
        narrow_pushed_sn = 0
        if @nd_type[recv] == "LocalVariableReadNode" && is_nullable_type(recv_t_sn) == 1
          push_type_narrow(@nd_name[recv], base_type(recv_t_sn))
          narrow_pushed_sn = 1
        end
        call_c_sn = compile_call_expr(nid)
        if narrow_pushed_sn == 1
          pop_type_narrow
        end
        @nd_callop[nid] = saved_callop_sn
        nil_check_sn = is_scalar_nullable_type(recv_t_sn) == 1 ? "sp_int_is_nil(" + recv_tmp_sn + ")" : "(" + recv_tmp_sn + " == NULL)"
        return "({ " + recv_ct_sn + " " + recv_tmp_sn + " = " + recv_c_sn + "; " + nil_check_sn + " ? " + nil_v_sn + " : " + call_c_sn + "; })"
      end
 # Non-nullable recv — `&.` is equivalent to `.`. Fall through.
    end

 # `Regexp.new(<arg>)` / `Regexp.compile(<arg>)` evaluates to a
 # `mrb_regexp_pattern *`. regex_pat_c_expr already maps it to
 # `sp_re_pat_<i>` (literal source) or `sp_re_dyn_<i>(<arg>)`
 # (dynamic source), so a regexp-typed local can store the
 # pointer directly. Without this arm the call fell through to
 # the unresolved-call fallback (silently `0`), which the
 # @local_regex_idx side-channel papered over for single-writer
 # locals but couldn't repair across an if/else union. Issue #609.
    if regexp_new_call_arg_id(nid) >= 0
      rp_new = regex_pat_c_expr(nid)
      if rp_new != ""
        return rp_new
      end
    end

 # Return CRuby's first-call default ("DEFAULT") since Spinel does
 # not track per-signal state. Covers both implicit-self and
 # explicit Signal / ::Signal receivers via trap_call_is_signal_stub.
    if mname == "trap" && trap_call_is_signal_stub(nid) == 1
      return "SPL(\"DEFAULT\")"
    end

 # `recv.send(:method_name, args...)` with a SymbolNode method
 # name reduces to the direct call -- temporarily mutate the
 # outer CallNode's @nd_name and the inner ArgumentsNode's
 # @nd_args so the dispatch sees the actual method call
 # signature, then restore. Issue #555 case 12.
 # `public_send` is identical to `send` for spinel (visibility is
 # not modeled). Issue #735.
    if (mname == "send" || mname == "public_send" || mname == "__send__") && recv >= 0
      args_id_send = @nd_arguments[nid]
      if args_id_send >= 0
        aa_send = get_args(args_id_send)
        if aa_send.length >= 1 && @nd_type[aa_send[0]] == "SymbolNode"
          sym_name_send = @nd_content[aa_send[0]]
          if sym_name_send != "" && sym_name_send != "send" && sym_name_send != "public_send" && sym_name_send != "__send__"
            saved_name_send = @nd_name[nid]
            saved_args_str = @nd_args[args_id_send]
            new_args_str = ""
            ks = 1
            while ks < aa_send.length
              if new_args_str == ""
                new_args_str = aa_send[ks].to_s
              else
                new_args_str = new_args_str + "," + aa_send[ks].to_s
              end
              ks = ks + 1
            end
            @nd_name[nid] = sym_name_send
            @nd_args[args_id_send] = new_args_str
            result_send = compile_call_expr(nid)
            @nd_name[nid] = saved_name_send
            @nd_args[args_id_send] = saved_args_str
            return result_send
          end
        end
      end
    end

 # `Module.accessor.<method>` where the slot was resolved by
 # `resolve_module_singleton_accessors`. With a single constant
 # in the resolved set, inline the call directly. With two or
 # more, emit a sentinel-switch over the slot variable.
    if recv >= 0 && @nd_type[recv] == "CallNode"
      inner_recv = @nd_receiver[recv]
      inner_mname = @nd_name[recv]
      if inner_recv >= 0 && @nd_type[inner_recv] == "ConstantReadNode"
        mod_name = @nd_name[inner_recv]
        if module_name_exists(mod_name) == 1
          rconsts = module_acc_resolved(mod_name, inner_mname)
          if rconsts != "" && rconsts != "?"
            args_id = @nd_arguments[nid]
            cands = rconsts.split(";", -1)
 # scan_new_calls' module-dispatch widening has already
 # unified the candidates' per-arg ptypes, so any
 # candidate's ptypes table tells us the target types
 # here. Box each arg expression to match — an int arg
 # passed to a poly-widened param would otherwise emit
 # raw `mrb_int` into a `sp_RbVal` slot.
            target_ptypes = "".split(",", -1)
            cands.each { |cn_t|
              cci_t = find_class_idx(cn_t)
              if cci_t >= 0
                pall_t = @cls_cmeth_ptypes[cci_t].split("|", -1)
                cmnames_t = @cls_cmeth_names[cci_t].split(";", -1)
                cmidx_t = 0
                while cmidx_t < cmnames_t.length
                  if cmnames_t[cmidx_t] == mname && cmidx_t < pall_t.length
                    target_ptypes = pall_t[cmidx_t].split(",", -1)
                    cmidx_t = cmnames_t.length
                  end
                  cmidx_t = cmidx_t + 1
                end
              end
              if target_ptypes.length == 0 && module_name_exists(cn_t) == 1
                mfn_t = cn_t + "_cls_" + mname
                mi_t = find_method_idx(mfn_t)
                if mi_t >= 0
                  target_ptypes = @meth_param_types[mi_t].split(",", -1)
                end
              end
            }
            arg_strs = ""
            if args_id >= 0
              aargs = get_args(args_id)
              k = 0
              while k < aargs.length
                if k > 0
                  arg_strs = arg_strs + ", "
                end
                if k < target_ptypes.length && base_type(target_ptypes[k]) == "poly"
                  arg_strs = arg_strs + box_expr_to_poly(aargs[k])
                else
                  arg_strs = arg_strs + compile_expr(aargs[k])
                end
                k = k + 1
              end
            end
 # `.nil?` on a module-accessor slot resolved to one (or more)
 # class candidates: the call should ask whether the slot is
 # assigned, not dispatch a class method on the candidate
 # class. The slot's int sentinel is 0 when unassigned (no
 # module_sentinel maps to 0). Same shape for 0+ candidate
 # cases since both reduce to "is the slot set?".
            if mname == "nil?"
              return "(sp_module_" + mod_name + "_" + sanitize_name(inner_mname) + " == 0)"
            end
            if cands.length == 1
              return "sp_" + cands[0] + "_cls_" + sanitize_name(mname) + "(" + arg_strs + ")"
            end
 # Stage 2: sentinel switch. The slot stores the assigned
 # module's sentinel; we walk the candidate list and dispatch
 # the first match. The default tail must match the call's
 # return type — when widening pushed the candidates to a
 # poly return , a literal `0` would type-mismatch
 # the ternary's other arms. Use c_default_val of the unified
 # return type the type system has already computed for us.
            slot = "sp_module_" + mod_name + "_" + sanitize_name(inner_mname)
            ret_t_d = ""
            cands.each { |cn_d|
              rt_d = lookup_cls_meth_return(cn_d, mname)
              if rt_d != ""
                if ret_t_d == ""
                  ret_t_d = rt_d
                elsif ret_t_d != rt_d
                  ret_t_d = "poly"
                end
              end
            }
            ret_t_d = "int" if ret_t_d == ""
            default_tail = c_default_val(ret_t_d)
            if ret_t_d == "poly"
              @needs_rb_value = 1
              default_tail = "sp_box_nil()"
            end
            expr = default_tail
            ki = cands.length - 1
            while ki >= 0
              cn = cands[ki]
              call_c = "sp_" + cn + "_cls_" + sanitize_name(mname) + "(" + arg_strs + ")"
 # Box per-arm calls when the unified return is poly but
 # this candidate's specific return is something narrower.
              if ret_t_d == "poly"
                arm_rt = lookup_cls_meth_return(cn, mname)
                if arm_rt != "" && arm_rt != "poly"
                  call_c = box_value_to_poly(arm_rt, call_c)
                end
              end
              expr = "((" + slot + " == " + module_sentinel(cn).to_s + ") ? " + call_c + " : " + expr + ")"
              ki = ki - 1
            end
            return expr
          end
        end
      end
    end

 # `bm.call(args)` / `bm[args]` where bm is a Method instance —
 # lower to a function-pointer cast and an indirect call. The
 # bound function's C signature is
 # `(void *self, mrb_int...) -> mrb_int`. The receiver expression
 # is stashed in a temp first so a side-effecting receiver (e.g.
 # `factory().method(:foo).call(x)`) evaluates exactly once. .
    if (mname == "call" || mname == "[]") && recv >= 0
      if base_type(infer_type(recv)) == "obj_Method"
        rc = compile_expr(recv)
        bm_tmp = new_temp
        emit("  sp_Method *" + bm_tmp + " = " + rc + ";")
        args_id = @nd_arguments[nid]
        joined = ""
 # In promote mode all int slots widened to bigint, so the
 # uniform Method ABI's int args / int return become sp_Bigint*.
 # The fn_ptr is cast accordingly; downstream consumers expecting
 # mrb_int unbox via sp_bigint_to_int.
        bm_promote = (@int_overflow_mode == "promote") ? 1 : 0
        ret_ct_bm = bm_promote == 1 ? "sp_Bigint *" : "mrb_int"
        arg_ct_bm = bm_promote == 1 ? "sp_Bigint *" : "mrb_int"
        sig_args = "void *"
        if args_id >= 0
          aargs = get_args(args_id)
          k = 0
          while k < aargs.length
            arg_v_bm = compile_expr(aargs[k])
            at_bm = infer_type(aargs[k])
            if bm_promote == 1
              @needs_bigint = 1
              if base_type(at_bm) == "int"
                arg_v_bm = "sp_bigint_new_int(" + arg_v_bm + ")"
              end
            else
              if at_bm == "bigint"
                @needs_bigint = 1
                arg_v_bm = "sp_bigint_to_int((sp_Bigint *)" + arg_v_bm + ")"
              end
            end
            joined = joined + ", " + arg_v_bm
            sig_args = sig_args + ", " + arg_ct_bm
            k = k + 1
          end
        end
        return "((" + ret_ct_bm + " (*)(" + sig_args + "))(uintptr_t)" + bm_tmp + "->iv_fn_ptr)((void *)" + bm_tmp + "->iv_self_obj" + joined + ")"
      end
    end

 # `<obj>.method(:bar)` — bind to a non-self receiver. The
 # detect_method_taken_classes pass keeps the receiver class
 # heap-allocated so `<obj>` evaluates to a stable pointer that
 # the resulting Method can capture. Walks the inheritance chain
 # to point at the *defining* class's C symbol; if no ancestor
 # defines the method, falls back to a null fn_ptr. .
    if mname == "method" && recv >= 0
      args_id = @nd_arguments[nid]
      if args_id >= 0
        arg_ids = get_args(args_id)
        if arg_ids.length >= 1
          recv_t = infer_type(recv)
          if is_obj_type(recv_t) == 1
            mref = @nd_content[arg_ids[0]]
            if mref == ""
              mref = @nd_name[arg_ids[0]]
            end
            recv_cname = recv_t[4, recv_t.length - 4]
            owner_cname = find_defining_class_name(find_class_idx(recv_cname), mref)
            rc = compile_expr(recv)
            if owner_cname != ""
              return "sp_Method_new((sp_Method *)(" + rc + "), (mrb_int)(uintptr_t)&sp_" + owner_cname + "_" + sanitize_name(mref) + ")"
            else
              return "sp_Method_new((sp_Method *)(" + rc + "), (mrb_int)0)"
            end
          end
 # Built-in array `<arr>.method(:op)`: emit a trampoline
 # matching the Method dispatch ABI and bind. The receiver
 # heap-allocated buffer pointer plays the role of `iv_self_obj`
 # — sp_gc_mark dispatches via the GC header's scan field
 # set at the array's allocation, so the type lie at the C
 # level is GC-safe.
          mref_b = @nd_content[arg_ids[0]]
          if mref_b == ""
            mref_b = @nd_name[arg_ids[0]]
          end
          if builtin_array_method_supported(recv_t, mref_b) == 1
            emit_builtin_array_method_adapter(recv_t, mref_b)
            pfx_b = builtin_array_type_pfx(recv_t)
            adapter_name_b = "sp_" + pfx_b + "_" + sanitize_name(mref_b) + "_builtin_method_adapter"
            rc_b = compile_expr(recv)
            return "sp_Method_new((sp_Method *)(" + rc_b + "), (mrb_int)(uintptr_t)&" + adapter_name_b + ")"
          end
        end
      end
    end

 # Hoisted instance_eval block: emit a direct C call to the synthetic
 # file-scope function. The receiver is a local variable known to
 # carry a class instance (the rewriter checked this); pass it as the
 # typed `self` argument.
    if is_ieval_call_name(mname) == 1
      return compile_ieval_call_expr(nid)
    end

 # Fiber.new { block }
    if mname == "new" && recv >= 0
      if constructor_class_name(recv) == "Fiber"
        return compile_fiber_new(nid)
      end
    end
 # fiber.resume(val)
    if mname == "resume" && recv >= 0
      rt2 = base_type(infer_type(recv))
      if rt2 == "fiber"
        rc = compile_expr_gc_rooted(recv)
        args_id = @nd_arguments[nid]
        if args_id >= 0
          arg_ids = get_args(args_id)
          if arg_ids.length > 0
            return "sp_Fiber_resume((sp_Fiber *)(" + rc + "), " + box_expr_to_poly(arg_ids[0]) + ")"
          end
        end
        return "sp_Fiber_resume((sp_Fiber *)(" + rc + "), sp_box_nil())"
      end
    end
 # Fiber.yield(val)
    if mname == "yield" && recv >= 0
      if constructor_class_name(recv) == "Fiber"
        @needs_fiber = 1
        args_id = @nd_arguments[nid]
        if args_id >= 0
          arg_ids = get_args(args_id)
          if arg_ids.length > 0
            return "sp_Fiber_yield(" + box_expr_to_poly(arg_ids[0]) + ")"
          end
        end
        return "sp_Fiber_yield(sp_box_nil())"
      end
    end
 # fiber.alive?
    if mname == "alive?" && recv >= 0
      rt2 = base_type(infer_type(recv))
      if rt2 == "fiber"
        rc = compile_expr_gc_rooted(recv)
        return "sp_Fiber_alive((sp_Fiber *)(" + rc + "))"
      end
    end
 # fiber.transfer(val)
    if mname == "transfer" && recv >= 0
      rt2 = base_type(infer_type(recv))
      if rt2 == "fiber"
        rc = compile_expr_gc_rooted(recv)
        args_id = @nd_arguments[nid]
        if args_id >= 0
          arg_ids = get_args(args_id)
          if arg_ids.length > 0
            return "sp_Fiber_transfer((sp_Fiber *)(" + rc + "), " + box_expr_to_poly(arg_ids[0]) + ")"
          end
        end
        return "sp_Fiber_transfer((sp_Fiber *)(" + rc + "), sp_box_nil())"
      end
    end
 # Fiber.current
    if mname == "current" && recv >= 0
      if constructor_class_name(recv) == "Fiber"
        @needs_fiber = 1
        return "sp_fiber_current"
      end
    end
 # Fiber[:k] / Fiber.current[:k] — per-fiber storage read. Matches
 # MRI's Fiber[] indexing on the storage Hash; returns nil for
 # unset keys (also when the storage Hash hasn't been allocated
 # yet, which is the lazy-init lower bound).
    if mname == "[]" && recv >= 0
      fiber_recv = ""
      if constructor_class_name(recv) == "Fiber"
        @needs_fiber = 1
        fiber_recv = "sp_fiber_current"
      elsif base_type(infer_type(recv)) == "fiber"
        fiber_recv = "(sp_Fiber *)(" + compile_expr_gc_rooted(recv) + ")"
      end
      if fiber_recv != ""
        args_id = @nd_arguments[nid]
        if args_id >= 0
          arg_ids = get_args(args_id)
          if arg_ids.length == 1
            return "sp_Fiber_storage_get(" + fiber_recv + ", " + compile_expr(arg_ids[0]) + ")"
          end
        end
      end
    end
 # Fiber[:k] = v as an EXPRESSION (e.g. `x = (Fiber[:k] = 42)`).
 # The statement form lands in compile_mutating_call_stmt; here we
 # cover the expression-context use via a gcc statement-expression
 # so the assignment's value (the RHS) reaches the outer
 # assignment. Mirrors MRI's `(h[k]=v) => v` semantics.
    if mname == "[]=" && recv >= 0
      fiber_recv = ""
      if constructor_class_name(recv) == "Fiber"
        @needs_fiber = 1
        fiber_recv = "sp_fiber_current"
      elsif base_type(infer_type(recv)) == "fiber"
        fiber_recv = "(sp_Fiber *)(" + compile_expr_gc_rooted(recv) + ")"
      end
      if fiber_recv != ""
        args_id = @nd_arguments[nid]
        if args_id >= 0
          arg_ids = get_args(args_id)
          if arg_ids.length == 2
            vtmp = new_temp
            vexpr = box_expr_to_poly(arg_ids[1])
            return "({ sp_RbVal " + vtmp + " = " + vexpr + "; sp_Fiber_storage_set(" + fiber_recv + ", " + compile_expr(arg_ids[0]) + ", " + vtmp + "); " + vtmp + "; })"
          end
        end
      end
    end

 # Issue #868: Regexp accessors -- only the literal recv form is
 # supported at this stage (dynamic-pattern recvs would need a
 # runtime Regexp struct that carries source/options). For now,
 # literal /pat/.source returns the raw pattern string, .options
 # returns the engine flags packed per CRuby.
    if recv >= 0 && @nd_type[recv] == "RegularExpressionNode"
      if mname == "source"
        return c_string_literal(@nd_unescaped[recv])
      end
      if mname == "options"
 # Translate prism's nd_flags bits (4=IGNORECASE, 8=EXTENDED,
 # 16=MULTILINE) to CRuby's Regexp::* bit mask
 # (1=IGNORECASE, 2=EXTENDED, 4=MULTILINE).
        pf = @nd_flags[recv]
        opts = 0
        if (pf & 4) != 0
          opts = opts | 1
        end
        if (pf & 8) != 0
          opts = opts | 2
        end
        if (pf & 16) != 0
          opts = opts | 4
        end
        return opts.to_s + "LL"
      end
    end
 # regex.match? / regex.match / regex =~ str — receiver is the regex
 # (typically a constant referring to a /…/ literal). Dispatched here
 # rather than compile_string_method_expr, which wants a string
 # receiver. Receiver can also be InterpolatedRegularExpressionNode
 # for `/foo_#{x}/.match?(s)` (rare but valid).
    if recv >= 0 && (mname == "match?" || mname == "=~" || mname == "match")
      rpat = regex_pat_c_expr(recv)
 # regexp-typed receiver (the local stored a real
 # mrb_regexp_pattern * — typically from an if/else union where
 # the side-channel lookup can't pick a single index). Use the
 # local's value directly.
      if rpat == "" && infer_type(recv) == "regexp"
        rpat = compile_expr(recv)
      end
      if rpat != ""
        args_id = @nd_arguments[nid]
        if args_id >= 0
          arg_ids = get_args(args_id)
          if arg_ids.length > 0
            sc = compile_expr(arg_ids[0])
            if mname == "match?"
 # Issue #869: 2-arg form starts matching at the given byte
 # offset (negative counts from the end). Without the _at
 # helper the position was silently dropped.
              if arg_ids.length >= 2
                return "sp_re_match_p_at(" + rpat + ", " + sc + ", " + compile_expr_as_int(arg_ids[1]) + ")"
              end
              return "sp_re_match_p(" + rpat + ", " + sc + ")"
            end
            if mname == "=~"
 # CRuby-compatible nil/Integer return (sp_re_match_poly)
 # so `.nil?` and direct value observation work.
              @needs_rb_value = 1
              return "sp_re_match_poly(" + rpat + ", " + sc + ")"
            end
            return "sp_re_match(" + rpat + ", " + sc + ")"
          end
        end
      end
    end

    if mname == "block_given?" && recv >= 0 && @nd_type[recv] == "SelfNode"
      return compile_block_given_expr
    end

 # No receiver
    if recv < 0
      return compile_no_recv_call_expr(nid, mname)
    end

 # FFI dispatch: receiver is a registered FFI module. Must precede
 # operator/constructor handlers — FFI function names can collide
 # with operator-style names (e.g. a C function named `pow`).
    if @nd_type[recv] == "ConstantReadNode"
      ffi_res = compile_ffi_call_expr(nid, mname, @nd_name[recv])
      if ffi_res != ""
        return ffi_res
      end
    end

 # Lambda calls
    rt = infer_type(recv)
    if rt == "lambda"
      r = compile_lambda_call_expr(nid, mname, recv)
      if r != ""
        return r
      end
    end

 # `Class === expr` — case-when membership for primitive type names.
 # Resolve at compile time based on the arg's inferred type. Has to
 # run before compile_operator_expr / compile_eq (both of which would
 # mishandle the constant receiver as a regular C identifier and emit
 # `<undeclared identifier> == arg`).
    if mname == "===" && recv >= 0 && (@nd_type[recv] == "ConstantReadNode" || @nd_type[recv] == "ConstantPathNode")
      rcname_threeq = resolve_const_ref_name(recv)
      args_id_threeq = @nd_arguments[nid]
      if args_id_threeq >= 0
        a_threeq = get_args(args_id_threeq)
        if a_threeq.length > 0
          at_threeq = infer_type(a_threeq[0])
          if rcname_threeq == "Integer"
            return at_threeq == "int" ? "TRUE" : "FALSE"
          end
          if rcname_threeq == "Float"
            return at_threeq == "float" ? "TRUE" : "FALSE"
          end
          if rcname_threeq == "Numeric"
            return (at_threeq == "int" || at_threeq == "float") ? "TRUE" : "FALSE"
          end
          if rcname_threeq == "Comparable"
 # Comparable is included by Integer, Float, String, Symbol.
            return (at_threeq == "int" || at_threeq == "float" ||
                    at_threeq == "string" || at_threeq == "mutable_str" ||
                    at_threeq == "symbol") ? "TRUE" : "FALSE"
          end
          if rcname_threeq == "String"
            return at_threeq == "string" || at_threeq == "mutable_str" ? "TRUE" : "FALSE"
          end
          if rcname_threeq == "Symbol"
            return at_threeq == "symbol" ? "TRUE" : "FALSE"
          end
          if rcname_threeq == "Array"
            return is_array_type(at_threeq) == 1 ? "TRUE" : "FALSE"
          end
          if rcname_threeq == "Hash"
 # Hash type names all end in `_hash` (sym_int_hash, str_str_hash,
 # sym_poly_hash, etc.); poly_hash also matches the runtime form.
            is_hash = 0
            if at_threeq == "poly_hash"
              is_hash = 1
            elsif at_threeq.length > 5 && at_threeq[at_threeq.length - 5, 5] == "_hash"
              is_hash = 1
            end
            return is_hash == 1 ? "TRUE" : "FALSE"
          end
          if rcname_threeq == "Range"
            return at_threeq == "range" ? "TRUE" : "FALSE"
          end
          if rcname_threeq == "TrueClass"
 # TrueClass === arg matches only the literal `true` value.
 # Compile-time decide for TrueNode/FalseNode literals; emit a
 # runtime check for other bool-typed values; FALSE for non-bool.
            if @nd_type[a_threeq[0]] == "TrueNode"
              return "TRUE"
            end
            if @nd_type[a_threeq[0]] == "FalseNode"
              return "FALSE"
            end
            if at_threeq == "bool"
              return "((" + compile_expr(a_threeq[0]) + ") == TRUE)"
            end
            return "FALSE"
          end
          if rcname_threeq == "FalseClass"
            if @nd_type[a_threeq[0]] == "FalseNode"
              return "TRUE"
            end
            if @nd_type[a_threeq[0]] == "TrueNode"
              return "FALSE"
            end
            if at_threeq == "bool"
              return "((" + compile_expr(a_threeq[0]) + ") == FALSE)"
            end
            return "FALSE"
          end
          if rcname_threeq == "NilClass"
            return at_threeq == "nil" ? "TRUE" : "FALSE"
          end
          if rcname_threeq == "Object" || rcname_threeq == "Kernel" || rcname_threeq == "BasicObject"
            return "TRUE"
          end
        end
      end
    end

 # Operator on object with custom method
    if is_operator_name(mname) == 1
      r = compile_obj_operator_expr(nid, mname, recv)
      if r != ""
        return r
      end
    end

 # .call on method reference or proc
    if mname == "call"
      r = compile_dot_call_expr(nid, recv)
      if r != ""
        return r
      end
    end

 # Operators
    r = compile_operator_expr(nid, mname, recv)
    if r != ""
      return r
    end

 # .new
    if mname == "new"
      r = compile_constructor_expr(nid, recv)
      if r != ""
        return r
      end
    end
 # `Regexp.compile(<arg>)` -- CRuby alias for Regexp.new, both
 # literal and dyn variants. The call value is unused at runtime
 # (regex_pat_c_expr handles dispatch); emit "0" to satisfy the
 # LV/const assignment without warning.
    if mname == "compile"
      if regexp_new_literal_pattern(nid) != "" || regexp_new_dynamic?(nid) == 1
        return "0"
      end
    end

    recv_type = infer_type(recv)
 # Nullable pointer receiver: dispatch identically to the base type.
 # The null check is the caller's responsibility, matching Ruby's
 # NoMethodError semantics on a nil receiver. Without this, a local
 # typed `string?` (e.g. an opt param `f = nil` later passed a
 # string) misses every per-type dispatcher and falls through to
 # the "0" fallback.
 #
 # Scalar-nullable receivers (int?) get their own dispatch arms
 # below (the sentinel-aware ones for .nil? / .inspect / .to_s),
 # so don't strip `?` here — the int? arm has to see the full type.
    if is_nullable_type(recv_type) == 1 && is_scalar_nullable_type(recv_type) == 0
      recv_type = base_type(recv_type)
    end
 # Recv expr emits sp_RbVal even though the cached static type
 # is something narrower (typically int default for a nullable
 # poly-hash `[]` access — see expr_emits_poly_rb_val for the
 # canonical shape: `matched[:k]` where matched is sym_poly_hash?).
 # Treat as poly so the dispatcher reaches compile_poly_method_call
 # instead of falling through to compile_int_method_expr and
 # emitting the "cannot resolve" fallback. Without this, downstream
 # `.dup` / `.each` / etc. on such expressions silently no-op.
    if recv_type != "poly" && expr_emits_poly_rb_val(recv) == 1
      recv_type = "poly"
    end
 # Detect the each_cons[.with_index].map fusion shape before emitting
 # `rc`. compile_map_expr's fusion path re-compiles the each_cons
 # inner receiver itself; if we emit `rc` first, the
 # with_index/each_cons placeholders land as `sp_PtrArray * _t = 0;`
 # and (worse) the inner chain's side effects (`gets`) execute
 # twice. Route directly to compile_map_expr instead, which
 # produces the correct single fused loop. Issue #621.
    if mname == "map" && @nd_block[nid] >= 0 && recv >= 0
      ec_check_recv = recv
      if @nd_type[ec_check_recv] == "CallNode" && @nd_name[ec_check_recv] == "with_index" && @nd_block[ec_check_recv] < 0
        ec_check_recv = @nd_receiver[ec_check_recv]
      end
      if ec_check_recv >= 0 && @nd_type[ec_check_recv] == "CallNode" && (@nd_name[ec_check_recv] == "each_cons" || @nd_name[ec_check_recv] == "each_slice") && @nd_block[ec_check_recv] < 0
        return compile_map_expr(nid, "")
      end
    end
    rc = compile_expr_gc_rooted(recv)
 # Type-narrow unbox: when recv is a LocalVariableReadNode whose
 # narrowed type (post-`raise unless x.is_a?(C)` guard) is a
 # concrete obj_<C> but the declared storage is sp_RbVal, the
 # `rc` expression is still the boxed local (`lv_x`). Downstream
 # emits like `rc->iv_body` then dereference an sp_RbVal as a
 # struct pointer — C compile error. Cast through the union
 # payload here so the post-guard recv reads as the narrowed
 # pointer type. Issue #493.
    if recv >= 0 && @nd_type[recv] == "LocalVariableReadNode"
      lvname_cu = @nd_name[recv]
      declared_t_cu = find_var_declared_type(lvname_cu)
      if declared_t_cu == "poly" && is_obj_type(recv_type) == 1
        cname_cu = recv_type[4, recv_type.length - 4]
        rc = "((sp_" + cname_cu + " *)(" + rc + ").v.p)"
      end
    end
 # Root receiver if it may be collected during argument evaluation
    if expr_may_gc(recv) == 1 && type_needs_gc_root(recv_type) == 1
      args_id = @nd_arguments[nid]
      if args_id >= 0
        aargs = get_args(args_id)
        has_gc_arg = 0
        ak = 0
        while ak < aargs.length
          if expr_may_gc(aargs[ak]) == 1
            has_gc_arg = 1
          end
          ak = ak + 1
        end
        if has_gc_arg == 1
          tmp = new_temp
          emit("  " + c_type(recv_type) + " " + tmp + " = " + rc + ";")
          emit_gc_root_for_expr(tmp, recv_type)
          rc = tmp
        end
      end
    end

 # StringIO methods
    if recv_type == "stringio"
      r = compile_stringio_method_expr(nid, mname, rc)
      if r != ""
        return r
      end
    end

 # Static intern optimization: "literal".to_sym / .intern where the
 # string content is already in @sym_names becomes a compile-time
 # constant (SPS_<name> or ((sp_sym)<idx>)), avoiding the runtime
 # sp_sym_intern strcmp loop and dynamic pool allocation.
    if recv_type == "string" && (mname == "to_sym" || mname == "intern")
      if recv >= 0 && @nd_type[recv] == "StringNode"
        sname = @nd_content[recv]
        if sym_name_index(sname) >= 0
          return compile_symbol_literal(sname)
        end
      end
    end

 # String methods
    if recv_type == "string"
      r = compile_string_method_expr(nid, mname, rc)
      if r != ""
        return r
      end
    end

 # Symbol methods
    if recv_type == "symbol"
      r = compile_symbol_method_expr(nid, mname, rc)
      if r != ""
        return r
      end
    end

 # Mutable string methods: delegate to string methods via ->data
    if recv_type == "mutable_str"
      if mname == "length" || mname == "size"
        return "sp_String_length(" + rc + ")"
      end
      if mname == "dup"
        return "sp_String_dup(" + rc + ")"
      end
      if mname == "to_s"
        return rc + "->data"
      end
 # Issues #740, #741: mutating methods on mutable_str.
      if mname == "prepend" || mname == "<<" || mname == "concat"
        arg0_ms = compile_arg0(nid)
        helper_ms = (mname == "prepend") ? "sp_String_prepend" : "sp_String_append"
        return "(" + helper_ms + "(" + rc + ", " + arg0_ms + "), " + rc + ")"
      end
 # Issue #859: chomp! on mutable_str mutates in place and
 # returns the receiver (CRuby returns nil if no change; spinel
 # always returns self -- close-enough subset behaviour). Same
 # shape for chop! / strip! / lstrip! / rstrip!.
      if mname == "chomp!" || mname == "chop!" || mname == "strip!" || mname == "lstrip!" || mname == "rstrip!" || mname == "upcase!" || mname == "downcase!"
        helper_bang = {
          "chomp!" => "sp_str_chomp",
          "chop!" => "sp_str_chop",
          "strip!" => "sp_str_strip",
          "lstrip!" => "sp_str_lstrip",
          "rstrip!" => "sp_str_rstrip",
          "upcase!" => "sp_str_upcase",
          "downcase!" => "sp_str_downcase",
        }[mname]
        return "(sp_String_replace(" + rc + ", " + helper_bang + "(" + rc + "->data)), " + rc + ")"
      end
 # `delete_prefix!` / `delete_suffix!` — bang variants of the
 # non-mutating counterparts. Mutates self in place.
      if mname == "delete_prefix!" || mname == "delete_suffix!"
        helper_dp = (mname == "delete_prefix!") ? "sp_str_delete_prefix" : "sp_str_delete_suffix"
        return "(sp_String_replace(" + rc + ", " + helper_dp + "(" + rc + "->data, " + compile_arg0(nid) + ")), " + rc + ")"
      end
      if mname == "insert"
        args_id_ms = @nd_arguments[nid]
        if args_id_ms >= 0
          aargs_ms = get_args(args_id_ms)
          if aargs_ms.length >= 2
            return "(sp_String_insert(" + rc + ", " + compile_expr(aargs_ms[0]) + ", " + compile_expr(aargs_ms[1]) + "), " + rc + ")"
          end
        end
      end
      if mname == "replace"
        return "(sp_String_replace(" + rc + ", " + compile_arg0(nid) + "), " + rc + ")"
      end
 # For all other string methods, convert via ->data
      r = compile_string_method_expr(nid, mname, rc + "->data")
      if r != ""
        return r
      end
    end

 # Range methods
    if recv_type == "range"
      r = compile_range_method_expr(nid, mname, rc)
      if r != ""
        return r
      end
    end

 # Wrap in a statement expression so receivers like `Time.now`
 # (which expand to a clock_gettime call) are evaluated exactly once
 # even when to_f references the value twice.
    if recv_type == "time"
      if mname == "to_i"
        return "({ sp_Time _t = " + rc + "; (mrb_int)_t.tv_sec; })"
      end
      if mname == "to_f"
        return "({ sp_Time _t = " + rc + "; (mrb_float)_t.tv_sec + (mrb_float)_t.tv_nsec / 1e9; })"
      end
 # Time#iso8601 / Time#strftime — format the time as a
 # string. iso8601 is a no-arg fixed format (the canonical
 # "%Y-%m-%dT%H:%M:%S%z" with the colon-separated offset
 # CRuby uses), strftime takes the format string as an arg.
 # Both delegate to sp_time_iso8601 / sp_time_strftime in the
 # runtime, which use libc's strftime under the hood.
      if mname == "iso8601"
        return "sp_time_iso8601(" + rc + ")"
      end
      if mname == "strftime"
        return "sp_time_strftime(" + rc + ", " + compile_arg0(nid) + ")"
      end
 # Time#utc — same instant with the presentation
 # flag flipped to UTC. Returns a sp_Time so chained calls
 # (`Time.now.utc.iso8601`) lower correctly via sp_time_iso8601's
 # is_utc branch.
      if mname == "utc"
        return "sp_time_utc(" + rc + ")"
      end
 # Time broken-down accessors and zone observation. is_utc is
 # respected by sp_time_vtm (gmtime vs localtime). Local Time.new
 # is in scope; the fixed-offset form is a separate Issue.
      if mname == "year"
        return "sp_time_year(" + rc + ")"
      end
      if mname == "mon" || mname == "month"
        return "sp_time_mon(" + rc + ")"
      end
      if mname == "mday" || mname == "day"
        return "sp_time_mday(" + rc + ")"
      end
      if mname == "hour"
        return "sp_time_hour(" + rc + ")"
      end
      if mname == "min"
        return "sp_time_min(" + rc + ")"
      end
      if mname == "sec"
        return "sp_time_sec(" + rc + ")"
      end
      if mname == "wday"
        return "sp_time_wday(" + rc + ")"
      end
      if mname == "yday"
        return "sp_time_yday(" + rc + ")"
      end
      if mname == "isdst" || mname == "dst?"
        return "(sp_time_isdst(" + rc + ") != 0)"
      end
      if mname == "utc_offset" || mname == "gmt_offset" || mname == "gmtoff"
        return "sp_time_utc_offset(" + rc + ")"
      end
      if mname == "zone"
        return "sp_time_zone(" + rc + ")"
      end
 # Time <=> Time. <, >, ==, +, - resolve via compile_operator_expr;
 # <=> has no arm there and falls through to here. Total order on
 # the instant (tv_sec, then tv_nsec), -1 / 0 / 1. Gated on a Time
 # argument — mixed Time <=> non-Time is out of scope (a separate
 # Issue would return nil), so it falls through unresolved.
      if mname == "<=>"
        cmp_args = @nd_arguments[nid]
        if cmp_args >= 0
          cmp_a = get_args(cmp_args)
          if cmp_a.length > 0 && infer_type(cmp_a[0]) == "time"
            return time_cmp_expr(rc, compile_expr(cmp_a[0]))
          end
        end
      end
    end

 # Complex (value-type sp_Complex)
    if recv_type == "complex"
      if mname == "real"
        return "(" + rc + ").re"
      end
      if mname == "imaginary" || mname == "imag"
        return "(" + rc + ").im"
      end
      if mname == "conjugate" || mname == "conj"
        return "sp_complex_conjugate(" + rc + ")"
      end
      if mname == "inspect" || mname == "to_s"
        return "sp_complex_inspect(" + rc + ")"
      end
    end
 # Rational #840 #841: numerator / denominator / inspect.
    if recv_type == "rational"
      if mname == "numerator"
        return "(" + rc + ").num"
      end
      if mname == "denominator"
        return "(" + rc + ").den"
      end
      if mname == "inspect" || mname == "to_s"
        return "sp_rational_inspect(" + rc + ")"
      end
    end

 # Integer methods
    if recv_type == "int"
      r = compile_int_method_expr(nid, mname, rc)
      if r != ""
        return r
      end
    end

 # int? (scalar-nullable int) methods. The base type is mrb_int, so
 # arithmetic and most queries reuse the int dispatch above by
 # falling through; the methods that diverge on the sentinel
 # (`.nil?` is handled at the top-level pred dispatch, and
 # `.inspect` / `.to_s` need to print "nil" rather than INT64_MIN's
 # decimal) get their own arms here. Sentinel leak on arithmetic
 # (`r + 1` when r is SP_INT_NIL) is the documented spec until the
 # narrow-on-nil-check path lands.
    if is_scalar_nullable_type(recv_type) == 1
 # CRuby's nil.to_s == "" but nil.inspect == "nil"; split the
 # arms so the int? to_s wrapper short-circuits to the empty
 # string for SP_INT_NIL while inspect emits "nil".
      if mname == "inspect"
        return "sp_int_opt_inspect(" + rc + ")"
      end
      if mname == "to_s"
        return "sp_int_opt_to_s(" + rc + ")"
      end
 # `<int?> == nil` / `<int?> != nil` compare against the sentinel
 # value, not against integer 0. Without this arm compile_expr
 # lowers NilNode -> "0" and the comparison silently matches when
 # the int? holds a real 0 — the canonical false-positive on
 # `h[:int_zero_key].nil?` shape.
      if (mname == "==" || mname == "!=") && @nd_arguments[nid] >= 0
        args_eq = get_args(@nd_arguments[nid])
        if args_eq.length >= 1 && @nd_type[args_eq[0]] == "NilNode"
          if mname == "=="
            return "sp_int_is_nil(" + rc + ")"
          end
          return "(!sp_int_is_nil(" + rc + "))"
        end
      end
      r = compile_int_method_expr(nid, mname, rc)
      if r != ""
        return r
      end
    end

 # Float methods
    if recv_type == "float"
      r = compile_float_method_expr(nid, mname, rc)
      if r != ""
        return r
      end
    end

 # Exception methods: recv is sp_Exception *; dispatch through
 # sp_exc_* helpers.
    if recv_type == "exception"
      if mname == "class"
        return "sp_exc_class_name(" + rc + ")"
      end
      if mname == "message" || mname == "to_s"
        return "sp_exc_message(" + rc + ")"
      end
      if mname == "inspect"
        return "sp_sprintf(\"#<%s: %s>\", sp_exc_class_name(" + rc + "), sp_exc_message(" + rc + "))"
      end
      if mname == "full_message"
        return "sp_sprintf(\"%s: %s\", sp_exc_class_name(" + rc + "), sp_exc_message(" + rc + "))"
      end
      if mname == "backtrace"
 # Issue #895: spinel doesn't track per-exception frames (no
 # call-stack management in the AOT model -- same rationale as
 # the deferred `caller` portion of #878). Return an empty
 # str_array instead of nil so callers' `.first` / `.length`
 # don't crash.
        @needs_str_array = 1
        @needs_gc = 1
        return "sp_StrArray_new()"
      end
      if mname == "is_a?" || mname == "kind_of?"
        @needs_exc_class_hierarchy = 1
        args_id_isaxc = @nd_arguments[nid]
        if args_id_isaxc >= 0
          aisxc = get_args(args_id_isaxc)
          if aisxc.length > 0
            arg_name_isxc = resolve_introspection_arg_name(aisxc[0])
            if arg_name_isxc != ""
              return "sp_exc_class_le(sp_exc_class_name(" + rc + "), \"" + arg_name_isxc + "\")"
            end
          end
        end
        return "FALSE"
      end
      if mname == "==" || mname == "!="
 # Identity compare on the sp_Exception pointer; Ruby's
 # Exception#== is also identity-based unless overridden.
        a_isxc = get_args(@nd_arguments[nid])
        if a_isxc.length > 0
          op = mname == "==" ? "==" : "!="
          return "(" + rc + " " + op + " " + compile_expr(a_isxc[0]) + ")"
        end
      end
      if mname == "nil?"
        return "(" + rc + " == NULL)"
      end
    end

 # Bigint methods
    if recv_type == "bigint"
      # Cast away volatile from bigint locals (see compile_bigint_arg).
      rc_b = "(sp_Bigint *)" + rc
      if mname == "<=>"
 # 3-way compare on bigint. Returns mrb_int (-1 / 0 / 1) at C
 # level; outer wrappers (return / push into bigint slot) will
 # promote to bigint when needed.
        args_id_cmp = @nd_arguments[nid]
        if args_id_cmp >= 0
          a_cmp = get_args(args_id_cmp)
          if a_cmp.length > 0
            other_t_cmp = infer_type(a_cmp[0])
            other_c_cmp = compile_expr(a_cmp[0])
            if other_t_cmp == "bigint" || expr_emit_is_bigint(a_cmp[0]) == 1
              return "sp_bigint_cmp(" + rc_b + ", (sp_Bigint *)" + other_c_cmp + ")"
            end
            if other_t_cmp == "int"
              return "sp_bigint_cmp(" + rc_b + ", sp_bigint_new_int(" + other_c_cmp + "))"
            end
            if other_t_cmp == "float"
              return "(((mrb_float)sp_bigint_to_int(" + rc_b + ") < " + other_c_cmp + ") ? -1 : ((mrb_float)sp_bigint_to_int(" + rc_b + ") > " + other_c_cmp + " ? 1 : 0))"
            end
          end
        end
      end
      if mname == "[]"
 # Integer#[idx] bit-index on bigint receiver.
        args_id_bi = @nd_arguments[nid]
        if args_id_bi >= 0
          a_bi = get_args(args_id_bi)
          if a_bi.length > 0
            idx_t_bi = infer_type(a_bi[0])
            if idx_t_bi == "int" || idx_t_bi == "poly" || idx_t_bi == "bigint"
              idx_bi = compile_arg0_as_int(nid)
              return "((sp_bigint_to_int(" + rc_b + ") >> (" + idx_bi + ")) & 1)"
            end
          end
        end
      end
      if mname == "to_s"
        return "sp_bigint_to_s(" + rc_b + ")"
      end
      if mname == "to_i"
        return "sp_bigint_to_int(" + rc_b + ")"
      end
      if mname == "to_f"
        return "(mrb_float)sp_bigint_to_int(" + rc_b + ")"
      end
      if mname == "inspect"
        return "sp_bigint_to_s(" + rc_b + ")"
      end
      if mname == "abs"
        return "({ sp_Bigint *_b = " + rc_b + "; sp_bigint_cmp(_b, sp_bigint_new_int(0)) < 0 ? sp_bigint_sub(sp_bigint_new_int(0), _b) : _b; })"
      end
      if mname == "even?"
        return "((sp_bigint_to_int(" + rc_b + ") & 1) == 0)"
      end
      if mname == "odd?"
        return "((sp_bigint_to_int(" + rc_b + ") & 1) != 0)"
      end
      if mname == "zero?"
        return "(sp_bigint_cmp(" + rc_b + ", sp_bigint_new_int(0)) == 0)"
      end
      if mname == "positive?"
        return "(sp_bigint_cmp(" + rc_b + ", sp_bigint_new_int(0)) > 0)"
      end
      if mname == "negative?"
        return "(sp_bigint_cmp(" + rc_b + ", sp_bigint_new_int(0)) < 0)"
      end
    end

 # Bool methods
    if recv_type == "bool"
      if mname == "to_s"
        return "(" + rc + " ? \"true\" : \"false\")"
      end
      if mname == "inspect"
        return "(" + rc + " ? \"true\" : \"false\")"
      end
    end

 # nil methods (receiver inferred as "nil" — only .inspect and .to_s
 # need an expression-level answer; other nil methods like .nil? are
 # already handled earlier.)
    if recv_type == "nil"
      if mname == "inspect"
        return "\"nil\""
      end
      if mname == "to_s"
        return "\"\""
      end
 # NilClass#to_i / to_f - constant zero coercions. Issue #871.
      if mname == "to_i"
        return "((mrb_int)0)"
      end
      if mname == "to_f"
        return "((mrb_float)0.0)"
      end
 # NilClass#to_a returns an empty array. v1 uses int_array since
 # that's the cheapest concrete type; downstream consumers should
 # treat it as empty regardless of element type.
      if mname == "to_a"
        @needs_int_array = 1
        @needs_gc = 1
        return "sp_IntArray_new()"
      end
 # NilClass#& / NilClass#| / NilClass#^ — Ruby booleanizes the rhs.
      if mname == "&"
        return "FALSE"
      end
      if mname == "|" || mname == "^"
 # arg truthy iff not nil/false in Ruby. compile_expr's int
 # result is non-zero when truthy; surface the boolean.
        if @nd_arguments[nid] >= 0
          aa_or = get_args(@nd_arguments[nid])
          if aa_or.length > 0
            arg_e_or = compile_expr(aa_or[0])
            arg_t_or = infer_type(aa_or[0])
            if arg_t_or == "nil"
              return "FALSE"
            end
            return "((" + arg_e_or + ") ? TRUE : FALSE)"
          end
        end
        return "FALSE"
      end
    end

 # Tuple methods
    if is_tuple_type(recv_type) == 1
      if mname == "inspect" || mname == "to_s"
 # Route through the shared tuple-inspect builder. Issues
 # #724, #726.
        ins_t = compile_inspect_for(recv_type, rc)
        if ins_t != ""
          return ins_t
        end
      end
      if mname == "[]"
        args_id = @nd_arguments[nid]
        if args_id >= 0
          aargs = get_args(args_id)
          if aargs.length > 0
            if @nd_type[aargs[0]] == "IntegerNode"
              idx = @nd_value[aargs[0]]
              return rc + "->_" + idx.to_s
            end
            idx_expr = compile_expr(aargs[0])
            return rc + "->_" + idx_expr
          end
        end
      end
      if mname == "first"
        return rc + "->_0"
      end
      if mname == "last"
        arity = tuple_arity(recv_type)
        return rc + "->_" + (arity - 1).to_s
      end
      if mname == "length" || mname == "size"
        return tuple_arity(recv_type).to_s
      end
    end

 # Array methods
    r = compile_array_method_expr(nid, mname, rc, recv_type)
    if r != ""
      return r
    end

 # Hash methods
    r = compile_hash_method_expr(nid, mname, rc, recv_type)
    if r != ""
      return r
    end

 # map/select/reject/reduce as expression. Pass through the
 # already-compiled `rc` so compile_map_expr (etc.) doesn't
 # re-emit the recv's side-effecting chain. Issue #540: `gets`
 # in `n, m = gets.split.map &:to_i` was getting emitted twice --
 # once via compile_call_expr's `rc = compile_expr_gc_rooted` and
 # once via compile_map_expr's own `compile_expr(recv)`. With
 # gets reading from stdin, the duplicate consumed two input
 # lines and the loop dispatched on the wrong values.
    r = compile_enumerable_expr(nid, mname, rc)
    if r != ""
      return r
    end

 # Constant receiver (ARGV, Math, File, Time, ENV, Dir, Module, Class)
    r = compile_constant_recv_expr(nid, mname, recv, rc)
    if r != ""
      return r
    end

 # to_a on range
    if mname == "to_a"
      r = compile_to_a_range_expr(nid, recv)
      if r != ""
        return r
      end
    end

 # Open class method dispatch on built-in types
    r = compile_open_class_dispatch_expr(nid, mname, rc, recv_type)
    if r != ""
      return r
    end

 # Poly method calls
    if recv_type == "poly"
      return compile_poly_method_call(nid, rc, mname)
    end

 # is_a? / respond_to? / nil? / frozen? / positive? / negative?
    r = compile_introspection_expr(nid, mname, rc, recv_type)
    if r != ""
      return r
    end

 # Object method calls
    r = compile_object_method_expr(nid, mname, rc, recv_type)
    if r != ""
      return r
    end

 # Fallback: int-to-class dispatch
    r = compile_int_class_fallback_expr(nid, mname, rc, recv_type)
    if r != ""
      return r
    end

 # Unresolved method call on a known receiver. None of the dispatch
 # branches above claimed the shape — typical causes: typo in the
 # method name, missing def on the receiver class, or a Ruby idiom
 # Spinel doesn't support yet. Warn loud at codegen and bake a
 # runtime NoMethodError raise into the expression itself via a
 # statement-expression. The raise only fires when the expression
 # is actually evaluated -- so chain-recognition arms (e.g.
 # `4.times.map { ... }` which generates its own for-loop and
 # discards the times call) keep working, while genuine
 # "x.unknown_method" sites surface the bug instead of returning
 # a silent zero. Issue #727.
 #
 # Gate the raise on a *concrete* receiver type. "int" and "poly"
 # often arise when an ivar / param's type couldn't be inferred
 # (e.g. `@x = nil` later assigned an obj at runtime); raising
 # would break the silent-fallback pattern optcarrot etc. depend
 # on (`@hook && @hook.fire(...)` where @hook starts nil and is
 # later assigned). Keep the warn for visibility, fall back to
 # silent 0 on int/poly recvs.
    warn_unresolved_call(mname, base_type(recv_type))
    rb_unr = base_type(recv_type)
    if rb_unr == "int" || rb_unr == "poly" || rb_unr == "nil"
      return "0"
    end
    @needs_exc_class_hierarchy = 1
    "({ sp_raise_cls(\"NoMethodError\", \"undefined method '" + mname + "' for " + rb_unr + "\"); (mrb_int)0; })"
  end

  def compile_block_given_expr
 # &block parameter form takes priority: when the enclosing method
 # declares `def m(&block)`, the block is bound to `lv_block`, not
 # the implicit yield slot — so check the explicit param first.
 # `body_has_yield` flags any method containing block_given? as a
 # yield-method, which would otherwise route through the `_block`
 # slot and miss the actually-bound `&block` param.
    if @current_method_block_param != ""
      return "(lv_" + @current_method_block_param + " != NULL)"
    end
    if @in_yield_method == 1
      return "(_block != NULL)"
    end
 # Inlined yield-using method body: block_given? statically answers
 # `true` when @inline_yield_blk is set (caller's block IS the
 # given block). Issue #706.
    if @inline_yield_blk != nil && @inline_yield_blk >= 0
      return "1"
    end
    "0"
  end

  def compile_no_recv_call_expr(nid, mname)
 # No-recv IO methods that exist in compile_io_call_stmt (puts/print/
 # printf) all return nil in MRI. When reached in expression context
 # — proc-body last stmt, consumed `if`-arm, ternary — emit the
 # side-effect through the statement handler and pass "0" (nil in C)
 # up as the expression value. Without this, the call falls through
 # to warn_unresolved_call and the IO is silently dropped.
    if mname == "puts" || mname == "print" || mname == "printf" || mname == "warn" || mname == "at_exit"
      if compile_io_call_stmt(nid, mname, -1) == 1
        return "0"
      end
    end

 # `include` is handled at analyze time; at codegen it returns nil.
    if mname == "include"
      return "0"
    end

 # Bare `name` (or `self.name`) inside `def self.<m>` returns
 # the class's literal name as a string. Issue #509. Used by
 # ActiveRecord's "#{name}.table_name must be overridden"
 # raise pattern. Matches the recv_type == "class" arm in
 # compile_object_method_expr (which catches the explicit
 # `Foo.name` form via the class-typed constant receiver).
    if mname == "name" && @current_method_has_self == 0 && @current_class_idx >= 0
      @needs_class_table = 1
      return "sp_class_to_s(((sp_Class){" + cls_id_for_user_internal(@current_class_idx).to_s + "LL}))"
    end
 # Bare `new` inside a `def self.<m>` body resolves to
 # <CurrentClass>.new. Dispatched here rather than via the
 # later `mname == "new"` branch in compile_call_expr because
 # compile_call_expr short-circuits to this function for
 # recv < 0 before reaching that branch.
    if mname == "new"
      r = compile_constructor_expr(nid, -1)
      if r != ""
        return r
      end
    end
 # catch as expression
    if mname == "catch"
