 # p(val) -> puts(val.inspect). For most types the output matches
 # puts, but symbols need ":name" and strings need quoting.
      compile_p(nid)
      return "0"
    end
    if mname == "srand"
      @needs_rand = 1
      emit("  srand((unsigned)" + compile_arg0(nid) + ");")
      return "0"
    end
    if mname == "sleep"
      args_id = @nd_arguments[nid]
      if args_id >= 0
        emit("  sp_sleep(" + compile_arg0_as_float(nid) + ");")
      end
      return "0"
    end
    if mname == "gets" || mname == "readline"
      return "sp_gets()"
    end
    if mname == "readlines"
      @needs_str_array = 1
      @needs_gc = 1
      return "sp_readlines()"
    end
    if mname == "rand"
      @needs_rand = 1
      args_id = @nd_arguments[nid]
      if args_id >= 0
        return "((mrb_int)(rand() % (int)" + compile_arg0(nid) + "))"
      end
      return "((mrb_int)rand())"
    end
    if mname == "raise"
      @needs_setjmp = 1
      args_id = @nd_arguments[nid]
      if args_id >= 0
        arg_ids = get_args(args_id)
        if arg_ids.length >= 2
          if @nd_type[arg_ids[0]] == "ConstantReadNode"
            emit("  sp_raise_cls(\"" + @nd_name[arg_ids[0]] + "\", " + compile_expr(arg_ids[1]) + ");")
          else
            emit("  sp_raise(" + compile_expr(arg_ids[1]) + ");")
          end
        elsif arg_ids.length == 1
          emit_raise_one_arg(arg_ids[0])
        else
          emit_bare_raise
        end
      else
        emit_bare_raise
      end
      return "0"
    end
    if mname == "format"
      return compile_sprintf_call(nid)
    end
    if mname == "sprintf"
      return compile_sprintf_call(nid)
    end
    if mname == "putc"
      args_id = @nd_arguments[nid]
      if args_id >= 0
        arg_ids = get_args(args_id)
        if arg_ids.length > 0
          at = infer_type(arg_ids[0])
          if at == "int"
            return "(putchar((char)" + compile_expr(arg_ids[0]) + "), 0)"
          else
            return "(putchar(" + compile_expr(arg_ids[0]) + "[0]), 0)"
          end
        end
      end
      return "0"
    end
    mi = find_method_idx(mname)
    if mi >= 0
 # yield-bearing fn called with a literal block in
 # expression position (e.g. `x = measure { ... }`). The default
 # `, NULL, NULL` yargs path below produces `sp_measure(, NULL, NULL)`
 # which doesn't compile. Mirror compile_yield_call_stmt's inline
 # path but capture the body's last expression into a result temp.
      if @meth_has_yield[mi] == 1 && has_literal_block(nid) == 1
