        if mname == "to_s"
          return "sp_int_to_s(self)"
        end
        if mname == "to_f"
          return "(mrb_float)(self)"
        end
        if mname == "abs"
          return "((self) < 0 ? -(self) : (self))"
        end
      end
 # float methods
      if st == "float"
        if mname == "to_i"
          return "(mrb_int)(self)"
        end
        if mname == "to_f"
          return "(self)"
        end
        if mname == "to_s"
          return "sp_float_to_s(self)"
        end
      end
    end
 # Inside an instance_eval inlined block: receiverless calls in
