 # Module case: cmeth is stored as synthetic `<Mod>_cls_<m>`
 # in @meth_*. find_method_idx already handles the lookup.
        if module_name_exists(owning) == 1
          synth = owning + "_cls_" + mname
          mi = find_method_idx(synth)
          if mi >= 0
            ca_m = compile_call_args_with_defaults(nid, mi)
            if ca_m == ""
              return "sp_" + sanitize_name(synth) + "()"
            end
            return "sp_" + sanitize_name(synth) + "(" + ca_m + ")"
          end
        end
      end
    end
 # Real-class cmeth emit path: emit_class_level_method sets
 # @current_method_name to the bare mname (no `_cls_` marker)
 # and @current_method_has_self to 0, distinguishing it from
 # instance methods (which set has_self = 1). Resolve sibling
 # cmeths against @cls_cmeth_names directly.
    if @current_class_idx >= 0 && @current_method_has_self == 0
      cmnames_r = @cls_cmeth_names[@current_class_idx].split(";", -1)
      cmidx_r = 0
      while cmidx_r < cmnames_r.length
        if cmnames_r[cmidx_r] == mname
          ca_r = compile_call_args_coerced_for_cmeth(nid, @current_class_idx, cmidx_r)
          owning_r = @cls_names[@current_class_idx]
          if ca_r == ""
            return "sp_" + owning_r + "_cls_" + sanitize_name(mname) + "()"
          end
          return "sp_" + owning_r + "_cls_" + sanitize_name(mname) + "(" + ca_r + ")"
        end
        cmidx_r = cmidx_r + 1
      end
    end
 # Unresolved bare-name call (`foobar(0)`, `foobar`). CRuby would
 # raise NoMethodError; Spinel can't, but warning at codegen so the
 # user sees the problem is far better than a silently-empty binary.
 # See the matching warn at the receiver-form fallthrough above for
 # why this is a warn-and-emit-0 rather than a hard error.
    warn_unresolved_call(mname, "(no receiver)")
    "0"
  end

  def compile_lambda_call_expr(nid, mname, recv)
    rc = compile_expr_gc_rooted(recv)
 # Determine return type unboxing
    ret_type = ""
    if @nd_type[recv] == "LocalVariableReadNode"
      ret_type = lambda_var_ret_type(@nd_name[recv])
    end
    if mname == "[]" || mname == "call"
      call_expr = ""
      args_id = @nd_arguments[nid]
      if args_id >= 0
        aargs = get_args(args_id)
 # multi-arg lambda dispatch. Pick `sp_lam_callN`
 # based on the number of args; up to arity-4 covered. Beyond
 # that, fall back to single-arg (caller is on its own).
        if aargs.length == 1
          ac = wrap_as_sp_val(aargs.first)
          call_expr = "sp_lam_call(" + rc + ", " + ac + ")"
        elsif aargs.length == 2
          a0 = wrap_as_sp_val(aargs[0])
          a1 = wrap_as_sp_val(aargs[1])
          call_expr = "sp_lam_call2(" + rc + ", " + a0 + ", " + a1 + ")"
        elsif aargs.length == 3
          a0 = wrap_as_sp_val(aargs[0])
          a1 = wrap_as_sp_val(aargs[1])
          a2 = wrap_as_sp_val(aargs[2])
          call_expr = "sp_lam_call3(" + rc + ", " + a0 + ", " + a1 + ", " + a2 + ")"
        elsif aargs.length == 4
          a0 = wrap_as_sp_val(aargs[0])
          a1 = wrap_as_sp_val(aargs[1])
          a2 = wrap_as_sp_val(aargs[2])
          a3 = wrap_as_sp_val(aargs[3])
          call_expr = "sp_lam_call4(" + rc + ", " + a0 + ", " + a1 + ", " + a2 + ", " + a3 + ")"
        end
      end
      if call_expr == ""
        call_expr = "sp_lam_call(" + rc + ", &sp_lam_nil_val)"
      end
      return lam_unbox(call_expr, ret_type)
    end
    ""
  end

  def compile_obj_operator_expr(nid, mname, recv)
    lt = infer_type(recv)
    if is_obj_type(lt) == 1
      cname = lt[4, lt.length - 4]
      ci = find_class_idx(cname)
      if ci >= 0
 # MRI's default `!=` is `!(self == other)`. Synthesize when
 # the class defines `==` but not `!=` -- otherwise this call
 # falls into compile_eq's raw fallback and breaks under
 # -Werror.
        synth_neq = mname == "!=" &&
                    find_method_owner(ci, "!=") == "" &&
                    find_method_owner(ci, "==") != ""
        target_mname = synth_neq ? "==" : mname

        owner = find_method_owner(ci, target_mname)
        if owner != ""
 # Box args to match the dispatched method's param types. A
 # widened `==(sp_RbVal other)` called with raw `mrb_int` /
 # `const char *` is the original -Werror failure.
          ca = compile_typed_call_args_by_name(nid, owner, target_mname)
          rc = compile_expr_gc_rooted(recv)
          recv_arg = owner == cname ? rc : "(sp_" + owner + " *)" + rc
          tail = ca != "" ? ", " + ca : ""
          call = "sp_" + owner + "_" + sanitize_name(target_mname) + "(" + recv_arg + tail + ")"
          return synth_neq ? "(!" + call + ")" : call
        end

        cmp_owner = find_method_owner(ci, "<=>")
        if cmp_owner != ""
          ca = compile_typed_call_args_by_name(nid, cmp_owner, "<=>")
          rc = compile_expr_gc_rooted(recv)
          cmp_call = "sp_" + cmp_owner + "__cmp(" + rc + ", " + ca + ")"
 # Promote mode: <=> returns sp_Bigint*. Unbox via sp_bigint_to_int
 # so the < / > / <= / >= comparison fires on the int value, not
 # on the heap pointer (which would compare against 0 = "is NULL?").
          cmp_ret = cls_method_return(find_class_idx(cmp_owner), "<=>")
          if base_type(cmp_ret) == "bigint"
            @needs_bigint = 1
            cmp_call = "sp_bigint_to_int((sp_Bigint *)" + cmp_call + ")"
          end
          if mname == "<"
            return "(" + cmp_call + " < 0)"
          end
          if mname == ">"
            return "(" + cmp_call + " > 0)"
          end
          if mname == "<="
            return "(" + cmp_call + " <= 0)"
          end
          if mname == ">="
            return "(" + cmp_call + " >= 0)"
          end
          if mname == "=="
            return "(" + cmp_call + " == 0)"
          end
          if mname == "!="
            return "(" + cmp_call + " != 0)"
          end
        end
      end
    end
    ""
  end

  def compile_dot_call_expr(nid, recv)
    if recv >= 0
      if @nd_type[recv] == "LocalVariableReadNode"
        rname = @nd_name[recv]
 # Check method references
        ri = 0
        while ri < @method_ref_vars.length
          if @method_ref_vars[ri] == rname
            ref_mname = @method_ref_names[ri]
            mi = find_method_idx(ref_mname)
            if mi >= 0
 # Use compile_call_args_with_defaults so the call routes
 # each arg through compile_expr_for_expected_type — picks
 # up promote-mode bigint coerce for an int literal flowing
 # into a sp_Bigint * param slot.
              return "sp_" + sanitize_name(ref_mname) + "(" + compile_call_args_with_defaults(nid, mi) + ")"
            end
          end
          ri = ri + 1
        end
 # Check if it's a proc variable
        vt = find_var_type(rname)
        if vt == "proc"
 # Pack the call-site args into a stack-allocated mrb_int array
 # (C99 compound literal) so a single `sp_proc_call(p, args)`
 # helper covers any arity. The proc fn unpacks args[i] into
 # named locals at function entry. compile_call_args returns
 # "" for zero args; pad with "0" so the array has at least
 # one slot (the proc fn's `_unused` fallback expects args[0]
 # to be addressable).
          ca = compile_proc_call_args(nid)
          return "sp_proc_call(lv_" + rname + ", (mrb_int[]){" + ca + "})"
        end
      end

 # Anonymous-proc-receiver dispatch — `proc { ... }.call`, or any
 # expression chain whose inferred type is `proc` (e.g.
 # `factory().call`). The LocalVariableReadNode branch above handles
 # the named-proc case directly; this generic branch compiles the
 # receiver expression and feeds it to sp_proc_call, using the same
 # arg-array packing convention.
      if infer_type(recv) == "proc"
        ca_anon = compile_call_args(nid)
        if ca_anon == ""
          ca_anon = "0"
        end
        return "sp_proc_call(" + compile_expr(recv) + ", (mrb_int[]){" + ca_anon + "})"
      end
    end
    rt = infer_type(recv)
    if rt == "proc"
      ca = compile_proc_call_args(nid)
      rc = compile_expr_gc_rooted(recv)
      return "sp_proc_call(" + rc + ", (mrb_int[]){" + ca + "})"
    end
    ""
  end

  def compile_bigint_arg(nid)
    args_id = @nd_arguments[nid]
    if args_id >= 0
      arg_ids = get_args(args_id)
      if arg_ids.length > 0
        at = infer_type(arg_ids[0])
 # The cache may say "int" even though the arg emits bigint
 # (arith CallNode with bigint operand, or an attr-reader / user-
 # method call whose return slot is now promoted). Peek operands
 # / consult the post-promote method-return tables so we don't
 # wrap an already-bigint expression with sp_bigint_new_int.
 # The unified `expr_emit_is_bigint` walker covers arith, bitop,
 # unary, paren, and user-method-return cases in one pass.
        if at != "bigint" && expr_emit_is_bigint(arg_ids[0]) == 1
          at = "bigint"
        end
        if at != "bigint" && @nd_type[arg_ids[0]] == "CallNode"
          ar_mn_bg = @nd_name[arg_ids[0]]
          if ar_mn_bg == "+" || ar_mn_bg == "-" || ar_mn_bg == "*" || ar_mn_bg == "/" || ar_mn_bg == "%" || ar_mn_bg == "**"
            ar_recv_bg = @nd_receiver[arg_ids[0]]
            if ar_recv_bg >= 0 && base_type(infer_type(ar_recv_bg)) == "bigint"
              at = "bigint"
            else
              ar_args_bg = @nd_arguments[arg_ids[0]]
              if ar_args_bg >= 0
                aa_bg = get_args(ar_args_bg)
                if aa_bg.length > 0 && base_type(infer_type(aa_bg[0])) == "bigint"
                  at = "bigint"
                end
              end
            end
          end
 # `obj.method` call: re-resolve through cls_method_return on the
 # now-promoted table. Stale cache may say "int". Also check
 # attr_reader directly (auto-generated, ivar-slot-typed).
          if at != "bigint"
            recv_bgp = @nd_receiver[arg_ids[0]]
            if recv_bgp >= 0
              recv_t_bgp = base_type(infer_type(recv_bgp))
              if is_obj_type(recv_t_bgp) == 1
                cn_bgp = recv_t_bgp[4, recv_t_bgp.length - 4]
                ci_bgp = find_class_idx(cn_bgp)
                if ci_bgp >= 0
                  mr_bgp = cls_method_return(ci_bgp, ar_mn_bg)
                  if base_type(mr_bgp) == "bigint"
                    at = "bigint"
                  end
                  if at != "bigint" && cls_has_attr_reader(ci_bgp, ar_mn_bg) == 1
                    slot_bgp = cls_ivar_type(ci_bgp, "@" + ar_mn_bg)
                    if base_type(slot_bgp) == "bigint"
                      at = "bigint"
                    end
                  end
                end
              end
            end
          end
        end
        val = compile_expr(arg_ids[0])
        if at == "bigint"
 # Cast away volatile (locals in setjmp-bearing functions are
 # emitted volatile) so passing to bigint runtime functions —
 # which take plain `sp_Bigint *` — doesn't warn. Pre-existing
 # latent issue triggered by bigint inside begin/rescue.
          return "(sp_Bigint *)" + val
        end
        if at == "poly"
 # poly-typed source whose payload is an int (SP_TAG_INT). Unbox
 # via .v.i then re-box into sp_Bigint *. Common in optcarrot
 # where Mixer/Noise/Pulse `sample` methods end up with a "poly"
 # return slot because their bodies have heterogeneous tails.
          @needs_rb_value = 1
          return "sp_bigint_new_int((" + val + ").v.i)"
        end
        return "sp_bigint_new_int(" + val + ")"
      end
    end
    "sp_bigint_new_int(0)"
  end

 # Collect flattened parts of a string concat chain: a + b + c → [a, b, c]
 # Returns compiled expression strings. Only flattens up to 4 parts.
  def collect_concat_chain(nid)
    parts = "".split(",", -1)
    collect_concat_parts(nid, parts)
    parts
  end

  def collect_concat_parts(nid, parts)
    if parts.length >= 12
      parts.push(compile_expr(nid))
      return
    end
    if @nd_type[nid] == "CallNode" && @nd_name[nid] == "+"
      recv = @nd_receiver[nid]
      if recv >= 0 && infer_type(recv) == "string"
        collect_concat_parts(recv, parts)
        args_id = @nd_arguments[nid]
        if args_id >= 0
          aargs = get_args(args_id)
          if aargs.length > 0
            at = infer_type(aargs[0])
            if at == "string"
              parts.push(compile_expr(aargs[0]))
            elsif at == "int"
              parts.push("sp_int_to_s(" + compile_expr(aargs[0]) + ")")
            elsif at == "bigint"
              @needs_bigint = 1
              parts.push("sp_bigint_to_s((sp_Bigint *)" + compile_expr(aargs[0]) + ")")
            elsif at == "float"
              parts.push("sp_float_to_s(" + compile_expr(aargs[0]) + ")")
            elsif at == "poly"
 # `"a" + poly_local + "b"` -- the 2-arg sp_str_concat path at
 # the single-`+` site already coerces via sp_poly_to_s; mirror
 # that here for chained concat collapsing into sp_str_concat3 /
 # sp_str_concat_arr. Without this, the chained form silently
 # passed an sp_RbVal into a `const char *` parameter and cc
 # rejected the generated code. Common shape: a local typed
 # through `if x.nil?; ""; else; x; end` when x came from a
 # poly-valued hash lookup -- the union stays sp_RbVal but its
 # string-side payload is always a valid c-string at runtime.
              parts.push("sp_poly_to_s(" + compile_expr(aargs[0]) + ")")
            elsif at == "symbol"
              parts.push("sp_sym_to_s(" + compile_expr(aargs[0]) + ")")
            elsif at == "mutable_str"
              parts.push("(" + compile_expr(aargs[0]) + ")->data")
            elsif at == "bigint"
              parts.push("sp_bigint_to_s(" + compile_expr(aargs[0]) + ")")
            else
              parts.push(compile_expr(aargs[0]))
            end
            return
          end
        end
      end
    end
    parts.push(compile_expr(nid))
  end

 # Total-order compare of two sp_Time values as a statement
 # expression yielding -1 / 0 / 1 (tv_sec, then tv_nsec). Both
 # sides are hoisted into temps so a fresh sp_time_now() receiver
 # is evaluated once. Used by Time's <, >, <=, >=, ==, <=>.
  def time_cmp_expr(la, lb)
    "({ sp_Time _a = " + la + "; sp_Time _b = " + lb + "; (_a.tv_sec < _b.tv_sec) ? -1 : (_a.tv_sec > _b.tv_sec) ? 1 : (_a.tv_nsec < _b.tv_nsec) ? -1 : (_a.tv_nsec > _b.tv_nsec) ? 1 : 0; })"
  end

 # True (1) iff the C expression `compile_expr(nid)` would emit
 # an `sp_Bigint *` value, even when `infer_type(nid)` returns
 # the stale-int cache from annotate_all_node_types. Walks
 # through ParenthesesNode and recurses into arith/bitop CallNodes
 # whose operands carry bigint type. The chain shape
 # `((a | b) & c) | d` needs the recursive walk -- only the
 # deepest operand directly types as bigint; each enclosing op
 # promotes through sp_bigint_<op> and the outer ops would
 # otherwise see "int" via infer_type. Promote-mode --
 # specifically optcarrot's CPU and PPU which thread multi-level
 # bitop chains through `self->iv_x` (bigint ivar) operands.
  def expr_emit_is_bigint(nid)
    if nid < 0
      return 0
    end
    if base_type(infer_type(nid)) == "bigint"
      return 1
    end
    t = @nd_type[nid]
    if t == "ParenthesesNode"
      body_eb = @nd_body[nid]
      if body_eb >= 0
        stmts_eb = get_stmts(body_eb)
        if stmts_eb.length == 1
          return expr_emit_is_bigint(stmts_eb[0])
        end
      end
      return 0
    end
 # `cond ? T : F`: if either arm emits bigint, the unified C type
 # of the ternary is sp_Bigint* (compile_if_expr boxes the other
 # arm via sp_bigint_new_int). Surface that to callers so a
 # bigint-arg coercer doesn't wrap the whole thing in another
 # sp_bigint_new_int treating it as int.
    if t == "IfNode" || t == "UnlessNode"
      if_then_eb = @nd_body[nid]
      if_sub_eb = @nd_subsequent[nid]
      if if_then_eb >= 0
        if_then_stmts_eb = get_stmts(if_then_eb)
        if if_then_stmts_eb.length > 0 && expr_emit_is_bigint(if_then_stmts_eb.last) == 1
          return 1
        end
      end
      if if_sub_eb >= 0 && @nd_type[if_sub_eb] == "ElseNode"
        if_else_body_eb = @nd_body[if_sub_eb]
        if if_else_body_eb >= 0
          if_else_stmts_eb = get_stmts(if_else_body_eb)
          if if_else_stmts_eb.length > 0 && expr_emit_is_bigint(if_else_stmts_eb.last) == 1
            return 1
          end
        end
      end
      return 0
    end
 # `lv_x &&= ...` / `lv_x ||= ...` / `lv_x += ...` returns the
 # updated slot value. When the LV is bigint, the result is too.
    if t == "LocalVariableAndWriteNode" || t == "LocalVariableOrWriteNode" || t == "LocalVariableOperatorWriteNode"
      if base_type(find_var_type(@nd_name[nid])) == "bigint"
        return 1
      end
    end
 # Same shape for ivar / cvar op-writes.
    if t == "InstanceVariableAndWriteNode" || t == "InstanceVariableOrWriteNode" || t == "InstanceVariableOperatorWriteNode"
      if @current_class_idx >= 0
        ivar_t_eb = cls_ivar_type(@current_class_idx, @nd_name[nid])
        if base_type(ivar_t_eb) == "bigint"
          return 1
        end
      end
    end
    if t != "CallNode"
      return 0
    end
    mn_eb = @nd_name[nid]
 # `bm.call(x)` / `bm[x]` on a Method recv in promote mode: the
 # fn_ptr cast returns sp_Bigint * (uniform ABI widening). The
 # cached at/return for this CallNode lags reality so the
 # caller's int-expected slot path mis-wraps with
 # sp_bigint_new_int. Detect directly.
    if (mn_eb == "call" || mn_eb == "[]") && @int_overflow_mode == "promote"
      rcv_bm_eb = @nd_receiver[nid]
      if rcv_bm_eb >= 0 && base_type(infer_type(rcv_bm_eb)) == "obj_Method"
        return 1
      end
 # Static alias: `m = method(:foo)` then `m.call(x)` rewrites to
 # a direct `sp_foo(x)` (see compile_dot_call_expr). Look up the
 # target method's promote-mode return.
      if rcv_bm_eb >= 0 && @nd_type[rcv_bm_eb] == "LocalVariableReadNode"
        rname_ma = @nd_name[rcv_bm_eb]
        ri_ma = 0
        while ri_ma < @method_ref_vars.length
          if @method_ref_vars[ri_ma] == rname_ma
            ref_mname_ma = @method_ref_names[ri_ma]
            mi_ma = find_method_idx(ref_mname_ma)
            if mi_ma >= 0 && mi_ma < @meth_return_types.length
              if base_type(@meth_return_types[mi_ma]) == "bigint"
                return 1
              end
            end
            ri_ma = @method_ref_vars.length
          end
          ri_ma = ri_ma + 1
        end
      end
    end
 # CallNode dispatch to a user method whose return slot has been
 # promoted to bigint: infer_type can be stale (the cls_method
 # _return / @meth_return_types tables get rewritten by
 # promote_int_to_bigint_globally after annotate_all_node_types
 # populates @nd_inferred_type). Resolve the call directly to
 # cross-check.
    rcv_eb_user = @nd_receiver[nid]
    if rcv_eb_user >= 0
      rcv_t_eb_user = base_type(infer_type(rcv_eb_user))
      if is_obj_type(rcv_t_eb_user) == 1
        cls_eb = rcv_t_eb_user[4, rcv_t_eb_user.length - 4]
        ci_eb_user = find_class_idx(cls_eb)
        if ci_eb_user >= 0
          ret_eb_user = cls_method_return(ci_eb_user, mn_eb)
          if base_type(ret_eb_user) == "bigint"
            return 1
          end
        end
      end
 # Class-method call: `CounterClass.count` lowers to
 # sp_CounterClass_cls_count whose return slot may have been
 # promoted to bigint. Detect via the recv's ConstantReadNode
 # (or ConstantPathNode) and the cls_cmeth_return.
      if @nd_type[rcv_eb_user] == "ConstantReadNode" || @nd_type[rcv_eb_user] == "ConstantPathNode"
        rname_eb = resolve_const_read_name(@nd_name[rcv_eb_user])
        cidx_eb = find_class_idx(rname_eb)
        if cidx_eb >= 0
          cret_eb = cls_method_return(cidx_eb, mn_eb, "cmeth")
          if base_type(cret_eb) == "bigint"
            return 1
          end
        end
 # Const-as-instance: `APP.count` where APP is `const obj_App` and
 # `count` is App's instance method (or attr_reader). Look up the
 # const's static type and resolve the imeth.
        ci_eb_const = find_const_idx(rname_eb)
        if ci_eb_const >= 0 && ci_eb_const < @const_types.length
          ct_eb_const = base_type(@const_types[ci_eb_const])
          if is_obj_type(ct_eb_const) == 1
            cls_eb_const = ct_eb_const[4, ct_eb_const.length - 4]
            cidx_eb_const = find_class_idx(cls_eb_const)
            if cidx_eb_const >= 0
              cret_eb_const = cls_method_return(cidx_eb_const, mn_eb)
              if base_type(cret_eb_const) == "bigint"
                return 1
              end
 # attr_reader on obj instance — return type is the ivar slot.
              if cls_has_attr_reader(cidx_eb_const, mn_eb) == 1
                slot_eb_const = cls_ivar_type(cidx_eb_const, "@" + mn_eb)
                if base_type(slot_eb_const) == "bigint"
                  return 1
                end
              end
            end
          end
        end
      end
 # Same shape: recv is an obj_<C> typed expression and mname is
 # an attr_reader. Cover the bigint slot regardless of whether
 # the method-return table reports the right type.
      rcv_t_eb_attr = base_type(infer_type(rcv_eb_user))
      if is_obj_type(rcv_t_eb_attr) == 1
        cls_eb_attr = rcv_t_eb_attr[4, rcv_t_eb_attr.length - 4]
        cidx_eb_attr = find_class_idx(cls_eb_attr)
        if cidx_eb_attr >= 0 && cls_has_attr_reader(cidx_eb_attr, mn_eb) == 1
          slot_eb_attr = cls_ivar_type(cidx_eb_attr, "@" + mn_eb)
          if base_type(slot_eb_attr) == "bigint"
            return 1
          end
        end
      end
 # `Module.accessor.<method>`: recv is a CallNode whose inner
 # recv is a ConstantReadNode for a module name with a resolved
 # accessor (resolve_module_singleton_accessors). Walk to the
 # candidate class(es) and check the cls method return type.
      if @nd_type[rcv_eb_user] == "CallNode"
        inner_recv_eb = @nd_receiver[rcv_eb_user]
        inner_mname_eb = @nd_name[rcv_eb_user]
        if inner_recv_eb >= 0 && @nd_type[inner_recv_eb] == "ConstantReadNode"
          mod_name_eb = @nd_name[inner_recv_eb]
          if module_name_exists(mod_name_eb) == 1
            rconsts_eb = module_acc_resolved(mod_name_eb, inner_mname_eb)
            if rconsts_eb != "" && rconsts_eb != "?"
              cands_eb = rconsts_eb.split(";", -1)
              ki_eb = 0
              while ki_eb < cands_eb.length
                cn_eb_ms = cands_eb[ki_eb]
                rt_eb_ms = lookup_cls_meth_return(cn_eb_ms, mn_eb)
                if base_type(rt_eb_ms) == "bigint"
                  return 1
                end
                ki_eb = ki_eb + 1
              end
            end
          end
        end
      end
    end
 # Issue #746: `bigint.abs` / `bigint.succ` / `bigint.pred` /
 # `bigint.divmod` return bigint when the recv is bigint. Without
 # this arm, expr_emit_is_bigint returns 0 and the caller wraps
 # the result with sp_bigint_new_int (treating the pointer as
 # int) -- garbage output.
    if mn_eb == "abs" || mn_eb == "succ" || mn_eb == "pred" || mn_eb == "next"
      rcv_abs = @nd_receiver[nid]
      if rcv_abs >= 0 && (base_type(infer_type(rcv_abs)) == "bigint" ||
                          expr_emit_is_bigint(rcv_abs) == 1)
        return 1
      end
    end
    if mn_eb != "+" && mn_eb != "-" && mn_eb != "*" && mn_eb != "/" && mn_eb != "%" && mn_eb != "**" &&
       mn_eb != "&" && mn_eb != "|" && mn_eb != "^" && mn_eb != "<<" && mn_eb != ">>" &&
       mn_eb != "~" && mn_eb != "-@"
      return 0
    end
 # Arith/bitop result is bigint only when at least one side is
 # bigint AND the recv is itself a numeric type (int/float/bigint
 # or nullable). `string + bigint_var` (legal-shape Ruby
 # dead-code in promote mode -- e.g. an included module body
 # that's never reached with int args) has the recv side decide
 # the dispatch: the string concat code path handles it. Treating
 # the inner `+` as bigint cascades through compile_operator_expr
 # and emits sp_bigint_add on string args.
    rcv_eb = @nd_receiver[nid]
    if rcv_eb < 0
      return 0
    end
    rcv_t_arith = base_type(infer_type(rcv_eb))
    if rcv_t_arith != "int" && rcv_t_arith != "float" && rcv_t_arith != "bigint" && rcv_t_arith != "numeric"
      return 0
    end
    if expr_emit_is_bigint(rcv_eb) == 1
      return 1
    end
    args_eb = @nd_arguments[nid]
    if args_eb >= 0
      ra_eb = get_args(args_eb)
      if ra_eb.length > 0 && expr_emit_is_bigint(ra_eb[0]) == 1
        return 1
      end
    end
    0
  end

  def compile_operator_expr(nid, mname, recv)
 # Bigint operators
    lt = infer_type(recv)
 # Widen lt to "bigint" only when recv is itself a numeric type
 # (int, float, bigint, or nullable variants). Other recv shapes
 # (poly / typed containers like int_array / str_array / strings /
 # ptr_array / hashes) have their own per-type dispatch arms
 # later in the file -- forcing them through the bigint block
 # would emit sp_bigint_shl on an sp_IntArray * receiver and the
 # like. The legacy widening predates promote mode.
    if lt != "bigint"
      lt_b = base_type(lt)
      if lt_b == "int" || lt_b == "float" || lt_b == "bigint"
        args_id = @nd_arguments[nid]
        if args_id >= 0
          aargs = get_args(args_id)
          if aargs.length > 0
            if infer_type(aargs[0]) == "bigint" || expr_emit_is_bigint(aargs[0]) == 1
              lt = "bigint"
            end
          end
        end
      end
    end
 # Stale-int recv whose actual emit is bigint: an arith / bit-op
 # CallNode whose own operands include a bigint locks the chain
 # into bigint (compile_operator_expr returns sp_Bigint *). The
 # parent operator sees the stale "int" cache from
 # annotate_all_node_types but the C expression is sp_Bigint *.
 # Detect that here so we enter the bigint-dispatch block and
 # route through sp_bigint_<op>. The chain can be multiple
 # levels deep (`((a | b) & 4095) | 8192` — three CallNodes,
 # only the deepest has a direct bigint operand) so this is a
 # recursive walk through ParenthesesNode + arith/bitop
 # CallNode nodes.
    if lt != "bigint" && expr_emit_is_bigint(recv) == 1
      lt = "bigint"
    end
 # When ONE side is bigint and the OTHER side is float, Ruby
 # promotes the result to float. Coerce the bigint operand to
 # mrb_float via sp_bigint_to_int and dispatch as float arith.
    if lt == "bigint"
      args_fp = @nd_arguments[nid]
      arg0_fp_t = ""
      arg0_fp_nid = -1
      if args_fp >= 0
        aargs_fp = get_args(args_fp)
        if aargs_fp.length > 0
          arg0_fp_t = infer_type(aargs_fp[0])
          arg0_fp_nid = aargs_fp[0]
        end
      end
 # `bigint == nil` / `bigint != nil` (and float / bool / etc.)
 # Ruby semantics: only nil equals nil. Constant-fold so the
 # bigint cmp path doesn't compare against sp_bigint_new_int(0)
 # (which would conflate a stored 0 with nil — see compile_eq).
      if (mname == "==" || mname == "!=") && arg0_fp_nid >= 0 && @nd_type[arg0_fp_nid] == "NilNode"
        rc_nil_b = compile_expr(recv)
        if mname == "=="
          return "(((void)(" + rc_nil_b + ")), FALSE)"
        end
        return "(((void)(" + rc_nil_b + ")), TRUE)"
      end
      recv_fp_t = infer_type(recv)
      if (recv_fp_t == "float" && arg0_fp_t == "bigint") || (recv_fp_t == "bigint" && arg0_fp_t == "float") || (recv_fp_t == "float" && arg0_fp_t == "float")
        rc_fp = compile_expr(recv)
        arg_fp = compile_expr(aargs_fp[0])
        if recv_fp_t == "bigint"
          @needs_bigint = 1
          rc_fp = "(mrb_float)sp_bigint_to_int((sp_Bigint *)" + rc_fp + ")"
        end
        if arg0_fp_t == "bigint"
          @needs_bigint = 1
          arg_fp = "(mrb_float)sp_bigint_to_int((sp_Bigint *)" + arg_fp + ")"
        end
        if mname == "+" || mname == "-" || mname == "*"
          return "(" + rc_fp + " " + mname + " " + arg_fp + ")"
        end
        if mname == "/"
          return "(" + rc_fp + " / " + arg_fp + ")"
        end
        if mname == "<" || mname == ">" || mname == "<=" || mname == ">=" || mname == "==" || mname == "!="
          return "(" + rc_fp + " " + mname + " " + arg_fp + ")"
        end
      end
    end
    if lt == "bigint"
      rc_raw = compile_expr(recv)
 # Cast away volatile from bigint locals (see compile_bigint_arg).
 # `infer_type(recv)` may say "int" for an arith CallNode whose
 # actual emit is bigint (operand-side promote — cache stale).
 # Peek the operands so we don't wrap an already-bigint sub-
 # expression with another sp_bigint_new_int (canonical
 # left-associative `a + b + c` chain shape, three bigint locals).
      recv_t_op = infer_type(recv)
 # `infer_type(recv)` may say "int" for an arith/bitop CallNode
 # whose actual emit is sp_Bigint *. Use the recursive walker to
 # decide whether rc_raw is already a bigint expression. Without
 # this we'd wrap an already-bigint sub-expression with another
 # sp_bigint_new_int (canonical left-associative chain shape:
 # `(a + b + c)` with three bigint locals, or
 # `((a | b) & c) | d` from optcarrot's flag-pack code).
      if recv_t_op != "bigint" && expr_emit_is_bigint(recv) == 1
        recv_t_op = "bigint"
      end
      rc = recv_t_op == "bigint" ? "(sp_Bigint *)" + rc_raw : "sp_bigint_new_int(" + rc_raw + ")"
      arg = compile_bigint_arg(nid)
      if mname == "+"
        return "sp_bigint_add(" + rc + ", " + arg + ")"
      end
      if mname == "-"
        return "sp_bigint_sub(" + rc + ", " + arg + ")"
      end
      if mname == "*"
        return "sp_bigint_mul(" + rc + ", " + arg + ")"
      end
      if mname == "/"
        return "sp_bigint_div(" + rc + ", " + arg + ")"
      end
      if mname == "%"
        return "sp_bigint_mod(" + rc + ", " + arg + ")"
      end
      if mname == "**" || mname == "pow"
        return "sp_bigint_pow(" + rc + ", " + compile_arg0(nid) + ")"
      end
      if mname == ">"
        return "(sp_bigint_cmp(" + rc + ", " + arg + ") > 0)"
      end
      if mname == "<"
        return "(sp_bigint_cmp(" + rc + ", " + arg + ") < 0)"
      end
      if mname == ">="
        return "(sp_bigint_cmp(" + rc + ", " + arg + ") >= 0)"
      end
      if mname == "<="
        return "(sp_bigint_cmp(" + rc + ", " + arg + ") <= 0)"
      end
      if mname == "=="
        return "(sp_bigint_cmp(" + rc + ", " + arg + ") == 0)"
      end
      if mname == "!="
        return "(sp_bigint_cmp(" + rc + ", " + arg + ") != 0)"
      end
 # Bitwise / shift on a bigint operand: route through the
 # sp_bigint_<op> helpers. Both operands are already boxed to
 # bigint (rc + arg via compile_bigint_arg), so the helper can
 # consume them directly. Helpers themselves round-trip through
 # int64 internally -- acceptable for the promote-mode common
 # case (small ints widened to bigint). The legacy in-line
 # `sp_bigint_new_int(unbox << unbox)` shape only fired when
 # `infer_type(recv) == "bigint"` exactly, which missed any
 # stale-int recv whose actual emit was bigint (the canonical
 # `(data << 1) & 255` shape in optcarrot's CPU emulator).
      if mname == "&"
        return "sp_bigint_and(" + rc + ", " + arg + ")"
      end
      if mname == "|"
        return "sp_bigint_or(" + rc + ", " + arg + ")"
      end
      if mname == "^"
        return "sp_bigint_xor(" + rc + ", " + arg + ")"
      end
      if mname == "<<"
        return "sp_bigint_shl(" + rc + ", sp_bigint_to_int(" + arg + "))"
      end
      if mname == ">>"
        return "sp_bigint_shr(" + rc + ", sp_bigint_to_int(" + arg + "))"
      end
    end
 # Operators
    if mname == "**" || mname == "pow"
      lt = infer_type(recv)
      if lt == "poly"
        @needs_rb_value = 1
        return "sp_poly_pow(" + compile_expr(recv) + ", " + box_expr_to_poly(get_args(@nd_arguments[nid])[0]) + ")"
      end
      if lt == "int" && mname == "pow"
        args_id = @nd_arguments[nid]
        if args_id >= 0
          a = get_args(args_id)
          if a.length >= 2
            return "sp_powmod(" + compile_expr(recv) + ", " + compile_expr(a[0]) + ", " + compile_expr(a[1]) + ")"
          end
        end
      end
      if lt == "int"
        return "((mrb_int)pow((double)" + compile_expr(recv) + ", (double)" + compile_arg0_as_int(nid) + "))"
      end
      return "pow(" + compile_expr(recv) + ", " + compile_arg0(nid) + ")"
    end
    if mname == "+"
      lt = infer_type(recv)
      if lt == "mutable_str"
        return "sp_str_concat(" + compile_expr(recv) + "->data, " + compile_arg0(nid) + ")"
      end
      if lt == "string"
        args_id = @nd_arguments[nid]
        if args_id >= 0
          arg_ids = get_args(args_id)
          if arg_ids.length > 0 && infer_type(arg_ids[0]) == "poly"
            return "sp_str_concat(" + compile_expr(recv) + ", sp_poly_to_s(" + compile_expr(arg_ids[0]) + "))"
          end
        end
 # Flatten chained string concat: a + b + c → sp_str_concat3(a,b,c)
        parts = collect_concat_chain(nid)
        if parts.length == 3
          return "sp_str_concat3(" + parts[0] + ", " + parts[1] + ", " + parts[2] + ")"
        end
        if parts.length == 4
          return "sp_str_concat4(" + parts[0] + ", " + parts[1] + ", " + parts[2] + ", " + parts[3] + ")"
        end
        if parts.length >= 5
 # Variable-length: single malloc for N parts via sp_str_concat_arr.
 # Hoist each part into a rooted temp first — the compound-literal
 # initializer order is unspecified, and any part that is a fresh
 # GC string would otherwise sit unrooted on the C stack while
 # later parts evaluate (and may trigger sp_gc_collect).
 # @needs_gc is set in scan_features for any string `+`, ensuring
 # SP_GC_SAVE() is in the function header before we emit roots here.
          tnames = "".split(",", -1)
          k = 0
          while k < parts.length
            t = new_temp
            emit("  const char * " + t + " = " + parts[k] + ";")
            emit("  SP_GC_ROOT(" + t + ");")
            tnames.push(t)
            k = k + 1
          end
          arr = "(const char *const[]){"
          k = 0
          while k < tnames.length
            if k > 0
              arr = arr + ", "
            end
            arr = arr + tnames[k]
            k = k + 1
          end
          arr = arr + "}"
          return "sp_str_concat_arr(" + arr + ", " + tnames.length.to_s + ")"
        end
        return "sp_str_concat(" + compile_expr(recv) + ", " + compile_arg0(nid) + ")"
      end
      if lt == "poly"
        @needs_rb_value = 1
        return "sp_poly_add(" + compile_expr(recv) + ", " + box_expr_to_poly(@nd_arguments[nid] >= 0 ? get_args(@nd_arguments[nid])[0] : -1) + ")"
      end
      if is_array_type(lt) == 1
        rhs_id_arr = @nd_arguments[nid] >= 0 ? get_args(@nd_arguments[nid])[0] : -1
        rhs_t_arr = rhs_id_arr >= 0 ? infer_type(rhs_id_arr) : ""
 # Heterogeneous Array#+ (issue #662). When the two arrays have
 # different element types, build a sp_PolyArray that boxes each
 # source element. Both ptr_array variants and the typed array
 # families fall into this path when the element types differ.
        if is_array_type(rhs_t_arr) == 1 && base_type(lt) != base_type(rhs_t_arr)
          @needs_rb_value = 1
          @needs_poly_array = 1
          @needs_gc = 1
          rc = compile_expr_gc_rooted(recv)
          arg = compile_arg0(nid)
          lt_pfx_p = array_c_prefix(lt)
          rt_pfx_p = array_c_prefix(rhs_t_arr)
          lt_elem_get = "sp_" + lt_pfx_p + "_get(" + rc + ", _i)"
          rt_elem_get = "sp_" + rt_pfx_p + "_get(" + arg + ", _i)"
          lt_box = elem_to_poly_box(lt, lt_elem_get)
          rt_box = elem_to_poly_box(rhs_t_arr, rt_elem_get)
          tmp = new_temp
          emit("  sp_PolyArray *" + tmp + " = sp_PolyArray_new();")
          emit("  { for (mrb_int _i = 0; _i < sp_" + lt_pfx_p + "_length(" + rc + "); _i++) sp_PolyArray_push(" + tmp + ", " + lt_box + "); }")
          emit("  { for (mrb_int _i = 0; _i < sp_" + rt_pfx_p + "_length(" + arg + "); _i++) sp_PolyArray_push(" + tmp + ", " + rt_box + "); }")
          return tmp
        end
        rc = compile_expr_gc_rooted(recv)
        arg = compile_arg0(nid)
        pfx = array_c_prefix(lt)
        tmp = new_temp
        itmp = new_temp
        emit("  " + c_type(lt) + tmp + " = sp_" + pfx + "_dup(" + rc + ");")
        emit("  for (mrb_int " + itmp + " = 0; " + itmp + " < sp_" + pfx + "_length(" + arg + "); " + itmp + "++)")
        emit("    sp_" + pfx + "_push(" + tmp + ", sp_" + pfx + "_get(" + arg + ", " + itmp + "));")
        return tmp
      end
      if lt == "complex"
        rhs_id_c = @nd_arguments[nid] >= 0 ? get_args(@nd_arguments[nid])[0] : -1
        if rhs_id_c >= 0 && infer_type(rhs_id_c) == "complex"
          return "sp_complex_add(" + compile_expr(recv) + ", " + compile_expr(rhs_id_c) + ")"
        end
      end
 # Time + Numeric — add n seconds (Float keeps sub-second via
 # sp_time_add), is_utc inherited. Result is a sp_Time so chained
 # .iso8601 etc. lower correctly.
      if lt == "time"
        return "sp_time_add(" + compile_expr(recv) + ", (mrb_float)(" + compile_arg0(nid) + "))"
      end
      args_id_add = @nd_arguments[nid]
      if args_id_add >= 0 && lt == "int"
        arg_ids_add = get_args(args_id_add)
        if arg_ids_add.length > 0 && infer_type(arg_ids_add[0]) == "int"
          return "sp_int_add(" + compile_expr(recv) + ", " + compile_arg0_as_int(nid) + ")"
        end
      end
      return "(" + compile_expr(recv) + " + " + compile_arg0_as_int(nid) + ")"
    end
    if mname == "-"
      lt = infer_type(recv)
      args_id = @nd_arguments[nid]
      if args_id < 0
 # Unary minus on int. `-INT64_MIN` overflows; the helper raises.
        if lt == "int"
          return "sp_int_neg(" + compile_expr(recv) + ")"
        end
        if lt == "bigint"
          @needs_bigint = 1
          return "sp_bigint_sub(sp_bigint_new_int(0), (sp_Bigint *)" + compile_expr(recv) + ")"
        end
        return "(-" + compile_expr(recv) + ")"
      end
      if lt == "poly"
        @needs_rb_value = 1
        return "sp_poly_sub(" + compile_expr(recv) + ", " + box_expr_to_poly(get_args(args_id)[0]) + ")"
      end
 # Hoist both sides into temps: each may be a fresh sp_time_now()
 # call, and tv_sec / tv_nsec are read twice each. Subtract the
 # integer fields *before* converting to float so we don't lose
 # bits when both timestamps are large (`tv_sec` past 2^53 seconds
 # falls outside double's exact-integer range, where the difference
 # `(double)a - (double)b` could miss the low-order bits even
 # though `(int64_t)(a - b)` is exact).
      if lt == "time"
        rhs_id = get_args(args_id)[0]
        if infer_type(rhs_id) == "time"
          return "({ sp_Time _a = " + compile_expr(recv) + "; sp_Time _b = " + compile_expr(rhs_id) + "; (mrb_float)(_a.tv_sec - _b.tv_sec) + (mrb_float)(_a.tv_nsec - _b.tv_nsec) / 1e9; })"
        end
 # Time - Numeric — subtract n seconds (Float keeps sub-second
 # via sp_time_add), is_utc inherited. Returns a sp_Time (CRuby:
 # Time - Time is Float, Time - Numeric is Time).
        return "sp_time_add(" + compile_expr(recv) + ", -(mrb_float)(" + compile_arg0(nid) + "))"
      end
      r = compile_array_setop_expr(nid, recv, "difference", lt)
      if r != ""
        return r
      end
 # Overflow-checked int - int (BIGINT.md option β). See `+` arm.
      if lt == "int"
        arg_ids_sub = get_args(args_id)
        if arg_ids_sub.length > 0 && infer_type(arg_ids_sub[0]) == "int"
          return "sp_int_sub(" + compile_expr(recv) + ", " + compile_arg0_as_int(nid) + ")"
        end
      end
      return "(" + compile_expr(recv) + " - " + compile_arg0_as_int(nid) + ")"
    end
    if mname == "*"
      lt = infer_type(recv)
      if lt == "string"
        return "sp_str_repeat(" + compile_expr(recv) + ", " + compile_arg0(nid) + ")"
      end
      if lt == "poly"
        @needs_rb_value = 1
        return "sp_poly_mul(" + compile_expr(recv) + ", " + box_expr_to_poly(get_args(@nd_arguments[nid])[0]) + ")"
      end
      if is_array_type(lt) == 1
 # `Array * String` is join, not repeat. Without this dispatch the
 # int-count repeat path below treats the string pointer as a loop
 # count and either blows out memory or emits garbage.
        args_id_am = @nd_arguments[nid]
        if args_id_am >= 0
          aa_am = get_args(args_id_am)
          if aa_am.length > 0 && infer_type(aa_am[0]) == "string"
            if lt == "int_array"
              return "sp_IntArray_join(" + compile_expr(recv) + ", " + compile_arg0(nid) + ")"
            end
            if lt == "str_array"
              return "sp_StrArray_join(" + compile_expr(recv) + ", " + compile_arg0(nid) + ")"
            end
          end
        end
 # All array kinds expose `_new` / `_length` / `_get` / `_push` with
 # the same shape, so the repeat loop is a single template
 # parameterized by the C prefix.
        mark_array_runtime_needs(lt)
        @needs_gc = 1
        pfx = array_c_prefix(lt)
        tmp = new_temp
        src = new_temp
        cnt = new_temp
        emit("  sp_" + pfx + " *" + src + " = " + compile_expr(recv) + ";")
        emit("  mrb_int " + cnt + " = " + compile_arg0(nid) + ";")
        emit("  sp_" + pfx + " *" + tmp + " = sp_" + pfx + "_new();")
        emit("  { mrb_int _mi; mrb_int _sl = sp_" + pfx + "_length(" + src + "); for (_mi = 0; _mi < " + cnt + "; _mi++) { mrb_int _mj; for (_mj = 0; _mj < _sl; _mj++) sp_" + pfx + "_push(" + tmp + ", sp_" + pfx + "_get(" + src + ", _mj)); } }")
        return tmp
      end
      if lt == "complex"
        rhs_id_cm = @nd_arguments[nid] >= 0 ? get_args(@nd_arguments[nid])[0] : -1
        if rhs_id_cm >= 0 && infer_type(rhs_id_cm) == "complex"
          return "sp_complex_mul(" + compile_expr(recv) + ", " + compile_expr(rhs_id_cm) + ")"
        end
      end
 # Overflow-checked int * int (BIGINT.md option β). See `+` arm.
      args_id_mul = @nd_arguments[nid]
      if args_id_mul >= 0 && lt == "int"
        arg_ids_mul = get_args(args_id_mul)
        if arg_ids_mul.length > 0 && infer_type(arg_ids_mul[0]) == "int"
          return "sp_int_mul(" + compile_expr(recv) + ", " + compile_arg0_as_int(nid) + ")"
        end
      end
      return "(" + compile_expr(recv) + " * " + compile_arg0_as_int(nid) + ")"
    end
    if mname == "/"
      lt = infer_type(recv)
      if lt == "poly"
        @needs_rb_value = 1
        return "sp_poly_div(" + compile_expr(recv) + ", " + box_expr_to_poly(get_args(@nd_arguments[nid])[0]) + ")"
      end
      if lt == "float"
        return "(" + compile_expr(recv) + " / " + compile_arg0(nid) + ")"
      end
 # Check RHS for float
      args_id = @nd_arguments[nid]
      if args_id >= 0
        aargs = get_args(args_id)
        if aargs.length > 0
          rt = infer_type(aargs.first)
          if rt == "float"
            return "((mrb_float)" + compile_expr(recv) + " / " + compile_arg0(nid) + ")"
          end
        end
      end
      return "sp_idiv(" + compile_expr(recv) + ", " + compile_arg0_as_int(nid) + ")"
    end
    if mname == "%"
      lt = infer_type(recv)
      if lt == "poly"
        @needs_rb_value = 1
        return "sp_poly_mod(" + compile_expr(recv) + ", " + box_expr_to_poly(get_args(@nd_arguments[nid])[0]) + ")"
      end
      if lt == "string" || lt == "mutable_str"
        args_id = @nd_arguments[nid]
        if args_id >= 0
          aargs = get_args(args_id)
          if aargs.length > 0
            rt = infer_type(aargs[0])
            if rt == "str_array"
              recv_c = compile_expr(recv)
              if lt == "mutable_str"
                recv_c = recv_c + "->data"
              end
 # The simple all-%s helper is fine when the format string
 # uses only bare %s placeholders. For anything richer
 # (`%-3s`, `%5s`, ...) box through the poly_array path.
              if @nd_type[recv] == "StringNode"
                lit_recv = @nd_unescaped[recv]
