                  block_ret_an = "poly_array"
                else
                  block_ret_an = infer_type(arrnew_pre_stmts.last)
                end
              end
            end
            an_ret_is_arr = (block_ret_an == "int_array" || block_ret_an == "float_array" || block_ret_an == "str_array" || block_ret_an == "sym_array")
            an_ret_is_deep_arr = (is_ptr_array_type(block_ret_an) == 1 || block_ret_an == "poly_array")
            arrnew_tmp = new_temp
            arrnew_iv = new_temp
            if block_ret_an == "string"
              @needs_str_array = 1
              emit("  sp_StrArray *" + arrnew_tmp + " = sp_StrArray_new();")
            elsif block_ret_an == "float"
              @needs_float_array = 1
              emit("  sp_FloatArray *" + arrnew_tmp + " = sp_FloatArray_new();")
            elsif block_ret_an == "poly"
              @needs_rb_value = 1
              emit("  sp_PolyArray *" + arrnew_tmp + " = sp_PolyArray_new();")
            elsif an_ret_is_deep_arr
              @needs_rb_value = 1
              emit("  sp_PolyArray *" + arrnew_tmp + " = sp_PolyArray_new();")
            elsif an_ret_is_arr
              @needs_ptr_array = 1
              emit("  sp_PtrArray *" + arrnew_tmp + " = sp_PtrArray_new();")
            else
              @needs_int_array = 1
              emit("  sp_IntArray *" + arrnew_tmp + " = sp_IntArray_new();")
            end
 # Root the new array before running the block body — pushing
 # poly/string values inside the loop can trigger a GC cycle
 # that would otherwise sweep the local pointer.
            emit("  SP_GC_ROOT(" + arrnew_tmp + ");")
            emit("  for (mrb_int " + arrnew_iv + " = 0; " + arrnew_iv + " < " + arrnew_count + "; " + arrnew_iv + "++) {")
            @indent = @indent + 1
            if arrnew_bp != ""
              arrnew_bp_t = find_var_type(arrnew_bp)
              if arrnew_bp_t == "bigint"
                @needs_bigint = 1
                emit("  lv_" + arrnew_bp + " = sp_bigint_new_int(" + arrnew_iv + ");")
              else
                emit("  lv_" + arrnew_bp + " = " + arrnew_iv + ";")
              end
            end
            if arrnew_body >= 0
              arrnew_stmts2 = get_stmts(arrnew_body)
              if arrnew_stmts2.length > 0
                arrnew_k = 0
                while arrnew_k < arrnew_stmts2.length - 1
                  compile_stmt(arrnew_stmts2[arrnew_k])
                  arrnew_k = arrnew_k + 1
                end
                if arrnew_empty_inner == 1
 # Skip compiling the `[]` / `[].dup` tail entirely —
 # we know it's an empty array; emit a fresh
 # sp_PolyArray instead so each inner is allocated as
 # the deferred-type container.
                  emit("  sp_PolyArray_push(" + arrnew_tmp + ", sp_box_poly_array(sp_PolyArray_new()));")
                else
                  arrnew_lastv = compile_expr(arrnew_stmts2.last)
                  if block_ret_an == "string"
                    emit("  sp_StrArray_push(" + arrnew_tmp + ", " + arrnew_lastv + ");")
                  elsif block_ret_an == "float"
                    emit("  sp_FloatArray_push(" + arrnew_tmp + ", " + arrnew_lastv + ");")
                  elsif block_ret_an == "poly"
                    emit("  sp_PolyArray_push(" + arrnew_tmp + ", " + arrnew_lastv + ");")
                  elsif an_ret_is_deep_arr
                    emit("  sp_PolyArray_push(" + arrnew_tmp + ", " + box_value_to_poly(block_ret_an, arrnew_lastv) + ");")
                  elsif an_ret_is_arr
                    emit("  sp_PtrArray_push(" + arrnew_tmp + ", (void *)(" + arrnew_lastv + "));")
                  else
 # promote-mode block tail may emit a bigint expr; unbox
 # for the int_array accumulator. Peek arith operands too —
 # `Array.new(N) { i * 2 }` with bigint i caches "int" but
 # emits sp_bigint_mul.
                    arrnew_tail_t = infer_type(arrnew_stmts2.last)
                    if arrnew_tail_t != "bigint" && expr_emit_is_bigint(arrnew_stmts2.last) == 1
                      arrnew_tail_t = "bigint"
                    end
                    if arrnew_tail_t == "bigint"
                      @needs_bigint = 1
                      arrnew_lastv = "sp_bigint_to_int((sp_Bigint *)" + arrnew_lastv + ")"
                    end
                    emit("  sp_IntArray_push(" + arrnew_tmp + ", " + arrnew_lastv + ");")
                  end
                end
              end
            end
            @indent = @indent - 1
            emit("  }")
            return arrnew_tmp
          end
        end
        if args_id >= 0
          aargs = get_args(args_id)
          if aargs.length >= 2
 # Array.new(n, val) - check fill value type
            vt = infer_type(aargs[1])
            if vt == "float"
              @needs_float_array = 1
              tmp = new_temp
              emit("  sp_FloatArray *" + tmp + " = sp_FloatArray_new();")
              emit("  { mrb_int _n = " + compile_expr_as_int(aargs.first) + "; mrb_float _v = " + compile_expr(aargs[1]) + "; for (mrb_int _i = 0; _i < _n; _i++) sp_FloatArray_push(" + tmp + ", _v); }")
              return tmp
            end
            if vt == "string"
              @needs_str_array = 1
              tmp = new_temp
              emit("  sp_StrArray *" + tmp + " = sp_StrArray_new();")
              emit("  { mrb_int _n = " + compile_expr_as_int(aargs.first) + "; const char *_v = " + compile_expr(aargs[1]) + "; for (mrb_int _i = 0; _i < _n; _i++) sp_StrArray_push(" + tmp + ", _v); }")
              return tmp
            end
 # `Array.new(n, nil)` -- the fill value is the nil singleton, so
 # the resulting array's element slots are sp_RbVal with the nil
 # tag set. Lowering to int_array would push 0 into each slot
 # (the C default), and `.inspect` would print "[0, 0, 0]" instead
 # of MRI's "[nil, nil, nil]". Use sp_PolyArray with sp_box_nil()
 # as the fill so downstream `[i]` reads, `inspect`, and `nil?`
 # see the actual nil. Same shape as the pointer-type arm below
 # but with a poly slot rather than a typed pointer.
            if vt == "nil"
              @needs_gc = 1
              @needs_rb_value = 1
              tmp = new_temp
              emit("  sp_PolyArray *" + tmp + " = sp_PolyArray_new();")
              emit("  { mrb_int _n = " + compile_expr_as_int(aargs.first) + "; for (mrb_int _i = 0; _i < _n; _i++) sp_PolyArray_push(" + tmp + ", sp_box_nil()); }")
              return tmp
            end
 # Pointer-type fills (objects, other arrays) need a typed PtrArray
 # so the GC scans the elements. Without this they'd be pushed
 # into an int_array and silently swept.
            if type_is_pointer(vt) == 1
              @needs_gc = 1
              tmp = new_temp
              emit("  sp_PtrArray *" + tmp + " = sp_PtrArray_new();")
              emit("  { mrb_int _n = " + compile_expr_as_int(aargs.first) + "; void *_v = (void *)(" + compile_expr(aargs[1]) + "); for (mrb_int _i = 0; _i < _n; _i++) sp_PtrArray_push(" + tmp + ", _v); }")
              return tmp
            end
            @needs_int_array = 1
            tmp = new_temp
            emit("  sp_IntArray *" + tmp + " = sp_IntArray_new();")
            emit("  { mrb_int _n = " + compile_expr_as_int(aargs.first) + "; mrb_int _v = " + compile_expr(aargs[1]) + "; for (mrb_int _i = 0; _i < _n; _i++) sp_IntArray_push(" + tmp + ", _v); }")
            return tmp
          end
 # `Array.new(n)` (single arg, no fill value) creates an array of
 # n nils in CRuby. The empty-IntArray lowering produced an array
 # of length 0, so a subsequent `Array.new(3) == [nil, nil, nil]`
 # compared `[]` against the RHS and surfaced false. Issue #619
 # puzzle 4. Lowering matches the `Array.new(n, nil)` arm above
 # since that's the actual CRuby semantic.
          if aargs.length == 1 && @nd_block[nid] < 0
            @needs_gc = 1
            @needs_rb_value = 1
            tmp = new_temp
            emit("  sp_PolyArray *" + tmp + " = sp_PolyArray_new();")
            emit("  { mrb_int _n = " + compile_expr_as_int(aargs.first) + "; for (mrb_int _i = 0; _i < _n; _i++) sp_PolyArray_push(" + tmp + ", sp_box_nil()); }")
            return tmp
          end
        end
        @needs_int_array = 1
        return "sp_IntArray_new()"
      end
      if cname == "String"
 # `String.new` and `String.new("seed")` produce the same
 # sp_String * value that `s = ""` widens into when
 # followed by `<<`. Mirror sp_String_new's signature: a
 # NUL-terminated seed (defaulting to "") that the runtime
 # copies into the freshly allocated buffer.
        @needs_mutable_str = 1
        @needs_gc = 1
        args_id = @nd_arguments[nid]
        if args_id >= 0
          aargs = get_args(args_id)
          if aargs.length >= 1
            return "sp_String_new(" + compile_expr(aargs.first) + ")"
          end
        end
        return "sp_String_new(\"\")"
      end
      if cname == "Hash"
        @needs_str_int_hash = 1
        @needs_gc = 1
        args_id = @nd_arguments[nid]
        if args_id >= 0
          aargs = get_args(args_id)
          if aargs.length >= 1 && @nd_block[nid] < 0
 # `Hash.new(default_value)` -- propagate the default to the
 # appropriate hash variant via `_new_with_default(d)`. The
 # default carries through `_get` (returns it on miss), `_dup`
 # / `_merge` (copied to the result), and is reachable via
 # `Hash#default` / `Hash#default=`. Block-form
 # `Hash.new { |h, k| ... }` is a separate feature (proc-default)
 # and falls through to the bare `_new` path below. Issue
 # #600 puzzle 2.
            dt = infer_type(aargs.first)
            dv = compile_expr(aargs.first)
            if dt == "string"
              @needs_str_str_hash = 1
              return "sp_StrStrHash_new_with_default(" + dv + ")"
            end
            if dt == "int" || dt == "bool" || dt == "nil"
              return "sp_StrIntHash_new_with_default((mrb_int)(" + dv + "))"
            end
 # Other default types (Array, Hash, obj_<C>, etc.) need a
 # poly-valued hash to hold them. Fall through to plain
 # str_int_hash for now -- the analyzer pins the variant at
 # str_int_hash anyway, so the codegen-side variant picker
 # would mismatch. Sibling carve to extend coverage.
            return "sp_StrIntHash_new()"
          end
        end
        return "sp_StrIntHash_new()"
      end
      if cname == "StringIO"
        @needs_stringio = 1
        args_id = @nd_arguments[nid]
        if args_id >= 0
          aargs = get_args(args_id)
          if aargs.length >= 1
            return "sp_StringIO_new_s(" + compile_expr(aargs.first) + ")"
          end
        end
        return "sp_StringIO_new()"
      end
 # `Object.new` — a sentinel allocation. Each call returns a fresh
 # GC-managed pointer so identity comparisons (`==` / `equal?`)
 # behave as in Ruby (distinct instances are not equal).
      if cname == "Object"
        @needs_gc = 1
        return "sp_Object_new()"
      end
 # Modules can't be instantiated; a `module M; def self.new ...`
 # is a user-defined class method, not a constructor. Fall back
 # to the normal CallNode dispatch so the actual cls method runs
 # and the declared return type takes effect. Without this, the
 # call site emitted sp_box_obj(<result>, <module_cls_id>) and
 # mis-boxed the return as if it were an instance of the module.
 # Issue #625.
      if module_name_exists(cname) == 1
        return ""
      end
      ci = find_class_idx(cname)
      if ci >= 0
        return "sp_" + cname + "_new(" + compile_constructor_args(ci, nid) + ")"
      end
    end
    ""
  end

  def compile_stringio_method_expr(nid, mname, rc)
    if mname == "string"
      return "sp_StringIO_string(" + rc + ")"
    end
    if mname == "pos" || mname == "tell"
      return "sp_StringIO_pos(" + rc + ")"
    end
    if mname == "size" || mname == "length"
      return "sp_StringIO_size(" + rc + ")"
    end
    if mname == "write"
      return "sp_StringIO_write(" + rc + ", " + compile_arg0(nid) + ")"
    end
    if mname == "read"
      args_id = @nd_arguments[nid]
      if args_id >= 0
        aargs = get_args(args_id)
        if aargs.length >= 1
          return "sp_StringIO_read_n(" + rc + ", " + compile_expr(aargs.first) + ")"
        end
      end
      return "sp_StringIO_read(" + rc + ")"
    end
    if mname == "gets"
      return "sp_StringIO_gets(" + rc + ")"
    end
    if mname == "getc"
      return "sp_StringIO_getc(" + rc + ")"
    end
    if mname == "getbyte"
      return "sp_StringIO_getbyte(" + rc + ")"
    end
    if mname == "puts"
      args_id = @nd_arguments[nid]
      if args_id >= 0
        aargs = get_args(args_id)
        if aargs.length >= 1
          emit("  sp_StringIO_puts(" + rc + ", " + compile_expr(aargs.first) + ");")
          return "0"
        end
      end
      emit("  sp_StringIO_puts_empty(" + rc + ");")
      return "0"
    end
    if mname == "print"
      emit("  sp_StringIO_print(" + rc + ", " + compile_arg0(nid) + ");")
      return "0"
    end
    if mname == "putc"
      return "sp_StringIO_putc(" + rc + ", " + compile_arg0(nid) + ")"
    end
    if mname == "rewind"
      emit("  sp_StringIO_rewind(" + rc + ");")
      return "0"
    end
    if mname == "seek"
      emit("  sp_StringIO_seek(" + rc + ", " + compile_arg0(nid) + ");")
      return "0"
    end
    if mname == "truncate"
      emit("  sp_StringIO_truncate(" + rc + ", " + compile_arg0(nid) + ");")
      return "0"
    end
    if mname == "close"
      emit("  sp_StringIO_close(" + rc + ");")
      return "0"
    end
    if mname == "eof?"
      return "sp_StringIO_eof_p(" + rc + ")"
    end
    if mname == "closed?"
      return "sp_StringIO_closed_p(" + rc + ")"
    end
    if mname == "flush"
      return "sp_StringIO_flush(" + rc + ")"
    end
    if mname == "sync"
      return "sp_StringIO_sync(" + rc + ")"
    end
    if mname == "isatty"
      return "sp_StringIO_isatty(" + rc + ")"
    end
    ""
  end

  def compile_string_method_expr(nid, mname, rc)
 # chomp! / chop! / etc. on a frozen string literal raise
 # FrozenError below; the mutable_str arm in compile_call_expr
 # handles the legal case before reaching here. Issues #859,
 # #886.
 # Comparable#clamp on string. Issue #899.
    if mname == "clamp"
      args_id_clp = @nd_arguments[nid]
      if args_id_clp >= 0
        a_clp = get_args(args_id_clp)
        if a_clp.length >= 2
          lo = compile_expr(a_clp[0])
          hi = compile_expr(a_clp[1])
          tmp_clp = new_temp
 # Single-evaluate rc/lo/hi into temps so strcmp side effects
 # don't fire twice when the clamp branches across the if/else.
          return "({ const char *" + tmp_clp + " = " + rc + "; const char *_lo = " + lo + "; const char *_hi = " + hi + "; strcmp(" + tmp_clp + ", _lo) < 0 ? _lo : (strcmp(" + tmp_clp + ", _hi) > 0 ? _hi : " + tmp_clp + "); })"
        end
      end
    end
 # String mutating methods called on a frozen string literal (recv
 # type "string", not "mutable_str"). MRI raises FrozenError;
 # spinel string literals are always frozen. The mutable_str arm
 # at compile_call_expr handles the legal case before reaching
 # here. Issue #886. The expression still yields a value so
 # downstream type inference doesn't break -- the raise is a
 # non-returning C call inside a stmt-expression.
    if mname == "insert" || mname == "prepend" || mname == "<<" || mname == "concat" || mname == "replace" || mname == "clear" ||
       mname == "chomp!" || mname == "chop!" || mname == "upcase!" || mname == "downcase!" || mname == "swapcase!" || mname == "capitalize!" ||
       mname == "sub!" || mname == "gsub!" || mname == "squeeze!" || mname == "strip!" || mname == "lstrip!" || mname == "rstrip!" ||
       mname == "tr!" || mname == "tr_s!" || mname == "delete!" || mname == "reverse!" || mname == "succ!" || mname == "next!"
      @needs_exc_class_hierarchy = 1
      return "({ sp_raise_cls(\"FrozenError\", \"can't modify frozen String\"); " + rc + "; })"
    end
 # String#<=> dispatches to strcmp clamped to -1/0/1.
 # Issue #900. Symmetric to the int / sym arms.
    if mname == "<=>"
      args_id_scmp = @nd_arguments[nid]
      if args_id_scmp >= 0
        a_scmp = get_args(args_id_scmp)
        if a_scmp.length >= 1
          arg_t_scmp = infer_type(a_scmp[0])
          if arg_t_scmp == "string" || arg_t_scmp == "mutable_str"
            arg_e_scmp = compile_expr(a_scmp[0])
            if arg_t_scmp == "mutable_str"
              arg_e_scmp = "(" + arg_e_scmp + ")->data"
            end
            cmp_scmp = "strcmp(" + rc + ", " + arg_e_scmp + ")"
            return "((" + cmp_scmp + ") < 0 ? (mrb_int)-1 : ((" + cmp_scmp + ") > 0 ? (mrb_int)1 : (mrb_int)0))"
          end
        end
      end
    end
 # is_a? / kind_of? / instance_of? for primitive String. Decide at
 # compile time based on Ruby's class hierarchy (String < Comparable
 # < Object). Anything outside that chain is FALSE.
    if mname == "is_a?" || mname == "kind_of?"
      args_id = @nd_arguments[nid]
      if args_id >= 0
        a = get_args(args_id)
        if a.length > 0
          arg_name = @nd_name[a[0]]
          if arg_name == "String" || arg_name == "Comparable" ||
             arg_name == "Object" || arg_name == "Kernel" || arg_name == "BasicObject"
            return "TRUE"
          end
          return "FALSE"
        end
      end
      return "FALSE"
    end
    if mname == "instance_of?"
      args_id = @nd_arguments[nid]
      if args_id >= 0
        a = get_args(args_id)
        if a.length > 0
          arg_name = @nd_name[a[0]]
          if arg_name == "String"
            return "TRUE"
          end
          return "FALSE"
        end
      end
      return "FALSE"
    end
 # String#each_char returns the receiver. Issue #866. Mirrors the
 # statement-level handler but emits a value (`rc`) so callers
 # like `s = "hi".each_char { ... }` get the string back.
    if mname == "each_char" && @nd_block[nid] >= 0
      bp_ec = get_block_param(nid, 0)
      if bp_ec == ""
        bp_ec = "_c"
      end
      tmp_ec = new_temp
      src_tmp_ec = new_temp
      cn_tmp_ec = new_temp
      char_buf_ec = new_temp
      emit("  const char *" + src_tmp_ec + " = " + rc + ";")
      emit("  for (mrb_int " + tmp_ec + " = 0; " + src_tmp_ec + "[" + tmp_ec + "]; ) {")
      emit("    int " + cn_tmp_ec + " = sp_utf8_advance(" + src_tmp_ec + " + " + tmp_ec + ");")
      emit("    char *" + char_buf_ec + " = sp_str_alloc_raw(" + cn_tmp_ec + " + 1);")
      emit("    memcpy(" + char_buf_ec + ", " + src_tmp_ec + " + " + tmp_ec + ", " + cn_tmp_ec + ");")
      emit("    " + char_buf_ec + "[" + cn_tmp_ec + "] = 0;")
      emit("    const char *lv_" + bp_ec + " = " + char_buf_ec + ";")
      @indent = @indent + 1
      push_scope
      declare_var(bp_ec, "string")
      compile_stmts_body(@nd_body[@nd_block[nid]])
      pop_scope
      @indent = @indent - 1
      emit("    " + tmp_ec + " += " + cn_tmp_ec + ";")
      emit("  }")
      return rc
    end
 # String#each_byte returns the receiver per CRuby. The statement-level
 # handler at compile_block_iteration_stmt emits the loop for `do …
 # end` / `{ … }` with no captured value; the expression-level form
 # (e.g. `ret = "hi".each_byte { ... }`) needs to produce the
 # receiver. Same loop body, just emit-then-return-rc.
    if mname == "each_byte" && @nd_block[nid] >= 0
      bp = get_block_param(nid, 0)
      if bp == ""
        bp = "_b"
      end
      itmp = new_temp
      src_tmp = new_temp
      emit("  const char *" + src_tmp + " = " + rc + ";")
      emit("  for (mrb_int " + itmp + " = 0; " + src_tmp + "[" + itmp + "]; " + itmp + "++) {")
      emit("    mrb_int lv_" + bp + " = (unsigned char)" + src_tmp + "[" + itmp + "];")
      @indent = @indent + 1
      push_scope
      declare_var(bp, "int")
      redo_label = push_redo_label
      emit_redo_label(redo_label)
      compile_stmts_body(@nd_body[@nd_block[nid]])
      pop_redo_label
      pop_scope
      @indent = @indent - 1
      emit("  }")
      return rc
    end
    if mname == "length"
 # Only use hoisted length if the receiver matches (otherwise we'd
 # return the wrong string's length).
      if @hoisted_strlen_var != "" && @hoisted_strlen_recv == rc
        return @hoisted_strlen_var
      end
      return "sp_str_length(" + rc + ")"
    end
    if mname == "to_i"
 # `"ff".to_i(16)` -- base-aware parse via sp_str_to_i_base.
 # Issue #883. The 0-arg form stays on sp_str_to_i_cruby (no
 # base prefix recognition; CRuby's plain `to_i` ignores `0x`).
      if @nd_arguments[nid] >= 0
        a_ti = get_args(@nd_arguments[nid])
        if a_ti.length > 0
          return "sp_str_to_i_base(" + rc + ", " + compile_expr_as_int(a_ti[0]) + ")"
        end
      end
      return "sp_str_to_i_cruby(" + rc + ")"
    end
    if mname == "to_f"
      return "atof(" + rc + ")"
    end
    if mname == "inspect" || mname == "dump"
 # String#dump and #inspect render the same quoted form for the
 # subset of characters sp_str_inspect already handles (basic
 # backslash escapes + \xHH for non-printable). CRuby's dump
 # adds a forced ASCII-7 fallback for high-byte sequences; that
 # divergence is documented but rare in practice.
      return "sp_str_inspect(" + rc + ")"
    end
    if mname == "upcase"
      return "sp_str_upcase(" + rc + ")"
    end
    if mname == "downcase"
      return "sp_str_downcase(" + rc + ")"
    end
    if mname == "swapcase"
      return "sp_str_swapcase(" + rc + ")"
    end
    if mname == "delete_prefix"
      return "sp_str_delete_prefix(" + rc + ", " + compile_arg0(nid) + ")"
    end
    if mname == "delete_suffix"
      return "sp_str_delete_suffix(" + rc + ", " + compile_arg0(nid) + ")"
    end
    if mname == "succ" || mname == "next"
      return "sp_str_succ(" + rc + ")"
    end
    if mname == "sum"
      tmp = new_temp
      itmp = new_temp
      emit("  mrb_int " + tmp + " = 0;")
      emit("  for (mrb_int " + itmp + " = 0; " + rc + "[" + itmp + "]; " + itmp + "++) " + tmp + " += (unsigned char)" + rc + "[" + itmp + "];")
      return tmp
    end
    if mname == "eql?"
      return "(strcmp(" + rc + ", " + compile_arg0(nid) + ") == 0)"
    end
    if mname == "partition"
      tt = "tuple:string,string,string"
      register_tuple_type(tt)
      @needs_gc = 1
      tname = tuple_c_name(tt)
      tmp = new_temp
      emit("  " + tname + " *" + tmp + " = (" + tname + " *)sp_gc_alloc(sizeof(" + tname + "), NULL, " + tuple_scan_name(tt) + ");")
