      @needs_gc = 1
      return "sp_str_split(" + rc + ", \"\")"
    end
 # Issue #903: String#codepoints returns int_array of codepoints.
    if mname == "codepoints"
      @needs_int_array = 1
      @needs_gc = 1
      return "sp_str_codepoints(" + rc + ")"
    end
    if mname == "bytes"
      @needs_int_array = 1
      @needs_gc = 1
 # `File.binread(path).bytes` — sp_str_bytes uses null-termination
 # so it stops at the first 0x00 byte, which is wrong for binary
 # data (e.g. .nes ROM files). Pattern-match the chained call
 # and emit a single binread-to-IntArray helper that reads with
 # the file's actual byte count.
      r = @nd_receiver[nid]
      if r >= 0 && @nd_type[r] == "CallNode"
        rmname = @nd_name[r]
        if rmname == "binread"
          rr = @nd_receiver[r]
          if rr >= 0 && @nd_type[rr] == "ConstantReadNode" && @nd_name[rr] == "File"
            rargs = @nd_arguments[r]
            if rargs >= 0
              ras = get_args(rargs)
              if ras.length >= 1
                @needs_file_io = 1
                return "sp_file_binread_bytes(" + compile_expr(ras[0]) + ")"
              end
            end
          end
        end
      end
      return "sp_str_bytes(" + rc + ")"
    end
 # String#unpack — returns a poly_array of boxed elements
 # (ints for numeric specs, strings for a/A/Z). Dispatches to
 # sp_str_unpack (lib/sp_pack.c, libspinel_rt.a).
    if mname == "unpack"
      args_id_up = @nd_arguments[nid]
      if args_id_up >= 0
        a_up = get_args(args_id_up)
        if a_up.length >= 1
          @needs_rb_value = 1
          return "sp_str_unpack(" + rc + ", " + compile_expr(a_up[0]) + ")"
        end
      end
    end
    if mname == "hex"
      return "((mrb_int)strtoll(" + rc + ", NULL, 16))"
    end
    if mname == "oct"
      return "((mrb_int)strtoll(" + rc + ", NULL, 8))"
    end
    if mname == "tr" || mname == "tr_s"
      args_id = @nd_arguments[nid]
      arg1 = "\"\""
      if args_id >= 0
        a = get_args(args_id)
        if a.length >= 2
          arg1 = compile_expr(a[1])
        end
      end
 # Issue #902: tr_s squeezes adjacent identical translated chars.
      helper = mname == "tr_s" ? "sp_str_tr_s" : "sp_str_tr"
      return helper + "(" + rc + ", " + compile_arg0(nid) + ", " + arg1 + ")"
    end
    if mname == "delete"
      return "sp_str_delete(" + rc + ", " + compile_arg0(nid) + ")"
    end
    if mname == "crypt"
 # 1-arg form (salt). 0-arg falls through (CRuby raises but
 # spinel keeps the contract permissive — empty salt = "..").
      args_id_cr = @nd_arguments[nid]
      salt_cr = "(&(\"\\xff\" \"..\")[1])"
      if args_id_cr >= 0
        a_cr = get_args(args_id_cr)
        if a_cr.length > 0
          salt_cr = compile_expr(a_cr[0])
        end
      end
      return "sp_str_crypt(" + rc + ", " + salt_cr + ")"
    end
    if mname == "scrub"
 # 1-arg: replacement string. 0-arg: NULL (helper falls back to U+FFFD).
      args_id_sc = @nd_arguments[nid]
      rep_sc = "NULL"
      if args_id_sc >= 0
        a_sc = get_args(args_id_sc)
        if a_sc.length > 0
          rep_sc = compile_expr(a_sc[0])
        end
      end
      return "sp_str_scrub(" + rc + ", " + rep_sc + ")"
    end
    if mname == "squeeze"
      return "sp_str_squeeze(" + rc + ")"
    end
    if mname == "size"
      if @hoisted_strlen_var != "" && @hoisted_strlen_recv == rc
        return @hoisted_strlen_var
      end
      return "sp_str_length(" + rc + ")"
    end
    if mname == "slice"
      args_id = @nd_arguments[nid]
      if args_id >= 0
        a = get_args(args_id)
        if a.length >= 2
          return "sp_str_sub_range(" + rc + ", " + compile_expr_as_int(a[0]) + ", " + compile_expr_as_int(a[1]) + ")"
        end
      end
      return "sp_str_sub_range(" + rc + ", " + compile_arg0_as_int(nid) + ", 1)"
    end
    if mname == "center"
      args_id = @nd_arguments[nid]
      if args_id >= 0
        a = get_args(args_id)
        if a.length >= 2
          return "sp_str_center2(" + rc + ", " + compile_expr(a[0]) + ", " + compile_expr(a[1]) + ")"
        end
      end
      return "sp_str_center(" + rc + ", " + compile_arg0(nid) + ")"
    end
    if mname == "lstrip"
      return "sp_str_lstrip(" + rc + ")"
    end
    if mname == "rstrip"
      return "sp_str_rstrip(" + rc + ")"
    end
    if mname == "dup"
      return "sp_str_dup(" + rc + ")"
    end
    if mname == "getbyte"
      return "((mrb_int)(unsigned char)(" + rc + ")[" + compile_arg0_as_int(nid) + "])"
    end
    if mname == "setbyte"
 # `s.setbyte(i, v)` mutates the receiver in place. Spinel
 # strings are stored as `const char *`, and compile-time
 # can't tell the writable heap buffers from rodata literals
 # at every receiver shape (LV pointing at a literal looks the
 # same as LV pointing at a dup). Issue #504 originally
 # disabled the emit because the prior naive cast SEGV'd on
 # literals; now the runtime helper sp_str_setbyte gates the
 # write on the marker byte at s[-1] (0xfe/0xfc heap, 0xfd
 # sp_String, 0xff literal -> no-op). Literal recvs stay safe;
 # `result = a.dup; result.setbyte(i, b)` (bm_ruby_xor) now
 # mutates.
      args_id_sb = @nd_arguments[nid]
      if args_id_sb >= 0
        a_sb = get_args(args_id_sb)
        if a_sb.length >= 2
          return "sp_str_setbyte(" + rc + ", " + compile_expr_as_int(a_sb[0]) + ", " + compile_expr_as_int(a_sb[1]) + ")"
        end
      end
      warn_unresolved_call(mname, "string")
      return "0"
    end
    if mname == "bytesize"
 # `sp_str_byte_len` reads the heap-string header's length field
 # for spinel-allocated buffers (preserving embedded NULs); falls
 # through to strlen for raw C string literals. Issue #593: a
 # `0.chr` buffer encodes \x00 + null terminator with header len=1
 # but strlen() saw only the first NUL and reported bytesize=0.
      return "(mrb_int)sp_str_byte_len(" + rc + ")"
    end
    if mname == "to_s"
      return rc
    end
    ""
  end

 # Resolve the literal RangeNode behind a method receiver, peeking
 # through a single ParenthesesNode wrap. Returns -1 when the receiver
 # isn't a literal range — in which case the runtime sp_Range struct is
 # used and exclude_end isn't tracked.
  def resolve_literal_range_recv(nid)
    recv = @nd_receiver[nid]
    if recv < 0
      return -1
    end
    if @nd_type[recv] == "RangeNode"
      return recv
    end
    if @nd_type[recv] == "ParenthesesNode"
      pb = @nd_body[recv]
      if pb >= 0
        ps = get_stmts(pb)
        if ps.length > 0 && @nd_type[ps.first] == "RangeNode"
          return ps.first
        end
      end
    end
    -1
  end

  def compile_range_method_expr(nid, mname, rc)
    if mname == "first" || mname == "begin" || mname == "min"
      return rc + ".first"
    end
    if mname == "last" || mname == "end" || mname == "max"
      return rc + ".last"
    end
 # String-range form: `("a".."z").include?("m")`. sp_Range only
 # holds int fields, so a string-typed RangeNode receiver can't
 # round-trip through it. When the receiver is a literal
 # RangeNode with String children, ignore `rc` and emit inline
 # strcmp bounds. Non-literal string ranges fall through to the
 # numeric path (which still mis-compiles for them — those are
 # explicitly outside the supported subset for now).
    if mname == "include?" || mname == "cover?" || mname == "==="
      lit_rg = resolve_literal_range_recv(nid)
      if lit_rg >= 0
        l_nid = @nd_left[lit_rg]
        r_nid = @nd_right[lit_rg]
        if l_nid >= 0 && r_nid >= 0 && infer_type(l_nid) == "string" && infer_type(r_nid) == "string"
          arg_s = compile_arg0(nid)
          left_s = compile_expr(l_nid)
          right_s = compile_expr(r_nid)
          op_rhs = (range_excl_end(lit_rg) == 1) ? "< 0" : "<= 0"
          return "(strcmp(" + arg_s + ", " + left_s + ") >= 0 && strcmp(" + arg_s + ", " + right_s + ") " + op_rhs + ")"
        end
      end
      tmp = new_temp
      emit("  sp_Range " + tmp + " = " + rc + ";")
      arg = compile_arg0_as_int(nid)
      return "(" + arg + " >= " + tmp + ".first && " + arg + " <= " + tmp + ".last)"
    end
    if mname == "overlap?"
 # `(a..b).overlap?(c..d)` for two numeric ranges reduces to
 # `a <= d && c <= b`. The arg must itself be a range (literal
 # or evaluated) — compile to an sp_Range struct.
      args_id_ov = @nd_arguments[nid]
      if args_id_ov >= 0
        a_ov = get_args(args_id_ov)
        if a_ov.length >= 1
          self_tmp = new_temp
          other_tmp = new_temp
          emit("  sp_Range " + self_tmp + " = " + rc + ";")
          emit("  sp_Range " + other_tmp + " = " + compile_expr(a_ov[0]) + ";")
          return "(" + self_tmp + ".first <= " + other_tmp + ".last && " + other_tmp + ".first <= " + self_tmp + ".last)"
        end
      end
      return "FALSE"
    end
    if mname == "to_a"
      @needs_int_array = 1
      @needs_gc = 1
 # Honour `...` exclusive Range when the receiver is a literal
 # RangeNode (or wrapped in parens). For non-literal Range values
 # held in sp_Range structs, exclude_end is not tracked at runtime
 # and the inclusive form is used.
      range_nid = resolve_literal_range_recv(nid)
      if range_nid >= 0
        rright = compile_expr(@nd_right[range_nid])
        if range_excl_end(range_nid) == 1
          rright = "(" + rright + ") - 1"
        end
        return "sp_IntArray_from_range(" + compile_expr(@nd_left[range_nid]) + ", " + rright + ")"
      end
      return "sp_IntArray_from_range(" + rc + ".first, " + rc + ".last)"
    end
    if mname == "length"
      return "(" + rc + ".last - " + rc + ".first + 1)"
    end
    if mname == "size"
      return "(" + rc + ".last - " + rc + ".first + 1)"
    end
    if mname == "min"
      return rc + ".first"
    end
    if mname == "max"
      range_nid = resolve_literal_range_recv(nid)
      if range_nid >= 0 && range_excl_end(range_nid) == 1
        return "(" + rc + ".last - 1)"
      end
      return rc + ".last"
    end
    if mname == "count"
 # Inclusive: last - first + 1. Exclusive (literal): last - first.
      range_nid = resolve_literal_range_recv(nid)
      if range_nid >= 0 && range_excl_end(range_nid) == 1
        return "(" + rc + ".last - " + rc + ".first)"
      end
      return "(" + rc + ".last - " + rc + ".first + 1)"
    end
 # `(a..b).any?/all?/none?/one? { |i| ... }` — the array-shape
 # predicate emitter already iterates ranges via emit_iter_open;
 # just route to it. Without this, the call falls through to the
 # unresolved-call warning and emits literal 0.
    if (mname == "any?" || mname == "all?" || mname == "none?" || mname == "one?") && @nd_block[nid] >= 0
      return compile_array_predicate_block(nid, rc, "range", mname)
    end
 # `(a..b).step(k)` -- returns an IntArray of a, a+k, ... up to b.
 # Without a block; block form is rarer and stays unhandled.
 # Issue #731.
    if mname == "step" && @nd_block[nid] < 0
      @needs_int_array = 1
      @needs_gc = 1
      step_arg = compile_arg0_as_int(nid)
      range_nid_step = resolve_literal_range_recv(nid)
      if range_nid_step >= 0
        rright_step = compile_expr(@nd_right[range_nid_step])
        if range_excl_end(range_nid_step) == 1
          rright_step = "(" + rright_step + ") - 1"
        end
        return "sp_IntArray_from_range_step(" + compile_expr(@nd_left[range_nid_step]) + ", " + rright_step + ", " + step_arg + ")"
      end
      return "sp_IntArray_from_range_step(" + rc + ".first, " + rc + ".last, " + step_arg + ")"
    end
    ""
  end

 # Symbol methods. rc is a sp_sym expression.
  def compile_symbol_method_expr(nid, mname, rc)
    if mname == "is_a?" || mname == "kind_of?"
      args_id = @nd_arguments[nid]
      if args_id >= 0
        a = get_args(args_id)
        if a.length > 0
          arg_name = @nd_name[a[0]]
          if arg_name == "Symbol" || arg_name == "Comparable" ||
             arg_name == "Object" || arg_name == "Kernel" || arg_name == "BasicObject"
            return "TRUE"
          end
          return "FALSE"
        end
      end
      return "FALSE"
    end
    if mname == "instance_of?"
      args_id = @nd_arguments[nid]
      if args_id >= 0
        a = get_args(args_id)
        if a.length > 0
          arg_name = @nd_name[a[0]]
          if arg_name == "Symbol"
            return "TRUE"
          end
          return "FALSE"
        end
      end
      return "FALSE"
    end
    if mname == "to_s" || mname == "id2name" || mname == "name"
      return "sp_sym_to_s(" + rc + ")"
    end
    if mname == "to_sym" || mname == "intern"
      return rc
    end
 # Symbol#upcase / Symbol#downcase: lower-case via the str case helper
 # then re-intern. Naming convention `sp_str_<mname>` lets one branch
 # handle both — and slots in cleanly for capitalize/swapcase later.
    if mname == "upcase" || mname == "downcase"
      return "sp_sym_intern(sp_str_" + mname + "(sp_sym_to_s(" + rc + ")))"
    end
    if mname == "inspect"
      return "sp_str_concat(SPL(\":\"), sp_sym_to_s(" + rc + "))"
    end
    if mname == "length" || mname == "size"
      return "((mrb_int)strlen(sp_sym_to_s(" + rc + ")))"
    end
    if mname == "empty?"
      return "(sp_sym_to_s(" + rc + ")[0] == 0)"
    end
    if mname == "hash"
      return "((mrb_int)" + rc + ")"
    end
    if mname == "<=>"
      args_id = @nd_arguments[nid]
      if args_id >= 0
        aargs = get_args(args_id)
        if aargs.length >= 1
          at = infer_type(aargs[0])
          if at == "symbol"
            other = compile_expr(aargs[0])
 # Lexical compare on symbol names (Ruby semantics)
            cmp = "strcmp(sp_sym_to_s(" + rc + "), sp_sym_to_s(" + other + "))"
            return "((" + cmp + ") < 0 ? (mrb_int)-1 : ((" + cmp + ") > 0 ? (mrb_int)1 : (mrb_int)0))"
          end
        end
      end
      return "0"
    end
    if mname == "==" || mname == "eql?"
      args_id = @nd_arguments[nid]
      if args_id >= 0
        aargs = get_args(args_id)
        if aargs.length >= 1
          at = infer_type(aargs[0])
          if at == "symbol"
            return "(" + rc + " == " + compile_expr(aargs[0]) + ")"
          end
 # Symbol != anything-non-symbol in Ruby
          return "FALSE"
        end
      end
    end
    if mname == "!="
      args_id = @nd_arguments[nid]
      if args_id >= 0
        aargs = get_args(args_id)
        if aargs.length >= 1
          at = infer_type(aargs[0])
          if at == "symbol"
            return "(" + rc + " != " + compile_expr(aargs[0]) + ")"
          end
          return "TRUE"
        end
      end
    end
    ""
  end

  def compile_int_method_expr(nid, mname, rc)
 # is_a? / kind_of? on a primitive int: resolve at compile time. The
 # arg is a class constant (Integer / Numeric / Comparable / etc.);
 # answer based on Ruby's class hierarchy. Anything not in the int
 # ancestor chain is FALSE.
    if mname == "is_a?" || mname == "kind_of?"
      args_id = @nd_arguments[nid]
      if args_id >= 0
        a = get_args(args_id)
        if a.length > 0
          arg_name = @nd_name[a[0]]
          if arg_name == "Integer" || arg_name == "Numeric" ||
             arg_name == "Comparable" || arg_name == "Object" ||
             arg_name == "Kernel" || arg_name == "BasicObject"
            return "TRUE"
          end
          return "FALSE"
        end
      end
      return "FALSE"
    end
 # instance_of? is is_a? without superclass / mixin matching.
    if mname == "instance_of?"
      args_id = @nd_arguments[nid]
      if args_id >= 0
        a = get_args(args_id)
        if a.length > 0
          arg_name = @nd_name[a[0]]
          if arg_name == "Integer"
            return "TRUE"
          end
          return "FALSE"
        end
      end
      return "FALSE"
    end
    if mname == "to_s"
      if @nd_arguments[nid] >= 0
        aargs = get_args(@nd_arguments[nid])
        if aargs.length > 0
          return "sp_int_to_s_base(" + rc + ", " + compile_expr(aargs[0]) + ")"
        end
      end
      return "sp_int_to_s(" + rc + ")"
    end
    if mname == "inspect"
      return "sp_int_to_s(" + rc + ")"
    end
 # `int <=> other` -- standard 3-way compare. Without this arm
 # the int-recv fallback at compile_call_expr's tail picks a
 # user-defined `<=>` and recurses. Comparable's
 # `<` / `>` / `<=` / `>=` already route to a numeric compare
 # in compile_call_expr; `<=>` itself was missing.
    if mname == "<=>"
      args_id_cmp = @nd_arguments[nid]
      if args_id_cmp >= 0
        a_cmp = get_args(args_id_cmp)
        if a_cmp.length >= 1
          rt_cmp = infer_type(a_cmp[0])
          if rt_cmp == "int" || rt_cmp == "float"
            arg_e = compile_expr(a_cmp[0])
            return "((" + rc + ") < (" + arg_e + ") ? (mrb_int)-1 : ((" + rc + ") > (" + arg_e + ") ? (mrb_int)1 : (mrb_int)0))"
          end
        end
      end
    end
    if mname == "digits"
      @needs_int_array = 1
      @needs_gc = 1
      base = "10"
      if @nd_arguments[nid] >= 0
        aargs = get_args(@nd_arguments[nid])
        if aargs.length > 0
          base = compile_expr(aargs[0])
        end
      end
      return "sp_int_digits(" + rc + ", " + base + ")"
    end
    if mname == "bit_length"
 # Number of bits needed to represent the integer (excluding sign)
      return "((" + rc + ") < 0 ? (64 - __builtin_clzll((uint64_t)~(" + rc + "))) : ((" + rc + ") == 0 ? 0 : (64 - __builtin_clzll((uint64_t)(" + rc + ")))))"
    end
    if mname == "fdiv"
      return "((mrb_float)(" + rc + ") / (mrb_float)" + compile_arg0(nid) + ")"
    end
    if mname == "divmod"
      tt = "tuple:int,int"
      register_tuple_type(tt)
      @needs_gc = 1
      name = tuple_c_name(tt)
      arg = compile_arg0(nid)
      tmp = new_temp
      emit("  " + name + " *" + tmp + " = (" + name + " *)sp_gc_alloc(sizeof(" + name + "), NULL, " + tuple_scan_name(tt) + ");")
      emit("  " + tmp + "->_0 = sp_idiv(" + rc + ", " + arg + ");")
      emit("  " + tmp + "->_1 = sp_imod(" + rc + ", " + arg + ");")
      return tmp
    end
    if mname == "to_i"
      return rc
    end
    if mname == "to_f"
      return "(mrb_float)(" + rc + ")"
    end
    if mname == "abs" || mname == "magnitude"
      return "((" + rc + ") < 0 ? -(" + rc + ") : (" + rc + "))"
    end
    if mname == "modulo"
      return "sp_imod(" + rc + ", " + compile_arg0(nid) + ")"
    end
    if mname == "remainder"
 # Ruby's Integer#remainder uses truncated division (C `%`),
 # which differs from `%` (Ruby) / sp_imod (floored division)
 # for mixed-sign operands: -7.remainder(3) == -1.
      arg_rem = compile_arg0(nid)
      return "((" + rc + ") - (((" + rc + ") / (" + arg_rem + ")) * (" + arg_rem + ")))"
    end
 # Integer#size: bytes used to represent the integer. Spinel
 # stores mrb_int as int64, so always 8 on every supported
 # target. CRuby distinguishes Fixnum (machine word) from Bignum
 # (variable), but spinel's fixnum range is the whole 64-bit
 # space anyway. Issue #860.
    if mname == "size"
      return "8"
    end
    if mname == "even?"
      return "((" + rc + ") % 2 == 0)"
    end
    if mname == "odd?"
      return "((" + rc + ") % 2 != 0)"
    end
    if mname == "allbits?"
      mask = compile_arg0(nid)
      return "(((" + rc + ") & (" + mask + ")) == (" + mask + "))"
    end
    if mname == "anybits?"
      return "(((" + rc + ") & (" + compile_arg0(nid) + ")) != 0)"
    end
    if mname == "nobits?"
      return "(((" + rc + ") & (" + compile_arg0(nid) + ")) == 0)"
    end
    if mname == "zero?"
      return "((" + rc + ") == 0)"
    end
 # Integer#nonzero?: returns nil for 0, self otherwise. Uses the
 # int? nullable representation (SP_INT_NIL sentinel for nil).
 # Issue #874.
    if mname == "nonzero?"
      return "((" + rc + ") == 0 ? SP_INT_NIL : (" + rc + "))"
    end
    if mname == "gcd"
      return "sp_gcd(" + rc + ", " + compile_arg0(nid) + ")"
    end
    if mname == "lcm"
      return "sp_lcm(" + rc + ", " + compile_arg0(nid) + ")"
    end
 # Integer#quo: returns a Rational. Issue #872.
    if mname == "quo"
      return "sp_rational_new(" + rc + ", " + compile_arg0(nid) + ")"
    end
 # Integer#gcdlcm: [gcd, lcm]. Emitted as a tuple value via the
 # same registered-tuple path divmod uses. Issue #894.
    if mname == "gcdlcm"
      tt_gl = "tuple:int,int"
      register_tuple_type(tt_gl)
      @needs_gc = 1
      name_gl = tuple_c_name(tt_gl)
      arg_gl = compile_arg0(nid)
      tmp_gl = new_temp
      emit("  " + name_gl + " *" + tmp_gl + " = (" + name_gl + " *)sp_gc_alloc(sizeof(" + name_gl + "), NULL, " + tuple_scan_name(tt_gl) + ");")
      emit("  " + tmp_gl + "->_0 = sp_gcd(" + rc + ", " + arg_gl + ");")
      emit("  " + tmp_gl + "->_1 = sp_lcm(" + rc + ", " + arg_gl + ");")
      return tmp_gl
    end
    if mname == "ceildiv"
      return "sp_ceildiv(" + rc + ", " + compile_arg0(nid) + ")"
    end
    if mname == "div"
      return "sp_idiv(" + rc + ", " + compile_arg0(nid) + ")"
    end
    if mname == "clamp"
      args_id = @nd_arguments[nid]
      if args_id >= 0
        a = get_args(args_id)
        if a.length >= 2
          return "sp_int_clamp(" + rc + ", " + compile_expr(a[0]) + ", " + compile_expr(a[1]) + ")"
        end
      end
    end
    if mname == "frozen?"
      return "TRUE"
    end
    if mname == "chr"
      return "sp_int_chr(" + rc + ")"
    end
    if mname == "succ" || mname == "next"
      return "((" + rc + ") + 1)"
    end
    if mname == "pred"
      return "((" + rc + ") - 1)"
    end
    if mname == "itself"
      return rc
    end
 # Integer#[idx] — bit indexing. `n[k]` returns bit k of n.
 # Skip when the receiver is a constant reference (ENV, STDIN,
 # ::ARGV, ...) — those resolve their type to the int fallback at
 # infer_type's tail and would otherwise eat the constant's own
 # `[]` dispatch (e.g. ENV["HOME"] → getenv, ::ARGV[i] → argv).
    if mname == "[]"
      recv_id = @nd_receiver[nid]
      if recv_id >= 0 && (@nd_type[recv_id] == "ConstantReadNode" || @nd_type[recv_id] == "ConstantPathNode")
        return ""
      end
      args_id = @nd_arguments[nid]
      if args_id >= 0
        aargs = get_args(args_id)
        if aargs.length > 0
 # Skip bit-extract when the index is a non-int — `row[:id]`
 # / `row["id"]` is hash subscript, not bit indexing on an
 # integer. Without this gate, a poly/hash-receiver param
 # that defaulted to "int" (no upstream pinning) routed
 # `row[:id]` to `(row >> SPS_id) & 1`, shifting an int by
 # the symbol's interned id (>= 64) which is undefined
 # behavior under -Wshift-count-overflow. Surfaces in
 # Roundhouse's `def self.from_raw(row); row[:id] || 0;
 # end` where `row` is unpinned. (Roundhouse
 # warnings family).
          idx_t = infer_type(aargs[0])
          if idx_t != "int" && idx_t != "poly"
            return ""
          end
          idx = compile_expr(aargs[0])
          return "(((" + rc + ") >> (" + idx + ")) & 1)"
        end
      end
    end
 # Integer#times / upto / downto in expression position. The stmt
 # form is handled by compile_block_iteration_stmt; the expression
 # form needs the same loop emit but a value too -- return self
 # per MRI. Issue #877.
    if (mname == "times" || mname == "upto" || mname == "downto") && @nd_block[nid] >= 0
      if mname == "times"
        compile_times_block(nid)
      elsif mname == "upto"
        compile_upto_block(nid)
      else
        compile_downto_block(nid)
      end
      return rc
    end
    ""
  end

  def compile_float_method_expr(nid, mname, rc)
    if mname == "is_a?" || mname == "kind_of?"
      args_id = @nd_arguments[nid]
      if args_id >= 0
        a = get_args(args_id)
        if a.length > 0
          arg_name = @nd_name[a[0]]
          if arg_name == "Float" || arg_name == "Numeric" ||
             arg_name == "Comparable" || arg_name == "Object" ||
             arg_name == "Kernel" || arg_name == "BasicObject"
            return "TRUE"
          end
          return "FALSE"
        end
      end
      return "FALSE"
    end
    if mname == "instance_of?"
      args_id = @nd_arguments[nid]
      if args_id >= 0
        a = get_args(args_id)
        if a.length > 0
          arg_name = @nd_name[a[0]]
          if arg_name == "Float"
            return "TRUE"
          end
          return "FALSE"
        end
      end
      return "FALSE"
    end
    if mname == "itself"
      return rc
    end
    if mname == "to_s"
      return "sp_float_to_s(" + rc + ")"
    end
    if mname == "inspect"
      return "sp_float_inspect(" + rc + ")"
    end
    if mname == "to_i"
      return "(mrb_int)(" + rc + ")"
    end
    if mname == "to_f"
      return "(" + rc + ")"
    end
 # ceil/floor/round/truncate with precision arg use a GCC stmt-expr so
 # the argument expression is compiled-and-emitted once on the Ruby
 # side and pow(10, n) is evaluated once at runtime — the original
 # form double-evaluated both, which broke any side-effecting arg.
    if mname == "ceil"
      if @nd_arguments[nid] >= 0
        arg = compile_arg0(nid)
        return "({ double _f = pow(10, " + arg + "); ceil((" + rc + ") * _f) / _f; })"
      end
      return "(mrb_int)ceil(" + rc + ")"
    end
    if mname == "floor"
      if @nd_arguments[nid] >= 0
        arg = compile_arg0(nid)
        return "({ double _f = pow(10, " + arg + "); floor((" + rc + ") * _f) / _f; })"
      end
      return "(mrb_int)floor(" + rc + ")"
    end
    if mname == "round"
      if @nd_arguments[nid] >= 0
        arg = compile_arg0(nid)
        return "({ double _f = pow(10, " + arg + "); round((" + rc + ") * _f) / _f; })"
      end
      return "(mrb_int)round(" + rc + ")"
    end
    if mname == "abs"
      return "fabs(" + rc + ")"
    end
    if mname == "nan?"
      return "(isnan(" + rc + ") ? TRUE : FALSE)"
    end
    if mname == "finite?"
      return "(isfinite(" + rc + ") ? TRUE : FALSE)"
    end
    if mname == "infinite?"
      return "(isinf(" + rc + ") ? (" + rc + " < 0 ? -1 : 1) : 0)"
    end
    if mname == "truncate"
      if @nd_arguments[nid] >= 0
        arg = compile_arg0(nid)
        return "({ double _f = pow(10, " + arg + "); trunc((" + rc + ") * _f) / _f; })"
      end
      return "(mrb_int)trunc(" + rc + ")"
    end
    if mname == "fdiv"
      return "((" + rc + ") / (mrb_float)" + compile_arg0(nid) + ")"
    end
    if mname == "divmod"
      tt = "tuple:int,float"
      register_tuple_type(tt)
      @needs_gc = 1
      tname = tuple_c_name(tt)
      arg = compile_arg0(nid)
      tmp = new_temp
      @needs_setjmp = 1
      # CRuby raises:
      #   ZeroDivisionError on `1.0.divmod(0)` / `divmod(0.0)`.
      #   FloatDomainError("NaN") on NaN dividend or NaN divisor.
      # Bind both operands to float locals before the raise checks so
      # they're each evaluated exactly once and so gcc can't constant-
      # fold `1.0 / 0LL` and trip -Wdiv-by-zero on the literal-zero
      # path below. The (mrb_int)floor cast on a NaN result would also
      # be C undefined behaviour; raise before reaching it.
      recv_tmp = new_temp
      arg_tmp = new_temp
      emit("  mrb_float " + recv_tmp + " = (mrb_float)(" + rc + ");")
      emit("  mrb_float " + arg_tmp + " = (mrb_float)(" + arg + ");")
      emit("  if (" + arg_tmp + " == 0.0) sp_raise_cls(\"ZeroDivisionError\", \"divided by 0\");")
      emit("  if (" + arg_tmp + " != " + arg_tmp + " || " + recv_tmp + " != " + recv_tmp + ") sp_raise_cls(\"FloatDomainError\", \"NaN\");")
      emit("  " + tname + " *" + tmp + " = (" + tname + " *)sp_gc_alloc(sizeof(" + tname + "), NULL, " + tuple_scan_name(tt) + ");")
      emit("  " + tmp + "->_0 = (mrb_int)floor(" + recv_tmp + " / " + arg_tmp + ");")
      emit("  " + tmp + "->_1 = " + recv_tmp + " - " + tmp + "->_0 * " + arg_tmp + ";")
      return tmp
    end
    ""
  end

  def compile_array_method_expr(nid, mname, rc, recv_type)
 # Skip non-array types. Without this guard a user class with a
 # method whose name happens to overlap an Array method (e.g.
 # `def sample`, `def first`) would be dispatched as that Array
 # method, with `array_c_prefix` falling back to `IntArray` and
 # the receiver pointer used as if it were an `sp_IntArray *`.
    if is_array_type(recv_type) == 0
      return ""
    end
 # Built-in Array method aliases. `at` -> `[]` and `append` -> `push`
 # apply only when the receiver is a built-in array; a user class
 # with `def at` / `def append` keeps its own dispatch via the
 # is_array_type guard above. Recurse so the local `mname` isn't
 # reassigned (a write to a parameter triggers a body-usage type
 # widening pass that makes warn_unresolved_call's mname param
 # land as poly in the bootstrap build). Issue #619 puzzles 8 / 9.
    if mname == "at"
      return compile_array_method_expr(nid, "[]", rc, recv_type)
    end
    if mname == "append"
      return compile_array_method_expr(nid, "push", rc, recv_type)
    end
 # Array#dig with a single index reduces to []. Multi-arg dig that
 # walks into nested arrays/hashes isn't supported here yet — fall
 # through to the unsupported-call warning.
    if mname == "dig"
      args_id = @nd_arguments[nid]
      if args_id >= 0
        aargs = get_args(args_id)
        if aargs.length == 1
          return compile_array_method_expr(nid, "[]", rc, recv_type)
        end
 # Multi-arg dig: get arr[idx0] then walk the remaining keys.
 # poly_array elements are sp_RbVal, so the inner traversal
 # reuses emit_dig_step's cls_id-aware Hash/Array dispatch.
 # Typed arrays (int_array / str_array / etc.) can't contain
 # nested containers so multi-arg dig is unreachable for
 # them; only the poly_array case fires here. Issue #555 case 07.
        if recv_type == "poly_array" && aargs.length >= 2
          @needs_rb_value = 1
          @needs_gc = 1
          idx_tmp_d = new_temp
          emit("  mrb_int " + idx_tmp_d + " = " + compile_expr(aargs[0]) + ";")
          acc_d = new_temp
          emit("  sp_RbVal " + acc_d + " = sp_PolyArray_get(" + rc + ", " + idx_tmp_d + ");")
          si_d = 1
          while si_d < aargs.length
            kt_d = infer_type(aargs[si_d])
            key_tmp_d = new_temp
            if kt_d == "symbol"
              emit("  sp_sym " + key_tmp_d + " = " + compile_expr(aargs[si_d]) + ";")
 # emit_dig_step references all 3 sym-keyed hash variants;
 # ensure each typedef is present so the cls_id dispatch
 # compiles even when the program never instantiated all of
 # them directly.
              @needs_sym_int_hash = 1
              @needs_sym_str_hash = 1
              @needs_sym_poly_hash = 1
            elsif kt_d == "string"
              emit("  const char *" + key_tmp_d + " = " + compile_expr_as_string(aargs[si_d]) + ";")
              @needs_str_poly_hash = 1
            elsif kt_d == "int"
              emit("  mrb_int " + key_tmp_d + " = " + compile_expr(aargs[si_d]) + ";")
            else
              emit("  mrb_int " + key_tmp_d + " = 0; (void)" + key_tmp_d + ";")
            end
            emit_dig_step(acc_d, key_tmp_d, kt_d)
            si_d = si_d + 1
          end
          return acc_d
        end
      end
    end
 # arr.slice!(from, n) — returns a fresh array of `n` elements
 # starting at `from` and removes them from the receiver. Each
 # array type lowers to its own runtime helper that mutates the
 # backing buffer in place. sym_array shares the IntArray helper
 # since symbols are stored as interned int IDs.
    if mname == "slice!"
      args_id = @nd_arguments[nid]
      if args_id >= 0
        aargs = get_args(args_id)
        if aargs.length >= 2
          from_e = compile_expr(aargs[0])
          n_e = compile_expr(aargs[1])
          if recv_type == "int_array" || recv_type == "sym_array"
            @needs_int_array = 1
            return "sp_IntArray_slice_bang(" + rc + ", " + from_e + ", " + n_e + ")"
          end
          if recv_type == "float_array"
            @needs_float_array = 1
            return "sp_FloatArray_slice_bang(" + rc + ", " + from_e + ", " + n_e + ")"
          end
          if recv_type == "str_array"
            @needs_str_array = 1
            return "sp_StrArray_slice_bang(" + rc + ", " + from_e + ", " + n_e + ")"
          end
          if is_ptr_array_type(recv_type) == 1
            @needs_ptr_array = 1
            return "sp_PtrArray_slice_bang(" + rc + ", " + from_e + ", " + n_e + ")"
          end
          if recv_type == "poly_array"
            @needs_poly_array = 1
            return "sp_PolyArray_slice_bang(" + rc + ", " + from_e + ", " + n_e + ")"
          end
        end
      end
    end
 # Array#inspect and Array#to_s (CRuby aliases them for arrays, so
 # the two share one definition via compile_inspect_for). Guard on
 # recv_type being an actual array type so scalar receivers with
 # the same method name (e.g. (poly).to_s, (int).to_s) fall through
 # to their own scalar dispatchers.
    if mname == "inspect" || mname == "to_s"
      if is_array_type(recv_type) == 1
        r = compile_inspect_for(recv_type, rc)
        if r != ""
          return r
        end
      end
    end
 # zip without block: return array of pairs/tuples
    if mname == "zip" && @nd_block[nid] < 0
      @needs_gc = 1
      pfx_recv = array_c_prefix(recv_type)
      args_id = @nd_arguments[nid]
      aargs = get_args(args_id)
 # Check if heterogeneous or multi-arg
      heterogeneous = 0
      k = 0
      while k < aargs.length
        at = infer_type(aargs[k])
        if at != recv_type
          heterogeneous = 1
        end
        k = k + 1
      end
      if aargs.length > 1
        heterogeneous = 1
      end
 # Compile all zip arguments
      arg_rcs = "".split(",", -1)
      arg_types = "".split(",", -1)
      k = 0
      while k < aargs.length
        arg_rcs.push(compile_expr(aargs[k]))
        arg_types.push(infer_type(aargs[k]))
        k = k + 1
      end
      tmp = new_temp
      itmp = new_temp
      pair_tmp = new_temp
      emit("  sp_PtrArray *" + tmp + " = sp_PtrArray_new();")
      emit("  for (mrb_int " + itmp + " = 0; " + itmp + " < sp_" + pfx_recv + "_length(" + rc + "); " + itmp + "++) {")
      if heterogeneous == 1
 # Build tuple type
        parts = "".split(",", -1)
        parts.push(elem_type_of_array(recv_type))
        k = 0
        while k < arg_types.length
          parts.push(elem_type_of_array(arg_types[k]))
          k = k + 1
        end
        tt = "tuple:" + parts.join(",")
        register_tuple_type(tt)
        tname = tuple_c_name(tt)
        emit("    " + tname + " *" + pair_tmp + " = (" + tname + " *)sp_gc_alloc(sizeof(" + tname + "), NULL, " + tuple_scan_name(tt) + ");")
        emit("    " + pair_tmp + "->_0 = sp_" + pfx_recv + "_get(" + rc + ", " + itmp + ");")
        k = 0
        while k < arg_rcs.length
          apfx = array_c_prefix(arg_types[k])
          emit("    " + pair_tmp + "->_" + (k + 1).to_s + " = sp_" + apfx + "_get(" + arg_rcs[k] + ", " + itmp + ");")
          k = k + 1
        end
      else
        emit("    " + c_type(recv_type) + " " + pair_tmp + " = sp_" + pfx_recv + "_new();")
        emit("    sp_" + pfx_recv + "_push(" + pair_tmp + ", sp_" + pfx_recv + "_get(" + rc + ", " + itmp + "));")
        k = 0
        while k < arg_rcs.length
          emit("    sp_" + pfx_recv + "_push(" + pair_tmp + ", sp_" + pfx_recv + "_get(" + arg_rcs[k] + ", " + itmp + "));")
          k = k + 1
        end
      end
      emit("    sp_PtrArray_push(" + tmp + ", " + pair_tmp + ");")
      emit("  }")
      return tmp
    end
 # first(n) / last(n) with argument: return new array
    if mname == "first" && @nd_arguments[nid] >= 0
      aargs = get_args(@nd_arguments[nid])
      if aargs.length > 0
        pfx = array_c_prefix(recv_type)
        n = compile_expr(aargs[0])
        tmp = new_temp
        itmp = new_temp
        emit("  " + c_type(recv_type) + " " + tmp + " = sp_" + pfx + "_new();")
        emit("  for (mrb_int " + itmp + " = 0; " + itmp + " < " + n + " && " + itmp + " < sp_" + pfx + "_length(" + rc + "); " + itmp + "++)")
        emit("    sp_" + pfx + "_push(" + tmp + ", sp_" + pfx + "_get(" + rc + ", " + itmp + "));")
        return tmp
      end
    end
    if mname == "last" && @nd_arguments[nid] >= 0
      aargs = get_args(@nd_arguments[nid])
      if aargs.length > 0
        pfx = array_c_prefix(recv_type)
        n = compile_expr(aargs[0])
        tmp = new_temp
        itmp = new_temp
        len_tmp = new_temp
        emit("  mrb_int " + len_tmp + " = sp_" + pfx + "_length(" + rc + ");")
        emit("  " + c_type(recv_type) + " " + tmp + " = sp_" + pfx + "_new();")
        emit("  for (mrb_int " + itmp + " = (" + len_tmp + " - " + n + " < 0 ? 0 : " + len_tmp + " - " + n + "); " + itmp + " < " + len_tmp + "; " + itmp + "++)")
        emit("    sp_" + pfx + "_push(" + tmp + ", sp_" + pfx + "_get(" + rc + ", " + itmp + "));")
        return tmp
      end
    end
 # Common array methods (all array types). compile_arg0_as_int unboxes
 # a bigint count operand into an mrb_int so the inline loop counter
 # has the right type (the take / drop emit assumes mrb_int).
    if mname == "take"
      pfx = array_c_prefix(recv_type)
      n = compile_arg0_as_int(nid)
      tmp = new_temp
      itmp = new_temp
      emit("  " + c_type(recv_type) + tmp + " = sp_" + pfx + "_new();")
      emit("  for (mrb_int " + itmp + " = 0; " + itmp + " < " + n + " && " + itmp + " < sp_" + pfx + "_length(" + rc + "); " + itmp + "++)")
      emit("    sp_" + pfx + "_push(" + tmp + ", sp_" + pfx + "_get(" + rc + ", " + itmp + "));")
      return tmp
    end
    if mname == "drop"
      pfx = array_c_prefix(recv_type)
      n = compile_arg0_as_int(nid)
      tmp = new_temp
      itmp = new_temp
      emit("  " + c_type(recv_type) + tmp + " = sp_" + pfx + "_new();")
      emit("  for (mrb_int " + itmp + " = " + n + "; " + itmp + " < sp_" + pfx + "_length(" + rc + "); " + itmp + "++)")
      emit("    sp_" + pfx + "_push(" + tmp + ", sp_" + pfx + "_get(" + rc + ", " + itmp + "));")
      return tmp
    end
    if mname == "fill"
      pfx = array_c_prefix(recv_type)
      args_id_fill = @nd_arguments[nid]
      val = compile_arg0(nid)
      start_expr = "0"
 # Default end: current array length (matches CRuby's no-args
 # form which fills the entire existing array).
      end_expr = "sp_" + pfx + "_length(" + rc + ")"
      if args_id_fill >= 0
        aargs_fill = get_args(args_id_fill)
        if aargs_fill.length >= 3
 # arr.fill(value, start, length): negative start counts from
 # the end; if still negative after that, clamp to 0
 # (matches CRuby: `[1,2,3].fill(9, -5, 2) #=> [9, 9, 3]`).
 # end_expr = start + length lets the array grow past its
 # current length when start+length > length; sp_*_set
 # auto-grows and zero-fills gaps (matches CRuby:
 # `[1,2,3].fill(9, 5, 2) #=> [1, 2, 3, 0, 0, 9, 9]`).
          start_tmp = new_temp
          len_tmp = new_temp
          emit("  mrb_int " + start_tmp + " = " + compile_expr(aargs_fill[1]) + ";")
          emit("  mrb_int " + len_tmp + " = " + compile_expr(aargs_fill[2]) + ";")
          emit("  if (" + start_tmp + " < 0) " + start_tmp + " += sp_" + pfx + "_length(" + rc + ");")
          emit("  if (" + start_tmp + " < 0) " + start_tmp + " = 0;")
          start_expr = start_tmp
          end_expr = "(" + start_tmp + " + " + len_tmp + ")"
        elsif aargs_fill.length == 2
 # arr.fill(value, start): fills from start to end of EXISTING
 # array. If start >= length, fills nothing (does NOT grow,
 # matching CRuby: `[1,2,3].fill(9, 5) #=> [1, 2, 3]`).
          start_tmp = new_temp
          emit("  mrb_int " + start_tmp + " = " + compile_expr(aargs_fill[1]) + ";")
          emit("  if (" + start_tmp + " < 0) " + start_tmp + " += sp_" + pfx + "_length(" + rc + ");")
          emit("  if (" + start_tmp + " < 0) " + start_tmp + " = 0;")
          start_expr = start_tmp
        end
      end
      itmp = new_temp
      emit("  for (mrb_int " + itmp + " = " + start_expr + "; " + itmp + " < " + end_expr + "; " + itmp + "++)")
      if recv_type == "poly_array"
        v_id = -1
        if args_id_fill >= 0
          v_id = get_args(args_id_fill)[0]
        end
        vt = v_id >= 0 ? infer_type(v_id) : "int"
        vbox = vt == "poly" ? val : box_value_to_poly(vt, val)
        emit("    sp_PolyArray_set(" + rc + ", " + itmp + ", " + vbox + ");")
      else
        emit("    sp_" + pfx + "_set(" + rc + ", " + itmp + ", " + val + ");")
      end
      return rc
    end
    if mname == "rotate"
      pfx = array_c_prefix(recv_type)
      n = compile_arg0(nid)
      if n == "0"
        n = "1"
      end
      tmp = new_temp
      itmp = new_temp
      len_tmp = new_temp
      emit("  mrb_int " + len_tmp + " = sp_" + pfx + "_length(" + rc + ");")
      emit("  " + c_type(recv_type) + tmp + " = sp_" + pfx + "_new();")
      emit("  for (mrb_int " + itmp + " = 0; " + itmp + " < " + len_tmp + "; " + itmp + "++)")
      emit("    sp_" + pfx + "_push(" + tmp + ", sp_" + pfx + "_get(" + rc + ", ((" + itmp + " + " + n + ") % " + len_tmp + " + " + len_tmp + ") % " + len_tmp + "));")
      return tmp
    end
    if mname == "sample"
      @needs_rand = 1
      pfx = array_c_prefix(recv_type)
 # Per-prefix sp_<X>_sample helper guards against `rand()%0` on
 # an empty array (SIGFPE under -O0, UB otherwise) and returns
 # the zero value of the slot's element type to mirror CRuby's
 # `nil` semantics in the typed-array representation. Also single-
 # evaluates rc, which the prior inline expansion did not. Issue
 # #536.
      if pfx == "PtrArray"
        elem_t = ptr_array_elem_type(recv_type)
        return "((" + c_type(elem_t) + ")sp_PtrArray_sample(" + rc + "))"
      end
      return "sp_" + pfx + "_sample(" + rc + ")"
    end
    if mname == "shuffle" && is_array_type(recv_type) == 1
      @needs_rand = 1
      pfx = array_c_prefix(recv_type)
      return "sp_" + pfx + "_shuffle(" + rc + ")"
    end
    if mname == "shuffle!" && is_array_type(recv_type) == 1
      @needs_rand = 1
      pfx = array_c_prefix(recv_type)
      emit("  sp_" + pfx + "_shuffle_bang(" + rc + ");")
      return rc
    end
    if mname == "any?" && @nd_block[nid] < 0
      pfx = array_c_prefix(recv_type)
      return "(sp_" + pfx + "_length(" + rc + ") > 0)"
    end
    if mname == "none?" && @nd_block[nid] < 0
      pfx = array_c_prefix(recv_type)
      return "(sp_" + pfx + "_length(" + rc + ") == 0)"
    end
    if mname == "count" && @nd_arguments[nid] >= 0 && @nd_block[nid] < 0
 # count(val) — count occurrences of a specific value
      pfx = array_c_prefix(recv_type)
      val = compile_arg0(nid)
      tmp_c = new_temp
