        return compile_hash_select_reject(nid, "str_int_hash", rc, mname)
      end
      if (mname == "count" || mname == "any?" || mname == "all?" || mname == "find" || mname == "detect") && @nd_block[nid] >= 0
        return compile_hash_block_predicate(nid, "str_int_hash", rc, mname)
      end
      if mname == "fetch"
        args_id = @nd_arguments[nid]
        if args_id >= 0
          aargs = get_args(args_id)
          key = compile_expr_as_string(aargs[0])
          if aargs.length >= 2
            def_at_f = infer_type(aargs[1])
            defval = compile_expr(aargs[1])
 # int-leaf + string default: convert get to string via
 # sp_int_to_s so the ternary's two arms agree on
 # `const char *`. Mirrors the analyze-side return widening.
            if def_at_f == "string" || def_at_f == "mutable_str"
              return "(sp_StrIntHash_has_key(" + rc + ", " + key + ") ? sp_int_to_s(sp_StrIntHash_get(" + rc + ", " + key + ")) : " + defval + ")"
            end
 # int-leaf + hash default (`fetch "k", {}`): no shared
 # primitive type, so box both arms to sp_RbVal. analyze surfaces
 # the call's static type as poly so the caller's slot widens.
            if is_hash_type(def_at_f) == 1
              @needs_rb_value = 1
              boxed_def = box_value_to_poly(def_at_f, defval)
              return "(sp_StrIntHash_has_key(" + rc + ", " + key + ") ? sp_box_int(sp_StrIntHash_get(" + rc + ", " + key + ")) : " + boxed_def + ")"
            end
 # nil default: SP_INT_NIL sentinel; the call's static type is
 # int? so a downstream .nil? distinguishes missing-key from a
 # legit 0 value (#682).
            if @nd_type[aargs[1]] == "NilNode"
              return "(sp_StrIntHash_has_key(" + rc + ", " + key + ") ? sp_StrIntHash_get(" + rc + ", " + key + ") : SP_INT_NIL)"
            end
            return "(sp_StrIntHash_has_key(" + rc + ", " + key + ") ? sp_StrIntHash_get(" + rc + ", " + key + ") : " + defval + ")"
          end
 # Issue #914.
          return "(sp_StrIntHash_has_key(" + rc + ", " + key + ") ? sp_StrIntHash_get(" + rc + ", " + key + ") : (sp_raise_cls(\"KeyError\", \"key not found\"), (mrb_int)0))"
        end
      end
      if mname == "merge"
 # Cross-variant: str_int_hash recv + str_str_hash / str_poly_hash
 # arg. Issue #661. Promote both sides to str_poly_hash and route
 # through sp_StrPolyHash_merge -- the per-source converters
 # sp_StrPolyHash_from_str_{int,str}_hash already box values via
 # sp_box_int / sp_box_str.
        args_id_sm = @nd_arguments[nid]
        if args_id_sm >= 0
          a_sm = get_args(args_id_sm)
          if a_sm.length >= 1
            arg_t_sm = infer_type(a_sm[0])
            if arg_t_sm == "str_str_hash"
              @needs_str_poly_hash = 1
              return "sp_StrPolyHash_merge(sp_StrPolyHash_from_str_int_hash(" + rc + "), sp_StrPolyHash_from_str_str_hash(" + compile_expr(a_sm[0]) + "))"
            elsif arg_t_sm == "str_poly_hash"
              @needs_str_poly_hash = 1
              return "sp_StrPolyHash_merge(sp_StrPolyHash_from_str_int_hash(" + rc + "), " + compile_expr(a_sm[0]) + ")"
            end
          end
        end
        tmp = new_temp
        arg = compile_arg0(nid)
        emit("  sp_StrIntHash *" + tmp + " = sp_StrIntHash_merge(" + rc + ", " + arg + ");")
        return tmp
      end
 # dup -- sibling of #510's sym_str_hash.dup. Issue #551.
      if mname == "dup" || mname == "clone"
        return "sp_StrIntHash_dup(" + rc + ")"
      end
 # Hash#default / #default= -- accessors for the per-instance
 # default value set by `Hash.new(N)`. Issue #600 puzzle 2.
      if mname == "default"
        return "(" + rc + "->default_v)"
      end
      if mname == "default="
        return "(" + rc + "->default_v = (mrb_int)(" + compile_arg0(nid) + "))"
      end
      if mname == "to_a"
        tt = "tuple:string,int"
        register_tuple_type(tt)
        @needs_gc = 1
        tname = tuple_c_name(tt)
        tmp = new_temp
        itmp = new_temp
        emit("  sp_PtrArray *" + tmp + " = sp_PtrArray_new();")
        emit("  for (mrb_int " + itmp + " = 0; " + itmp + " < " + rc + "->len; " + itmp + "++) {")
        emit("    " + tname + " *_tp = (" + tname + " *)sp_gc_alloc(sizeof(" + tname + "), NULL, " + tuple_scan_name(tt) + ");")
        emit("    _tp->_0 = " + rc + "->order[" + itmp + "];")
        emit("    _tp->_1 = sp_StrIntHash_get(" + rc + ", " + rc + "->order[" + itmp + "]);")
        emit("    sp_PtrArray_push(" + tmp + ", _tp);")
        emit("  }")
        return tmp
      end
      if mname == "transform_values"
        if @nd_block[nid] >= 0
          blk = @nd_block[nid]
          bp = get_block_param(nid, 0)
          tmp = new_temp
          emit("  sp_StrIntHash *" + tmp + " = sp_StrIntHash_new();")
          emit("  for (mrb_int _i = 0; _i < " + rc + "->len; _i++) {")
          emit("    mrb_int lv_" + bp + " = sp_StrIntHash_get(" + rc + ", " + rc + "->order[_i]);")
          push_scope
          declare_var(bp, "int")
          bbody = @nd_body[blk]
          bexpr = "0"
          if bbody >= 0
            bs = get_stmts(bbody)
            if bs.length > 0
              bexpr = compile_expr(bs.last)
            end
          end
          emit("    sp_StrIntHash_set(" + tmp + ", " + rc + "->order[_i], " + bexpr + ");")
          pop_scope
          emit("  }")
          return tmp
        end
      end
 # transform_keys: apply the block to each key, keep the matching
 # value, build a new hash. Result type matches the input hash
 # type when the block returns the same key C-type — the common
 # case for `transform_keys { |k| k.upcase }` etc.
      if mname == "transform_keys"
        if @nd_block[nid] >= 0
          blk = @nd_block[nid]
          bp = get_block_param(nid, 0)
          tmp = new_temp
          emit("  sp_StrIntHash *" + tmp + " = sp_StrIntHash_new();")
          emit("  for (mrb_int _i = 0; _i < " + rc + "->len; _i++) {")
          emit("    const char *lv_" + bp + " = " + rc + "->order[_i];")
          push_scope
          declare_var(bp, "string")
          bbody = @nd_body[blk]
          bexpr = "lv_" + bp
          if bbody >= 0
            bs = get_stmts(bbody)
            if bs.length > 0
              bexpr = compile_expr(bs.last)
            end
          end
          emit("    sp_StrIntHash_set(" + tmp + ", " + bexpr + ", sp_StrIntHash_get(" + rc + ", " + rc + "->order[_i]));")
          pop_scope
          emit("  }")
          return tmp
        end
      end
    end
    if recv_type == "int_int_hash"
      if mname == "[]"
        return "sp_IntIntHash_get(" + rc + ", " + compile_arg0_as_int(nid) + ")"
      end
      if mname == "has_key?" || mname == "key?" || mname == "include?" || mname == "member?"
        return "sp_IntIntHash_has_key(" + rc + ", " + compile_arg0_as_int(nid) + ")"
      end
      if mname == "length" || mname == "size" || (mname == "count" && @nd_block[nid] < 0 && @nd_arguments[nid] < 0)
        return "sp_IntIntHash_length(" + rc + ")"
      end
      if mname == "empty?"
        return "(sp_IntIntHash_length(" + rc + ") == 0)"
      end
      if mname == "any?" && @nd_block[nid] < 0
        return "(sp_IntIntHash_length(" + rc + ") > 0)"
      end
      if mname == "dup" || mname == "clone"
        return "sp_IntIntHash_dup(" + rc + ")"
      end
    end
    if recv_type == "int_str_hash"
      @needs_int_str_hash = 1
      if mname == "[]"
        return "sp_IntStrHash_get(" + rc + ", " + compile_arg0_as_int(nid) + ")"
      end
      if mname == "has_key?" || mname == "key?" || mname == "include?" || mname == "member?"
        return "sp_IntStrHash_has_key(" + rc + ", " + compile_arg0_as_int(nid) + ")"
      end
      if mname == "value?" || mname == "has_value?"
        return "sp_IntStrHash_has_value(" + rc + ", " + compile_str_arg0(nid) + ")"
      end
      if mname == "to_a"
        @needs_rb_value = 1
        return "sp_IntStrHash_to_a(" + rc + ")"
      end
      if mname == "invert"
        @needs_rb_value = 1
        return "sp_IntStrHash_invert(" + rc + ")"
      end
      if mname == "length" || mname == "size" || (mname == "count" && @nd_block[nid] < 0 && @nd_arguments[nid] < 0)
        return "sp_IntStrHash_length(" + rc + ")"
      end
      if mname == "empty?"
        return "(sp_IntStrHash_length(" + rc + ") == 0)"
      end
      if mname == "any?" && @nd_block[nid] < 0
        return "(sp_IntStrHash_length(" + rc + ") > 0)"
      end
      if (mname == "select" || mname == "filter" || mname == "reject") && @nd_block[nid] >= 0
        return compile_hash_select_reject(nid, "int_str_hash", rc, mname == "filter" ? "select" : mname)
      end
      if (mname == "count" || mname == "any?" || mname == "all?") && @nd_block[nid] >= 0
        return compile_hash_block_predicate(nid, "int_str_hash", rc, mname)
      end
      if mname == "keys"
        @needs_int_array = 1
        return "sp_IntStrHash_keys(" + rc + ")"
      end
      if mname == "values"
        @needs_str_array = 1
        return "sp_IntStrHash_values(" + rc + ")"
      end
      if mname == "fetch"
        args_id = @nd_arguments[nid]
        if args_id >= 0
          aargs = get_args(args_id)
          key = compile_expr(aargs[0])
          if infer_type(aargs[0]) == "poly"
            key = "(" + key + ").v.i"
          end
          if aargs.length >= 2
            defval = compile_expr(aargs[1])
            return "(sp_IntStrHash_has_key(" + rc + ", " + key + ") ? sp_IntStrHash_get(" + rc + ", " + key + ") : " + defval + ")"
          end
 # Issue #914.
          return "(sp_IntStrHash_has_key(" + rc + ", " + key + ") ? sp_IntStrHash_get(" + rc + ", " + key + ") : (sp_raise_cls(\"KeyError\", \"key not found\"), (const char *)0))"
        end
      end
 # transform_values block form. Mirrors str_int_hash's arm: walk
 # self, run the block on each value, build a new hash with the
 # same keys and the block's returns. Result type matches the
 # input hash type.
      if mname == "transform_values"
        if @nd_block[nid] >= 0
          blk = @nd_block[nid]
          bp = get_block_param(nid, 0)
          tmp = new_temp
          emit("  sp_IntStrHash *" + tmp + " = sp_IntStrHash_new();")
          emit("  for (mrb_int _i = 0; _i < " + rc + "->len; _i++) {")
          emit("    const char *lv_" + bp + " = sp_IntStrHash_get(" + rc + ", " + rc + "->order[_i]);")
          push_scope
          declare_var(bp, "string")
          bbody = @nd_body[blk]
          bexpr = "0"
          if bbody >= 0
            bs = get_stmts(bbody)
            if bs.length > 0
              bexpr = compile_expr(bs.last)
            end
          end
          emit("    sp_IntStrHash_set(" + tmp + ", " + rc + "->order[_i], " + bexpr + ");")
          pop_scope
          emit("  }")
          return tmp
        end
      end
      if mname == "dup" || mname == "clone"
        return "sp_IntStrHash_dup(" + rc + ")"
      end
      if mname == "default"
        return "(" + rc + "->default_v ? " + rc + "->default_v : (&(\"\\xff\")[1]))"
      end
      if mname == "default="
        return "(" + rc + "->default_v = " + compile_expr_as_string(get_args(@nd_arguments[nid])[0]) + ")"
      end
    end
    if recv_type == "str_str_hash"
      if mname == "[]"
        return "sp_StrStrHash_get(" + rc + ", " + compile_str_arg0(nid) + ")"
      end
      if mname == "has_key?" || mname == "key?" || mname == "include?" || mname == "member?"
        return "sp_StrStrHash_has_key(" + rc + ", " + compile_str_arg0(nid) + ")"
      end
      if mname == "value?" || mname == "has_value?"
        return "sp_StrStrHash_has_value(" + rc + ", " + compile_str_arg0(nid) + ")"
      end
      if mname == "to_a"
        @needs_rb_value = 1
        return "sp_StrStrHash_to_a(" + rc + ")"
      end
      if mname == "invert"
 # str_str_hash invert preserves type (str→str round-trip).
        return "sp_StrStrHash_invert(" + rc + ")"
      end
      if mname == "length" || mname == "size" || (mname == "count" && @nd_block[nid] < 0 && @nd_arguments[nid] < 0)
        return "sp_StrStrHash_length(" + rc + ")"
      end
      if mname == "empty?"
        return "(sp_StrStrHash_length(" + rc + ") == 0)"
      end
      if mname == "any?" && @nd_block[nid] < 0
        return "(sp_StrStrHash_length(" + rc + ") > 0)"
      end
      if mname == "keys"
        return "sp_StrStrHash_keys(" + rc + ")"
      end
      if mname == "values"
        return "sp_StrStrHash_values(" + rc + ")"
      end
      if mname == "invert"
        return "sp_StrStrHash_invert(" + rc + ")"
      end
      if mname == "to_a"
        tt = "tuple:string,string"
        register_tuple_type(tt)
        @needs_gc = 1
        tname = tuple_c_name(tt)
        tmp = new_temp
        itmp = new_temp
        emit("  sp_PtrArray *" + tmp + " = sp_PtrArray_new();")
        emit("  for (mrb_int " + itmp + " = 0; " + itmp + " < " + rc + "->len; " + itmp + "++) {")
        emit("    " + tname + " *_tp = (" + tname + " *)sp_gc_alloc(sizeof(" + tname + "), NULL, " + tuple_scan_name(tt) + ");")
        emit("    _tp->_0 = " + rc + "->order[" + itmp + "];")
        emit("    _tp->_1 = sp_StrStrHash_get(" + rc + ", " + rc + "->order[" + itmp + "]);")
        emit("    sp_PtrArray_push(" + tmp + ", _tp);")
        emit("  }")
        return tmp
      end
      if (mname == "select" || mname == "reject") && @nd_block[nid] >= 0
        return compile_hash_select_reject(nid, "str_str_hash", rc, mname)
      end
      if (mname == "count" || mname == "any?" || mname == "all?" || mname == "find" || mname == "detect") && @nd_block[nid] >= 0
        return compile_hash_block_predicate(nid, "str_str_hash", rc, mname)
      end
      if mname == "fetch"
        args_id = @nd_arguments[nid]
        if args_id >= 0
          aargs = get_args(args_id)
          key = compile_expr_as_string(aargs[0])
          if aargs.length >= 2
            defval = compile_expr(aargs[1])
            return "(sp_StrStrHash_has_key(" + rc + ", " + key + ") ? sp_StrStrHash_get(" + rc + ", " + key + ") : " + defval + ")"
          end
 # Issue #914.
          return "(sp_StrStrHash_has_key(" + rc + ", " + key + ") ? sp_StrStrHash_get(" + rc + ", " + key + ") : (sp_raise_cls(\"KeyError\", \"key not found\"), (const char *)0))"
        end
      end
      if mname == "dup" || mname == "clone"
        return "sp_StrStrHash_dup(" + rc + ")"
      end
      if mname == "default"
        return "(" + rc + "->default_v ? " + rc + "->default_v : (&(\"\\xff\")[1]))"
      end
      if mname == "default="
        return "(" + rc + "->default_v = " + compile_expr_as_string(get_args(@nd_arguments[nid])[0]) + ")"
      end
    end
    ""
  end

 # Multi-key Hash#dig walks across poly slots: each step dispatches
 # on acc.cls_id to pick a concrete-hash variant (cls_ids stamped in
 # box_value_to_poly via cls_id_for_hash_type). A cls_id that matches
 # no known variant collapses the walk to nil, covering both "key
 # missing mid-walk" and "value at this depth isn't a hash".
  def compile_hash_dig(nid, rc, recv_type)
    args_id = @nd_arguments[nid]
    aargs = []
    if args_id >= 0
      aargs = get_args(args_id)
    end
    if aargs.length == 0
      @needs_rb_value = 1
      return "sp_box_nil()"
    end

 # `"".split(",", -1)` builds an empty str_array — bare `[]` would be
 # inferred as int_array under spinel's self-host rules and can't
 # hold the string temps below.
    key_tmps = "".split(",", -1)
    key_types = "".split(",", -1)
    ki = 0
    while ki < aargs.length
      kt = infer_type(aargs[ki])
      tmp = new_temp
      if kt == "symbol"
        emit("  sp_sym " + tmp + " = " + compile_expr(aargs[ki]) + ";")
      elsif kt == "string"
        emit("  const char *" + tmp + " = " + compile_expr_as_string(aargs[ki]) + ";")
      elsif kt == "int"
        emit("  mrb_int " + tmp + " = " + compile_expr(aargs[ki]) + ";")
      else
        emit("  mrb_int " + tmp + " = 0; (void)" + tmp + ";")
      end
      key_tmps.push(tmp)
      key_types.push(kt)
      ki = ki + 1
    end

 # First-key static mismatch: short-circuit before the typed `_get`
 # so we don't fabricate a sentinel 0/"" leaf that would round-trip
 # through boxing as a real boxed 0/"".
    if hash_key_matches_recv(recv_type, key_types[0]) == 0
      @needs_rb_value = 1
      return "sp_box_nil()"
    end

    if aargs.length == 1
      return hash_get_expr(recv_type, rc, key_tmps[0])
    end

    @needs_rb_value = 1
    acc = new_temp
    emit("  sp_RbVal " + acc + ";")
    first_get = hash_get_expr(recv_type, rc, key_tmps[0])
    emit("  " + acc + " = " + box_non_nullable_value_to_poly(hash_leaf_type(recv_type), first_get) + ";")

    si = 1
    while si < aargs.length
      emit_dig_step(acc, key_tmps[si], key_types[si])
      si = si + 1
    end
    acc
  end

 # Caller must pass `key_expr` typed for recv_type's key family —
 # compile_hash_dig validates this with hash_key_matches_recv first.
  def hash_get_expr(recv_type, rc, key_expr)
    if recv_type == "sym_int_hash"
      return "sp_SymIntHash_get((sp_SymIntHash *)(" + rc + "), " + key_expr + ")"
    end
    if recv_type == "sym_str_hash"
      return "sp_SymStrHash_get((sp_SymStrHash *)(" + rc + "), " + key_expr + ")"
    end
    if recv_type == "sym_poly_hash"
      @needs_rb_value = 1
      return "sp_SymPolyHash_get((sp_SymPolyHash *)(" + rc + "), " + key_expr + ")"
    end
    if recv_type == "str_poly_hash"
      @needs_rb_value = 1
      return "sp_StrPolyHash_get(" + rc + ", " + key_expr + ")"
    end
    if recv_type == "str_int_hash"
      return "sp_StrIntHash_get(" + rc + ", " + key_expr + ")"
    end
    if recv_type == "str_str_hash"
      return "sp_StrStrHash_get(" + rc + ", " + key_expr + ")"
    end
    if recv_type == "int_str_hash"
      return "sp_IntStrHash_get(" + rc + ", " + key_expr + ")"
    end
    "0"
  end

 # Non-poly inner hashes need a has_key guard: their typed `_get`
 # returns 0/"" on miss, which sp_box_int/sp_box_str would otherwise
 # round-trip as a genuine 0/"" leaf indistinguishable from a real
 # value. Poly inner hashes don't need the guard — their `_get`
 # already returns sp_box_nil() on miss.
  def emit_dig_step(acc, key_expr, key_type)
    emit("  if (" + acc + ".tag != SP_TAG_OBJ) { " + acc + " = sp_box_nil(); } else {")
    if key_type == "symbol"
      emit_dig_arm_poly(acc, key_expr, "SP_BUILTIN_SYM_POLY_HASH", "sp_SymPolyHash")
      emit_dig_arm_typed(acc, key_expr, "SP_BUILTIN_SYM_INT_HASH", "sp_SymIntHash", "sp_box_int")
      emit_dig_arm_typed(acc, key_expr, "SP_BUILTIN_SYM_STR_HASH", "sp_SymStrHash", "sp_box_str")
    elsif key_type == "string"
      emit_dig_arm_poly(acc, key_expr, "SP_BUILTIN_STR_POLY_HASH", "sp_StrPolyHash")
      emit_dig_arm_typed(acc, key_expr, "SP_BUILTIN_STR_INT_HASH", "sp_StrIntHash", "sp_box_int")
      emit_dig_arm_typed(acc, key_expr, "SP_BUILTIN_STR_STR_HASH", "sp_StrStrHash", "sp_box_str")
    elsif key_type == "int"
      emit_dig_arm_typed(acc, key_expr, "SP_BUILTIN_INT_STR_HASH", "sp_IntStrHash", "sp_box_str")
 # Array variants for int-keyed dig: a nested array element
 # ([[1, [2, "3"]]].dig(0, 1, 1)) walks through poly_array
 # elements until it hits the final leaf. Without these arms
 # the cls_id check landed only on IntStrHash and every step
 # collapsed the accumulator to nil. Issue #619 puzzle 6.
      emit_dig_arm_poly_array(acc, key_expr, "SP_BUILTIN_POLY_ARRAY", "sp_PolyArray")
      emit_dig_arm_typed_array(acc, key_expr, "SP_BUILTIN_INT_ARRAY", "sp_IntArray", "sp_box_int")
      emit_dig_arm_typed_array(acc, key_expr, "SP_BUILTIN_STR_ARRAY", "sp_StrArray", "sp_box_str")
      emit_dig_arm_typed_array(acc, key_expr, "SP_BUILTIN_FLT_ARRAY", "sp_FloatArray", "sp_box_float")
    end
    emit("    " + acc + " = sp_box_nil();")
    emit("  }")
  end

 # Poly-array dig arm. sp_PolyArray_get already returns sp_RbVal,
 # so no boxing wrapper; an explicit bounds check guards against
 # the runtime function's missing upper-bound check (the dig
 # contract is `nil on OOB`).
  def emit_dig_arm_poly_array(acc, key_expr, cls_id, cstruct)
    emit("    if (" + acc + ".cls_id == " + cls_id + ") { " + cstruct + " *_da = (" + cstruct + " *)" + acc + ".v.p; mrb_int _di = " + key_expr + "; if (_di < 0) _di += _da->len; " + acc + " = (_di >= 0 && _di < _da->len) ? " + cstruct + "_get(_da, _di) : sp_box_nil(); } else")
  end

 # Typed-array dig arm. Bounds-check + box the typed element so
 # downstream steps (or the final `==`) see a uniform sp_RbVal.
  def emit_dig_arm_typed_array(acc, key_expr, cls_id, cstruct, box_fn)
    emit("    if (" + acc + ".cls_id == " + cls_id + ") { " + cstruct + " *_da = (" + cstruct + " *)" + acc + ".v.p; mrb_int _di = " + key_expr + "; if (_di < 0) _di += _da->len; " + acc + " = (_di >= 0 && _di < _da->len) ? " + box_fn + "(" + cstruct + "_get(_da, _di)) : sp_box_nil(); } else")
  end

  def emit_dig_arm_poly(acc, key_expr, cls_id, cstruct)
    emit("    if (" + acc + ".cls_id == " + cls_id + ") { " + acc + " = " + cstruct + "_get((" + cstruct + " *)" + acc + ".v.p, " + key_expr + "); } else")
  end

  def emit_dig_arm_typed(acc, key_expr, cls_id, cstruct, box_fn)
    emit("    if (" + acc + ".cls_id == " + cls_id + ") { " + cstruct + " *_dh = (" + cstruct + " *)" + acc + ".v.p; " + acc + " = " + cstruct + "_has_key(_dh, " + key_expr + ") ? " + box_fn + "(" + cstruct + "_get(_dh, " + key_expr + ")) : sp_box_nil(); } else")
  end

  def compile_enumerable_expr(nid, mname, precomputed_rc = "")
 # map as expression
    if mname == "map"
      if @nd_block[nid] >= 0
        return compile_map_expr(nid, precomputed_rc)
      end
    end

 # flat_map as expression
    if mname == "flat_map"
      if @nd_block[nid] >= 0
        return compile_flat_map_expr(nid)
      end
    end

 # each_with_object as expression: run the loop as side effect, return obj
    if mname == "each_with_object"
      if @nd_block[nid] >= 0
        return compile_each_with_object_block(nid)
      end
    end

 # tap: run block with receiver, return receiver
    if mname == "tap"
      if @nd_block[nid] >= 0
        return compile_tap_expr(nid)
      end
    end

 # then / yield_self: pass receiver to block, return block result
    if mname == "then" || mname == "yield_self"
      if @nd_block[nid] >= 0
        return compile_then_expr(nid)
      end
    end

 # select as expression
    if mname == "select" || mname == "filter"
      if @nd_block[nid] >= 0
        return compile_select_expr(nid)
      end
    end

 # reject as expression
    if mname == "reject"
      if @nd_block[nid] >= 0
        return compile_reject_expr(nid)
      end
    end

 # reduce/inject as expression
    if mname == "reduce"
      if @nd_block[nid] >= 0
        return compile_reduce_expr(nid)
      end
    end
    if mname == "inject"
      if @nd_block[nid] >= 0
        return compile_reduce_expr(nid)
      end
    end
    ""
  end

 # Returns the C op token ("+", "*", ...) when `nid` is an
 # `arr.reduce(:op)` / `arr.inject(:op)` call with a single
 # SymbolNode arg naming an inlinable binary arithmetic /
 # bitwise op. Else "". Issue #506. Pulled out of the
 # int_array dispatch so the emit site has no new locals
 # (the dispatch method is large and adding scope tripped
 # self-host scan_locals; see feedback_self_host_recursive_fn_arm).
  def reduce_sym_op_for(nid)
    args_id = @nd_arguments[nid]
    if args_id < 0
      return ""
    end
    args = get_args(args_id)
    if args.length != 1
      return ""
    end
    if @nd_type[args[0]] != "SymbolNode"
      return ""
    end
    op = @nd_content[args[0]]
    if op == "+" || op == "*" || op == "-" || op == "/" || op == "%" || op == "&" || op == "|" || op == "^"
      return op
    end
    ""
  end

 # 1 if `mname` is a Math module function taking exactly one
 # argument and lowering to a libm call of the same name. Keep
 # in sync with math_fn_returns_float? in spinel_analyze.rb —
 # both files iterate over the same name set.
  def math_fn_one_arg?(mname)
    if mname == "sqrt" || mname == "cos" || mname == "sin" || mname == "tan"
      return 1
    end
    if mname == "acos" || mname == "asin" || mname == "atan"
      return 1
    end
    if mname == "sinh" || mname == "cosh" || mname == "tanh"
      return 1
    end
    if mname == "asinh" || mname == "acosh" || mname == "atanh"
      return 1
    end
    if mname == "log" || mname == "log2" || mname == "log10" || mname == "exp"
      return 1
    end
    0
  end

 # 1 if `mname` is a Math module function taking two arguments.
  def math_fn_two_arg?(mname)
    if mname == "atan2" || mname == "hypot"
      return 1
    end
    0
  end

  def compile_constant_recv_expr(nid, mname, recv, rc)
    rcname = constructor_class_name(recv)
 # `Mod.accessor` read for a `class << self; attr_accessor :x; end`
 # whose write side stored to the poly-slot const synthesized at
 # analyze time. The constant-fold path (used when every observed
 # write had a ConstantReadNode RHS) is checked separately below;
 # this arm covers the non-const RHS case where the slot holds an
 # sp_RbVal at runtime. Issue #511.
    if rcname != "" && (@nd_arguments[nid] < 0 || get_args(@nd_arguments[nid]).length == 0)
      if module_name_exists(rcname) == 1
        slot_r = rcname + "_" + mname
        if find_const_idx(slot_r) >= 0 && find_module_acc_idx(rcname + "." + mname) >= 0
          rconsts_r = module_acc_resolved(rcname, mname)
          if rconsts_r == "" || rconsts_r == "?"
            @needs_rb_value = 1
            return "cst_" + slot_r
          end
        end
      end
    end
    if rcname != ""
 # Foo.method_defined?(:sym[, inherit=true]) — compile-time decide.
 # Default arm walks the parent chain via class_has_method (covers
 # instance methods, attr readers/writers, ancestors). When the
 # second arg is the literal `false`, restrict the lookup to the
 # receiver's own methods (no parent walk) via class_has_method_local.
      if mname == "method_defined?"
        ci_md = find_class_idx(rcname)
        if ci_md >= 0
          args_id_md = @nd_arguments[nid]
          if args_id_md >= 0
            a_md = get_args(args_id_md)
            if a_md.length > 0
              if @nd_type[a_md[0]] == "SymbolNode" || @nd_type[a_md[0]] == "StringNode"
                lit_name = @nd_content[a_md[0]]
                inherit_md = 1
                if a_md.length >= 2 && @nd_type[a_md[1]] == "FalseNode"
                  inherit_md = 0
                end
                hit = inherit_md == 1 ? class_has_method(ci_md, lit_name) : class_has_method_local(ci_md, lit_name)
                return hit == 1 ? "TRUE" : "FALSE"
              end
            end
          end
        end
      end
 # ARGV methods
      if rcname == "ARGV"
        if mname == "length"
          @needs_argv = 1
          return "sp_argv.len"
        end
        if mname == "[]"
          @needs_argv = 1
          idx_expr = compile_arg0_as_int(nid)
          return "((" + idx_expr + " < sp_argv.len) ? sp_argv.data[(int)" + idx_expr + "] : NULL)"
        end
      end
 # Math.<fn> dispatch. Single source of truth via
 # math_fn_one_arg? / math_fn_two_arg?; the matching analyze-side
 # gate lives in spinel_analyze.rb:math_fn_returns_float? and
 # additions need both files updated.
      if rcname == "Math"
        if math_fn_one_arg?(mname) == 1
          return mname + "(" + compile_arg0(nid) + ")"
        end
        if math_fn_two_arg?(mname) == 1
          args_id = @nd_arguments[nid]
          if args_id >= 0
            arg_ids = get_args(args_id)
            if arg_ids.length >= 2
              return mname + "(" + compile_expr(arg_ids[0]) + ", " + compile_expr(arg_ids[1]) + ")"
            end
          end
        end
      end
 # Integer class methods (Ruby 2.5+)
      if rcname == "Integer"
        if mname == "sqrt"
 # Integer.sqrt(n) is the integer square root, distinct from
 # Math.sqrt's float result. Use sp_int_sqrt (Newton's method,
 # exact for the full mrb_int range) instead of casting through
 # double — double has only 53 bits of mantissa so values above
 # ~2^53 round and produce off-by-one results.
          return "sp_int_sqrt(" + compile_arg0(nid) + ")"
        end
      end
 # File operations
      if rcname == "File"
        if mname == "read" || mname == "binread"
          return "sp_file_read(" + compile_arg0(nid) + ")"
        end
        if mname == "exist?"
          return "sp_file_exist(" + compile_arg0(nid) + ")"
        end
        if mname == "directory?"
          return "sp_file_directory(" + compile_arg0(nid) + ")"
        end
        if mname == "file?"
          return "sp_file_file(" + compile_arg0(nid) + ")"
        end
        if mname == "readable?"
 # Reuse the exist check: on every platform Spinel
 # targets, a fopen-able file is also readable from
 # the same process. Distinguishing the two would
 # need access(2), which isn't worth a runtime fn for
 # the dead-code optcarrot battery-save path that
 # surfaced this.
          return "sp_file_exist(" + compile_arg0(nid) + ")"
        end
        if mname == "delete"
          return "(sp_file_delete(" + compile_arg0(nid) + "), 0)"
        end
        if mname == "binwrite" || mname == "write"
 # NOTE: `sp_file_write` uses fputs, so an embedded NUL
 # in the payload truncates the write; fine for the
 # optcarrot save-RAM dead-code path that surfaced
 # this, not safe for general binary use. File.write
 # in CRuby returns the number of bytes written; we
 # return 0 to match the statement-context lowering at
 # compile_control_call_stmt (which also discards the
 # byte count).
          args_id_bw = @nd_arguments[nid]
          if args_id_bw >= 0
            a_bw = get_args(args_id_bw)
            if a_bw.length >= 2
              return "(sp_file_write(" + compile_expr(a_bw[0]) + ", " + compile_expr(a_bw[1]) + "), 0)"
            end
          end
          return "0"
        end
        if mname == "join"
          args_id = @nd_arguments[nid]
          if args_id >= 0
            arg_ids = get_args(args_id)
            if arg_ids.length >= 2
              return "sp_str_concat(sp_str_concat(" + compile_expr(arg_ids[0]) + ", " + c_string_literal("/") + "), " + compile_expr(arg_ids[1]) + ")"
            end
          end
          return "\"\""
        end
        if mname == "basename"
          return "sp_file_basename(" + compile_arg0(nid) + ")"
        end
 # Issue #892.
        if mname == "dirname"
          return "sp_file_dirname(" + compile_arg0(nid) + ")"
        end
        if mname == "extname"
          return "sp_file_extname(" + compile_arg0(nid) + ")"
        end
      end
      if rcname == "Dir"
        if mname == "pwd" || mname == "getwd"
          return "sp_dir_pwd()"
        end
      end
      if rcname == "StringScanner"
        if mname == "new"
          return "sp_StringScanner_new(" + compile_arg0(nid) + ")"
        end
      end
      if rcname == "Time"
        if mname == "now"
          return "sp_time_now()"
        end
        if mname == "at"
          arg_id = compile_arg0(nid)
          args_id = @nd_arguments[nid]
          if args_id >= 0
            aargs = get_args(args_id)
            if aargs.length > 0 && infer_type(aargs[0]) == "float"
              return "sp_time_at_float(" + arg_id + ")"
            end
          end
          return "sp_time_at_int(" + arg_id + ")"
        end
 # Time.new(y[,mo[,d[,h[,mi[,s]]]]]) — local construction with
 # compile-time arity resolution (same shape as Time.at). Missing
 # positions get C-literal defaults; 0 args is the current time.
 # 7+ args is the fixed-offset form (a separate Issue): this arm
 # does not emit for it. analyze still types Time.new as "time",
 # so the call surfaces as an unresolved-call warning and then a
 # hard C type error — Time.new with an offset is unsupported and
 # fails to build by design, not silently.
        if mname == "new"
          nargs_id = @nd_arguments[nid]
          na = nargs_id >= 0 ? get_args(nargs_id) : []
          nn = na.length
          if nn == 0
            return "sp_time_now()"
          end
          if nn >= 1 && nn <= 6
            ny = compile_expr(na[0])
            nmo = nn >= 2 ? compile_expr(na[1]) : "1"
            nd = nn >= 3 ? compile_expr(na[2]) : "1"
            nh = nn >= 4 ? compile_expr(na[3]) : "0"
            nmi = nn >= 5 ? compile_expr(na[4]) : "0"
            ns = nn >= 6 ? compile_expr(na[5]) : "0"
            return "sp_time_new(" + ny + ", " + nmo + ", " + nd + ", " + nh + ", " + nmi + ", " + ns + ")"
          end
        end
      end
 # Complex.polar(magnitude, angle) — value-type Cartesian
 # Complex (sp_Complex). Used in optcarrot's nestopia palette
 # generator; see lib/sp_runtime.h for the runtime helpers.
 # Args may arrive boxed (poly) when the surrounding code
 # destructured them out of a poly_array; unbox via
 # sp_poly_to_f rather than a plain `(mrb_float)` cast (the
 # cast would mis-reinterpret the sp_RbVal struct).
      if rcname == "Complex"
        if mname == "polar"
          args_id_cp = @nd_arguments[nid]
          if args_id_cp >= 0
            aargs_cp = get_args(args_id_cp)
            if aargs_cp.length >= 2
              a0_e = compile_expr(aargs_cp[0])
              a1_e = compile_expr(aargs_cp[1])
              a0_t_cp = infer_type(aargs_cp[0])
              if a0_t_cp == "poly"
                a0_e = "sp_poly_to_f(" + a0_e + ")"
              elsif a0_t_cp == "bigint" || expr_emit_is_bigint(aargs_cp[0]) == 1
                @needs_bigint = 1
                a0_e = "(mrb_float)sp_bigint_to_int((sp_Bigint *)" + a0_e + ")"
              else
                a0_e = "(mrb_float)(" + a0_e + ")"
              end
              a1_t_cp = infer_type(aargs_cp[1])
              if a1_t_cp == "poly"
                a1_e = "sp_poly_to_f(" + a1_e + ")"
              elsif a1_t_cp == "bigint" || expr_emit_is_bigint(aargs_cp[1]) == 1
                @needs_bigint = 1
                a1_e = "(mrb_float)sp_bigint_to_int((sp_Bigint *)" + a1_e + ")"
              else
                a1_e = "(mrb_float)(" + a1_e + ")"
              end
              return "sp_complex_polar(" + a0_e + ", " + a1_e + ")"
            end
          end
        end
      end
 # Process.clock_gettime — assume CLOCK_MONOTONIC; the clock_id
 # arg is not modeled. Returns seconds as a float.
      if rcname == "Process"
        if mname == "clock_gettime"
          return "({ struct timespec _ts; clock_gettime(CLOCK_MONOTONIC, &_ts); (mrb_float)_ts.tv_sec + (mrb_float)_ts.tv_nsec / 1e9; })"
        end
 # Process.pid / .ppid: direct syscall lowering. unistd.h is
 # already included in the runtime. MinGW's <unistd.h> lacks
 # getppid -- route through a runtime wrapper that #ifdef's
 # away on Windows. Issue #893.
        if mname == "pid"
          return "((mrb_int)getpid())"
        end
        if mname == "ppid"
          return "sp_process_ppid()"
        end
      end
 # Regexp.escape / Regexp.quote -- single-string-arg form. Routes
 # to sp_re_escape (runtime), which prefixes regex metachars and
 # whitespace with a single backslash so the result feeds safely
 # into `Regexp.new(...)`. The 0-arg or multi-arg form falls
 # through to unresolved-call.
      if rcname == "Regexp"
        if mname == "escape" || mname == "quote"
          args_id_rxe = @nd_arguments[nid]
          if args_id_rxe >= 0
            argl_rxe = get_args(args_id_rxe)
            if argl_rxe.length == 1
              @needs_regexp = 1
              return "sp_re_escape(" + compile_expr(argl_rxe[0]) + ")"
            end
          end
        end
      end
 # ENV
      if rcname == "ENV"
        if mname == "[]"
          return "sp_str_dup_external(getenv(" + compile_arg0(nid) + "))"
        end
        if mname == "fetch"
 # Two-arg form: ENV.fetch(key, default). If the env var is
 # set, return its value; otherwise return the supplied
 # default. The single-arg form (`ENV.fetch("X")`) raises
 # KeyError in CRuby; spinel doesn't model that, so it
 # behaves like ENV[] -- callers wanting strict behaviour
 # should pass an explicit default.
          args_id = @nd_arguments[nid]
          if args_id >= 0
            argz = get_args(args_id)
            if argz.length >= 2
              key = compile_expr(argz[0])
              dfl = compile_expr_as_string(argz[1])
              tmp = new_temp
              return "({ const char *" + tmp + " = getenv(" + key + "); " +
                     tmp + " ? sp_str_dup_external(" + tmp + ") : (" + dfl + "); })"
            end
            if argz.length == 1
              return "sp_str_dup_external(getenv(" + compile_arg0(nid) + "))"
            end
          end
          return "(&(\"\\xff\")[1])"
        end
      end
 # Dir
      if rcname == "Dir"
        if mname == "home"
          return "sp_str_dup_external(getenv(\"HOME\"))"
        end
      end
 # Module class method dispatch
      mi2 = 0
      while mi2 < @module_names.length
        if @module_names[mi2] == rcname
 # Look for module class method
          mfn = rcname + "_cls_" + mname
          mfi = find_method_idx(mfn)
          if mfi >= 0
 # Route through compile_call_args_with_defaults so a
 # `def self.greet(name, msg = nil); end` inside a
 # module accepts shorter call sites — caller-omitted
 # trailing args get filled in from the method's
 # recorded default expressions, the same as top-level
 # method calls.
            ca = compile_call_args_with_defaults(nid, mfi)
            if ca != ""
              return "sp_" + sanitize_name(mfn) + "(" + ca + ")"
            else
              return "sp_" + sanitize_name(mfn) + "()"
            end
          end
        end
        mi2 = mi2 + 1
      end
 # `Klass.method(:cls_meth)` — bind to a class method. Mirrors
 # the instance-recv `obj.method(:bar)` form (line ~20940), but
 # the underlying class method has no `self *` param. Emit a
 # static adapter trampoline that ignores the dispatch ABI's
 # `void *self` slot and forwards the rest, then bind the
 # Method's iv_fn_ptr to the adapter. iv_self_obj is unused but
 # set to a stable stand-in (a NULL pointer cast through
 # sp_Method *); the Method dispatch in compile_poly_method_call
 # passes it as the void * arg, which the adapter discards.
      if mname == "method"
        ci_cm = find_class_idx(rcname)
        if ci_cm >= 0
          args_id_cm = @nd_arguments[nid]
          if args_id_cm >= 0
            arg_ids_cm = get_args(args_id_cm)
            if arg_ids_cm.length >= 1
              cm_ref = @nd_content[arg_ids_cm[0]]
              if cm_ref == ""
                cm_ref = @nd_name[arg_ids_cm[0]]
              end
              owner_cm = cls_method_owner_for(ci_cm, cm_ref, "cmeth")
              if owner_cm >= 0
                owner_cm_name = @cls_names[owner_cm]
                emit_cls_method_adapter(owner_cm, cm_ref)
                adapter_name = "sp_" + owner_cm_name + "_" + sanitize_name(cm_ref) + "_cls_method_adapter"
                return "sp_Method_new((sp_Method *)0, (mrb_int)(uintptr_t)&" + adapter_name + ")"
              end
            end
          end
        end
      end
 # Class method dispatch (def self.xxx). walk the
 # parent chain so `Leaf.all` resolves to `Base.all`'s emitter
 # (`sp_Base_cls_all`, not `sp_Leaf_cls_all` which is never
 # generated when Leaf doesn't override).
      ci3 = find_class_idx(rcname)
      if ci3 >= 0
        owner_ci = cls_method_owner_for(ci3, mname, "cmeth")
        if owner_ci >= 0
          owner_name = @cls_names[owner_ci]
          owner_cmnames = @cls_cmeth_names[owner_ci].split(";", -1)
          owner_cmptypes = @cls_cmeth_ptypes[owner_ci].split("|", -1)
          owner_cmdefaults = @cls_cmeth_defaults[owner_ci].split("|", -1)
          cmidx = 0
          while cmidx < owner_cmnames.length
            if owner_cmnames[cmidx] == mname
              break
            end
            cmidx = cmidx + 1
          end
          ca = ""
          if cmidx < owner_cmnames.length && cmidx < owner_cmptypes.length
            owner_pn = cls_cmeth_pnames_get(owner_ci, cmidx)
            owner_pt = owner_cmptypes[cmidx].split(",", -1)
            owner_df = "".split(",", -1)
            if cmidx < owner_cmdefaults.length
              owner_df = owner_cmdefaults[cmidx].split(",", -1)
            end
 # Extract positional + kwarg pairs from the call site, so
 # `W.write(200, set_cookies: cookies)` against
 # `def self.write(status, set_cookies: {})` routes `cookies`
 # into the set_cookies slot (instead of compiling the
 # KeywordHashNode as a generic literal that lowers to 0).
 # Sibling to the kwarg-fallback path in
 # compile_call_args_with_defaults' instance-method handler.
            args_id_cm2 = @nd_arguments[nid]
            arg_ids_cm2 = []
            if args_id_cm2 >= 0
              arg_ids_cm2 = get_args(args_id_cm2)
            end
            kw_names_cm = "".split(",", -1)
            kw_vals_cm = "".split(",", -1)
            kw_arg_ids_cm = []
            positional_cm = []
            ak_cm = 0
            while ak_cm < arg_ids_cm2.length
              if @nd_type[arg_ids_cm2[ak_cm]] == "KeywordHashNode"
                elems_cm = parse_id_list(@nd_elements[arg_ids_cm2[ak_cm]])
                ek_cm = 0
                while ek_cm < elems_cm.length
                  if @nd_type[elems_cm[ek_cm]] == "AssocNode"
                    key_id_cm = @nd_key[elems_cm[ek_cm]]
                    if key_id_cm >= 0 && @nd_type[key_id_cm] == "SymbolNode"
                      kw_names_cm.push(@nd_content[key_id_cm])
                      kw_vals_cm.push(compile_expr(@nd_expression[elems_cm[ek_cm]]))
                      kw_arg_ids_cm.push(@nd_expression[elems_cm[ek_cm]])
                    end
                  end
                  ek_cm = ek_cm + 1
                end
              else
                positional_cm.push(arg_ids_cm2[ak_cm])
              end
              ak_cm = ak_cm + 1
            end
 # Track which kwargs land on a named param slot; the leftovers
 # bundle into the first hash-typed positional slot below.
            kw_matched_cm = []
            kmci = 0
            while kmci < kw_names_cm.length
              kw_matched_cm.push(0)
              kmci = kmci + 1
            end
            pkn = 0
            while pkn < owner_pn.length
              kki = 0
              while kki < kw_names_cm.length
                if kw_names_cm[kki] == owner_pn[pkn]
                  kw_matched_cm[kki] = 1
                end
                kki = kki + 1
              end
              pkn = pkn + 1
            end
            bundle_emitted_cm = 0
            pos_idx_cm = 0
            kk = 0
            while kk < owner_pn.length
              slot_expr_cm = ""
              if pos_idx_cm < positional_cm.length
 # Route through compile_expr_for_expected_type when the
 # slot's declared type needs a coercion: int<->bigint
 # promote mode, OR when arg type and param type disagree
 # in a way the helper can bridge (poly->concrete unbox via
 # tag-field, concrete->poly box, etc.). #685 surfaces this
 # whenever an sp_RbVal ivar flows into a typed-hash /
 # typed-obj / mrb_int callee param.
                slot_pt_pos_cm = kk < owner_pt.length ? owner_pt[kk] : ""
                at_pos_cm = infer_type(positional_cm[pos_idx_cm])
                slot_pt_base_cm = base_type(slot_pt_pos_cm)
                at_pos_base_cm = base_type(at_pos_cm)
                needs_coerce_cm = 0
                if slot_pt_pos_cm != ""
                  if slot_pt_base_cm == "bigint" || slot_pt_base_cm == "int"
                    needs_coerce_cm = 1
                  elsif at_pos_cm == "poly" && slot_pt_base_cm != "poly" && slot_pt_base_cm != ""
                    needs_coerce_cm = 1
                  elsif at_pos_cm != "poly" && slot_pt_base_cm == "poly"
                    needs_coerce_cm = 1
                  elsif is_hash_type(at_pos_base_cm) == 1 && is_hash_type(slot_pt_base_cm) == 1 && at_pos_base_cm != slot_pt_base_cm
 # Cross-variant hash arg (sym_X_hash -> str_poly_hash etc.)
 # needs a runtime converter; compile_expr_for_expected_type's
 # hash-to-hash arm dispatches via hash_variant_convert.
                    needs_coerce_cm = 1
                  end
                end
                if needs_coerce_cm == 1
                  slot_expr_cm = compile_expr_for_expected_type(positional_cm[pos_idx_cm], slot_pt_pos_cm)
                else
                  slot_expr_cm = cast_away_volatile_arg(positional_cm[pos_idx_cm], compile_expr(positional_cm[pos_idx_cm]))
                end
                pos_idx_cm = pos_idx_cm + 1
              else
 # Try kwarg by name.
                pname_cm = owner_pn[kk]
                ki_cm = 0
                while ki_cm < kw_names_cm.length
                  if kw_names_cm[ki_cm] == pname_cm
                    slot_expr_cm = kw_vals_cm[ki_cm]
                    ki_cm = kw_names_cm.length
                  else
                    ki_cm = ki_cm + 1
                  end
                end
 # Bundle-as-positional: when no positional/kwarg fills this
 # slot and the slot's ptype is a hash type, pack any unmatched
 # kwargs into a fresh sp_StrPolyHash and pass it here. Mirrors
 # the analyzer-side `widen_ptypes_from_args` fallback that
 # widens `attrs = {}` to str_poly_hash at the call site.
                if slot_expr_cm == "" && bundle_emitted_cm == 0
                  slot_pt_cm = ""
                  if kk < owner_pt.length
                    slot_pt_cm = base_type(owner_pt[kk])
                  end
                  if is_hash_type(slot_pt_cm) == 1
                    have_unmatched_cm = 0
                    chi = 0
                    while chi < kw_names_cm.length
                      if kw_matched_cm[chi] == 0
                        have_unmatched_cm = 1
                      end
                      chi = chi + 1
                    end
                    if have_unmatched_cm == 1
                      bundle_tmp_cm = new_temp
                      @needs_rb_value = 1
                      emit("  sp_StrPolyHash *" + bundle_tmp_cm + " = sp_StrPolyHash_new();")
                      bbi = 0
                      while bbi < kw_names_cm.length
                        if kw_matched_cm[bbi] == 0
                          key_c_cm = "(&(\"\\xff\" \"" + kw_names_cm[bbi] + "\")[1])"
                          emit("  sp_StrPolyHash_set(" + bundle_tmp_cm + ", " + key_c_cm + ", " + box_expr_to_poly(kw_arg_ids_cm[bbi]) + ");")
                        end
                        bbi = bbi + 1
                      end
                      slot_expr_cm = bundle_tmp_cm
                      bundle_emitted_cm = 1
                    end
                  end
                end
                if slot_expr_cm == ""
                  if kk < owner_df.length
                    def_id_cm = owner_df[kk].to_i
                    if def_id_cm >= 0
                      def_pt_cm = ""
                      if kk < owner_pt.length
                        def_pt_cm = owner_pt[kk]
                      end
                      coerced_cm = empty_hash_coerce(def_id_cm, def_pt_cm)
                      if coerced_cm != ""
                        slot_expr_cm = coerced_cm
                      else
                        slot_expr_cm = compile_expr(def_id_cm)
                      end
                    end
                  end
                end
              end
              if slot_expr_cm != ""
                if ca == ""
                  ca = slot_expr_cm
                else
                  ca = ca + ", " + slot_expr_cm
                end
              end
              kk = kk + 1
            end
            has_block_param = (owner_pt.length > 0 && owner_pt.last == "proc") ? 1 : 0
            if has_block_param == 1
              blk_types = ""
              if @cls_cmeth_blk_param_types != nil
                flat_idx = 0
                ci_walk = 0
                while ci_walk < owner_ci
                  if ci_walk < @cls_cmeth_names.length
                    flat_idx = flat_idx + @cls_cmeth_names[ci_walk].split(";", -1).length
                  end
                  ci_walk = ci_walk + 1
                end
                flat_idx = flat_idx + cmidx
                if flat_idx < @cls_cmeth_blk_param_types.length
                  blk_types = @cls_cmeth_blk_param_types[flat_idx]
                end
              end
              block_proc = block_forward_expr(nid, blk_types)
              if block_proc != ""
                if ca != ""
                  ca = ca + ", " + block_proc
                else
                  ca = block_proc
                end
              end
            end
          end
          if ca != ""
            return "sp_" + owner_name + "_cls_" + sanitize_name(mname) + "(" + ca + ")"
          else
            return "sp_" + owner_name + "_cls_" + sanitize_name(mname) + "()"
          end
        end
      end
    end
    ""
  end

  def compile_to_a_range_expr(nid, recv)
    range_nid = -1
    if @nd_type[recv] == "RangeNode"
      range_nid = recv
    end
    if @nd_type[recv] == "ParenthesesNode"
      pb = @nd_body[recv]
      if pb >= 0
        pstmts = get_stmts(pb)
        if pstmts.length > 0
          if @nd_type[pstmts.first] == "RangeNode"
            range_nid = pstmts.first
          end
        end
      end
    end
    if range_nid >= 0
      @needs_int_array = 1
      @needs_gc = 1
      right_expr = compile_expr(@nd_right[range_nid])
 # sp_IntArray_from_range is inclusive; for `1...3` shave the upper end.
      if range_excl_end(range_nid) == 1
        right_expr = "(" + right_expr + ") - 1"
      end
      return "sp_IntArray_from_range(" + compile_expr(@nd_left[range_nid]) + ", " + right_expr + ")"
    end
    ""
  end

  def compile_open_class_dispatch_expr(nid, mname, rc, recv_type)
 # Open class method dispatch on built-in types
    oc_prefix = ""
    if recv_type == "int" || recv_type == "bigint"
      oc_prefix = "__oc_Integer_"
    end
    if recv_type == "string"
      oc_prefix = "__oc_String_"
    end
    if recv_type == "float"
      oc_prefix = "__oc_Float_"
    end
    if oc_prefix != ""
      oc_name = oc_prefix + mname
      oc_mi = find_method_idx(oc_name)
      if oc_mi >= 0
 # Open-class `self` for Integer is always `mrb_int` (see
 # build_params_str at line 9207). In promote mode the call site's
 # recv is sp_Bigint*; unbox so the function signature matches.
        rc_oc = rc
        if recv_type == "bigint"
          @needs_bigint = 1
          rc_oc = "sp_bigint_to_int((sp_Bigint *)" + rc + ")"
        end
        ca = compile_call_args(nid)
        if ca != ""
          return "sp_" + sanitize_name(oc_name) + "(" + rc_oc + ", " + ca + ")"
        else
          return "sp_" + sanitize_name(oc_name) + "(" + rc_oc + ")"
        end
      end
    end
    ""
  end

  def is_static_const_ref(aid)
    if @nd_type[aid] == "ConstantReadNode" || @nd_type[aid] == "ConstantPathNode"
      return 1
    end
    0
  end

 # Resolve an is_a?/kind_of?/instance_of? argument to its registered
 # class name. ConstantPathNode (`Foo::Bar`) walks the path via
 # resolve_const_ref_name; ConstantReadNode (`Foo`) carries the leaf
 # in @nd_name. Other shapes fall back to @nd_name so static lookup
 # still has a name to try.
  def resolve_introspection_arg_name(aid)
    if @nd_type[aid] == "ConstantPathNode"
      return resolve_const_ref_name(aid)
    end
    @nd_name[aid]
  end

  def compile_introspection_expr(nid, mname, rc, recv_type)
 # is_a? / kind_of? — kind_of? is an exact alias of is_a? in MRI.
 # Both walk the class hierarchy: cname is or inherits from arg0 → TRUE.
    if mname == "is_a?" || mname == "kind_of?"
      if base_type(recv_type) == "encoding"
        arg0_enc_isa = ""
        args_id_enc_isa = @nd_arguments[nid]
        if args_id_enc_isa >= 0
          a_enc_isa = get_args(args_id_enc_isa)
          if a_enc_isa.length > 0
            arg0_enc_isa = resolve_introspection_arg_name(a_enc_isa[0])
          end
        end
        if arg0_enc_isa == "Encoding" || arg0_enc_isa == "Object" || arg0_enc_isa == "Kernel" || arg0_enc_isa == "BasicObject"
          return "TRUE"
        end
        return "FALSE"
      end
      if is_obj_type(recv_type) == 1
        cname = recv_type[4, recv_type.length - 4]
        arg0 = ""
        args_id = @nd_arguments[nid]
        if args_id >= 0
          a = get_args(args_id)
          if a.length > 0
 # Dynamic Class arg (a non-const expression evaluating to a class).
 # The statically-typed recv knows its own cls_id; the arg carries
 # the target cls_id at runtime. sp_class_le walks the precomputed
 # ancestors table to decide membership.
            arg_t = infer_type(a[0])
            if arg_t == "class" && is_static_const_ref(a[0]) == 0
              ci = find_class_idx(cname)
              if ci >= 0
                @needs_class_table = 1
                @needs_class_ancestors = 1
                return "sp_class_le((sp_Class){" + cls_id_for_user_internal(ci).to_s + "LL}, " + compile_expr(a[0]) + ")"
              end
            end
            arg0 = resolve_introspection_arg_name(a[0])
          end
        end
        if is_class_or_ancestor(cname, arg0) == 1
          return "TRUE"
        end
 # Descendant case: arg0 is a proper subclass of cname (recv's
 # static type). The recv's static type only bounds the runtime
 # class above; the instance can be cname or any descendant
 # including arg0. Consult the recv's actual cls_id slot.
        target_ci = find_class_idx(arg0)
        if target_ci >= 0 && is_descendant(arg0, cname) == 1
          @needs_class_table = 1
          @needs_class_ancestors = 1
          recv_id = @nd_receiver[nid]
          if recv_id >= 0
            return "sp_class_le((sp_Class){" + compile_expr(recv_id) + "->cls_id}, (sp_Class){" + cls_id_for_user_internal(target_ci).to_s + "LL})"
          end
        end
 # Unrelated classes — neither ancestor nor descendant. Always FALSE.
        return "FALSE"
      end
      return "FALSE"
    end

 # instance_of? — exact class identity, no ancestor walk.
 # The recv's static type only bounds the runtime class above; the
 # instance can be the static type OR any descendant. The runtime
 # class can therefore equal arg0 only if arg0 is in that set —
 # i.e., arg0 is cname or a descendant of cname. Other shapes
 # (arg0 is an ancestor of cname, or unrelated) make the equality
 # statically impossible and collapse to FALSE.
 #
 # `cname == arg0` does NOT in general collapse to TRUE — a parent-
 # typed local holding a descendant returns FALSE for
 # `instance_of?(parent)`. The check is runtime via the recv's
 # cls_id slot. EXCEPTION: value-type classes have no subclasses
 # by design (no cls_id field on the struct, no polymorphism), so
 # for value-type cname the runtime is always exactly cname and
 # the cname == arg0 check collapses back to static TRUE.
    if mname == "instance_of?"
      arg0 = ""
      args_id = @nd_arguments[nid]
      if args_id >= 0
        a = get_args(args_id)
        if a.length > 0
          arg0 = resolve_introspection_arg_name(a[0])
        end
      end
 # Built-in container classes: every Array variant
 # (int_array / str_array / etc.) is conceptually `Array`
 # in CRuby; every Hash variant is `Hash`. Static recv-type
 # knowledge folds the check at compile time. Issue #562.
      if arg0 == "Array" && is_array_type(recv_type) == 1
        return "TRUE"
      end
      if arg0 == "Hash" && is_hash_type(recv_type) == 1
        return "TRUE"
      end
      if base_type(recv_type) == "encoding"
        if arg0 == "Encoding"
          return "TRUE"
        end
        return "FALSE"
      end
      if is_obj_type(recv_type) == 1
        cname = recv_type[4, recv_type.length - 4]
        target_ci = find_class_idx(arg0)
        if target_ci >= 0 && (cname == arg0 || is_descendant(arg0, cname) == 1)
          if is_value_type_class(cname) == 1
            return "TRUE"
          end
          @needs_class_table = 1
          recv_id = @nd_receiver[nid]
          if recv_id >= 0
            return "(" + compile_expr(recv_id) + "->cls_id == " + cls_id_for_user_internal(target_ci).to_s + "LL)"
          end
        end
        return "FALSE"
      end
      return "FALSE"
    end

 # respond_to? - check if method exists
    if mname == "respond_to?"
 # Primitive recv: assume the common method set is supported.
 # An exhaustive enumeration is brittle, but `42.respond_to?(:to_s)`
 # returning FALSE is much worse than a few false positives. The
 # short list covers Object's universal methods + each primitive's
 # commonly probed methods. Returns TRUE for any of these regardless
 # of actual presence -- spinel can't reliably introspect a primitive's
 # method table at compile time. Issue #716.
      bt_rt = base_type(recv_type)
      if bt_rt == "int" || bt_rt == "bigint" || bt_rt == "float" ||
         bt_rt == "string" || bt_rt == "mutable_str" || bt_rt == "symbol" ||
         bt_rt == "bool" || bt_rt == "nil" ||
         is_array_type(bt_rt) == 1 || is_hash_type(bt_rt) == 1
        args_id_rt = @nd_arguments[nid]
        arg0_rt = ""
        if args_id_rt >= 0
          a_rt = get_args(args_id_rt)
          if a_rt.length > 0
            arg0_rt = @nd_content[a_rt[0]]
          end
        end
 # Conservative allowlist of methods every primitive responds to.
        if arg0_rt == "to_s" || arg0_rt == "to_i" || arg0_rt == "to_f" ||
           arg0_rt == "inspect" || arg0_rt == "class" || arg0_rt == "nil?" ||
           arg0_rt == "is_a?" || arg0_rt == "kind_of?" || arg0_rt == "instance_of?" ||
           arg0_rt == "==" || arg0_rt == "!=" || arg0_rt == "hash" ||
           arg0_rt == "respond_to?" || arg0_rt == "frozen?" || arg0_rt == "freeze" ||
           arg0_rt == "dup" || arg0_rt == "clone" || arg0_rt == "tap" || arg0_rt == "then"
          return "TRUE"
        end
      end
      if is_obj_type(recv_type) == 1
        cname = recv_type[4, recv_type.length - 4]
        ci = find_class_idx(cname)
        if ci >= 0
          arg0 = ""
          args_id = @nd_arguments[nid]
          if args_id >= 0
            a = get_args(args_id)
            if a.length > 0
              arg0 = @nd_content[a[0]]
            end
          end
          if cls_find_method(ci, arg0) >= 0
            return "TRUE"
          end
 # Check attr_readers
          readers = @cls_attr_readers[ci].split(";", -1)
          rk = 0
          while rk < readers.length
            if readers[rk] == arg0
              return "TRUE"
            end
            rk = rk + 1
          end
          return "FALSE"
        end
      end
      return "FALSE"
    end

 # nil?
    if mname == "nil?"
      if recv_type == "nil"
        return "TRUE"
      end
      if recv_type == "poly"
        return "sp_poly_nil_p(" + rc + ")"
      end
 # Scalar-nullable types (int?, ...) encode nil with a reserved
 # sentinel value, not NULL. Test via sp_int_is_nil before falling
 # through to the NULL-pointer branch (which would compare mrb_int
 # to NULL and silently mean "== 0").
      if is_scalar_nullable_type(recv_type) == 1
        return "sp_int_is_nil(" + rc + ")"
      end
      if is_nullable_type(recv_type) == 1
        return "(" + rc + " == NULL)"
      end
      if type_is_pointer(recv_type) == 1
        return "(" + rc + " == NULL)"
      end
      return "FALSE"
    end

 # frozen? on any type
    if mname == "frozen?"
      return "TRUE"
    end

 # `freeze` on any object — returns the receiver. The string /
 # mutable-str dispatchers earlier in compile_call_expr handle their
 # own variants; this catches everything else (obj_*, sp_Object *,
 # array types, etc.) so `expr.freeze` in a const initializer (issue
 # #63) doesn't fall through to the "0" fallback.
    if mname == "freeze"
      return rc
    end

 # positive? / negative?
    if mname == "positive?"
      return "(" + rc + " > 0)"
    end
    if mname == "negative?"
      return "(" + rc + " < 0)"
    end
    ""
  end

  def compile_object_method_expr(nid, mname, rc, recv_type)
 # `self.name` inside `def self.<m>` -- self is typed obj_<C>
 # by infer_type, but the runtime intent is the class itself.
 # Route to sp_class_to_s before the obj-dispatch arms below
 # would emit a no-op. Issue #509.
    if mname == "name" && @current_method_has_self == 0 && @current_class_idx >= 0
      recv_n = @nd_receiver[nid]
      if recv_n >= 0 && @nd_type[recv_n] == "SelfNode"
        @needs_class_table = 1
        return "sp_class_to_s(((sp_Class){" + cls_id_for_user_internal(@current_class_idx).to_s + "LL}))"
      end
    end
    if recv_type == "encoding"
      if mname == "name" || mname == "to_s"
        return "sp_encoding_name(" + rc + ")"
      end
      if mname == "inspect"
        return "sp_encoding_inspect(" + rc + ")"
      end
      if mname == "==" || mname == "eql?"
        arg0_enc_eq = -1
        if @nd_arguments[nid] >= 0
          args_enc_eq = get_args(@nd_arguments[nid])
          if args_enc_eq.length > 0
            arg0_enc_eq = args_enc_eq[0]
          end
        end
        if arg0_enc_eq >= 0 && infer_type(arg0_enc_eq) == "encoding"
          rhs_enc_eq = compile_expr(arg0_enc_eq)
          return "sp_encoding_eq(" + rc + ", " + rhs_enc_eq + ")"
        end
        return "FALSE"
      end
      if mname == "!="
        arg0_enc_ne = -1
        if @nd_arguments[nid] >= 0
          args_enc_ne = get_args(@nd_arguments[nid])
          if args_enc_ne.length > 0
            arg0_enc_ne = args_enc_ne[0]
          end
        end
        if arg0_enc_ne >= 0 && infer_type(arg0_enc_ne) == "encoding"
          rhs_enc_ne = compile_expr(arg0_enc_ne)
          return "(!sp_encoding_eq(" + rc + ", " + rhs_enc_ne + "))"
        end
        return "TRUE"
      end
      if mname == "class"
        bid_enc = builtin_class_id_for_name("Encoding")
        if bid_enc >= 0
          @needs_class_table = 1
          return "((sp_Class){" + bid_enc.to_s + "LL})"
        end
      end
      if mname == "nil?"
        return "FALSE"
      end
    end
 # methods on a sp_Class value.
 #
 # Phase 1: `.to_s` -> sp_class_to_s(c) (per-program
 # sp_class_names[] lookup).
 #
 # Phase 2 additions:
 # - `.name` / `.inspect` -- both alias `.to_s` in the simple
 # case. CRuby's #inspect is technically `"#<Class:Foo>"`
 # but Phase 2 keeps the bare-name shape consistent with
 # the existing #to_s; the canonical CRuby spelling is a
 # Phase 3 polish.
 # - `.==` / `.!=` / `.eql?` -- equality compares the cls_id
 # fields via the sp_class_eq runtime helper.
 #
 # Out of scope for Phase 2: `.superclass`, `.ancestors`,
 # `.<` / `.<=` / `.>` / `.>=`, dynamic `is_a?(c)` against a
 # variable, case-when on a Class value. Those need
 # precomputed ancestor tables (see docs/CLASS-OBJECT.md).
    if recv_type == "class"
 # `Kernel.<m>(args)` routes to the bare-method
 # dispatch (compile_no_recv_call_expr handles `sleep` /
 # `puts` / `rand` / etc. as zero-receiver calls already).
 # Bare `sleep(...)` works fine; the Kernel-prefixed form
 # was emit-0'd because compile_object_method_expr's
 # recv_type=="class" arms only covered class-introspection
 # methods. CRuby's Kernel includes every method-function
 # we already implement at the bare path, so the redirect
 # is uniform -- no per-method list needed here.
      recv_id = @nd_receiver[nid]
      if recv_id >= 0 && @nd_type[recv_id] == "ConstantReadNode" && @nd_name[recv_id] == "Kernel"
        return compile_no_recv_call_expr(nid, mname)
      end
      if mname == "to_s" || mname == "name" || mname == "inspect"
        @needs_class_table = 1
        return "sp_class_to_s(" + rc + ")"
      end
 # Module#const_defined?(:X) — static-class + literal-symbol-arg
 # fast path. Spinel emits one C global per user-class constant
 # named `cst_<Class>_<X>`, and the analyzer tracks those names
 # in `@const_names`. Look up via `find_const_idx` to fold to
 # TRUE / FALSE at compile time. Dynamic receivers or non-
 # literal symbol args (or builtin classes whose constants live
 # outside @const_names — Math::PI etc.) keep falling through.
      if mname == "const_defined?"
        recv_id_cd = @nd_receiver[nid]
        args_id_cd = @nd_arguments[nid]
        if recv_id_cd >= 0 && @nd_type[recv_id_cd] == "ConstantReadNode" && args_id_cd >= 0
          aa_cd = get_args(args_id_cd)
          if aa_cd.length >= 1 && @nd_type[aa_cd[0]] == "SymbolNode"
            qname_cd = @nd_name[recv_id_cd] + "_" + @nd_content[aa_cd[0]]
            if find_const_idx(qname_cd) >= 0
              return "TRUE"
            end
            return "FALSE"
          end
        end
      end
      if mname == "==" || mname == "eql?"
        rhs_eq = compile_arg0(nid)
        return "sp_class_eq(" + rc + ", " + rhs_eq + ")"
      end
      if mname == "!="
        rhs_ne = compile_arg0(nid)
        return "(!sp_class_eq(" + rc + ", " + rhs_ne + "))"
      end
 # `<class_value_slot>.nil?` — sp_Class's nil sentinel is
 # cls_id == -1 (matches sp_class_superclass's root return and
 # the default value emitted for unassigned `attr_accessor`
 # class slots). Without this arm the call falls through to the
 # constant-receiver dispatch which would emit
 # `sp_<Klass>_cls_nil_p()` against whatever concrete class the
 # slot was statically resolved to — an undeclared function.
      if mname == "nil?"
        return "((" + rc + ").cls_id == -1)"
      end
 # class hierarchy queries.
 # .superclass -> sp_class_superclass(c) (returns sp_Class{-1} for root)
 # .ancestors -> sp_class_ancestors_arr(c) (returns sp_PolyArray of boxed sp_Class)
 # <, <= -> sp_class_lt / sp_class_le (proper / non-proper subclass)
 # >, >= -> reversed args of the above.
      if mname == "superclass"
        @needs_class_table = 1
        @needs_class_parents = 1
        return "sp_class_superclass(" + rc + ")"
      end
      if mname == "ancestors"
        @needs_class_table = 1
        @needs_class_ancestors = 1
        @needs_rb_value = 1
        return "sp_class_ancestors_arr(" + rc + ")"
      end
      if mname == "<"
        @needs_class_table = 1
        @needs_class_ancestors = 1
        return "sp_class_lt(" + rc + ", " + compile_arg0(nid) + ")"
      end
      if mname == "<="
        @needs_class_table = 1
        @needs_class_ancestors = 1
        return "sp_class_le(" + rc + ", " + compile_arg0(nid) + ")"
      end
      if mname == ">"
        @needs_class_table = 1
        @needs_class_ancestors = 1
        return "sp_class_lt(" + compile_arg0(nid) + ", " + rc + ")"
      end
      if mname == ">="
        @needs_class_table = 1
        @needs_class_ancestors = 1
        return "sp_class_le(" + compile_arg0(nid) + ", " + rc + ")"
      end
 # Tier 5: `<sp_Class>.new` over a *dynamic*
 # Class value (Class-typed local / param / ivar). Routes
 # through the per-cls_id adapter table. The static constant
 # path (`Foo.new(...)`) keeps using constructor_class_name
 # / direct sp_<C>_new dispatch -- we only want dynamic
 # recv here.
      if mname == "new"
        recv_id_new = @nd_receiver[nid]
        recv_ty_new = recv_id_new >= 0 ? @nd_type[recv_id_new] : ""
        if recv_ty_new != "ConstantReadNode" && recv_ty_new != "ConstantPathNode"
          nargs_id = @nd_arguments[nid]
          if nargs_id < 0 || get_args(nargs_id).length == 0
            @needs_class_table = 1
            @needs_rb_value = 1
            return "sp_class_new_dispatch(" + rc + ")"
          end
        end
      end
 # `<obj>.class.<cmeth>(...)` lowering. The recv
 # here is itself a `<X>.class` CallNode -- the outer
 # `compile_call_expr` already emitted the inner sp_Class
 # literal into `rc`, but for a `cmeth` dispatch we want to
 # bypass the runtime sp_Class value and emit a direct
 # `sp_<C>_cls_<m>` call against the statically-known class.
 # Gated on the recv AST being a `class` CallNode whose own
 # recv has a known obj_<C> type, so dynamic poly Class
 # values still fall through (they're Phase 3 work).
      recv_id = @nd_receiver[nid]
      if recv_id >= 0 && @nd_type[recv_id] == "CallNode" && @nd_name[recv_id] == "class"
        inner_recv = @nd_receiver[recv_id]
        if inner_recv >= 0
          inner_t = infer_type(inner_recv)
          if is_obj_type(inner_t) == 1
            inner_bt = base_type(inner_t)
            inner_cname = inner_bt[4, inner_bt.length - 4]
            inner_ci = find_class_idx(inner_cname)
            if inner_ci >= 0
              owner_idx = cls_method_owner_for(inner_ci, mname, "cmeth")
              if owner_idx >= 0
                owner_name = @cls_names[owner_idx]
                ca = compile_call_args(nid)
 # when descendants of inner_ci override
 # `mname` as a cmeth, the static call below routes
 # everything to the base class -- wrong when the
 # runtime instance is actually a subclass. Lower to
 # a switch on `<inner>->cls_id` so the dispatch lands
 # on the override. Gated on:
 # - inner_recv simple (SelfNode or LocalVar) so its
 # C expression has no side effects and can be
 # reused for both `->cls_id` and the per-arm call.
 # - inner_ci non-value-type (value types have no
 # cls_id slot and no subclassing in spinel).
 # - args absent (the no-arg case covers the canonical
 # reproducer and lets us reuse compile_call_args
 # output across arms without reasoning about side
 # effects from arg expressions).
 # - all candidate owners' return types match (otherwise
 # a unified result temp can't be typed).
                ovr = ""
                if @cls_is_value_type[inner_ci] == 0 && ca == ""
                  nty = @nd_type[inner_recv]
                  if nty == "SelfNode" || nty == "LocalVariableReadNode"
                    ovr = cls_method_override_descendants(inner_ci, owner_idx, mname, "cmeth")
                  end
                end
                if ovr != ""
                  base_rt = cls_method_return(owner_idx, mname, "cmeth")
                  ovr_pairs = ovr.split(";", -1)
                  rt_ok = 1
                  op = 0
                  while op < ovr_pairs.length
                    pair = ovr_pairs[op].split(",", -1)
                    cand_owner_check = pair[1].to_i
                    cand_rt = cls_method_return(cand_owner_check, mname, "cmeth")
                    if cand_rt != base_rt
                      rt_ok = 0
                      op = ovr_pairs.length
                    else
                      op = op + 1
                    end
                  end
                  inner_c_chain = compile_expr(inner_recv)
                  tmp_chain = new_temp
                  default_call_chain = "sp_" + owner_name + "_cls_" + sanitize_name(mname) + "()"
                  if rt_ok == 1
 # Matching return types across base + descendants
 # (the canonical shape). Declare the temp with
 # the shared C type and put the base call in the
 # `default:` arm so a base-only implementation
 # that raises -- the Rails abstract-base pattern --
 # only fires when the runtime cls_id is the base
 # (or an unmodelled type), not on every dispatch.
                    rt_c_chain = c_type(base_rt)
                    emit("  " + rt_c_chain + " " + tmp_chain + " = " + c_default_val(base_rt) + ";")
                    emit("  switch (" + inner_c_chain + "->cls_id) {")
                    oi_chain = 0
                    while oi_chain < ovr_pairs.length
                      pair_chain = ovr_pairs[oi_chain].split(",", -1)
                      cand_cid_chain = pair_chain[0].to_i
                      cand_owner_chain = pair_chain[1].to_i
                      cand_name_chain = @cls_names[cand_owner_chain]
                      cand_call_chain = "sp_" + cand_name_chain + "_cls_" + sanitize_name(mname) + "()"
 # cls_id_for_user_internal converts the candidate
 # internal index to the unified id that the
 # constructor stamped into self->cls_id.
                      emit("    case " + cls_id_for_user_internal(cand_cid_chain).to_s + "LL: " + tmp_chain + " = " + cand_call_chain + "; break;")
                      oi_chain = oi_chain + 1
                    end
                    emit("    default: " + tmp_chain + " = " + default_call_chain + "; break;")
                    emit("  }")
                    return tmp_chain
                  else
 # candidate return types diverge -- the
 # canonical "abstract base raises, subclass returns
 # a concrete value" Rails pattern, plus the milder
 # "different concrete types per override". Box each
 # arm's return into sp_RbVal so the unified result
 # temp has a single C type, and route the base call
 # through the `default:` arm so a raise stub only
 # fires when the runtime cls_id genuinely lands on
 # the base. infer_type on the analyze side widens
 # the chain's return to "poly" so downstream
 # callers consume the boxed value through the
 # existing poly-dispatch machinery.
                    @needs_rb_value = 1
                    default_box_chain = box_value_to_poly(base_rt, default_call_chain)
                    emit("  sp_RbVal " + tmp_chain + " = sp_box_nil();")
                    emit("  switch (" + inner_c_chain + "->cls_id) {")
                    oi_div = 0
                    while oi_div < ovr_pairs.length
                      pair_div = ovr_pairs[oi_div].split(",", -1)
                      cand_cid_div = pair_div[0].to_i
                      cand_owner_div = pair_div[1].to_i
                      cand_name_div = @cls_names[cand_owner_div]
                      cand_rt_div = cls_method_return(cand_owner_div, mname, "cmeth")
                      cand_call_div = "sp_" + cand_name_div + "_cls_" + sanitize_name(mname) + "()"
                      cand_box_div = box_value_to_poly(cand_rt_div, cand_call_div)
                      emit("    case " + cls_id_for_user_internal(cand_cid_div).to_s + "LL: " + tmp_chain + " = " + cand_box_div + "; break;")
                      oi_div = oi_div + 1
                    end
                    emit("    default: " + tmp_chain + " = " + default_box_chain + "; break;")
                    emit("  }")
                    return tmp_chain
                  end
                end
                if ca == ""
                  return "sp_" + owner_name + "_cls_" + sanitize_name(mname) + "()"
                end
                return "sp_" + owner_name + "_cls_" + sanitize_name(mname) + "(" + ca + ")"
              end
            end
          end
        end
      end
    end
 # `<obj>.class` on an object with a statically-known
 # class. Returns a sp_Class value carrying the class id; the
 # surrounding chain consumes it (typically through the
 # recv_type == "class" arm above for the next method, or via
 # an assignment like `c = obj.class; c.to_s`).
    if mname == "class" && is_obj_type(recv_type) == 1
      cls_bt = base_type(recv_type)
      cls_cname = cls_bt[4, cls_bt.length - 4]
      cls_idx = find_class_idx(cls_cname)
      if cls_idx >= 0
        @needs_class_table = 1
        return "((sp_Class){" + cls_id_for_user_internal(cls_idx).to_s + "LL})"
      end
    end
 # `<primitive>.class` -- map each primitive type to its builtin
 # class. Issue #715.
    if mname == "class"
      prim_class_name_pc = ""
      bt_pc = base_type(recv_type)
      if bt_pc == "int" || bt_pc == "bigint"
        prim_class_name_pc = "Integer"
      elsif bt_pc == "float"
        prim_class_name_pc = "Float"
      elsif bt_pc == "string" || bt_pc == "mutable_str"
        prim_class_name_pc = "String"
      elsif bt_pc == "symbol"
        prim_class_name_pc = "Symbol"
      elsif bt_pc == "bool"
        prim_class_name_pc = "TrueClass"
 # bool's runtime class is TrueClass / FalseClass depending on
 # the value; emit a ternary so the static cls_id picks at runtime.
        @needs_class_table = 1
        bid_t = builtin_class_id_for_name("TrueClass")
        bid_f = builtin_class_id_for_name("FalseClass")
        if bid_t >= 0 && bid_f >= 0
          return "((" + rc + ") ? ((sp_Class){" + bid_t.to_s + "LL}) : ((sp_Class){" + bid_f.to_s + "LL}))"
        end
      elsif bt_pc == "nil"
        prim_class_name_pc = "NilClass"
      elsif bt_pc == "range"
        prim_class_name_pc = "Range"
      elsif bt_pc == "time"
        prim_class_name_pc = "Time"
      elsif bt_pc == "encoding"
        prim_class_name_pc = "Encoding"
      elsif is_array_type(bt_pc) == 1
        prim_class_name_pc = "Array"
      elsif is_hash_type(bt_pc) == 1
        prim_class_name_pc = "Hash"
      elsif bt_pc == "proc" || bt_pc == "lambda"
        prim_class_name_pc = "Proc"
      end
      if prim_class_name_pc != ""
        bid_pc = builtin_class_id_for_name(prim_class_name_pc)
        if bid_pc >= 0
          @needs_class_table = 1
          return "((sp_Class){" + bid_pc.to_s + "LL})"
        end
      end
    end
 # StringScanner: the type is a primitive (`stringscanner` →
 # `sp_StringScanner *`); methods route to the sp_StringScanner_*
 # helpers in libspinel_rt.a (lib/sp_strscan.c).
    if recv_type == "stringscanner"
      ssm = strscan_runtime_call(mname, rc, nid)
      return ssm if ssm != ""
    end
 # Object method calls
    if is_obj_type(recv_type) == 1
      bt = base_type(recv_type)
      cname = bt[4, bt.length - 4]
      ci = find_class_idx(cname)
      if ci >= 0
 # `undef <m>` recorded in @undef_*: raise NoMethodError at
 # the call site so the rescue block sees it. The slot was
 # already pruned from @cls_meth_names by
 # collect_class_method_undef; this check fires before any
 # other dispatch arm. Issue #717.
        u_chk = 0
        u_ci = ci
        while u_ci >= 0 && u_chk == 0
          ui = 0
          while ui < @undef_class_idx.length
            if @undef_class_idx[ui] == u_ci && @undef_method[ui] == mname
              u_chk = 1
              ui = @undef_class_idx.length
            else
              ui = ui + 1
            end
          end
          if u_chk == 0
            if @cls_parents[u_ci] != ""
              u_ci = find_class_idx(@cls_parents[u_ci])
            else
              u_ci = -1
            end
          end
        end
        if u_chk == 1
          @needs_setjmp = 1
          rt_u = infer_type(nid)
          return "(sp_raise_cls(\"NoMethodError\", \"undefined method '" + mname + "' for " + cname + "\"), " + c_default_val(rt_u) + ")"
        end
        arrow = "->"
        if @cls_is_value_type[ci] == 1
          arrow = "."
        end
 # attr_reader -- walks the parent chain for inherited
 # attr_accessor / attr_reader (issue #508).
        if cls_has_attr_reader(ci, mname) == 1
          return rc + arrow + sanitize_ivar(mname)
        end
 # attr_writer
        if mname.length > 1
          if mname[mname.length - 1] == "="
            bname = mname[0, mname.length - 1]
            writers = @cls_attr_writers[ci].split(";", -1)
            j = 0
            while j < writers.length
              if writers[j] == bname
 # Box the rhs when the slot is poly so the assignment
 # type-matches at C level. Spill the rhs to a typed
 # temp first via a statement-expression so its side
 # effects run exactly once: the chain's value must be
 # the *original* rhs (Ruby's `obj.attr = v` returns
 # `v`), so without the temp the comma form would
 # textually substitute `arg0_w` twice and re-execute
 # any function call inside it.
                slot_t = cls_ivar_type(ci, "@" + bname)
                arg0_w = compile_arg0(nid)
                if slot_t == "poly"
                  arg_t = "int"
                  args_id_w = @nd_arguments[nid]
                  if args_id_w >= 0
                    arg_ids_w = get_args(args_id_w)
                    if arg_ids_w.length > 0
                      arg_t = infer_type(arg_ids_w[0])
                    end
                  end
                  tmp_w = new_temp
                  boxed = box_value_to_poly(arg_t, tmp_w)
                  return "({" + c_type(arg_t) + " " + tmp_w + " = " + arg0_w + "; " + rc + arrow + sanitize_ivar(bname) + " = " + boxed + "; " + tmp_w + ";})"
                end
 # promote-mode-widened ivar: wrap an int rhs through
 # sp_bigint_new_int. Mirror the bigint coerce branches at
 # the other ivar-write sites (line 24924, etc.).
                if slot_t == "bigint"
                  arg_t_bw = "int"
                  args_id_bw = @nd_arguments[nid]
                  if args_id_bw >= 0
                    arg_ids_bw = get_args(args_id_bw)
                    if arg_ids_bw.length > 0
                      arg_t_bw = infer_type(arg_ids_bw[0])
                    end
                  end
                  if arg_t_bw == "int"
                    @needs_bigint = 1
                    return "(" + rc + arrow + sanitize_ivar(bname) + " = sp_bigint_new_int(" + arg0_w + "))"
                  end
                end
                return "(" + rc + arrow + sanitize_ivar(bname) + " = " + arg0_w + ")"
              end
              j = j + 1
            end
          end
        end
 # Method call
        owner = find_method_owner(ci, mname)
        if owner != ""
          oci2 = find_class_idx(owner)
          midx2 = -1
          if oci2 >= 0
            midx2 = cls_find_method_direct(oci2, mname)
          end
 # Omit the trailing &block slot from default-padding when the
 # callee declares one — we'll fill it explicitly from the
 # call site's literal block below.
          has_proc = cls_method_has_block_param(oci2, midx2)
          ca = ""
          if midx2 >= 0
            ca = compile_typed_call_args(nid, oci2, midx2, has_proc)
          else
            ca = compile_call_args(nid)
          end
          bp = ""
          if has_proc == 1
            bp = block_forward_expr(nid)
            if bp == ""
 # The callee declares &block but the call site provides
 # none — fill the slot with NULL so the C call has the
 # right arity.
              bp = "0"
            end
          end
 # Pad the trailing `_block, _benv` yield-ABI slots when the callee's
 # body uses `yield`. The literal-block path inlines via
 # compile_yield_call_stmt and bypasses this C call entirely, so
 # reaching here means no literal block at the call site.
          yargs = cls_call_yargs(oci2, midx2)
          tail = build_call_tail(ca, bp, yargs)
 # Self-receiver override dispatch: when the receiver is
 # `self` inside a parent-class method body and descendants
 # of @current_class_idx override `mname` (including the
 # operator forms `[]` / `[]=` / `==` / `<=>` / etc.), emit
 # a `switch (self->cls_id)` so the dispatch lands on the
 # override at runtime. Mirrors the bare-imeth case at
 # compile_call_expr's @current_class_idx path. Without
 # this, `self[:foo]` inside `Base#fetch` resolved
 # statically to Base#__aref even when Article < Base
 # overrode `[]`. Issue #563.
          recv_id_so = @nd_receiver[nid]
          if recv_id_so >= 0 && @nd_type[recv_id_so] == "SelfNode" && @current_class_idx >= 0 && @cls_is_value_type[@current_class_idx] == 0 && has_proc == 0
            ovr_pairs_so = cls_method_override_descendants(@current_class_idx, oci2, mname, "imeth")
            if ovr_pairs_so != ""
              base_rt_so = cls_method_return(oci2, mname)
              base_rt_c_so = c_type(base_rt_so)
              rt_ok_so = 1
              ovr_list_so = ovr_pairs_so.split(";", -1)
              ol_so = 0
              while ol_so < ovr_list_so.length
                p_so = ovr_list_so[ol_so].split(",", -1)
                cand_owner_so = p_so[1].to_i
                cand_rt_so = cls_method_return(cand_owner_so, mname)
                if c_type(cand_rt_so) != base_rt_c_so
                  rt_ok_so = 0
                  ol_so = ovr_list_so.length
                else
                  ol_so = ol_so + 1
                end
              end
              base_ptypes_so = midx2 >= 0 ? cls_meth_ptypes_get(oci2, midx2) : "".split(",", -1)
              pt_ok_so = cls_imeth_override_ptypes_match(ovr_pairs_so, mname, base_ptypes_so)
              if rt_ok_so == 1 && pt_ok_so == 1
                tmp_so = new_temp
                default_call_so = ""
                if owner == cname
                  default_call_so = "sp_" + owner + "_" + sanitize_name(mname) + "(" + rc + tail + ")"
                else
                  default_call_so = "sp_" + owner + "_" + sanitize_name(mname) + "((sp_" + owner + " *)" + rc + tail + ")"
                end
                emit("  " + base_rt_c_so + " " + tmp_so + " = " + c_return_default(base_rt_so) + ";")
                emit("  switch (" + rc + "->cls_id) {")
                ol2_so = 0
                while ol2_so < ovr_list_so.length
                  p2_so = ovr_list_so[ol2_so].split(",", -1)
                  cand_internal_ci_so = p2_so[0].to_i
                  cand_cid_so = cls_id_for_user_internal(cand_internal_ci_so)
                  cand_owner2_so = p2_so[1].to_i
                  cand_name_so = @cls_names[cand_owner2_so]
                  cand_call_so = "sp_" + cand_name_so + "_" + sanitize_name(mname) + "((sp_" + cand_name_so + " *)" + rc + tail + ")"
                  emit("    case " + cand_cid_so.to_s + "LL: " + tmp_so + " = " + cand_call_so + "; break;")
                  ol2_so = ol2_so + 1
                end
                emit("    default: " + tmp_so + " = " + default_call_so + "; break;")
                emit("  }")
                return tmp_so
              end
            end
          end
          if owner == cname
            return "sp_" + owner + "_" + sanitize_name(mname) + "(" + rc + tail + ")"
          else
            return "sp_" + owner + "_" + sanitize_name(mname) + "((sp_" + owner + " *)" + rc + tail + ")"
          end
        end
      end
    end
    ""
  end

  def compile_int_class_fallback_expr(nid, mname, rc, recv_type)
 # Fallback: if receiver is int (e.g. from IntArray get) but method belongs to a class,
 # cast the int to the appropriate class pointer and dispatch.
 #
 # ...but NOT when `mname` is a method also defined on a
 # primitive type (String, Array, Hash, Integer, etc.). The
 # int-to-class cast here would silently pick the first user
 # class defining the same method name — e.g. routing
 # `s.index("[")` (a String method on a still-int-typed param)
 # to `ArticlesController#index`. A param typed `mrb_int`
 # because it wasn't pinned upstream is not the IntArray-of-
 # pointers shape this fallback was written for; refuse to
 # pick a user class and let the unresolved-call diagnostic
 # fire instead.
    if recv_type == "int" && primitive_method_shared_with_user_class(mname) == 1
      return ""
    end
    if recv_type == "int"
      ci2 = 0
      while ci2 < @cls_names.length
        cname2 = @cls_names[ci2]
        readers2 = @cls_attr_readers[ci2].split(";", -1)
        found_reader = 0
        j2 = 0
        while j2 < readers2.length
          if readers2[j2] == mname
            found_reader = 1
          end
          j2 = j2 + 1
        end
        if found_reader == 1
          return "((sp_" + cname2 + " *)" + rc + ")->" + sanitize_ivar(mname)
        end
 # Check writers
        if mname.length > 1
          if mname[mname.length - 1] == "="
            bname2 = mname[0, mname.length - 1]
            writers2 = @cls_attr_writers[ci2].split(";", -1)
            j2 = 0
            while j2 < writers2.length
              if writers2[j2] == bname2
                return "(((sp_" + cname2 + " *)" + rc + ")->" + sanitize_ivar(bname2) + " = " + compile_arg0(nid) + ")"
              end
              j2 = j2 + 1
            end
          end
        end
 # Check methods
        owner2 = find_method_owner(ci2, mname)
        if owner2 != ""
          oci3 = find_class_idx(owner2)
          midx3 = -1
          if oci3 >= 0
            midx3 = cls_find_method_direct(oci3, mname)
          end
          ca2 = ""
          if midx3 >= 0
            ca2 = compile_typed_call_args(nid, oci3, midx3, 0)
          else
            ca2 = compile_call_args(nid)
          end
          if ca2 != ""
            return "sp_" + owner2 + "_" + sanitize_name(mname) + "((sp_" + owner2 + " *)" + rc + ", " + ca2 + ")"
          else
            return "sp_" + owner2 + "_" + sanitize_name(mname) + "((sp_" + owner2 + " *)" + rc + ")"
          end
        end
        ci2 = ci2 + 1
      end
    end
    ""
  end


 # Inferred return type for `recv.mname(...)` when `recv` is poly.
 # If every user class that defines mname agrees on the return type,
 # that concrete type is used. If any two disagree, the call is
 # genuinely polymorphic and the caller must treat the result as
 # an sp_RbVal.
 # Returns 1 if class `ci` declares `mname` as an attr_reader (in
 # which case `obj.<mname>` reads `obj->iv_<mname>`).
  def cls_has_attr_reader(ci, mname)
    readers = @cls_attr_readers[ci].split(";", -1)
    j = 0
    while j < readers.length
      if readers[j] == mname
        return 1
      end
      j = j + 1
    end
    if @cls_parents[ci] != ""
      pi = find_class_idx(@cls_parents[ci])
      if pi >= 0
        return cls_has_attr_reader(pi, mname)
      end
    end
    0
  end

 # Decide whether a `<poly>[k]` call site (the outer `[]` in
 # `arr[i][k]` chains) can return int instead of poly. The poly
 # value came from `arr[i]` where `arr` is a poly_array; if every
 # element kind observed for `arr`'s slot has an int-returning
 # `[]` (IntArray + Method, the optcarrot `__fetch__` shape), the
 # outer dispatch is guaranteed to land on a poly carrying an int
 # tag, and we can read it as `mrb_int` directly. Returns 0
 # Return the type that compile_poly_method_call would actually emit
 # for `<poly>[idx]`, or "" if `nid` isn't that shape. Used by
 # infer_type to keep its static answer in sync with the emit; the
 # cached annotation from analyze can lag the emit's narrow_int
 # decision (block-param recvs short-circuit narrowing), and
 # downstream consumers like compile_arg0_as_int rely on the
 # answer matching the C type of the temp the emit produces.
  def poly_aref_call_type(nid)
    if @nd_type[nid] != "CallNode" || @nd_name[nid] != "[]"
      return ""
    end
    recv_id = @nd_receiver[nid]
    if recv_id < 0 || infer_type(recv_id) != "poly"
      return ""
    end
    if poly_index_narrow_int(nid) == 1
      return "int"
    end
    "poly"
  end

 # `nullable_poly_hash[k]` — recv's static type carries `?` (a
 # `if recv.nil?; return; end` upstream doesn't strip the suffix),
 # so analyze's [] dispatch falls through to the int default in
 # its cache. The actual emit is sp_<*PolyHash>_get(...) returning
 # sp_RbVal, so the cached "int" diverges from the C temp type and
 # the caller's int-typed param then receives an sp_RbVal unboxed.
 # Detect the shape here so compile_expr_for_expected_type and the
 # poly-dispatch arm can do the unbox even when cached "at" lied.
  def expr_emits_poly_rb_val(nid)
    if @nd_type[nid] != "CallNode" || @nd_name[nid] != "[]"
      return 0
    end
    recv_id = @nd_receiver[nid]
    if recv_id < 0
      return 0
    end
    rt = infer_type(recv_id)
    bt = base_type(rt)
    if bt == "sym_poly_hash" || bt == "str_poly_hash" || bt == "poly_poly_hash"
      return 1
    end
    0
  end

 # whenever the chain doesn't fit the pattern, so the default
 # poly-typed temp is preserved for everything else.
  def poly_index_narrow_int(nid)
    recv_id = @nd_receiver[nid]
    if recv_id < 0
      return 0
    end
 # The receiver must itself be a `[]` call (`arr[i]`).
    if @nd_type[recv_id] != "CallNode" || @nd_name[recv_id] != "[]"
      return 0
    end
    inner_recv = @nd_receiver[recv_id]
    if inner_recv < 0
      return 0
    end
 # Resolve the inner receiver to an ivar (directly, or via a
 # one-step LV alias from `lv = @ivar`).
    iname = ""
    if @nd_type[inner_recv] == "InstanceVariableReadNode"
      iname = @nd_name[inner_recv]
    elsif @nd_type[inner_recv] == "LocalVariableReadNode"
      lv_name = @nd_name[inner_recv]
 # Codegen-time scope alias takes priority (set by the LV-write
 # handler when `lv = @ivar` is emitted in this scope).
      iname = find_var_ivar_alias(lv_name)
 # Fallback for inference-time (`infer_type` before codegen,
 # when the scope stack hasn't been populated yet): walk the
 # enclosing method bodies for a single, unambiguous
 # `lv_name = @ivar` write. If the LV is reassigned from a
 # non-ivar elsewhere, leave iname empty and let the caller
 # bail out — the alias is no longer load-bearing.
      if iname == ""
        iname = find_lv_ivar_alias_in_ast(lv_name)
      end
    end
    if iname == "" || @current_class_idx < 0
      return 0
    end
 # The slot must currently be a poly_array — the only shape that
 # produces a poly via `[i]`.
    slot_t = cls_ivar_type(@current_class_idx, iname)
    if slot_t != "poly_array"
      return 0
    end
 # Derive the heterogeneous element kinds from
 # `cls_ivar_observed_types`. Each entry there is a slot type
 # the ivar held at some scan iteration: `int_array` means int
 # elements were stored, `obj_Method_ptr_array` means Method
 # elements, etc. The final `poly_array` entry just records the
 # widened state and adds no info. A bare `poly` observation
 # (whole-ivar `@x = something_poly`) is unknown — bail out.
    obs = cls_ivar_observed_types_for(@current_class_idx, iname)
    if obs == ""
      return 0
    end
    distinct = obs.split(",", -1)
    saw_any = 0
    di = 0
    while di < distinct.length
      t = distinct[di]
      if t == "" || t == "poly_array"
 # ignore — uninformative
      elsif t == "int_array" || t == "obj_Method_ptr_array"
 # int-returning element kind
        saw_any = 1
      else
 # any other observed slot type (str_array, float_array,
 # other ptr_array variants, "poly" whole-ivar writes…) is
 # not safely narrowable.
        return 0
      end
      di = di + 1
    end
    saw_any
  end

 # Inference-time fallback for resolving `lv_name -> @ivar` when the
 # codegen scope alias isn't available yet. Walks every method body
 # in the current class for `lv_name = @ivar` writes. Returns the
 # ivar name only if the LV is unambiguously aliased (one ivar
 # source, no non-ivar reassignment); empty string otherwise. Cached
 # in `@lv_alias_cache_<class>:<lv>` to keep the per-narrow cost
 # down — this is called during type inference, which runs many
 # iterations.
  def find_lv_ivar_alias_in_ast(lv_name)
    if @current_class_idx < 0
      return ""
    end
    cache_key = @current_class_idx.to_s + ":" + lv_name
    if @lv_alias_cache.key?(cache_key)
      return @lv_alias_cache[cache_key]
    end
    found = ""
    bodies = @cls_meth_bodies[@current_class_idx].split(";", -1)
    bi = 0
    while bi < bodies.length
      bid = bodies[bi].to_i
      if bid >= 0
        r = scan_lv_alias_for(bid, lv_name)
        if r == "?"
 # Ambiguous: at least one non-ivar write to this LV. The
 # alias is unstable and unsafe to use for narrowing.
          found = ""
          break
        end
        if r != ""
          if found != "" && found != r
            found = ""
            break
          end
          found = r
        end
      end
      bi = bi + 1
    end
    @lv_alias_cache[cache_key] = found
    found
  end

 # Recursive AST walk under `nid`. Returns:
 # "" — no `lv_name = ...` write seen
 # "?" — `lv_name = <non-ivar>` write seen (alias is unstable)
 # "@x" — exactly one ivar source `lv_name = @x` seen
  def scan_lv_alias_for(nid, lv_name)
    if nid < 0
      return ""
    end
    found = ""
    if @nd_type[nid] == "LocalVariableWriteNode" && @nd_name[nid] == lv_name
      ex_id = @nd_expression[nid]
      if ex_id >= 0 && @nd_type[ex_id] == "InstanceVariableReadNode"
        found = @nd_name[ex_id]
      else
        return "?"
      end
    end
    cs = []
    push_child_ids(nid, cs)
    k = 0
    while k < cs.length
      r = scan_lv_alias_for(cs[k], lv_name)
      if r == "?"
        return "?"
      end
      if r != ""
        if found != "" && found != r
          return "?"
        end
        found = r
      end
      k = k + 1
    end
    found
  end

 # Read the comma-separated whole-ivar observation list for a given
 # ivar by name. Used by `poly_index_narrow_int`.
  def cls_ivar_observed_types_for(ci, iname)
    if ci < 0 || ci >= @cls_ivar_observed_types.length
      return ""
    end
    names = @cls_ivar_names[ci].split(";", -1)
    parts = @cls_ivar_observed_types[ci].split(";", -1)
    k = 0
    while k < names.length
      if names[k] == iname && k < parts.length
        return parts[k]
      end
      k = k + 1
    end
    ""
  end

 # Poly-recv dispatch helpers (poly_dispatch_return_type /
 # poly_dispatch_narrow_class_set / poly_dispatch_class_in_set /
 # poly_dispatch_arm_param_compat) moved to compiler_helpers.rb
 # -- shared with spinel_analyze.rb.

 # Runtime tag-check for `<poly>.is_a?(<klass>)` / `kind_of?` /
 # `instance_of?`. Returns a C boolean expression for the named
 # built-in class (Integer, String, Float, etc.), including
 # mixin-style names that match every value (Object, Kernel,
 # BasicObject, Comparable). Returns "" when the name has no
 # SP_TAG_* mapping (caller falls back to user-class dispatch).
  def poly_is_a_tag_check(klass, recv_tmp, is_instance_of)
    if klass == "Integer"
      return "(" + recv_tmp + ".tag == SP_TAG_INT)"
    end
    if klass == "String"
      return "(" + recv_tmp + ".tag == SP_TAG_STR)"
    end
    if klass == "Float"
      return "(" + recv_tmp + ".tag == SP_TAG_FLT)"
    end
    if klass == "Symbol"
      return "(" + recv_tmp + ".tag == SP_TAG_SYM)"
    end
    if klass == "Encoding"
      return "(" + recv_tmp + ".tag == SP_TAG_ENCODING)"
    end
    if klass == "NilClass"
      return "(" + recv_tmp + ".tag == SP_TAG_NIL)"
    end
    if klass == "TrueClass"
      return "(" + recv_tmp + ".tag == SP_TAG_BOOL && " + recv_tmp + ".v.b)"
    end
    if klass == "FalseClass"
      return "(" + recv_tmp + ".tag == SP_TAG_BOOL && !" + recv_tmp + ".v.b)"
    end
    if klass == "Numeric"
      return "(" + recv_tmp + ".tag == SP_TAG_INT || " + recv_tmp + ".tag == SP_TAG_FLT)"
    end
    if klass == "Comparable"
      if is_instance_of == 1
        return "0"
      end
      return "(" + recv_tmp + ".tag == SP_TAG_INT || " + recv_tmp + ".tag == SP_TAG_FLT || " + recv_tmp + ".tag == SP_TAG_STR || " + recv_tmp + ".tag == SP_TAG_SYM)"
    end
    if klass == "Object" || klass == "Kernel" || klass == "BasicObject"
 # Every value is_a? Object in Ruby. instance_of?(Object) is FALSE
 # for primitives (their class is Integer/String/etc., not Object).
      if is_instance_of == 1
        return "0"
      end
      return "1"
    end
    if klass == "Array"
      return "(" + recv_tmp + ".tag == SP_TAG_OBJ && (" + recv_tmp + ".cls_id == SP_BUILTIN_INT_ARRAY || " + recv_tmp + ".cls_id == SP_BUILTIN_STR_ARRAY || " + recv_tmp + ".cls_id == SP_BUILTIN_FLT_ARRAY || " + recv_tmp + ".cls_id == SP_BUILTIN_SYM_ARRAY || " + recv_tmp + ".cls_id == SP_BUILTIN_PTR_ARRAY || " + recv_tmp + ".cls_id == SP_BUILTIN_POLY_ARRAY))"
    end
    if klass == "Hash"
      return "(" + recv_tmp + ".tag == SP_TAG_OBJ && (" + recv_tmp + ".cls_id == SP_BUILTIN_STR_INT_HASH || " + recv_tmp + ".cls_id == SP_BUILTIN_STR_STR_HASH || " + recv_tmp + ".cls_id == SP_BUILTIN_INT_STR_HASH || " + recv_tmp + ".cls_id == SP_BUILTIN_SYM_INT_HASH || " + recv_tmp + ".cls_id == SP_BUILTIN_SYM_STR_HASH || " + recv_tmp + ".cls_id == SP_BUILTIN_STR_POLY_HASH || " + recv_tmp + ".cls_id == SP_BUILTIN_SYM_POLY_HASH))"
    end
    if klass == "Range"
      return "(" + recv_tmp + ".tag == SP_TAG_OBJ && " + recv_tmp + ".cls_id == SP_BUILTIN_RANGE)"
    end
    if klass == "Proc"
      return "(" + recv_tmp + ".tag == SP_TAG_OBJ && " + recv_tmp + ".cls_id == SP_BUILTIN_PROC)"
    end
    ""
  end

  def compile_poly_method_call(nid, rc, mname)
    @needs_rb_value = 1
    if mname == "nil?"
      return "sp_poly_nil_p(" + rc + ")"
    end
    if mname == "to_s"
      return "sp_poly_to_s(" + rc + ")"
    end
 # `<poly>.inspect` -- canonical Ruby-style representation
 # (nil -> "nil", strings quoted, etc.). #532's
 # `puts pos.inspect` flows through this when pos came from
 # the nullable `String#index`.
    if mname == "inspect"
      return "sp_poly_inspect(" + rc + ")"
    end
    if mname == "to_i"
 # Unbox the poly value's int payload. For SP_TAG_INT it's the
 # raw `v.i`. For SP_TAG_OBJ branches the runtime values are
 # always pointers — `.to_i` on a class that doesn't define
 # `to_i` is the obj-id in Ruby; we approximate as 0 since
 # spinel doesn't expose a stable obj-id and the only practical
 # use is unboxing a poly-with-int payload (e.g. the result of
 # `arr[i][j]` over a heterogeneous IntArray + Method array,
 # whose dispatch arms all box back to SP_TAG_INT).
      tmp = new_temp
      recv_tmp = new_temp
      emit("  sp_RbVal " + recv_tmp + " = " + rc + ";")
      emit("  mrb_int " + tmp + " = (" + recv_tmp + ".tag == SP_TAG_INT) ? " + recv_tmp + ".v.i : 0;")
      return tmp
    end
 # `<poly>.is_a?(<Class>)` / `kind_of?` / `instance_of?` — decide
 # at runtime by inspecting the SP_TAG_* tag (and cls_id for
 # SP_TAG_OBJ). Without this branch the call falls through to the
 # SP_TAG_OBJ dispatch below, which has no `is_a?` method on any
 # user class — every primitive arm returns the default and
 # `is_a?(Integer)` on a poly slot is always falsy. Common in
 # dispatch helpers like `(addr.is_a?(Integer) ? [addr] : addr).each`.
    if mname == "is_a?" || mname == "kind_of?" || mname == "instance_of?"
      args_id = @nd_arguments[nid]
      if args_id >= 0
        a = get_args(args_id)
        if a.length > 0
 # dynamic Class arg on a poly
 # recv. Recover the recv's cls_id with sp_class_for_poly,
 # then sp_class_le against the runtime-supplied Class.
 # instance_of? still needs equality on the resolved
 # cls_id; sp_class_eq handles that.
          arg_t = infer_type(a[0])
          if arg_t == "class" && @nd_type[a[0]] != "ConstantReadNode"
            recv_tmp = new_temp
            emit("  sp_RbVal " + recv_tmp + " = " + rc + ";")
            @needs_class_table = 1
            @needs_class_ancestors = 1
            if mname == "instance_of?"
              return "sp_class_eq(sp_class_for_poly(" + recv_tmp + "), " + compile_expr(a[0]) + ")"
            end
            return "sp_class_le(sp_class_for_poly(" + recv_tmp + "), " + compile_expr(a[0]) + ")"
          end
          arg_name = @nd_name[a[0]]
          recv_tmp = new_temp
          emit("  sp_RbVal " + recv_tmp + " = " + rc + ";")
          io = mname == "instance_of?" ? 1 : 0
          tag_check = poly_is_a_tag_check(arg_name, recv_tmp, io)
          if tag_check != ""
            return tag_check
          end
 # User-defined class: match by cls_id. instance_of? requires
 # exact class; is_a?/kind_of? include subclasses, so
 # enumerate user classes whose ancestor chain reaches
 # arg_name (cls_is_descendant) and OR them in.
          ci = find_class_idx(arg_name)
          if ci >= 0
 # Tier 4: cls_id stamped on boxed instances is unified
 # (BC + internal_ci) -- compare against that.
            ci_uid = cls_id_for_user_internal(ci)
            if mname == "instance_of?"
              return "(" + recv_tmp + ".tag == SP_TAG_OBJ && " + recv_tmp + ".cls_id == " + ci_uid.to_s + ")"
            end
            check = "(" + recv_tmp + ".tag == SP_TAG_OBJ && (" + recv_tmp + ".cls_id == " + ci_uid.to_s
            cn = 0
            while cn < @cls_names.length
              if cn != ci && cls_is_descendant(cn, ci) == 1
                check = check + " || " + recv_tmp + ".cls_id == " + cls_id_for_user_internal(cn).to_s
              end
              cn = cn + 1
            end
            check = check + "))"
            return check
          end
          return "0"
        end
      end
      return "0"
    end
 # For object method calls, dispatch based on cls_id. Two namespaces
 # of cls_id share SP_TAG_OBJ:
 # - non-negative: index into @cls_names (user-defined classes)
 # - negative SP_BUILTIN_*: built-in pointer types (IntArray, ...)
 # The result temp is typed by the method's return type. If user
 # classes disagree on that type, the result is sp_RbVal and each
 # branch boxes its concrete return value.
 # Pre-compute arg base types (just `infer_type`, no emit) so the
 # return-type analysis can apply the same param-incompat
 # suppression the emit loop uses below. Without this the
 # result temp widens to sp_RbVal whenever an unreachable arm
 # has a different return type. Issue #549.
    args_id_pre = @nd_arguments[nid]
    arg_types_pre = "".split(",", -1)
    if args_id_pre >= 0
      aargs_pre = get_args(args_id_pre)
      kp = 0
      while kp < aargs_pre.length
        arg_types_pre.push(infer_type(aargs_pre[kp]))
        kp = kp + 1
      end
    end
    ret_type = poly_dispatch_return_type(mname, nid, arg_types_pre)
 # Approach 2 narrowing: `<poly>[k]` defaults to poly because the
 # static `[]` dispatch can't pin the return; check whether the
 # poly receiver here came from `<poly_array>[i]` whose every
 # observed element kind has an int-returning `[]` (IntArray,
 # Method-with-int-return). If so, narrow to int so the slot
 # @_pc / @_addr / etc. on the caller side stays mrb_int instead
 # of widening to sp_RbVal and breaking downstream `iv += 1`,
 # `~poly`, and friends.
    narrowed_int_idx = 0
    if ret_type == "poly" && mname == "[]"
      narrowed_int_idx = poly_index_narrow_int(nid)
      if narrowed_int_idx == 1
        ret_type = "int"
      end
    end
    is_poly_ret = ret_type == "poly" ? 1 : 0
    ret_ct = c_type(ret_type)
    ret_def = c_default_val(ret_type)
 # Stash the receiver in a temp so we don't re-evaluate the
 # expression for every if-branch below.
    recv_tmp = new_temp
    emit("  sp_RbVal " + recv_tmp + " = " + rc + ";")
 # Compile the call's argument list once. Track the inferred
 # source type alongside the compiled expression so the int-bit
 # branch below can unbox a poly arg without re-walking the AST.
    arg_compiled = "".split(",", -1)
    arg_types = "".split(",", -1)
    aargs_for_unbox = []
    arg_strs = ""
    args_id = @nd_arguments[nid]
    if args_id >= 0
      aargs = get_args(args_id)
      k = 0
      while k < aargs.length
        ce = compile_expr(aargs[k])
        arg_compiled.push(ce)
        arg_types.push(infer_type(aargs[k]))
        aargs_for_unbox.push(aargs[k])
        arg_strs = arg_strs + ", " + ce
        k = k + 1
      end
    end
    tmp = new_temp
    emit("  " + ret_ct + " " + tmp + " = " + ret_def + ";")
 # `int[i]` (bit-extraction) on a poly receiver. When a CPU
 # register / scratch ivar is widened to sp_RbVal but still
 # carries an int value, `pc[8]` (the page-bit test in branch
 # instructions etc.) must compile to `(pc >> 8) & 1`, not to
 # the array dispatch in the SP_TAG_OBJ block below — which
 # would silently leave the result at nil and miscount cycles.
 # Only emit the int-bit-extract fallback when the index
 # argument is itself an int (or a poly we can unbox to int).
 # For non-int keys (string, sym, ...) the SP_TAG_INT branch
 # is unreachable at runtime and `(recv.v.i >> key)` is
 # invalid C — `>> const char *` won't compile.
    if mname == "[]" && arg_compiled.length >= 1 && (arg_types[0] == "int" || arg_types[0] == "poly" || arg_types[0] == "bigint")
      a0_int = arg_compiled[0]
      if arg_types[0] == "poly"
        a0_int = "(" + a0_int + ").v.i"
      end
      if arg_types[0] == "bigint" || (arg_types[0] == "int" && (a0_int.start_with?("sp_bigint_") || a0_int.start_with?("(sp_Bigint *)")))
        @needs_bigint = 1
        a0_int = "sp_bigint_to_int((sp_Bigint *)" + a0_int + ")"
      end
      bit = "((" + recv_tmp + ".v.i >> (" + a0_int + ")) & 1)"
      brhs = is_poly_ret == 1 ? "sp_box_int(" + bit + ")" : bit
      emit("  if (" + recv_tmp + ".tag == SP_TAG_INT) " + tmp + " = " + brhs + ";")
    end
 # 2-arg `[]` on a poly recv carrying a String: `s[start, length]`
 # substring. Mirrors compile_string_method_expr's typed path
 # using sp_str_sub_range. Issue #659. Without this arm, the
 # poly recv falls through to the SP_TAG_OBJ block (no String
 # branch), and the result temp stays sp_box_nil() -> empty.
    if mname == "[]" && arg_compiled.length == 2 && is_poly_ret == 1
      a1_t_idx = arg_types.length > 0 ? arg_types[0] : ""
      a2_t_idx = arg_types.length > 1 ? arg_types[1] : ""
      if (a1_t_idx == "int" || a1_t_idx == "poly" || base_type(a1_t_idx) == "bigint") &&
         (a2_t_idx == "int" || a2_t_idx == "poly" || base_type(a2_t_idx) == "bigint")
        a1s_idx = arg_compiled[0]
        if a1_t_idx == "poly"
          a1s_idx = "(" + a1s_idx + ").v.i"
        elsif base_type(a1_t_idx) == "bigint"
          @needs_bigint = 1
          a1s_idx = "sp_bigint_to_int((sp_Bigint *)" + a1s_idx + ")"
        end
        a2s_idx = arg_compiled[1]
        if a2_t_idx == "poly"
          a2s_idx = "(" + a2s_idx + ").v.i"
        elsif base_type(a2_t_idx) == "bigint"
          @needs_bigint = 1
          a2s_idx = "sp_bigint_to_int((sp_Bigint *)" + a2s_idx + ")"
        end
        ssub_c = "sp_str_sub_range(" + recv_tmp + ".v.s, " + a1s_idx + ", " + a2s_idx + ")"
        emit("  if (" + recv_tmp + ".tag == SP_TAG_STR) " + tmp + " = sp_box_str(" + ssub_c + ");")
      end
    end
 # SP_TAG_STR arm for string methods that have a concrete
 # str-recv lowering. `v.gsub(/re/, repl)` where v is poly
 # (e.g. v came from `poly_hash[k]`) needs a per-tag dispatch
 # arm — otherwise the poly recv falls through to the
 # SP_TAG_OBJ block, which has no String-method handler, and
 # the result temp stays at its default (mrb_int 0). The
 # caller's downstream assignment to a const char * slot then
 # fails C compile.
    if mname == "gsub" || mname == "sub"
      args_id_gs = @nd_arguments[nid]
      if args_id_gs >= 0
        a_gs = get_args(args_id_gs)
        if a_gs.length >= 2
          rpat_gs = regex_pat_c_expr(a_gs[0])
          fn_gs = mname == "gsub" ? "sp_re_gsub" : "sp_re_sub"
          str_fn_gs = mname == "gsub" ? "sp_str_gsub" : "sp_str_sub"
          rep_gs = compile_expr(a_gs[1])
          if rpat_gs != ""
 # gsub(regex, hash) on the SP_TAG_STR poly arm. Issue #503:
 # the typed-receiver path (compile_string_method_expr) routes
 # str_str_hash replacements through `sp_re_gsub_str_str_hash`;
 # the poly arm previously fell through to `sp_re_gsub` and
 # smuggled the hash pointer through where `const char *rep`
 # is expected. Mirror the typed-receiver branch here.
            if mname == "gsub" && infer_type(a_gs[1]) == "str_str_hash"
              call_gs = "sp_re_gsub_str_str_hash(" + rpat_gs + ", " + recv_tmp + ".v.s, " + rep_gs + ")"
            else
              call_gs = fn_gs + "(" + rpat_gs + ", " + recv_tmp + ".v.s, " + rep_gs + ")"
            end
          else
            call_gs = str_fn_gs + "(" + recv_tmp + ".v.s, " + compile_expr(a_gs[0]) + ", " + rep_gs + ")"
          end
          str_rhs_gs = is_poly_ret == 1 ? "sp_box_str(" + call_gs + ")" : call_gs
          emit("  if (" + recv_tmp + ".tag == SP_TAG_STR) " + tmp + " = " + str_rhs_gs + ";")
        end
      end
    end
 # SP_TAG_STR arm for length / size. `v.length` where v is poly
 # (e.g. v came from `poly_array[i]`) carrying a string at
 # runtime needs a tag-dispatch arm — without this the only
 # length emits live inside the SP_TAG_OBJ block below (typed
 # array variants), so a string-tagged poly always read 0.
 # Surfaces in `if v.is_a?(String) && v.length > 0 ; ... end`
 # against a poly_array[i] receiver: the && condition's second
 # half stays 0, the then-arm never fires, and the user-level
 # guarded code path is silently skipped.
    if mname == "length" || mname == "size"
      slen_c = "sp_str_length(" + recv_tmp + ".v.s)"
      if is_poly_ret == 1
        slen_rhs = "sp_box_int(" + slen_c + ")"
      elsif base_type(ret_type) == "bigint"
        @needs_bigint = 1
        slen_rhs = "sp_bigint_new_int(" + slen_c + ")"
      else
        slen_rhs = slen_c
      end
      emit("  if (" + recv_tmp + ".tag == SP_TAG_STR) " + tmp + " = " + slen_rhs + ";")
    end
 # SP_TAG_STR arm for empty? on a poly recv. Issue #552.
    if mname == "empty?"
      semp_c = "(sp_str_length(" + recv_tmp + ".v.s) == 0)"
      semp_rhs = is_poly_ret == 1 ? "sp_box_bool(" + semp_c + ")" : semp_c
      emit("  if (" + recv_tmp + ".tag == SP_TAG_STR) " + tmp + " = " + semp_rhs + ";")
    end
 # SP_TAG_STR arm for include? on a poly recv -- only fires
 # when the arg is a string (CRuby's String#include? takes
 # a substring; non-string args TypeError at runtime, so
 # we leave the result temp at its default in that case).
 # Issue #558.
    if mname == "include?" && arg_compiled.length >= 1 && (arg_types.length == 0 || arg_types[0] == "string" || arg_types[0] == "mutable_str" || arg_types[0] == "poly")
      sinc_arg = arg_compiled[0]
      if arg_types.length > 0 && arg_types[0] == "poly"
        sinc_arg = "(" + sinc_arg + ").v.s"
      end
      sinc_c = "sp_str_include(" + recv_tmp + ".v.s, " + sinc_arg + ")"
      sinc_rhs = is_poly_ret == 1 ? "sp_box_bool(" + sinc_c + ")" : sinc_c
      emit("  if (" + recv_tmp + ".tag == SP_TAG_STR) " + tmp + " = " + sinc_rhs + ";")
    end
    emit("  if (" + recv_tmp + ".tag == SP_TAG_OBJ) {")
 # User-class dispatch. Narrow the candidate set when the recv
 # is an ivar whose observed types are entirely concrete obj_<C>
 # entries — the runtime value can only be an instance of one
 # of those classes, so dispatch arms for unrelated classes
 # that happen to share the method name are unreachable.
 # Without this filter, Issue #575 surfaces: a same-named method
 # on a class never assigned to the ivar (e.g. an Unrelated#run
 # with zero args returning int when the ivar only ever sees
 # Worker#run(item) returning string) widens the dispatch
 # result temp to sp_RbVal and trips downstream type-strict
 # consumers (sp_file_write etc.). The return-type union in
 # poly_dispatch_return_type already consults this set; the
 # emit loop just needed the matching skip.
    dispatch_narrow_set = poly_dispatch_narrow_class_set(nid)
    poly_dispatch_arms_emitted = 0
    i = 0
    while i < @cls_names.length
      if dispatch_narrow_set != "" && poly_dispatch_class_in_set(dispatch_narrow_set, i) == 0
        i = i + 1
        next
      end
      cname = @cls_names[i]
      midx = cls_find_method_direct(i, mname)
      owner_idx = i
      if midx < 0
        owner_name = find_method_owner(i, mname)
        if owner_name != ""
          owner_idx = find_class_idx(owner_name)
          if owner_idx >= 0
            midx = cls_find_method_direct(owner_idx, mname)
          end
        end
      end
      if midx >= 0
 # Match each arm to the target method's *fixed* C arity:
 # pad missing trailing slots with default-typed zeros, and
 # truncate extras (when the call site supplies more args than
 # this candidate accepts — happens when several classes share
 # the method name but disagree on parameter count).
        arm_arg_strs = ""
        arm_ptypes = cls_meth_ptypes_get(owner_idx, midx)
        pk = 0
        while pk < arm_ptypes.length
          if pk < arg_compiled.length
 # When this arm's param widened to `poly` (cross-
 # call-site union) but the call site supplied a
 # concrete value (string / mrb_int / symbol / ...),
 # box it via the appropriate sp_box_* helper so the
 # arg type matches the slot — otherwise gcc errors
 # `incompatible type for argument` on `const char *` /
 # `mrb_int` into a `sp_RbVal`. The inverse direction
 # (poly arg into a concrete-typed param) is handled
 # downstream; this only does the boxing direction.
            arg_v = arg_compiled[pk]
            arm_pt_base = base_type(arm_ptypes[pk])
 # Inverse direction: this arm expects a concrete primitive
 # but the call site supplied a value whose actual C type
 # is sp_RbVal (analyze's cached `at` lagged the emit -- see
 # expr_emits_poly_rb_val). Unbox via the matching union
 # field. Mirrors compile_expr_for_expected_type's poly→prim.
            if pk < aargs_for_unbox.length && expr_emits_poly_rb_val(aargs_for_unbox[pk]) == 1
              if arm_pt_base == "int" || arm_pt_base == "symbol"
                @needs_rb_value = 1
                arg_v = "(" + arg_v + ").v.i"
                if arm_pt_base == "symbol"
                  arg_v = "(sp_sym)" + arg_v
                end
              elsif arm_pt_base == "string" || arm_pt_base == "mutable_str"
                @needs_rb_value = 1
                arg_v = "(" + arg_v + ").v.s"
              elsif arm_pt_base == "float"
                @needs_rb_value = 1
                arg_v = "(" + arg_v + ").v.f"
              elsif arm_pt_base == "bool"
                @needs_rb_value = 1
                arg_v = "(" + arg_v + ").v.b"
              elsif arm_pt_base == "bigint"
                @needs_rb_value = 1
                @needs_bigint = 1
                arg_v = "sp_bigint_new_int((" + arg_v + ").v.i)"
              end
 # Mark arg as already coerced so the post-step int↔bigint
 # bridge below doesn't double-wrap.
              arg_types_v = arg_types[pk]
              arg_types[pk] = arm_pt_base
            end
            if arm_pt_base == "poly" && pk < arg_types.length && arg_types[pk] != "poly" && arg_types[pk] != ""
              arg_v = box_value_to_poly(arg_types[pk], arg_v)
            end
 # Promote mode: arm param is bigint but arg is int (literal /
 # int LV / int-typed expr) — wrap with sp_bigint_new_int. And
 # vice versa: arm param is int but arg is bigint — unbox via
 # sp_bigint_to_int.
            if arm_pt_base == "bigint" && pk < arg_types.length && base_type(arg_types[pk]) == "int"
              @needs_bigint = 1
              arg_v = "sp_bigint_new_int(" + arg_v + ")"
            elsif arm_pt_base == "int" && pk < arg_types.length && base_type(arg_types[pk]) == "bigint"
              @needs_bigint = 1
              arg_v = "sp_bigint_to_int((sp_Bigint *)" + arg_v + ")"
            end
            arm_arg_strs = arm_arg_strs + ", " + arg_v
          else
            pad = "0"
            pt_base = base_type(arm_ptypes[pk])
            if pt_base == "poly"
              pad = "sp_box_nil()"
            end
            arm_arg_strs = arm_arg_strs + ", " + pad
          end
          pk = pk + 1
        end
        call_expr = "sp_" + @cls_names[owner_idx] + "_" + sanitize_name(mname) + "((sp_" + @cls_names[owner_idx] + " *)" + recv_tmp + ".v.p" + arm_arg_strs + ")"
        rhs = call_expr
        if is_poly_ret == 1
          this_rt = cls_method_return(owner_idx, mname)
          rhs = box_val_to_poly(call_expr, this_rt)
        end
 # Suppress user-class arms whose param-slot types are
 # incompatible with the dispatch-site arg types — when the
 # box/unbox logic above can't bridge them. E.g. `sub.fetch(
 # "title", "")` dispatched at a site where `sub` may be a
 # FlashLike whose `fetch(key, default)` has `key: mrb_int`
 # (committed by sym-only direct callers) — the String "title"
 # can't be cast to `mrb_int` without a runtime sym lookup, and
 # the receiver in any source-level-valid path is a Hash, never
 # FlashLike, so the arm is unreachable at runtime. Parallels
 # the `narrowed_int_idx` skip below.
        arm_incompat = 0
        pk_chk = 0
        while pk_chk < arm_ptypes.length && pk_chk < arg_compiled.length && pk_chk < arg_types.length
          at_b = base_type(arg_types[pk_chk])
          pt_b = base_type(arm_ptypes[pk_chk])
          if at_b != "" && pt_b != "" && at_b != "poly" && pt_b != "poly" && at_b != pt_b
 # int/symbol/bool all lower to mrb_int — compatible.
            if (at_b == "int" && pt_b == "symbol") || (at_b == "symbol" && pt_b == "int") ||
               (at_b == "int" && pt_b == "bool")   || (at_b == "bool"   && pt_b == "int")
 # compatible
            elsif (at_b == "int" && pt_b == "bigint") || (at_b == "bigint" && pt_b == "int")
 # promote mode: int and bigint are numerically compatible.
 # compile_expr_for_expected_type box/unbox bridges them.
            else
              arm_incompat = 1
            end
          end
          pk_chk = pk_chk + 1
        end
 # Narrowed `[]` arms (Approach 2): suppress user-class arms
 # whose `[]` doesn't return int — the dead-code emit would
 # otherwise assign e.g. a string to the now-mrb_int result
 # temp and fail the C compile. The runtime can't reach these
 # arms anyway because the observation set narrowed past them.
        if arm_incompat == 1
 # skip — runtime can't reach this arm in a source-level-valid
 # path because the dispatch-site arg types preclude the user
 # class as the actual receiver.
        elsif narrowed_int_idx == 1 && cls_method_return(owner_idx, mname) != "int"
 # skip
        else
          emit("    if (" + recv_tmp + ".cls_id == " + cls_id_for_user_internal(i).to_s + ") " + tmp + " = " + rhs + ";")
          poly_dispatch_arms_emitted = poly_dispatch_arms_emitted + 1
        end
      elsif cls_has_attr_reader(i, mname) == 1
 # An auto-registered attr_reader doesn't appear in
 # @cls_meth_names, so the explicit-method walk above misses it.
 # Read the ivar directly. .
        ivar_expr = "((sp_" + cname + " *)" + recv_tmp + ".v.p)->" + sanitize_ivar("@" + mname)
        rhs = ivar_expr
        if is_poly_ret == 1
          this_rt = cls_ivar_type(i, "@" + mname)
          rhs = box_val_to_poly(ivar_expr, this_rt)
        end
        if narrowed_int_idx == 1 && cls_ivar_type(i, "@" + mname) != "int"
 # skip non-int attr_reader arms on a narrowed `[]`
        else
          emit("    if (" + recv_tmp + ".cls_id == " + cls_id_for_user_internal(i).to_s + ") " + tmp + " = " + rhs + ";")
          poly_dispatch_arms_emitted = poly_dispatch_arms_emitted + 1
        end
      elsif mname.length > 1 && mname[mname.length - 1] == "=" && cls_has_attr_writer(i, mname[0, mname.length - 1]) == 1
 # An auto-registered attr_writer setter (`obj.x = v`) on a
 # poly-typed receiver. Without this arm the cls_id dispatch
 # finds neither a real method nor an attr_reader, falls
 # through silently, and the assignment never executes —
 # `obj.x = v` becomes a no-op.
        bname = mname[0, mname.length - 1]
        raw_val = arg_compiled.length > 0 ? arg_compiled[0] : "0"
        raw_t   = arg_types.length > 0 ? arg_types[0] : ""
        slot_t  = cls_ivar_type(i, "@" + bname)
 # Match the rhs to the slot's concrete C type for *this arm*.
 # Three cases:
 # slot poly + arg concrete -> box the arg.
 # slot concrete + arg poly -> unbox the arg.
 # else -> direct assign.
 # Different arms in the dispatch may take different branches
 # (e.g. one slot is `int`, another is `string`).
        store_val = raw_val
        if slot_t == "poly" && raw_t != "poly" && raw_t != ""
          store_val = box_value_to_poly(raw_t, raw_val)
        elsif slot_t != "poly" && raw_t == "poly"
          store_val = unbox_poly_to(slot_t, raw_val)
        end
        ivar_lhs = "((sp_" + cname + " *)" + recv_tmp + ".v.p)->" + sanitize_ivar("@" + bname)
 # `x = v` returns v in Ruby. The result tmp's type is set by
 # poly_dispatch_return_type (poly when slot types diverge,
 # otherwise the common slot type). Box / coerce the stored
 # value into the tmp's expected shape.
        rhs_for_tmp = store_val
        if is_poly_ret == 1
          rhs_for_tmp = box_val_to_poly(store_val, slot_t)
        end
        emit("    if (" + recv_tmp + ".cls_id == " + cls_id_for_user_internal(i).to_s + ") { " + ivar_lhs + " = " + store_val + "; " + tmp + " = " + rhs_for_tmp + "; }")
        poly_dispatch_arms_emitted = poly_dispatch_arms_emitted + 1
      end
      i = i + 1
    end
 # Built-in type dispatch (cls_id < 0).
    emit_poly_builtin_dispatch(recv_tmp, mname, arg_compiled, arg_types, tmp, is_poly_ret, narrowed_int_idx, ret_type)
    emit("  }")
 # Warn when the user-class dispatch loop emitted zero arms. The
 # result temp keeps its default (0) and downstream code consuming
 # the result as the receiver's RBS-declared type emits ill-typed
 # C (e.g. mrb_int 0 passed to a pointer parameter). Common cause:
 # an RBS-typed singleton accessor (`def self.adapter: () -> Iface`)
 # for an abstract class with no concrete implementors in scope is
 # never assigned before the call. Issue #623. Matches the existing
 # `cannot resolve call to 'X' on Y (emitting 0)` pattern so editors
 # / CI grep for compile noise still surface this case.
    if poly_dispatch_arms_emitted == 0
      warn_unresolved_call(mname, "poly (no concrete user-class arm)")
    end
    tmp
  end

 # Emit branches for the built-in (negative cls_id) entries. Each
 # entry maps a (SP_BUILTIN_*, method) pair to a C expression.
 # Adding a new built-in type means one more `if` branch here.
  def emit_poly_builtin_dispatch(recv_tmp, mname, arg_compiled, arg_types, result_tmp, is_poly_ret, narrowed_int = 0, result_t = "")
    a0 = ""
    if arg_compiled.length > 0
      a0 = arg_compiled[0]
 # Unbox if poly / bigint — every built-in `[]` arm here passes
 # a0 to a function expecting `mrb_int` (sp_IntArray_get etc.,
 # or the Method fn_ptr's int parameter). When the caller's arg
 # is poly or promote-mode bigint, unbox before the C call.
      if arg_types.length > 0 && arg_types[0] == "poly"
        a0 = "(" + a0 + ").v.i"
      end
      if arg_types.length > 0 && arg_types[0] == "bigint"
        @needs_bigint = 1
        a0 = "sp_bigint_to_int((sp_Bigint *)" + a0 + ")"
      end
 # When the cache reports stale "int" but the actual emit is
 # bigint (arith / bitop / user-method returning bigint), use
 # the same unbox. arg_types is populated from infer_type; the
 # walker catches stale-int rhs shapes.
      if arg_compiled.length > 0 && (arg_types.length == 0 || arg_types[0] == "int") && a0 != ""
 # Need the original AST node to consult expr_emit_is_bigint;
 # the caller doesn't pass it, so we detect from the compiled
 # string instead: sp_bigint_* return-typed expressions all
 # start with sp_bigint_ except for `(sp_Bigint *)lv_x` casts.
        if a0.start_with?("sp_bigint_") || a0.start_with?("(sp_Bigint *)")
          @needs_bigint = 1
          a0 = "sp_bigint_to_int((sp_Bigint *)" + a0 + ")"
        end
      end
    end
 # `[]` — element types differ per built-in. When the result temp
 # is sp_RbVal (poly return), every branch can box into it. When
 # the temp is concretely typed, only built-ins whose element type
 # fits the temp can contribute — otherwise the assignment is a
 # C type mismatch. The unmatched runtime types simply leave the
 # temp at its default (`0`/empty) for that input, which is
 # acceptable since the caller's static type analysis already
 # picked a compatible result type.
 #
 # Every built-in [] arm here passes the key to a function
 # expecting `mrb_int`. Only emit the arms when the key type
 # is int or poly (poly is unboxed via `.v.i` above). For
 # non-int keys (string, sym), these arms are unreachable at
 # runtime (a poly recv carrying a String key would be a hash,
 # not an array) and emitting them produces Wint-conversion
 # warnings — or hard errors under -Werror.
    a0_is_int = arg_compiled.length >= 1 && (arg_types.length == 0 || arg_types[0] == "int" || arg_types[0] == "poly" || arg_types[0] == "bigint")
 # Hash dispatch arms for `[]` on a poly recv whose runtime
 # storage is a *-Hash variant. The chained `outer[k1][k2]`
 # shape where outer is StrPolyHash lands here — the inner []
 # recv carries an arbitrary str-keyed hash storage. Emit
 # arms keyed by the string-typed index. Sym-keyed variants
 # are skipped here because the sp_SymIntHash / sp_SymStrHash
 # typedefs are emit-gated by @needs flags set during pre-scan,
 # which doesn't see this dispatch path yet; the existing
 # sp_StrIntHash family ships unconditionally in sp_runtime.h.
    if mname == "[]" && arg_compiled.length >= 1
      key_t = arg_types.length > 0 ? arg_types[0] : ""
      if key_t == "string" || key_t == "mutable_str"
        if is_poly_ret == 1
          emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_STR_INT_HASH) " + result_tmp + " = sp_box_int(sp_StrIntHash_get((sp_StrIntHash *)" + recv_tmp + ".v.p, " + arg_compiled[0] + "));")
          emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_STR_STR_HASH) " + result_tmp + " = sp_box_str(sp_StrStrHash_get((sp_StrStrHash *)" + recv_tmp + ".v.p, " + arg_compiled[0] + "));")
          emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_STR_POLY_HASH) " + result_tmp + " = sp_StrPolyHash_get((sp_StrPolyHash *)" + recv_tmp + ".v.p, " + arg_compiled[0] + ");")
        end
      end
    end
 # `fetch` arms — parallel to `[]` above for the (key, default)
 # form. Each Str*-Hash variant tests has_key first, returns the
 # boxed value on hit, or the boxed default on miss. Sibling to
 # #456 (which added Hash arms to poly-recv `[]` / `[]=`); without
 # this, `sub.fetch("k", "d")` on a poly recv that resolves to a
 # Hash variant at runtime matches no arm and silently returns
 # the temp's nil default — even though the Hash holds the key.
 # Sym-keyed variants are deferred for the same `@needs`-gating
 # reason as `[]`.
    if mname == "fetch" && arg_compiled.length >= 1
      key_t = arg_types.length > 0 ? arg_types[0] : ""
      if (key_t == "string" || key_t == "mutable_str") && is_poly_ret == 1
        key_c = arg_compiled[0]
        def_box = "sp_box_nil()"
        if arg_compiled.length >= 2
          def_t = arg_types.length >= 2 ? arg_types[1] : ""
          def_c = arg_compiled[1]
          if def_t == "poly" || def_t == ""
            def_box = def_c
          else
            def_box = box_value_to_poly(def_t, def_c)
          end
        end
        emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_STR_INT_HASH) " + result_tmp + " = sp_StrIntHash_has_key((sp_StrIntHash *)" + recv_tmp + ".v.p, " + key_c + ") ? sp_box_int(sp_StrIntHash_get((sp_StrIntHash *)" + recv_tmp + ".v.p, " + key_c + ")) : " + def_box + ";")
        emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_STR_STR_HASH) " + result_tmp + " = sp_StrStrHash_has_key((sp_StrStrHash *)" + recv_tmp + ".v.p, " + key_c + ") ? sp_box_str(sp_StrStrHash_get((sp_StrStrHash *)" + recv_tmp + ".v.p, " + key_c + ")) : " + def_box + ";")
        emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_STR_POLY_HASH) " + result_tmp + " = sp_StrPolyHash_has_key((sp_StrPolyHash *)" + recv_tmp + ".v.p, " + key_c + ") ? sp_StrPolyHash_get((sp_StrPolyHash *)" + recv_tmp + ".v.p, " + key_c + ") : " + def_box + ";")
      end
    end
 # `dup` arms — Hash#dup on a poly recv whose runtime storage is
 # any hash variant. matched[:path_params].dup is the canonical
 # form in real-blog's request-params chain. Pre-fix the call
 # fell through to int default ("cannot resolve call to 'dup' on
 # int" warning), leaving downstream chained writes silently
 # against the int 0. Each arm dups via the matching runtime
 # helper and boxes back as obj. Only the always-in hash variants
 # (sp_runtime.h) are emitted; SymInt / SymStr variants are
 # typedef-gated by @needs flags which aren't reliably set at
 # this emit point.
    if mname == "dup"
      if is_poly_ret == 1
        emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_STR_INT_HASH) " + result_tmp + " = sp_box_obj((void *)sp_StrIntHash_dup((sp_StrIntHash *)" + recv_tmp + ".v.p), SP_BUILTIN_STR_INT_HASH);")
        emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_STR_STR_HASH) " + result_tmp + " = sp_box_obj((void *)sp_StrStrHash_dup((sp_StrStrHash *)" + recv_tmp + ".v.p), SP_BUILTIN_STR_STR_HASH);")
        emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_INT_STR_HASH) " + result_tmp + " = sp_box_obj((void *)sp_IntStrHash_dup((sp_IntStrHash *)" + recv_tmp + ".v.p), SP_BUILTIN_INT_STR_HASH);")
        emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_STR_POLY_HASH) " + result_tmp + " = sp_box_obj((void *)sp_StrPolyHash_dup((sp_StrPolyHash *)" + recv_tmp + ".v.p), SP_BUILTIN_STR_POLY_HASH);")
        emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_SYM_POLY_HASH) " + result_tmp + " = sp_box_obj((void *)sp_SymPolyHash_dup((sp_SymPolyHash *)" + recv_tmp + ".v.p), SP_BUILTIN_SYM_POLY_HASH);")
        emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_POLY_POLY_HASH) " + result_tmp + " = sp_box_obj((void *)sp_PolyPolyHash_dup((sp_PolyPolyHash *)" + recv_tmp + ".v.p), SP_BUILTIN_POLY_POLY_HASH);")
      end
    end
 # length / size arms — for a poly recv whose runtime storage
 # is an Array or Hash variant. The SP_TAG_STR length arm fires
 # earlier in compile_poly_method_call; this covers the
 # SP_TAG_OBJ side. Without these arms, a `param.length` call
 # on a body-usage-widened poly param (issue #552) silently
 # reads the result_tmp default (0) for every non-string
 # runtime value. Result type is always int / sp_box_int.
    if mname == "length" || mname == "size"
 # Pre-compute the wrap-by-int-result-type pattern once; the
 # length arms below paste this onto each runtime-typed length
 # call. poly-ret needs sp_box_int; bigint result slot needs
 # sp_bigint_new_int; everything else takes the mrb_int raw.
      pbd_len_open = ""
      pbd_len_close = ""
      if is_poly_ret == 1
        pbd_len_open = "sp_box_int("
        pbd_len_close = ")"
      elsif base_type(result_t) == "bigint"
        @needs_bigint = 1
        pbd_len_open = "sp_bigint_new_int("
        pbd_len_close = ")"
      end
      ic = pbd_len_open + "sp_IntArray_length((sp_IntArray *)" + recv_tmp + ".v.p)" + pbd_len_close
      emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_INT_ARRAY) " + result_tmp + " = " + ic + ";")
      fc = pbd_len_open + "sp_FloatArray_length((sp_FloatArray *)" + recv_tmp + ".v.p)" + pbd_len_close
      emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_FLT_ARRAY) " + result_tmp + " = " + fc + ";")
      sc = pbd_len_open + "sp_StrArray_length((sp_StrArray *)" + recv_tmp + ".v.p)" + pbd_len_close
      emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_STR_ARRAY) " + result_tmp + " = " + sc + ";")
      yc = pbd_len_open + "sp_IntArray_length((sp_IntArray *)" + recv_tmp + ".v.p)" + pbd_len_close
      emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_SYM_ARRAY) " + result_tmp + " = " + yc + ";")
      pc = pbd_len_open + "sp_PtrArray_length((sp_PtrArray *)" + recv_tmp + ".v.p)" + pbd_len_close
      emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_PTR_ARRAY) " + result_tmp + " = " + pc + ";")
      polyc = pbd_len_open + "sp_PolyArray_length((sp_PolyArray *)" + recv_tmp + ".v.p)" + pbd_len_close
      emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_POLY_ARRAY) " + result_tmp + " = " + polyc + ";")
      sihc = pbd_len_open + "sp_StrIntHash_length((sp_StrIntHash *)" + recv_tmp + ".v.p)" + pbd_len_close
      emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_STR_INT_HASH) " + result_tmp + " = " + sihc + ";")
