      emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_PTR_ARRAY) " + result_tmp + " = " + perhs + ";")
      polyec = "(sp_PolyArray_length((sp_PolyArray *)" + recv_tmp + ".v.p) == 0)"
