    end
 # `[]` with a symbol key — sym_poly_hash dispatch. Mirrors the
 # int-key block above for the case where a poly receiver carries
 # a SymPolyHash at runtime (e.g. a constant hash boxed back into
 # a slot whose static type is poly because of an earlier
 # is_a?(String) branch).
    a0_is_sym = arg_compiled.length >= 1 && arg_types.length >= 1 && arg_types[0] == "symbol"
    if mname == "[]" && a0_is_sym
      shc = "sp_SymPolyHash_get((sp_SymPolyHash *)" + recv_tmp + ".v.p, " + arg_compiled[0] + ")"
      shrhs = is_poly_ret == 1 ? shc : "(" + shc + ").v.i"
      emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_SYM_POLY_HASH) " + result_tmp + " = " + shrhs + ";")
 # SymIntHash arm: heterogeneous-element array of `{n: 3}`-style
 # hashes boxes each as SymIntHash. Returns mrb_int,
 # box to poly when the call site expects poly. Only emit when
 # the program already uses SymIntHash so we don't pull the
 # runtime helpers in for unrelated programs.
      if @needs_sym_int_hash == 1
        sihc = "sp_SymIntHash_get((sp_SymIntHash *)" + recv_tmp + ".v.p, " + arg_compiled[0] + ")"
        sihrhs = is_poly_ret == 1 ? "sp_box_int(" + sihc + ")" : sihc
        emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_SYM_INT_HASH) " + result_tmp + " = " + sihrhs + ";")
      end
      if @needs_sym_str_hash == 1
        sshc = "sp_SymStrHash_get((sp_SymStrHash *)" + recv_tmp + ".v.p, " + arg_compiled[0] + ")"
        sshrhs = is_poly_ret == 1 ? "sp_box_str(" + sshc + ")" : sshc
        emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_SYM_STR_HASH) " + result_tmp + " = " + sshrhs + ";")
      end
    end
 # `length` / `size` — every built-in array exposes its own
 # `_length` helper (sym_array shares IntArray's). PtrArray is
 # safe here because length doesn't need an element type.
    if mname == "length" || mname == "size"
 # Pick int-result wrap once: poly-ret needs sp_box_int, bigint
 # result slot needs sp_bigint_new_int, otherwise raw mrb_int.
      pmc_len_open = ""
      pmc_len_close = ""
      if is_poly_ret == 1
        pmc_len_open = "sp_box_int("
        pmc_len_close = ")"
      elsif base_type(result_t) == "bigint"
        @needs_bigint = 1
        pmc_len_open = "sp_bigint_new_int("
        pmc_len_close = ")"
      end
      ic = pmc_len_open + "sp_IntArray_length((sp_IntArray *)" + recv_tmp + ".v.p)" + pmc_len_close
      emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_INT_ARRAY) " + result_tmp + " = " + ic + ";")
      fc = pmc_len_open + "sp_FloatArray_length((sp_FloatArray *)" + recv_tmp + ".v.p)" + pmc_len_close
      emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_FLT_ARRAY) " + result_tmp + " = " + fc + ";")
      sc = pmc_len_open + "sp_StrArray_length((sp_StrArray *)" + recv_tmp + ".v.p)" + pmc_len_close
      emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_STR_ARRAY) " + result_tmp + " = " + sc + ";")
 # sym_array shares the IntArray representation (same `_length`).
      yc = pmc_len_open + "sp_IntArray_length((sp_IntArray *)" + recv_tmp + ".v.p)" + pmc_len_close
      emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_SYM_ARRAY) " + result_tmp + " = " + yc + ";")
      pc = pmc_len_open + "sp_PtrArray_length((sp_PtrArray *)" + recv_tmp + ".v.p)" + pmc_len_close
      emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_PTR_ARRAY) " + result_tmp + " = " + pc + ";")
      polyc = pmc_len_open + "sp_PolyArray_length((sp_PolyArray *)" + recv_tmp + ".v.p)" + pmc_len_close
      emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_POLY_ARRAY) " + result_tmp + " = " + polyc + ";")
    end
  end

 # Try to compile str[i] <op> "c" as direct char comparison
 # Returns "" if not applicable
  def try_char_cmp(nid, c_op)
    recv = @nd_receiver[nid]
    args_id = @nd_arguments[nid]
    if args_id < 0
      return ""
    end
    a = get_args(args_id)
    if a.length == 0
      return ""
    end
    arg_id = a[0]
    if @nd_type[arg_id] != "StringNode"
      return ""
    end
    lit = @nd_content[arg_id]
    if lit == ""
      lit = @nd_unescaped[arg_id]
    end
    if lit.length != 1
      return ""
    end
    if @nd_type[recv] != "CallNode" || @nd_name[recv] != "[]"
      return ""
    end
    sr = @nd_receiver[recv]
    if sr < 0 || infer_type(sr) != "string"
      return ""
    end
 # Skip the single-char fast path when the `[]` arg is a Range
 # (or anything other than an int). `s[i..j] == "/"` should
 # dispatch through sp_str_sub_range and a string compare, not
 # cast a RangeNode to mrb_int. Issue #644.
    sub_args_id = @nd_arguments[recv]
    if sub_args_id >= 0
      sub_a = get_args(sub_args_id)
      if sub_a.length > 0
        idx_t_chk = infer_type(sub_a[0])
        if idx_t_chk == "range" || sub_a.length >= 2
          return ""
        end
        if sub_a.length == 1 && @nd_type[sub_a[0]] == "RangeNode"
          return ""
        end
      end
    end
    str_c = compile_expr(sr)
    idx_c = compile_arg0(recv)
    ch = lit
    if lit == "\n"
      ch = "\\n"
    elsif lit == "\t"
      ch = "\\t"
    elsif lit == "\r"
      ch = "\\r"
    elsif lit.ord == 92 || lit.ord == 39
 # backslash or single quote — skip char optimization
      return ""
    end
    "(" + str_c + "[(mrb_int)" + idx_c + "] " + c_op + " '" + ch + "')"
  end

 # Helper for compile_eq's `<container_op> == nil` shape.
 # Returns the C truthy expression for the nil-on-miss check
 # (negated when op is "!="), or "" when the shape isn't
 # recognized so compile_eq falls through to its existing
 # type-strict short-circuits. Issue #562.
  def compile_container_op_nil_check(recv_nid, op)
    mname = @nd_name[recv_nid]
    inner_recv = @nd_receiver[recv_nid]
    if inner_recv < 0
      return ""
    end
    inner_t = infer_type(inner_recv)
    inner_c = compile_expr(inner_recv)
    args_id_c = @nd_arguments[recv_nid]
 # arr[i] == nil -> (i < 0 || i >= len).
    if mname == "[]" && is_array_type(inner_t) == 1 && args_id_c >= 0
      a_c = get_args(args_id_c)
      if a_c.length >= 1
        idx_c = compile_expr(a_c[0])
        len_fn = array_length_fn(inner_t)
        if len_fn != ""
          chk = "(" + idx_c + " < 0 || " + idx_c + " >= " + len_fn + "(" + inner_c + "))"
          return op == "==" ? chk : "(!" + chk + ")"
        end
      end
    end
 # hash[k] == nil -> !has_key?(k). For int-leaf hashes the
 # stored value 0 IS distinguishable from missing key via
 # has_key, so the check is sound (Hash#[] returns nil on
 # miss in CRuby).
    if mname == "[]" && is_hash_type(inner_t) == 1 && args_id_c >= 0
      a_c = get_args(args_id_c)
      if a_c.length >= 1
        has_key_fn = hash_has_key_fn(inner_t)
        if has_key_fn != ""
          key_c = hash_key_arg_for(inner_t, a_c[0])
          chk = "(!" + has_key_fn + "(" + inner_c + ", " + key_c + "))"
          return op == "==" ? chk : "(!" + chk + ")"
        end
      end
    end
 # arr.first / arr.last / arr.pop == nil -> (len == 0).
 # pop on an empty array is a no-op in CRuby (returns nil),
 # so the equality check pre-mutation answer is correct.
    if (mname == "first" || mname == "last" || mname == "pop") && is_array_type(inner_t) == 1
      len_fn = array_length_fn(inner_t)
      if len_fn != "" && (args_id_c < 0 || get_args(args_id_c).length == 0)
        chk = "(" + len_fn + "(" + inner_c + ") == 0)"
        return op == "==" ? chk : "(!" + chk + ")"
      end
    end
 # arr.delete_at(n) == nil -> (n < 0 || n >= len). Checked
 # BEFORE the mutation; CRuby's delete_at returns nil on
 # out-of-range without mutating.
    if mname == "delete_at" && is_array_type(inner_t) == 1 && args_id_c >= 0
      a_c = get_args(args_id_c)
      if a_c.length >= 1
        idx_c = compile_expr(a_c[0])
        len_fn = array_length_fn(inner_t)
        if len_fn != ""
          chk = "(" + idx_c + " < 0 || " + idx_c + " >= " + len_fn + "(" + inner_c + "))"
          return op == "==" ? chk : "(!" + chk + ")"
        end
      end
    end
 # arr.find_index(x) == nil -> !arr.include?(x).
    if mname == "find_index" && is_array_type(inner_t) == 1 && args_id_c >= 0
      a_c = get_args(args_id_c)
      if a_c.length >= 1
        inc_fn = array_include_fn(inner_t)
        if inc_fn != ""
          val_c = compile_expr(a_c[0])
          chk = "(!" + inc_fn + "(" + inner_c + ", " + val_c + "))"
          return op == "==" ? chk : "(!" + chk + ")"
        end
      end
    end
 # regex.match(str) == nil -> !regex.match?(str).
    if mname == "match" && args_id_c >= 0
      rpat = regex_pat_c_expr(inner_recv)
      if rpat != ""
        a_c = get_args(args_id_c)
        if a_c.length >= 1
          chk = "(!sp_re_match_p(" + rpat + ", " + compile_expr(a_c[0]) + "))"
          return op == "==" ? chk : "(!" + chk + ")"
        end
      end
    end
    ""
  end

 # Helper: array-type -> length helper fn name.
  def array_length_fn(t)
    if t == "int_array" || t == "sym_array"
      return "sp_IntArray_length"
    end
    if t == "float_array"
      return "sp_FloatArray_length"
    end
    if t == "str_array"
      return "sp_StrArray_length"
    end
    if t == "poly_array"
      return "sp_PolyArray_length"
    end
    if t.end_with?("_ptr_array")
      return "sp_PtrArray_length"
    end
    ""
  end

  def array_include_fn(t)
    if t == "int_array" || t == "sym_array"
      return "sp_IntArray_include"
    end
    if t == "float_array"
      return "sp_FloatArray_include"
    end
    if t == "str_array"
      return "sp_StrArray_include"
    end
    if t == "poly_array"
      return "sp_PolyArray_include"
    end
    ""
  end

  def hash_has_key_fn(t)
    if t == "str_int_hash"
      return "sp_StrIntHash_has_key"
    end
    if t == "str_str_hash"
      return "sp_StrStrHash_has_key"
    end
    if t == "str_poly_hash"
      return "sp_StrPolyHash_has_key"
    end
    if t == "sym_int_hash"
      return "sp_SymIntHash_has_key"
    end
    if t == "sym_str_hash"
      return "sp_SymStrHash_has_key"
    end
    if t == "sym_poly_hash"
      return "sp_SymPolyHash_has_key"
    end
    if t == "int_str_hash"
      return "sp_IntStrHash_has_key"
    end
    if t == "poly_poly_hash"
      return "sp_PolyPolyHash_has_key"
    end
    ""
  end

  def hash_key_arg_for(t, arg_id)
    if t == "poly_poly_hash"
      return box_expr_to_poly(arg_id)
    end
    if t.start_with?("str_")
      return compile_expr_as_string(arg_id)
    end
    compile_expr(arg_id)
  end

  def compile_eq(nid, op)
    recv = @nd_receiver[nid]
    lt = infer_type(recv)
    args_id = @nd_arguments[nid]
    arg_id = -1
    if args_id >= 0
      a = get_args(args_id)
      if a.length > 0
        arg_id = a[0]
      end
    end
    at = "int"
    if arg_id >= 0
      at = infer_type(arg_id)
    end
 # `<int?> == nil` / `<int?> != nil` compare against the int?
 # sentinel, not against integer 0. Without this arm the
 # fall-through emit lowers NilNode -> "0" and the comparison
 # silently matches when the int? holds a real 0 — the canonical
 # false-positive on `s.index(needle) == nil` when needle is at
 # position 0.
    if is_scalar_nullable_type(lt) == 1 && at == "nil"
      lc_opt = compile_expr(recv)
      if op == "=="
        return "sp_int_is_nil(" + lc_opt + ")"
      end
      return "(!sp_int_is_nil(" + lc_opt + "))"
    end
 # Container-op `== nil` / `!= nil` shapes that the typed
 # returns can't represent at the value level (sp_IntArray_get
 # returns 0 on out-of-range, not nil). Recognize the call
 # shape on the lhs and emit a length / has_key check
 # equivalent to CRuby's nil-on-miss semantics. Issue #562.
    if at == "nil" && recv >= 0 && @nd_type[recv] == "CallNode"
      r2 = compile_container_op_nil_check(recv, op)
      if r2 != ""
        return r2
      end
    end
 # sp_Class equality via field compare.
 # Class is a value-type struct so plain `==` on a struct
 # isn't valid C; route through the sp_class_eq runtime helper.
 # Same shape for both sides being "class" (the canonical
 # `Foo == Bar` / `c == Foo`) -- mixed class-vs-non-class falls
 # through to the existing cross-type fold below.
    if lt == "class" && at == "class"
      lc_cls = compile_expr(recv)
      rc_cls = arg_id >= 0 ? compile_expr(arg_id) : "((sp_Class){-1LL})"
      @needs_class_table = 1
      if op == "=="
        return "sp_class_eq(" + lc_cls + ", " + rc_cls + ")"
      end
      return "(!sp_class_eq(" + lc_cls + ", " + rc_cls + "))"
    end
 # Encoding is a value-type struct, so plain C `==` is invalid.
 # Encoding only compares equal to another Encoding value.
    if lt == "encoding" && at == "encoding"
      lc_enc = compile_expr(recv)
      rc_enc = arg_id >= 0 ? compile_expr(arg_id) : "sp_encoding_utf8()"
      if op == "=="
        return "sp_encoding_eq(" + lc_enc + ", " + rc_enc + ")"
      end
      return "(!sp_encoding_eq(" + lc_enc + ", " + rc_enc + "))"
    elsif (lt == "encoding" || at == "encoding") && lt != "poly" && at != "poly"
      return op == "==" ? "FALSE" : "TRUE"
    end
 # Time == Time / != — equal instant (tv_sec and tv_nsec). Plain
 # `==` on the struct isn't valid C. Same-instant times compare
 # equal regardless of the is_utc presentation flag.
    if lt == "time" && at == "time"
      le_t = compile_expr(recv)
      re_t = arg_id >= 0 ? compile_expr(arg_id) : "((sp_Time){0,0,0})"
      if op == "=="
        return "(" + time_cmp_expr(le_t, re_t) + " == 0)"
      end
      return "(" + time_cmp_expr(le_t, re_t) + " != 0)"
    end
 # Cross-type prim-vs-obj. Integer#== / Float#== fall back to
 # `other == self` via num_equal (numeric.c); String, Symbol,
 # Nil, True, False are type-strict with no fallback. obj-LHS
 # is handled in compile_obj_operator_expr -- this path is
 # `prim == obj` plus the obj-LHS no-`==`-no-`<=>` fall-through.
    lhs_obj = is_obj_type(lt)
    rhs_obj = is_obj_type(at)
    if lhs_obj != rhs_obj
      other_t = lhs_obj == 1 ? at : lt
 # `obj == nil` / `obj != nil` on a nullable obj
 # type can't constant-fold -- the runtime pointer is allowed
 # to be NULL (the type is obj_<C>?), and the body's behavior
 # depends on the actual value. Fall through to the pointer
 # comparison emit below. Non-nullable obj types still fold
 # because the pointer is never NULL by design (locals are
 # only typed `obj_<C>` after the type-tracker proved every
 # assigned write is non-nil).
      if other_t == "nil"
        obj_side_t = lhs_obj == 1 ? lt : at
        if is_nullable_type(obj_side_t) == 1
          obj_expr_nilcmp = lhs_obj == 1 ? compile_expr(recv) : compile_expr(arg_id)
          if op == "=="
            return "(" + obj_expr_nilcmp + " == NULL)"
          end
          return "(" + obj_expr_nilcmp + " != NULL)"
        end
      end
      if lhs_obj == 0 && (other_t == "int" || other_t == "float")
        cname = at[4, at.length - 4]
        ci = find_class_idx(cname)
        if ci >= 0
          owner = find_method_owner(ci, "==")
          if owner != ""
            owner_ci = find_class_idx(owner)
            midx = cls_find_method_direct(owner_ci, "==")
            ptypes = cls_meth_ptypes_get(owner_ci, midx)
            boxed = ptypes.length > 0 ? compile_expr_for_expected_type(recv, ptypes[0]) : compile_expr(recv)
            obj_expr = compile_expr_gc_rooted(arg_id)
            recv_arg = owner == cname ? obj_expr : "(sp_" + owner + " *)" + obj_expr
            call = "sp_" + owner + "_" + sanitize_name("==") + "(" + recv_arg + ", " + boxed + ")"
            return op == "==" ? call : "(!" + call + ")"
          end
        end
      end
 # Type-strict primitive, or Numeric vs an obj with no user `==`
 # (BasicObject#== identity -> false in MRI).
      if other_t == "int" || other_t == "float" || other_t == "bool" || other_t == "nil" ||
         other_t == "string" || other_t == "mutable_str" || other_t == "symbol" ||
         other_t == "bigint"
        return op == "==" ? "FALSE" : "TRUE"
      end
    end
    lc = compile_expr(recv)
    rc = "0"
    if arg_id >= 0
      rc = compile_expr(arg_id)
    end
    if lt == "poly" || at == "poly"
      @needs_rb_value = 1
      left = lc
      right = rc
      if lt != "poly"
        left = box_value_to_poly(lt, lc)
      end
      if at != "poly"
        right = box_value_to_poly(at, rc)
      end
      if op == "=="
        return "sp_poly_eq(" + left + ", " + right + ")"
      else
        return "(!sp_poly_eq(" + left + ", " + right + "))"
      end
    end
 # Symbol equality: distinct from all non-symbol types in Ruby.
    if lt == "symbol"
      if at == "symbol"
        if op == "=="
          return "(" + lc + " == " + rc + ")"
        else
          return "(" + lc + " != " + rc + ")"
        end
      end
 # sym vs non-sym: always unequal in Ruby
      return op == "==" ? "FALSE" : "TRUE"
    end
    if at == "symbol"
 # non-sym lhs vs sym rhs: also always unequal
      return op == "==" ? "FALSE" : "TRUE"
    end
    if lt == "string"
      if at == "nil"
        if op == "=="
          return "(" + lc + " == NULL)"
        else
          return "(" + lc + " != NULL)"
        end
      end
 # Optimize: str[i] == "c" → direct char comparison (no malloc)
      cc = try_char_cmp(nid, op)
      if cc != ""
        return cc
      end
 # NULL-safe equality via sp_str_eq. Plain strcmp(NULL, ...)
 # is UB and segfaults on real inputs (ENV[] returns NULL for
 # unset vars). The helper does a NULL check then strcmp;
 # identical answer for non-NULL operands, so existing
 # equality call sites are unaffected.
      if op == "=="
        return "sp_str_eq(" + lc + ", " + rc + ")"
      else
        return "(!sp_str_eq(" + lc + ", " + rc + "))"
      end
    end
    if at == "nil"
      if type_is_pointer(lt) == 1
        if op == "=="
          return "(" + lc + " == NULL)"
        else
          return "(" + lc + " != NULL)"
        end
      end
 # Pure value-type LHS (int, float, bool) against nil: in Ruby,
 # `0 == nil` is false (only nil equals nil). Without this arm
 # `int == nil` fell through to the raw `(lc == 0)` emit, since
 # compile_expr(NilNode) lowers to "0" and unboxed ints share the
 # same C representation. The conflation surfaced in #521 where
 # `v = h[k]; v == nil` mistook a stored 0 for a missing key.
 # Note: this does NOT fix the underlying hash-missing-key problem
 # (sp_StrIntHash_get still returns 0 for both stored 0 and miss);
 # use Hash#has_key? / Hash#fetch when distinguishing matters.
      if lt == "int" || lt == "float" || lt == "bool" || lt == "bigint"
        if op == "=="
          return "(((void)(" + lc + ")), FALSE)"
        else
          return "(((void)(" + lc + ")), TRUE)"
        end
      end
    end
    if lt == "nil"
 # Symmetric arm for `nil == int` / `nil != int` (and float/bool).
 # Same reasoning as the LHS-typed-int arm above.
      if at == "int" || at == "float" || at == "bool" || at == "bigint"
        if op == "=="
          return "(((void)(" + rc + ")), FALSE)"
        else
          return "(((void)(" + rc + ")), TRUE)"
        end
      end
    end
 # IntArray-backed equality (int_array, sym_array, and the
 # cross combination -- a `<<`-ed sym-tagged push leaves the
 # static type as int_array but the runtime values are sym
 # ids; both sides share the IntArray layout so the helper
 # is sound). Issue #555.
 #
 # Literal-vs-literal mismatch in element type
 # (`[0,0,0] == %i[a a a]`) answers FALSE -- CRuby distinguishes
 # element classes, and the raw IntArray_eq would coincidentally
 # return true when sym ids collide with the int values
 # (SPS_a == 0 makes `[:a,:a,:a]` encode identically to
 # `[0,0,0]`). Restricted to direct ArrayNode literals on both
 # sides so the `<<`-widened "int_array carrying syms at runtime"
 # shape (issue #555's test #06) keeps using IntArray_eq.
    if (lt == "int_array" || lt == "sym_array") && (at == "int_array" || at == "sym_array")
      if lt != at && both_array_literals?(nid) == 1
        return op == "==" ? "FALSE" : "TRUE"
      end
      if op == "=="
        return "sp_IntArray_eq((sp_IntArray *)(" + lc + "), (sp_IntArray *)(" + rc + "))"
      else
        return "(!sp_IntArray_eq((sp_IntArray *)(" + lc + "), (sp_IntArray *)(" + rc + ")))"
      end
    end
    if lt == "str_array" && at == "str_array"
      if op == "=="
        return "sp_StrArray_eq(" + lc + ", " + rc + ")"
      else
        return "(!sp_StrArray_eq(" + lc + ", " + rc + "))"
      end
    end
    if lt == "float_array" && at == "float_array"
      if op == "=="
        return "sp_FloatArray_eq(" + lc + ", " + rc + ")"
      else
        return "(!sp_FloatArray_eq(" + lc + ", " + rc + "))"
      end
    end
    if lt == "poly_array" && at == "poly_array"
      if op == "=="
        return "sp_PolyArray_eq(" + lc + ", " + rc + ")"
      else
        return "(!sp_PolyArray_eq(" + lc + ", " + rc + "))"
      end
    end
 # `<poly_array> == [nil, nil, ...]` shape (Array.new(N) ==
 # [nil, nil, nil] etc.). The RHS array literal would
 # otherwise lower to int_array of zeros and fall through to a
 # raw pointer compare. Build a poly_array of nils inline to
 # match the LHS shape and route through sp_PolyArray_eq. The
 # global "[nil, ...] literal -> poly_array" lift is unsafe
 # (it cascades into optcarrot's [nil] * N init pattern); the
 # contextual lift here only fires at the == call site.
 # Issue #619 puzzle 4.
    if lt == "poly_array" && arg_id >= 0 && @nd_type[arg_id] == "ArrayNode"
      rhs_elems_p4 = parse_id_list(@nd_elements[arg_id])
      all_nil_p4 = 1
      rhs_k_p4 = 0
      while rhs_k_p4 < rhs_elems_p4.length
        if @nd_type[rhs_elems_p4[rhs_k_p4]] != "NilNode"
          all_nil_p4 = 0
        end
        rhs_k_p4 = rhs_k_p4 + 1
      end
      if all_nil_p4 == 1
        @needs_rb_value = 1
        @needs_gc = 1
        rhs_pa_tmp = new_temp
        emit("  sp_PolyArray *" + rhs_pa_tmp + " = sp_PolyArray_new();")
        if rhs_elems_p4.length > 0
          emit("  { mrb_int _n_pa = " + rhs_elems_p4.length.to_s + "; for (mrb_int _i_pa = 0; _i_pa < _n_pa; _i_pa++) sp_PolyArray_push(" + rhs_pa_tmp + ", sp_box_nil()); }")
        end
        if op == "=="
          return "sp_PolyArray_eq(" + lc + ", " + rhs_pa_tmp + ")"
        else
          return "(!sp_PolyArray_eq(" + lc + ", " + rhs_pa_tmp + "))"
        end
      end
    end
 # Hash equality arms. Same shape as the typed-array arms
 # above. Issue #555. Compares by sorted key set + per-key
 # value equality (each variant's _eq helper handles its
 # value type's comparison: int via ==, string via sp_str_eq,
 # poly via sp_poly_eq).
    if is_hash_type(lt) == 1 && lt == at
      hash_eq_fn = ""
      if lt == "str_int_hash"
        hash_eq_fn = "sp_StrIntHash_eq"
      elsif lt == "str_str_hash"
        hash_eq_fn = "sp_StrStrHash_eq"
      elsif lt == "int_str_hash"
        hash_eq_fn = "sp_IntStrHash_eq"
      elsif lt == "sym_int_hash"
        hash_eq_fn = "sp_SymIntHash_eq"
        @needs_sym_int_hash = 1
      elsif lt == "sym_str_hash"
        hash_eq_fn = "sp_SymStrHash_eq"
        @needs_sym_str_hash = 1
      elsif lt == "str_poly_hash"
        hash_eq_fn = "sp_StrPolyHash_eq"
        @needs_str_poly_hash = 1
      elsif lt == "sym_poly_hash"
        hash_eq_fn = "sp_SymPolyHash_eq"
        @needs_sym_poly_hash = 1
      elsif lt == "poly_poly_hash"
        hash_eq_fn = "sp_PolyPolyHash_eq"
        @needs_poly_poly_hash = 1
      end
      if hash_eq_fn != ""
        if op == "=="
          return hash_eq_fn + "(" + lc + ", " + rc + ")"
        else
          return "(!" + hash_eq_fn + "(" + lc + ", " + rc + "))"
        end
      end
    end
    "(" + lc + " " + op + " " + rc + ")"
  end

 # Box an already-compiled value of static type `at` into an sp_RbVal.
 # Mirrors box_expr_to_poly but operates on a raw (type, value) pair so
 # callers that already have temps don't have to re-emit the expr.
 # Unbox an sp_RbVal expression `val` into the C representation
 # of `at`. Used at sites where the destructure / cls_id-aware
 # dispatch produced an sp_RbVal but the consumer slot is a
 # concrete C type (mrb_int, sp_IntArray *, const char *, ...).
 # No runtime cls_id check — caller has already narrowed via
 # static type / wrapping cls_id dispatch.
  def unbox_poly_to(at, val)
    base = is_nullable_type(at) == 1 ? base_type(at) : at
    if base == "int" || base == "bool" || base == "nil"
      return "(" + val + ").v.i"
    end
    if base == "float"
      return "(" + val + ").v.f"
    end
    if base == "string"
      return "(const char *)(" + val + ").v.p"
    end
    if base == "symbol"
      return "(sp_sym)(" + val + ").v.i"
    end
    if base == "encoding"
      return "((sp_Encoding){(" + val + ").v.s})"
    end
    if base == "int_array"
      return "(sp_IntArray *)(" + val + ").v.p"
    end
    if base == "float_array"
      return "(sp_FloatArray *)(" + val + ").v.p"
    end
    if base == "str_array"
      return "(sp_StrArray *)(" + val + ").v.p"
    end
    if base == "sym_array"
      return "(sp_IntArray *)(" + val + ").v.p"
    end
    if base == "poly_array"
      return "(sp_PolyArray *)(" + val + ").v.p"
    end
    if is_ptr_array_type(base) == 1
      return "(sp_PtrArray *)(" + val + ").v.p"
    end
    if is_obj_type(base) == 1
      cname = base[4, base.length - 4]
      return "(sp_" + cname + " *)(" + val + ").v.p"
    end
 # Fallback: cast generic pointer.
    "(void *)(" + val + ").v.p"
  end

 # Compile a `when` / `else` arm's last expression and, when the
 # case-expression's unified target type is `poly` (sp_RbVal) but
 # the arm's static type is a typed pointer / scalar, route through
 # `box_value_to_poly` so the assignment lands in the tagged-union
 # slot. Without this, a `case ... when A.new; when B.new; end`
 # whose unified result is poly emits raw `sp_A *` / `sp_B *`
 # assignments into the sp_RbVal slot and fails C compile.
 # Issue #580.
  def box_when_arm_to_target(arm_nid, target_t)
    arm_t = infer_type(arm_nid)
    val = compile_expr(arm_nid)
    if target_t == "poly" && arm_t != "" && arm_t != "poly" && arm_t != "void"
      return box_value_to_poly(arm_t, val)
    end
    val
  end

  def box_value_to_poly(at, val)
    nullable = is_nullable_type(at)
    raw_at = at
    at = base_type(at)
    if nullable == 1 && is_nullable_pointer_type(raw_at) == 1
      if at == "string"
        return "sp_box_nullable_str(" + val + ")"
      end
      if at == "int_array"
        return "sp_box_nullable_obj(" + val + ", SP_BUILTIN_INT_ARRAY)"
      end
      if at == "float_array"
        return "sp_box_nullable_obj(" + val + ", SP_BUILTIN_FLT_ARRAY)"
      end
      if at == "str_array"
        return "sp_box_nullable_obj(" + val + ", SP_BUILTIN_STR_ARRAY)"
      end
      if at == "sym_array"
        return "sp_box_nullable_obj(" + val + ", SP_BUILTIN_SYM_ARRAY)"
      end
      if is_ptr_array_type(at) == 1
        return "sp_box_nullable_obj(" + val + ", SP_BUILTIN_PTR_ARRAY)"
      end
      if at == "poly_array"
        return "sp_box_nullable_obj(" + val + ", SP_BUILTIN_POLY_ARRAY)"
      end
      if at == "proc" || at == "lambda"
        return "sp_box_nullable_obj(" + val + ", SP_BUILTIN_PROC)"
      end
      if is_obj_type(at) == 1
        cname = at[4, at.length - 4]
        ci = find_class_idx(cname)
 # Tier 4: stamp the unified cls_id so the
 # boxed value carries the same id that constructors
 # write and that sp_class_for_poly reads back.
        return "sp_box_nullable_obj(" + val + ", " + cls_id_for_user_internal(ci).to_s + ")"
      end
 # Stamp hash cls_id so Hash#dig can recover the concrete type;
 # falling through to cls_id=0 would make dig collapse to nil.
      hcid = cls_id_for_hash_type(at)
      if hcid != ""
        return "sp_box_nullable_obj((void *)(" + val + "), " + hcid + ")"
      end
      if type_is_pointer(at) == 1
        return "sp_box_nullable_obj((void *)(" + val + "), 0)"
      end
    end
    box_non_nullable_value_to_poly(at, val)
  end

  def box_non_nullable_value_to_poly(at, val)
    if at == "poly"
      return val
    end
    if at == "int"
      return "sp_box_int(" + val + ")"
    end
    if at == "bigint"
 # No dedicated SP_BUILTIN_BIGINT slot in the box helpers; unbox
 # to mrb_int and route through sp_box_int. The value fits when
 # it does (the canonical promote-mode scenario where the bigint
 # is just an int-sized integer wearing the bigint suit); larger
 # values truncate, which is the same trade-off as any other
 # bigint -> mrb_int coerce in this codegen.
      @needs_bigint = 1
      return "sp_box_int(sp_bigint_to_int((sp_Bigint *)" + val + "))"
    end
    if at == "string"
      return "sp_box_str(" + val + ")"
    end
    if at == "float"
      return "sp_box_float(" + val + ")"
    end
    if at == "bool"
      return "sp_box_bool(" + val + ")"
    end
    if at == "nil"
 # `val` may be a side-effecting call (e.g. an arm in a
 # cls_id-dispatched table where the user-defined override
 # returns nil because its body is a `puts` / similar). Drop
 # the value but keep the side effect via the comma operator;
 # otherwise the generated dispatch silently elides the call
 # for any subclass whose method's static return type is nil.
      return "((void)(" + val + "), sp_box_nil())"
    end
    if at == "symbol"
      return "sp_box_sym(" + val + ")"
    end
    if at == "encoding"
      return "sp_box_encoding(" + val + ")"
    end
    if at == "int_array"
      return "sp_box_int_array(" + val + ")"
    end
    if at == "float_array"
      return "sp_box_float_array(" + val + ")"
    end
    if at == "str_array"
      return "sp_box_str_array(" + val + ")"
    end
    if at == "sym_array"
      return "sp_box_sym_array(" + val + ")"
    end
    if is_ptr_array_type(at) == 1
      return "sp_box_ptr_array(" + val + ")"
    end
    if at == "poly_array"
      return "sp_box_poly_array(" + val + ")"
    end
    if at == "proc" || at == "lambda"
      return "sp_box_proc(" + val + ")"
    end
    if at == "range"
 # sp_Range is a 16-byte value type; sp_RbVal's union is 8.
 # sp_box_range copies the stack range onto the GC heap and
 # boxes the pointer via SP_BUILTIN_RANGE.
      return "sp_box_range(" + val + ")"
    end
    if at == "time"
 # Same shape as range: sp_Time is wider than sp_RbVal's union,
 # heap-copy via sp_box_time and box through SP_BUILTIN_TIME.
      return "sp_box_time(" + val + ")"
    end
    if is_obj_type(at) == 1
      cname = at[4, at.length - 4]
      ci = find_class_idx(cname)
      return "sp_box_obj(" + val + ", " + cls_id_for_user_internal(ci).to_s + ")"
    end
    hcid = cls_id_for_hash_type(at)
    if hcid != ""
      return "sp_box_obj((void *)(" + val + "), " + hcid + ")"
    end
 # A `sp_String *` (mutable_str) is a heap buffer with a `data`
 # field of const char *. Box it as a string (SP_TAG_STR) so
 # consumers that dispatch on the tag (sp_poly_to_s, write_response
 # in roundhouse's Tep::Server, etc.) read the string content
 # instead of falling through to the SP_TAG_OBJ cls_id=0 case
 # which matches no arm. Issue #541. Spill the recv to a temp via
 # a statement-expression so side effects fire exactly once.
    if at == "mutable_str"
      mtmp = new_temp
      return "({ sp_String *" + mtmp + " = " + val + "; " + mtmp + " ? sp_box_str(" + mtmp + "->data) : sp_box_nil(); })"
    end
 # Other pointer types — box with a neutral cls_id of 0 rather
 # than truncating the pointer to int.
    if type_is_pointer(at) == 1
      return "sp_box_obj((void *)(" + val + "), 0)"
    end
 # FFI :ptr is a raw C pointer that type_is_pointer() reports as
 # non-pointer (user-managed, not GC-traced). Boxing it into a poly
 # slot still needs to survive as a pointer, not as an int.
    if at == "ptr"
      return "sp_box_obj((void *)(" + val + "), 0)"
    end
    "sp_box_int(" + val + ")"
  end

  def box_expr_to_poly(nid)
 # Ternary / if-as-expression whose branches may have different
 # concrete types: per-branch box unconditionally. Same-type
 # branches yield a redundant box that still produces correct
 # sp_RbVal; mixed-type branches need the per-branch box to
 # avoid C's pointer/integer ternary-type-mismatch (which would
 # otherwise land as an unsafe cast in the poly slot and
 # segfault). Gating on infer_type's "poly" answer would miss
 # mixed-type cases — unify_return_type treats int as
 # default/unresolved (`int + T → T`), so a genuinely
 # int-string ternary infers as "string" and a poly gate would
 # fall through to the same UB-prone wholesale `sp_box_str`.
    if nid >= 0 && @nd_type[nid] == "IfNode"
 # When the predicate is a statically-decidable is_a? /
 # kind_of? on an already-typed expression, emit only the
 # live arm. The dead arm may contain a recursion call whose
 # argument types don't match the function's signature (e.g.
 # `v.is_a?(Hash) ? recurse(v) : v` where v is statically a
 # string) — generating it would land as a C type error even
 # though the branch is unreachable at runtime.
      sv = static_is_a_value(@nd_predicate[nid])
      if sv == "TRUE"
        body = @nd_body[nid]
        if body >= 0
          ts = get_stmts(body)
          if ts.length > 0
            return box_expr_to_poly(ts.last)
          end
        end
        return "sp_box_nil()"
      end
      if sv == "FALSE"
        sub = @nd_subsequent[nid]
        if sub >= 0
          if @nd_type[sub] == "ElseNode"
            eb = @nd_body[sub]
            if eb >= 0
              es = get_stmts(eb)
              if es.length > 0
                return box_expr_to_poly(es.last)
              end
            end
          else
            return box_expr_to_poly(sub)
          end
        end
        return "sp_box_nil()"
      end
      cond = compile_cond_expr(@nd_predicate[nid])
      then_v = "sp_box_nil()"
      body = @nd_body[nid]
      if body >= 0
        ts = get_stmts(body)
        if ts.length > 0
          then_v = box_expr_to_poly(ts.last)
        end
      end
      else_v = "sp_box_nil()"
      sub = @nd_subsequent[nid]
      if sub >= 0
        if @nd_type[sub] == "ElseNode"
          eb = @nd_body[sub]
          if eb >= 0
            es = get_stmts(eb)
            if es.length > 0
              else_v = box_expr_to_poly(es.last)
            end
          end
        else
          else_v = box_expr_to_poly(sub)
        end
      end
      return "(" + cond + " ? " + then_v + " : " + else_v + ")"
    end
 # Pass the nullable type through; box_value_to_poly's nullable
 # wrapper picks the right `sp_box_nullable_*` variant before
 # falling back to base-type dispatch.
    at = infer_type(nid)
 # `is_a?(<C>)`-narrowed LV read where declared storage is poly:
 # `compile_expr` returns the raw sp_RbVal slot (`lv_x`), so we
 # already have a boxed value. `box_value_to_poly("obj_<C>",
 # "lv_x")` would emit `sp_box_obj(lv_x, <cls_id>)` — type-clash
 # at the void* arg. Short-circuit: declared-poly LV with an
 # obj-narrow stays as the existing slot value (already sp_RbVal,
 # the runtime tag/cls_id match the narrow).
    if nid >= 0 && @nd_type[nid] == "LocalVariableReadNode"
      lvname_bep = @nd_name[nid]
      declared_bep = find_var_declared_type(lvname_bep)
      if declared_bep == "poly" && is_obj_type(at) == 1
        return compile_expr(nid)
      end
    end
    val = compile_expr(nid)
    box_value_to_poly(at, val)
  end

  def box_val_to_poly(val, at)
    box_value_to_poly(at, val)
  end

 # Emit a chained `@a = @b = ... = expr` write as one rhs evaluation
 # plus N per-slot stores. Caller has verified that `nid` is an
 # InstanceVariableWriteNode whose expression is itself an
 # InstanceVariableWriteNode. Each slot is typed independently (some
 # widened to poly by scan_writer_calls, others kept native), so the
 # store boxes through sp_RbVal only for the poly slots.
  def compile_chained_ivar_writes(nid)
 # Collect the chain of ivar names (head -> tail) and the bottom
 # rhs node id.
    ivars = []
    cur = nid
    while @nd_type[cur] == "InstanceVariableWriteNode"
      ivars.push(@nd_name[cur])
      cur = @nd_expression[cur]
    end
    rhs_id = cur
    rhs_type = infer_type(rhs_id)
 # NilNode rhs has no side effect and `compile_expr(NilNode)` is the
 # null-pointer-constant `0`, which assigns cleanly to any slot
 # type. Routing it through a typed temp would force a `mrb_int 0`
 # variable into pointer slots, which C won't implicitly null. Emit
 # one store per slot through the unchained IVW path; each slot
 # picks its own boxing rule (poly slots box to sp_box_nil()).
    if @nd_type[rhs_id] == "NilNode"
      ki = 0
      while ki < ivars.length
        cur_iv = nid
        kj = 0
        while kj < ki
          cur_iv = @nd_expression[cur_iv]
          kj = kj + 1
        end
        saved_expr = @nd_expression[cur_iv]
        @nd_expression[cur_iv] = rhs_id
        compile_stmt(cur_iv)
        @nd_expression[cur_iv] = saved_expr
        ki = ki + 1
      end
      return
    end
 # Empty `{}` / `[]` literal RHS — `compile_expr` returns the
 # default `sp_StrIntHash_new()` / `sp_IntArray_new()`, but
 # slots may have been promoted to a typed container by their
 # subsequent writes (e.g. `@h["k"] = "v"` lifts the slot to
 # str_str_hash). If every chain participant agrees on the
 # same promoted concrete container type, emit the slot-typed
 # constructor as the temp so each store is type-correct AND
 # the Ruby semantic of one shared object is preserved across
 # the chain. Disagreeing-type chains fall through to the
 # general case below; the resulting C will still warn about
 # pointer
 # type mismatch but at least one slot will be correct.
    if is_empty_hash_literal(rhs_id) == 1 || is_empty_array_literal(rhs_id) == 1
      consensus_t = ""
      consensus_ok = 1
      pi = 0
      while pi < ivars.length
        pt = ""
        if @current_class_idx >= 0
          pt = cls_ivar_type(@current_class_idx, ivars[pi])
        end
        if pi == 0
          consensus_t = pt
        elsif pt != consensus_t
          consensus_ok = 0
        end
        pi = pi + 1
      end
      if consensus_ok == 1 && consensus_t != "" && consensus_t != "str_int_hash" && consensus_t != "int_array" && consensus_t != "poly"
        typed_ctor = ""
        if is_empty_hash_literal(rhs_id) == 1
          if consensus_t == "str_str_hash"
            @needs_str_str_hash = 1
            typed_ctor = "sp_StrStrHash_new()"
          elsif consensus_t == "int_str_hash"
            @needs_int_str_hash = 1
            typed_ctor = "sp_IntStrHash_new()"
          elsif consensus_t == "sym_int_hash"
            @needs_sym_int_hash = 1
            typed_ctor = "sp_SymIntHash_new()"
          elsif consensus_t == "sym_str_hash"
            @needs_sym_str_hash = 1
            typed_ctor = "sp_SymStrHash_new()"
          elsif consensus_t == "str_poly_hash"
            typed_ctor = "sp_StrPolyHash_new()"
          elsif consensus_t == "sym_poly_hash"
            typed_ctor = "sp_SymPolyHash_new()"
          elsif consensus_t == "poly_poly_hash"
            @needs_poly_poly_hash = 1
            @needs_rb_value = 1
            typed_ctor = "sp_PolyPolyHash_new()"
          end
        else
          typed_ctor = empty_array_new_for_type(consensus_t)
        end
        if typed_ctor != ""
          @needs_gc = 1
          typed_tmp = new_temp
          emit("  " + c_type(consensus_t) + " " + typed_tmp + " = " + typed_ctor + ";")
          typed_ivi = 0
          while typed_ivi < ivars.length
            emit("  " + self_arrow + sanitize_ivar(ivars[typed_ivi]) + " = " + typed_tmp + ";")
            typed_ivi = typed_ivi + 1
          end
          return
        end
      end
    end
 # General case: evaluate the rhs once into a typed temp, then
 # store into each slot. Side-effecting rhs (CallNode etc.) must
 # not be replicated.
    rhs_expr = compile_expr(rhs_id)
    tmp = new_temp
    emit("  " + c_type(rhs_type) + " " + tmp + " = " + rhs_expr + ";")
    ki = 0
    while ki < ivars.length
      iname_i = ivars[ki]
      ivt_i = ""
      if @current_class_idx >= 0
        ivt_i = cls_ivar_type(@current_class_idx, iname_i)
      end
      val_i = tmp
      if ivt_i == "poly" && rhs_type != "poly"
        val_i = box_value_to_poly(rhs_type, tmp)
      end
      if ivt_i == "bigint" && rhs_type == "int"
        @needs_bigint = 1
        val_i = "sp_bigint_new_int(" + tmp + ")"
      elsif ivt_i == "int" && rhs_type == "bigint"
        @needs_bigint = 1
        val_i = "sp_bigint_to_int((sp_Bigint *)" + tmp + ")"
      end
      mod_ivar = 0
      mi3 = 0
      while mi3 < @module_names.length
        mmod = @module_names[mi3]
        if mmod != ""
          if @current_method_name.start_with?(mmod + "_cls_")
            cname3 = mmod + "_" + iname_i[1, iname_i.length - 1]
            ci3 = find_const_idx(cname3)
            if ci3 >= 0
              emit("  cst_" + cname3 + " = " + val_i + ";")
              mod_ivar = 1
            end
          end
        end
        mi3 = mi3 + 1
      end
      if mod_ivar == 0
        emit("  " + self_arrow + sanitize_ivar(iname_i) + " = " + val_i + ";")
      end
      ki = ki + 1
    end
  end

 # Emit a runtime loop that pushes every element of the array `src_expr`
 # (a node id whose value is some typed array) onto the destination
 # int_array variable `dst`. Used when expanding `*args` into a rest
 # parameter that will be received as sp_IntArray *.
  def emit_splat_into_int_array(dst, src_expr)
    src_t = infer_type(src_expr)
    src_v = compile_expr(src_expr)
    @needs_int_array = 1
    @needs_gc = 1
    if src_t == "int_array" || src_t == "sym_array"
      i = new_temp
      emit("  for (mrb_int " + i + " = 0; " + i + " < sp_IntArray_length(" + src_v + "); " + i + "++) sp_IntArray_push(" + dst + ", sp_IntArray_get(" + src_v + ", " + i + "));")
      return
    end
    if src_t == "str_array"
      @needs_str_array = 1
      i = new_temp
      emit("  for (mrb_int " + i + " = 0; " + i + " < sp_StrArray_length(" + src_v + "); " + i + "++) sp_IntArray_push(" + dst + ", (mrb_int)sp_StrArray_get(" + src_v + ", " + i + "));")
      return
    end
    if src_t == "float_array"
      @needs_float_array = 1
      i = new_temp
      emit("  for (mrb_int " + i + " = 0; " + i + " < sp_FloatArray_length(" + src_v + "); " + i + "++) sp_IntArray_push(" + dst + ", (mrb_int)sp_FloatArray_get(" + src_v + ", " + i + "));")
      return
    end
    if is_ptr_array_type(src_t) == 1
      i = new_temp
      emit("  for (mrb_int " + i + " = 0; " + i + " < sp_PtrArray_length(" + src_v + "); " + i + "++) sp_IntArray_push(" + dst + ", (mrb_int)(intptr_t)sp_PtrArray_get(" + src_v + ", " + i + "));")
      return
    end
    if src_t == "poly_array"
      i = new_temp
      emit("  for (mrb_int " + i + " = 0; " + i + " < sp_PolyArray_length(" + src_v + "); " + i + "++) sp_IntArray_push(" + dst + ", sp_PolyArray_get(" + src_v + ", " + i + ").v.i);")
      return
    end
 # Fallback: treat the single value as one element.
    emit("  sp_IntArray_push(" + dst + ", (mrb_int)" + src_v + ");")
  end

 # Read an element of a typed array as an mrb_int (so it fits int param
 # slots and the int_array rest bundle uniformly).
  def array_get_as_int_expr(src_t, src_v, idx_expr)
    if src_t == "int_array" || src_t == "sym_array"
      return "sp_IntArray_get(" + src_v + ", " + idx_expr + ")"
    end
    if src_t == "str_array"
      return "(mrb_int)sp_StrArray_get(" + src_v + ", " + idx_expr + ")"
    end
    if src_t == "float_array"
      return "(mrb_int)sp_FloatArray_get(" + src_v + ", " + idx_expr + ")"
    end
    if is_ptr_array_type(src_t) == 1
      return "(mrb_int)(intptr_t)sp_PtrArray_get(" + src_v + ", " + idx_expr + ")"
    end
    if src_t == "poly_array"
 # Pull the int channel out of the tagged union. Lossy for non-int
 # tags — Spinel's *rest can only hold mrb_int today, so any non-int
 # element splatted into a rest param prints as raw bits.
      return "sp_PolyArray_get(" + src_v + ", " + idx_expr + ").v.i"
    end
    "0"
  end

 # Same as array_get_as_int_expr but returns the element in its native
 # C type (used when the param slot is typed, e.g. const char *).
  def array_get_native_expr(src_t, src_v, idx_expr)
    if src_t == "int_array" || src_t == "sym_array"
      return "sp_IntArray_get(" + src_v + ", " + idx_expr + ")"
    end
    if src_t == "str_array"
      return "sp_StrArray_get(" + src_v + ", " + idx_expr + ")"
    end
    if src_t == "float_array"
      return "sp_FloatArray_get(" + src_v + ", " + idx_expr + ")"
    end
    if is_ptr_array_type(src_t) == 1
      return "sp_PtrArray_get(" + src_v + ", " + idx_expr + ")"
    end
    "0"
  end

 # Splat-aware companion to compile_call_args_with_defaults. Handles a
 # single SplatNode in positional args. The conceptual positional list
 # is (prefix... ++ splat_array ++ suffix...); fixed params eat from the
 # left; the rest param (if any) gets the remainder.
  def compile_call_args_splat(nid, mi, pnames, ptypes, defaults, kw_names, kw_vals, kw_arg_ids, positional_ids, splat_idx, rest_param_idx)
    splat_node = positional_ids[splat_idx]
    splat_src_id = @nd_expression[splat_node]
    prefix_count = splat_idx
    suffix_count = positional_ids.length - splat_idx - 1

 # Pre-evaluate the splat source so we can index it twice (length and
 # element access) without re-evaluating side effects.
    src_t = "int_array"
    src_v = "0"
    if splat_src_id >= 0
      src_t = infer_type(splat_src_id)
      @needs_gc = 1
      src_tmp = new_temp
      emit("  " + c_type(src_t) + " " + src_tmp + " = " + compile_expr(splat_src_id) + ";")
      emit_gc_root_for_expr(src_tmp, src_t)
      src_v = src_tmp
    end
    src_len_expr = length_c_expr(src_t, src_v)
    if src_len_expr == ""
      src_len_expr = "0"
    end

 # Identify if the last emitted param is the explicit rest slot.
    method_has_rest = 0
    if rest_param_idx >= 0 && rest_param_idx == pnames.length - 1
      method_has_rest = 1
    end
    n_fixed = pnames.length
    if method_has_rest == 1
      n_fixed = pnames.length - 1
    end

    result = ""
    k = 0
    while k < pnames.length
      if k > 0
        result = result + ", "
      end

 # Keyword args take priority (matches non-splat path).
      kw_found = 0
      ki = 0
      while ki < kw_names.length
        if kw_names[ki] == pnames[k]
          kw_found = 1
          if k < ptypes.length && ptypes[k] == "poly"
 # Pick the box helper from the arg's actual source
 # type via box_expr_to_poly. A hardcoded sp_box_str
 # would mistype any non-string source (e.g. an
 # `obj_<C>` instance) as SP_TAG_STR — invalid C and a
 # value that disagrees with sp_RbVal's tag/cls_id
 # contract at runtime.
            result = result + box_expr_to_poly(kw_arg_ids[ki])
          else
            result = result + kw_vals[ki]
          end
        end
        ki = ki + 1
      end
      if kw_found == 1
        k = k + 1
        next
      end

 # Rest param: bundle leftover splat elements + suffix positionals.
      if k == pnames.length - 1 && method_has_rest == 1
        @needs_int_array = 1
        @needs_gc = 1
        rest_tmp = new_temp
        emit("  sp_IntArray *" + rest_tmp + " = sp_IntArray_new();")
 # Prefix positionals beyond n_fixed overflow into the rest before
 # any splat content (e.g. take(1, 2, *xs) where take has only a
 # *rest param: the literals 1 and 2 must lead the bundle).
        po_start = n_fixed
        if po_start < 0
          po_start = 0
        end
        if po_start < prefix_count
          poi = po_start
          while poi < prefix_count
            emit("  sp_IntArray_push(" + rest_tmp + ", (mrb_int)" + compile_expr(positional_ids[poi]) + ");")
            poi = poi + 1
          end
        end
        consumed = n_fixed - prefix_count
        if consumed < 0
          consumed = 0
        end
        i_loop = new_temp
        emit("  for (mrb_int " + i_loop + " = " + consumed.to_s + "; " + i_loop + " < " + src_len_expr + "; " + i_loop + "++) sp_IntArray_push(" + rest_tmp + ", " + array_get_as_int_expr(src_t, src_v, i_loop) + ");")
        si = 0
        while si < suffix_count
          pid = positional_ids[splat_idx + 1 + si]
          emit("  sp_IntArray_push(" + rest_tmp + ", (mrb_int)" + compile_expr(pid) + ");")
          si = si + 1
        end
        result = result + rest_tmp
        k = k + 1
        next
      end

 # Fixed param. Determine which conceptual positional it consumes.
      pt = "int"
      if k < ptypes.length
        pt = ptypes[k]
      end
      if k < prefix_count
        if pt == "poly"
          result = result + box_expr_to_poly(positional_ids[k])
        else
 # empty `{}` literal as arg gets coerced to the
 # param's expected hash variant (which may have been widened
 # by narrow_param_hash_types_from_body_writes from the
 # caller-side default `str_int_hash`). Without this, the
 # caller would emit `sp_StrIntHash_new()` and the callee's
 # signature `sp_StrStrHash *` would type-mismatch.
          coerced = empty_hash_coerce(positional_ids[k], pt)
          if coerced != ""
            result = result + coerced
          else
 # Route through compile_expr_for_expected_type so int<->
 # bigint coerce fires for promote-mode-widened params.
            result = result + compile_expr_for_expected_type(positional_ids[k], pt)
          end
        end
        k = k + 1
        next
      end
 # Index into the splat source.
      idx_in_splat = k - prefix_count
 # Unconsumed splat elements available for fixed params:
 # src_len - (positional slots after the splat that need to come
 # from the splat to feed remaining fixed params)
 # We don't know src_len statically, so we trust the caller has
 # provided enough — a runtime over-read returns 0/NULL via the
 # array's bounds clamp.
      slots_left_for_splat = n_fixed - prefix_count
      if idx_in_splat < slots_left_for_splat
        ge = array_get_native_expr(src_t, src_v, idx_in_splat.to_s)
 # Coerce when the splat source's elem type doesn't match the
 # callee's param slot — promote-mode IntArray element (mrb_int)
 # into a bigint-promoted param.
        elem_t_spl = elem_type_of_array(src_t)
        if pt == "poly"
 # The splat element itself isn't a node id, so wrap manually.
          result = result + ge
        elsif base_type(pt) == "bigint" && elem_t_spl == "int"
          @needs_bigint = 1
          result = result + "sp_bigint_new_int(" + ge + ")"
        elsif base_type(pt) == "int" && elem_t_spl == "bigint"
          @needs_bigint = 1
          result = result + "sp_bigint_to_int((sp_Bigint *)" + ge + ")"
        else
          result = result + ge
        end
        k = k + 1
        next
      end
 # Comes from a suffix positional (after the splat).
      suffix_offset = idx_in_splat - slots_left_for_splat
      pid_idx = splat_idx + 1 + suffix_offset
      if pid_idx < positional_ids.length
        if pt == "poly"
          result = result + box_expr_to_poly(positional_ids[pid_idx])
        else
          result = result + compile_expr(positional_ids[pid_idx])
        end
      else
 # Fall back to default if defined.
        if k < defaults.length
          def_id = defaults[k].to_i
          if def_id >= 0
            if k < ptypes.length
              result = result + compile_expr_for_expected_type(def_id, ptypes[k])
            else
              result = result + compile_expr(def_id)
            end
          else
            if k < ptypes.length && ptypes[k] == "poly"
              result = result + "sp_box_nil()"
            else
              result = result + "0"
            end
          end
        else
          if k < ptypes.length && ptypes[k] == "poly"
            result = result + "sp_box_nil()"
          else
            result = result + "0"
          end
        end
      end
      k = k + 1
    end
    result
  end

  def compile_call_args_with_defaults(nid, mi, omit_trailing = 0)
 # `omit_trailing` is the number of trailing param slots to leave out
 # entirely — block-forwarding call sites pass 1 so the &block slot
 # isn't default-padded with "0" (the actual proc is appended by the
 # caller after this returns).
    args_id = @nd_arguments[nid]
    arg_ids = []
    if args_id >= 0
      arg_ids = get_args(args_id)
    end
    pnames = @meth_param_names[mi].split(",", -1)
    ptypes = @meth_param_types[mi].split(",", -1)
    defaults = @meth_has_defaults[mi].split(",", -1)
    rest_param_idx = method_rest_index(mi)
    if omit_trailing > 0
      kept = "".split(",", -1)
      pk = 0
      limit = pnames.length - omit_trailing
      if limit < 0
        limit = 0
      end
      while pk < limit
        kept.push(pnames[pk])
        pk = pk + 1
      end
      pnames = kept
    end
    if rest_param_idx >= pnames.length
      rest_param_idx = -1
    end

 # Check if args contain a KeywordHashNode - extract kw pairs.
 # Track kw_arg_ids parallel to kw_vals so the poly-boxing branch
 # below () can pick the right box helper from the arg's
 # actual source type via box_expr_to_poly, rather than hardcoding
 # sp_box_str.
    kw_names = "".split(",", -1)
    kw_vals = "".split(",", -1)
    kw_arg_ids = []
    positional_ids = []
    splat_idx = -1
    splat_count_local = 0
    ak = 0
    while ak < arg_ids.length
      if @nd_type[arg_ids[ak]] == "KeywordHashNode"
        elems = parse_id_list(@nd_elements[arg_ids[ak]])
        ek = 0
        while ek < elems.length
          if @nd_type[elems[ek]] == "AssocNode"
            key_id = @nd_key[elems[ek]]
            if key_id >= 0
              kname = ""
              if @nd_type[key_id] == "SymbolNode"
                kname = @nd_content[key_id]
              end
              kw_names.push(kname)
              kw_vals.push(compile_expr(@nd_expression[elems[ek]]))
              kw_arg_ids.push(@nd_expression[elems[ek]])
            end
          end
          ek = ek + 1
        end
      else
        if @nd_type[arg_ids[ak]] == "SplatNode"
          if splat_idx < 0
            splat_idx = positional_ids.length
          end
          splat_count_local = splat_count_local + 1
        end
        positional_ids.push(arg_ids[ak])
      end
      ak = ak + 1
    end

 # When the splat slot was widened to poly_array (heterogeneous call
 # sites), bypass compile_call_args_splat — that helper hardcodes
 # int_array and would mis-pack the args. The main path's poly_array
 # branch builds a PolyArray under the right element-box helper.
 # Issue #666.
    poly_rest_target = 0
    if rest_param_idx >= 0 && rest_param_idx < ptypes.length && ptypes[rest_param_idx] == "poly_array"
      poly_rest_target = 1
    end
    if splat_count_local == 1 && poly_rest_target == 0
      return compile_call_args_splat(nid, mi, pnames, ptypes, defaults, kw_names, kw_vals, kw_arg_ids, positional_ids, splat_idx, rest_param_idx)
    end

 # Pre-compute the kwrest slot index so we can route unmatched kw
 # args into the packed `**kwargs` hash below.
    kwrest_param_idx = method_kwrest_index(mi)
    if kwrest_param_idx >= pnames.length
      kwrest_param_idx = -1
    end

    result = ""
    k = 0
    while k < pnames.length
      if k > 0
        result = result + ", "
      end
 # `**kwargs` slot: pack every kw arg whose name doesn't match an
 # explicit keyword param into a sym_poly_hash. Done before the per-
 # pname kw_names check below so the kwrest slot doesn't try to find
 # itself in kw_names.
      if k == kwrest_param_idx
        @needs_sym_poly_hash = 1
        @needs_gc = 1
        tmp_kw = new_temp
        emit("  sp_SymPolyHash *" + tmp_kw + " = sp_SymPolyHash_new();")
        ki_kw = 0
        while ki_kw < kw_names.length
 # Skip kw_names that match an explicit (non-kwrest) param of
 # the callee; those were already bound to their own slot.
          consumed = 0
          pj = 0
          while pj < pnames.length
            if pj != kwrest_param_idx && pnames[pj] == kw_names[ki_kw]
              consumed = 1
            end
            pj = pj + 1
          end
          if consumed == 0
            sym_id = compile_symbol_literal(kw_names[ki_kw])
            emit("  sp_SymPolyHash_set(" + tmp_kw + ", " + sym_id + ", " + box_expr_to_poly(kw_arg_ids[ki_kw]) + ");")
          end
          ki_kw = ki_kw + 1
        end
        result = result + tmp_kw
        k = k + 1
        next
      end
 # Check keyword args first
      kw_found = 0
      ki = 0
      while ki < kw_names.length
        if kw_names[ki] == pnames[k]
          kw_found = 1
 # Check if param is poly
          if k < ptypes.length
            if ptypes[k] == "poly"
 # Pick the box helper from the arg's actual source
 # type via box_expr_to_poly. A hardcoded sp_box_str
 # would mistype any non-string source — and a
 # kwargs call site with a poly-widened param
 # (e.g. `model:` after call-site widening folds
 # Article + Comment into poly) is exactly the path
 # that flows non-string objs through here.
              result = result + box_expr_to_poly(kw_arg_ids[ki])
            else
 # promote-mode coerce: kw value's static type vs
 # param's declared type may need int <-> bigint.
              kw_val_pft = kw_vals[ki]
              kw_arg_t_pft = ki < kw_arg_ids.length ? infer_type(kw_arg_ids[ki]) : ""
              if base_type(ptypes[k]) == "bigint" && kw_arg_t_pft == "int"
                @needs_bigint = 1
                kw_val_pft = "sp_bigint_new_int(" + kw_val_pft + ")"
              elsif base_type(ptypes[k]) == "int" && kw_arg_t_pft == "bigint"
                @needs_bigint = 1
                kw_val_pft = "sp_bigint_to_int((sp_Bigint *)" + kw_val_pft + ")"
              end
              result = result + kw_val_pft
            end
          else
            result = result + kw_vals[ki]
          end
        end
        ki = ki + 1
      end
      if kw_found == 0
        if k < ptypes.length
          if ptypes[k] == "poly_array" && k == rest_param_idx
 # Splat slot was widened to poly_array (heterogeneous call sites
 # — e.g. `f(1,2,3); f("a","b")`). Build a PolyArray and box each
 # positional arg in its declared type. Without this branch the
 # call site emits the raw scalar as the first arg and the
 # callee's `sp_PolyArray *lv_args` signature mismatches at clang.
 # Issue #666.
            @needs_poly_array = 1
            @needs_gc = 1
            tmp_pa = new_temp
            emit("  sp_PolyArray *" + tmp_pa + " = sp_PolyArray_new();")
            pi_pa = k
            while pi_pa < positional_ids.length
              if @nd_type[positional_ids[pi_pa]] == "SplatNode"
                src_pa_expr = @nd_expression[positional_ids[pi_pa]]
                if src_pa_expr >= 0
                  src_pa_t = infer_type(src_pa_expr)
                  src_pa_c = compile_expr(src_pa_expr)
                  ii_pa_splat = new_temp
                  if src_pa_t == "int_array"
                    emit("  for (mrb_int " + ii_pa_splat + " = 0; " + ii_pa_splat + " < sp_IntArray_length(" + src_pa_c + "); " + ii_pa_splat + "++) sp_PolyArray_push(" + tmp_pa + ", sp_box_int(sp_IntArray_get(" + src_pa_c + ", " + ii_pa_splat + ")));")
                  elsif src_pa_t == "str_array"
                    emit("  for (mrb_int " + ii_pa_splat + " = 0; " + ii_pa_splat + " < sp_StrArray_length(" + src_pa_c + "); " + ii_pa_splat + "++) sp_PolyArray_push(" + tmp_pa + ", sp_box_str(sp_StrArray_get(" + src_pa_c + ", " + ii_pa_splat + ")));")
                  elsif src_pa_t == "poly_array"
                    emit("  for (mrb_int " + ii_pa_splat + " = 0; " + ii_pa_splat + " < sp_PolyArray_length(" + src_pa_c + "); " + ii_pa_splat + "++) sp_PolyArray_push(" + tmp_pa + ", sp_PolyArray_get(" + src_pa_c + ", " + ii_pa_splat + "));")
                  end
                end
              else
                emit("  sp_PolyArray_push(" + tmp_pa + ", " + box_expr_to_poly(positional_ids[pi_pa]) + ");")
              end
              pi_pa = pi_pa + 1
            end
            result = result + tmp_pa
            k = k + 1
            next
          end
          if ptypes[k] == "int_array" && k == rest_param_idx
 # Rest parameter (splat). Trigger when caller passes more
 # positional args than the method has params, OR when any
 # positional arg is itself a SplatNode that we have to expand.
            has_splat_arg = 0
            si = k
            while si < positional_ids.length
              if @nd_type[positional_ids[si]] == "SplatNode"
                has_splat_arg = 1
              end
              si = si + 1
            end
 # Treat the last param as a rest target when it's the trailing
 # int_array slot. This covers three cases:
 # - extra positional args spilling in (the original heuristic)
 # - a SplatNode somewhere in the args
 # - no args supplied at all (rest-only method called bare)
            is_last_param = 0
            if k == pnames.length - 1
              is_last_param = 1
            end
            treat_as_rest = 0
            if positional_ids.length > pnames.length || has_splat_arg == 1
              treat_as_rest = 1
            end
            if is_last_param == 1 && positional_ids.length <= k
              treat_as_rest = 1
            end
 # Middle splat (def f(a, *b, c)): there are trailing fixed params
 # after the rest slot. The rest slot always gets *some* args (may be
 # empty), so fire the rest path even when total arg count equals
 # pname count. Issue #710.
            if is_last_param == 0
              treat_as_rest = 1
            end
            if treat_as_rest == 1
 # Fast path: the only positional is a splat whose source is
 # already an int_array. Pass it directly without copying.
              if has_splat_arg == 1 && positional_ids.length == k + 1 && @nd_type[positional_ids[k]] == "SplatNode"
                src_expr = @nd_expression[positional_ids[k]]
                if src_expr >= 0
                  src_t = infer_type(src_expr)
                  if src_t == "int_array" || src_t == "sym_array"
                    result = result + compile_expr(src_expr)
                    k = k + 1
                    next
                  end
                end
              end
              @needs_int_array = 1
              @needs_gc = 1
              tmp = new_temp
              emit("  sp_IntArray *" + tmp + " = sp_IntArray_new();")
 # Leave args for trailing positional params after the rest.
 # `def g(a, *b, c)` -- the splat takes the middle, c gets the
 # final arg. Issue #710.
              trailing_after_rest = pnames.length - 1 - rest_param_idx
              if trailing_after_rest < 0
                trailing_after_rest = 0
              end
              splat_end = positional_ids.length - trailing_after_rest
              pi = k
              while pi < splat_end
                if @nd_type[positional_ids[pi]] == "SplatNode"
                  src_expr2 = @nd_expression[positional_ids[pi]]
                  if src_expr2 >= 0
                    emit_splat_into_int_array(tmp, src_expr2)
                  end
                else
                  emit("  sp_IntArray_push(" + tmp + ", (mrb_int)" + compile_expr(positional_ids[pi]) + ");")
                end
                pi = pi + 1
              end
              result = result + tmp
 # Rebuild positional_ids so post-splat indices align with the
 # remaining ptypes. positional_ids[k] (the rest_param slot) is
 # left as-is (already consumed via the splat tmp above); new
 # entries at k+1.. pull from positional_ids[splat_end..].
              new_pos = []
              ni = 0
              while ni < k
                new_pos.push(positional_ids[ni])
                ni = ni + 1
              end
 # Placeholder for the rest_param slot itself; never read because
 # the outer loop's next iteration starts at k+1.
              new_pos.push(positional_ids[k])
              trailing_pi = splat_end
              while trailing_pi < positional_ids.length
                new_pos.push(positional_ids[trailing_pi])
                trailing_pi = trailing_pi + 1
              end
              positional_ids = new_pos
              k = k + 1
              next
            end
          end
        end
        if k < positional_ids.length
          if k < ptypes.length
            if ptypes[k] == "poly"
              result = result + box_expr_to_poly(positional_ids[k])
              k = k + 1
              next
            end
 # An empty `[]` literal at the call site needs to
 # construct the right typed-array container. The
 # literal's own infer_type returns int_array
 # (compile_array_literal emits sp_IntArray_new()), but
 # when the param is a concrete typed-array, emit the
 # matching constructor instead.
            if is_empty_array_literal(positional_ids[k]) == 1
              if ptypes[k] == "str_array"
                @needs_str_array = 1
                @needs_gc = 1
                result = result + "sp_StrArray_new()"
                k = k + 1
                next
              end
              if ptypes[k] == "float_array"
                @needs_float_array = 1
                @needs_gc = 1
                result = result + "sp_FloatArray_new()"
                k = k + 1
                next
              end
              if ptypes[k] == "sym_array"
                @needs_int_array = 1
                @needs_gc = 1
                result = result + "sp_IntArray_new()"
                k = k + 1
                next
              end
            end
 # empty `{}` literal -> coerce to the param's
 # widened hash variant (e.g. body promoted str_int_hash
 # to str_str_hash via narrow_param_hash_types_from_body_writes).
            coerced_h = empty_hash_coerce(positional_ids[k], ptypes[k])
            if coerced_h != ""
              result = result + coerced_h
              k = k + 1
              next
            end
 # When the param expects `sp_<C> *` but the arg's static
 # type is `int` (typically a local catching a method
 # whose return widened to mrb_int because the union
 # collapsed somewhere upstream — e.g.
 # `parent = article` after a `nil.return` narrows
 # parent's declared type but the call site below still
 # passes `lv_parent` raw), insert the same cast that
 # compile_int_class_fallback_expr already inserts at
 # property-access sites. Without this, gcc errors
 # `incompatible integer to pointer conversion`.
            if is_obj_type(ptypes[k]) == 1
              arg_at = infer_type(positional_ids[k])
              if arg_at == "int" || arg_at == "bigint" || expr_emit_is_bigint(positional_ids[k]) == 1
                bt_arg = base_type(ptypes[k])
                arg_cname = bt_arg[4, bt_arg.length - 4]
                arg_v_ito = compile_expr(positional_ids[k])
                if arg_at == "bigint" || expr_emit_is_bigint(positional_ids[k]) == 1
                  @needs_bigint = 1
                  arg_v_ito = "sp_bigint_to_int((sp_Bigint *)" + arg_v_ito + ")"
                end
                result = result + "(sp_" + arg_cname + " *)(uintptr_t)" + arg_v_ito
                k = k + 1
                next
              end
            end
 # Issue #542 / #545: param body-inferred as a hash or array
 # variant but the caller's arg is int/nil because the source
 # (uninitialized ivar, untyped registry getter, etc.) never
 # got widened. Cast the int/nil value to NULL of the param's
 # pointer type. The matching runtime NULL-guards in
 # `sp_<X>Hash_get` / `sp_PolyArray_length` etc. return the
 # slot's default sentinel so the body's `param["k"]` /
 # `param.length` produces 0 / nil instead of segfaulting --
 # closer to CRuby's NoMethodError (still wrong but at least
 # defined and unlike the silent emit-0).
            if is_hash_type(ptypes[k]) == 1 || ptypes[k] == "poly_array"
              arg_at_h542 = infer_type(positional_ids[k])
              if arg_at_h542 == "int" || arg_at_h542 == "nil"
                result = result + "(" + c_type(ptypes[k]) + ")NULL"
                k = k + 1
                next
              end
              if arg_at_h542 == "poly"
                result = result + "(" + c_type(ptypes[k]) + ")(" + compile_expr(positional_ids[k]) + ").v.p"
                k = k + 1
                next
              end
            end
          end
          if k < ptypes.length
 # Route through compile_expr_for_expected_type so a poly arg
 # passed to a typed param (after an is_a? guard, or whenever
 # the caller is more general than the callee) is unboxed via
 # the matching union field. Mirrors the #438 IntStrHash-key
 # unbox and extends it to user-method args.
            result = result + cast_away_volatile_arg(positional_ids[k], compile_expr_for_expected_type(positional_ids[k], ptypes[k]))
          else
            result = result + cast_away_volatile_arg(positional_ids[k], compile_expr(positional_ids[k]))
          end
        else
 # Use default value
          if k < defaults.length
            def_id = defaults[k].to_i
            if def_id >= 0
 # An empty `{}` default whose receiving param has been
 # body-widened to a specific hash variant (e.g.
 # `set_cookies:` to sp_SymStrHash via callers passing
 # symbol-keyed hashes) needs to construct the matching
 # empty container, not the generic sp_StrIntHash. Mirrors
 # the positional-arg empty_hash_coerce branch above.
              if k < ptypes.length
                coerced_def_h = empty_hash_coerce(def_id, ptypes[k])
                if coerced_def_h != ""
                  result = result + coerced_def_h
                  k = k + 1
                  next
                end
              end
 # Route through compile_expr_for_expected_type so a `= nil`
 # default landing in a poly slot (after the #634 widening)
 # boxes to sp_box_nil() rather than emitting the bare `0`
 # that the caller would otherwise pass as the param value.
              if k < ptypes.length
                result = result + compile_expr_for_expected_type(def_id, ptypes[k])
              else
                result = result + compile_expr(def_id)
              end
            else
 # Issue #642: a positional param with no default and no call-
 # site arg was silently filled with `0` / `sp_box_nil()`. The
 # generated binary then ran with garbage in the missing slot,
 # producing the canonical "looks-like-200-OK" failure mode the
 # tep#13 reporter hit. Warn loud so the user sees the missing
 # arg at compile time; still emit `0` so the codegen completes
 # (a hard error would tear up partially-implemented patterns).
              warn_missing_positional_arg(mi, k, pnames[k])
              if k < ptypes.length && ptypes[k] == "poly"
                result = result + "sp_box_nil()"
              elsif k < ptypes.length && base_type(ptypes[k]) == "bigint"
                @needs_bigint = 1
                result = result + "sp_bigint_new_int(0)"
              else
                result = result + "0"
              end
            end
          else
            warn_missing_positional_arg(mi, k, pnames[k])
            if k < ptypes.length && ptypes[k] == "poly"
              result = result + "sp_box_nil()"
            elsif k < ptypes.length && base_type(ptypes[k]) == "bigint"
              @needs_bigint = 1
              result = result + "sp_bigint_new_int(0)"
            else
              result = result + "0"
            end
          end
        end
      end
      k = k + 1
    end
    result
  end

 # Emit a one-shot warning per (callee, missing-param) the first
 # time a call site omits that slot with no default available.
 # Dedupe so a missing arg threaded through 50 call sites surfaces
 # once. Lives alongside warn_unresolved_call's dedupe stash.
  def warn_missing_positional_arg(mi, slot_idx, pname)
    if mi < 0 || mi >= @meth_names.length
      return
    end
    callee_name = @meth_names[mi]
    key = "_miss_arg_:" + callee_name + ":" + slot_idx.to_s + ":" + pname
    i = 0
    while i < @unresolved_call_warnings.length
      if @unresolved_call_warnings[i] == key
        return
      end
      i = i + 1
    end
    @unresolved_call_warnings.push(key)
    $stderr.puts "warning: call to '" + callee_name + "' is missing required arg #" + (slot_idx + 1).to_s + " (" + pname + "); emitting 0 (this is wrong — define a default or pass the arg)"
  end

  def compile_constructor_args(ci, nid)
    args_id = @nd_arguments[nid]
    if args_id < 0
 # No call-site args. If init has parameters with defaults, fill them
 # in here `Counter.new` for `initialize(start = 0)`).
      init_ci = find_init_class(ci)
      if init_ci >= 0
        init_idx = cls_find_method_direct(init_ci, "initialize")
        if init_idx >= 0
          return compile_typed_call_args(nid, init_ci, init_idx, 0, 1)
        end
      end
      return ""
    end
    arg_ids = get_args(args_id)
 # Check if any arg is a KeywordHashNode
    has_kw = 0
    ak = 0
    while ak < arg_ids.length
      if @nd_type[arg_ids[ak]] == "KeywordHashNode"
        has_kw = 1
      end
      ak = ak + 1
    end
    if has_kw == 0
 # Positional args: compile against the inferred initializer
 # signature so defaults are filled and poly params are boxed.
      init_ci_p = find_init_class(ci)
      if init_ci_p >= 0
        init_idx_p = cls_find_method_direct(init_ci_p, "initialize")
        if init_idx_p >= 0
          return compile_typed_call_args(nid, init_ci_p, init_idx_p, 0, 1)
        end
      end
      return compile_call_args(nid)
    end
 # Extract keyword pairs — remember the expression nid too so we can
 # box it (sp_box_int etc.) when the matching ctor param is poly.
    kw_names = "".split(",", -1)
    kw_exprs = []
    ak = 0
    while ak < arg_ids.length
      if @nd_type[arg_ids[ak]] == "KeywordHashNode"
        elems = parse_id_list(@nd_elements[arg_ids[ak]])
        ek = 0
        while ek < elems.length
          if @nd_type[elems[ek]] == "AssocNode"
            key_id = @nd_key[elems[ek]]
            if key_id >= 0
              kname = ""
              if @nd_type[key_id] == "SymbolNode"
                kname = @nd_content[key_id]
              end
              kw_names.push(kname)
              kw_exprs.push(@nd_expression[elems[ek]])
            end
          end
          ek = ek + 1
        end
      end
      ak = ak + 1
    end
 # Get init param names/types from class
    init_ci = find_init_class(ci)
    if init_ci < 0
      return compile_call_args(nid)
    end
    init_idx = cls_find_method_direct(init_ci, "initialize")
    if init_idx < 0
      return compile_call_args(nid)
    end
    pnames = cls_meth_pnames_get(init_ci, init_idx)
    ptypes = cls_meth_ptypes_get(init_ci, init_idx)
 # Kwarg-as-bundle: if the init has exactly one positional param,
 # the kwargs don't match its name, and the param's inferred type
 # is `str_poly_hash` (set by the matching analyze-side widening
 # for the same shape), build a sp_StrPolyHash from the kwargs and
 # pass it as the single arg. Sam Ruby's #530 segv: roundhouse's
 # `Article.new(title: "", body: "...")` lowered to
 # `sp_Article_new(0)` because no kwarg name matched the
 # `attrs` positional, then `attrs["title"]` dereferenced NULL.
    if pnames.length == 1 && pk_kwarg_name_matches?(kw_names, pnames) == 0 && ptypes.length >= 1 && ptypes[0] == "str_poly_hash"
      @needs_rb_value = 1
      hash_tmp_530 = new_temp
      emit("  sp_StrPolyHash *" + hash_tmp_530 + " = sp_StrPolyHash_new();")
      ki_530 = 0
      while ki_530 < kw_names.length
        key_c = "(&(\"\\xff\" \"" + kw_names[ki_530] + "\")[1])"
        emit("  sp_StrPolyHash_set(" + hash_tmp_530 + ", " + key_c + ", " + box_expr_to_poly(kw_exprs[ki_530]) + ");")
        ki_530 = ki_530 + 1
      end
      return hash_tmp_530
    end
 # Build args in param order using keyword values
    result = ""
    pk = 0
    while pk < pnames.length
      if pk > 0
        result = result + ", "
      end
      pt = "int"
      if pk < ptypes.length
        pt = ptypes[pk]
      end
      found = 0
      ki = 0
      while ki < kw_names.length
        if kw_names[ki] == pnames[pk]
          expr_id = kw_exprs[ki]
          if pt == "poly"
            result = result + box_expr_to_poly(expr_id)
          else
 # Route through compile_expr_for_expected_type so a kwarg
 # whose expression returns sp_RbVal (poly dispatch from a
 # `<poly_recv>.<method>` chain) gets unboxed to the ctor
 # param's expected concrete type. Without this, the raw
 # sp_RbVal flows into a `const char *` slot and clang
 # errors at the call site (#685, ActionResponse.new(body:
 # controller.body) where controller is poly-typed).
            result = result + compile_expr_for_expected_type(expr_id, pt)
          end
          found = 1
        end
        ki = ki + 1
      end
      if found == 0
        if pt == "poly"
          result = result + "sp_box_nil()"
        else
          result = result + "0"
        end
      end
      pk = pk + 1
    end
    result
  end

 # Returns 1 if any kw_name matches any pname, 0 otherwise. Helper
 # for compile_constructor_args's kwarg-as-bundle detection. Issue
 # #530.
  def pk_kwarg_name_matches?(kw_names, pnames)
    ki = 0
    while ki < kw_names.length
      pi = 0
      while pi < pnames.length
        if kw_names[ki] == pnames[pi]
          return 1
        end
        pi = pi + 1
      end
      ki = ki + 1
    end
    0
  end

 # Like compile_call_args but coerces each arg's type to match the
 # callee class-method's declared param type. Used by the bare cls
 # method call path (`_adapter_exists_by_id_p(id)` inside `def self.X`)
 # which previously emitted raw compile_expr and tripped clang on
 # poly<->concrete mismatches (#685, Article#exists? -> Article#
 # _adapter_exists_by_id_p with sp_RbVal arg into mrb_int param).
  def compile_call_args_coerced_for_cmeth(nid, ci, cmidx)
    args_id = @nd_arguments[nid]
    if args_id < 0
      return ""
    end
    arg_ids = get_args(args_id)
    if arg_ids.length == 0
      return ""
    end
    ptypes = cls_cmeth_ptypes_get(ci, cmidx)
    result = ""
    k = 0
    while k < arg_ids.length
      if k > 0
        result = result + ", "
      end
      pt_arg = k < ptypes.length ? ptypes[k] : ""
      at_arg = infer_type(arg_ids[k])
      pt_base_arg = base_type(pt_arg)
      needs_arg = 0
      if pt_arg != ""
        if pt_base_arg == "bigint" || pt_base_arg == "int"
          needs_arg = 1
        elsif at_arg == "poly" && pt_base_arg != "poly" && pt_base_arg != ""
          needs_arg = 1
        elsif at_arg != "poly" && pt_base_arg == "poly"
          needs_arg = 1
        elsif pt_base_arg == "string" || pt_base_arg == "mutable_str"
          needs_arg = 1
        elsif is_hash_type(pt_base_arg) == 1 || is_array_type(pt_base_arg) == 1
          needs_arg = 1
        end
      end
      if needs_arg == 1
        result = result + compile_expr_for_expected_type(arg_ids[k], pt_arg)
      else
        result = result + cast_away_volatile_arg(arg_ids[k], compile_expr(arg_ids[k]))
      end
      k = k + 1
    end
    result
  end

  def compile_call_args(nid)
    args_id = @nd_arguments[nid]
    if args_id < 0
      return ""
    end
    arg_ids = get_args(args_id)
 # Check if multiple args may trigger GC
    gc_count = 0
    k = 0
    while k < arg_ids.length
      if expr_may_gc(arg_ids[k]) == 1
        gc_count = gc_count + 1
      end
      k = k + 1
    end
    if gc_count >= 2
      return compile_gc_safe_args(arg_ids)
    end
    result = ""
    k = 0
    while k < arg_ids.length
      if k > 0
        result = result + ", "
      end
      result = result + cast_away_volatile_arg(arg_ids[k], compile_expr(arg_ids[k]))
      k = k + 1
    end
    result
  end

 # When the enclosing function uses setjmp (top-level begin/rescue),
 # every pointer LV in main() is declared `volatile T *`. Passing
 # such a local to a function that takes plain `T *` discards the
 # volatile qualifier — gcc -Wdiscarded-qualifiers and clang's
 # -Wincompatible-pointer-types-discards-qualifiers flag it. Casting
 # away volatile is safe because the qualifier is strictly stronger
 # than what the callee asks for. Mirrors the bigint-side cast at
 # the operator dispatch (search for `(sp_Bigint *)`).
  def cast_away_volatile_arg(arg_id, val)
    if @needs_setjmp != 1
      return val
    end
    if arg_id < 0
      return val
    end
    if @nd_type[arg_id] != "LocalVariableReadNode"
      return val
    end
    vt = find_var_declared_type(@nd_name[arg_id])
    if vt == "" || type_is_pointer(vt) != 1
      return val
    end
 # Skip the cast when `val` isn't a bare `lv_<name>` read --
 # compile_expr_for_expected_type may have wrapped the LV in a
 # conversion call (e.g. `sp_StrPolyHash_from_sym_poly_hash(lv_form_attrs)`),
 # producing a value whose actual type differs from the LV's
 # declared type. Casting that to `(c_type(vt))` would emit the
 # wrong cast (LV's old type) on a value of the new type --
 # the #700 shape "(sp_SymPolyHash *)sp_StrPolyHash_from_sym_poly_hash(...)"
 # symptom. The wrapping itself isn't volatile-sensitive (the
 # conversion fn reads h->order[i] which is safe under longjmp),
 # so dropping the cast here is correct.
    if val != ("lv_" + @nd_name[arg_id])
      return val
    end
    "(" + c_type(vt) + ")" + val
  end

  def compile_proc_call_args(nid)
    args_id = @nd_arguments[nid]
    if args_id < 0
      return "0"
    end
    arg_ids = get_args(args_id)
    if arg_ids.length == 0
      return "0"
    end
    result = ""
    k = 0
    while k < arg_ids.length
      if k > 0
        result = result + ", "
      end
      val = compile_expr(arg_ids[k])
      at = infer_type(arg_ids[k])
      if base_type(at) == "bigint"
 # Proc ABI is `mrb_int(*)(void*, mrb_int*)`. In promote mode an
 # int arg arrives as sp_Bigint *; unbox to the underlying int
 # before packing. Wrapping the pointer via (mrb_int)(uintptr_t)
 # would silently pass a heap address as the proc's `n`.
        @needs_bigint = 1
        result = result + "sp_bigint_to_int((sp_Bigint *)" + val + ")"
      elsif type_is_pointer(at) == 1
        result = result + "(mrb_int)(uintptr_t)(" + val + ")"
      else
        result = result + val
      end
      k = k + 1
    end
    result
  end

  def compile_gc_safe_args(arg_ids)
    temps = "".split(",", -1)
    k = 0
    while k < arg_ids.length
      if expr_may_gc(arg_ids[k]) == 1
        tmp = new_temp
        at = infer_type(arg_ids[k])
        ct = c_type(at)
        emit("  " + ct + " " + tmp + " = " + cast_away_volatile_arg(arg_ids[k], compile_expr(arg_ids[k])) + ";")
        emit_gc_root_for_expr(tmp, at)
        temps.push(tmp)
      else
        temps.push(cast_away_volatile_arg(arg_ids[k], compile_expr(arg_ids[k])))
      end
      k = k + 1
    end
    result = ""
    k = 0
    while k < temps.length
      if k > 0
        result = result + ", "
      end
      result = result + temps[k]
      k = k + 1
    end
    result
  end

  def constructor_arg_needs_root(arg_type)
    bt = base_type(arg_type)
    if type_needs_gc_root(bt) == 1
      return 1
    end
    0
  end

  def root_constructor_arg_if_needed(expr_id, expr, arg_type, later_arg_may_gc)
    if constructor_arg_needs_root(arg_type) == 0
      return expr
    end
    may_gc = 0
    if expr_id >= 0
      may_gc = expr_may_gc(expr_id)
    end
 # Detect a wrapped sp_bigint_new_int(...) emit. The wrap itself
 # allocates an sp_Bigint via sp_bigint_alloc, which may trigger
 # GC -- but expr_may_gc walks the AST and sees only the IntegerNode
 # literal at the source level, so we have to look at the C expr.
 # Same shape for any "sp_bigint_*(" prefix that returns a freshly
 # allocated sp_Bigint*.
    if may_gc == 0 && (expr.start_with?("sp_bigint_new_int(") || expr.start_with?("sp_bigint_add(") || expr.start_with?("sp_bigint_sub(") || expr.start_with?("sp_bigint_mul("))
      may_gc = 1
    end
    if may_gc == 0 && later_arg_may_gc == 0
      return expr
    end
    @needs_gc = 1
    tmp = new_temp
    emit("  " + c_type(arg_type) + " " + tmp + " = " + expr + ";")
    emit_gc_root_for_expr(tmp, arg_type)
    tmp
  end

 # compile_typed_call_args for callers that hold the owner / method
 # names rather than pre-resolved indices. Untyped fallback on miss.
  def compile_typed_call_args_by_name(nid, owner, mname, omit_trailing = 0)
    owner_ci = find_class_idx(owner)
    return compile_call_args(nid) if owner_ci < 0
    midx = cls_find_method_direct(owner_ci, mname)
    return compile_call_args(nid) if midx < 0
    compile_typed_call_args(nid, owner_ci, midx, omit_trailing)
  end

  def compile_typed_call_args(nid, target_ci, target_midx, omit_trailing, root_constructor_args = 0)
 # Like compile_call_args but casts arguments to match target method param
 # types AND fills in defaults from @cls_meth_defaults for trailing
 # parameters the caller omitted . Returns "" only when the
 # method takes no parameters at all.
 #
 # `omit_trailing` is the number of trailing param slots to leave out
 # entirely — block-forwarding call sites pass 1 so the &block slot
 # isn't default-padded with "0" (the actual proc is appended by the
 # caller after this returns).
    args_id = @nd_arguments[nid]
    raw_arg_ids = []
    if args_id >= 0
      raw_arg_ids = get_args(args_id)
    end
    all_defaults = @cls_meth_defaults[target_ci].split("|", -1)
    ptypes = cls_meth_ptypes_get(target_ci, target_midx)
    pnames_t = cls_meth_pnames_get(target_ci, target_midx)
    defaults = "".split(",", -1)
    if target_midx < all_defaults.length
      defaults = all_defaults[target_midx].split(",", -1)
    end
 # Pull out kwargs (KeywordHashNode) from the positional stream
 # so the loop below can map `key: value` to the matching named
 # param. Without this, a trailing `head(204, content_type: "x")`
 # call-site widening would land the whole keyword hash on the
 # next positional slot (ptype[1]) and emit garbage for the
 # actual content_type kwarg slot.
    arg_ids = []
    kw_name_to_arg = "".split(",", -1)
    kw_name_keys  = "".split(",", -1)
    kak = 0
    while kak < raw_arg_ids.length
      if @nd_type[raw_arg_ids[kak]] == "KeywordHashNode"
        kelems = parse_id_list(@nd_elements[raw_arg_ids[kak]])
        kei = 0
        while kei < kelems.length
          if @nd_type[kelems[kei]] == "AssocNode"
            kkey = @nd_key[kelems[kei]]
            kval = @nd_expression[kelems[kei]]
            if kkey >= 0 && kval >= 0 && @nd_type[kkey] == "SymbolNode"
              knm = @nd_content[kkey]
              if knm == ""
                knm = @nd_name[kkey]
              end
              kw_name_keys.push(knm)
              kw_name_to_arg.push(kval.to_s)
            end
          end
          kei = kei + 1
        end
      else
        arg_ids.push(raw_arg_ids[kak])
      end
      kak = kak + 1
    end
 # Drop the trailing slots the caller will fill explicitly (the
 # &block slot when block-forwarding) — otherwise a surplus
 # positional arg would mis-cast against the omitted slot's type
 # and the loop's default-padding would emit "0" for the slot the
 # caller is about to fill itself.
    if omit_trailing > 0
      kept = []
      pk = 0
      limit = ptypes.length - omit_trailing
      if limit < 0
        limit = 0
      end
      while pk < limit
        kept.push(ptypes[pk])
        pk = pk + 1
      end
      ptypes = kept
    end
 # Resolve each named param against the kwarg map by injecting
 # the matched kwarg's value-id into arg_ids[slot] so the loop's
 # positional path picks it up. Same effect as
 # compile_call_args_with_defaults's kwarg routing.
    kw_matched = []
    kmi = 0
    while kmi < kw_name_keys.length
      kw_matched.push(0)
      kmi = kmi + 1
    end
    if kw_name_keys.length > 0
      pkk = 0
      while pkk < pnames_t.length
        kwi = 0
        while kwi < kw_name_keys.length
          if kw_name_keys[kwi] == pnames_t[pkk]
            while arg_ids.length <= pkk
              arg_ids.push(-1)
            end
            arg_ids[pkk] = kw_name_to_arg[kwi].to_i
            kw_matched[kwi] = 1
          end
          kwi = kwi + 1
        end
        pkk = pkk + 1
      end
    end
 # Bundle-as-positional: any kwarg that didn't match a param name
 # gets packed into the next available hash-typed positional slot.
 # The analyzer widens that slot to `str_poly_hash` via
 # widen_ptypes_from_args's fallback , so we synthesize a
 # sp_StrPolyHash literal here to match. Without this, the call
 # `Comment.create(article_id: 1, body: "...")` against
 # `def self.create(attrs = {})` dropped every kwarg and emitted
 # `sp_Comment_cls_create(sp_StrIntHash_new())` (empty), so the
 # constructor saw an empty attrs hash and built a Comment with
 # all defaults.
    if kw_name_keys.length > 0
      unmatched_kw_idxs = []
      uki = 0
      while uki < kw_name_keys.length
        if kw_matched[uki] == 0
          unmatched_kw_idxs.push(uki)
        end
        uki = uki + 1
      end
      if unmatched_kw_idxs.length > 0
        target_slot = -1
        psl = 0
        while psl < ptypes.length
          pt_sl = base_type(ptypes[psl])
          slot_filled = 0
          if psl < arg_ids.length && arg_ids[psl] >= 0
            slot_filled = 1
          end
          if slot_filled == 0 && is_hash_type(pt_sl) == 1 && target_slot < 0
            target_slot = psl
          end
          psl = psl + 1
        end
        if target_slot >= 0
          bundle_tmp = new_temp
          @needs_rb_value = 1
          emit("  sp_StrPolyHash *" + bundle_tmp + " = sp_StrPolyHash_new();")
          ubi = 0
          while ubi < unmatched_kw_idxs.length
            uk = unmatched_kw_idxs[ubi]
            key_c_b = "(&(\"\\xff\" \"" + kw_name_keys[uk] + "\")[1])"
            val_id_b = kw_name_to_arg[uk].to_i
            emit("  sp_StrPolyHash_set(" + bundle_tmp + ", " + key_c_b + ", " + box_expr_to_poly(val_id_b) + ");")
            ubi = ubi + 1
          end
          while arg_ids.length <= target_slot
            arg_ids.push(-1)
          end
 # Mark the slot with a synthetic id pointing at the bundle local.
 # The loop below special-cases this via a string compare on the
 # generated C expression, but simpler: drop the bundle string
 # straight into result via a side-channel map keyed by slot.
          @typed_call_bundle_slot = target_slot
          @typed_call_bundle_expr = bundle_tmp
        else
          @typed_call_bundle_slot = -1
          @typed_call_bundle_expr = ""
        end
      else
        @typed_call_bundle_slot = -1
        @typed_call_bundle_expr = ""
      end
    else
      @typed_call_bundle_slot = -1
      @typed_call_bundle_expr = ""
    end
    total = ptypes.length
    if arg_ids.length > total
      total = arg_ids.length
    end
    if total == 0
      return ""
    end
    later_arg_may_gc = []
    if root_constructor_args == 1
      gc_expr_ids = []
      gk = 0
      while gk < total
        gc_expr_id = -1
        if gk < arg_ids.length
          gc_expr_id = arg_ids[gk]
        else
          if gk < defaults.length
            gc_expr_id = defaults[gk].to_i
          end
        end
        gc_expr_ids.push(gc_expr_id)
        gk = gk + 1
      end
      seen_gc = 0
      gk = total - 1
      while gk >= 0
        later_arg_may_gc[gk] = seen_gc
        gc_expr_id = gc_expr_ids[gk]
        if gc_expr_id >= 0 && expr_may_gc(gc_expr_id) == 1
          seen_gc = 1
        end
        gk = gk - 1
      end
    end
 # Snapshot the bundle slot/local before the per-slot loop —
 # nested compile_expr calls (e.g. a kwarg value that's itself a
 # method call) will recursively re-enter compile_typed_call_args
 # and rewrite the ivars. Copying them into locals here keeps the
 # outer call's bundle reachable from the slot-fill arm.
    bundle_slot_l = @typed_call_bundle_slot
    bundle_expr_l = @typed_call_bundle_expr
    result = ""
    pcname = ""
    k = 0
    while k < total
      if k > 0
        result = result + ", "
      end
 # Bundle slot: emit the pre-built sp_StrPolyHash local
 # synthesized from the unmatched kwargs above.
      if bundle_slot_l == k && bundle_expr_l != ""
        result = result + bundle_expr_l
        k = k + 1
        next
      end
      if k < arg_ids.length && arg_ids[k] >= 0
        at = infer_type(arg_ids[k])
        if k < ptypes.length
          pt = ptypes[k]
          pt_base = base_type(pt)
          if pt_base == "poly" || pt_base == "string" || is_array_type(pt_base) == 1 || (at == "poly" && is_obj_type(pt_base) == 1) || (at == "poly" && is_hash_type(pt_base) == 1) || (pt_base == "bigint" && at != "bigint") || (at == "bigint" && pt_base != "bigint")
            aexpr = compile_expr_for_expected_type(arg_ids[k], pt)
            if root_constructor_args == 1
              aexpr = root_constructor_arg_if_needed(arg_ids[k], aexpr, pt, later_arg_may_gc[k])
            end
            result = result + aexpr
            k = k + 1
            next
          end
          aexpr = compile_expr(arg_ids[k])
          if at == "int" || at == "bigint" || expr_emit_is_bigint(arg_ids[k]) == 1
            if is_obj_type(pt) == 1
 # Cast int / bigint to object pointer. Strip the nullable
 # `?` marker before deriving the C class name. For bigint,
 # unbox first via sp_bigint_to_int (the int value is then
 # cast to pointer; NULL/0 stays NULL).
              pt_base = pt
              if is_nullable_type(pt) == 1
                pt_base = base_type(pt)
              end
              pcname = pt_base[4, pt_base.length - 4]
              if at == "bigint" || expr_emit_is_bigint(arg_ids[k]) == 1
                @needs_bigint = 1
                aexpr = "(sp_" + pcname + " *)(uintptr_t)sp_bigint_to_int((sp_Bigint *)" + aexpr + ")"
              else
                aexpr = "(sp_" + pcname + " *)(uintptr_t)" + aexpr
              end
            end
          end
          if is_obj_type(at) == 1
            if pt == "int"
 # Cast object pointer to int
              aexpr = "(mrb_int)" + aexpr
            end
          end
        else
          aexpr = compile_expr(arg_ids[k])
          pt = at
        end
        if root_constructor_args == 1
          aexpr = root_constructor_arg_if_needed(arg_ids[k], aexpr, pt, later_arg_may_gc[k])
        end
        result = result + aexpr
      else
 # Caller omitted this trailing arg — emit the method's
 # default expression. The default was authored in the
 # callee's class scope, so any `self` / `@ivar` references
 # need to resolve against the call's receiver, not the
 # caller's self. Switch @current_class_idx and override
 # `self_arrow` for the duration of the inline expansion.
        if k < defaults.length
          def_id = defaults[k].to_i
          if def_id >= 0
            recv_for_default = @nd_receiver[nid]
            saved_ci = @current_class_idx
            saved_override = @self_override
            if recv_for_default >= 0
 # Materialize the recv into a C expression. Wrap in
 # parens so any cast/operator chain stays self-
 # contained when consumed as `(<recv>)->iv_X` (via
 # `self_arrow`) or as the first arg of a same-class
 # method call (via `self_expr`).
              recv_c = compile_expr_gc_rooted(recv_for_default)
 # Cast the recv expression to the target class's
 # pointer type when the static type of the recv is not
 # already that pointer (e.g. an inherited @apu ivar
 # whose slot was inferred as mrb_int but the runtime
 # value is sp_Optcarrot_APU *). Without the cast, an
 # `@cpu` reference inside the default expression
 # lowers to `(<recv>)->iv_cpu` which gcc rejects when
 # `<recv>` is mrb_int.
              recv_t = infer_type(recv_for_default)
              target_obj_t = "obj_" + @cls_names[target_ci]
              if base_type(recv_t) != target_obj_t && @cls_is_value_type[target_ci] != 1
                recv_c = "(sp_" + @cls_names[target_ci] + " *)" + recv_c
              end
              @self_override = "(" + recv_c + ")"
              @current_class_idx = target_ci
            end
            if k < ptypes.length
              aexpr = compile_expr_for_expected_type(def_id, ptypes[k])
              if root_constructor_args == 1
                aexpr = root_constructor_arg_if_needed(def_id, aexpr, ptypes[k], later_arg_may_gc[k])
              end
              result = result + aexpr
            else
              aexpr = compile_expr(def_id)
              if root_constructor_args == 1
                aexpr = root_constructor_arg_if_needed(def_id, aexpr, infer_type(def_id), later_arg_may_gc[k])
              end
              result = result + aexpr
            end
            @current_class_idx = saved_ci
            @self_override = saved_override
          else
            if k < ptypes.length && ptypes[k] == "poly"
              result = result + "sp_box_nil()"
            else
              result = result + "0"
            end
          end
        else
          if k < ptypes.length && ptypes[k] == "poly"
            result = result + "sp_box_nil()"
          else
            result = result + "0"
          end
        end
      end
      k = k + 1
    end
    result
  end

  def find_method_owner(ci, mname)
    if ci < 0
      return ""
    end
    mnames = @cls_meth_names[ci].split(";", -1)
    j = 0
    while j < mnames.length
      if mnames[j] == mname
        return @cls_names[ci]
      end
      j = j + 1
    end
    if @cls_parents[ci] != ""
      pi = find_class_idx(@cls_parents[ci])
      if pi >= 0
        return find_method_owner(pi, mname)
      end
    end
    ""
  end

 # --- prepend chain helpers (mirror of spinel_analyze.rb) ----------
 # The chain is materialized into @cls_meth_prep_chain by analyze.
 # See spinel_analyze.rb prep_snapshot_active for the storage shape.

 # List of synthetic shadow names for (ci, mname). Index 0 is the
 # oldest snapshot (closest to parent); the highest index is the
 # newest (next super target from the active method).
  def prep_chain_syn_names(ci, mname)
    result = "".split(",", -1)
    if ci < 0 || ci >= @cls_meth_prep_chain.length
      return result
    end
    chain_str = @cls_meth_prep_chain[ci]
    if chain_str == ""
      return result
    end
    entries = chain_str.split(";", -1)
    ei = 0
    while ei < entries.length
      eq_pos = entries[ei].index("=")
      if eq_pos != nil
        em = entries[ei][0, eq_pos]
        if em == mname
          syns_str = entries[ei][eq_pos + 1, entries[ei].length - eq_pos - 1]
          return syns_str.split(",", -1)
        end
      end
      ei = ei + 1
    end
    result
  end

 # Reverse lookup -- source user mname for a synthetic shadow on
 # class ci. "" if syn_name is not a shadow.
  def prep_syn_source_mname(ci, syn_name)
    if ci < 0 || ci >= @cls_meth_prep_chain.length
      return ""
    end
    chain_str = @cls_meth_prep_chain[ci]
    if chain_str == ""
      return ""
    end
    entries = chain_str.split(";", -1)
    ei = 0
    while ei < entries.length
      eq_pos = entries[ei].index("=")
      if eq_pos != nil
        em = entries[ei][0, eq_pos]
        syns_str = entries[ei][eq_pos + 1, entries[ei].length - eq_pos - 1]
        syns = syns_str.split(",", -1)
        si = 0
        while si < syns.length
          if syns[si] == syn_name
            return em
          end
          si = si + 1
        end
      end
      ei = ei + 1
    end
    ""
  end

 # Position in chain (0 = oldest = deepest from active) for a
 # synthetic shadow on ci. -1 if syn_name is not a shadow.
  def prep_syn_position(ci, syn_name)
    if ci < 0 || ci >= @cls_meth_prep_chain.length
      return -1
    end
    chain_str = @cls_meth_prep_chain[ci]
    if chain_str == ""
      return -1
    end
    entries = chain_str.split(";", -1)
    ei = 0
    while ei < entries.length
      eq_pos = entries[ei].index("=")
      if eq_pos != nil
        syns_str = entries[ei][eq_pos + 1, entries[ei].length - eq_pos - 1]
        syns = syns_str.split(",", -1)
        si = 0
        while si < syns.length
          if syns[si] == syn_name
            return si
          end
          si = si + 1
        end
      end
      ei = ei + 1
    end
    -1
  end

 # Synthetic on-class super target for (ci, cur_mname). Returns
 # the shadow name to call (always a method on ci) or "" to mean
 # "fall through to the parent class".
  def prep_super_target(ci, cur_mname)
    if ci < 0 || ci >= @cls_meth_prep_chain.length
      return ""
    end
    if @cls_meth_prep_chain[ci] == ""
      return ""
    end
    pos = prep_syn_position(ci, cur_mname)
    if pos >= 0
      if pos > 0
        src_mname = prep_syn_source_mname(ci, cur_mname)
        syns = prep_chain_syn_names(ci, src_mname)
        if pos - 1 < syns.length
          return syns[pos - 1]
        end
      end
      return ""
    end
    syns = prep_chain_syn_names(ci, cur_mname)
    if syns.length > 0
      return syns[syns.length - 1]
    end
    ""
  end

 # When super walks past the synthetic to the parent, the parent
 # lookup uses the original user mname.
  def prep_super_parent_mname(ci, cur_mname)
    src = prep_syn_source_mname(ci, cur_mname)
    if src != ""
      return src
    end
    cur_mname
  end

 # `recv OP rhs` lowering for an obj-typed receiver. When the
 # receiver's class (or an ancestor) defines `op` as a user method,
 # returns the C expression `sp_<owner>_<op>(<recv_c>, <rhs_c>)`.
 # Returns "" when no dispatch applies (caller falls back to its
 # inline path, or to `warn_unresolved_call`).
  def obj_op_dispatch_expr(recv_t, recv_c, op, rhs_c, rhs_t = "")
    if is_obj_type(recv_t) == 0
      return ""
    end
    cname = recv_t[4, recv_t.length - 4]
    ci = find_class_idx(cname)
    if ci < 0
      return ""
    end
    owner = find_method_owner(ci, op)
    if owner == ""
      warn_unresolved_call(op, "obj_" + cname)
      return ""
    end
    cast = ""
    if owner != cname
      cast = "(sp_" + owner + " *)"
    end
 # When the user method's first param has been promoted to bigint
 # by `--int-overflow=promote`, an int rhs needs the bigint wrap
 # to match the C-level signature. Same shape for the reverse.
    rhs_coerced = rhs_c
    owner_ci = find_class_idx(owner)
    if owner_ci >= 0 && rhs_t != "" && rhs_t != ""
      midx_oo = cls_find_method_direct(owner_ci, op)
      if midx_oo >= 0
        pts_oo = cls_meth_ptypes_get(owner_ci, midx_oo)
        if pts_oo.length > 0
          first_pt_oo = base_type(pts_oo[0])
          if first_pt_oo == "bigint" && rhs_t == "int"
            @needs_bigint = 1
            rhs_coerced = "sp_bigint_new_int(" + rhs_c + ")"
          elsif first_pt_oo == "int" && rhs_t == "bigint"
            @needs_bigint = 1
            rhs_coerced = "sp_bigint_to_int((sp_Bigint *)" + rhs_c + ")"
          end
        end
      end
    end
    "sp_" + owner + "_" + sanitize_name(op) + "(" + cast + recv_c + ", " + rhs_coerced + ")"
  end

  def if_branch_has_multi_stmt(body)
    if body < 0
      return 0
    end
    if get_stmts(body).length > 1
      return 1
    end
    0
  end

 # Assign the value of an if-arm body to a temp, executing any
 # leading side-effect statements before the assignment. Body
 # convention: stmts[0..n-2] run for their side-effects;
 # stmts[n-1] supplies the arm's value. Empty/missing body → "0".
  def compile_if_arm_to_tmp(body, tmp, unified_t)
    if body < 0
      emit("  " + tmp + " = 0;")
      return
    end
    stmts = get_stmts(body)
    if stmts.length == 0
      emit("  " + tmp + " = 0;")
      return
    end
    i = 0
    while i < stmts.length - 1
      compile_stmt(stmts[i])
      i = i + 1
    end
    last_id = stmts.last
    val = compile_expr(last_id)
    if unified_t == "poly" && infer_type(last_id) != "poly"
      val = box_value_to_poly(infer_type(last_id), val)
    end
    emit("  " + tmp + " = " + val + ";")
  end

  def compile_if_expr(nid)
    cond = compile_cond_expr(@nd_predicate[nid])
    unified_t = infer_type(nid)
    body = @nd_body[nid]
    sub = @nd_subsequent[nid]

 # Side-effect-aware path: when any branch holds more than one
 # statement, the leading stmts must execute conditionally. The
 # plain ternary form drops them. Emit a real if-statement that
 # assigns to a temp and return the temp as the expression value.
 # Elsif chains recurse — the inner call returns either a temp or
 # a ternary string, both valid expressions.
    has_then_multi = if_branch_has_multi_stmt(body)
    has_else_multi = 0
    if sub >= 0 && @nd_type[sub] == "ElseNode"
      has_else_multi = if_branch_has_multi_stmt(@nd_body[sub])
    end
    if has_then_multi == 1 || has_else_multi == 1
      tmp = new_temp
      emit("  " + c_type(unified_t) + " " + tmp + ";")
      emit("  if (" + cond + ") {")
      @indent = @indent + 1
      compile_if_arm_to_tmp(body, tmp, unified_t)
      @indent = @indent - 1
      emit("  } else {")
      @indent = @indent + 1
      if sub >= 0 && @nd_type[sub] == "ElseNode"
        compile_if_arm_to_tmp(@nd_body[sub], tmp, unified_t)
      elsif sub >= 0
        sub_val = compile_if_expr(sub)
        sub_t = infer_type(sub)
        if unified_t == "poly" && sub_t != "poly"
          sub_val = box_value_to_poly(sub_t, sub_val)
        end
        emit("  " + tmp + " = " + sub_val + ";")
      else
        emit("  " + tmp + " = 0;")
      end
      @indent = @indent - 1
      emit("  }")
      return tmp
    end

 # Fast path: every branch is at most one statement, so the
 # whole if-expression collapses to a C ternary.
 # Flow-sensitive narrowing for `<lv> == nil ? T : F` and
 # `<lv> != nil ? T : F` shapes: the arm that sees `<lv>` as
 # non-nil narrows the var's type from `T?` to `T`, so reads
 # inside that arm pick the unboxed slot. Issue #645.
    nc_pred_ie = parse_nil_check_predicate(@nd_predicate[nid])
    nc_var_ie = nc_pred_ie[0]
    nc_then_narrow_ie = ""
    nc_else_narrow_ie = ""
    if nc_var_ie != ""
      slot_t_ie = find_var_type(nc_var_ie)
      stripped_t_ie = ""
      if is_nullable_type(slot_t_ie) == 1
        stripped_t_ie = slot_t_ie[0, slot_t_ie.length - 1]
      end
      if stripped_t_ie != ""
        if nc_pred_ie[1] == "non_nil"
          nc_then_narrow_ie = stripped_t_ie
        elsif nc_pred_ie[1] == "nil"
          nc_else_narrow_ie = stripped_t_ie
        end
      end
    end
    then_val = "0"
    then_t = "nil"
    if body >= 0
      stmts = get_stmts(body)
      if stmts.length > 0
        if nc_then_narrow_ie != ""
          push_type_narrow(nc_var_ie, nc_then_narrow_ie)
        end
        then_t = infer_type(stmts.last)
        then_val = compile_expr(stmts.last)
        if nc_then_narrow_ie != ""
          pop_type_narrow
        end
      end
    end
    else_val = "0"
    else_t = "nil"
    if sub >= 0
      if @nd_type[sub] == "ElseNode"
        eb = @nd_body[sub]
        if eb >= 0
          es = get_stmts(eb)
          if es.length > 0
            if nc_else_narrow_ie != ""
              push_type_narrow(nc_var_ie, nc_else_narrow_ie)
            end
            else_t = infer_type(es.last)
            else_val = compile_expr(es.last)
            if nc_else_narrow_ie != ""
              pop_type_narrow
            end
          end
        end
      else
        else_t = infer_type(sub)
        else_val = compile_if_expr(sub)
      end
    end
 # When the if-expression's unified type is `poly` but the
 # branches have concrete types, the raw C ternary
 # `(cond ? sp_IntArray * : sp_PtrArray *)` mixes pointer types
 # and the C compiler rejects the assignment to sp_RbVal.
 # Box each branch into sp_RbVal so the ternary's two arms
 # share a type. Keeps the static infer_type(IfNode) → poly
 # contract that downstream dispatch (e.g. .each on poly recv)
 # relies on.
    if unified_t == "poly"
      if then_t != "poly"
        then_val = box_value_to_poly(then_t, then_val)
      end
      if else_t != "poly"
        else_val = box_value_to_poly(else_t, else_val)
      end
    end
 # Same shape for unified bigint: the two arms must share an
 # sp_Bigint* C type so the ternary doesn't mix int / pointer.
 # Boxes an int literal arm via sp_bigint_new_int (and the rarely
 # firing inverse int-unified-but-arm-is-bigint via
 # sp_bigint_to_int).
    if base_type(unified_t) == "bigint"
      if then_t == "int" || then_t == "nil"
        @needs_bigint = 1
        then_val = "sp_bigint_new_int(" + then_val + ")"
      end
      if else_t == "int" || else_t == "nil"
        @needs_bigint = 1
        else_val = "sp_bigint_new_int(" + else_val + ")"
      end
    end
    "(" + cond + " ? " + then_val + " : " + else_val + ")"
  end

  def compile_unless_expr(nid)
    cond = compile_cond_expr(@nd_predicate[nid])
    then_val = "0"
    then_t = "nil"
    body = @nd_body[nid]
    if body >= 0
      stmts = get_stmts(body)
      if stmts.length > 0
        then_t = infer_type(stmts.last)
        then_val = compile_expr(stmts.last)
      end
    end
    unified_t = infer_type(nid)
    else_val = c_return_default(then_t)
    if unified_t == "poly"
      if then_t != "poly"
        then_val = box_value_to_poly(then_t, then_val)
      end
      else_val = box_value_to_poly("nil", "0")
    end
    "(!" + cond + " ? " + then_val + " : " + else_val + ")"
  end

 # Compile an `ArrayNode` literal as `sp_PolyArray *`, regardless
 # of the inferred elem type. Used by the nested-array path in
 # the poly_array branch so 3D-and-deeper arrays preserve cls_id
 # tags through every level (e.g. an inner `[1,2,3]` ends up
 # boxed via `sp_box_int_array` so the dispatch can still
 # `sp_IntArray_get` on it).
  def compile_array_literal_as_poly(nid)
    @needs_gc = 1
    @needs_rb_value = 1
    elems = parse_id_list(@nd_elements[nid])
    tmp = new_temp
    emit("  sp_PolyArray *" + tmp + " = sp_PolyArray_new();")
    k = 0
    while k < elems.length
      eid = elems[k]
      et = infer_type(eid)
      if @nd_type[eid] == "ArrayNode" && (is_ptr_array_type(et) == 1 || et == "poly_array")
        inner = compile_array_literal_as_poly(eid)
        emit("  sp_PolyArray_push(" + tmp + ", sp_box_poly_array(" + inner + "));")
      elsif is_ptr_array_type(et) == 1
 # Non-ArrayNode whose static type is a typed `<X>_ptr_array`
 # (e.g. `Array.new(N) { ... }` returning int_array_ptr_array).
 # Convert at runtime so each inner element keeps its real
 # cls_id (sp_box_int_array etc.) — `arr[i][j][k]` chains
 # correctly through the next-level dispatch.
        val = compile_expr(eid)
        inner_t = ptr_array_elem_type(et)
        conv = new_temp
        ii = new_temp
        emit("  sp_PolyArray *" + conv + " = sp_PolyArray_new();")
        emit("  for (mrb_int " + ii + " = 0; " + ii + " < sp_PtrArray_length(" + val + "); " + ii + "++) {")
        inner_get = "(" + c_type(inner_t) + ")sp_PtrArray_get(" + val + ", " + ii + ")"
        emit("    sp_PolyArray_push(" + conv + ", " + box_value_to_poly(inner_t, inner_get) + ");")
        emit("  }")
        emit("  sp_PolyArray_push(" + tmp + ", sp_box_poly_array(" + conv + "));")
      else
        val = compile_expr(eid)
 # Stale cache may say "int" for an arith CallNode whose
 # actual emit is bigint. Promote at the box boundary so
 # box_value_to_poly's bigint arm fires (unbox + sp_box_int).
        if et != "bigint" && @nd_type[eid] == "CallNode"
          eml = @nd_name[eid]
          if eml == "+" || eml == "-" || eml == "*" || eml == "/" || eml == "%" || eml == "**"
            er = @nd_receiver[eid]
            if er >= 0 && base_type(infer_type(er)) == "bigint"
              et = "bigint"
            else
              ea = @nd_arguments[eid]
              if ea >= 0
                aa_lit = get_args(ea)
                if aa_lit.length > 0 && base_type(infer_type(aa_lit[0])) == "bigint"
                  et = "bigint"
                end
              end
            end
          end
        end
        emit("  sp_PolyArray_push(" + tmp + ", " + box_value_to_poly(et, val) + ");")
      end
      k = k + 1
    end
    tmp
  end

  def compile_array_literal(nid)
    @needs_gc = 1
    elems = parse_id_list(@nd_elements[nid])
    if elems.length == 0
      @needs_int_array = 1
      return "sp_IntArray_new()"
    end
    compile_array_literal_from_ids(elems, array_literal_arr_type(elems))
  end

 # Pick the array type for a non-empty `[e0, e1, ...]` literal. Spinel's
 # general infer_array_elem_type returns `int_array` when no other arm
 # claims the shape, which silently swallows raw-pointer elements
 # (FFI `:ptr` returns) into an IntArray slot — every push then fires
 # `-Wint-conversion` because mrb_int isn't void*. Check that case up
 # front: if every element infers as `ptr`, lower the literal directly
 # to `ptr_ptr_array` so codegen picks sp_PtrArray + noscan. Otherwise
 # defer to the existing inference cascade.
  def array_literal_arr_type(elems)
    if elems.length > 0 && infer_type(elems[0]) == "ptr"
      all_ptr = 1
      k = 1
      while k < elems.length
        if infer_type(elems[k]) != "ptr"
          all_ptr = 0
        end
        k = k + 1
      end
      if all_ptr == 1
        return "ptr_ptr_array"
      end
    end
    infer_array_elem_type_from_ids(elems)
  end

 # Body of compile_array_literal, parameterised on the list of value
 # node ids and the resolved array element type. Lets a HashNode
 # whose keys are 0..N-1 (lowered to Array) reuse the same emission
 # paths by feeding in the AssocNode rhs ids without needing an
 # ArrayNode wrapper.
  def compile_array_literal_from_ids(elems, arr_type)
    @needs_gc = 1
    if is_tuple_type(arr_type) == 1
      name = tuple_c_name(arr_type)
      tmp = new_temp
      parts = tuple_elem_types_str(arr_type).split(",", -1)
      emit("  " + name + " *" + tmp + " = (" + name + " *)sp_gc_alloc(sizeof(" + name + "), NULL, " + tuple_scan_name(arr_type) + ");")
      k = 0
      while k < elems.length && k < parts.length
        emit("  " + tmp + "->_" + k.to_s + " = " + compile_expr(elems[k]) + ";")
        k = k + 1
      end
      return tmp
    end
    if arr_type == "str_array"
      @needs_str_array = 1
      tmp = new_temp
      emit("  sp_StrArray *" + tmp + " = sp_StrArray_new();")
      emit("  SP_GC_ROOT(" + tmp + ");")
      k = 0
      while k < elems.length
        emit("  sp_StrArray_push(" + tmp + ", " + compile_expr(elems[k]) + ");")
        k = k + 1
      end
      return tmp
    end
    if arr_type == "poly_array"
      @needs_rb_value = 1
      tmp = new_temp
      emit("  sp_PolyArray *" + tmp + " = sp_PolyArray_new();")
      emit("  SP_GC_ROOT(" + tmp + ");")
      k = 0
      while k < elems.length
        et = infer_type(elems[k])
 # 3D+ shape: when the element is itself a typed
 # `<X>_ptr_array` that came from a nested ArrayNode, the
 # default `compile_array_literal` for that element would
 # emit a typed sp_PtrArray and `sp_box_ptr_array` would
 # erase the elem type (cls_id PTR_ARRAY). Recompile the
 # nested literal as poly_array so the next-level dispatch
 # sees `cls_id == POLY_ARRAY` and recurses with each
 # innermost typed array still tagged correctly.
        if @nd_type[elems[k]] == "ArrayNode" && (is_ptr_array_type(et) == 1 || et == "poly_array")
          val = compile_array_literal_as_poly(elems[k])
          emit("  sp_PolyArray_push(" + tmp + ", sp_box_poly_array(" + val + "));")
        elsif is_ptr_array_type(et) == 1
 # Same 3D+ erasure but the element is a non-ArrayNode
 # expression (e.g. `Array.new(N) { ... }` returning a
 # typed `<X>_ptr_array`). compile_array_literal_as_poly
 # only walks ArrayNodes — emit a runtime conversion that
 # iterates the typed PtrArray and tags each inner with
 # its real cls_id (sp_box_int_array etc.).
          val = compile_expr(elems[k])
          inner_t = ptr_array_elem_type(et)
          conv = new_temp
          ii = new_temp
          emit("  sp_PolyArray *" + conv + " = sp_PolyArray_new();")
          emit("  for (mrb_int " + ii + " = 0; " + ii + " < sp_PtrArray_length(" + val + "); " + ii + "++) {")
          inner_get = "(" + c_type(inner_t) + ")sp_PtrArray_get(" + val + ", " + ii + ")"
          emit("    sp_PolyArray_push(" + conv + ", " + box_value_to_poly(inner_t, inner_get) + ");")
          emit("  }")
          emit("  sp_PolyArray_push(" + tmp + ", sp_box_poly_array(" + conv + "));")
        else
          val = compile_expr(elems[k])
 # Stale cache may say "int" for an arith CallNode whose
 # actual emit is bigint OR poly. Promote at the box boundary
 # so box_value_to_poly picks the matching arm.
          if et != "bigint" && et != "poly" && @nd_type[elems[k]] == "CallNode"
            ear_mn = @nd_name[elems[k]]
            if ear_mn == "+" || ear_mn == "-" || ear_mn == "*" || ear_mn == "/" || ear_mn == "%" || ear_mn == "**"
              ear_r = @nd_receiver[elems[k]]
              if ear_r >= 0 && base_type(infer_type(ear_r)) == "bigint"
                et = "bigint"
              elsif ear_r >= 0 && base_type(infer_type(ear_r)) == "poly"
                et = "poly"
              else
                ear_a = @nd_arguments[elems[k]]
                if ear_a >= 0
                  aa_ear = get_args(ear_a)
                  if aa_ear.length > 0
                    a0_t = base_type(infer_type(aa_ear[0]))
                    if a0_t == "bigint"
                      et = "bigint"
                    elsif a0_t == "poly"
                      et = "poly"
                    end
                  end
                end
              end
            end
          end
          emit("  sp_PolyArray_push(" + tmp + ", " + box_value_to_poly(et, val) + ");")
        end
        k = k + 1
      end
      return tmp
    end
    if arr_type == "float_array"
      @needs_float_array = 1
      tmp = new_temp
      emit("  sp_FloatArray *" + tmp + " = sp_FloatArray_new();")
      emit("  SP_GC_ROOT(" + tmp + ");")
      k = 0
      while k < elems.length
        emit("  sp_FloatArray_push(" + tmp + ", " + compile_expr(elems[k]) + ");")
        k = k + 1
      end
      return tmp
    end
    if is_ptr_array_type(arr_type) == 1
      tmp = new_temp
 # Raw `:ptr` elements (FFI returns, dlopen handles, ...) don't
 # carry sp_gc_hdr, so the default GC-scanning PtrArray would crash
 # when the collector tried to walk element headers. Pick the
 # noscan constructor — the array header is still GC-tracked but
 # element slots are treated as opaque pointer-sized values.
      if ptr_array_elem_type(arr_type) == "ptr"
        emit("  sp_PtrArray *" + tmp + " = sp_PtrArray_new_noscan();")
      else
        emit("  sp_PtrArray *" + tmp + " = sp_PtrArray_new();")
      end
 # Root the freshly-allocated PtrArray before compiling element
 # expressions. Each element is typically Klass.new(...), and that
 # call allocates → may trigger GC. Without this, GC sees `tmp` as
 # unreachable and frees it, leaving a dangling pointer that the
 # subsequent push (and the eventual ivar assignment) writes through.
      emit("  SP_GC_ROOT(" + tmp + ");")
      k = 0
      while k < elems.length
        emit("  sp_PtrArray_push(" + tmp + ", " + compile_expr(elems[k]) + ");")
        k = k + 1
      end
      return tmp
    end
    @needs_int_array = 1
    tmp = new_temp
    emit("  sp_IntArray *" + tmp + " = sp_IntArray_new();")
    k = 0
    while k < elems.length
      eid = elems[k]
 # SplatNode in an Array literal — `[*range]` or `[*arr]` —
 # expands the inner expression's elements into the array.
 # Without this branch, compile_expr lowered the splat to a
 # default value (e.g., the lower bound of a Range), so
 # `[*0..4096]` ended up as just `[0]`.
      if @nd_type[eid] == "SplatNode"
        inner = @nd_expression[eid]
        it = infer_type(inner)
 # Root tmp so a sp_IntArray_push grow inside the splat loop
 # can't sweep the half-built array. Hoist range / source
 # expressions to a temp so side effects (method calls in the
 # bound, chained recv) fire exactly once.
        emit("  SP_GC_ROOT(" + tmp + ");")
        if @nd_type[inner] == "RangeNode"
          lo = compile_expr(@nd_left[inner])
          hi_expr = compile_expr(@nd_right[inner])
          hi = new_temp
          emit("  mrb_int " + hi + " = " + hi_expr + ";")
          cmp = range_excl_end(inner) == 1 ? "<" : "<="
          ii = new_temp
          emit("  for (mrb_int " + ii + " = " + lo + "; " + ii + " " + cmp + " " + hi + "; " + ii + "++) {")
          emit("    sp_IntArray_push(" + tmp + ", " + ii + ");")
          emit("  }")
        elsif it == "int_array" || it == "sym_array"
          src_expr = compile_expr(inner)
          src = new_temp
          emit("  sp_IntArray *" + src + " = " + src_expr + ";")
          emit("  SP_GC_ROOT(" + src + ");")
          ii = new_temp
          emit("  for (mrb_int " + ii + " = 0; " + ii + " < sp_IntArray_length(" + src + "); " + ii + "++) {")
          emit("    sp_IntArray_push(" + tmp + ", sp_IntArray_get(" + src + ", " + ii + "));")
          emit("  }")
        end
        k = k + 1
        next
      end
      ev = compile_expr(eid)
      et = infer_type(eid)
 # Block-param destructure (`|(x, y), i|` from a poly_array source)
 # leaves x, y uncached by annotate_all_node_types — the cached
 # type for `x - y` falls back to "int" while the actual emit
 # picks `sp_poly_sub` (sp_RbVal) because find_var_type at codegen
 # time sees x as poly. Refresh the cached classification by
 # checking the receiver's CURRENT scope type. Issue surfaced via
 # `each_cons_with_index_map_no_double_gets` under promote.
      if et == "int" && @nd_type[eid] == "CallNode"
        e_mn = @nd_name[eid]
        if e_mn == "+" || e_mn == "-" || e_mn == "*" || e_mn == "/" || e_mn == "%" || e_mn == "**"
          e_rcv = @nd_receiver[eid]
          if e_rcv >= 0 && @nd_type[e_rcv] == "LocalVariableReadNode"
            e_rcv_t = find_var_type(@nd_name[e_rcv])
            if e_rcv_t == "poly"
              et = "poly"
            end
          end
        end
      end
 # Unbox poly values when pushing into a (concrete) IntArray.
 # An ArrayNode literal whose elements are poly (e.g.
 # `[addr]` where addr's recorded type is sp_RbVal) needs the
 # int payload extracted via `.v.i`. Without this, the C
 # compiler rejects the push with "incompatible type".
      if et == "poly"
        ev = "(" + ev + ").v.i"
      elsif et == "bigint" || expr_emit_is_bigint(eid) == 1
 # promote-mode element: unbox to mrb_int.
        @needs_bigint = 1
        ev = "sp_bigint_to_int((sp_Bigint *)" + ev + ")"
      end
      emit("  sp_IntArray_push(" + tmp + ", " + ev + ");")
      k = k + 1
    end
    tmp
  end

 # HashNode literal whose keys are 0..N-1 lowered to an Array
 # literal. Reuses compile_array_literal_from_ids by mapping each
 # AssocNode to its rhs value id.
  def compile_int_keyed_hash_as_array(nid)
    @needs_gc = 1
    elems = parse_id_list(@nd_elements[nid])
    vids = []
    k = 0
    while k < elems.length
      vids.push(@nd_expression[elems[k]])
      k = k + 1
    end
    compile_array_literal_from_ids(vids, infer_array_elem_type_from_ids(vids))
  end

  def compile_hash_literal(nid)
    @needs_gc = 1
    if is_int_array_lowered_hash(nid) == 1
      return compile_int_keyed_hash_as_array(nid)
    end
    elems = parse_id_list(@nd_elements[nid])
    if elems.length == 0
      @needs_str_int_hash = 1
      return "sp_StrIntHash_new()"
    end
    ht = infer_hash_val_type(nid)
    if ht == "int_str_hash"
      @needs_int_str_hash = 1
      tmp = new_temp
      emit("  sp_IntStrHash *" + tmp + " = sp_IntStrHash_new();")
      emit("  SP_GC_ROOT(" + tmp + ");")
      elems.each { |el|
        if @nd_type[el] == "AssocNode"
          emit("  sp_IntStrHash_set(" + tmp + ", " + compile_expr(@nd_key[el]) + ", " + compile_expr(@nd_expression[el]) + ");")
        end
      }
      return tmp
    end
    if ht == "str_str_hash"
      @needs_str_str_hash = 1
      tmp = new_temp
      emit("  sp_StrStrHash *" + tmp + " = sp_StrStrHash_new();")
      emit("  SP_GC_ROOT(" + tmp + ");")
      elems.each { |el|
        if @nd_type[el] == "AssocNode"
          vt = infer_type(@nd_expression[el])
          val = compile_expr(@nd_expression[el])
          if vt == "int"
            val = "sp_int_to_s(" + val + ")"
          else
            if vt == "float"
              val = "sp_float_to_s(" + val + ")"
            else
              if vt == "bool"
                val = "(" + val + " ? \"true\" : \"false\")"
              end
            end
          end
          emit("  sp_StrStrHash_set(" + tmp + ", " + compile_expr_as_string(@nd_key[el]) + ", " + val + ");")
        end
      }
      return tmp
    end
    if ht == "sym_int_hash"
      @needs_sym_int_hash = 1
      tmp = new_temp
      emit("  sp_SymIntHash *" + tmp + " = sp_SymIntHash_new();")
      emit("  SP_GC_ROOT(" + tmp + ");")
      elems.each { |el|
        if @nd_type[el] == "AssocNode"
          v_syh = compile_expr(@nd_expression[el])
          if infer_type(@nd_expression[el]) == "bigint"
            @needs_bigint = 1
            v_syh = "sp_bigint_to_int((sp_Bigint *)" + v_syh + ")"
          end
          emit("  sp_SymIntHash_set(" + tmp + ", " + compile_expr(@nd_key[el]) + ", " + v_syh + ");")
        end
      }
      return tmp
    end
    if ht == "sym_str_hash"
      @needs_sym_str_hash = 1
      tmp = new_temp
      emit("  sp_SymStrHash *" + tmp + " = sp_SymStrHash_new();")
      emit("  SP_GC_ROOT(" + tmp + ");")
      elems.each { |el|
        if @nd_type[el] == "AssocNode"
          emit("  sp_SymStrHash_set(" + tmp + ", " + compile_expr(@nd_key[el]) + ", " + compile_expr(@nd_expression[el]) + ");")
        end
      }
      return tmp
    end
    if ht == "sym_poly_hash"
      @needs_rb_value = 1
      tmp = new_temp
      emit("  sp_SymPolyHash *" + tmp + " = sp_SymPolyHash_new();")
      emit("  SP_GC_ROOT(" + tmp + ");")
      elems.each { |el|
        if @nd_type[el] == "AssocNode"
          emit("  sp_SymPolyHash_set(" + tmp + ", " + compile_expr(@nd_key[el]) + ", " + box_expr_to_poly(@nd_expression[el]) + ");")
        end
      }
      return tmp
    end
    if ht == "str_poly_hash"
      @needs_rb_value = 1
      tmp = new_temp
      emit("  sp_StrPolyHash *" + tmp + " = sp_StrPolyHash_new();")
      emit("  SP_GC_ROOT(" + tmp + ");")
      elems.each { |el|
        if @nd_type[el] == "AssocNode"
          emit("  sp_StrPolyHash_set(" + tmp + ", " + compile_expr_as_string(@nd_key[el]) + ", " + box_expr_to_poly(@nd_expression[el]) + ");")
        end
      }
      return tmp
    end
    if ht == "poly_poly_hash"
 # Mixed-shape keys (e.g. `{ 0 => false, a: 1 }`). Both key
 # and value carry their own tag; box each at the assoc site.
 # Issue #536.
      @needs_rb_value = 1
      @needs_poly_poly_hash = 1
      tmp = new_temp
      emit("  sp_PolyPolyHash *" + tmp + " = sp_PolyPolyHash_new();")
      emit("  SP_GC_ROOT(" + tmp + ");")
      elems.each { |el|
        if @nd_type[el] == "AssocNode"
          emit("  sp_PolyPolyHash_set(" + tmp + ", " + box_expr_to_poly(@nd_key[el]) + ", " + box_expr_to_poly(@nd_expression[el]) + ");")
        end
      }
      return tmp
    end
    @needs_str_int_hash = 1
    tmp = new_temp
    emit("  sp_StrIntHash *" + tmp + " = sp_StrIntHash_new();")
    emit("  SP_GC_ROOT(" + tmp + ");")
    elems.each { |el|
      if @nd_type[el] == "AssocNode"
        v_sih = compile_expr(@nd_expression[el])
        if infer_type(@nd_expression[el]) == "bigint"
          @needs_bigint = 1
          v_sih = "sp_bigint_to_int((sp_Bigint *)" + v_sih + ")"
        end
        emit("  sp_StrIntHash_set(" + tmp + ", " + compile_expr_as_string(@nd_key[el]) + ", " + v_sih + ");")
      end
    }
    tmp
  end

 # ---- Statement compiler ----
  def compile_stmt(nid)
    if nid < 0
      return
    end
    t = @nd_type[nid]
    if t == "UnsupportedNode"
 # Imaginary / Rational now have proper nodes (#840 #841). Any
 # remaining UnsupportedNode is a genuine syntax gap; hard-error.
      kind_us2 = @nd_content[nid]
      $stderr.puts "Spinel: cannot compile " + kind_us2 + " at line " + @nd_value[nid].to_s + " (unsupported Ruby syntax)"
      exit(1)
    end
    if t == "MultiWriteNode"
      compile_multi_write(nid)
      return
    end
    if t == "GlobalVariableWriteNode"
      gname = @nd_name[nid]
      if gname != "$stderr" && gname != "$stdout" && gname != "$?"
        cname = sanitize_gvar(gname)
        val = compile_expr(@nd_expression[nid])
        emit("  " + cname + " = " + val + ";")
        return
      end
    end
    if t == "GlobalVariableOperatorWriteNode"
 # `$x += val`, `$x -= val`, etc. Mirrors LocalVariableOperatorWriteNode
 # for the storage path (sanitize_gvar instead of fiber_var_ref).
      op = @nd_binop[nid]
      val = compile_expr(@nd_expression[nid])
      cname = sanitize_gvar(@nd_name[nid])
      if op == "+"
        emit("  " + cname + " += " + val + ";")
      end
      if op == "-"
        emit("  " + cname + " -= " + val + ";")
      end
      if op == "*"
        emit("  " + cname + " *= " + val + ";")
      end
      if op == "/"
        emit("  " + cname + " = sp_idiv(" + cname + ", " + val + ");")
      end
      if op == "%"
        emit("  " + cname + " = sp_imod(" + cname + ", " + val + ");")
      end
      if op == "<<"
        emit("  " + cname + " <<= " + val + ";")
      end
      if op == ">>"
        emit("  " + cname + " >>= " + val + ";")
      end
      if op == "&"
        emit("  " + cname + " &= " + val + ";")
      end
      if op == "|"
        emit("  " + cname + " |= " + val + ";")
      end
      if op == "^"
        emit("  " + cname + " ^= " + val + ";")
      end
      return
    end
    if t == "GlobalVariableOrWriteNode"
 # `$x ||= val`. Short-circuit: only evaluate RHS when LHS is
 # falsy. compile_expr can emit prerequisite statements; running
 # it inside the C `if` block ensures those side effects only
 # fire on the assign branch. Note: in Ruby, an undefined $-var
 # reads as nil, which is falsy in C terms, so the `if (!cname)`
 # guard fires both for never-assigned and assigned-to-falsy.
      cname = sanitize_gvar(@nd_name[nid])
      emit("  if (!(" + cname + ")) {")
      val = compile_expr(@nd_expression[nid])
      emit("    " + cname + " = " + val + ";")
      emit("  }")
      return
    end
    if t == "GlobalVariableAndWriteNode"
 # `$x &&= val`. Short-circuit: only evaluate RHS when LHS is
 # truthy. compile_expr can emit prerequisite statements; running
 # it inside the C `if` block keeps those side effects on the
 # assign branch only. Mirror of OrWrite, condition inverted.
      cname = sanitize_gvar(@nd_name[nid])
      emit("  if (" + cname + ") {")
      val = compile_expr(@nd_expression[nid])
      emit("    " + cname + " = " + val + ";")
      emit("  }")
      return
    end
    if t == "ClassVariableWriteNode"
 # `@@x = val` inside class body or method. Storage is the
 # per-(class,name) C global cvar_<ClassName>_<var> registered
 # by collect_cvars during the pre-pass. If the cvar wasn't seen
 # there (e.g. inside a class-method that pre-pass missed) we
 # register defensively.
      qname = cvar_qname(@current_class_idx, @nd_name[nid])
      ci_cv_pre = find_cvar_idx(qname)
      cv_slot_t_pre = ci_cv_pre >= 0 ? @cvar_types[ci_cv_pre] : ""
      if cv_slot_t_pre == "" || cv_slot_t_pre == ""
        val = compile_expr(@nd_expression[nid])
        val_t = infer_type(@nd_expression[nid])
      else
        val = compile_expr_for_expected_type(@nd_expression[nid], cv_slot_t_pre)
        val_t = cv_slot_t_pre
      end
      register_cvar(qname, val_t)
      emit("  cvar_" + qname + " = " + val + ";")
      return
    end
    if t == "ClassVariableOperatorWriteNode"
 # `@@x op= val` -- desugar to `@@x = @@x op val`. Mirrors
 # GlobalVariableOperatorWriteNode and the instance-var
 # variant. Same storage path as ClassVariableWriteNode.
      qname = cvar_qname(@current_class_idx, @nd_name[nid])
      val = compile_expr(@nd_expression[nid])
      val_t = infer_type(@nd_expression[nid])
      register_cvar(qname, val_t)
      cname = "cvar_" + qname
      op = @nd_binop[nid]
      if op == "+"
        emit("  " + cname + " += " + val + ";")
      elsif op == "-"
        emit("  " + cname + " -= " + val + ";")
      elsif op == "*"
        emit("  " + cname + " *= " + val + ";")
      elsif op == "/"
        emit("  " + cname + " = sp_idiv(" + cname + ", " + val + ");")
      elsif op == "%"
        emit("  " + cname + " = sp_imod(" + cname + ", " + val + ");")
      elsif op == "<<"
        emit("  " + cname + " <<= " + val + ";")
      elsif op == ">>"
        emit("  " + cname + " >>= " + val + ";")
      elsif op == "&"
        emit("  " + cname + " &= " + val + ";")
      elsif op == "|"
        emit("  " + cname + " |= " + val + ";")
      elsif op == "^"
        emit("  " + cname + " ^= " + val + ";")
      else
        emit("  " + cname + " = " + cname + " " + op + " " + val + ";")
      end
      return
    end
    if t == "ClassVariableOrWriteNode"
 # `@@x ||= val` -- evaluate rhs only when @@x is falsy.
 # Mirror of GlobalVariableOrWriteNode.
      qname = cvar_qname(@current_class_idx, @nd_name[nid])
      val_t = infer_type(@nd_expression[nid])
      register_cvar(qname, val_t)
      cname = "cvar_" + qname
      emit("  if (!(" + cname + ")) {")
      val = compile_expr(@nd_expression[nid])
      emit("    " + cname + " = " + val + ";")
      emit("  }")
      return
    end
    if t == "ClassVariableAndWriteNode"
 # `@@x &&= val` -- evaluate rhs only when @@x is truthy.
      qname = cvar_qname(@current_class_idx, @nd_name[nid])
      val_t = infer_type(@nd_expression[nid])
      register_cvar(qname, val_t)
      cname = "cvar_" + qname
      emit("  if (" + cname + ") {")
      val = compile_expr(@nd_expression[nid])
      emit("    " + cname + " = " + val + ";")
      emit("  }")
      return
    end
    if t == "RedoNode"
 # `redo` -- jump to the top of the current iteration without
 # advancing the iterator or re-evaluating the loop guard. The
 # loop emitter installs a label via push_redo_label /
 # emit_redo_label; we goto the innermost.
      if @redo_label_stack.length == 0
        $stderr.puts "Spinel: `redo` outside of a loop"
        exit(1)
      end
      lbl = @redo_label_stack.last
      emit("  goto " + lbl + ";")
      return
    end
    if t == "AliasGlobalVariableNode"
 # `alias $copy $orig` -- compile-time only. collect_all
 # already populated @galias_*; references through
 # sanitize_gvar / scan_features / infer_type pick up the
 # rewrite. Nothing to emit at runtime.
      return
    end
    if t == "AliasMethodNode"
 # `alias new old` -- compile-time only. The class-collect pass
 # already registered a duplicate method-table entry under the
 # new name pointing to the same body_id; subsequent dispatch
 # finds it like any other method.
      return
    end
    if t == "UndefNode"
 # `undef foo` -- compile-time only. The class-collect pass
 # already recorded the removal in @undef_*; nothing to emit.
      return
    end
    if t == "PreExecutionNode"
 # `BEGIN { ... }`. collect_all already pushed the body onto
 # @pre_execution_blocks; emit_main hoists it to the top of
 # main(). The toplevel statement itself is a no-op at its
 # source location.
      return
    end
    if t == "PostExecutionNode"
 # `END { ... }`. collect_all pushed the body onto
 # @post_execution_blocks; emit_post_execution_funcs emits the
 # static sp_end_block_<n> function and emit_main inserts an
 # atexit() call at startup.
      return
    end
    if t == "LocalVariableWriteNode"
      lname = @nd_name[nid]
 # `var = method(:name)` (no receiver, top-level) is the legacy
 # static-alias path: the call_expr handler returns a `0`
 # placeholder, we record (lname, mref) here, and a later
 # `m.call(x)` is rewritten in compile_dot_call_expr to a
 # direct `sp_<name>(x)` call. Inside a class body OR with a
 # receiver (`var = recv.method(:_)`), the call expr already
 # produced a real obj_Method instance — fall through to the
 # normal compile path so the typed local picks it up. .
      expr_id = @nd_expression[nid]
      if expr_id >= 0
        if @nd_type[expr_id] == "CallNode"
          if @nd_name[expr_id] == "method" && @nd_receiver[expr_id] < 0 && @current_class_idx < 0
            args_id = @nd_arguments[expr_id]
            if args_id >= 0
              arg_ids = get_args(args_id)
              if arg_ids.length >= 1
                mref = @nd_content[arg_ids[0]]
                if mref == ""
                  mref = @nd_name[arg_ids[0]]
                end
                @method_ref_vars.push(lname)
                @method_ref_names.push(mref)
                emit("  /* " + lname + " = method(:" + mref + ") */")
                return
              end
            end
          end
        end
      end
      vref = fiber_var_ref(lname)
 # LV-write picks the slot's tracked C storage type — the narrow
 # stack (find_var_type) is read-only. A re-assignment inside an
 # `if x.is_a?(String) ... end` body must use the slot's actual
 # type for the emit decision (poly_box arm, hash-variant arm,
 # etc.), not the in-body narrow that only governs reads. Without
 # this, `opt = { a: 7 } if opt.is_a?(String)` would look up
 # vt=="string" inside the modifier-if body and skip the
 # sym_poly_hash literal arm. See #615.
      vt = find_var_declared_type(lname)
 # Empty array literal: create the correct array type. Returning
 # early here also preserves the scope's already-promoted type
 # , #85) — the fall-through path below would clobber
 # vt with infer_type([])'s "int_array" via set_var_type.
      if vt == "str_array" || vt == "float_array" || vt == "sym_array" || vt == "poly_array" || is_ptr_array_type(vt) == 1
        expr_id = @nd_expression[nid]
        if expr_id >= 0 && @nd_type[expr_id] == "ArrayNode"
          elems = parse_id_list(@nd_elements[expr_id])
          if elems.length == 0
            if vt == "str_array"
              @needs_str_array = 1
              @needs_gc = 1
              emit("  " + vref + " = sp_StrArray_new();")
            elsif vt == "float_array"
              @needs_float_array = 1
              @needs_gc = 1
              emit("  " + vref + " = sp_FloatArray_new();")
            elsif vt == "sym_array"
 # sym_array shares sp_IntArray storage.
              @needs_int_array = 1
              @needs_gc = 1
              emit("  " + vref + " = sp_IntArray_new();")
            elsif vt == "poly_array"
              @needs_rb_value = 1
              @needs_gc = 1
              emit("  " + vref + " = sp_PolyArray_new();")
            else
              @needs_gc = 1
              emit("  " + vref + " = sp_PtrArray_new();")
            end
            return
          end
        end
      end
 # Empty hash literal: create the correct hash type. The local's
 # type was promoted by scan_locals' empty-hash promotion (str_int_hash
 # default refined based on first []= site's key/value types).
 # Without these arms the literal `{}` would always emit
 # sp_StrIntHash_new() and the assignment would mismatch the
 # promoted local's struct type.
      if vt == "str_str_hash" || vt == "int_str_hash" || vt == "sym_int_hash" || vt == "sym_str_hash" || vt == "str_poly_hash" || vt == "sym_poly_hash" || vt == "poly_poly_hash"
 # `Hash.new(default)` against a poly-widened LV: the
 # compile_constructor_expr emit picks the variant from the
 # default's type, but if the LV later widened (e.g. mixed-key
 # writes), the construction mismatches the declared LV type.
 # Build the appropriate widened variant here, boxing the
 # default if necessary. Issue #600 puzzle 2 with widening.
        expr_id2 = @nd_expression[nid]
        if expr_id2 >= 0 && @nd_type[expr_id2] == "CallNode" && @nd_name[expr_id2] == "new"
          recv_hn = @nd_receiver[expr_id2]
          if recv_hn >= 0 && @nd_type[recv_hn] == "ConstantReadNode" && @nd_name[recv_hn] == "Regexp"
 # Regexp.new -- not Hash. Fall through.
          elsif recv_hn >= 0 && @nd_type[recv_hn] == "ConstantReadNode" && @nd_name[recv_hn] == "Hash" && @nd_block[expr_id2] < 0
            args_id_hn = @nd_arguments[expr_id2]
            if args_id_hn >= 0
              aa_hn = get_args(args_id_hn)
              if aa_hn.length >= 1
                if vt == "str_poly_hash"
                  @needs_str_poly_hash = 1
                  @needs_rb_value = 1
                  @needs_gc = 1
                  emit("  " + vref + " = sp_StrPolyHash_new_with_default(" + box_expr_to_poly(aa_hn[0]) + ");")
                  return
                end
                if vt == "sym_poly_hash"
                  @needs_sym_poly_hash = 1
                  @needs_rb_value = 1
                  @needs_gc = 1
                  emit("  " + vref + " = sp_SymPolyHash_new_with_default(" + box_expr_to_poly(aa_hn[0]) + ");")
                  return
                end
              end
            end
          end
        end
        if expr_id2 >= 0 && @nd_type[expr_id2] == "HashNode"
          elems2 = parse_id_list(@nd_elements[expr_id2])
          if elems2.length == 0
            @needs_gc = 1
            if vt == "str_str_hash"
              @needs_str_str_hash = 1
              emit("  " + vref + " = sp_StrStrHash_new();")
            elsif vt == "int_str_hash"
              @needs_int_str_hash = 1
              emit("  " + vref + " = sp_IntStrHash_new();")
            elsif vt == "sym_int_hash"
              @needs_sym_int_hash = 1
              emit("  " + vref + " = sp_SymIntHash_new();")
            elsif vt == "sym_str_hash"
              @needs_sym_str_hash = 1
              emit("  " + vref + " = sp_SymStrHash_new();")
            elsif vt == "str_poly_hash"
              @needs_str_poly_hash = 1
              @needs_rb_value = 1
              emit("  " + vref + " = sp_StrPolyHash_new();")
            elsif vt == "sym_poly_hash"
              @needs_sym_poly_hash = 1
              @needs_rb_value = 1
              emit("  " + vref + " = sp_SymPolyHash_new();")
            elsif vt == "poly_poly_hash"
              @needs_poly_poly_hash = 1
              @needs_rb_value = 1
              emit("  " + vref + " = sp_PolyPolyHash_new();")
            end
            return
          end
 # Non-empty hash literal against an LV widened to a `*_poly_hash`
 # variant (the analyzer scan_locals widening for cross-type
 # `[]=` writes after an initial typed literal). Build the
 # literal as the poly variant directly, boxing each value.
 # Without this, the literal init emitted `sp_StrStrHash_new` +
 # `sp_StrStrHash_set` and assigned the result to the
 # poly-typed LV slot, producing a -Wincompatible-pointer-types
 # warning (and later setter calls on the LV used the wrong
 # variant's ABI).
          if vt == "str_poly_hash" || vt == "sym_poly_hash"
            @needs_gc = 1
            @needs_rb_value = 1
            tmp_hp = new_temp
            if vt == "str_poly_hash"
              @needs_str_poly_hash = 1
              emit("  sp_StrPolyHash *" + tmp_hp + " = sp_StrPolyHash_new();")
            else
              @needs_sym_poly_hash = 1
              emit("  sp_SymPolyHash *" + tmp_hp + " = sp_SymPolyHash_new();")
            end
            ehk = 0
            while ehk < elems2.length
              if @nd_type[elems2[ehk]] == "AssocNode"
                key_eh = @nd_key[elems2[ehk]]
                val_eh = @nd_expression[elems2[ehk]]
                if key_eh >= 0 && val_eh >= 0
                  setter = vt == "str_poly_hash" ? "sp_StrPolyHash_set" : "sp_SymPolyHash_set"
                  key_eh_c = vt == "str_poly_hash" ? compile_expr_as_string(key_eh) : compile_expr(key_eh)
                  emit("  " + setter + "(" + tmp_hp + ", " + key_eh_c + ", " + box_expr_to_poly(val_eh) + ");")
                end
              end
              ehk = ehk + 1
            end
            emit("  " + vref + " = " + tmp_hp + ";")
            return
          end
        end
      end
      if vt == "bigint"
 # Route through compile_expr_for_expected_type so the cache-
 # override for arith CallNode on a bigint recv kicks in. This
 # avoids the double-wrap `sp_bigint_new_int(sp_bigint_mul(...))`
 # when the rhs is a bigint expression whose cached annotation
 # is stale at "int".
        val = compile_expr_for_expected_type(@nd_expression[nid], "bigint")
        emit("  " + vref + " = " + val + ";")
 # Trigger GC after bigint statement (safe point - all results stored in vars)
        emit("  if(sp_gc_bytes>sp_gc_threshold){size_t _b=sp_gc_bytes;sp_gc_collect();size_t _f=_b-sp_gc_bytes;if(_f<_b/4)sp_gc_threshold=_b*2;else if(sp_gc_bytes>0){sp_gc_threshold=sp_gc_bytes*4;if(sp_gc_threshold<sp_gc_threshold_init)sp_gc_threshold=sp_gc_threshold_init;}else sp_gc_threshold=sp_gc_threshold_init;}")
        return
      end
      if vt == "poly"
 # Box the value
        emit("  " + vref + " = " + box_expr_to_poly(@nd_expression[nid]) + ";")
        return
      end
      if vt == "mutable_str"
        rhs_type = infer_type(@nd_expression[nid])
        val = compile_expr(@nd_expression[nid])
        if rhs_type == "string" || rhs_type == "int"
          emit("  " + vref + " = sp_String_new(" + val + ");")
        else
          emit("  " + vref + " = " + val + ";")
        end
        return
      end
 # Optimize: x = str.split(sep) inside a loop → reuse StrArray
      if @in_loop == 1 && vt == "str_array"
        expr_id = @nd_expression[nid]
        if expr_id >= 0 && @nd_type[expr_id] == "CallNode" && @nd_name[expr_id] == "split"
          r = @nd_receiver[expr_id]
          if r >= 0 && infer_type(r) == "string"
            src = compile_expr(r)
            sep = compile_arg0(expr_id)
            emit("  if (" + vref + " == NULL) " + vref + " = sp_str_split(" + src + ", " + sep + ");")
            emit("  else sp_str_split_into(" + vref + ", " + src + ", " + sep + ");")
            return
          end
        end
      end
      rhs_t = infer_type(@nd_expression[nid])
      if rhs_t == "nil" && is_nullable_type(vt) == 1
        emit("  " + vref + " = NULL;")
      else
        val = compile_expr(@nd_expression[nid])
 # Wrap narrower hash RHS to match a wider *_poly_hash slot.
 # See widen_hash_assign / issue #614.
        val = widen_hash_assign(val, vt, rhs_t)
 # Box scalar RHS into poly when the local slot is poly. Without
 # this, `lv = sp_IntArray_get(...)` (int RHS) into a sp_RbVal
 # slot fails C compile. Mirrors the InstanceVariableWriteNode
 # path's box-when-slot-is-poly logic.
        if vt == "poly" && rhs_t != "" && rhs_t != "poly"
          val = box_value_to_poly(rhs_t, val)
        end
 # Auto-unbox poly RHS into a primitive local slot. Common
 # case: `pixel0 = arr[i]` where arr is heterogeneous (poly
 # element type) and the dispatch arms all return int —
 # spinel types `arr[i]` as poly, but the local is concretely
 # int from a prior int-typed write. Reading .v.i preserves
 # the runtime int payload; non-int payloads fall to 0
 # (matches `to_i` semantics for poly).
        if rhs_t == "poly" && (vt == "int" || vt == "bool")
          val = "(" + val + ").v.i"
          rhs_t = vt
        end
        if rhs_t == "poly" && vt == "float"
          val = "(" + val + ").v.f"
          rhs_t = vt
        end
 # Auto-unbox poly RHS into a typed pointer slot. The
 # poly_poly_hash IndexOrWriteNode lowering returns sp_RbVal
 # so a `param = @cache[k] ||= param` assignment against a
 # typed param (e.g. `sp_Method *` for the optcarrot @pokes
 # cache where all callers happen to pass Method) needs the
 # `.v.p` extraction here. Strip the nullable `?` marker so
 # nullable obj slots (`obj_Method?`) cast to the same C type.
        kept_typed_unbox = 0
        if rhs_t == "poly" && is_obj_type(base_type(vt)) == 1
          cname_unbox = base_type(vt)[4, base_type(vt).length - 4]
          val = "(sp_" + cname_unbox + " *)(" + val + ").v.p"
          kept_typed_unbox = 1
        end
        emit("  " + vref + " = " + val + ";")
      end
      if rhs_t != "nil" || is_nullable_type(vt) == 0
 # Skip the type-widening update when we just unboxed the
 # poly RHS into a typed pointer slot — the C variable's
 # declared type is unchanged, so future reads must keep
 # treating the slot as the original obj_X.
        if !(rhs_t == "poly" && is_obj_type(base_type(vt)) == 1)
          set_var_type(lname, rhs_t)
        end
      end
 # Track `lv = @ivar` as a one-step alias so the `<poly>[k]`
 # narrowing can resolve through the local back to the ivar's
 # element-observation list. Any non-ivar RHS (or a subsequent
 # write of a non-ivar) clears the alias.
      ivar_alias = ""
      ex_id = @nd_expression[nid]
      if ex_id >= 0 && @nd_type[ex_id] == "InstanceVariableReadNode"
        ivar_alias = @nd_name[ex_id]
      end
      set_var_ivar_alias(lname, ivar_alias)
      return
    end
    if t == "LocalVariableOperatorWriteNode"
      op = @nd_binop[nid]
      val = compile_expr(@nd_expression[nid])
      vref = fiber_var_ref(@nd_name[nid])
      vt = find_var_type(@nd_name[nid])
 # Same desugaring as the ivar form: `local OP= rhs` is
 # `local = local OP rhs`. Dispatch through the user-defined
 # operator when the local is obj-typed.
      disp = obj_op_dispatch_expr(vt, vref, op, val, infer_type(@nd_expression[nid]))
      if disp != ""
        emit("  " + vref + " = " + disp + ";")
        return
      end
      if base_type(vt) == "bigint"
        at = infer_type(@nd_expression[nid])
 # The cache may say "int" even though the rhs emits bigint;
 # the unified emit walker covers arith, bitop, user methods,
 # paren, and unary.
        if at != "bigint" && expr_emit_is_bigint(@nd_expression[nid]) == 1
          at = "bigint"
        end
 # Cast away volatile from bigint locals (see compile_bigint_arg).
        barg = at == "bigint" ? "(sp_Bigint *)" + val : "sp_bigint_new_int(" + val + ")"
        vref_b = "(sp_Bigint *)" + vref
        @needs_bigint = 1
        if op == "+"
          emit("  " + vref + " = sp_bigint_add(" + vref_b + ", " + barg + ");")
        end
        if op == "-"
          emit("  " + vref + " = sp_bigint_sub(" + vref_b + ", " + barg + ");")
        end
        if op == "*"
          emit("  " + vref + " = sp_bigint_mul(" + vref_b + ", " + barg + ");")
        end
        if op == "/"
          emit("  " + vref + " = sp_bigint_div(" + vref_b + ", " + barg + ");")
        end
        if op == "%"
          emit("  " + vref + " = sp_bigint_mod(" + vref_b + ", " + barg + ");")
        end
        if op == "&"
          emit("  " + vref + " = sp_bigint_and(" + vref_b + ", " + barg + ");")
        end
        if op == "|"
          emit("  " + vref + " = sp_bigint_or(" + vref_b + ", " + barg + ");")
        end
        if op == "^"
          emit("  " + vref + " = sp_bigint_xor(" + vref_b + ", " + barg + ");")
        end
        if op == "<<" || op == ">>"
          shamt_slv = at == "bigint" ? "sp_bigint_to_int(" + barg + ")" : "(" + val + ")"
          h_slv = op == "<<" ? "sp_bigint_shl" : "sp_bigint_shr"
          emit("  " + vref + " = " + h_slv + "(" + vref_b + ", " + shamt_slv + ");")
        end
        emit("  if(sp_gc_bytes>sp_gc_threshold){size_t _b=sp_gc_bytes;sp_gc_collect();size_t _f=_b-sp_gc_bytes;if(_f<_b/4)sp_gc_threshold=_b*2;else if(sp_gc_bytes>0){sp_gc_threshold=sp_gc_bytes*4;if(sp_gc_threshold<sp_gc_threshold_init)sp_gc_threshold=sp_gc_threshold_init;}else sp_gc_threshold=sp_gc_threshold_init;}")
        return
      end
      if op == "+"
        if vt == "string" && infer_type(@nd_expression[nid]) == "string"
          emit("  " + vref + " = sp_str_concat(" + vref + ", " + val + ");")
        elsif vt == "complex" && infer_type(@nd_expression[nid]) == "complex"
 # `+=` on a struct doesn't compile in C; desugar to
 # `vref = sp_complex_add(vref, val)`.
          emit("  " + vref + " = sp_complex_add(" + vref + ", " + val + ");")
        else
          emit("  " + vref + " += " + val + ";")
        end
      end
      if op == "-"
        emit("  " + vref + " -= " + val + ";")
      end
      if op == "*"
        if vt == "complex" && infer_type(@nd_expression[nid]) == "complex"
          emit("  " + vref + " = sp_complex_mul(" + vref + ", " + val + ");")
        else
          emit("  " + vref + " *= " + val + ";")
        end
      end
      if op == "/"
        emit("  " + vref + " = sp_idiv(" + vref + ", " + val + ");")
      end
      if op == "%"
        emit("  " + vref + " = sp_imod(" + vref + ", " + val + ");")
      end
      if op == "<<"
        emit("  " + vref + " <<= " + val + ";")
      end
      if op == ">>"
        emit("  " + vref + " >>= " + val + ";")
      end
      if op == "&"
        emit("  " + vref + " &= " + val + ";")
      end
      if op == "|"
        emit("  " + vref + " |= " + val + ";")
      end
      if op == "^"
        emit("  " + vref + " ^= " + val + ";")
      end
      return
    end
    if t == "LocalVariableOrWriteNode"
      vref = fiber_var_ref(@nd_name[nid])
      val = compile_expr(@nd_expression[nid])
      lvw_t = find_var_declared_type(@nd_name[nid])
      rhs_t_orw = infer_type(@nd_expression[nid])
 # Type-aware truthy check + value coerce to slot. Issue #702.
 # Raw `if (!vref)` fails to compile when vref is an sp_RbVal
 # struct, so use truthy_c_expr for poly / scalar-nullable
 # specifically. For other types (incl. "nil" -- the first-write
 # type for `a = nil; a ||= ...` where scan_locals never widened),
 # keep the C-truthy fallback so the runtime value gets checked.
      check_orw = "(!(" + vref + "))"
      if lvw_t == "poly" || is_scalar_nullable_type(lvw_t) == 1
        check_orw = "(!" + truthy_c_expr(lvw_t, vref) + ")"
      end
      val_orw = val
      if lvw_t == "poly" && rhs_t_orw != "" && rhs_t_orw != "poly"
        val_orw = box_value_to_poly(rhs_t_orw, val)
      end
      emit("  if " + check_orw + " " + vref + " = " + val_orw + ";")
      return
    end
    if t == "LocalVariableAndWriteNode"
      vref = fiber_var_ref(@nd_name[nid])
      val = compile_expr(@nd_expression[nid])
      lvw_t = find_var_declared_type(@nd_name[nid])
      rhs_t_aw = infer_type(@nd_expression[nid])
      check_aw = "(" + vref + ")"
      if lvw_t == "poly" || is_scalar_nullable_type(lvw_t) == 1
        check_aw = truthy_c_expr(lvw_t, vref)
      end
      val_aw = val
      if lvw_t == "poly" && rhs_t_aw != "" && rhs_t_aw != "poly"
        val_aw = box_value_to_poly(rhs_t_aw, val)
      end
      emit("  if (" + check_aw + ") " + vref + " = " + val_aw + ";")
      return
    end
    if t == "InstanceVariableWriteNode"
      iname = @nd_name[nid]
      expr_id = @nd_expression[nid]
 # Chained `@a = @b = ... = expr`. The naive emit lowers this as
 # `iv_a = (iv_b = (... = expr))` — one `expr` evaluation, but the
 # outer slot tries to absorb the inner write's typed value, so
 # disagreeing slot types fail the C compile. Per-slot recursion
 # would re-evaluate `expr` once per ivar and double-fire side
 # effects on a CallNode rhs. Compute `expr` once into a typed
 # temp and assign each slot from the temp, boxing to poly only
 # for the slots that scan_writer_calls already widened.
      if @nd_type[expr_id] == "InstanceVariableWriteNode"
        compile_chained_ivar_writes(nid)
        return
      end
 # Empty `{}` / `[]` literal assigned to an ivar that scan_writer_calls
 # has promoted to a non-default container type. The literal emitters use
 # default empty container types, so without this special-case the ivar
 # slot's type and the initializer's type can disagree.
      ivt = ""
      if @current_class_idx >= 0
        ivt = cls_ivar_type(@current_class_idx, iname)
      end
 # Module class method (`def self.X` on a module): the ivar
 # `@X` resolves to a module-level constant `cst_<Mod>_<X>`,
 # not an instance ivar. Look up the const's stored type so the
 # empty-`{}` / empty-`[]` promotion below picks the right
 # `sp_*_new()` for the slot's actual hash/array variant.
 # Without this, `def self.reset_slots!; @slots = {}; end` on a
 # module whose @slots constant is sym_poly_hash emits
 # sp_StrIntHash_new() (the empty-hash default), failing C
 # compile at the cst write.
      if ivt == "" && @current_method_name != ""
        mci = 0
        while mci < @module_names.length
          mod_n = @module_names[mci]
          if mod_n != "" && @current_method_name.start_with?(mod_n + "_cls_")
            const_n = mod_n + "_" + iname[1, iname.length - 1]
            const_idx = find_const_idx(const_n)
            if const_idx >= 0
              ivt = @const_types[const_idx]
              break
            end
          end
          mci = mci + 1
        end
      end
      if is_empty_hash_literal(expr_id) == 1 && ivt != "" && ivt != "str_int_hash"
        ctor = ""
        if ivt == "str_str_hash"
          @needs_str_str_hash = 1
          ctor = "sp_StrStrHash_new()"
        elsif ivt == "int_str_hash"
          @needs_int_str_hash = 1
          ctor = "sp_IntStrHash_new()"
        elsif ivt == "sym_int_hash"
          @needs_sym_int_hash = 1
          ctor = "sp_SymIntHash_new()"
        elsif ivt == "sym_str_hash"
          @needs_sym_str_hash = 1
          ctor = "sp_SymStrHash_new()"
        elsif ivt == "str_poly_hash"
          ctor = "sp_StrPolyHash_new()"
        elsif ivt == "sym_poly_hash"
          ctor = "sp_SymPolyHash_new()"
        elsif ivt == "poly_poly_hash"
          @needs_poly_poly_hash = 1
          @needs_rb_value = 1
          ctor = "sp_PolyPolyHash_new()"
        end
        if ctor != ""
          @needs_gc = 1
          emit("  " + ivar_lhs(iname) + " = " + ctor + ";")
          return
        end
      end
      if is_empty_array_literal(expr_id) == 1 && ivt != ""
        ctor = empty_array_new_for_type(ivt)
        if ctor != ""
          @needs_gc = 1
          emit("  " + ivar_lhs(iname) + " = " + ctor + ";")
          return
        end
      end
 # `@arr = [nil] * N` where @arr is a poly_array (or ptr_array)
 # slot. The default `*` codegen produces an sp_IntArray, which
 # mismatches the slot type and corrupts later
 # `sp_PolyArray_set(@arr, ...)` calls. Emit a sized PolyArray
 # of sp_box_nil() (or PtrArray of NULLs) inline so the slot
 # holds the matching storage.
      if (ivt == "poly_array" || is_ptr_array_type(ivt) == 1) && is_sized_empty_array_default(expr_id) == 1
        @needs_gc = 1
        cnt_e = compile_arg0_as_int(expr_id)
        tmp_arr = new_temp
        if ivt == "poly_array"
          @needs_rb_value = 1
          emit("  sp_PolyArray *" + tmp_arr + " = sp_PolyArray_new();")
          emit("  { mrb_int _n = " + cnt_e + "; for (mrb_int _i = 0; _i < _n; _i++) sp_PolyArray_push(" + tmp_arr + ", sp_box_nil()); }")
        else
          emit("  sp_PtrArray *" + tmp_arr + " = sp_PtrArray_new();")
          emit("  { mrb_int _n = " + cnt_e + "; for (mrb_int _i = 0; _i < _n; _i++) sp_PtrArray_push(" + tmp_arr + ", NULL); }")
        end
        emit("  " + self_arrow + sanitize_ivar(iname) + " = " + tmp_arr + ";")
        return
      end
 # `@arr = [nil] * N` where @arr is a poly slot (sp_RbVal). The
 # cyclic inference can leave a slot at poly when its definition
 # site `[nil] * N` would naturally infer as int_array but a
 # subsequent heterogeneous write demands more. Emit as a sized
 # PolyArray boxed to poly so the runtime storage supports
 # heterogeneous writes via the poly-recv `[]=` dispatch.
      if ivt == "poly" && is_sized_empty_array_default(expr_id) == 1
        @needs_gc = 1
        @needs_rb_value = 1
        cnt_e = compile_arg0_as_int(expr_id)
        tmp_arr = new_temp
        emit("  sp_PolyArray *" + tmp_arr + " = sp_PolyArray_new();")
        emit("  { mrb_int _n = " + cnt_e + "; for (mrb_int _i = 0; _i < _n; _i++) sp_PolyArray_push(" + tmp_arr + ", sp_box_nil()); }")
        emit("  " + self_arrow + sanitize_ivar(iname) + " = sp_box_poly_array(" + tmp_arr + ");")
        return
      end
 # Non-empty array literal `[a, b, ...]` going into a poly_array
 # slot. compile_array_literal infers a typed array (ptr_array of
 # one class for homogeneous obj literals, etc.) and emits the
 # corresponding storage — but the slot was widened to poly_array,
 # so a typed-array-pointer assignment would fail the C compile.
 # Emit a fresh PolyArray with each element boxed to sp_RbVal.
      if ivt == "poly_array" && @nd_type[expr_id] == "ArrayNode"
        @needs_gc = 1
        @needs_rb_value = 1
        tmp_arr = new_temp
        emit("  sp_PolyArray *" + tmp_arr + " = sp_PolyArray_new();")
        elems_pa = parse_id_list(@nd_elements[expr_id])
        ek = 0
        while ek < elems_pa.length
          eid = elems_pa[ek]
          et = infer_type(eid)
 # 3D+ shape: nested ArrayNode with ptr_array element
 # type — recompile as poly_array so cls_id chain stays
 # tagged through every level.
          if @nd_type[eid] == "ArrayNode" && (is_ptr_array_type(et) == 1 || et == "poly_array")
            inner = compile_array_literal_as_poly(eid)
            emit("  sp_PolyArray_push(" + tmp_arr + ", sp_box_poly_array(" + inner + "));")
          elsif is_ptr_array_type(et) == 1
 # Same 3D+ erasure but the element is a non-ArrayNode
 # expression (e.g. `Array.new(N) { ... }` returning a
 # typed `<X>_ptr_array`). Convert at runtime so each
 # inner element keeps its real cls_id —
 # `arr[b][i][j]` chains correctly.
            ev = compile_expr(eid)
            inner_t_pa = ptr_array_elem_type(et)
            conv_pa = new_temp
            ii_pa = new_temp
            emit("  sp_PolyArray *" + conv_pa + " = sp_PolyArray_new();")
            emit("  for (mrb_int " + ii_pa + " = 0; " + ii_pa + " < sp_PtrArray_length(" + ev + "); " + ii_pa + "++) {")
            inner_get_pa = "(" + c_type(inner_t_pa) + ")sp_PtrArray_get(" + ev + ", " + ii_pa + ")"
            emit("    sp_PolyArray_push(" + conv_pa + ", " + box_value_to_poly(inner_t_pa, inner_get_pa) + ");")
            emit("  }")
            emit("  sp_PolyArray_push(" + tmp_arr + ", sp_box_poly_array(" + conv_pa + "));")
          else
            ev = compile_expr(eid)
            ebox = et == "poly" ? ev : box_value_to_poly(et, ev)
            emit("  sp_PolyArray_push(" + tmp_arr + ", " + ebox + ");")
          end
          ek = ek + 1
        end
        emit("  " + self_arrow + sanitize_ivar(iname) + " = " + tmp_arr + ";")
        return
      end
 # Poly slot — every concrete-typed RHS must be boxed to
 # sp_RbVal. Without the box, the C compiler sees
 # `sp_RbVal = mrb_int` (or const char *, etc.) and either
 # rejects the assignment or silently coerces. Read sites
 # already dispatch through poly-aware emitters
 # (sp_poly_puts, etc.) that unbox.
      if ivt == "poly"
        val = box_expr_to_poly(expr_id)
      else
        val = compile_expr(expr_id)
 # Issue #639: ivar slot is concrete (RBS-pinned Integer / String
 # etc.) but rhs is poly because the source flow lost the type
 # (case-by-symbol dispatch where each `when :sym` arm narrows a
 # union-typed value to the ivar's slot type at runtime). Unbox
 # via the matching union field so the C-level assignment
 # type-checks; the runtime narrowing the user wrote keeps it
 # sound.
        rhs_t_ivw_p = infer_type(expr_id)
        if rhs_t_ivw_p == "poly" && ivt != "" && ivt != "poly"
          @needs_rb_value = 1
          ivt_b = base_type(ivt)
          if ivt_b == "int" || ivt_b == "bool" || ivt_b == "symbol"
            val = "(" + val + ").v.i"
          elsif ivt_b == "string" || ivt_b == "mutable_str"
            val = "(" + val + ").v.s"
          elsif ivt_b == "float"
            val = "(" + val + ").v.f"
          elsif ivt_b == "bigint"
 # poly bitop helpers (sp_poly_band / _bor / _bxor / _shl / _shr)
 # return sp_RbVal with SP_TAG_INT (Ruby bitops produce ints).
 # Unbox via .v.i and rebox into sp_Bigint * to match the
 # promote-mode bigint ivar slot.
            @needs_bigint = 1
            val = "sp_bigint_new_int((" + val + ").v.i)"
          elsif is_obj_type(ivt_b) == 1 || is_array_type(ivt_b) == 1 || is_hash_type(ivt_b) == 1 || is_ptr_array_type(ivt_b) == 1 || ivt_b == "proc"
            val = "(" + c_type(ivt) + ")(" + val + ").v.p"
          end
        end
 # `--int-overflow=promote` widens ivar slots to bigint; an
 # int-typed RHS (literal, arithmetic, etc.) needs the
 # sp_bigint_new_int wrap before assignment. Detect the
 # promote-side stale-cache shapes (IVOpWriteNode rhs whose own
 # ivar slot is bigint, ParenthesesNode peek, attr_writer
 # setter on a bigint-promoted slot) so the wrap fires only on
 # actual int rhs.
        rhs_eff_t_ivw = infer_type(expr_id)
        if ivt == "bigint" && rhs_eff_t_ivw != "bigint"
          eff_rhs_ivw = expr_id
          if eff_rhs_ivw >= 0 && @nd_type[eff_rhs_ivw] == "ParenthesesNode"
            pb_iv = @nd_body[eff_rhs_ivw]
            if pb_iv >= 0
              ps_iv = get_stmts(pb_iv)
              if ps_iv.length == 1
                eff_rhs_ivw = ps_iv[0]
              end
            end
          end
          if eff_rhs_ivw >= 0
            erhs_t_iv = @nd_type[eff_rhs_ivw]
            if erhs_t_iv == "InstanceVariableOperatorWriteNode" || erhs_t_iv == "InstanceVariableAndWriteNode" || erhs_t_iv == "InstanceVariableOrWriteNode" || erhs_t_iv == "InstanceVariableWriteNode"
              if @current_class_idx >= 0
                ivar_inner = cls_ivar_type(@current_class_idx, @nd_name[eff_rhs_ivw])
                if base_type(ivar_inner) == "bigint"
                  rhs_eff_t_ivw = "bigint"
                end
              end
            elsif erhs_t_iv == "CallNode"
              rcv_eff = @nd_receiver[eff_rhs_ivw]
              mn_eff = @nd_name[eff_rhs_ivw]
              if rcv_eff >= 0 && mn_eff.length > 1 && mn_eff[mn_eff.length - 1] == "=" && mn_eff != "==" && mn_eff != "!=" && mn_eff != "<=" && mn_eff != ">="
                rt_eff = base_type(infer_type(rcv_eff))
                if is_obj_type(rt_eff) == 1
                  rcn_eff = rt_eff[4, rt_eff.length - 4]
                  rci_eff = find_class_idx(rcn_eff)
                  if rci_eff >= 0
                    bn_eff = mn_eff[0, mn_eff.length - 1]
                    if cls_has_attr_writer(rci_eff, bn_eff) == 1
                      if base_type(cls_ivar_type(rci_eff, "@" + bn_eff)) == "bigint"
                        rhs_eff_t_ivw = "bigint"
                      end
                    end
                  end
                end
              end
 # Arith / bitwise CallNode on a bigint recv emits bigint.
              if rhs_eff_t_ivw != "bigint" && rcv_eff >= 0 && (mn_eff == "+" || mn_eff == "-" || mn_eff == "*" || mn_eff == "/" || mn_eff == "%" || mn_eff == "**" || mn_eff == "<<" || mn_eff == ">>" || mn_eff == "&" || mn_eff == "|" || mn_eff == "^")
                if base_type(infer_type(rcv_eff)) == "bigint"
                  rhs_eff_t_ivw = "bigint"
                end
              end
            end
          end
        end
        if ivt == "bigint" && rhs_eff_t_ivw == "int"
          @needs_bigint = 1
          val = "sp_bigint_new_int(" + val + ")"
        end
      end
 # Check if we're in a module class method
      mod_ivar = 0
      mi3 = 0
      while mi3 < @module_names.length
        mmod = @module_names[mi3]
        if mmod != ""
          if @current_method_name.start_with?(mmod + "_cls_")
            cname3 = mmod + "_" + iname[1, iname.length - 1]
            ci3 = find_const_idx(cname3)
            if ci3 >= 0
              emit("  cst_" + cname3 + " = " + val + ";")
              mod_ivar = 1
            end
          end
        end
        mi3 = mi3 + 1
      end
      if mod_ivar == 0
        emit("  " + ivar_lhs(iname) + " = " + val + ";")
      end
      return
    end
 # `@x ||= expr`: `@x = expr` only when @x is currently nil/false.
 # Lower to `if (!@x) { @x = expr; }`. For pointer-typed slots
 # (sp_Foo *, const char *, ...) the C `!ptr` check is exact; for
 # an int slot we treat 0 as falsy (Spinel's int slot has no
 # separate nil/false state). The `&&= expr` form is the dual.
 # Compile the rhs INSIDE the conditional block so any auxiliary
 # emits land in the conditional body — matches Ruby's
 # short-circuit semantics where the rhs (and its side effects)
 # only run when the lhs is falsy.
    if t == "InstanceVariableOrWriteNode" || t == "InstanceVariableAndWriteNode"
      ivor_iname = @nd_name[nid]
      ivor_lhs = ivar_lhs(ivor_iname)
      ivor_expr_id = @nd_expression[nid]
      ivor_ivar_t = ""
      if @current_class_idx >= 0
        ivor_ivar_t = cls_ivar_type(@current_class_idx, ivor_iname)
      end
      ivor_cond = ""
      if base_type(ivor_ivar_t) == "poly"
        ivor_cond = "(" + ivor_lhs + ").tag == SP_TAG_NIL || ((" + ivor_lhs + ").tag == SP_TAG_BOOL && (" + ivor_lhs + ").v.i == 0)"
      else
        ivor_cond = "!(" + ivor_lhs + ")"
      end
      if t == "InstanceVariableAndWriteNode"
        ivor_cond = "!(" + ivor_cond + ")"
      end
      emit("  if (" + ivor_cond + ") {")
      ivor_val = compile_expr(ivor_expr_id)
      ivor_val_t = infer_type(ivor_expr_id)
      if base_type(ivor_ivar_t) == "poly" && ivor_val_t != "" && ivor_val_t != "poly"
        ivor_val = box_value_to_poly(ivor_val_t, ivor_val)
      end
      emit("    " + ivor_lhs + " = " + ivor_val + ";")
      emit("  }")
      return
    end
    if t == "InstanceVariableOperatorWriteNode"
      op = @nd_binop[nid]
      val = compile_expr(@nd_expression[nid])
      lhs = ivar_lhs(@nd_name[nid])
      ivar_t = ""
      if @current_class_idx >= 0
        ivar_t = cls_ivar_type(@current_class_idx, @nd_name[nid])
      end
 # `@x OP= v` desugars to `@x = @x OP v`. When @x is obj-typed
 # and the class defines OP, dispatch to the user method
 # instead of emitting a raw C `+=` (which on a pointer is
 # silently miscompiled as pointer arithmetic).
      disp = obj_op_dispatch_expr(ivar_t, lhs, op, val, infer_type(@nd_expression[nid]))
      if disp != ""
        emit("  " + lhs + " = " + disp + ";")
        return
      end
 # bigint-typed ivar in promote mode: route arithmetic through
 # sp_bigint_* helpers, wrap an int rhs through sp_bigint_new_int.
      if ivar_t == "bigint"
        @needs_bigint = 1
        rhs_t_iov = infer_type(@nd_expression[nid])
 # Stale "int" infer with a bigint-emitting rhs (a `^` or other
 # bitop chain whose operands include bigint): the rhs is
 # already sp_Bigint *, so wrapping it in sp_bigint_new_int is
 # the wrong shape. Use the emit walker to upgrade.
        if rhs_t_iov != "bigint" && expr_emit_is_bigint(@nd_expression[nid]) == 1
          rhs_t_iov = "bigint"
        end
        rhs_big_iov = rhs_t_iov == "bigint" ? "(sp_Bigint *)(" + val + ")" : "sp_bigint_new_int(" + val + ")"
        if op == "+"
          emit("  " + lhs + " = sp_bigint_add((sp_Bigint *)" + lhs + ", " + rhs_big_iov + ");")
          return
        end
        if op == "-"
          emit("  " + lhs + " = sp_bigint_sub((sp_Bigint *)" + lhs + ", " + rhs_big_iov + ");")
          return
        end
        if op == "*"
          emit("  " + lhs + " = sp_bigint_mul((sp_Bigint *)" + lhs + ", " + rhs_big_iov + ");")
          return
        end
        if op == "/"
          emit("  " + lhs + " = sp_bigint_div((sp_Bigint *)" + lhs + ", " + rhs_big_iov + ");")
          return
        end
        if op == "%"
          emit("  " + lhs + " = sp_bigint_mod((sp_Bigint *)" + lhs + ", " + rhs_big_iov + ");")
          return
        end
        if op == "<<" || op == ">>"
          shamt_iov = rhs_t_iov == "bigint" ? "sp_bigint_to_int(" + rhs_big_iov + ")" : "(" + val + ")"
          h_iov = op == "<<" ? "sp_bigint_shl" : "sp_bigint_shr"
          emit("  " + lhs + " = " + h_iov + "((sp_Bigint *)" + lhs + ", " + shamt_iov + ");")
          return
        end
        if op == "&" || op == "|" || op == "^"
          h_bitop_iov = op == "&" ? "sp_bigint_and" : (op == "|" ? "sp_bigint_or" : "sp_bigint_xor")
          emit("  " + lhs + " = " + h_bitop_iov + "((sp_Bigint *)" + lhs + ", " + rhs_big_iov + ");")
          return
        end
      end
 # Bitwise / shift / arithmetic op-assigns map directly onto C
 # `OP=`. Without these arms `@a &= v`, `@a |= v`, etc. were
 # silently dropped — the function emit fell through with no
 # `iv_<name>` write, so every read after kept the pre-call
 # value. Mirror the LocalVariableOperatorWriteNode arm.
      if op == "+"
        if ivar_t == "string" && infer_type(@nd_expression[nid]) == "string"
          emit("  " + lhs + " = sp_str_concat(" + lhs + ", " + val + ");")
        else
          emit("  " + lhs + " += " + val + ";")
        end
        return
      end
      if op == "-"
        emit("  " + lhs + " -= " + val + ";")
        return
      end
      if op == "*"
        emit("  " + lhs + " *= " + val + ";")
        return
      end
      if op == "/"
        emit("  " + lhs + " = sp_idiv(" + lhs + ", " + val + ");")
        return
      end
      if op == "%"
        emit("  " + lhs + " = sp_imod(" + lhs + ", " + val + ");")
        return
      end
      if op == "<<" || op == ">>" || op == "&" || op == "|" || op == "^"
        emit("  " + lhs + " " + op + "= " + val + ";")
        return
      end
      return
    end
 # `recv[idx] OP= value`. Without this case, the IndexOperatorWriteNode
 # the parser emits would fall through and the increment would be
 # silently dropped — symptoms include matmul / += accumulators
 # producing zero-valued output even though forward passes look fine.
    if t == "IndexOperatorWriteNode"
      compile_index_op_assign(nid)
      return
    end
    if t == "IndexAndWriteNode"
      compile_index_and_assign(nid)
      return
    end
    if t == "IndexOrWriteNode"
      compile_index_or_assign(nid)
      return
    end
    if t == "CallOperatorWriteNode"
      compile_call_assign_typed(nid, "Operator")
      return
    end
    if t == "CallAndWriteNode"
      compile_call_assign_typed(nid, "And")
      return
    end
    if t == "CallOrWriteNode"
      compile_call_assign_typed(nid, "Or")
      return
    end
    if t == "IfNode"
      compile_if_stmt(nid)
      return
    end
    if t == "UnlessNode"
      compile_unless_stmt(nid)
      return
    end
    if t == "WhileNode"
      compile_while_stmt(nid)
      return
    end
    if t == "UntilNode"
      compile_until_stmt(nid)
      return
    end
    if t == "ForNode"
      compile_for_stmt(nid)
      return
    end
    if t == "CaseNode"
      compile_case_stmt(nid)
      return
    end
    if t == "CaseMatchNode"
      compile_case_match_stmt(nid)
      return
    end
    if t == "ReturnNode"
      compile_return_stmt(nid)
      return
    end
    if t == "BreakNode"
      emit("  break;")
      return
    end
    if t == "NextNode"
      emit("  continue;")
      return
    end
    if t == "RetryNode"
      emit("  continue;")
      return
    end
    if t == "YieldNode"
      compile_yield_stmt(nid)
      return
    end
    if t == "BeginNode"
      compile_begin_stmt(nid)
      return
    end
    if t == "CallNode"
      compile_call_stmt(nid)
      return
    end
    if t == "StatementsNode"
      stmts = parse_id_list(@nd_stmts[nid])
      k = 0
      while k < stmts.length
        compile_stmt(stmts[k])
        k = k + 1
      end
      return
    end
    if t == "ParenthesesNode"
      body = @nd_body[nid]
      if body >= 0
        pstmts = get_stmts(body)
        pk = 0
        while pk < pstmts.length
          compile_stmt(pstmts[pk])
          pk = pk + 1
        end
      end
      return
    end
    expr = compile_expr(nid)
    if expr != "0"
      emit("  " + expr + ";")
    end
    return
  end

 # Emit assignment of `value_expr` to a single MultiWrite target node
 # (LocalVariableTargetNode or InstanceVariableTargetNode). Centralized
 # so the splat path doesn't have to duplicate the InstanceVariable
 # special-cases (module-method-promoted ivar handling).
 # Assign `value_expr` (whose static C type is `value_type`) into the
 # multi-write target node. When the local target's slot is `poly` and
 # the source value isn't already boxed, the value is boxed first so a
 # heterogeneous RHS like `a, b, c = [1, "b", 2.0]` lands in the right
 # tagged-union slots.
  def emit_multi_write_target(tid, value_expr, value_type)
    if @nd_type[tid] == "LocalVariableTargetNode"
      lname = @nd_name[tid]
      vt = find_var_type(lname)
      v = value_expr
      if vt == "poly" && value_type != "" && value_type != "poly"
        v = box_value_to_poly(value_type, value_expr)
      end
 # Reverse direction: poly RHS into a concrete-typed local
 # slot. Happens when destructuring a poly_array element
 # (each slot was sp_PolyArray_get, returning sp_RbVal).
      if value_type == "poly" && vt != "" && vt != "poly"
        v = unbox_poly_to(vt, value_expr)
      end
 # promote-mode-widened slot: wrap an int RHS through
 # sp_bigint_new_int (and unbox the reverse direction).
      if vt == "bigint" && value_type == "int"
        @needs_bigint = 1
        v = "sp_bigint_new_int(" + value_expr + ")"
      end
      if vt == "int" && value_type == "bigint"
        @needs_bigint = 1
        v = "sp_bigint_to_int((sp_Bigint *)" + value_expr + ")"
      end
      emit("  " + fiber_var_ref(lname) + " = " + v + ";")
      return
    end
    if @nd_type[tid] == "InstanceVariableTargetNode"
      iname = @nd_name[tid]
      mod_ivar = 0
      mi3 = 0
      while mi3 < @module_names.length
        mmod = @module_names[mi3]
        if mmod != ""
          if @current_method_name.start_with?(mmod + "_cls_")
            cname3 = mmod + "_" + iname[1, iname.length - 1]
            ci3 = find_const_idx(cname3)
            if ci3 >= 0
              emit("  cst_" + cname3 + " = " + value_expr + ";")
              mod_ivar = 1
            end
          end
        end
        mi3 = mi3 + 1
      end
      if mod_ivar == 0
        v = value_expr
        if @current_class_idx >= 0
          it = cls_ivar_type(@current_class_idx, iname)
          if it == "poly" && value_type != "" && value_type != "poly"
            v = box_value_to_poly(value_type, value_expr)
          end
          if value_type == "poly" && it != "" && it != "poly"
            v = unbox_poly_to(it, value_expr)
          end
          if it == "bigint" && value_type == "int"
            @needs_bigint = 1
            v = "sp_bigint_new_int(" + value_expr + ")"
          end
          if it == "int" && value_type == "bigint"
            @needs_bigint = 1
            v = "sp_bigint_to_int((sp_Bigint *)" + value_expr + ")"
          end
        end
        emit("  " + self_arrow + sanitize_ivar(iname) + " = " + v + ";")
      end
      return
    end
    if @nd_type[tid] == "CallTargetNode"
 # `obj.attr = val` style — used as one slot in a multi-write
 # destructure. Lower as either a direct ivar write (when the
 # receiver class has an attr_writer for the name) or as a call
 # to `sp_<C>_<attr>_eq`.
      recv_id = @nd_receiver[tid]
      mname = @nd_name[tid]
      if mname.end_with?("=")
        mname = mname[0, mname.length - 1]
      end
      recv_t = infer_type(recv_id)
      recv_c = compile_expr(recv_id)
      if recv_t.start_with?("obj_")
        cls_n = recv_t[4, recv_t.length - 4]
        ci_w = find_class_idx(cls_n)
        ve_call_t = value_expr
        if ci_w >= 0
          slot_t_ct = cls_ivar_type(ci_w, "@" + mname)
          if slot_t_ct == "bigint" && value_type == "int"
            @needs_bigint = 1
            ve_call_t = "sp_bigint_new_int(" + value_expr + ")"
          elsif slot_t_ct == "int" && value_type == "bigint"
            @needs_bigint = 1
            ve_call_t = "sp_bigint_to_int((sp_Bigint *)" + value_expr + ")"
          end
        end
        if cls_has_attr_writer(ci_w, mname) == 1
          emit("  " + recv_c + "->iv_" + mname + " = " + ve_call_t + ";")
        else
          emit("  sp_" + cls_n + "_" + mname + "_eq(" + recv_c + ", " + ve_call_t + ");")
        end
      end
    end
    if @nd_type[tid] == "IndexTargetNode"
 # Multi-assign LHS: `a[0], b[1] = 1, 2`. Each LHS is an
 # IndexTargetNode with a receiver and an arguments slot.
 # Routes through the same per-receiver-type sp_<TYPE>_set
 # dispatch as compile_index_op_assign, but without the
 # read-then-modify dance -- the value is supplied by the
 # caller. The temp-receiver pattern keeps `a` and the index
 # evaluated exactly once.
      tgt_recv = @nd_receiver[tid]
      tgt_args_id = @nd_arguments[tid]
      tgt_arg_ids = tgt_args_id >= 0 ? get_args(tgt_args_id) : []
      if tgt_arg_ids.length >= 1
        rt = infer_type(tgt_recv)
        rc = compile_expr_gc_rooted(tgt_recv)
        idx = compile_expr(tgt_arg_ids[0])
 # promote-mode-widened index: unbox to mrb_int for typed-array /
 # int-keyed-hash recv sites that expect an int key.
        idx_int_mt = idx
        if infer_type(tgt_arg_ids[0]) == "bigint"
          @needs_bigint = 1
          idx_int_mt = "sp_bigint_to_int((sp_Bigint *)" + idx + ")"
        end
        if rt == "float_array" || rt == "int_array"
          pfx = array_c_prefix(rt)
          tt = new_temp
          ti = new_temp
          emit("  { sp_" + pfx + " *" + tt + " = " + rc + "; mrb_int " + ti + " = " + idx_int_mt +
               "; sp_" + pfx + "_set(" + tt + ", " + ti + ", (" + value_expr + ")); }")
        end
        if rt == "str_int_hash"
          tt = new_temp
          ti = new_temp
          idx_s = compile_expr_as_string(tgt_arg_ids[0])
          emit("  { sp_StrIntHash *" + tt + " = " + rc + "; const char *" + ti + " = " + idx_s +
               "; sp_StrIntHash_set(" + tt + ", " + ti + ", (" + value_expr + ")); }")
        end
        if rt == "sym_int_hash"
          tt = new_temp
          ti = new_temp
          emit("  { sp_SymIntHash *" + tt + " = " + rc + "; sp_sym " + ti + " = " + idx +
               "; sp_SymIntHash_set(" + tt + ", " + ti + ", (" + value_expr + ")); }")
        end
        if rt == "int_str_hash"
          tt = new_temp
          ti = new_temp
          emit("  { sp_IntStrHash *" + tt + " = " + rc + "; mrb_int " + ti + " = " + idx +
               "; sp_IntStrHash_set(" + tt + ", " + ti + ", (" + value_expr + ")); }")
        end
      end
    end
    if @nd_type[tid] == "GlobalVariableTargetNode"
 # Multi-assign LHS: `$a, $b = 1, 2`. Same storage path as
 # GlobalVariableWriteNode but without an embedded expression --
 # the value is supplied by the caller.
      emit("  " + sanitize_gvar(@nd_name[tid]) + " = " + value_expr + ";")
    end
    if @nd_type[tid] == "MultiTargetNode"
 # Nested LHS: `a, (b, c), d = 1, [2, 3], 4`. The slot of the
 # outer multi-write that this node occupies is an array-typed
 # value; recursively unpack it into the inner targets via
 # per-element index reads.
      compile_nested_multi_target(tid, value_expr, value_type)
    end
  end

 # Handle `a, *b = rhs` / `*a, b = rhs` / `a, *b, c = rhs`.
 # `lefts` are pre-splat targets, `rest_id` is the SplatNode (its
 # expression is the splat target), `rights` are post-splat targets.
  def compile_multi_write_splat(lefts, rest_id, rights, val_id)
    splat_target = @nd_expression[rest_id]
    nleft = lefts.length
    nright = rights.length

 # ArrayNode literal RHS — split statically.
    if @nd_type[val_id] == "ArrayNode"
      elems = parse_id_list(@nd_elements[val_id])
      n = elems.length
 # Evaluate all RHS into temps first (swap-safe).
      tmps = "".split(",", -1)
      ttypes = "".split(",", -1)
      k = 0
      while k < n
        tmp = new_temp
        tmps.push(tmp)
        et = infer_type(elems[k])
        ttypes.push(et)
        emit("  " + c_type(et) + " " + tmp + " = " + compile_expr(elems[k]) + ";")
        k = k + 1
      end
 # Pre-splat targets get the first `nleft` temps.
      k = 0
      while k < nleft
        if k < n
          emit_multi_write_target(lefts[k], tmps[k], ttypes[k])
        end
        k = k + 1
      end
 # Splat target receives a fresh array of the matching element type.
      mid_count = n - nleft - nright
      if mid_count < 0
        mid_count = 0
      end
      st_type = splat_rest_type(val_id)
      st_tmp = new_temp
      @needs_gc = 1
      if st_type == "str_array"
        @needs_str_array = 1
        emit("  sp_StrArray *" + st_tmp + " = sp_StrArray_new();")
        k = 0
        while k < mid_count
          emit("  sp_StrArray_push(" + st_tmp + ", " + tmps[nleft + k] + ");")
          k = k + 1
        end
      elsif st_type == "float_array"
        @needs_float_array = 1
        emit("  sp_FloatArray *" + st_tmp + " = sp_FloatArray_new();")
        k = 0
        while k < mid_count
          emit("  sp_FloatArray_push(" + st_tmp + ", " + tmps[nleft + k] + ");")
          k = k + 1
        end
      elsif is_ptr_array_type(st_type) == 1
        emit("  sp_PtrArray *" + st_tmp + " = sp_PtrArray_new();")
        k = 0
        while k < mid_count
          emit("  sp_PtrArray_push(" + st_tmp + ", " + tmps[nleft + k] + ");")
          k = k + 1
        end
      elsif st_type == "poly_array"
        emit("  sp_PolyArray *" + st_tmp + " = sp_PolyArray_new();")
        k = 0
        while k < mid_count
          boxed = box_value_to_poly(ttypes[nleft + k], tmps[nleft + k])
          emit("  sp_PolyArray_push(" + st_tmp + ", " + boxed + ");")
          k = k + 1
        end
      else
 # int_array / sym_array share IntArray storage via mrb_int
 # reinterpretation at compile time.
        @needs_int_array = 1
        emit("  sp_IntArray *" + st_tmp + " = sp_IntArray_new();")
        k = 0
        while k < mid_count
          emit("  sp_IntArray_push(" + st_tmp + ", (mrb_int)" + tmps[nleft + k] + ");")
          k = k + 1
        end
      end
      emit_multi_write_target(splat_target, st_tmp, st_type)
 # Post-splat targets get the trailing temps.
      k = 0
      while k < nright
        idx = n - nright + k
        if idx >= 0 && idx < n
          emit_multi_write_target(rights[k], tmps[idx], ttypes[idx])
        end
        k = k + 1
      end
      return
    end

 # Generic typed-array RHS — slice at runtime.
    rt = infer_type(val_id)
    @needs_gc = 1
    tmp = new_temp
    emit("  " + c_type(rt) + " " + tmp + " = " + compile_expr(val_id) + ";")
    emit("  SP_GC_ROOT(" + tmp + ");")
    len_tmp = new_temp
    emit("  mrb_int " + len_tmp + " = " + length_c_expr(rt, tmp) + ";")
 # Pre-splat targets. int_array / sym_array share IntArray storage,
 # so they share the default. Other typed arrays need their matching
 # `_get` / `_slice` so the C calls are well-typed.
    get_fn = "sp_IntArray_get"
    slice_fn = "sp_IntArray_slice"
    if rt == "str_array"
      get_fn = "sp_StrArray_get"
      slice_fn = "sp_StrArray_slice"
    end
    if rt == "float_array"
      get_fn = "sp_FloatArray_get"
      slice_fn = "sp_FloatArray_slice"
    end
    if rt == "poly_array"
      get_fn = "sp_PolyArray_get"
      slice_fn = "sp_PolyArray_slice"
    end
    if is_ptr_array_type(rt) == 1
      get_fn = "sp_PtrArray_get"
      slice_fn = "sp_PtrArray_slice"
    end
    elem_t = elem_type_of_array(rt)
    k = 0
    while k < nleft
      emit_multi_write_target(lefts[k], get_fn + "(" + tmp + ", " + k.to_s + ")", elem_t)
      k = k + 1
    end
 # Splat target gets a runtime slice.
    mid_len = len_tmp + " - " + (nleft + nright).to_s
    emit_multi_write_target(splat_target, slice_fn + "(" + tmp + ", " + nleft.to_s + ", " + mid_len + ")", rt)
 # Post-splat targets.
    k = 0
    while k < nright
      offset_expr = len_tmp + " - " + (nright - k).to_s
      emit_multi_write_target(rights[k], get_fn + "(" + tmp + ", " + offset_expr + ")", elem_t)
      k = k + 1
    end
  end

 # Recursively unpack a `MultiTargetNode` slot in a multi-assign.
 # `value_expr` holds the value of this slot (always an array-typed
 # expression, since the source is `a, (b, c), d = ..., [2, 3], ...`).
 # We dispatch on the array's element type and emit per-target
 # index reads.
  def compile_nested_multi_target(tid, value_expr, value_type)
    lefts = parse_id_list(@nd_targets[tid])
    prefix = ""
    elem_t = "int"
    if value_type == "int_array"
      prefix = "IntArray"
      elem_t = "int"
    end
    if value_type == "float_array"
      prefix = "FloatArray"
      elem_t = "float"
    end
    if value_type == "str_array"
      prefix = "StrArray"
      elem_t = "string"
    end
    if value_type == "sym_array"
      prefix = "IntArray"
      elem_t = "sym"
    end
    if prefix == ""
      $stderr.puts "Spinel: MultiTargetNode requires a typed-array RHS slot; got value_type \"" + value_type + "\""
      exit(1)
    end
    @needs_gc = 1
    tmp_arr = new_temp
    emit("  sp_" + prefix + " *" + tmp_arr + " = " + value_expr + ";")
    k = 0
    while k < lefts.length
      inner_val = "sp_" + prefix + "_get(" + tmp_arr + ", " + k.to_s + ")"
      emit_multi_write_target(lefts[k], inner_val, elem_t)
      k = k + 1
    end
  end

  def compile_multi_write(nid)
    targets = parse_id_list(@nd_targets[nid])
    val_id = @nd_expression[nid]
    if val_id < 0
      return
    end
 # `a, b = nil` -- Ruby semantics: every target binds to nil. Pre-
 # fix the codegen fell through to the typed-array destructure path
 # and emitted `sp_IntArray *_t = 0; sp_IntArray_get(_t, 0)` which
 # segfaults on the NULL deref. Issue #705.
    if @nd_type[val_id] == "NilNode"
      k = 0
      while k < targets.length
        tid = targets[k]
        if @nd_type[tid] == "LocalVariableTargetNode"
          emit_multi_write_target(tid, "0", "nil")
        elsif @nd_type[tid] == "InstanceVariableTargetNode"
          emit_multi_write_target(tid, "0", "nil")
        end
        k = k + 1
      end
      return
    end
    rest_id = @nd_rest[nid]
    if is_splat_with_target(rest_id) == 1
      rights = parse_id_list(@nd_rights[nid])
      compile_multi_write_splat(targets, rest_id, rights, val_id)
      return
    end
    if @nd_type[val_id] == "ArrayNode"
 # Direct array literal: a, b, c = [1, 2, 3] or a, b = b, a
      elems = parse_id_list(@nd_elements[val_id])
 # For swap safety, evaluate all RHS first into temps
      tmps = "".split(",", -1)
      ttypes_lit = "".split(",", -1)
      k = 0
      while k < elems.length
        tmp = new_temp
        tmps.push(tmp)
        et = infer_type(elems[k])
        ttypes_lit.push(et)
        emit("  " + c_type(et) + " " + tmp + " = " + compile_expr(elems[k]) + ";")
        k = k + 1
      end
 # Now assign — emit_multi_write_target boxes when target slot is poly.
      k = 0
      while k < targets.length
        if k < tmps.length
          emit_multi_write_target(targets[k], tmps[k], ttypes_lit[k])
        end
        k = k + 1
      end
    elsif is_tuple_type(infer_type(val_id)) == 1
 # RHS is a tuple-returning call — destructure via field access.
 # Route every slot through emit_multi_write_target so ivar /
 # constant / attr-writer / index targets (not just local vars)
 # all get the per-component assignment.
      val_t = infer_type(val_id)
      @needs_gc = 1
      tmp = new_temp
      emit("  " + c_type(val_t) + " " + tmp + " = " + compile_expr(val_id) + ";")
      emit("  SP_GC_ROOT(" + tmp + ");")
      k = 0
      while k < targets.length
        tid = targets[k]
        slot_expr = tmp + "->_" + k.to_s
        slot_type = tuple_elem_type_at(val_t, k)
        emit_multi_write_target(tid, slot_expr, slot_type)
        k = k + 1
      end
    else
 # RHS is a function call returning a typed array. Dispatch by
 # the RHS's static type — IntArray default, PolyArray when the
 # inner is heterogeneous (optcarrots `@io_addr,
 # @bg_pattern_lut_fetched, _ = @attr_lut[i]` where attr_lut
 # elements are 3-tuples of mixed types), and the matching typed-
 # array variants otherwise. Without per-type dispatch a method
 # returning e.g. `[Mat.new, Mat.new]` (typed obj_Mat_ptr_array)
 # destructured via `a, b = self.two_mats` got compiled as
 # `sp_IntArray *_t = sp_N_two_mats(...); sp_IntArray_get(_t, i)`,
 # mismatching the actual sp_PtrArray * return.
      val_t_local = infer_type(val_id)
      @needs_gc = 1
      tmp = new_temp
      if val_t_local == "poly_array"
        @needs_rb_value = 1
        emit("  sp_PolyArray *" + tmp + " = " + compile_expr(val_id) + ";")
      elsif val_t_local == "poly"
 # RHS is a poly value (e.g. `@attr_lut[i]` where @attr_lut
 # is a poly_array of inner arrays — each element is a
 # boxed sp_PolyArray with cls_id POLY_ARRAY). Unbox to
 # sp_PolyArray * and destructure via sp_PolyArray_get.
 # Same shape as the static poly_array branch above.
        @needs_rb_value = 1
        rb_tmp_mw = new_temp
        emit("  sp_RbVal " + rb_tmp_mw + " = " + compile_expr(val_id) + ";")
        emit("  sp_PolyArray *" + tmp + " = (" + rb_tmp_mw + ".cls_id == SP_BUILTIN_POLY_ARRAY) ? (sp_PolyArray *)" + rb_tmp_mw + ".v.p : NULL;")
      elsif val_t_local == "str_array"
        @needs_str_array = 1
        emit("  sp_StrArray *" + tmp + " = " + compile_expr(val_id) + ";")
      elsif val_t_local == "float_array"
        @needs_float_array = 1
        emit("  sp_FloatArray *" + tmp + " = " + compile_expr(val_id) + ";")
      elsif val_t_local == "sym_array"
        emit("  sp_IntArray *" + tmp + " = " + compile_expr(val_id) + ";")
      elsif is_ptr_array_type(val_t_local) == 1
        emit("  sp_PtrArray *" + tmp + " = " + compile_expr(val_id) + ";")
      else
        @needs_int_array = 1
        emit("  sp_IntArray *" + tmp + " = " + compile_expr(val_id) + ";")
      end
      emit("  SP_GC_ROOT(" + tmp + ");")
      k = 0
      while k < targets.length
        tid = targets[k]
        if val_t_local == "poly_array" || val_t_local == "poly"
          rhs = "sp_PolyArray_get(" + tmp + ", " + k.to_s + ")"
          val_t_for_target = "poly"
        elsif val_t_local == "str_array"
          rhs = "sp_StrArray_get(" + tmp + ", " + k.to_s + ")"
          val_t_for_target = "string"
        elsif val_t_local == "float_array"
          rhs = "sp_FloatArray_get(" + tmp + ", " + k.to_s + ")"
          val_t_for_target = "float"
        elsif val_t_local == "sym_array"
          rhs = "((sp_sym)sp_IntArray_get(" + tmp + ", " + k.to_s + "))"
          val_t_for_target = "symbol"
        elsif is_ptr_array_type(val_t_local) == 1
          elem_t = ptr_array_elem_type(val_t_local)
          rhs = "((" + c_type(elem_t) + ")sp_PtrArray_get(" + tmp + ", " + k.to_s + "))"
          val_t_for_target = elem_t
        else
          rhs = "sp_IntArray_get(" + tmp + ", " + k.to_s + ")"
          val_t_for_target = "int"
        end
 # Route ivar / local writes through emit_multi_write_target so
 # the box-when-slot-is-poly logic fires. Without boxing, an int
 # RHS into a sp_RbVal slot fails C compile (`@x, @y = arr` where
 # @y is poly because other writers store other types).
        if @nd_type[tid] == "LocalVariableTargetNode"
          emit_multi_write_target(tid, rhs, val_t_for_target)
        end
        if @nd_type[tid] == "InstanceVariableTargetNode"
          emit_multi_write_target(tid, rhs, val_t_for_target)
        end
        if @nd_type[tid] == "ConstantTargetNode"
          if find_const_idx(@nd_name[tid]) >= 0
            emit("  cst_" + @nd_name[tid] + " = " + rhs + ";")
          end
        end
        if @nd_type[tid] == "CallTargetNode"
 # `obj.attr = <slot>` in a multi-write context.
 # Inline as a direct ivar write when the recv class has an
 # attr_writer; otherwise fall back to the generated setter.
          recv_id = @nd_receiver[tid]
          mname = @nd_name[tid]
          if mname.end_with?("=")
            mname = mname[0, mname.length - 1]
          end
          recv_t = infer_type(recv_id)
          recv_c = compile_expr(recv_id)
          slot_expr = "sp_IntArray_get(" + tmp + ", " + k.to_s + ")"
          if recv_t.start_with?("obj_")
            cls_n = recv_t[4, recv_t.length - 4]
            ci_w = find_class_idx(cls_n)
            if cls_has_attr_writer(ci_w, mname) == 1
              emit("  " + recv_c + "->iv_" + mname + " = " + slot_expr + ";")
            else
              emit("  sp_" + cls_n + "_" + mname + "_eq(" + recv_c + ", " + slot_expr + ");")
            end
          end
        end
        k = k + 1
      end
    end
  end

  def compile_if_stmt(nid)
    cond = compile_cond_expr(@nd_predicate[nid])
 # Static-false fold: a predicate whose static type is `nil`
 # (e.g. an attr_reader for an ivar only ever assigned `nil`)
 # collapses to `if (FALSE) { … }`. The body is unreachable, but
 # its statements still pass through the C compiler — and they
 # often type-error against ivars/methods whose shapes only make
 # sense when the predicate is true. Drop the body entirely; emit
 # the else branch (if any) at the surrounding scope.
    if cond == "FALSE"
      sub_sf = @nd_subsequent[nid]
      if sub_sf >= 0
        if @nd_type[sub_sf] == "ElseNode"
          compile_stmts_body(@nd_body[sub_sf])
        else
          compile_if_stmt(sub_sf)
        end
      end
      return
    end
    if cond == "TRUE"
      compile_stmts_body(@nd_body[nid])
      return
    end
    emit("  if (" + cond + ") {")
    @indent = @indent + 1
 # Mirror compile_cond_return's is_a? narrow push so the then-arm of
 # a non-tail `if x.is_a?(C) ... end` sees `x` as the narrowed type.
 # Without this, a poly-typed `x` flowing into a typed callee
 # (sp_re_escape, sp_re_match_p's string arg, `%s` interpolation,
 # ...) inside the body emits the raw sp_RbVal and trips a C
 # compile -- the #615 shape (volatile locals were a red herring;
 # the actual gap was non-tail-position ifs). The narrow is popped
 # before the else branch and after the body so the else sees the
 # un-narrowed type.
    isa_info_is = parse_is_a_predicate(@nd_predicate[nid])
    isa_pushed_is = 0
    if isa_info_is[0] != ""
      push_type_narrow(isa_info_is[0], isa_info_is[1])
      isa_pushed_is = 1
    end
    compile_stmts_body(@nd_body[nid])
    if isa_pushed_is == 1
      pop_type_narrow
    end
    @indent = @indent - 1
    sub = @nd_subsequent[nid]
    if sub >= 0
      if @nd_type[sub] == "ElseNode"
        emit("  } else {")
        @indent = @indent + 1
        compile_stmts_body(@nd_body[sub])
        @indent = @indent - 1
      else
 # Wrap elsif in braces. compile_cond_expr for the nested
 # predicate may emit prologue C (temp decls, tag checks)
 # before returning the cond expression — e.g.
 # `value.is_a?(B)` on a poly receiver expands to
 # `sp_RbVal _t = ...; if (_t.tag == SP_TAG_OBJ) {...}; if
 # (_flag) ...`. Without the wrap, the `} else <prologue>
 # if (...)` shape is invalid C: the bare-else's body
 # would be the first statement only (the prologue decl),
 # leaving the inner if in the outer scope with the decl
 # out of reach.
        emit("  } else {")
        @indent = @indent + 1
        compile_if_stmt(sub)
        @indent = @indent - 1
        emit("  }")
        return
      end
    end
    emit("  }")
  end

  def compile_unless_stmt(nid)
    cond = compile_cond_expr(@nd_predicate[nid])
 # Symmetric to compile_if_stmt's static-fold: an `unless` whose
 # predicate is statically TRUE drops its body, FALSE drops the
 # else branch.
    if cond == "TRUE"
      ec_sf = @nd_else_clause[nid]
      if ec_sf >= 0
        compile_stmts_body(@nd_body[ec_sf])
      end
      return
    end
    if cond == "FALSE"
      compile_stmts_body(@nd_body[nid])
      return
    end
    emit("  if (!(" + cond + ")) {")
    @indent = @indent + 1
    compile_stmts_body(@nd_body[nid])
    @indent = @indent - 1
    ec = @nd_else_clause[nid]
    if ec >= 0
      emit("  } else {")
      @indent = @indent + 1
      compile_stmts_body(@nd_body[ec])
      @indent = @indent - 1
    end
    emit("  }")
  end

 # C expression for computing length of a value of the given type.
 # Returns "" if the type doesn't have a hoist-friendly length op.
  def length_c_expr(rt, rc)
    if rt == "string"
      return "sp_str_length(" + rc + ")"
    end
    if rt == "int_array" || rt == "sym_array"
      return "sp_IntArray_length(" + rc + ")"
    end
    if rt == "str_array"
      return "sp_StrArray_length(" + rc + ")"
    end
    if rt == "float_array"
      return "sp_FloatArray_length(" + rc + ")"
    end
    if is_ptr_array_type(rt) == 1
      return "sp_PtrArray_length(" + rc + ")"
    end
    if rt == "poly_array"
      return "sp_PolyArray_length(" + rc + ")"
    end
    if rt == "str_int_hash"
      return "sp_StrIntHash_length(" + rc + ")"
    end
    if rt == "str_str_hash"
      return "sp_StrStrHash_length(" + rc + ")"
    end
    if rt == "int_str_hash"
      return "sp_IntStrHash_length(" + rc + ")"
    end
    if rt == "sym_int_hash"
      return "sp_SymIntHash_length((sp_SymIntHash *)(" + rc + "))"
    end
    if rt == "sym_str_hash"
      return "sp_SymStrHash_length((sp_SymStrHash *)(" + rc + "))"
    end
    ""
  end

 # Scan a while-body for any mutation of a local variable (by name).
 # Returns 1 if any mutating method call is found on the receiver
 # (push/pop/shift/unshift/<< / []= / delete / clear / insert /
 # replace / concat). Used to block unsafe hoisting.
  def body_mutates_var?(body_nid, vname)
    if body_nid < 0
      return 0
    end
    t = @nd_type[body_nid]
    if t == "CallNode"
      mn = @nd_name[body_nid]
      recv = @nd_receiver[body_nid]
      if recv >= 0 && @nd_type[recv] == "LocalVariableReadNode" && @nd_name[recv] == vname
        if mn == "push" || mn == "pop" || mn == "shift" || mn == "unshift" ||
           mn == "<<" || mn == "[]=" || mn == "delete" || mn == "delete_at" ||
           mn == "clear" || mn == "insert" || mn == "replace" || mn == "concat" ||
           mn == "sort!" || mn == "reverse!" || mn == "compact!" || mn == "uniq!" ||
           mn == "merge!" || mn == "store" || mn == "update" || mn == "fill"
          return 1
        end
      end
    end
    if (t == "LocalVariableWriteNode" || t == "LocalVariableOperatorWriteNode") && @nd_name[body_nid] == vname
      return 1
    end
 # Recurse into children
    if @nd_expression[body_nid] >= 0
      if body_mutates_var?(@nd_expression[body_nid], vname) == 1
        return 1
      end
    end
    if @nd_body[body_nid] >= 0
      if body_mutates_var?(@nd_body[body_nid], vname) == 1
        return 1
      end
    end
    stmts = parse_id_list(@nd_stmts[body_nid])
    k = 0
    while k < stmts.length
      if body_mutates_var?(stmts[k], vname) == 1
        return 1
      end
      k = k + 1
    end
    if @nd_subsequent[body_nid] >= 0
      if body_mutates_var?(@nd_subsequent[body_nid], vname) == 1
        return 1
      end
    end
    if @nd_receiver[body_nid] >= 0
      if body_mutates_var?(@nd_receiver[body_nid], vname) == 1
        return 1
      end
    end
    args_id = @nd_arguments[body_nid]
    if args_id >= 0
      arr = get_args(args_id)
      k = 0
      while k < arr.length
        if body_mutates_var?(arr[k], vname) == 1
          return 1
        end
        k = k + 1
      end
    end
    0
  end

 # Return the local variable name on which .length/.size is called
 # inside a comparison predicate (for mutation scanning). Empty if
 # the predicate doesn't match the hoist pattern.
  def hoist_receiver_var(pred_nid)
    if @nd_type[pred_nid] != "CallNode"
      return ""
    end
    op = @nd_name[pred_nid]
    if op != "<" && op != "<=" && op != ">" && op != ">="
      return ""
    end
    len_nid = -1
    args_id = @nd_arguments[pred_nid]
    if args_id >= 0
      a = get_args(args_id)
      if a.length > 0
        len_nid = a[0]
      end
    end
    if op == ">" || op == ">="
      len_nid = @nd_receiver[pred_nid]
    end
    if len_nid < 0 || @nd_type[len_nid] != "CallNode"
      return ""
    end
    mn = @nd_name[len_nid]
    if mn != "length" && mn != "size"
      return ""
    end
    recv = @nd_receiver[len_nid]
    if recv < 0 || @nd_type[recv] != "LocalVariableReadNode"
      return ""
    end
    @nd_name[recv]
  end

 # Check if while condition uses .length/.size and hoist if safe.
 # Supports string, arrays, and hashes.
  def try_hoist_strlen(pred_nid)
    if @nd_type[pred_nid] != "CallNode"
      return ""
    end
    op = @nd_name[pred_nid]
    if op != "<" && op != "<=" && op != ">"  && op != ">="
      return ""
    end
 # Find the .length/.size call
    len_nid = -1
    args_id = @nd_arguments[pred_nid]
    if args_id >= 0
      a = get_args(args_id)
      if a.length > 0
        len_nid = a[0]
      end
    end
 # For > or >=, the length call may be on the receiver side
    if op == ">" || op == ">="
      len_nid = @nd_receiver[pred_nid]
    end
    if len_nid < 0
      return ""
    end
    if @nd_type[len_nid] != "CallNode"
      return ""
    end
    mn = @nd_name[len_nid]
    if mn != "length" && mn != "size"
      return ""
    end
    recv = @nd_receiver[len_nid]
    if recv < 0
      return ""
    end
    rt = infer_type(recv)
 # Must be a local variable so we can check for mutations in the body
    if @nd_type[recv] != "LocalVariableReadNode"
 # string literal or ivar: be conservative, only hoist string (already safe)
      if rt != "string"
        return ""
      end
      tmp = new_temp
      rc = compile_expr_gc_rooted(recv)
      emit("  mrb_int " + tmp + " = sp_str_length(" + rc + ");")
      @hoisted_strlen_recv = rc
      return tmp
    end
    len_c = length_c_expr(rt, "")
    if len_c == ""
      return ""
    end
 # Check that the loop body doesn't mutate this variable
    vname = @nd_name[recv]
 # (The pred_nid is the while predicate; body scan happens below via caller
 # passing @while_body_nid. Here we only check if type is hoistable.)
    tmp = new_temp
    rc = compile_expr_gc_rooted(recv)
    emit("  mrb_int " + tmp + " = " + length_c_expr(rt, rc) + ";")
    @hoisted_strlen_recv = rc
    tmp
  end

  def compile_while_stmt(nid)
    old = @in_loop
    @in_loop = 1
 # Save outer hoist state to restore on exit (support nested loops)
    saved_var = @hoisted_strlen_var
    saved_recv = @hoisted_strlen_recv
 # Try to hoist length from condition (string/array/hash). Skip if the
 # loop body mutates the receiver variable (push/pop/<< etc.).
    len_tmp = ""
    can_hoist = 1
    hoist_target = hoist_receiver_var(@nd_predicate[nid])
    if hoist_target != ""
      if body_mutates_var?(@nd_body[nid], hoist_target) == 1
        can_hoist = 0
      end
    end
    if can_hoist == 1
      len_tmp = try_hoist_strlen(@nd_predicate[nid])
      if len_tmp != ""
        @hoisted_strlen_var = len_tmp
      end
    end
 # Prism PM_LOOP_FLAGS_BEGIN_MODIFIER (bit 0): `begin..end while cond`
 # is a post-test (do-while) loop — body runs at least once. Without
 # this, optcarrots `poke_4014` slow-path DMA never runs because
 # `data <<= 8` makes `data & 0xff == 0` initially, so the pre-test
 # while condition is false and the body is skipped.
    if (@nd_flags[nid] & 4) != 0
      emit("  do {")
      @indent = @indent + 1
      redo_label = push_redo_label
      emit_redo_label(redo_label)
      compile_stmts_body(@nd_body[nid])
      pop_redo_label
      @indent = @indent - 1
      cond = compile_cond_expr(@nd_predicate[nid])
      emit("  } while (" + cond + ");")
    else
 # Compile the predicate into a scratch buffer so any side-effecting
 # emits (compile_expr_gc_rooted's `temp = call(); SP_GC_ROOT(temp);`
 # for a CallNode receiver, etc.) land INSIDE the loop body instead
 # of once before it. Issue #500: `while (n = gets.to_i) > 0` hoisted
 # `_t1 = sp_gets(); SP_GC_ROOT(_t1);` ahead of the while, so every
 # iteration re-read the same captured first line and the loop never
 # terminated. Capturing the cond's emits and replaying them inside
 # the loop body — wrapped in `while (1) { ...; if (!cond) break; ... }`
 # — keeps the receiver call (and its transient root) per-iteration,
 # so EOF on stdin actually advances `_t1` and the condition flips.
      saved_out = @out_lines
      @out_lines = "".split(",", -1)
      cond = compile_cond_expr(@nd_predicate[nid])
      cond_hoists = @out_lines
      @out_lines = saved_out
      if cond_hoists.length > 0
        emit("  while (1) {")
        @indent = @indent + 1
        ch_i = 0
        while ch_i < cond_hoists.length
          @out_lines.push(cond_hoists[ch_i])
          ch_i = ch_i + 1
        end
        emit("if (!(" + cond + ")) break;")
        redo_label = push_redo_label
        emit_redo_label(redo_label)
        compile_stmts_body(@nd_body[nid])
        pop_redo_label
        @indent = @indent - 1
        emit("  }")
      else
        emit("  while (" + cond + ") {")
        @indent = @indent + 1
        redo_label = push_redo_label
        emit_redo_label(redo_label)
        compile_stmts_body(@nd_body[nid])
        pop_redo_label
        @indent = @indent - 1
        emit("  }")
      end
    end
    @hoisted_strlen_var = saved_var
    @hoisted_strlen_recv = saved_recv
    @in_loop = old
  end

  def compile_until_stmt(nid)
    old = @in_loop
    @in_loop = 1
    if (@nd_flags[nid] & 4) != 0
      emit("  do {")
      @indent = @indent + 1
      redo_label = push_redo_label
      emit_redo_label(redo_label)
      compile_stmts_body(@nd_body[nid])
      pop_redo_label
      @indent = @indent - 1
      cond = compile_cond_expr(@nd_predicate[nid])
      emit("  } while (!(" + cond + "));")
    else
      cond = compile_cond_expr(@nd_predicate[nid])
      emit("  while (!(" + cond + ")) {")
      @indent = @indent + 1
      redo_label = push_redo_label
      emit_redo_label(redo_label)
      compile_stmts_body(@nd_body[nid])
      pop_redo_label
      @indent = @indent - 1
      emit("  }")
    end
    @in_loop = old
  end

  def compile_for_stmt(nid)
    old = @in_loop
    @in_loop = 1
    coll = @nd_collection[nid]
    if coll >= 0
      vname = "i"
      tgt = @nd_target[nid]
      if tgt >= 0
        if @nd_type[tgt] == "LocalVariableTargetNode"
          vname = @nd_name[tgt]
        end
      end
      slot_t_for = find_var_type(vname)
      if @nd_type[coll] == "RangeNode"
        left = compile_expr(@nd_left[coll])
        right = compile_expr(@nd_right[coll])
        cmp = range_excl_end(coll) == 1 ? "<" : "<="
        if slot_t_for == "bigint"
 # promote-mode-widened loop var: use a fresh mrb_int counter
 # and wrap into the bigint slot at each iteration so the body
 # sees a bigint LV but `++` still works on the C counter.
          @needs_bigint = 1
          ftmp = new_temp
          emit("  for (mrb_int " + ftmp + " = " + left + "; " + ftmp + " " + cmp + " " + right + "; " + ftmp + "++) {")
          emit("    lv_" + vname + " = sp_bigint_new_int(" + ftmp + ");")
        else
          emit("  for (lv_" + vname + " = " + left + "; lv_" + vname + " " + cmp + " " + right + "; lv_" + vname + "++) {")
        end
        @indent = @indent + 1
        redo_label = push_redo_label
        emit_redo_label(redo_label)
        compile_stmts_body(@nd_body[nid])
        pop_redo_label
        @indent = @indent - 1
        emit("  }")
      else
 # for x in array
        ct = infer_type(coll)
        rc = compile_expr(coll)
        tmp = new_temp
        pfx = array_c_prefix(ct)
        emit("  for (mrb_int " + tmp + " = 0; " + tmp + " < sp_" + pfx + "_length(" + rc + "); " + tmp + "++) {")
 # Loop-var assignment stays OUTSIDE the redo label so `redo` re-runs
 # the body with the same value (matches MRI: `redo` does not advance).
        et_for = elem_type_of_array(ct)
        if tgt >= 0 && @nd_type[tgt] == "MultiTargetNode"
 # `for a, b in coll` -- fetch the per-iteration element (always
 # an array-typed value) and unpack into the named targets.
          mt_kids_for = parse_id_list(@nd_targets[tgt])
          inner_pfx = array_c_prefix(et_for)
          etmp = new_temp
          emit("    sp_" + inner_pfx + " *" + etmp + " = sp_" + pfx + "_get(" + rc + ", " + tmp + ");")
          mk = 0
          while mk < mt_kids_for.length
            kid = mt_kids_for[mk]
            if @nd_type[kid] == "LocalVariableTargetNode"
              emit("    lv_" + @nd_name[kid] + " = sp_" + inner_pfx + "_get(" + etmp + ", " + mk.to_s + ");")
            end
            mk = mk + 1
          end
        elsif slot_t_for == "bigint" && et_for == "int"
          @needs_bigint = 1
          emit("    lv_" + vname + " = sp_bigint_new_int(sp_" + pfx + "_get(" + rc + ", " + tmp + "));")
        else
          emit("    lv_" + vname + " = sp_" + pfx + "_get(" + rc + ", " + tmp + ");")
        end

        @indent = @indent + 1
        redo_label = push_redo_label
        emit_redo_label(redo_label)
        compile_stmts_body(@nd_body[nid])
        pop_redo_label
        @indent = @indent - 1
        emit("  }")
      end
    end
    @in_loop = old
  end

  def compile_case_stmt(nid)
    pred = @nd_predicate[nid]
    if pred < 0
      compile_case_no_pred(nid)
      return
    end
    pred_type = infer_type(pred)
    pred_val = compile_expr(pred)
    tmp = new_temp
    if pred_type == "string"
      emit("  const char *" + tmp + " = " + pred_val + ";")
    elsif is_obj_type(pred_type) == 1
 # `case obj when ClassName` — declare the temp at the C type
 # c_type uses for this obj kind. That picks `sp_<X>` for
 # value-type classes (per-class free-list pool) and `sp_<X> *`
 # for the standard pointer representation, so the assignment
 # matches the predicate's actual storage shape.
      emit("  " + c_type(pred_type) + " " + tmp + " = " + pred_val + ";")
    elsif pred_type == "poly"
 # `case <poly_value> when ...` — keep the receiver tagged so
 # each when-arm can do tag-check + value-compare. .
      emit("  sp_RbVal " + tmp + " = " + pred_val + ";")
    elsif pred_type == "range" || pred_type == "time" || pred_type == "float" || pred_type == "bool"
 # Concrete non-int / non-string scrutinees follow the same
 # `c_type(pred_type)` shape: `sp_Range` / `sp_Time` / `mrb_float`
 # / `mrb_bool`. Pre-fix the `mrb_int` fallback below assigned a
 # struct value to an int, tripping the C compiler. Issue #604
 # sibling: a case as a function tail with a Range scrutinee.
      emit("  " + c_type(pred_type) + " " + tmp + " = " + pred_val + ";")
    elsif pred_type == "bigint"
 # promote-mode-widened predicate: keep the temp typed as
 # bigint and unbox to mrb_int for the when comparisons via
 # the compile_when_conds path (which already handles the
 # bigint cmp through sp_bigint_to_int when needed).
      @needs_bigint = 1
      emit("  mrb_int " + tmp + " = sp_bigint_to_int((sp_Bigint *)" + pred_val + ");")
      pred_type = "int"
    else
      emit("  mrb_int " + tmp + " = " + pred_val + ";")
    end
    conds = parse_id_list(@nd_conditions[nid])
    k = 0
    while k < conds.length
      wid = conds[k]
      if @nd_type[wid] == "WhenNode"
        kw = "if"
        if k > 0
          kw = "} else if"
        end
        cond_str = compile_when_conds(wid, tmp, pred_type)
        emit("  " + kw + " (" + cond_str + ") {")
        @indent = @indent + 1
        compile_stmts_body(@nd_body[wid])
        @indent = @indent - 1
      end
      k = k + 1
    end
    ec = @nd_else_clause[nid]
    if ec >= 0
      emit("  } else {")
      @indent = @indent + 1
      compile_stmts_body(@nd_body[ec])
      @indent = @indent - 1
    end
    emit("  }")
  end

  def compile_case_no_pred(nid)
    conds = parse_id_list(@nd_conditions[nid])
    k = 0
    while k < conds.length
      wid = conds[k]
      if @nd_type[wid] == "WhenNode"
        kw = "if"
        if k > 0
          kw = "} else if"
        end
        wconds = parse_id_list(@nd_conditions[wid])
        cexpr = "0"
        if wconds.length > 0
          cexpr = compile_expr(wconds.first)
        end
        emit("  " + kw + " (" + cexpr + ") {")
        @indent = @indent + 1
        compile_stmts_body(@nd_body[wid])
        @indent = @indent - 1
      end
      k = k + 1
    end
    ec = @nd_else_clause[nid]
    if ec >= 0
      emit("  } else {")
      @indent = @indent + 1
      compile_stmts_body(@nd_body[ec])
      @indent = @indent - 1
    end
    emit("  }")
  end

  def compile_when_conds(wid, tmp, pred_type)
    wconds = parse_id_list(@nd_conditions[wid])
    result = ""
    k = 0
    while k < wconds.length
      if k > 0
        result = result + " || "
      end
      cid = wconds[k]
      if @nd_type[cid] == "RangeNode"
        left = compile_expr(@nd_left[cid])
        right = compile_expr(@nd_right[cid])
        cmp = range_excl_end(cid) == 1 ? "<" : "<="
        result = result + "(" + tmp + " >= " + left + " && " + tmp + " " + cmp + " " + right + ")"
      elsif is_obj_type(pred_type) == 1 && (@nd_type[cid] == "ConstantReadNode" || @nd_type[cid] == "ConstantPathNode")
 # `case obj when ClassName` — resolve statically against the
 # predicate's known class. ConstantPathNode (`Mod::Klass`) is
 # routed through resolve_const_ref_name so the walked name
 # matches the class registry. Predicate type `obj_X`:
 # when X (or any ancestor of X) → match (with a NULL guard
 # when the predicate is nullable, since `nil` is not a class
 # instance); anything else → no match. Subclass matching
 # across an `obj_<Parent>` predicate that actually carries an
 # `obj_<Child>` instance needs a runtime cls_id check; covered
 # by the descendant runtime branch in is_a?, separate concern.
        cname = @nd_type[cid] == "ConstantPathNode" ? resolve_const_ref_name(cid) : @nd_name[cid]
        if find_class_idx(cname) >= 0
          bt = base_type(pred_type)
          pred_cname = bt[4, bt.length - 4]
          if is_class_or_ancestor(pred_cname, cname) == 1
            if is_nullable_type(pred_type) == 1
              result = result + tmp + " != NULL"
            else
              result = result + "1"
            end
          else
            result = result + "0"
          end
        else
          result = result + "0"
        end
      else
        if pred_type == "poly"
 # `case <poly> when <lit>` — . The pred_tmp is
 # an sp_RbVal; emit a tag-check + value-compare matched
 # to the literal's type.
          ct = @nd_type[cid]
 # follow-up: `case <poly> when
 # ClassConst` -- Module#=== treats the recv as the class
 # and the arg as the instance, so it's equivalent to
 # `arg.is_a?(recv)`. sp_class_le over the precomputed
 # ancestors handles user classes, modules, and built-ins
 # uniformly through sp_class_for_poly.
          handled_class_when = 0
          if ct == "ConstantReadNode"
            cname_w = @nd_name[cid]
            cuid = unified_cls_id_for_name(cname_w)
            if cuid >= 0
              @needs_class_table = 1
              @needs_class_ancestors = 1
              result = result + "sp_class_le(sp_class_for_poly(" + tmp + "), (sp_Class){" + cuid.to_s + "LL})"
              handled_class_when = 1
            end
          end
          if handled_class_when == 1
 # already appended above; skip literal-arms cascade
          elsif ct == "SymbolNode"
            result = result + "(" + tmp + ".tag == SP_TAG_SYM && " + tmp + ".v.i == " + compile_expr(cid) + ")"
          elsif ct == "StringNode"
            result = result + "(" + tmp + ".tag == SP_TAG_STR && strcmp(" + tmp + ".v.s, " + compile_expr(cid) + ") == 0)"
          elsif ct == "IntegerNode"
            result = result + "(" + tmp + ".tag == SP_TAG_INT && " + tmp + ".v.i == " + compile_expr(cid) + ")"
          elsif ct == "FloatNode"
            result = result + "(" + tmp + ".tag == SP_TAG_FLT && " + tmp + ".v.f == " + compile_expr(cid) + ")"
          elsif ct == "NilNode"
            result = result + "(" + tmp + ".tag == SP_TAG_NIL)"
          elsif ct == "TrueNode"
            result = result + "(" + tmp + ".tag == SP_TAG_BOOL && " + tmp + ".v.b)"
          elsif ct == "FalseNode"
            result = result + "(" + tmp + ".tag == SP_TAG_BOOL && !" + tmp + ".v.b)"
          else
 # Fallback: unbox via sp_poly_eq (does the right thing for
 # numeric / string / sym pairs) and box the rhs.
            @needs_rb_value = 1
            result = result + "sp_poly_eq(" + tmp + ", " + box_expr_to_poly(cid) + ")"
          end
        elsif pred_type == "string"
 # `case <string> when :sym_literal` — CRuby's
 # `:sym === "str"` is always false (Symbol#=== returns
 # false for non-Symbol receivers), so emit a literal
 # 0 for this arm. Without the special-case
 # compile_expr(cid) returns `SPS_<sym>` (an sp_sym aka
 # long long) and strcmp would reject it.
          if @nd_type[cid] == "SymbolNode"
            result = result + "0"
 # `case <string> when ClassConst` — Module#===: matches when
 # the recv is an instance of ClassConst. For a string predicate,
 # only `when String` matches; other built-in class constants
 # never match. Without this branch the generic strcmp arm
 # below tried to compare the sp_Class struct with the string
 # tmp, tripping the C compile.
          elsif @nd_type[cid] == "ConstantReadNode" && not_in(@nd_name[cid], @builtin_class_names) == 0
            result = result + (@nd_name[cid] == "String" ? "1" : "0")
 # Issue #852: `case <string> when /regex/` -- Regexp#=== runs
 # the regex against the receiver. Route through sp_re_match_p.
 # Without this, the generic strcmp arm passed `0` (compile_expr
 # fallback for RegularExpressionNode) and segfaulted.
          elsif @nd_type[cid] == "RegularExpressionNode" || @nd_type[cid] == "InterpolatedRegularExpressionNode"
            rpat_w = regex_pat_c_expr(cid)
            if rpat_w != ""
              @needs_regexp = 1
              result = result + "sp_re_match_p(" + rpat_w + ", " + tmp + ")"
            else
              result = result + "0"
            end
          else
            result = result + "strcmp(" + tmp + ", " + compile_expr(cid) + ") == 0"
          end
        else
 # Symmetric case: `case <sym> when "literal_str"` is
 # also always false in CRuby (String#=== returns false
 # for a Symbol). Emit 0 to avoid a `mrb_int == const
 # char *` type mismatch in the generated C.
          if pred_type == "symbol" && @nd_type[cid] == "StringNode"
            result = result + "0"
 # `case <scalar> when ClassConst` — Module#=== resolution
 # against the predicate's known kind. Matches when the
 # class name corresponds to the predicate's type (Integer
 # for int, Float for float, Symbol for symbol, TrueClass /
 # FalseClass for bool); otherwise no match. Same shape as
 # the string-predicate branch above; without this the
 # generic equality arm would compare an sp_Class struct to
 # an mrb_int / mrb_float / etc.
          elsif @nd_type[cid] == "ConstantReadNode" && not_in(@nd_name[cid], @builtin_class_names) == 0
            cname_w2 = @nd_name[cid]
            matches_pw = 0
            if pred_type == "int"
              if cname_w2 == "Integer" || cname_w2 == "Numeric"
                matches_pw = 1
              end
            elsif pred_type == "float"
              if cname_w2 == "Float" || cname_w2 == "Numeric"
                matches_pw = 1
              end
            elsif pred_type == "symbol"
              if cname_w2 == "Symbol"
                matches_pw = 1
              end
            elsif pred_type == "bool"
              if cname_w2 == "TrueClass" || cname_w2 == "FalseClass"
                matches_pw = 1
              end
            end
            result = result + matches_pw.to_s
          else
            result = result + tmp + " == " + compile_expr(cid)
          end
        end
      end
      k = k + 1
    end
    result
  end

  def compile_case_match_stmt(nid)
    pred = @nd_predicate[nid]
    pred_type = infer_type(pred)
    pred_val = compile_expr(pred)
    tmp = new_temp
 # For typed containers (int_array, sym_array, str_array, hash
 # variants, range, time, user-class obj_*, ...) the temp must be
 # declared with the receiver's actual C type so the pattern arms
 # can dereference `tmp->len` / `tmp->data[i]` and per-variant hash
 # lookups can pass the right pointer type. Without this the temp
 # was declared as `mrb_int` for everything non-poly/string/float
 # and any pattern shape touching the scrutinee structurally
 # crashed at cc time. Primitive shapes (int/bool/symbol/nil) keep
 # the historic `mrb_int` slot.
    if pred_type == "poly"
      emit("  sp_RbVal " + tmp + " = " + pred_val + ";")
    elsif pred_type == "string"
      emit("  const char *" + tmp + " = " + pred_val + ";")
    elsif pred_type == "float"
      emit("  mrb_float " + tmp + " = " + pred_val + ";")
    elsif pred_type == "bigint"
      @needs_bigint = 1
      emit("  mrb_int " + tmp + " = sp_bigint_to_int((sp_Bigint *)" + pred_val + ");")
      pred_type = "int"
    elsif pred_type == "int" || pred_type == "bool" || pred_type == "symbol" || pred_type == "nil" || pred_type == ""
      emit("  mrb_int " + tmp + " = " + pred_val + ";")
    else
      emit("  " + c_type(pred_type) + " " + tmp + " = " + pred_val + ";")
    end
    conds = parse_id_list(@nd_conditions[nid])
 # Track LV names already declared by any preceding ArrayPatternNode
 # arm in this case-match so re-using a name (`in [a, b]` then
 # `in [a, b, c]`) doesn't double-declare the C local.
    declared_arr_pat_lvs = "".split(",", -1)
    k = 0
    while k < conds.length
      inid = conds[k]
      if @nd_type[inid] == "InNode"
        kw = "if"
        if k > 0
          kw = "} else if"
        end
        pat = @nd_pattern[inid]
 # `pat => var` (CapturePatternNode): peel off the capture so the
 # array/hash arm runs as usual, then inject a binding at the
 # top of the matched body. Issue #884.
 # Parser "value" → @nd_expression, "target" → @nd_target.
        capture_var_name = ""
        if @nd_type[pat] == "CapturePatternNode"
          cp_tgt_arm = @nd_target[pat]
          if cp_tgt_arm >= 0 && @nd_type[cp_tgt_arm] == "LocalVariableTargetNode"
            capture_var_name = @nd_name[cp_tgt_arm]
          end
          pat = @nd_expression[pat]
        end
 # Array pattern `[a, b, c]`: declare the bound LVs at the
 # case-match level before any per-arm cond, bind them inline,
 # and gate match on length + per-elem sub-pattern check. Issue #669.
        if @nd_type[pat] == "ArrayPatternNode"
          compile_array_pattern_arm(pat, tmp, pred_type, kw, inid, declared_arr_pat_lvs, capture_var_name)
        elsif @nd_type[pat] == "HashPatternNode"
          compile_hash_pattern_arm(pat, tmp, pred_type, kw, inid, capture_var_name)
        else
          cond_str = compile_in_pattern(pat, tmp, pred_type)
          emit("  " + kw + " (" + cond_str + ") {")
          @indent = @indent + 1
          if capture_var_name != ""
            emit("lv_" + capture_var_name + " = " + tmp + ";")
          end
          compile_stmts_body(@nd_body[inid])
          @indent = @indent - 1
        end
      end
      k = k + 1
    end
    ec = @nd_else_clause[nid]
    if ec >= 0
      emit("  } else {")
      @indent = @indent + 1
      compile_stmts_body(@nd_body[ec])
      @indent = @indent - 1
    end
    if conds.length > 0
      emit("  }")
    end
  end

 # `case x in [a, b, c]` arm. Declares the bound LVs in the case-
 # match's scope, gates the if on length + per-position sub-pattern,
 # binds each LV inline, then compiles the body. Only the
 # LocalVariableTargetNode case (capture) is supported as a leaf;
 # other patterns (literals, pinned, nested) fall back to "0" so the
 # arm doesn't silently match.
  def compile_array_pattern_arm(pat_id, tmp, pred_type, kw, inid, declared_lvs = "".split(",", -1), capture_var = "")
    requireds = parse_id_list(@nd_requireds[pat_id])
 # Pick a get expression and elem c_type based on the scrutinee's
 # static array kind. Fall back to mrb_int for unknown shapes.
    elem_t = "int"
    get_fn = "sp_IntArray_get"
    len_expr = ""
    cast_pref = ""
    if pred_type == "int_array" || pred_type == "sym_array"
      elem_t = "int"
      get_fn = "sp_IntArray_get"
      len_expr = "sp_IntArray_length(" + tmp + ")"
    elsif pred_type == "str_array"
      elem_t = "string"
      get_fn = "sp_StrArray_get"
      len_expr = "sp_StrArray_length(" + tmp + ")"
    elsif pred_type == "float_array"
      elem_t = "float"
      get_fn = "sp_FloatArray_get"
      len_expr = "sp_FloatArray_length(" + tmp + ")"
    elsif pred_type == "poly_array"
      elem_t = "poly"
      get_fn = "sp_PolyArray_get"
      len_expr = "sp_PolyArray_length(" + tmp + ")"
    elsif is_ptr_array_type(pred_type) == 1
      inner_t = ptr_array_elem_type(pred_type)
      elem_t = inner_t
      get_fn = "sp_PtrArray_get"
      len_expr = "sp_PtrArray_length(" + tmp + ")"
      cast_pref = "(" + c_type(inner_t) + ")"
    else
 # Unknown scrutinee shape -- emit a stub arm so the rest of the
 # case-match still type-checks but the body is unreachable.
      emit("  " + kw + " (0) {")
      @indent = @indent + 1
      compile_stmts_body(@nd_body[inid])
      @indent = @indent - 1
      return
    end
    n = requireds.length
 # scan_locals already registered each LocalVariableTargetNode
 # in the surrounding scope's storage (defaults to int). The
 # codegen-side declare_method_locals_from emits the C declaration
 # at function entry. No per-arm emit needed here -- the bind
 # below assigns into the pre-declared slot.
 # Issue #805: when the pattern has a trailing rest (`[a, b, *]`),
 # the length check is `>= requireds` rather than `== requireds`
 # so longer arrays still match.
    rest_id = @nd_rest[pat_id]
    cmp_op = (rest_id >= 0) ? ">=" : "=="
    emit("  " + kw + " (" + len_expr + " " + cmp_op + " " + n.to_s + ") {")
    @indent = @indent + 1
    qi = 0
    while qi < n
      tgt = requireds[qi]
      if @nd_type[tgt] == "LocalVariableTargetNode"
        nm_b = @nd_name[tgt]
 # Box the element when the LV slot was promoted to bigint (promote
 # mode widens scalar int slots). For non-int element types the
 # bind matches the declared slot directly.
        slot_t_b = find_var_type(nm_b)
        get_expr = cast_pref + get_fn + "(" + tmp + ", " + qi.to_s + "LL)"
        if base_type(slot_t_b) == "bigint" && elem_t == "int"
          @needs_bigint = 1
          get_expr = "sp_bigint_new_int(" + get_expr + ")"
        end
        emit("lv_" + nm_b + " = " + get_expr + ";")
      end
      qi = qi + 1
    end
 # `*name` rest (SplatNode with non-nil expression): bind the
 # remaining elements as an array slice. `*` without a name is
 # just a length-flexibility hint with no binding.
    if rest_id >= 0 && @nd_type[rest_id] == "SplatNode"
      rest_expr_id = @nd_expression[rest_id]
      if rest_expr_id >= 0 && @nd_type[rest_expr_id] == "LocalVariableTargetNode"
        rname = @nd_name[rest_expr_id]
        if pred_type == "int_array" || pred_type == "sym_array"
          emit("lv_" + rname + " = sp_IntArray_slice(" + tmp + ", " + n.to_s + "LL, " + len_expr + " - " + n.to_s + "LL);")
        elsif pred_type == "str_array"
          emit("lv_" + rname + " = sp_StrArray_slice(" + tmp + ", " + n.to_s + "LL, " + len_expr + " - " + n.to_s + "LL);")
        elsif pred_type == "float_array"
          emit("lv_" + rname + " = sp_FloatArray_slice(" + tmp + ", " + n.to_s + "LL, " + len_expr + " - " + n.to_s + "LL);")
        elsif pred_type == "poly_array"
          emit("lv_" + rname + " = sp_PolyArray_slice(" + tmp + ", " + n.to_s + "LL, " + len_expr + " - " + n.to_s + "LL);")
        end
      end
    end
 # `[1, *] => arr` capture binding: bind the matched scrutinee to
 # the as-LV at body entry. Issue #884.
    if capture_var != ""
      emit("lv_" + capture_var + " = " + tmp + ";")
    end
    compile_stmts_body(@nd_body[inid])
    @indent = @indent - 1
  end

 # `case h in {a:, b: 2, c:}` -- HashPatternNode. Each AssocNode
 # element pairs a symbol key with either a LocalVariableTargetNode
 # (shorthand `a:` binding) or a sub-pattern (literal match like
 # `b: 2`). The arm matches when every required key is present and,
 # for non-binding entries, the stored value satisfies the sub-
 # pattern. Issue #805.
  def compile_hash_pattern_arm(pat_id, tmp, pred_type, kw, inid, capture_var = "")
    elems = parse_id_list(@nd_elements[pat_id])
    has_key_fn = ""
    get_fn = ""
    key_cast = ""
    val_type = ""
    if pred_type == "sym_int_hash"
      has_key_fn = "sp_SymIntHash_has_key"
      get_fn = "sp_SymIntHash_get"
      val_type = "int"
    elsif pred_type == "sym_str_hash"
      has_key_fn = "sp_SymStrHash_has_key"
      get_fn = "sp_SymStrHash_get"
      val_type = "string"
    elsif pred_type == "sym_poly_hash"
      has_key_fn = "sp_SymPolyHash_has_key"
      get_fn = "sp_SymPolyHash_get"
      val_type = "poly"
    elsif pred_type == "str_int_hash"
      has_key_fn = "sp_StrIntHash_has_key"
      get_fn = "sp_StrIntHash_get"
      val_type = "int"
    elsif pred_type == "str_str_hash"
      has_key_fn = "sp_StrStrHash_has_key"
      get_fn = "sp_StrStrHash_get"
      val_type = "string"
    elsif pred_type == "str_poly_hash"
      has_key_fn = "sp_StrPolyHash_has_key"
      get_fn = "sp_StrPolyHash_get"
      val_type = "poly"
    else
 # Unknown hash variant -- emit a stub arm so the case still
 # type-checks but never fires.
      emit("  " + kw + " (0) {")
      @indent = @indent + 1
      compile_stmts_body(@nd_body[inid])
      @indent = @indent - 1
      return
    end
 # Build the match guard: AND over has_key checks for every required
 # symbol key. Sub-pattern value checks (literals) are appended below.
    conds = "".split(",", -1)
    binds = "".split(",", -1)
    ei = 0
    while ei < elems.length
      asoc = elems[ei]
      if @nd_type[asoc] == "AssocNode"
        kn = @nd_key[asoc]
        if kn >= 0 && @nd_type[kn] == "SymbolNode"
 # SymbolNode's "value" field is routed to @nd_content by the
 # AST loader (see compiler_helpers.rb's set_ref_field "value" arm).
          ksym_name = @nd_content[kn]
          if pred_type[0, 4] == "sym_"
            key_c = "SPS_" + ksym_name
          else
            key_c = "(&(\"\\xff\" \"" + ksym_name + "\")[1])"
          end
          conds.push(has_key_fn + "(" + tmp + ", " + key_c + ")")
 # AssocNode's "value" REF lowers to @nd_expression in the loader
 # (see compiler_helpers.rb's set_ref_field).
          vn = @nd_expression[asoc]
          if vn >= 0 && @nd_type[vn] == "LocalVariableTargetNode"
            binds.push("lv_" + @nd_name[vn] + " = " + get_fn + "(" + tmp + ", " + key_c + ");")
          end
        end
      end
      ei = ei + 1
    end
    cond_expr = "1"
    if conds.length > 0
      cond_expr = conds.join(" && ")
    end
    emit("  " + kw + " (" + cond_expr + ") {")
    @indent = @indent + 1
    bi = 0
    while bi < binds.length
      emit(binds[bi])
      bi = bi + 1
    end
    if capture_var != ""
      emit("lv_" + capture_var + " = " + tmp + ";")
    end
    compile_stmts_body(@nd_body[inid])
    @indent = @indent - 1
  end

  def compile_in_pattern(pat_id, tmp, pred_type)
    if pat_id < 0
      return "1"
    end
    pt = @nd_type[pat_id]
 # Bare local-variable target (`case x in n`): always match, bind
 # lv_n to the scrutinee in the condition itself so the body sees
 # the value. scan_locals already declared the slot. Issue #905.
    if pt == "LocalVariableTargetNode"
      lvname_lt = @nd_name[pat_id]
      return "((lv_" + lvname_lt + " = " + tmp + "), 1)"
    end
 # `pat if guard` -- prism represents this as IfNode wrapping the
 # actual pattern in `statements`. Run the inner pattern's match
 # (which also runs any LV binds via comma-expr), then AND-fold
 # the guard expression. Issue #905. Note: "statements" field
 # is mapped onto @nd_body by compiler_helpers' set_ref_field.
    if pt == "IfNode"
      stmts_if = @nd_body[pat_id]
      inner_pat = -1
      if stmts_if >= 0
        inner_stmts = get_stmts(stmts_if)
        if inner_stmts.length > 0
          inner_pat = inner_stmts[0]
        end
      end
      inner_cond = compile_in_pattern(inner_pat, tmp, pred_type)
      guard_pred = @nd_predicate[pat_id]
      if guard_pred >= 0
        return "((" + inner_cond + ") && (" + compile_expr(guard_pred) + "))"
      end
      return inner_cond
    end
 # `pat => var` capture: recurse for the inner pattern's match,
 # AND-fold the binding side-effect via comma-expr. Issue #884.
 # Parser "value" → @nd_expression, "target" → @nd_target.
    if pt == "CapturePatternNode"
      inner_cp = compile_in_pattern(@nd_expression[pat_id], tmp, pred_type)
      tgt_cp = @nd_target[pat_id]
      if tgt_cp >= 0 && @nd_type[tgt_cp] == "LocalVariableTargetNode"
        lvname_cp = @nd_name[tgt_cp]
        return "((" + inner_cp + ") && ((lv_" + lvname_cp + " = " + tmp + "), 1))"
      end
      return inner_cp
    end
    if pt == "ConstantReadNode"
      cname = @nd_name[pat_id]
      if pred_type == "poly"
        if cname == "Integer"
          return tmp + ".tag == SP_TAG_INT"
        end
        if cname == "String"
          return tmp + ".tag == SP_TAG_STR"
        end
        if cname == "Float"
          return tmp + ".tag == SP_TAG_FLT"
        end
        return "0"
      end
      if cname == "Integer"
        return "1"
      end
      if cname == "String"
        return "1"
      end
      if cname == "Float"
        return "1"
      end
      return "0"
    end
    if pt == "IntegerNode"
      if pred_type == "poly"
        return "(" + tmp + ".tag == SP_TAG_INT && " + tmp + ".v.i == " + @nd_value[pat_id].to_s + ")"
      end
      return "#{tmp} == #{@nd_value[pat_id]}"
    end
    if pt == "StringNode"
      if pred_type == "poly"
        return "(" + tmp + ".tag == SP_TAG_STR && strcmp(" + tmp + ".v.s, " + c_string_literal(@nd_content[pat_id]) + ") == 0)"
      end
      return "strcmp(" + tmp + ", " + c_string_literal(@nd_content[pat_id]) + ") == 0"
    end
    if pt == "NilNode"
      if pred_type == "poly"
        return tmp + ".tag == SP_TAG_NIL"
      end
      return tmp + " == 0"
    end
    if pt == "TrueNode"
      if pred_type == "poly"
        return "(" + tmp + ".tag == SP_TAG_BOOL && " + tmp + ".v.b)"
      end
      return tmp + " != 0"
    end
    if pt == "FalseNode"
      if pred_type == "poly"
        return "(" + tmp + ".tag == SP_TAG_BOOL && !" + tmp + ".v.b)"
      end
      return tmp + " == 0"
    end
    if pt == "SymbolNode"
 # `case sym in :foo` -- literal symbol pattern. Without this arm
 # the dispatch fell through to the trailing "1" fallback and any
 # symbol pattern silently always matched.
      sym_lit = compile_symbol_literal(@nd_content[pat_id])
      if pred_type == "poly"
        return "(" + tmp + ".tag == SP_TAG_SYM && (sp_sym)" + tmp + ".v.i == (" + sym_lit + "))"
      end
      return "(sp_sym)(" + tmp + ") == (" + sym_lit + ")"
    end
    if pt == "FloatNode"
 # `case f in 3.14` -- literal float pattern. Same fallthrough
 # silent-match bug as SymbolNode.
      fval = @nd_value[pat_id]
      if pred_type == "poly"
        return "(" + tmp + ".tag == SP_TAG_FLT && " + tmp + ".v.f == " + fval + ")"
      end
      return tmp + " == " + fval
    end
    if pt == "AlternationPatternNode"
      left = compile_in_pattern(@nd_left[pat_id], tmp, pred_type)
      right = compile_in_pattern(@nd_right[pat_id], tmp, pred_type)
      return "(" + left + " || " + right + ")"
    end
 # PinnedVariableNode / PinnedExpressionNode: `case x in ^var` /
 # `in ^(expr)`. Both share the `@nd_expression` slot -- the parse
 # layer routes the variable into the expression field so codegen
 # treats them uniformly. Match by `==` against the pinned value;
 # poly-tagged scrutinees get both tag and value checks so a pinned
 # Integer doesn't spuriously match against a string with the same
 # underlying byte pattern.
    if pt == "PinnedVariableNode" || pt == "PinnedExpressionNode"
      pinned = compile_expr(@nd_expression[pat_id])
      pinned_type = infer_type(@nd_expression[pat_id])
      if pred_type == "poly"
        if pinned_type == "int"
          return "(" + tmp + ".tag == SP_TAG_INT && " + tmp + ".v.i == (" + pinned + "))"
        end
        if pinned_type == "string"
          return "(" + tmp + ".tag == SP_TAG_STR && strcmp(" + tmp + ".v.s, " + pinned + ") == 0)"
        end
        if pinned_type == "symbol"
          return "(" + tmp + ".tag == SP_TAG_SYM && (sp_sym)" + tmp + ".v.i == (" + pinned + "))"
        end
        if pinned_type == "float"
          return "(" + tmp + ".tag == SP_TAG_FLT && " + tmp + ".v.f == (" + pinned + "))"
        end
        if pinned_type == "bool"
          return "(" + tmp + ".tag == SP_TAG_BOOL && " + tmp + ".v.b == (" + pinned + "))"
        end
        if pinned_type == "nil"
          return tmp + ".tag == SP_TAG_NIL"
        end
        return "0"
      end
      if pinned_type == "string" && pred_type == "string"
        return "strcmp(" + tmp + ", " + pinned + ") == 0"
      end
 # bigint-typed pinned value (`case x in ^bigint_ivar`): compare
 # via sp_bigint_cmp rather than C `==` (which would compare
 # pointer identity, not value equality).
      if base_type(pinned_type) == "bigint"
        @needs_bigint = 1
        if pred_type == "bigint"
          return "(sp_bigint_cmp((sp_Bigint *)" + tmp + ", (sp_Bigint *)" + pinned + ") == 0)"
        end
        return "(sp_bigint_cmp(sp_bigint_new_int(" + tmp + "), (sp_Bigint *)" + pinned + ") == 0)"
      end
      return "(" + tmp + ") == (" + pinned + ")"
    end
    "1"
  end

  def compile_return_stmt(nid)
    args_id = @nd_arguments[nid]
    if args_id >= 0
      arg_ids = get_args(args_id)
      if arg_ids.length > 1
 # `return a, b [, c]` — materialize as a fixed-arity tuple struct.
        @needs_gc = 1
        tt = tuple_type_from_elems(arg_ids)
        tname = tuple_c_name(tt)
        arr_tmp = new_temp
        emit("  " + tname + " *" + arr_tmp + " = (" + tname + " *)sp_gc_alloc(sizeof(" + tname + "), NULL, " + tuple_scan_name(tt) + ");")
        k = 0
        while k < arg_ids.length
          emit("  " + arr_tmp + "->_" + k.to_s + " = " + compile_expr(arg_ids[k]) + ";")
          k = k + 1
        end
 # Replay any in-scope `ensure` bodies before the return.
 # Ruby semantics: return value is already materialized, ensure
 # may mutate locals/ivars but does not affect the saved value.
 # `sp_exc_top -= N` undoes the setjmps we pushed; emit it once
 # before the replays so a nested `return` inside an ensure
 # body doesn't double-pop.
        emit_setjmp_depth_unwind
        emit_ensure_replays
        if @in_gc_scope == 1
          emit("  SP_GC_RESTORE();")
        end
        emit("  return " + arr_tmp + ";")
        return
      end
      if arg_ids.length > 0
 # `pre_return_unwind` = needs `sp_exc_top -= N;` and/or
 # ensure-body replays. When neither, we can leave the
 # original simple `return <expr>;` shape alone.
        pre_return_unwind = 0
        if @ensure_stack.length > 0
          pre_return_unwind = 1
        end
        if @setjmp_depth > 0
          pre_return_unwind = 1
        end
        if @current_method_return == "poly"
          ret_expr = box_expr_to_poly(arg_ids[0])
          if @in_gc_scope == 1
            tmp = new_temp
            emit("  sp_RbVal " + tmp + " = " + ret_expr + ";")
            emit_setjmp_depth_unwind
            emit_ensure_replays
            emit("  SP_GC_RESTORE();")
            emit("  return " + tmp + ";")
          else
            if pre_return_unwind == 1
              tmp = new_temp
              emit("  sp_RbVal " + tmp + " = " + ret_expr + ";")
              emit_setjmp_depth_unwind
              emit_ensure_replays
              emit("  return " + tmp + ";")
            else
              emit("  return " + ret_expr + ";")
            end
          end
          return
        end
        rt = infer_type(arg_ids[0])
 # return nil in a nullable pointer method → return NULL
        if rt == "nil" && is_nullable_pointer_type(@current_method_return) == 1
          emit_setjmp_depth_unwind
          emit_ensure_replays
          if @in_gc_scope == 1
            emit("  SP_GC_RESTORE();")
          end
          emit("  return NULL;")
          return
        end
 # When the function's declared return type is concrete but the
 # value being returned is statically poly (a local declared as
 # sp_RbVal because the param widened, but the surrounding
 # is_a?(C) narrowed it back), route through
 # compile_expr_for_expected_type so the matching .v.<field>
 # unbox happens at the return site. Mirrors the
 # narrow-respecting return-type unify added on the analyze
 # side; without this, the function signature says `const char *`
 # but the emit is `return lv_v;` where lv_v is sp_RbVal.
        ret_val = compile_expr(arg_ids[0])
        ret_ctype = c_type(rt)
        if rt == "poly" && @current_method_return != "poly" && @current_method_return != "void" && @current_method_return != ""
          ret_val = compile_expr_for_expected_type(arg_ids[0], @current_method_return)
          ret_ctype = c_type(@current_method_return)
 # `--int-overflow=promote` widens return slots to bigint; an
 # explicit `return <int_expr>` needs sp_bigint_new_int wrap.
 # Reverse covers callers that still want mrb_int. Use the
 # stale-cache walker so a bigint-emitting arith/bitop chain
 # (`return a | b | c` with bigint operands) doesn't get
 # double-wrapped just because infer_type still reports "int".
        elsif (base_type(@current_method_return) == "bigint" && rt == "int") || (base_type(@current_method_return) == "int" && rt == "bigint")
          rt_eff = rt
          if rt == "int" && expr_emit_is_bigint(arg_ids[0]) == 1
            rt_eff = "bigint"
          end
          ret_val = maybe_bigint_coerce(ret_val, rt_eff, @current_method_return)
          ret_ctype = c_type(@current_method_return)
        end
        if @in_gc_scope == 1
 # Save return value, run ensure replays (which may mutate
 # ivars/locals), restore GC, then return the saved value.
          tmp = new_temp
          emit("  " + ret_ctype + " " + tmp + " = " + ret_val + ";")
          emit_setjmp_depth_unwind
          emit_ensure_replays
          emit("  SP_GC_RESTORE();")
          emit("  return " + tmp + ";")
        else
          if pre_return_unwind == 1
            tmp = new_temp
            emit("  " + ret_ctype + " " + tmp + " = " + ret_val + ";")
            emit_setjmp_depth_unwind
            emit_ensure_replays
            emit("  return " + tmp + ";")
          else
            emit("  return " + ret_val + ";")
          end
        end
        return
      end
    end
 # bare return — emit shape depends on the enclosing function's
 # C return type:
 # void → return;
 # poly → return sp_box_nil(); (boxed nil)
 # obj_<C> → return self; (constructor
 # synthesis path
 # with self in
 # scope)
 # nullable pointer → return NULL;
 # anything else → return 0;
 # The shape per @current_method_return matters because a
 # `return if x.nil?` inside an `sp_RbVal`-returning method
 # would otherwise emit `return 0;` (int) into a poly slot,
 # and the same bare-return inside a `def initialize` reaches
 # the constructor-synthesis branch where `return 0;` would
 # silently NULL the instance.
    emit_setjmp_depth_unwind
    emit_ensure_replays
    if @in_gc_scope == 1
      emit("  SP_GC_RESTORE();")
    end
    if @current_method_return == "void"
      emit("  return;")
    elsif @current_method_return == "poly"
      @needs_rb_value = 1
      emit("  return sp_box_nil();")
    elsif is_obj_type(@current_method_return) == 1
 # `self` is in C scope only when the wrapping function has a
 # self binding — instance methods and constructor synthesis.
 # Class methods, module class methods, and top-level free
 # functions don't have self; their bare returns fall through
 # to `c_return_default` (value-type classes get
 # `(sp_<C>){0}`, pointer-typed obj returns get NULL).
      if @current_method_has_self == 1
        emit("  return self;")
      else
        emit("  return " + c_return_default(@current_method_return) + ";")
      end
    elsif is_nullable_pointer_type(@current_method_return) == 1
      emit("  return NULL;")
    else
      emit("  return 0;")
    end
  end


 # Match the CRuby shapes that resolve to Kernel#trap. Spinel has
 # no signal-handler runtime so all variants compile to a no-op.
  def trap_call_is_signal_stub(nid)
    rcv = @nd_receiver[nid]
    if rcv < 0
      return 1
    end
    rt = @nd_type[rcv]
    if rt == "ConstantReadNode" && @nd_name[rcv] == "Signal"
      return 1
    end
 # `::Signal.trap` parses as ConstantPathNode with parent < 0
 # (toplevel). Reject `Foo::Signal.trap` -- that's a different module.
    if rt == "ConstantPathNode" && @nd_name[rcv] == "Signal" && @nd_receiver[rcv] < 0
      return 1
    end
    0
  end

  def compile_call_stmt(nid)
    mname = @nd_name[nid]
    recv = @nd_receiver[nid]

 # define_method is handled at collection time, skip at runtime
    if mname == "define_method"
      return
    end

 # `Module.accessor = X` write.
 # Write the sentinel for the assigned module class. Both
 # single-candidate and multi-candidate cases need this — the
 # `.nil?` reader compares the slot against 0 to detect
 # un-assigned, so the writer must stamp the sentinel even when
 # the resolver only saw one candidate.
    if mname.length > 1 && mname[mname.length - 1] == "=" && recv >= 0 && @nd_type[recv] == "ConstantReadNode"
      mod_name = @nd_name[recv]
      if module_name_exists(mod_name) == 1
        accessor = mname[0, mname.length - 1]
        rconsts = module_acc_resolved(mod_name, accessor)
        if rconsts != "" && rconsts != "?"
          args_id2 = @nd_arguments[nid]
          if args_id2 >= 0
            ai = get_args(args_id2)
            if ai.length > 0 && @nd_type[ai[0]] == "ConstantReadNode"
              rhs = @nd_name[ai[0]]
              slot = "sp_module_" + mod_name + "_" + sanitize_name(accessor)
              emit("  " + slot + " = " + module_sentinel(rhs).to_s + ";")
              return
            end
          end
        end
 # Non-constant RHS (or poisoned ?): write the poly-slot
 # const synthesized by the analyze-side SingletonClassNode
 # pass. Issue #511.
        if rconsts == "" || rconsts == "?"
          poly_slot = mod_name + "_" + accessor
          if find_const_idx(poly_slot) >= 0
            args_id_w = @nd_arguments[nid]
            if args_id_w >= 0
              ai_w = get_args(args_id_w)
              if ai_w.length > 0
                emit("  cst_" + poly_slot + " = " + box_expr_to_poly(ai_w[0]) + ";")
                return
              end
            end
          end
        end
      end
    end

 # Hoisted instance_eval block (statement context): the lifted
 # function returns void, so emit it as a plain statement.
    if is_ieval_call_name(mname) == 1
      emit("  " + compile_ieval_call(nid) + ";")
      return
    end

 # IO: puts, print, printf
    if compile_io_call_stmt(nid, mname, recv) == 1
      return
    end

 # File.open with block
    if compile_file_open_call_stmt(nid, mname, recv) == 1
      return
    end

 # Mutating operations: []=, delete, <<, replace, clear, push, reverse!, sort!
    if compile_mutating_call_stmt(nid, mname, recv) == 1
      return
    end

 # Block iteration: each, times, upto, downto, loop, reduce, inject, reject
    if compile_block_iteration_stmt(nid, mname, recv) == 1
      return
    end

 # Control flow: raise, system, trap, catch, throw, File ops, exit
    if compile_control_call_stmt(nid, mname, recv) == 1
      return
    end

 # attr_writer, map, select, yield method calls
    if compile_writer_and_block_call_stmt(nid, mname, recv) == 1
      return
    end

 # General
    val = compile_expr(nid)
    if val != "0"
      emit("  " + val + ";")
    end
  end

  def compile_io_call_stmt(nid, mname, recv)
    if mname == "puts"
      if recv < 0
        compile_puts(nid)
        return 1
      end
      if recv >= 0
        if @nd_type[recv] == "GlobalVariableReadNode"
          if @nd_name[recv] == "$stderr"
            compile_stderr_puts(nid)
            return 1
          end
        end
      end
    end
 # $stdout.flush / $stderr.flush / STDOUT.flush / STDERR.flush.
 # Important on Windows where stdio is fully-buffered when stdout
 # is a pipe — without an explicit flush, output written via puts
 # before a `system(...)` call appears after the child process's
 # output. The expression-context system path already flushes open
 # streams implicitly; this lets user code do the same explicitly.
    if mname == "flush" && recv >= 0
      stream = ""
      if @nd_type[recv] == "GlobalVariableReadNode"
        if @nd_name[recv] == "$stdout"
          stream = "stdout"
        elsif @nd_name[recv] == "$stderr"
          stream = "stderr"
        end
      elsif @nd_type[recv] == "ConstantReadNode"
        if @nd_name[recv] == "STDOUT"
          stream = "stdout"
        elsif @nd_name[recv] == "STDERR"
          stream = "stderr"
        end
      end
      if stream != ""
        emit("  fflush(" + stream + ");")
        return 1
      end
    end
    if mname == "print"
      if recv < 0
        compile_print(nid)
        return 1
      end
    end
    if mname == "printf"
      if recv < 0
        compile_printf(nid)
        return 1
      end
    end
 # `warn arg, arg, ...` -- write each arg to stderr followed by a
 # newline (matching Kernel#warn). Issue #734.
    if mname == "warn"
      if recv < 0
        compile_stderr_puts(nid)
        return 1
      end
    end
 # `at_exit { ... }` -- spinel doesn't model atexit hooks; emit
 # nothing and let the block be ignored. A real implementation
 # would push the block onto a static registry called from main's
 # exit path; not worth the runtime plumbing for a generally-
 # uncommon pattern. Issue #734.
    if mname == "at_exit"
      if recv < 0
        return 1
      end
    end
    0
  end

  def compile_file_open_call_stmt(nid, mname, recv)
 # File.open with block
    if mname == "open"
      if recv >= 0
        if @nd_type[recv] == "ConstantReadNode"
          if @nd_name[recv] == "File"
            if @nd_block[nid] >= 0
              args_id = @nd_arguments[nid]
              path_expr = "\"\""
              mode_expr = "\"r\""
              if args_id >= 0
                arg_ids = get_args(args_id)
                if arg_ids.length >= 1
                  path_expr = compile_expr(arg_ids[0])
                end
                if arg_ids.length >= 2
                  mode_expr = compile_expr(arg_ids[1])
                end
              end
              blk = @nd_block[nid]
              bp = get_block_param(nid, 0)
              ftmp = new_temp
              emit("  { FILE *" + ftmp + " = fopen(" + path_expr + ", " + mode_expr + ");")
              emit("  if (" + ftmp + ") {")
 # Compile block body -- f.puts => fprintf, f.each_line => fgets loop
              bbody = @nd_body[blk]
              if bbody >= 0
                bstmts = get_stmts(bbody)
                bk = 0
                while bk < bstmts.length
                  compile_file_block_stmt(bstmts[bk], ftmp, bp)
                  bk = bk + 1
                end
              end
              emit("  fclose(" + ftmp + ");")
              emit("  } }")
              return 1
            end
          end
        end
      end
    end
    0
  end

  def compile_mutating_call_stmt(nid, mname, recv)
 # []=
    if mname == "[]="
      if recv >= 0
 # Fiber[:k] = v / Fiber.current[:k] = v — per-fiber storage write.
 # Lazily allocates the storage Hash on first write (matches MRI's
 # lazy-init for fibers that never touch storage).
        fiber_recv = ""
        if constructor_class_name(recv) == "Fiber"
          @needs_fiber = 1
          fiber_recv = "sp_fiber_current"
        elsif base_type(infer_type(recv)) == "fiber"
          fiber_recv = "(sp_Fiber *)(" + compile_expr_gc_rooted(recv) + ")"
        end
        if fiber_recv != ""
          args_id = @nd_arguments[nid]
          if args_id >= 0
            arg_ids = get_args(args_id)
            if arg_ids.length == 2
              emit("  sp_Fiber_storage_set(" + fiber_recv + ", " + compile_expr(arg_ids[0]) + ", " + box_expr_to_poly(arg_ids[1]) + ");")
              return 1
            end
          end
        end
        compile_bracket_assign(nid)
        return 1
      end
    end

 # store (Hash): equivalent to []=
    if mname == "store"
      if recv >= 0
        rt = infer_type(recv)
        args_id = @nd_arguments[nid]
        if args_id >= 0
          aargs = get_args(args_id)
          if aargs.length >= 2
            rc = compile_expr_gc_rooted(recv)
            val = compile_expr(aargs[1])
            if rt == "sym_int_hash"
              emit("  sp_SymIntHash_set(" + rc + ", " + compile_expr(aargs[0]) + ", " + val + ");")
              return 1
            end
            if rt == "sym_str_hash"
              emit("  sp_SymStrHash_set(" + rc + ", " + compile_expr(aargs[0]) + ", " + val + ");")
              return 1
            end
            if rt == "int_str_hash"
              emit("  sp_IntStrHash_set(" + rc + ", " + compile_expr(aargs[0]) + ", " + val + ");")
              return 1
            end
            key = compile_expr_as_string(aargs[0])
            if rt == "str_int_hash"
              emit("  sp_StrIntHash_set(" + rc + ", " + key + ", " + val + ");")
              return 1
            end
            if rt == "str_str_hash"
              emit("  sp_StrStrHash_set(" + rc + ", " + key + ", " + val + ");")
              return 1
            end
          end
        end
      end
    end

 # delete on built-in containers. Issue #518: the receiver's
 # compile_expr_gc_rooted was previously called UNCONDITIONALLY
 # before the type check, so a non-container receiver (e.g.
 # `M.adapter.delete` where `M.adapter` is a singleton-accessor
 # reader returning a Module) emitted the receiver expression
 # (with its attendant warn_unresolved_call probe) even when
 # none of the hash / array arms matched. Defer the side-effect
 # into each arm so non-matching shapes fall through cleanly to
 # the general dispatch at the bottom of compile_call_stmt.
    if mname == "delete"
      if recv >= 0
        rt = infer_type(recv)
        if rt == "sym_int_hash"
          emit("  sp_SymIntHash_delete(" + compile_expr_gc_rooted(recv) + ", " + compile_arg0(nid) + ");")
          return 1
        end
        if rt == "sym_str_hash"
          emit("  sp_SymStrHash_delete(" + compile_expr_gc_rooted(recv) + ", " + compile_arg0(nid) + ");")
          return 1
        end
        if rt == "str_int_hash"
          emit("  sp_StrIntHash_delete(" + compile_expr_gc_rooted(recv) + ", " + compile_str_arg0(nid) + ");")
          return 1
        end
        if rt == "str_str_hash"
          emit("  sp_StrStrHash_delete(" + compile_expr_gc_rooted(recv) + ", " + compile_str_arg0(nid) + ");")
          return 1
        end
        if rt == "int_array"
          emit("  sp_IntArray_delete(" + compile_expr_gc_rooted(recv) + ", " + compile_arg0(nid) + ");")
          return 1
        end
        if rt == "str_array"
          emit("  sp_StrArray_delete(" + compile_expr_gc_rooted(recv) + ", " + compile_arg0(nid) + ");")
          return 1
        end
      end
    end

 # << on string (mutating append)
    if mname == "<<"
      if recv >= 0
        rt = infer_type(recv)
        if rt == "mutable_str"
          @needs_mutable_str = 1
          rc = compile_expr_gc_rooted(recv)
          arg_id = @nd_arguments[nid]
          if arg_id >= 0
            argl = parse_id_list(@nd_args[arg_id])
            if argl.length > 0
              at = infer_type(argl[0])
              val = compile_expr(argl[0])
              if at == "int"
 # Issue #882: `s << int` appends the UTF-8 character at that
 # codepoint, not the decimal digits. Per MRI String#<<.
                emit("  sp_String_append(" + rc + ", sp_int_codepoint_to_str(" + val + "));")
              elsif at == "bigint"
                @needs_bigint = 1
                emit("  sp_String_append(" + rc + ", sp_bigint_to_s((sp_Bigint *)" + val + "));")
              else
                if at == "mutable_str"
                  emit("  sp_String_append(" + rc + ", " + val + "->data);")
                else
                  if at == "poly"
 # A poly-typed source (e.g. a module method
 # returning sp_RbVal from a SymPolyHash read)
 # needs runtime unbox to const char * before
 # sp_String_append. sp_poly_to_s handles
 # every tag.
                    emit("  sp_String_append(" + rc + ", sp_poly_to_s(" + val + "));")
                  else
                    emit("  sp_String_append(" + rc + ", " + val + ");")
                  end
                end
              end
            end
          end
          return 1
        end
        if rt == "string"
          rc = compile_expr_gc_rooted(recv)
          val = compile_arg0(nid)
 # If receiver is a local variable, reassign
          if @nd_type[recv] == "LocalVariableReadNode"
            emit("  lv_" + @nd_name[recv] + " = sp_str_concat(lv_" + @nd_name[recv] + ", " + val + ");")
            return 1
          end
          if @nd_type[recv] == "InstanceVariableReadNode"
            emit("  " + self_arrow + sanitize_ivar(@nd_name[recv]) + " = sp_str_concat(self->" + sanitize_ivar(@nd_name[recv]) + ", " + val + ");")
            return 1
          end
        end
      end
    end

 # << on array (same as push)
    if mname == "<<"
      if recv >= 0
        rt = infer_type(recv)
        if rt == "int_array" || rt == "sym_array"
          rc = compile_expr_gc_rooted(recv)
          av = compile_arg0(nid)
          a0id = -1
          args_id2 = @nd_arguments[nid]
          if args_id2 >= 0
            aargs2 = get_args(args_id2)
            if aargs2.length > 0
              a0id = aargs2[0]
            end
          end
          if a0id >= 0
            at_iaip = infer_type(a0id)
            if at_iaip == "lambda"
              av = "(mrb_int)" + av
            elsif at_iaip == "bigint" || expr_emit_is_bigint(a0id) == 1
              @needs_bigint = 1
              av = "sp_bigint_to_int((sp_Bigint *)" + av + ")"
            elsif at_iaip == "poly"
              @needs_rb_value = 1
              av = "(" + av + ").v.i"
            end
          end
          emit("  sp_IntArray_push(" + rc + ", " + av + ");")
          return 1
        end
        if rt == "str_array"
          rc = compile_expr_gc_rooted(recv)
          emit("  sp_StrArray_push(" + rc + ", " + compile_arg0(nid) + ");")
          return 1
        end
        if rt == "float_array"
          rc = compile_expr_gc_rooted(recv)
          emit("  sp_FloatArray_push(" + rc + ", " + compile_arg0(nid) + ");")
          return 1
        end
        if is_ptr_array_type(rt) == 1
          rc = compile_expr_gc_rooted(recv)
          emit("  sp_PtrArray_push(" + rc + ", " + compile_arg0(nid) + ");")
          return 1
        end
        if rt == "poly_array"
          rc = compile_expr_gc_rooted(recv)
          args_id3 = @nd_arguments[nid]
          if args_id3 >= 0
            aa = get_args(args_id3)
            if aa.length > 0
              vt = infer_type(aa[0])
              vexpr = compile_expr(aa[0])
              if vt != "poly"
                vexpr = box_value_to_poly(vt, vexpr)
              end
              emit("  sp_PolyArray_push(" + rc + ", " + vexpr + ");")
              return 1
            end
          end
        end
      end
    end

 # update / merge! on hash (mutating merge)
    if mname == "update" || mname == "merge!"
      if recv >= 0
        rt = infer_type(recv)
        if rt == "str_int_hash"
          rc = compile_expr_gc_rooted(recv)
          emit("  sp_StrIntHash_update(" + rc + ", " + compile_arg0(nid) + ");")
          return 1
        end
        if rt == "str_str_hash"
          rc = compile_expr_gc_rooted(recv)
          emit("  sp_StrStrHash_update(" + rc + ", " + compile_arg0(nid) + ");")
          return 1
        end
      end
    end

 # concat on array (mutating append)
    if mname == "concat"
      if recv >= 0
        rt = infer_type(recv)
        if is_array_type(rt) == 1
          rc = compile_expr_gc_rooted(recv)
          pfx = array_c_prefix(rt)
 # Walk every arg. Two prior bugs (issue #548): only the first
 # arg was processed (multi-arg `a.concat(b, c)` silently dropped
 # the tail), and the source-array length was queried inside the
 # loop -- when arg aliased recv (`a.concat(a)`) every push grew
 # the length and the loop never terminated. Snapshot the length
 # before the inner loop so self-concat appends the original
 # contents and stops.
          args_id_cc = @nd_arguments[nid]
          if args_id_cc >= 0
            aargs_cc = get_args(args_id_cc)
            ak_cc = 0
            while ak_cc < aargs_cc.length
              arg_tmp = new_temp
              len_tmp = new_temp
              it_tmp  = new_temp
              emit("  " + c_type(rt) + " " + arg_tmp + " = " + compile_expr(aargs_cc[ak_cc]) + ";")
              emit("  mrb_int " + len_tmp + " = sp_" + pfx + "_length(" + arg_tmp + ");")
              emit("  for (mrb_int " + it_tmp + " = 0; " + it_tmp + " < " + len_tmp + "; " + it_tmp + "++)")
              emit("    sp_" + pfx + "_push(" + rc + ", sp_" + pfx + "_get(" + arg_tmp + ", " + it_tmp + "));")
              ak_cc = ak_cc + 1
            end
          end
          return 1
        end
        if rt == "mutable_str"
          @needs_mutable_str = 1
          rc = compile_expr_gc_rooted(recv)
          args_id = @nd_arguments[nid]
          if args_id >= 0
            aargs = get_args(args_id)
            ak = 0
            while ak < aargs.length
              emit("  sp_String_append(" + rc + ", " + compile_expr(aargs[ak]) + ");")
              ak = ak + 1
            end
          end
          return 1
        end
      end
    end

 # replace on string (mutating reassign)
    if mname == "replace"
      if recv >= 0
        rt = infer_type(recv)
        if rt == "mutable_str"
          rc = compile_expr_gc_rooted(recv)
          val = compile_arg0(nid)
          emit("  " + rc + "->len = 0; " + rc + "->data[0] = 0; sp_String_append(" + rc + ", " + val + ");")
          return 1
        end
        if rt == "string"
          val = compile_arg0(nid)
          if @nd_type[recv] == "LocalVariableReadNode"
            emit("  lv_" + @nd_name[recv] + " = " + val + ";")
            return 1
          end
          if @nd_type[recv] == "InstanceVariableReadNode"
            emit("  " + self_arrow + sanitize_ivar(@nd_name[recv]) + " = " + val + ";")
            return 1
          end
        end
        if rt == "int_array"
          rc = compile_expr_gc_rooted(recv)
          emit("  sp_IntArray_replace(" + rc + ", " + compile_arg0(nid) + ");")
          return 1
        end
        if rt == "sym_array"
          rc = compile_expr_gc_rooted(recv)
          emit("  sp_IntArray_replace(" + rc + ", " + compile_arg0(nid) + ");")
          return 1
        end
        if rt == "str_array"
          rc = compile_expr_gc_rooted(recv)
          emit("  sp_StrArray_replace(" + rc + ", " + compile_arg0(nid) + ");")
          return 1
        end
        if rt == "float_array"
          rc = compile_expr_gc_rooted(recv)
          emit("  sp_FloatArray_replace(" + rc + ", " + compile_arg0(nid) + ");")
          return 1
        end
      end
    end

 # prepend on mutable_str (mutating prepend)
    if mname == "prepend"
      if recv >= 0
        rt = infer_type(recv)
        if rt == "mutable_str"
          @needs_mutable_str = 1
          rc = compile_expr_gc_rooted(recv)
          val = compile_arg0(nid)
          emit("  sp_String_prepend(" + rc + ", " + val + ");")
          return 1
        end
      end
    end

 # clear on string (set to empty)
    if mname == "clear"
      if recv >= 0
        rt = infer_type(recv)
        if rt == "mutable_str"
          rc = compile_expr_gc_rooted(recv)
          emit("  " + rc + "->len = 0; " + rc + "->data[0] = 0;")
          return 1
        end
        if rt == "string"
          if @nd_type[recv] == "LocalVariableReadNode"
            emit("  lv_" + @nd_name[recv] + " = \"\";")
            return 1
          end
          if @nd_type[recv] == "InstanceVariableReadNode"
            emit("  " + self_arrow + sanitize_ivar(@nd_name[recv]) + " = \"\";")
            return 1
          end
        end
 # Typed array Array#clear — zero the length (and start
 # for IntArray, which uses a sliding window). Capacity
 # and the backing buffer stay; subsequent pushes refill
 # the slots from index 0.
        if rt == "int_array" || rt == "sym_array"
          rc = compile_expr_gc_rooted(recv)
          emit("  " + rc + "->len = 0; " + rc + "->start = 0;")
          return 1
        end
        if rt == "float_array" || rt == "poly_array" || is_ptr_array_type(rt) == 1
          rc = compile_expr_gc_rooted(recv)
          emit("  " + rc + "->len = 0;")
          return 1
        end
        if rt == "str_array"
          rc = compile_expr_gc_rooted(recv)
 # StrArray has an inline-storage optimization: data may
 # point to inline_data (small) or a malloc'd buffer.
 # Either way, zeroing len is a clean reset — the next
 # push refills from index 0.
          emit("  " + rc + "->len = 0;")
          return 1
        end
      end
    end

 # push
    if mname == "push"
      if recv >= 0
        rt = infer_type(recv)
        if rt == "int_array" || rt == "sym_array"
          rc = compile_expr_gc_rooted(recv)
          av = compile_arg0(nid)
 # If pushing a lambda value, cast to mrb_int. With promote
 # mode, an int_array.push(bigint_lv) sees a sp_Bigint * arg
 # against an mrb_int param — unbox.
          a0id = -1
          args_id2 = @nd_arguments[nid]
          if args_id2 >= 0
            aargs2 = get_args(args_id2)
            if aargs2.length > 0
              a0id = aargs2[0]
            end
          end
          if a0id >= 0
            at_iaip = infer_type(a0id)
            if at_iaip == "lambda"
              av = "(mrb_int)" + av
            elsif at_iaip == "bigint" || expr_emit_is_bigint(a0id) == 1
              @needs_bigint = 1
              av = "sp_bigint_to_int((sp_Bigint *)" + av + ")"
            elsif at_iaip == "poly"
              @needs_rb_value = 1
              av = "(" + av + ").v.i"
            end
          end
          emit("  sp_IntArray_push(" + rc + ", " + av + ");")
          return 1
        end
        if rt == "str_array"
          rc = compile_expr_gc_rooted(recv)
          emit("  sp_StrArray_push(" + rc + ", " + compile_arg0(nid) + ");")
          return 1
        end
        if rt == "float_array"
          rc = compile_expr_gc_rooted(recv)
          emit("  sp_FloatArray_push(" + rc + ", " + compile_arg0(nid) + ");")
          return 1
        end
        if is_ptr_array_type(rt) == 1
          rc = compile_expr_gc_rooted(recv)
          emit("  sp_PtrArray_push(" + rc + ", " + compile_arg0(nid) + ");")
          return 1
        end
      end
    end

 # rotate!(n) — defaults to n=1 like Ruby.
    if mname == "rotate!"
      if recv >= 0
        rt = infer_type(recv)
        rot_pfx = ""
        if rt == "int_array" || rt == "sym_array"
          rot_pfx = "IntArray"
        end
        if rt == "float_array"
          rot_pfx = "FloatArray"
        end
        if rt == "str_array"
          rot_pfx = "StrArray"
        end
        if is_ptr_array_type(rt) == 1
          rot_pfx = "PtrArray"
        end
        if rt == "poly_array"
          rot_pfx = "PolyArray"
        end
        if rot_pfx != ""
          args_id = @nd_arguments[nid]
          n_expr = "1"
          if args_id >= 0
            aargs = get_args(args_id)
            if aargs.length > 0
              n_expr = compile_expr(aargs[0])
            end
          end
          rc = compile_expr_gc_rooted(recv)
          emit("  sp_" + rot_pfx + "_rotate_bang(" + rc + ", " + n_expr + ");")
          return 1
        end
      end
    end

 # reverse! / sort!
    if mname == "reverse!"
      if recv >= 0
        rt = infer_type(recv)
        rev_pfx = ""
        if rt == "int_array" || rt == "sym_array"
          rev_pfx = "IntArray"
        end
        if rt == "str_array"
          rev_pfx = "StrArray"
        end
        if rt == "float_array"
          rev_pfx = "FloatArray"
        end
        if is_ptr_array_type(rt) == 1
          rev_pfx = "PtrArray"
        end
        if rev_pfx != ""
          rc = compile_expr_gc_rooted(recv)
          emit("  sp_" + rev_pfx + "_reverse_bang(" + rc + ");")
          return 1
        end
      end
    end
    if mname == "sort!"
      if recv >= 0
        rt = infer_type(recv)
        if rt == "int_array"
          rc = compile_expr_gc_rooted(recv)
          emit("  sp_IntArray_sort_bang(" + rc + ");")
          return 1
        end
        if rt == "sym_array"
 # sym sort compares by symbol name, not numeric ID
          rc = compile_expr_gc_rooted(recv)
          emit("  sp_sym_array_sort(" + rc + ");")
          return 1
        end
        if rt == "str_array"
          rc = compile_expr_gc_rooted(recv)
          emit("  sp_StrArray_sort_bang(" + rc + ");")
          return 1
        end
        if rt == "float_array"
          rc = compile_expr_gc_rooted(recv)
          emit("  sp_FloatArray_sort_bang(" + rc + ");")
          return 1
        end
      end
    end
    0
  end

  def compile_block_iteration_stmt(nid, mname, recv)
 # each with block
    if mname == "each" || mname == "each_entry" || (mname == "each_pair" && recv >= 0)
      if @nd_block[nid] >= 0
 # For object types with yield-using each, use yield method call
        if recv >= 0
          ert = infer_type(recv)
          if is_obj_type(ert) == 1 && is_ptr_array_type(ert) == 0
 # Fall through to yield method handler below
          else
            compile_each_block(nid)
            return 1
          end
        else
          compile_each_block(nid)
          return 1
        end
      end
    end

 # Hash#delete_if / #select! / #reject! on typed hashes —
 # walk the hash, evaluate block on each (k, v), collect keys
 # to drop, then delete in a second pass (modify-during-iter is
 # not safe with the open-addressing layout). select! inverts
 # the predicate (keep iff true).
    if (mname == "delete_if" || mname == "reject!" || mname == "select!") && @nd_block[nid] >= 0 && recv >= 0
      rt_dh = infer_type(recv)
      pfx_dh = ""
      key_ty_dh = ""
      val_ty_dh = ""
      key_arr_pfx = "IntArray" # default sym ids stored in int array
      if rt_dh == "sym_int_hash"
        pfx_dh = "SymIntHash"; key_ty_dh = "symbol"; val_ty_dh = "int"
      elsif rt_dh == "str_int_hash"
        pfx_dh = "StrIntHash"; key_ty_dh = "string"; val_ty_dh = "int"; key_arr_pfx = "StrArray"
      end
      if pfx_dh != ""
        old_dh = @in_loop
        @in_loop = 1
        rc_dh = compile_expr_gc_rooted(recv)
        bp_k = get_block_param(nid, 0)
        bp_k = "_k" if bp_k == ""
        bp_v = get_block_param(nid, 1)
        bp_v = "_v" if bp_v == ""
        rm_arr = new_temp
        idx_dh = new_temp
        @needs_int_array = 1
        @needs_str_array = 1 if key_arr_pfx == "StrArray"
        @needs_gc = 1
        emit("  sp_" + key_arr_pfx + " *" + rm_arr + " = sp_" + key_arr_pfx + "_new();")
        emit("  SP_GC_ROOT(" + rm_arr + ");")
        emit("  for (mrb_int " + idx_dh + " = 0; " + idx_dh + " < " + rc_dh + "->len; " + idx_dh + "++) {")
        key_c_decl = (key_ty_dh == "symbol") ? "sp_sym" : "const char *"
        emit("    " + key_c_decl + " lv_" + bp_k + " = " + rc_dh + "->order[" + idx_dh + "];")
        emit("    mrb_int lv_" + bp_v + " = sp_" + pfx_dh + "_get(" + rc_dh + ", lv_" + bp_k + ");")
        @indent = @indent + 1
        push_scope
        declare_var(bp_k, key_ty_dh)
        declare_var(bp_v, val_ty_dh)
        bbody_dh = @nd_body[@nd_block[nid]]
        bexpr_dh = "FALSE"
        if bbody_dh >= 0
          bs_dh = get_stmts(bbody_dh)
          kk = 0
          while kk < bs_dh.length - 1
            compile_stmt(bs_dh[kk])
            kk = kk + 1
          end
          if bs_dh.length > 0
            bexpr_dh = compile_expr(bs_dh.last)
          end
        end
        cond_dh = (mname == "select!") ? "!(" + bexpr_dh + ")" : "(" + bexpr_dh + ")"
        push_arg = (key_ty_dh == "symbol") ? "(mrb_int)lv_" + bp_k : "lv_" + bp_k
        emit("    if (" + cond_dh + ") sp_" + key_arr_pfx + "_push(" + rm_arr + ", " + push_arg + ");")
        pop_scope
        @indent = @indent - 1
        emit("  }")
        rm_idx_dh = new_temp
        get_call = (key_ty_dh == "symbol") ? "(sp_sym)sp_IntArray_get(" + rm_arr + ", " + rm_idx_dh + ")" : "sp_StrArray_get(" + rm_arr + ", " + rm_idx_dh + ")"
        emit("  for (mrb_int " + rm_idx_dh + " = 0; " + rm_idx_dh + " < " + rm_arr + "->len; " + rm_idx_dh + "++) {")
        emit("    sp_" + pfx_dh + "_delete(" + rc_dh + ", " + get_call + ");")
        emit("  }")
        @in_loop = old_dh
        return 1
      end
    end

 # `arr.combination(k) { |c| ... }` on int_array — call the
 # blockless helper to materialise all combinations, then loop
 # them and bind each sub-array to the block param.
    if mname == "combination" && @nd_block[nid] >= 0 && recv >= 0
      rt_co = infer_type(recv)
      if rt_co == "int_array"
        old_co = @in_loop
        @in_loop = 1
        rc_co = compile_expr_gc_rooted(recv)
        bp_co = get_block_param(nid, 0)
        bp_co = "_c" if bp_co == ""
        @needs_int_array = 1
        @needs_gc = 1
        combos_co = new_temp
        iter_co = new_temp
        emit("  sp_PtrArray *" + combos_co + " = sp_IntArray_combination(" + rc_co + ", " + compile_arg0_as_int(nid) + ");")
        emit("  SP_GC_ROOT(" + combos_co + ");")
        emit("  for (mrb_int " + iter_co + " = 0; " + iter_co + " < " + combos_co + "->len; " + iter_co + "++) {")
        emit("    sp_IntArray * lv_" + bp_co + " = (sp_IntArray *)" + combos_co + "->data[" + iter_co + "];")
        @indent = @indent + 1
        push_scope
        declare_var(bp_co, "int_array")
        compile_stmts_body(@nd_body[@nd_block[nid]])
        pop_scope
        @indent = @indent - 1
        emit("  }")
        @in_loop = old_co
        return 1
      end
    end

 # `reverse_each` on a typed array: walk indices backwards.
    if mname == "reverse_each" && @nd_block[nid] >= 0 && recv >= 0
      rt_re = infer_type(recv)
      pfx_re = ""
      ety_re = ""
      if rt_re == "int_array"
        pfx_re = "IntArray"; ety_re = "int"
      elsif rt_re == "str_array"
        pfx_re = "StrArray"; ety_re = "string"
      elsif rt_re == "float_array"
        pfx_re = "FloatArray"; ety_re = "float"
      elsif rt_re == "sym_array"
        pfx_re = "SymArray"; ety_re = "symbol"
        rt_re = "int_array"; pfx_re = "IntArray" # sym storage shares IntArray
      end
      if pfx_re != ""
        old_re = @in_loop
        @in_loop = 1
        rc_re = compile_expr_gc_rooted(recv)
        bp_re = get_block_param(nid, 0)
        bp_re = "_x" if bp_re == ""
        tmp_re = new_temp
        emit("  for (mrb_int " + tmp_re + " = sp_" + pfx_re + "_length(" + rc_re + ") - 1; " + tmp_re + " >= 0; " + tmp_re + "--) {")
        emit("    " + c_type(ety_re) + " lv_" + bp_re + " = sp_" + pfx_re + "_get(" + rc_re + ", " + tmp_re + ");")
        @indent = @indent + 1
        push_scope
        declare_var(bp_re, ety_re)
        compile_stmts_body(@nd_body[@nd_block[nid]])
        pop_scope
        @indent = @indent - 1
        emit("  }")
        @in_loop = old_re
        return 1
      end
    end

    if mname == "each_with_index"
      if @nd_block[nid] >= 0
        compile_each_with_index_block(nid)
        return 1
      end
    end

 # `hash.each_value { |v| ... }` for poly_poly_hash. Other hash
 # shapes can be added here once they surface; the underlying
 # representation is the same `vals[order[i]]` walk.
    if mname == "each_value" && recv >= 0 && @nd_block[nid] >= 0
      rt_ev = infer_type(recv)
      if rt_ev == "poly_poly_hash"
        rc_ev = compile_expr_gc_rooted(recv)
        bp_ev = get_block_param(nid, 0)
        has_bp_ev = 1
        if bp_ev == ""
          has_bp_ev = 0
          bp_ev = "_v"
        end
        tmp_ev = new_temp
        emit("  for (mrb_int " + tmp_ev + " = 0; " + tmp_ev + " < " + rc_ev + "->len; " + tmp_ev + "++) {")
        if has_bp_ev == 1
          emit("    sp_RbVal lv_" + bp_ev + " = " + rc_ev + "->vals[" + rc_ev + "->order[" + tmp_ev + "]];")
        end
        @indent = @indent + 1
        push_scope
        if has_bp_ev == 1
          declare_var(bp_ev, "poly")
        end
        redo_label_ev = push_redo_label
        emit_redo_label(redo_label_ev)
        compile_stmts_body(@nd_body[@nd_block[nid]])
        pop_redo_label
        pop_scope
        @indent = @indent - 1
        emit("  }")
        return 1
      end
 # Issue #851: each_value on the common typed-hash variants.
 # The shape is the same: walk h->order[i] and dispatch the
 # variant's _get. Only int and string value parts here; the
 # poly variants flow through the poly_poly_hash arm above
 # already after boxing.
      pfx_ev = ""
      vty_ev = ""
      vtag_ev = ""
      if rt_ev == "sym_int_hash"
        pfx_ev = "SymIntHash"; vty_ev = "mrb_int"; vtag_ev = "int"
        @needs_sym_int_hash = 1
      elsif rt_ev == "str_int_hash"
        pfx_ev = "StrIntHash"; vty_ev = "mrb_int"; vtag_ev = "int"
        @needs_str_int_hash = 1
      elsif rt_ev == "int_str_hash"
        pfx_ev = "IntStrHash"; vty_ev = "const char *"; vtag_ev = "string"
      elsif rt_ev == "str_str_hash"
        pfx_ev = "StrStrHash"; vty_ev = "const char *"; vtag_ev = "string"
      elsif rt_ev == "sym_str_hash"
        pfx_ev = "SymStrHash"; vty_ev = "const char *"; vtag_ev = "string"
      end
      if pfx_ev != ""
        rc_ev2 = compile_expr_gc_rooted(recv)
        bp_ev2 = get_block_param(nid, 0)
        if bp_ev2 == ""
          bp_ev2 = "_v"
        end
        tmp_ev2 = new_temp
        emit("  for (mrb_int " + tmp_ev2 + " = 0; " + tmp_ev2 + " < " + rc_ev2 + "->len; " + tmp_ev2 + "++) {")
        emit("    " + vty_ev + " lv_" + bp_ev2 + " = sp_" + pfx_ev + "_get(" + rc_ev2 + ", " + rc_ev2 + "->order[" + tmp_ev2 + "]);")
        @indent = @indent + 1
        push_scope
        declare_var(bp_ev2, vtag_ev)
        compile_stmts_body(@nd_body[@nd_block[nid]])
        pop_scope
        @indent = @indent - 1
        emit("  }")
        return 1
      end
    end

    if mname == "each_slice"
      if @nd_block[nid] >= 0
        compile_each_slice_block(nid)
        return 1
      end
    end

    if mname == "each_char"
      if @nd_block[nid] >= 0 && recv >= 0
        rt = infer_type(recv)
        if rt == "string" || rt == "mutable_str"
          rc = compile_expr_gc_rooted(recv)
          bp = get_block_param(nid, 0)
          if bp == ""
            bp = "_c"
          end
          tmp = new_temp
          src = rc
          if rt == "mutable_str"
            src = rc + "->data"
          end
          src_tmp = new_temp
          cn_tmp = new_temp
          char_buf = new_temp
          emit("  const char *" + src_tmp + " = " + src + ";")
          emit("  for (mrb_int " + tmp + " = 0; " + src_tmp + "[" + tmp + "]; ) {")
          emit("    int " + cn_tmp + " = sp_utf8_advance(" + src_tmp + " + " + tmp + ");")
          emit("    char *" + char_buf + " = sp_str_alloc_raw(" + cn_tmp + " + 1);")
          emit("    memcpy(" + char_buf + ", " + src_tmp + " + " + tmp + ", " + cn_tmp + ");")
          emit("    " + char_buf + "[" + cn_tmp + "] = 0;")
          emit("    const char *lv_" + bp + " = " + char_buf + ";")
          @indent = @indent + 1
          push_scope
          declare_var(bp, "string")
          compile_stmts_body(@nd_body[@nd_block[nid]])
          pop_scope
          @indent = @indent - 1
          emit("    " + tmp + " += " + cn_tmp + ";")
          emit("  }")
          return 1
        end
      end
    end

    if mname == "each_byte"
      if @nd_block[nid] >= 0 && recv >= 0
        rt = infer_type(recv)
        if rt == "string" || rt == "mutable_str"
          rc = compile_expr_gc_rooted(recv)
          bp = get_block_param(nid, 0)
          if bp == ""
            bp = "_b"
          end
          tmp = new_temp
          src = rc
          if rt == "mutable_str"
            src = rc + "->data"
          end
          src_tmp = new_temp
          emit("  const char *" + src_tmp + " = " + src + ";")
          emit("  for (mrb_int " + tmp + " = 0; " + src_tmp + "[" + tmp + "]; " + tmp + "++) {")
          emit("    mrb_int lv_" + bp + " = (unsigned char)" + src_tmp + "[" + tmp + "];")
          @indent = @indent + 1
          push_scope
          declare_var(bp, "int")
          compile_stmts_body(@nd_body[@nd_block[nid]])
          pop_scope
          @indent = @indent - 1
          emit("  }")
          return 1
        end
      end
    end

    if mname == "each_line"
      if @nd_block[nid] >= 0 && recv >= 0
        rt = infer_type(recv)
        if rt == "string" || rt == "mutable_str"
          rc = compile_expr_gc_rooted(recv)
          bp = get_block_param(nid, 0)
          if bp == ""
            bp = "_l"
          end
          src_el = rc
          if rt == "mutable_str"
            src_el = rc + "->data"
          end
          base_el = new_temp
          start_el = new_temp
          pos_el = new_temp
          slen_el = new_temp
          buf_el = new_temp
          llen_el = new_temp
          emit("  const char *" + base_el + " = " + src_el + ";")
          emit("  mrb_int " + slen_el + " = sp_str_length(" + base_el + ");")
          emit("  mrb_int " + start_el + " = 0;")
          emit("  mrb_int " + pos_el + " = 0;")
          emit("  while (" + start_el + " < " + slen_el + ") {")
          emit("    while (" + pos_el + " < " + slen_el + " && " + base_el + "[" + pos_el + "] != '\\n') " + pos_el + "++;")
          emit("    if (" + pos_el + " < " + slen_el + ") " + pos_el + "++;")
          emit("    mrb_int " + llen_el + " = " + pos_el + " - " + start_el + ";")
          emit("    char *" + buf_el + " = sp_str_alloc(" + llen_el + ");")
          emit("    memcpy(" + buf_el + ", " + base_el + " + " + start_el + ", " + llen_el + ");")
          emit("    " + buf_el + "[" + llen_el + "] = 0;")
          emit("    const char *lv_" + bp + " = " + buf_el + ";")
          @indent = @indent + 1
          push_scope
          declare_var(bp, "string")
          compile_stmts_body(@nd_body[@nd_block[nid]])
          pop_scope
          @indent = @indent - 1
          emit("    " + start_el + " = " + pos_el + ";")
          emit("  }")
          return 1
        end
      end
    end

    if mname == "each_cons"
      if @nd_block[nid] >= 0
        compile_each_cons_block(nid)
        return 1
      end
    end

    if mname == "each_with_object"
      if @nd_block[nid] >= 0 && recv >= 0
        compile_each_with_object_block(nid)
        return 1
      end
    end

    if mname == "zip"
      if @nd_block[nid] >= 0 && recv >= 0
        old = @in_loop
        @in_loop = 1
        rt = infer_type(recv)
        rc = compile_expr_gc_rooted(recv)
        arg = compile_arg0(nid)
        bp1 = get_block_param(nid, 0)
        bp2 = get_block_param(nid, 1)
        if bp1 == ""
          bp1 = "_a"
        end
        if bp2 == ""
          bp2 = "_b"
        end
        pfx = array_c_prefix(rt)
        elem_t = elem_type_of_array(rt)
        et = c_type(elem_t)
        tmp_i = new_temp
        emit("  for (mrb_int " + tmp_i + " = 0; " + tmp_i + " < sp_" + pfx + "_length(" + rc + "); " + tmp_i + "++) {")
        emit("    " + et + " lv_" + bp1 + " = sp_" + pfx + "_get(" + rc + ", " + tmp_i + ");")
        emit("    " + et + " lv_" + bp2 + " = sp_" + pfx + "_get(" + arg + ", " + tmp_i + ");")
        @indent = @indent + 1
        push_scope
        declare_var(bp1, elem_t)
        declare_var(bp2, elem_t)
        redo_label = push_redo_label
        emit_redo_label(redo_label)
        compile_stmts_body(@nd_body[@nd_block[nid]])
        pop_redo_label
        pop_scope
        @indent = @indent - 1
        emit("  }")
        @in_loop = old
        return 1
      end
    end

    if mname == "step"
      if @nd_block[nid] >= 0 && recv >= 0
        old = @in_loop
        @in_loop = 1
        recv_t_step = infer_type(recv)
        rc = compile_expr_gc_rooted(recv)
        args_id = @nd_arguments[nid]
        limit_val = "0"
        step_val = "1"
        if args_id >= 0
          aargs = get_args(args_id)
          if aargs.length > 0
            limit_val = compile_expr(aargs[0])
          end
          if aargs.length > 1
            step_val = compile_expr(aargs[1])
          end
        end
 # Issue #870: float receiver / float step needs a mrb_float
 # induction variable. Integer-typed `lv_x += 0.5` truncates to
 # `+= 0` and loops forever.
        is_float_step = 0
        if recv_t_step == "float"
          is_float_step = 1
        end
        if args_id >= 0
          aargs_t = get_args(args_id)
          if aargs_t.length > 0 && infer_type(aargs_t[0]) == "float"
            is_float_step = 1
          end
          if aargs_t.length > 1 && infer_type(aargs_t[1]) == "float"
            is_float_step = 1
          end
        end
        bp1 = get_block_param(nid, 0)
        synth = 0
        if bp1 == ""
          bp1 = "_i"
          synth = 1
        end
 # When the block omits its parameter, the synthesized `_i` isn't
 # declared anywhere — wrap the loop in a block scope and declare
 # it locally. This also avoids redefinition errors when multiple
 # paramless `step` blocks appear in the same function.
        if synth == 1
          emit("  {")
          if is_float_step == 1
            emit("  mrb_float lv_" + bp1 + " = 0.0;")
          else
            emit("  mrb_int lv_" + bp1 + " = 0;")
          end
        end
        bp_t_st = find_var_type(bp1)
        if is_float_step == 1
          emit("  for (lv_" + bp1 + " = " + rc + "; lv_" + bp1 + " <= " + limit_val + "; lv_" + bp1 + " += " + step_val + ") {")
        elsif bp_t_st == "bigint"
          @needs_bigint = 1
          stmp_st = new_temp
          emit("  for (mrb_int " + stmp_st + " = " + rc + "; " + stmp_st + " <= " + limit_val + "; " + stmp_st + " += " + step_val + ") {")
          emit("    lv_" + bp1 + " = sp_bigint_new_int(" + stmp_st + ");")
        else
          emit("  for (lv_" + bp1 + " = " + rc + "; lv_" + bp1 + " <= " + limit_val + "; lv_" + bp1 + " += " + step_val + ") {")
        end
        @indent = @indent + 1
        push_scope
        bp_decl_t = is_float_step == 1 ? "float" : (bp_t_st == "bigint" ? "bigint" : "int")
        declare_var(bp1, bp_decl_t)
        redo_label = push_redo_label
        emit_redo_label(redo_label)
        compile_stmts_body(@nd_body[@nd_block[nid]])
        pop_redo_label
        pop_scope
        @indent = @indent - 1
        emit("  }")
        if synth == 1
          emit("  }")
        end
        @in_loop = old
        return 1
      end
    end

    if mname == "cycle"
      if @nd_block[nid] >= 0 && recv >= 0
        old = @in_loop
        @in_loop = 1
        rt = infer_type(recv)
        rc = compile_expr_gc_rooted(recv)
        n = compile_arg0(nid)
        bp1 = get_block_param(nid, 0)
        if bp1 == ""
          bp1 = "_x"
        end
        pfx = array_c_prefix(rt)
        et = elem_type_of_array(rt)
        tmp_c = new_temp
        tmp_i = new_temp
        emit("  for (mrb_int " + tmp_c + " = 0; " + tmp_c + " < " + n + "; " + tmp_c + "++)")
        emit("  for (mrb_int " + tmp_i + " = 0; " + tmp_i + " < sp_" + pfx + "_length(" + rc + "); " + tmp_i + "++) {")
        emit("    " + c_type(et) + " lv_" + bp1 + " = sp_" + pfx + "_get(" + rc + ", " + tmp_i + ");")
        @indent = @indent + 1
        push_scope
        declare_var(bp1, et)
        redo_label = push_redo_label
        emit_redo_label(redo_label)
        compile_stmts_body(@nd_body[@nd_block[nid]])
        pop_redo_label
        pop_scope
        @indent = @indent - 1
        emit("  }")
        @in_loop = old
        return 1
      end
    end

 # scan with block: str.scan(/re/) { |m| ... }
    if mname == "scan"
      if @nd_block[nid] >= 0
        recv = @nd_receiver[nid]
        if recv >= 0
          args_id = @nd_arguments[nid]
          if args_id >= 0
            argl = get_args(args_id)
            if argl.length > 0
              ridx = find_regexp_index(argl[0])
              if ridx >= 0
                @needs_str_array = 1
                rc = compile_expr_gc_rooted(recv)
                bp = get_block_param(nid, 0)
                if bp == ""
                  bp = "_m"
                end
                tmp_arr = new_temp
                tmp_i = new_temp
                emit("  sp_StrArray *" + tmp_arr + " = sp_re_scan(sp_re_pat_" + ridx.to_s + ", " + rc + ");")
                emit("  for (mrb_int " + tmp_i + " = 0; " + tmp_i + " < " + tmp_arr + "->len; " + tmp_i + "++) {")
                emit("    const char *lv_" + bp + " = " + tmp_arr + "->data[" + tmp_i + "];")
                push_scope
                declare_var(bp, "string")
                blk = @nd_block[nid]
                if @nd_body[blk] >= 0
                  compile_stmts_body(@nd_body[blk])
                end
                pop_scope
                emit("  }")
                return 1
              end
            end
          end
        end
      end
    end

 # times/upto/downto with block
    if mname == "times"
      if @nd_block[nid] >= 0
        compile_times_block(nid)
        return 1
      end
    end
    if mname == "upto"
      if @nd_block[nid] >= 0
        compile_upto_block(nid)
        return 1
      end
    end
    if mname == "downto"
      if @nd_block[nid] >= 0
        compile_downto_block(nid)
        return 1
      end
    end

 # reduce/inject
    if mname == "reduce"
      if @nd_block[nid] >= 0
        compile_reduce_block(nid)
        return 1
      end
    end
    if mname == "inject"
      if @nd_block[nid] >= 0
        compile_reduce_block(nid)
        return 1
      end
    end

 # reject
    if mname == "reject"
      if @nd_block[nid] >= 0
        compile_reject_block(nid)
        return 1
      end
    end

 # loop
    if mname == "loop"
      if @nd_block[nid] >= 0
        old = @in_loop
        @in_loop = 1
        emit("  while (1) {")
        @indent = @indent + 1
        redo_label = push_redo_label
        emit_redo_label(redo_label)
        compile_stmts_body(@nd_body[@nd_block[nid]])
        pop_redo_label
        @indent = @indent - 1
        emit("  }")
        @in_loop = old
        return 1
      end
    end
    0
  end

  def compile_control_call_stmt(nid, mname, recv)
 # raise
    if mname == "raise"
      if recv < 0
        @needs_setjmp = 1
        args_id = @nd_arguments[nid]
        if args_id >= 0
          arg_ids = get_args(args_id)
          if arg_ids.length >= 2
 # raise ClassName, "message" - use the message with class
            if @nd_type[arg_ids[0]] == "ConstantReadNode"
              emit("  sp_raise_cls(\"" + @nd_name[arg_ids[0]] + "\", " + compile_expr(arg_ids[1]) + ");")
            else
              emit("  sp_raise(" + compile_expr(arg_ids[1]) + ");")
            end
          else
            if arg_ids.length == 1
              emit_raise_one_arg(arg_ids[0])
            else
              emit_bare_raise
            end
          end
        else
          emit_bare_raise
        end
        return 1
      end
    end

 # system
    if mname == "system"
      if recv < 0
        emit("  " + compile_system_call(nid) + ";")
        return 1
      end
    end

 # trap / Signal.trap: no-op at every shape (implicit-self or
 # explicit receiver, with or without block, stmt or expr position).
    if mname == "trap" && trap_call_is_signal_stub(nid) == 1
      return 1
    end

 # catch/throw
    if mname == "catch"
      if recv < 0
        if @nd_block[nid] >= 0
          compile_catch_stmt(nid)
          return 1
        end
      end
    end
    if mname == "throw"
      if recv < 0
        compile_throw_stmt(nid)
        return 1
      end
    end

 # File operations
    if recv >= 0
      if @nd_type[recv] == "ConstantReadNode"
        rcname = @nd_name[recv]
        if rcname == "File"
          if mname == "write"
            args_id = @nd_arguments[nid]
            arg_ids = []
            if args_id >= 0
              arg_ids = get_args(args_id)
            end
            a0 = "0"
            a1 = "0"
            if arg_ids.length >= 1
              a0 = compile_expr(arg_ids[0])
              if infer_type(arg_ids[0]) == "poly"
                @needs_rb_value = 1
                a0 = "(" + a0 + ").v.s"
              end
            end
            if arg_ids.length >= 2
              a1 = compile_expr(arg_ids[1])
              if infer_type(arg_ids[1]) == "poly"
                @needs_rb_value = 1
                a1 = "(" + a1 + ").v.s"
              end
            end
            emit("  sp_file_write(" + a0 + ", " + a1 + ");")
            return 1
          end
          if mname == "delete"
            emit("  sp_file_delete(" + compile_arg0(nid) + ");")
            return 1
          end
        end
      end
    end

 # exit
    if mname == "exit"
      if recv < 0
        val = compile_arg0(nid)
        emit("  exit(" + val + ");")
        return 1
      end
    end

 # abort — print message to stderr and exit(1)
    if mname == "abort"
      if recv < 0
        args_id = @nd_arguments[nid]
        if args_id >= 0
          aargs = get_args(args_id)
          if aargs.length > 0
            msg = compile_expr(aargs[0])
            emit("  fputs(" + msg + ", stderr); fputc('\\n', stderr);")
          end
        end
        emit("  exit(1);")
        return 1
      end
    end
    0
  end

  def compile_writer_and_block_call_stmt(nid, mname, recv)
 # attr_writer: obj.x = val — only short-circuit to a direct field
 # write when `x=` is actually a registered attr_writer on the class
 # (or transitive parent). Otherwise fall through to method-call
 # dispatch so a real `def x=(v)` method gets called.
    if recv >= 0
      if mname.length > 1
        if mname[mname.length - 1] == "="
          bname = mname[0, mname.length - 1]
          rt = infer_type(recv)
          if is_obj_type(rt) == 1
            r_cname = rt[4, rt.length - 4]
            r_ci = find_class_idx(r_cname)
            is_writer = 0
            if r_ci >= 0
              is_writer = cls_has_attr_writer(r_ci, bname)
            end
            if is_writer == 1
              rc = compile_expr_gc_rooted(recv)
              arrow2 = "->"
              if is_value_type_obj(rt) == 1
                arrow2 = "."
              end
 # Box rhs when the slot is poly, same as the
 # expression-form attr_writer above.
              slot_t = cls_ivar_type(r_ci, "@" + bname)
              arg0_w = compile_arg0(nid)
              arg_t_aw = "int"
              args_id_aw = @nd_arguments[nid]
              if args_id_aw >= 0
                arg_ids_aw = get_args(args_id_aw)
                if arg_ids_aw.length > 0
                  arg_t_aw = infer_type(arg_ids_aw[0])
 # Check if the rhs is itself a promote-mode setter or
 # bigint-returning method call whose cached type is stale.
 # Mirror the compile_expr_for_expected_type override so a
 # `b1.n = b2.n = 7` chain doesn't double-wrap.
                  inner_aw = arg_ids_aw[0]
                  if inner_aw >= 0 && @nd_type[inner_aw] == "ParenthesesNode"
                    pbody_in = @nd_body[inner_aw]
                    if pbody_in >= 0
                      pstmts_in = get_stmts(pbody_in)
                      if pstmts_in.length == 1
                        inner_aw = pstmts_in[0]
                      end
                    end
                  end
                  if arg_t_aw != "bigint" && inner_aw >= 0 && @nd_type[inner_aw] == "CallNode"
                    rcv_in_aw = @nd_receiver[inner_aw]
                    mn_in_aw = @nd_name[inner_aw]
                    if rcv_in_aw >= 0
                      rt_in_aw = base_type(infer_type(rcv_in_aw))
                      if is_obj_type(rt_in_aw) == 1
                        rcn_in_aw = rt_in_aw[4, rt_in_aw.length - 4]
                        rci_in_aw = find_class_idx(rcn_in_aw)
                        if rci_in_aw >= 0
                          if mn_in_aw.length > 1 && mn_in_aw[mn_in_aw.length - 1] == "=" && mn_in_aw != "==" && mn_in_aw != "!=" && mn_in_aw != "<=" && mn_in_aw != ">="
                            bn_in_aw = mn_in_aw[0, mn_in_aw.length - 1]
                            if cls_has_attr_writer(rci_in_aw, bn_in_aw) == 1
                              if base_type(cls_ivar_type(rci_in_aw, "@" + bn_in_aw)) == "bigint"
                                arg_t_aw = "bigint"
                              end
                            end
                          end
                        end
                      end
                    end
                  end
                end
              end
              if slot_t == "poly"
                arg0_w = box_value_to_poly(arg_t_aw, arg0_w)
              elsif slot_t == "bigint" && arg_t_aw == "int"
 # promote-mode-widened ivar: wrap an int rhs.
                @needs_bigint = 1
                arg0_w = "sp_bigint_new_int(" + arg0_w + ")"
              elsif slot_t == "int" && arg_t_aw == "bigint"
                @needs_bigint = 1
                arg0_w = "sp_bigint_to_int((sp_Bigint *)" + arg0_w + ")"
              end
              emit("  " + rc + arrow2 + sanitize_ivar(bname) + " = " + arg0_w + ";")
              return 1
            end
          end
        end
      end
    end

 # map with block
    if mname == "map"
      if @nd_block[nid] >= 0
        compile_map_block(nid)
        return 1
      end
    end

 # select with block
    if mname == "select"
      if @nd_block[nid] >= 0
        compile_select_block(nid)
        return 1
      end
    end

 # User-defined yield function or instance_eval trampoline, called
 # with a literal block. (A `&proc_var` forward at the call site
 # doesn't trigger inlining — those flow through compile_call_expr's
 # regular block-forwarding path.)
    if has_literal_block(nid) == 1
      if recv < 0
        mi = find_method_idx(mname)
        if mi >= 0
          if @meth_has_yield[mi] == 1
            compile_yield_call_stmt(nid, mi)
            return 1
          end
        end
 # Bare `m { ... }` inside another method body of the same
 # class — `m` is a sibling instance method, lookup happens on
 # @current_class_idx (and its ancestors). compile_yield_method
 # _call_stmt synthesizes `self` for rc when recv < 0.
        if @current_class_idx >= 0
          ci_self = @current_class_idx
          if try_yield_or_trampoline_dispatch(nid, recv, ci_self, mname) == 1
            return 1
          end
          pwalk = ci_self
          while @cls_parents[pwalk] != ""
            pci = find_class_idx(@cls_parents[pwalk])
            if pci < 0
              break
            end
            if try_yield_or_trampoline_dispatch(nid, recv, pci, mname) == 1
              return 1
            end
            pwalk = pci
          end
        end
      end
 # Class method with yield, or an arity-0 instance_eval trampoline.
 # The direct-class and parent-class lookups share the same dispatch
 # shape (find midx, check yield, check trampoline); collapsed into
 # try_yield_or_trampoline_dispatch.
      if recv >= 0
        rtype = infer_type(recv)
        if is_obj_type(rtype) == 1
          cn = rtype[4, rtype.length - 4]
          cci = find_class_idx(cn)
          if cci >= 0
            if try_yield_or_trampoline_dispatch(nid, recv, cci, mname) == 1
              return 1
            end
            if @cls_parents[cci] != ""
              pci = find_class_idx(@cls_parents[cci])
              if pci >= 0
                if try_yield_or_trampoline_dispatch(nid, recv, pci, mname) == 1
                  return 1
                end
              end
            end
          end
        end
      end
    end
    0
  end


  def compile_file_block_stmt(nid, ftmp, bp)
    if nid < 0
      return
    end
    t = @nd_type[nid]
    if t == "CallNode"
      mn = @nd_name[nid]
      r = @nd_receiver[nid]
 # f.puts "text"
      if mn == "puts"
        if r >= 0
          if @nd_type[r] == "LocalVariableReadNode"
            if @nd_name[r] == bp
              args_id = @nd_arguments[nid]
              if args_id >= 0
                arg_ids = get_args(args_id)
                if arg_ids.length >= 1
                  emit("  fprintf(" + ftmp + ", \"%s" + bsl_n + "\", " + compile_expr(arg_ids[0]) + ");")
                  return
                end
              end
              emit("  fputc('" + bsl_n + "', " + ftmp + ");")
              return
            end
          end
        end
      end
 # f.print "text"
      if mn == "print"
        if r >= 0
          if @nd_type[r] == "LocalVariableReadNode"
            if @nd_name[r] == bp
              args_id = @nd_arguments[nid]
              if args_id >= 0
                arg_ids = get_args(args_id)
                if arg_ids.length >= 1
                  emit("  fputs(" + compile_expr(arg_ids[0]) + ", " + ftmp + ");")
                  return
                end
              end
              return
            end
          end
        end
      end
 # f.write "text"
      if mn == "write"
        if r >= 0
          if @nd_type[r] == "LocalVariableReadNode"
            if @nd_name[r] == bp
              args_id = @nd_arguments[nid]
              if args_id >= 0
                arg_ids = get_args(args_id)
                if arg_ids.length >= 1
                  emit("  fputs(" + compile_expr(arg_ids[0]) + ", " + ftmp + ");")
                  return
                end
              end
              return
            end
          end
        end
      end
 # f.each_line { |line| ... }
      if mn == "each_line"
        if r >= 0
          if @nd_type[r] == "LocalVariableReadNode"
            if @nd_name[r] == bp
              if @nd_block[nid] >= 0
                lblk = @nd_block[nid]
                lbp = get_block_param(nid, 0)
                ltmp = new_temp
                emit("  { char " + ltmp + "[4096];")
                emit("  while (fgets(" + ltmp + ", sizeof(" + ltmp + "), " + ftmp + ")) {")
                emit("    const char *lv_" + lbp + " = " + ltmp + ";")
                push_scope
                declare_var(lbp, "string")
 # Compile block body
                lbbody = @nd_body[lblk]
                if lbbody >= 0
                  lbs = get_stmts(lbbody)
                  lbk = 0
                  while lbk < lbs.length
                    compile_stmt(lbs[lbk])
                    lbk = lbk + 1
                  end
                end
                pop_scope
                emit("  } }")
                return
              end
            end
          end
        end
      end
    end
 # Handle control flow: while/if/unless with file block context
    if t == "WhileNode"
      cond = @nd_predicate[nid]
      emit("  while (" + compile_expr(cond) + ") {")
      body = @nd_body[nid]
      if body >= 0
        bs = get_stmts(body)
        bk = 0
        while bk < bs.length
          compile_file_block_stmt(bs[bk], ftmp, bp)
          bk = bk + 1
        end
      end
      emit("  }")
      return
    end
    if t == "IfNode"
      cond = @nd_predicate[nid]
      emit("  if (" + compile_expr(cond) + ") {")
      body = @nd_body[nid]
      if body >= 0
        bs = get_stmts(body)
        bk = 0
        while bk < bs.length
          compile_file_block_stmt(bs[bk], ftmp, bp)
          bk = bk + 1
        end
      end
      if @nd_subsequent[nid] >= 0
        emit("  } else {")
        ebs = get_stmts(@nd_subsequent[nid])
        ebk = 0
        while ebk < ebs.length
          compile_file_block_stmt(ebs[ebk], ftmp, bp)
          ebk = ebk + 1
        end
      end
      emit("  }")
      return
    end
 # Fallback: compile as normal statement
    compile_stmt(nid)
  end

  def scan_lambda_free_vars(nid, params, locals, free_vars)
 # Scan AST node for free variable references
    if nid < 0
      return
    end
    t = @nd_type[nid]
    if t == "LocalVariableReadNode"
      vn = @nd_name[nid]
      if not_in(vn, params) == 1
        if not_in(vn, locals) == 1
          if not_in(vn, free_vars) == 1
            free_vars.push(vn)
          end
        end
      end
      return
    end
    if t == "LambdaNode"
 # For nested lambdas, find their free vars and add them to OUR free vars
 # (they need to be captured transitively). Collect ALL formal params,
 # not just the first one .
      inner_params = "".split(",", -1)
      inner_params_id = @nd_parameters[nid]
      if inner_params_id >= 0
        reqs = parse_id_list(@nd_requireds[inner_params_id])
        ip = 0
        while ip < reqs.length
          inner_params.push(@nd_name[reqs[ip]])
          ip = ip + 1
        end
      end
      inner_body = @nd_body[nid]
      if inner_body >= 0
        inner_locals = "".split(",", -1)
        inner_free = "".split(",", -1)
        scan_lambda_free_vars(inner_body, inner_params, inner_locals, inner_free)
        inner_free.each { |vn|
          if not_in(vn, params) == 1
            if not_in(vn, locals) == 1
              if not_in(vn, free_vars) == 1
                free_vars.push(vn)
              end
            end
          end
        }
      end
      return
    end
 # Collect local writes — scan expression first to detect reads before the write
    if t == "LocalVariableWriteNode"
      vn = @nd_name[nid]
 # Scan the RHS expression first (may contain reads of the same var)
      if @nd_expression[nid] >= 0
        scan_lambda_free_vars(@nd_expression[nid], params, locals, free_vars)
      end
      if not_in(vn, locals) == 1
        if not_in(vn, params) == 1
          if not_in(vn, free_vars) == 1
 # Check if variable exists in outer scope — if so, it's a free var
            outer_t = find_var_type(vn)
            if outer_t != ""
              free_vars.push(vn)
            else
              locals.push(vn)
            end
          end
        end
      end
      return
    end
 # Recurse
    if @nd_body[nid] >= 0
      scan_lambda_free_vars(@nd_body[nid], params, locals, free_vars)
    end
    stmts = parse_id_list(@nd_stmts[nid])
    k = 0
    while k < stmts.length
      scan_lambda_free_vars(stmts[k], params, locals, free_vars)
      k = k + 1
    end
    if @nd_expression[nid] >= 0
      scan_lambda_free_vars(@nd_expression[nid], params, locals, free_vars)
    end
    if @nd_left[nid] >= 0
      scan_lambda_free_vars(@nd_left[nid], params, locals, free_vars)
    end
    if @nd_right[nid] >= 0
      scan_lambda_free_vars(@nd_right[nid], params, locals, free_vars)
    end
    if @nd_receiver[nid] >= 0
      scan_lambda_free_vars(@nd_receiver[nid], params, locals, free_vars)
    end
    if @nd_arguments[nid] >= 0
      scan_lambda_free_vars(@nd_arguments[nid], params, locals, free_vars)
    end
    args = parse_id_list(@nd_args[nid])
    k = 0
    while k < args.length
      scan_lambda_free_vars(args[k], params, locals, free_vars)
      k = k + 1
    end
    if @nd_predicate[nid] >= 0
      scan_lambda_free_vars(@nd_predicate[nid], params, locals, free_vars)
    end
    if @nd_subsequent[nid] >= 0
      scan_lambda_free_vars(@nd_subsequent[nid], params, locals, free_vars)
    end
    if @nd_else_clause[nid] >= 0
      scan_lambda_free_vars(@nd_else_clause[nid], params, locals, free_vars)
    end
    if @nd_block[nid] >= 0
      scan_lambda_free_vars(@nd_block[nid], params, locals, free_vars)
    end
    elems = parse_id_list(@nd_elements[nid])
    k = 0
    while k < elems.length
      scan_lambda_free_vars(elems[k], params, locals, free_vars)
      k = k + 1
    end
    parts = parse_id_list(@nd_parts[nid])
    k = 0
    while k < parts.length
      scan_lambda_free_vars(parts[k], params, locals, free_vars)
      k = k + 1
    end
    if @nd_collection[nid] >= 0
      scan_lambda_free_vars(@nd_collection[nid], params, locals, free_vars)
    end
  end

  def scan_lambda_ret_types(stmts)
    stmts.each { |sid|
      scan_lambda_ret_types_node(sid)
    }
 # Also check: h = method_call() where method returns lambda
    stmts.each { |sid|
      if @nd_type[sid] == "LocalVariableWriteNode"
        vn = @nd_name[sid]
        expr = @nd_expression[sid]
        if expr >= 0 && @nd_type[expr] == "CallNode"
          call_ret = infer_type(expr)
          if call_ret == "lambda"
 # Find the method and its lambda return
            mn = @nd_name[expr]
            mi = find_method_idx(mn)
            if mi >= 0
              bid = @meth_body_ids[mi]
              if bid >= 0
                mbs = get_stmts(bid)
                if mbs.length > 0
                  last = mbs.last
                  if @nd_type[last] == "LambdaNode"
                    lbody = @nd_body[last]
                    if lbody >= 0
                      lbs = get_stmts(lbody)
                      if lbs.length > 0
                        lrt = infer_type(lbs.last)
                        if not_in(vn, @lambda_var_ret_names) == 1
                          @lambda_var_ret_names.push(vn)
                          @lambda_var_ret_types.push(lrt)
                        end
                      end
                    end
                  end
                end
              end
            end
          end
        end
      end
    }
  end

  def scan_lambda_ret_types_node(nid)
    if nid < 0
      return
    end
    t = @nd_type[nid]
    if t == "LocalVariableWriteNode"
      vn = @nd_name[nid]
      expr = @nd_expression[nid]
      if expr >= 0 && @nd_type[expr] == "LambdaNode"
        lbody = @nd_body[expr]
        if lbody >= 0
          lbs = get_stmts(lbody)
          if lbs.length > 0
            lrt = infer_type(lbs.last)
            if not_in(vn, @lambda_var_ret_names) == 1
              @lambda_var_ret_names.push(vn)
              @lambda_var_ret_types.push(lrt)
            end
          end
        end
      end
      scan_lambda_ret_types_node(expr)
    end
 # Scan into method bodies to find lambdas returned from methods
    if t == "DefNode"
      if @nd_body[nid] >= 0
        scan_lambda_ret_types_node(@nd_body[nid])
      end
      return
    end
    if @nd_body[nid] >= 0
      scan_lambda_ret_types_node(@nd_body[nid])
    end
    if @nd_expression[nid] >= 0
      scan_lambda_ret_types_node(@nd_expression[nid])
    end
    ss = parse_id_list(@nd_stmts[nid])
    k = 0
    while k < ss.length
      scan_lambda_ret_types_node(ss[k])
      k = k + 1
    end
  end

  def lambda_var_ret_type(vname)
    i = 0
    while i < @lambda_var_ret_names.length
      if @lambda_var_ret_names[i] == vname
        return @lambda_var_ret_types[i]
      end
      i = i + 1
    end
    ""
  end

  def lam_box(expr, vtype)
    bt = base_type(vtype)
    if bt == "string"
      return "sp_lam_int((mrb_int)" + expr + ")"
    end
    if bt == "float"
      return "sp_lam_int(*(mrb_int*)&(mrb_float){" + expr + "})"
    end
    if bt == "bool"
      return "sp_lam_bool(" + expr + ")"
    end
    if bt == "nil" || bt == "void"
      return "&sp_lam_nil_val"
    end
    "sp_lam_int(" + expr + ")"
  end

  def lam_unbox(expr, vtype)
    bt = base_type(vtype)
    if bt == "string"
      return "(const char*)sp_lam_to_int(" + expr + ")"
    end
    if bt == "float"
      return "*(mrb_float*)&(mrb_int){sp_lam_to_int(" + expr + ")}"
    end
    if bt == "bool"
      return "(" + expr + ")->u.bval"
    end
    if bt == "nil" || bt == "void"
      return "(sp_lam_to_int(" + expr + "), 0)"
    end
    "sp_lam_to_int(" + expr + ")"
  end

  def compile_lambda_body_expr(nid, params, captures)
 # Compile an expression inside a lambda body, replacing:
 # - param refs with lv_param (local)
 # - captured var refs with self->captures[i]
    if nid < 0
      return "&sp_lam_nil_val"
    end
    t = @nd_type[nid]
    if t == "LocalVariableReadNode"
      vn = @nd_name[nid]
 # Check param
      if not_in(vn, params) == 0
        return "lv_" + vn
      end
 # Check captures
      ci = 0
      while ci < captures.length
        if captures[ci] == vn
          ct = ""
          if ci < @lambda_capture_cell_types.length
            ct = @lambda_capture_cell_types[ci]
          end
          if ct != ""
 # Typed cell capture: dereference and box
            deref = "*(" + c_type(ct) + "*)self->captures[" + ci.to_s + "]"
            return lam_box(deref, ct)
          end
          return "self->captures[" + ci.to_s + "]"
        end
        ci = ci + 1
      end
      return "lv_" + vn
    end
    if t == "LocalVariableWriteNode"
      vn = @nd_name[nid]
      val = compile_lambda_body_expr(@nd_expression[nid], params, captures)
 # Check if capture
      ci = 0
      while ci < captures.length
        if captures[ci] == vn
          ct = ""
          if ci < @lambda_capture_cell_types.length
            ct = @lambda_capture_cell_types[ci]
          end
          if ct != ""
 # Typed cell capture: unbox and store
            cptr = "*(" + c_type(ct) + "*)self->captures[" + ci.to_s + "]"
            return "(" + cptr + " = " + lam_unbox(val, ct) + ", " + val + ")"
          end
          return "(self->captures[" + ci.to_s + "] = " + val + ")"
        end
        ci = ci + 1
      end
      emit("  sp_Val *lv_" + vn + " = " + val + ";")
      return "lv_" + vn
    end
    if t == "IntegerNode"
      return "sp_lam_int(" + @nd_value[nid].to_s + ")"
    end
    if t == "TrueNode"
      return "sp_lam_bool(TRUE)"
    end
    if t == "FalseNode"
      return "sp_lam_bool(FALSE)"
    end
    if t == "NilNode"
      return "&sp_lam_nil_val"
    end
    if t == "StringNode"
      return "sp_lam_int(0)"
    end
    if t == "ConstantReadNode"
      cname = @nd_name[nid]
      ci = find_const_idx(cname)
      if ci >= 0
        return "cst_" + cname
      end
      return "&sp_lam_nil_val"
    end
    if t == "LambdaNode"
      return compile_lambda_expr(nid)
    end
    if t == "CallNode"
      mname = @nd_name[nid]
      recv = @nd_receiver[nid]
 # f[arg] -> sp_lam_call(f, arg)
      if mname == "[]"
        if recv >= 0
          rc = compile_lambda_body_expr(recv, params, captures)
          args_id = @nd_arguments[nid]
          if args_id >= 0
            aargs = get_args(args_id)
            if aargs.length > 0
              ac = compile_lambda_body_expr(aargs.first, params, captures)
              return "sp_lam_call(" + rc + ", " + ac + ")"
            end
          end
          return "sp_lam_call(" + rc + ", &sp_lam_nil_val)"
        end
      end
 # f.call(arg) -> sp_lam_call(f, arg)
      if mname == "call"
        if recv >= 0
          rc = compile_lambda_body_expr(recv, params, captures)
          args_id = @nd_arguments[nid]
          if args_id >= 0
            aargs = get_args(args_id)
            if aargs.length > 0
              ac = compile_lambda_body_expr(aargs.first, params, captures)
              return "sp_lam_call(" + rc + ", " + ac + ")"
            end
          end
          return "sp_lam_call(" + rc + ", &sp_lam_nil_val)"
        end
      end
 # No receiver: bare function call
      if recv < 0
        if mname == "+"
          return "sp_lam_int(0)"
        end
        mi = find_method_idx(mname)
        if mi >= 0
          ca = ""
          args_id = @nd_arguments[nid]
          if args_id >= 0
            aargs = get_args(args_id)
            k = 0
            while k < aargs.length
              if k > 0
                ca = ca + ", "
              end
              ca = ca + compile_lambda_body_expr(aargs[k], params, captures)
              k = k + 1
            end
          end
          return "sp_" + sanitize_name(mname) + "(" + ca + ")"
        end
      end
 # Arithmetic on sp_Val (+ operator)
      if mname == "+"
        if recv >= 0
          rc = compile_lambda_body_expr(recv, params, captures)
          ac = compile_lambda_body_expr(get_args(@nd_arguments[nid])[0], params, captures)
          return "sp_lam_int(sp_lam_to_int(" + rc + ") + sp_lam_to_int(" + ac + "))"
        end
      end
 # more numeric ops on sp_Val so multi-arg lambda
 # bodies like `->(a, b, c) { a * b * c }` lower correctly.
      if mname == "-"
        if recv >= 0
          rc = compile_lambda_body_expr(recv, params, captures)
          ac = compile_lambda_body_expr(get_args(@nd_arguments[nid])[0], params, captures)
          return "sp_lam_int(sp_lam_to_int(" + rc + ") - sp_lam_to_int(" + ac + "))"
        end
      end
      if mname == "*"
        if recv >= 0
          rc = compile_lambda_body_expr(recv, params, captures)
          ac = compile_lambda_body_expr(get_args(@nd_arguments[nid])[0], params, captures)
          return "sp_lam_int(sp_lam_to_int(" + rc + ") * sp_lam_to_int(" + ac + "))"
        end
      end
      if mname == "/"
        if recv >= 0
          rc = compile_lambda_body_expr(recv, params, captures)
          ac = compile_lambda_body_expr(get_args(@nd_arguments[nid])[0], params, captures)
          return "sp_lam_int(sp_idiv(sp_lam_to_int(" + rc + "), sp_lam_to_int(" + ac + ")))"
        end
      end
      if mname == "%"
        if recv >= 0
          rc = compile_lambda_body_expr(recv, params, captures)
          ac = compile_lambda_body_expr(get_args(@nd_arguments[nid])[0], params, captures)
          return "sp_lam_int(sp_imod(sp_lam_to_int(" + rc + "), sp_lam_to_int(" + ac + ")))"
        end
      end
      if mname == "<" || mname == ">" || mname == "<=" || mname == ">=" || mname == "==" || mname == "!="
        if recv >= 0
          rc = compile_lambda_body_expr(recv, params, captures)
          ac = compile_lambda_body_expr(get_args(@nd_arguments[nid])[0], params, captures)
          return "sp_lam_bool(sp_lam_to_int(" + rc + ") " + mname + " sp_lam_to_int(" + ac + "))"
        end
      end
      return "&sp_lam_nil_val"
    end
    if t == "IfNode"
      pred = compile_lambda_body_expr(@nd_predicate[nid], params, captures)
      body = @nd_body[nid]
      bexpr = "&sp_lam_nil_val"
      if body >= 0
        bs = get_stmts(body)
        if bs.length > 0
          bexpr = compile_lambda_body_expr(bs.last, params, captures)
        end
      end
      ec = @nd_else_clause[nid]
      eexpr = "&sp_lam_nil_val"
      if ec >= 0
        ebs = get_stmts(@nd_body[ec])
        if ebs.length > 0
          eexpr = compile_lambda_body_expr(ebs[ebs.length - 1], params, captures)
        end
      end
      return "(" + pred + " ? " + bexpr + " : " + eexpr + ")"
    end
    "&sp_lam_nil_val"
  end

  def wrap_as_sp_val(nid)
    at = infer_type(nid)
    if at == "lambda"
      return compile_expr(nid)
    end
    if at == "int"
      return "sp_lam_int(" + compile_expr(nid) + ")"
    end
    if at == "bool"
      return "sp_lam_bool(" + compile_expr(nid) + ")"
    end
    if @nd_type[nid] == "NilNode"
      return "&sp_lam_nil_val"
    end
 # Default: try to compile as expression
    compile_expr(nid)
  end

  def compile_lambda_expr(nid)
    @needs_lambda = 1
 # Collect ALL formal params, not just the first . The
 # legacy single-`pname` path still drives the typed-caps emit
 # block below (it only handles single-arg lambdas with typed
 # captures); multi-arg flows through the sp_Val* path which now
 # honours `param_arr.length`.
    param_arr = "".split(",", -1)
    params_id = @nd_parameters[nid]
    if params_id >= 0
      reqs = parse_id_list(@nd_requireds[params_id])
      pi = 0
      while pi < reqs.length
        param_arr.push(@nd_name[reqs[pi]])
        pi = pi + 1
      end
    end
    pname = ""
    if param_arr.length > 0
      pname = param_arr[0]
    end

    body = @nd_body[nid]
 # Find free variables (captures)
    free_vars = "".split(",", -1)
    locals = "".split(",", -1)
    if body >= 0
      scan_lambda_free_vars(body, param_arr, locals, free_vars)
    end

 # Generate lambda function
    lam_id = @lambda_counter
    @lambda_counter = @lambda_counter + 1
    fname = "_lam_" + lam_id.to_s

 # Compute capture cell types (before body compilation)
    cap_cell_types = "".split(",", -1)
    k = 0
    while k < free_vars.length
      fv = free_vars[k]
      cell = heap_promoted_cell(fv)
      if cell == "" && @in_fiber_body == 1 && fiber_capture_index(fv) >= 0
        cell = "_cap->" + fv
      end
 # Regular locals will be heap-promoted (not lambda params/captures)
      if cell == "" && not_in(fv, @lambda_params) == 1
        is_enclosing_cap = 0
        ci = 0
        while ci < @lambda_captures.length
          if @lambda_captures[ci] == fv
            is_enclosing_cap = 1
          end
          ci = ci + 1
        end
        if is_enclosing_cap == 0
          vt = find_var_type(fv)
          if vt != "" && vt != "lambda"
            cell = "will_promote"
          end
        end
      end
      if cell != ""
        cap_cell_types.push(find_var_type(fv))
      else
        cap_cell_types.push("")
      end
      k = k + 1
    end

 # Check if we have typed cell captures (need regular compiler path)
    has_typed_caps = 0
    k = 0
    while k < cap_cell_types.length
      if cap_cell_types[k] != ""
        has_typed_caps = 1
      end
      k = k + 1
    end

 # Get body expression
    bexpr = "&sp_lam_nil_val"
    if body >= 0
      bs = get_stmts(body)
      if bs.length > 0 && has_typed_caps == 1
 # Typed captures: compile body using regular compiler
        save_out = @out_lines
        save_indent = @indent
        save_hp_names_len = @heap_promoted_names.length
        save_hp_cells_len = @heap_promoted_cells.length
        @out_lines = "".split(",", -1)
        @indent = 1

        push_scope
 # Declare parameter with proper type
        if pname != ""
          ptype = infer_type(bs.last)
          if ptype == ""
            ptype = "int"
          end
          declare_var(pname, "int")
        end
 # Set up cell pointer locals for typed captures
        k = 0
        while k < free_vars.length
          if cap_cell_types[k] != ""
            ct = c_type(cap_cell_types[k])
            cell_local = "_lc_" + free_vars[k]
            emit("  " + ct + " *" + cell_local + " = (" + ct + "*)self->captures[" + k.to_s + "];")
            @heap_promoted_names.push(free_vars[k])
            @heap_promoted_cells.push(cell_local)
            declare_var(free_vars[k], cap_cell_types[k])
          end
          k = k + 1
        end
 # Declare body-local variables. Read precomputed scan_locals
 # output (cached by analyze, keyed by body bid; analyze's
 # exclusion is the block's syntactic params). free_vars are
 # not part of analyze's exclusion, so filter them here so
 # captured-by-name vars stay outer-scoped instead of getting
 # a fresh lv_<name> shadow declaration.
        lnames = "".split(",", -1)
        ltypes = "".split(",", -1)
        sn_lb = @nd_scope_names[body]
        if sn_lb != ""
          raw_n = sn_lb.split("|", -1)
          raw_t = @nd_scope_types[body].split("|", -1)
          rk = 0
          while rk < raw_n.length
            keep = 1
            fvi = 0
            while fvi < free_vars.length
              if free_vars[fvi] == raw_n[rk]
                keep = 0
              end
              fvi = fvi + 1
            end
            if keep == 1
              lnames.push(raw_n[rk])
              ltypes.push(raw_t[rk])
            end
            rk = rk + 1
          end
        end
        lk = 0
        while lk < lnames.length
          declare_var(lnames[lk], ltypes[lk])
          emit("  " + c_type(ltypes[lk]) + " lv_" + lnames[lk] + " = " + c_default_val(ltypes[lk]) + ";")
          lk = lk + 1
        end
 # Compile body statements
        i = 0
        while i < bs.length - 1
          compile_stmt(bs[i])
          i = i + 1
        end
        last = bs.last
        last_type = infer_type(last)
        if @nd_type[last] == "LocalVariableWriteNode" || @nd_type[last] == "LocalVariableOperatorWriteNode"
          compile_stmt(last)
        end
        last_val = compile_expr(last)

        pop_scope
        body_stmts = @out_lines.join(10.chr) + 10.chr
        @out_lines = save_out
        @indent = save_indent
 # Restore heap promoted
        while @heap_promoted_names.length > save_hp_names_len
          @heap_promoted_names.pop
        end
        while @heap_promoted_cells.length > save_hp_cells_len
          @heap_promoted_cells.pop
        end

 # Build lambda function with typed body
        @lambda_funcs <<"static sp_Val *" + fname + "(sp_Val *self, sp_Val *arg) {\n"
        if pname != ""
          @lambda_funcs << "  mrb_int lv_"
          @lambda_funcs << pname
          @lambda_funcs << " = sp_lam_to_int(arg);\n"
        end
        @lambda_funcs << body_stmts
        @lambda_funcs << 10.chr
        bexpr = lam_box(last_val, last_type)
        @lambda_funcs << "  return "
        @lambda_funcs << bexpr
        @lambda_funcs << ";\n}\n\n"
      elsif bs.length > 0
 # No typed captures: use sp_Val* lambda body compiler
        save_out = @out_lines
        save_params = @lambda_params
        save_captures = @lambda_captures
        save_cell_types = @lambda_capture_cell_types
        @out_lines = "".split(",", -1)
        @lambda_params = param_arr
        @lambda_captures = free_vars
        @lambda_capture_cell_types = cap_cell_types
        si = 0
        while si < bs.length - 1
          side_expr = compile_lambda_body_expr(bs[si], param_arr, free_vars)
          emit("  " + side_expr + ";")
          si = si + 1
        end
        bexpr = compile_lambda_body_expr(bs.last, param_arr, free_vars)
        body_stmts = @out_lines.join(10.chr) + 10.chr
        @out_lines = save_out
        @lambda_params = save_params
        @lambda_captures = save_captures
        @lambda_capture_cell_types = save_cell_types

 # emit signature with one sp_Val* per param so
 # multi-arg `->(a, b) { a + b }` works. The runtime
 # sp_lam_call2 / _3 / _4 cast the fn ptr to the matching arity.
        sig_args = "sp_Val *self"
        decls = ""
        pi_s = 0
        while pi_s < param_arr.length
          sig_args = sig_args + ", sp_Val *_arg" + pi_s.to_s
          decls = decls + "  sp_Val *lv_" + param_arr[pi_s] + " = _arg" + pi_s.to_s + ";\n"
          pi_s = pi_s + 1
        end
        if param_arr.length == 0
          sig_args = sig_args + ", sp_Val *arg"
        end
        if body_stmts != ""
          @lambda_funcs <<"static sp_Val *" + fname + "(" + sig_args + ") {\n"
          @lambda_funcs <<decls
          @lambda_funcs <<"  (void)self;\n"
          if param_arr.length == 0
            @lambda_funcs <<"  (void)arg;\n"
          end
          @lambda_funcs <<body_stmts + 10.chr
          @lambda_funcs <<"  return " + bexpr + ";\n"
          @lambda_funcs <<"}\n\n"
        else
          @lambda_funcs <<"static sp_Val *" + fname + "(" + sig_args + ") {\n"
          @lambda_funcs <<decls
          @lambda_funcs <<"  (void)self;\n"
          if param_arr.length == 0
            @lambda_funcs <<"  (void)arg;\n"
          end
          @lambda_funcs <<"  return " + bexpr + ";\n"
          @lambda_funcs <<"}\n\n"
        end
      else
        @lambda_funcs <<"static sp_Val *" + fname + "(sp_Val *self, sp_Val *arg) { (void)self; (void)arg; return &sp_lam_nil_val; }\n\n"
      end
    else
      @lambda_funcs <<"static sp_Val *" + fname + "(sp_Val *self, sp_Val *arg) { (void)self; (void)arg; return &sp_lam_nil_val; }\n\n"
    end

 # Build the closure creation expression
    if free_vars.length > 0
 # Heap-promote regular locals that need cell captures
      k = 0
      while k < free_vars.length
        if cap_cell_types[k] != "" && heap_promoted_cell(free_vars[k]) == ""
          fv = free_vars[k]
 # Skip if it's a fiber capture (already has cell) or lambda context
          if @in_fiber_body == 0 || fiber_capture_index(fv) < 0
            if not_in(fv, @heap_promoted_names) == 1
              ct = c_type(cap_cell_types[k])
              cell = "_hcell_" + fv + "_l" + lam_id.to_s
              emit("  " + ct + " *" + cell + " = (" + ct + "*)sp_gc_alloc(sizeof(" + ct + "), NULL, NULL);")
              emit("  *" + cell + " = " + fiber_var_ref(fv) + ";")
              @heap_promoted_names.push(fv)
              @heap_promoted_cells.push(cell)
            end
          end
        end
        k = k + 1
      end
      tmp = new_temp
 # Cast multi-arg fn ptr to sp_fn_t for storage; sp_lam_callN
 # casts back to the matching arity at the call site ().
      emit("  sp_Val *" + tmp + " = sp_lam_proc((sp_fn_t)(uintptr_t)" + fname + ", " + free_vars.length.to_s + ");")
      k = 0
      while k < free_vars.length
        fv = free_vars[k]
        if cap_cell_types[k] != ""
 # Heap-promoted or fiber-captured: store cell pointer cast to sp_Val*
          cell = heap_promoted_cell(fv)
          if cell == "" && @in_fiber_body == 1 && fiber_capture_index(fv) >= 0
            cell = "_cap->" + fv
          end
          emit("  " + tmp + "->captures[" + k.to_s + "] = (sp_Val*)" + cell + ";")
        else
 # Check if it's a param or capture of enclosing lambda (sp_Val* world)
          is_lam_ctx = 0
          if not_in(fv, @lambda_params) == 0
            is_lam_ctx = 1
            emit("  " + tmp + "->captures[" + k.to_s + "] = lv_" + fv + ";")
          else
            ci = 0
            while ci < @lambda_captures.length
              if @lambda_captures[ci] == fv
                is_lam_ctx = 1
                emit("  " + tmp + "->captures[" + k.to_s + "] = self->captures[" + ci.to_s + "];")
              end
              ci = ci + 1
            end
          end
          if is_lam_ctx == 0
 # Regular local: should have been heap-promoted already
            cell = heap_promoted_cell(fv)
            if cell != ""
              emit("  " + tmp + "->captures[" + k.to_s + "] = (sp_Val*)" + cell + ";")
            else
              emit("  " + tmp + "->captures[" + k.to_s + "] = " + fiber_var_ref(fv) + ";")
            end
          end
        end
        k = k + 1
      end
      return tmp
    else
      return "sp_lam_proc((sp_fn_t)(uintptr_t)" + fname + ", 0)"
    end
  end

 # Build the proc-fn body prelude that unpacks the args array passed
 # to the uniform `(void *_cap, mrb_int *args)` signature into named
 # `lv_<bp>` locals — one `mrb_int lv_<bp> = args[<idx>];` line per
 # block param. Used at both proc-fn body emit sites (captures and
 # no-captures branches; identical shape).
  def proc_fn_args_unpack(bps, pts = "".split(",", -1))
    s = ""
    bk = 0
    while bk < bps.length
      ct = "mrb_int"
      expr = "args[" + bk.to_s + "]"
      if bk < pts.length && pts[bk] != "" && pts[bk] != "int"
        ct = c_type(pts[bk])
        expr = "(" + ct + ")(uintptr_t)args[" + bk.to_s + "]"
      end
      s = s + "  " + ct + " lv_" + bps[bk] + " = " + expr + ";\n"
      bk = bk + 1
    end
    s
  end

  def compile_proc_literal(nid, blk_param_types = "")
    blk = @nd_block[nid]
    if blk < 0
      return "sp_proc_new(NULL, NULL, NULL)"
    end
 # Collect every block param name. Single-param blocks fall through
 # to the existing `_unused` fallback for parameterless bodies.
    bps = "".split(",", -1)
    pi = 0
    pn = get_block_param(nid, pi)
    while pn != ""
      bps.push(pn)
      pi = pi + 1
      pn = get_block_param(nid, pi)
    end
    if bps.length == 0
      bps.push("_unused")
    end
 # Generate a static function for the proc body
    @proc_counter = @proc_counter + 1
    pid = @proc_counter
    fname = "_sp_proc_fn_" + pid.to_s
    cap_name = "_proc_cap_" + pid.to_s
    cap_scan_name = "_proc_cap_scan_" + pid.to_s
    bbody = @nd_body[blk]

 # Detect captures (free variables that resolve in outer scope).
 # Every block param is in scope inside the body; only locals from
 # the outer scope read inside the body count as free.
    free_vars = "".split(",", -1)
    if bbody >= 0
 # scan_lambda_free_vars treats `params` as read-only, so bps can
 # be passed directly without an intermediate copy.
      proc_locals = "".split(",", -1)
      scan_lambda_free_vars(bbody, bps, proc_locals, free_vars)
    end
    captures = "".split(",", -1)
    capture_types = "".split(",", -1)
    fk = 0
    while fk < free_vars.length
      fv = free_vars[fk]
      vt = find_var_type(fv)
      if vt != ""
        captures.push(fv)
        capture_types.push(vt)
      end
      fk = fk + 1
    end
    has_captures = 0
    if captures.length > 0
      has_captures = 1
    end

 # Compile the body. While captures > 0, set @in_proc_body so that
 # compile_expr's fiber_var_ref rewrites captured-var reads/writes to
 # (*_cap->VN). Heap promotion of those vars in the enclosing scope is
 # done after body compile (so cells exist before they're referenced
 # in the cap struct allocation).
    save_out = @out_lines
    @out_lines = "".split(",", -1)
    saved_in_proc_body = @in_proc_body
    saved_proc_captures = @proc_captures
    saved_proc_capture_types = @proc_capture_types
    saved_heap_hp_names_len = @heap_promoted_names.length
    saved_heap_hp_cells_len = @heap_promoted_cells.length
    if has_captures == 1
      @in_proc_body = 1
      @proc_captures = captures
      @proc_capture_types = capture_types
    else
      @in_proc_body = 0
      @proc_captures = "".split(",", -1)
      @proc_capture_types = "".split(",", -1)
    end
    push_scope
    pts = "".split("|", -1)
    if blk_param_types != ""
      pts = blk_param_types.split("|", -1)
    end
    di = 0
    while di < bps.length
      pt = "int"
      if di < pts.length && pts[di] != ""
        pt = pts[di]
      end
      declare_var(bps[di], pt)
      di = di + 1
    end
    bexpr = "0"
    bexpr_t_proc = "int"
    body_stmts = ""
    if bbody >= 0
      bs = get_stmts(bbody)
      if bs.length > 0
        k = 0
        while k < bs.length
          lt = infer_type(bs[k])
          if k == bs.length - 1
            last_t = @nd_type[bs[k]]
            if last_t == "LocalVariableWriteNode" || last_t == "LocalVariableOperatorWriteNode"
              compile_stmt(bs[k])
              body_stmts = @out_lines.join(10.chr) + 10.chr
              @out_lines = "".split(",", -1)
              bexpr = fiber_var_ref(@nd_name[bs[k]])
              bexpr_t_proc = find_var_type(@nd_name[bs[k]])
            elsif lt != "void"
              body_stmts = @out_lines.join(10.chr) + 10.chr
              @out_lines = "".split(",", -1)
              bexpr = compile_expr(bs[k])
              bexpr_t_proc = lt
              extra = @out_lines.join(10.chr) + 10.chr
              @out_lines = "".split(",", -1)
              body_stmts = body_stmts + extra
            else
              compile_stmt(bs[k])
            end
          else
            compile_stmt(bs[k])
          end
          k = k + 1
        end
        if body_stmts == ""
          body_stmts = @out_lines.join(10.chr) + 10.chr
          @out_lines = "".split(",", -1)
        end
      end
    end
 # Proc fn ABI returns mrb_int regardless of body type. Unbox a
 # bigint body tail before return so the function signature
 # matches; analogous to the same coerce in compile_yield_call
 # _expr's tail. Also peek arith operands so a stale "int"
 # bexpr_t_proc gets upgraded.
    if base_type(bexpr_t_proc) != "bigint" && bbody >= 0
      bs_chk = get_stmts(bbody)
      if bs_chk.length > 0
        bt_last = bs_chk.last
        if @nd_type[bt_last] == "CallNode"
          bmn_proc = @nd_name[bt_last]
          if bmn_proc == "+" || bmn_proc == "-" || bmn_proc == "*" || bmn_proc == "/" || bmn_proc == "%" || bmn_proc == "**"
            br_proc = @nd_receiver[bt_last]
            if br_proc >= 0 && base_type(infer_type(br_proc)) == "bigint"
              bexpr_t_proc = "bigint"
            else
              ba_proc = @nd_arguments[bt_last]
              if ba_proc >= 0
                aa_proc = get_args(ba_proc)
                if aa_proc.length > 0 && base_type(infer_type(aa_proc[0])) == "bigint"
                  bexpr_t_proc = "bigint"
                end
              end
            end
          end
        end
      end
    end
    if base_type(bexpr_t_proc) == "bigint"
      @needs_bigint = 1
      bexpr = "sp_bigint_to_int((sp_Bigint *)(" + bexpr + "))"
    end
    pop_scope
    @in_proc_body = saved_in_proc_body
    @proc_captures = saved_proc_captures
    @proc_capture_types = saved_proc_capture_types
    while @heap_promoted_names.length > saved_heap_hp_names_len
      @heap_promoted_names.pop
    end
    while @heap_promoted_cells.length > saved_heap_hp_cells_len
      @heap_promoted_cells.pop
    end
    @out_lines = save_out

    if has_captures == 1
 # Emit per-proc capture struct + scan function + body fn that casts
 # the void* cap to the typed struct.
      @lambda_funcs << "typedef struct { "
      k = 0
      while k < captures.length
        @lambda_funcs << c_type(capture_types[k])
        @lambda_funcs << " *"
        @lambda_funcs << captures[k]
        @lambda_funcs << "; "
        k = k + 1
      end
      @lambda_funcs << "} "
      @lambda_funcs << cap_name
      @lambda_funcs << ";\n"
      @lambda_funcs << "static void "
      @lambda_funcs << cap_scan_name
      @lambda_funcs << "(void *p) {\n"
      @lambda_funcs << "  "
      @lambda_funcs << cap_name
      @lambda_funcs << " *_c = ("
      @lambda_funcs << cap_name
      @lambda_funcs << " *)p;\n"
      k = 0
      while k < captures.length
        @lambda_funcs << "  if (_c->"
        @lambda_funcs << captures[k]
        @lambda_funcs << ") sp_gc_mark((void *)_c->"
        @lambda_funcs << captures[k]
        @lambda_funcs << ");\n"
        k = k + 1
      end
      @lambda_funcs << "}\n"
      @lambda_funcs << "static mrb_int "
      @lambda_funcs << fname
      @lambda_funcs << "(void *_cap_raw, mrb_int *args) {\n"
      @lambda_funcs << proc_fn_args_unpack(bps, pts)
      @lambda_funcs << "  "
      @lambda_funcs << cap_name
      @lambda_funcs << " *_cap = ("
      @lambda_funcs << cap_name
      @lambda_funcs << " *)_cap_raw;\n"
      if body_stmts != ""
        @lambda_funcs << body_stmts
      end
      @lambda_funcs << "  return "
      @lambda_funcs << bexpr
      @lambda_funcs << ";\n}\n"

 # In the enclosing scope: heap-promote each captured local (allocate
 # a cell, copy current value into it, register so subsequent
 # references in the enclosing scope go through the cell), then
 # allocate the cap struct and populate its pointers.
      k = 0
      while k < captures.length
        vn = captures[k]
        ct = c_type(capture_types[k])
        already_promoted = 0
        ci = 0
        while ci < @heap_promoted_names.length
          if @heap_promoted_names[ci] == vn
            already_promoted = 1
          end
          ci = ci + 1
        end
        if already_promoted == 0
          if @in_proc_body == 1 && proc_capture_index(vn) >= 0
            cell = "_cap->" + vn
          else
            cell = "_hcell_" + vn + "_p" + pid.to_s
            emit("  " + ct + " *" + cell + " = (" + ct + " *)sp_gc_alloc(sizeof(" + ct + "), NULL, NULL);")
            emit("  *" + cell + " = " + fiber_var_ref(vn) + ";")
          end
          @heap_promoted_names.push(vn)
          @heap_promoted_cells.push(cell)
        end
        k = k + 1
      end
      cap_ptr = "_cap_ptr_p" + pid.to_s
      emit("  " + cap_name + " *" + cap_ptr + " = (" + cap_name + " *)sp_gc_alloc(sizeof(" + cap_name + "), NULL, " + cap_scan_name + ");")
      k = 0
      while k < captures.length
        vn = captures[k]
        ci = 0
        cell = ""
        while ci < @heap_promoted_names.length
          if @heap_promoted_names[ci] == vn
            cell = @heap_promoted_cells[ci]
          end
          ci = ci + 1
        end
        emit("  " + cap_ptr + "->" + vn + " = " + cell + ";")
        k = k + 1
      end
      return "sp_proc_new(" + fname + ", " + cap_ptr + ", " + cap_scan_name + ")"
    end

 # No captures: file-scope function with unused cap arg, sp_proc_new
 # with NULL cap and NULL scan.
    @lambda_funcs << "static mrb_int "
    @lambda_funcs << fname
    @lambda_funcs << "(void *_cap, mrb_int *args) {\n"
    @lambda_funcs << "  (void)_cap;\n"
    @lambda_funcs << proc_fn_args_unpack(bps, pts)
    if body_stmts != ""
      @lambda_funcs << body_stmts
    end
    @lambda_funcs << "  return "
    @lambda_funcs << bexpr
    @lambda_funcs << ";\n}\n"
    return "sp_proc_new(" + fname + ", NULL, NULL)"
  end

  def compile_bracket_assign(nid)
    recv = @nd_receiver[nid]
    rt = infer_type(recv)
 # When the recv is a local whose declared C slot type is a
 # different (wider) hash variant than the analyzer's per-call-
 # site infer_type, prefer the declared type. The analyzer's
 # refine_method_body_locals pass-2 widens locals to str_poly_hash
 # when cross-type writes flow in (the post-#610 follow-on shape
 # from #613); the matching scope decl already lays the local
 # down as sp_StrPolyHash *, but infer_type may still report
 # the un-widened str_str_hash from the initial `.dup`-from-
 # str_str_hash writer. Dispatching on the un-widened type emits
 # sp_StrStrHash_set against an sp_StrPolyHash * slot — hard cc
 # error.
    if @nd_type[recv] == "LocalVariableReadNode"
      decl_rt = find_var_declared_type(@nd_name[recv])
      if decl_rt != "" && decl_rt != rt && is_hash_type(decl_rt) == 1
        rt = decl_rt
      end
    end
 # Nullable hash receivers (`str_str_hash?` etc.) should dispatch
 # identically to the base hash; NULL-check semantics live at the
 # caller, mirroring compile_call_expr's strip-? handling. Without
 # this, `<str_str_hash?>[k] = v` fell through every arm and
 # emitted nothing — the silent-elision shape reported in #610.
    if is_nullable_pointer_type(rt) == 1 && is_nullable_type(rt) == 1
      rt = base_type(rt)
    end
    rc = compile_expr_gc_rooted(recv)
    args_id = @nd_arguments[nid]
    arg_ids = []
    if args_id >= 0
      arg_ids = get_args(args_id)
    end
 # Slice assignment `arr[i, n] = src`: replace n elements
 # starting at index i with the elements of src. Same-length
 # only (n == src.length); resize semantics not yet supported.
 # Only fires when both sides are the same C kind — falls
 # through otherwise to avoid silent miscompiles on mistyped
 # inputs (e.g. an `int_array`-typed src that's actually an
 # array-of-IntArrays would copy the wrong shape).
    if arg_ids.length == 3 && (rt == "int_array" || rt == "float_array" || rt == "str_array" || rt == "sym_array" || is_ptr_array_type(rt) == 1 || rt == "poly_array")
      src_t_check = infer_type(arg_ids[2])
      if array_c_prefix(rt) == array_c_prefix(src_t_check) && (src_t_check == "int_array" || src_t_check == "float_array" || src_t_check == "str_array" || src_t_check == "sym_array" || is_ptr_array_type(src_t_check) == 1 || src_t_check == "poly_array")
        compile_slice_assign(nid, recv, rt, rc, arg_ids)
        return
      end
    end
 # Slice assignment with poly recv: `@bg_pixels[xfine, 8] =
 # pattern_lut[bg_pattern]` against an iv typed as poly (because
 # widening saw it as either an int_array or a poly_array at
 # different points). Without this, the fall-through `[]=` path
 # would treat arg_ids[1] (the slice length) as the value to
 # store and silently drop the actual rhs. Dispatch by runtime
 # cls_id and copy len elements from src to dest.
    if arg_ids.length == 3 && rt == "poly"
      compile_poly_slice_assign(nid, recv, rc, arg_ids)
      return
    end
 # Slice assignment with poly_array recv and poly src: the recv
 # is statically typed (sp_PolyArray *) but src is sp_RbVal —
 # fold into compile_poly_slice_assign by pre-boxing the recv to
 # sp_RbVal so the runtime cls_id dispatch can pick the right
 # copy loop. This is the shape `@bg_pixels[xfine, 8] =
 # @bg_pattern_lut[@bg_pattern]` ends up in once a 3-level array
 # constant (TILE_LUT) types its inner-of-inner reads as poly.
    if arg_ids.length == 3 && rt == "poly_array"
      src_t_check2 = infer_type(arg_ids[2])
      if src_t_check2 == "poly"
        @needs_rb_value = 1
        compile_poly_slice_assign(nid, recv, "sp_box_poly_array(" + rc + ")", arg_ids)
        return
      end
    end
    idx = "0"
    val = "0"
    if arg_ids.length >= 1
      if rt == "str_int_hash" || rt == "str_str_hash"
        idx = compile_expr_as_string(arg_ids[0])
      else
        idx = compile_expr(arg_ids[0])
 # Auto-unbox poly index for typed-array recv. The block-param
 # iteration over a poly recv (compile_each_block's poly arm)
 # delivers `lv_<bp>` as sp_RbVal, but a downstream
 # `@arr[bp] = v` against a typed array expects an mrb_int.
        idx_t = infer_type(arg_ids[0])
        if idx_t == "poly" && (rt == "int_array" || rt == "float_array" || rt == "str_array" || rt == "sym_array" || is_ptr_array_type(rt) == 1 || rt == "poly_array")
          idx = "(" + idx + ").v.i"
        end
 # Same auto-unbox for typed-hash recv whose key half is sym /
 # str / int. `other.each { |k, v| result[k] = v }` over a poly
 # `other` lands here when `result` is sym_poly_hash etc; without
 # the unbox we'd pass sp_RbVal to sp_SymPolyHash_set's sp_sym
 # parameter. Issue #634 shape B cascade.
        if idx_t == "poly" && (rt == "sym_int_hash" || rt == "sym_str_hash" || rt == "sym_poly_hash")
          idx = "(" + idx + ").v.sym"
        end
        if idx_t == "poly" && rt == "int_str_hash"
          idx = "(" + idx + ").v.i"
        end
 # promote-mode-widened idx for int-keyed receivers.
        if idx_t == "bigint" && (rt == "int_array" || rt == "float_array" || rt == "str_array" || rt == "sym_array" || is_ptr_array_type(rt) == 1 || rt == "poly_array" || rt == "int_str_hash")
          @needs_bigint = 1
          idx = "sp_bigint_to_int((sp_Bigint *)" + idx + ")"
        end
      end
    end
    if arg_ids.length >= 2
      val = compile_expr(arg_ids[1])
    end
    if rt == "int_str_hash"
      emit("  sp_IntStrHash_set(" + rc + ", " + idx + ", " + val + ");")
      return
    end
 # str_int_hash / str_str_hash were both missing here previously,
 # so `<str_str_hash>[k] = v` fell through compile_bracket_assign
 # with no emit at all — the silent-elision shape reported in #610
 # where a typed-hash write inside a `.each` block disappeared.
 # The value side coerces through compile_expr_as_int /
 # compile_expr_as_string so a poly-typed RHS (the canonical
 # `v.is_a?(Hash) ? ... : v` ternary shape) unboxes to the cell's
 # stored type rather than dropping silently.
    if rt == "str_int_hash"
      val_int = compile_expr_as_int(arg_ids[1])
      emit("  sp_StrIntHash_set(" + rc + ", " + idx + ", " + val_int + ");")
      return
    end
    if rt == "str_str_hash"
      val_str = compile_expr_as_string(arg_ids[1])
      emit("  sp_StrStrHash_set(" + rc + ", " + idx + ", " + val_str + ");")
      return
    end
    if rt == "sym_int_hash"
      val_sih = val
      if arg_ids.length >= 2 && infer_type(arg_ids[1]) == "bigint"
        @needs_bigint = 1
        val_sih = "sp_bigint_to_int((sp_Bigint *)" + val + ")"
      end
      emit("  sp_SymIntHash_set(" + rc + ", " + idx + ", " + val_sih + ");")
      return
    end
    if rt == "sym_str_hash"
      emit("  sp_SymStrHash_set(" + rc + ", " + idx + ", " + val + ");")
      return
    end
    if rt == "sym_poly_hash"
      boxed = val
      if arg_ids.length >= 2
        boxed = box_expr_to_poly(arg_ids[1])
      end
      emit("  sp_SymPolyHash_set(" + rc + ", " + idx + ", " + boxed + ");")
      return
    end
    if rt == "str_poly_hash"
      idx_s = compile_expr_as_string(arg_ids[0])
      boxed = val
      if arg_ids.length >= 2
        boxed = box_expr_to_poly(arg_ids[1])
      end
      emit("  sp_StrPolyHash_set(" + rc + ", " + idx_s + ", " + boxed + ");")
      return
    end
    if rt == "poly_poly_hash"
      key_boxed = box_expr_to_poly(arg_ids[0])
      val_boxed = val
      if arg_ids.length >= 2
        val_boxed = box_expr_to_poly(arg_ids[1])
      end
      emit("  sp_PolyPolyHash_set(" + rc + ", " + key_boxed + ", " + val_boxed + ");")
      return
    end
    if rt == "int_array"
 # Check if value is an object pointer - needs cast
      vt = "int"
      if arg_ids.length >= 2
        vt = infer_type(arg_ids[1])
      end
      if is_obj_type(vt) == 1
        emit("  sp_IntArray_set(" + rc + ", " + idx + ", (mrb_int)" + val + ");")
      else
        emit("  sp_IntArray_set(" + rc + ", " + idx + ", " + val + ");")
      end
      return
    end
    if rt == "float_array"
      emit("  sp_FloatArray_set(" + rc + ", " + idx + ", " + val + ");")
      return
    end
    if rt == "str_array"
      emit("  sp_StrArray_set(" + rc + ", " + idx + ", " + val + ");")
      return
    end
    if is_ptr_array_type(rt) == 1
      emit("  sp_PtrArray_set(" + rc + ", " + idx + ", (void *)" + val + ");")
      return
    end
    if rt == "poly_array"
      vbox = val
      if arg_ids.length >= 2
        vt = infer_type(arg_ids[1])
        if vt != "poly"
          vbox = box_value_to_poly(vt, val)
        end
      end
      emit("  sp_PolyArray_set(" + rc + ", " + idx + ", " + vbox + ");")
      return
    end
    if rt == "poly"
 # Statically string index: the array arms below (PolyArray /
 # PtrArray / IntArray) all expect an mrb_int index and would
 # fail C compile when called with a `const char *`. The chained
 # `outer[k1][k2] = v` shape where outer is StrPolyHash lands
 # here — `outer[k1]` returns sp_RbVal which may be any hash
 # storage at runtime. Emit Hash setter arms instead, keyed by
 # the same cls_id dispatch.
      idx_t_poly = arg_ids.length >= 1 ? infer_type(arg_ids[0]) : ""
      val_t_poly = arg_ids.length >= 2 ? infer_type(arg_ids[1]) : "int"
      if idx_t_poly == "string" || idx_t_poly == "mutable_str"
        @needs_rb_value = 1
        @needs_str_int_hash = 1
        @needs_str_str_hash = 1
        @needs_str_poly_hash = 1
        vbox = val
        if val_t_poly != "poly"
          vbox = box_value_to_poly(val_t_poly, val)
        end
        vbox_tmp = new_temp
        emit("  sp_RbVal " + vbox_tmp + " = " + vbox + ";")
        cur_h = new_temp
        emit("  sp_RbVal " + cur_h + " = " + rc + ";")
        emit("  if (" + cur_h + ".cls_id == SP_BUILTIN_STR_INT_HASH) sp_StrIntHash_set((sp_StrIntHash *)" + cur_h + ".v.p, " + idx + ", " + vbox_tmp + ".v.i);")
        emit("  else if (" + cur_h + ".cls_id == SP_BUILTIN_STR_STR_HASH) sp_StrStrHash_set((sp_StrStrHash *)" + cur_h + ".v.p, " + idx + ", " + vbox_tmp + ".v.s);")
        emit("  else if (" + cur_h + ".cls_id == SP_BUILTIN_STR_POLY_HASH) sp_StrPolyHash_set((sp_StrPolyHash *)" + cur_h + ".v.p, " + idx + ", " + vbox_tmp + ");")
        return
      end
 # Symbol index + poly recv: mirror of the string-idx arm above
 # for Sym*Hash variants. Surfaces in `arr[i][:k] = v` where the
 # outer container is a poly_array of boxed sym_int_hash /
 # sym_poly_hash. Without this arm the assignment silently no-ops
 # (falls through to Array arms that never match).
      if idx_t_poly == "symbol"
        @needs_rb_value = 1
        vbox = val
        if val_t_poly != "poly"
          vbox = box_value_to_poly(val_t_poly, val)
        end
        vbox_tmp = new_temp
        emit("  sp_RbVal " + vbox_tmp + " = " + vbox + ";")
        cur_h = new_temp
        emit("  sp_RbVal " + cur_h + " = " + rc + ";")
        emit("  if (" + cur_h + ".cls_id == SP_BUILTIN_SYM_INT_HASH) sp_SymIntHash_set((sp_SymIntHash *)" + cur_h + ".v.p, (sp_sym)(" + idx + "), " + vbox_tmp + ".v.i);")
        emit("  else if (" + cur_h + ".cls_id == SP_BUILTIN_SYM_POLY_HASH) sp_SymPolyHash_set((sp_SymPolyHash *)" + cur_h + ".v.p, (sp_sym)(" + idx + "), " + vbox_tmp + ");")
        return
      end
 # Poly index (sp_RbVal): the key's concrete type isn't known
 # statically, so the dispatch must read the key's tag at
 # runtime. Surfaces in `merged[k] = v` inside an `each`
 # iteration over a poly-recv hash (real-blog Main.run's
 # request[:params].each forwards both k and v as poly). Emit:
 #
 # - SP_TAG_STR keys: route to Str*Hash setters via .v.s
 # - SP_TAG_SYM keys: route to Sym*Hash setters via .v.i
 # - other key tags fall through to the Array arms below
 #   (which unbox via .v.i)
      if idx_t_poly == "poly"
        @needs_rb_value = 1
        @needs_str_int_hash = 1
        @needs_str_str_hash = 1
        @needs_str_poly_hash = 1
        vbox = val
        if val_t_poly != "poly"
          vbox = box_value_to_poly(val_t_poly, val)
        end
        vbox_tmp = new_temp
        emit("  sp_RbVal " + vbox_tmp + " = " + vbox + ";")
        cur_p = new_temp
        emit("  sp_RbVal " + cur_p + " = " + rc + ";")
 # String-tagged key + Str*Hash recv. The `(" + idx + ").v.s`
 # cast extracts the const char * payload.
        emit("  if ((" + idx + ").tag == SP_TAG_STR && " + cur_p + ".cls_id == SP_BUILTIN_STR_INT_HASH) sp_StrIntHash_set((sp_StrIntHash *)" + cur_p + ".v.p, (" + idx + ").v.s, " + vbox_tmp + ".v.i);")
        emit("  else if ((" + idx + ").tag == SP_TAG_STR && " + cur_p + ".cls_id == SP_BUILTIN_STR_STR_HASH) sp_StrStrHash_set((sp_StrStrHash *)" + cur_p + ".v.p, (" + idx + ").v.s, " + vbox_tmp + ".v.s);")
        emit("  else if ((" + idx + ").tag == SP_TAG_STR && " + cur_p + ".cls_id == SP_BUILTIN_STR_POLY_HASH) sp_StrPolyHash_set((sp_StrPolyHash *)" + cur_p + ".v.p, (" + idx + ").v.s, " + vbox_tmp + ");")
 # Symbol-tagged key + Sym*Hash recv. sp_SymPolyHash is in
 # sp_runtime.h unconditionally; the sym_int_hash / sym_str_hash
 # variants are emit-gated and may not have typedefs, so only
 # SymPolyHash is dispatched here.
        emit("  else if ((" + idx + ").tag == SP_TAG_SYM && " + cur_p + ".cls_id == SP_BUILTIN_SYM_POLY_HASH) sp_SymPolyHash_set((sp_SymPolyHash *)" + cur_p + ".v.p, (sp_sym)(" + idx + ").v.i, " + vbox_tmp + ");")
 # Int-tagged key + Array storage. Fall through to the existing
 # Array arms by using `(" + idx + ").v.i` as the index.
        emit("  else if ((" + idx + ").tag == SP_TAG_INT && " + cur_p + ".cls_id == SP_BUILTIN_POLY_ARRAY) sp_PolyArray_set((sp_PolyArray *)" + cur_p + ".v.p, (" + idx + ").v.i, " + vbox_tmp + ");")
        emit("  else if ((" + idx + ").tag == SP_TAG_INT && " + cur_p + ".cls_id == SP_BUILTIN_PTR_ARRAY) sp_PtrArray_set((sp_PtrArray *)" + cur_p + ".v.p, (" + idx + ").v.i, " + vbox_tmp + ".v.p);")
        emit("  else if ((" + idx + ").tag == SP_TAG_INT && " + cur_p + ".cls_id == SP_BUILTIN_INT_ARRAY) sp_IntArray_set((sp_IntArray *)" + cur_p + ".v.p, (" + idx + ").v.i, " + vbox_tmp + ".v.i);")
        return
      end
 # Slot is sp_RbVal — runtime cls_id determines which storage
 # the underlying pointer points at. Optcarrot's `@fetch[a] =
 # method(:peek_X)` lands here when @fetch was widened to poly
 # (rather than poly_array) by the heterogeneous IntArray + Method
 # writes. Dispatch by cls_id at runtime.
 #
 # When the slot's runtime storage is IntArray but the value
 # being stored is non-int (a pointer / poly with cls_id != 0),
 # we'd lose the cls_id by storing as int. Widen the storage at
 # runtime: allocate a fresh PolyArray, copy the existing int
 # elements as boxed-int, then store the new value boxed. Update
 # the slot to hold the new PolyArray. Requires knowing where
 # the slot is — only fires when recv is an ivar / local / cvar
 # / gvar that we can reassign in C.
      vbox = val
      vt = "int"
      if arg_ids.length >= 2
        vt = infer_type(arg_ids[1])
        if vt != "poly"
          vbox = box_value_to_poly(vt, val)
        end
      end
      vbox_tmp = new_temp
      emit("  sp_RbVal " + vbox_tmp + " = " + vbox + ";")
 # Determine the slot expression — what we'd assign to in order
 # to replace the storage. Only ivar / local / cvar / gvar are
 # supported; anything else falls back to no-widen (still
 # correct for the homogeneous cases, just not heterogeneous).
      slot_lhs = ""
      if @nd_type[recv] == "InstanceVariableReadNode"
        slot_lhs = self_arrow + sanitize_ivar(@nd_name[recv])
      elsif @nd_type[recv] == "LocalVariableReadNode"
        slot_lhs = fiber_var_ref(@nd_name[recv])
      end
      if slot_lhs != ""
        @needs_gc = 1
        @needs_rb_value = 1
        cur = new_temp
        new_arr = new_temp
        old_int = new_temp
        ii = new_temp
        emit("  sp_RbVal " + cur + " = " + rc + ";")
 # Widen path: if storage is IntArray but value can't fit int
 # (i.e. value carries cls_id != 0 or tag != INT, meaning it's
 # a typed pointer/box that loses info if cast to int).
        emit("  if (" + cur + ".cls_id == SP_BUILTIN_INT_ARRAY && (" + vbox_tmp + ".tag != SP_TAG_INT || " + vbox_tmp + ".cls_id != 0)) {")
        emit("    sp_IntArray *" + old_int + " = (sp_IntArray *)" + cur + ".v.p;")
        emit("    sp_PolyArray *" + new_arr + " = sp_PolyArray_new();")
        emit("    for (mrb_int " + ii + " = 0; " + ii + " < sp_IntArray_length(" + old_int + "); " + ii + "++) sp_PolyArray_push(" + new_arr + ", sp_box_int(sp_IntArray_get(" + old_int + ", " + ii + ")));")
        emit("    sp_PolyArray_set(" + new_arr + ", " + idx + ", " + vbox_tmp + ");")
        emit("    " + slot_lhs + " = sp_box_poly_array(" + new_arr + ");")
        emit("  } else if (" + cur + ".cls_id == SP_BUILTIN_POLY_ARRAY) {")
        emit("    sp_PolyArray_set((sp_PolyArray *)" + cur + ".v.p, " + idx + ", " + vbox_tmp + ");")
        emit("  } else if (" + cur + ".cls_id == SP_BUILTIN_PTR_ARRAY) {")
        emit("    sp_PtrArray_set((sp_PtrArray *)" + cur + ".v.p, " + idx + ", " + vbox_tmp + ".v.p);")
        emit("  } else if (" + cur + ".cls_id == SP_BUILTIN_INT_ARRAY) {")
        emit("    sp_IntArray_set((sp_IntArray *)" + cur + ".v.p, " + idx + ", " + vbox_tmp + ".v.i);")
        emit("  }")
      else
        emit("  if (" + rc + ".cls_id == SP_BUILTIN_POLY_ARRAY) sp_PolyArray_set((sp_PolyArray *)" + rc + ".v.p, " + idx + ", " + vbox_tmp + ");")
        emit("  else if (" + rc + ".cls_id == SP_BUILTIN_PTR_ARRAY) sp_PtrArray_set((sp_PtrArray *)" + rc + ".v.p, " + idx + ", " + vbox_tmp + ".v.p);")
        emit("  else if (" + rc + ".cls_id == SP_BUILTIN_INT_ARRAY) sp_IntArray_set((sp_IntArray *)" + rc + ".v.p, " + idx + ", " + vbox_tmp + ".v.i);")
      end
      return
    end
    if rt == "str_int_hash"
      emit("  sp_StrIntHash_set(" + rc + ", " + idx + ", " + val + ");")
      return
    end
    if rt == "str_str_hash"
      emit("  sp_StrStrHash_set(" + rc + ", " + idx + ", " + val + ");")
      return
    end
 # user-class `def []=(key, value)`. The recv is a
 # typed instance (`obj_<C>`); dispatch to the class's `_aset`
 # method, with arg boxing matching the method's declared
 # param types (a `value` param widened to poly takes the rhs
 # box, a typed param takes it raw).
    if is_obj_type(rt) == 1
      bt_aset = base_type(rt)
      cname_aset = bt_aset[4, bt_aset.length - 4]
      ci_aset = find_class_idx(cname_aset)
      if ci_aset >= 0
        owner_aset = find_method_owner(ci_aset, "[]=")
        if owner_aset != ""
          owner_ci_aset = find_class_idx(owner_aset)
          midx_aset = cls_find_method_direct(owner_ci_aset, "[]=")
          if midx_aset >= 0
            ca_aset = compile_typed_call_args(nid, owner_ci_aset, midx_aset, 0)
            recv_arg_aset = owner_aset == cname_aset ? rc : "(sp_" + owner_aset + " *)" + rc
            tail_aset = ca_aset != "" ? ", " + ca_aset : ""
 # Self-receiver override dispatch for `self[k] = v`. When
 # the recv is `self` inside a parent body and descendants
 # of @current_class_idx override `[]=`, emit a
 # switch (self->cls_id) so the dispatch lands on the
 # override. Same shape as compile_user_class_method_expr's
 # `self[]` arm. Issue #563.
            recv_id_so_a = recv
            if recv_id_so_a >= 0 && @nd_type[recv_id_so_a] == "SelfNode" && @current_class_idx >= 0 && @cls_is_value_type[@current_class_idx] == 0
              ovr_pairs_a = cls_method_override_descendants(@current_class_idx, owner_ci_aset, "[]=", "imeth")
              if ovr_pairs_a != ""
                base_pt_a = cls_meth_ptypes_get(owner_ci_aset, midx_aset)
                pt_ok_a = cls_imeth_override_ptypes_match(ovr_pairs_a, "[]=", base_pt_a)
                if pt_ok_a == 1
                  emit("  switch (" + rc + "->cls_id) {")
                  ovr_list_a = ovr_pairs_a.split(";", -1)
                  ol_a = 0
                  while ol_a < ovr_list_a.length
                    p_a = ovr_list_a[ol_a].split(",", -1)
                    cand_internal_a = p_a[0].to_i
                    cand_cid_a = cls_id_for_user_internal(cand_internal_a)
                    cand_owner_a = p_a[1].to_i
                    cand_name_a = @cls_names[cand_owner_a]
                    emit("    case " + cand_cid_a.to_s + "LL: sp_" + cand_name_a + "__aset((sp_" + cand_name_a + " *)" + rc + tail_aset + "); break;")
                    ol_a = ol_a + 1
                  end
                  emit("    default: sp_" + owner_aset + "__aset(" + recv_arg_aset + tail_aset + "); break;")
                  emit("  }")
                  return
                end
              end
            end
            emit("  sp_" + owner_aset + "__aset(" + recv_arg_aset + tail_aset + ");")
            return
          end
        end
      end
    end
  end

 # `arr[start, len] = src` where arr is a poly-typed slot (sp_RbVal).
 # Dispatches by runtime cls_id of arr and src and emits a per-index
 # copy. Same-length only — `src.length` must equal `len`. Falls
 # back silently when src isn't an array (no copy emitted).
  def compile_poly_slice_assign(nid, recv, rc, arg_ids)
    @needs_rb_value = 1
    start_id = arg_ids[0]
    len_id = arg_ids[1]
    src_id = arg_ids[2]
    start_e = compile_expr(start_id)
    len_e = compile_expr(len_id)
    src_e = compile_expr_gc_rooted(src_id)
    src_t = infer_type(src_id)
 # Box src to poly so we can switch on cls_id at runtime even when
 # spinel statically inferred a concrete array kind (e.g. when src
 # is `pattern_lut[bg_pattern]` returning a poly value boxed from
 # a typed array push).
    if src_t != "poly"
      src_e = box_value_to_poly(src_t, src_e)
    end
    rc_t = new_temp
    src_t_v = new_temp
    start_t = new_temp
    len_t = new_temp
    ii = new_temp
    emit("  {")
    emit("    sp_RbVal " + rc_t + " = " + rc + ";")
    emit("    sp_RbVal " + src_t_v + " = " + src_e + ";")
    emit("    mrb_int " + start_t + " = " + start_e + ";")
    emit("    mrb_int " + len_t + " = " + len_e + ";")
    emit("    if (" + rc_t + ".cls_id == SP_BUILTIN_INT_ARRAY && " + src_t_v + ".cls_id == SP_BUILTIN_INT_ARRAY) {")
    emit("      for (mrb_int " + ii + " = 0; " + ii + " < " + len_t + "; " + ii + "++) sp_IntArray_set((sp_IntArray *)" + rc_t + ".v.p, " + start_t + " + " + ii + ", sp_IntArray_get((sp_IntArray *)" + src_t_v + ".v.p, " + ii + "));")
    emit("    } else if (" + rc_t + ".cls_id == SP_BUILTIN_POLY_ARRAY && " + src_t_v + ".cls_id == SP_BUILTIN_POLY_ARRAY) {")
    emit("      for (mrb_int " + ii + " = 0; " + ii + " < " + len_t + "; " + ii + "++) sp_PolyArray_set((sp_PolyArray *)" + rc_t + ".v.p, " + start_t + " + " + ii + ", sp_PolyArray_get((sp_PolyArray *)" + src_t_v + ".v.p, " + ii + "));")
    emit("    } else if (" + rc_t + ".cls_id == SP_BUILTIN_INT_ARRAY && " + src_t_v + ".cls_id == SP_BUILTIN_POLY_ARRAY) {")
    emit("      for (mrb_int " + ii + " = 0; " + ii + " < " + len_t + "; " + ii + "++) sp_IntArray_set((sp_IntArray *)" + rc_t + ".v.p, " + start_t + " + " + ii + ", sp_PolyArray_get((sp_PolyArray *)" + src_t_v + ".v.p, " + ii + ").v.i);")
    emit("    } else if (" + rc_t + ".cls_id == SP_BUILTIN_POLY_ARRAY && " + src_t_v + ".cls_id == SP_BUILTIN_INT_ARRAY) {")
    emit("      for (mrb_int " + ii + " = 0; " + ii + " < " + len_t + "; " + ii + "++) sp_PolyArray_set((sp_PolyArray *)" + rc_t + ".v.p, " + start_t + " + " + ii + ", sp_box_int(sp_IntArray_get((sp_IntArray *)" + src_t_v + ".v.p, " + ii + ")));")
    emit("    }")
    emit("  }")
  end

 # Compile `arr[start, len] = src` slice assignment. Replaces
 # `len` elements of `arr` starting at `start` with the elements
 # of `src`. Same-length only — `src.length` must equal `len` at
 # runtime; resize semantics not implemented. Each index `i in
 # 0...len` is emitted as `arr[start + i] = src[i]`.
  def compile_slice_assign(nid, recv, rt, rc, arg_ids)
    start_id = arg_ids[0]
    len_id = arg_ids[1]
    src_id = arg_ids[2]
    src_t = infer_type(src_id)
    start_e = compile_expr(start_id)
    len_e = compile_expr(len_id)
    src_e = compile_expr_gc_rooted(src_id)
    pfx = array_c_prefix(rt)
    src_pfx = array_c_prefix(src_t)
    if pfx == "" || src_pfx == ""
      return
    end
    rc_t = new_temp
    src_t_v = new_temp
    start_t = new_temp
    ii = new_temp
    emit("  {")
    emit("    sp_" + pfx + " *" + rc_t + " = " + rc + ";")
    emit("    sp_" + src_pfx + " *" + src_t_v + " = " + src_e + ";")
    emit("    mrb_int " + start_t + " = " + start_e + ";")
    emit("    mrb_int _n = " + len_e + ";")
 # Inner loop: copy n elements from src to dest. Casting between
 # array kinds isn't supported here (e.g. int_array ← float_array
 # would silently truncate); both must be the same C kind.
    if pfx == src_pfx
      emit("    for (mrb_int " + ii + " = 0; " + ii + " < _n; " + ii + "++) {")
      emit("      sp_" + pfx + "_set(" + rc_t + ", " + start_t + " + " + ii + ", sp_" + src_pfx + "_get(" + src_t_v + ", " + ii + "));")
      emit("    }")
    end
    emit("  }")
  end

 # Compile `recv[idx] OP= value` (IndexOperatorWriteNode).
 #
 # Emitted as a get-modify-set against the appropriate typed container,
 # in a block scope so that the receiver and index are each evaluated
 # exactly once. Falls through silently for receiver types we don't
 # handle yet — currently float_array, int_array, and the four numeric
 # hash variants. Compound-assign on string arrays / poly hashes / str
 # hashes is rarely useful and would need per-type semantics.
  def compile_index_op_assign(nid)
    recv = @nd_receiver[nid]
    args_id = @nd_arguments[nid]
    arg_ids = args_id >= 0 ? get_args(args_id) : []
    return if arg_ids.length < 1
    op = @nd_binop[nid]
    rt = infer_type(recv)
    rc = compile_expr_gc_rooted(recv)
    idx = compile_expr(arg_ids[0])
    val = compile_expr(@nd_expression[nid])
    idx_int_io = idx
    if infer_type(arg_ids[0]) == "bigint"
      @needs_bigint = 1
      idx_int_io = "sp_bigint_to_int((sp_Bigint *)" + idx + ")"
    end

    if rt == "float_array" || rt == "int_array"
      pfx = array_c_prefix(rt)
      tt  = new_temp
      ti  = new_temp
      emit("  { sp_" + pfx + " *" + tt + " = " + rc + "; mrb_int " + ti + " = " + idx_int_io +
           "; sp_" + pfx + "_set(" + tt + ", " + ti +
           ", sp_" + pfx + "_get(" + tt + ", " + ti + ") " + op + " (" + val + ")); }")
      return
    end
    if rt == "str_int_hash"
      tt = new_temp
      ti = new_temp
      idx_s = compile_expr_as_string(arg_ids[0])
      emit("  { sp_StrIntHash *" + tt + " = " + rc + "; const char *" + ti + " = " + idx_s +
           "; sp_StrIntHash_set(" + tt + ", " + ti +
           ", sp_StrIntHash_get(" + tt + ", " + ti + ") " + op + " (" + val + ")); }")
      return
    end
    if rt == "int_str_hash"
 # Concatenating strings (`+= str`) is the only sensible op here.
      if op == "+"
        tt = new_temp
        ti = new_temp
        emit("  { sp_IntStrHash *" + tt + " = " + rc + "; mrb_int " + ti + " = " + idx +
             "; sp_IntStrHash_set(" + tt + ", " + ti +
             ", sp_str_concat(sp_IntStrHash_get(" + tt + ", " + ti + "), " + val + ")); }")
        return
      end
    end
    if rt == "sym_int_hash"
      tt = new_temp
      ti = new_temp
      emit("  { sp_SymIntHash *" + tt + " = " + rc + "; sp_sym " + ti + " = " + idx +
           "; sp_SymIntHash_set(" + tt + ", " + ti +
           ", sp_SymIntHash_get(" + tt + ", " + ti + ") " + op + " (" + val + ")); }")
      return
    end
 # sym_str_hash / str_str_hash with `+= str` — string concat
 # (the only sensible compound op for string-valued hashes).
    if rt == "sym_str_hash" && op == "+"
      tt = new_temp
      ti = new_temp
      emit("  { sp_SymStrHash *" + tt + " = " + rc + "; sp_sym " + ti + " = " + idx +
           "; sp_SymStrHash_set(" + tt + ", " + ti +
           ", sp_str_concat(sp_SymStrHash_get(" + tt + ", " + ti + "), " + val + ")); }")
      return
    end
    if rt == "str_str_hash" && op == "+"
      tt = new_temp
      ti = new_temp
      idx_s2 = compile_expr_as_string(arg_ids[0])
      emit("  { sp_StrStrHash *" + tt + " = " + rc + "; const char *" + ti + " = " + idx_s2 +
           "; sp_StrStrHash_set(" + tt + ", " + ti +
           ", sp_str_concat(sp_StrStrHash_get(" + tt + ", " + ti + "), " + val + ")); }")
      return
    end
 # sym_poly_hash / str_poly_hash with `+= int` — unbox the
 # current sp_RbVal, run the op, re-box. Only int-valued slots
 # are supported here; other op-arg shapes fall through.
    if rt == "sym_poly_hash" && op == "+" && infer_type(@nd_expression[nid]) == "int"
      @needs_rb_value = 1
      tt = new_temp
      ti = new_temp
      emit("  { sp_SymPolyHash *" + tt + " = " + rc + "; sp_sym " + ti + " = " + idx +
           "; sp_SymPolyHash_set(" + tt + ", " + ti +
           ", sp_box_int(sp_SymPolyHash_get(" + tt + ", " + ti + ").v.i " + op + " (" + val + "))); }")
      return
    end
    if rt == "str_poly_hash" && op == "+" && infer_type(@nd_expression[nid]) == "int"
      @needs_rb_value = 1
      tt = new_temp
      ti = new_temp
      idx_s3 = compile_expr_as_string(arg_ids[0])
      emit("  { sp_StrPolyHash *" + tt + " = " + rc + "; const char *" + ti + " = " + idx_s3 +
           "; sp_StrPolyHash_set(" + tt + ", " + ti +
           ", sp_box_int(sp_StrPolyHash_get(" + tt + ", " + ti + ").v.i " + op + " (" + val + "))); }")
      return
    end
 # Poly recv + symbol idx: surfaces in `arr[i][:k] += v` (and the
 # each-block analog `f[:k] += v` where f is destructured from a
 # poly_array of boxed hashes — block param type is widened to
 # poly). Mirrors the `[]=` arm in compile_bracket_assign. Only
 # SymIntHash is dispatched here; SymPolyHash compound-assign needs
 # poly-op semantics and is deferred.
    if rt == "poly"
      idx_t = infer_type(arg_ids[0])
      if idx_t == "symbol"
        @needs_rb_value = 1
        cur_h = new_temp
        k_t   = new_temp
        v_t   = new_temp
        h_t   = new_temp
        emit("  {")
        emit("    sp_RbVal " + cur_h + " = " + rc + ";")
        emit("    sp_sym " + k_t + " = (sp_sym)(" + idx + ");")
        emit("    mrb_int " + v_t + " = (" + val + ");")
        emit("    if (" + cur_h + ".cls_id == SP_BUILTIN_SYM_INT_HASH) {")
        emit("      sp_SymIntHash *" + h_t + " = (sp_SymIntHash *)" + cur_h + ".v.p;")
        emit("      sp_SymIntHash_set(" + h_t + ", " + k_t + ", sp_SymIntHash_get(" + h_t + ", " + k_t + ") " + op + " " + v_t + ");")
        emit("    }")
        emit("  }")
        return
      end
    end
  end

 # `obj.attr <op>= val` family helper -- builds the
 # temp-receiver-once C block for typed-instance receivers backed by
 # an attr_accessor (or struct field). For non-attr receivers, we
 # exit with a precise error rather than fall through to an
 # incorrect emission. The caller passes a fragment that takes the
 # temp variable name and returns the C body to execute.
 #
 # Spec note: even for the typed-attr-accessor case the receiver is
 # evaluated exactly ONCE -- the source `obj.bar += val` is
 # `tmp = obj; tmp.bar = tmp.bar + val`, NOT `obj.bar = obj.bar + val`.
 # The temp pattern matters when the receiver expression has side
 # effects (e.g. `next_holder().attr += 1`).
  def compile_call_assign_typed(nid, kind)
    recv = @nd_receiver[nid]
    rt = infer_type(recv)
    bname = @nd_name[nid]   # parser emits read_name as "name"
    if rt.length <= 4 || rt[0, 4] != "obj_"
      $stderr.puts "Spinel: Call" + kind + "WriteNode requires a typed instance receiver with attr_accessor; got receiver type \"" + rt + "\""
      exit(1)
    end
    cname = rt[4, rt.length - 4]
    ci = find_class_idx(cname)
    if ci < 0 || cls_has_attr_writer(ci, bname) == 0
      $stderr.puts "Spinel: Call" + kind + "WriteNode for `." + bname + "` requires attr_accessor (or struct field) on class " + cname
      exit(1)
    end
    rc = compile_expr_gc_rooted(recv)
    val = compile_expr(@nd_expression[nid])
    tt = new_temp
    field = "iv_" + bname
    if kind == "Operator"
      op = @nd_binop[nid]
      ivar_t = cls_ivar_type(ci, "@" + bname)
      if op == "+" && ivar_t == "string" && infer_type(@nd_expression[nid]) == "string"
 # String-valued attr with `+=` becomes sp_str_concat, mirroring
 # the LocalVariableOperatorWriteNode arm at line 21786.
        emit("  { sp_" + cname + " *" + tt + " = " + rc + "; " +
             tt + "->" + field + " = sp_str_concat(" + tt + "->" + field + ", (" + val + ")); }")
        return
      end
 # bigint-typed attr in promote mode: route arithmetic / bitwise
 # ops through the matching sp_bigint_* helper, wrapping a raw
 # mrb_int rhs through sp_bigint_new_int first.
      if ivar_t == "bigint"
        @needs_bigint = 1
        rhs_t = infer_type(@nd_expression[nid])
        rhs_big = rhs_t == "bigint" ? "(sp_Bigint *)(" + val + ")" : "sp_bigint_new_int(" + val + ")"
        big_op = ""
        if op == "+"
          big_op = "sp_bigint_add"
        elsif op == "-"
          big_op = "sp_bigint_sub"
        elsif op == "*"
          big_op = "sp_bigint_mul"
        elsif op == "/"
          big_op = "sp_bigint_div"
        elsif op == "%"
          big_op = "sp_bigint_mod"
        end
        if big_op != ""
          emit("  { sp_" + cname + " *" + tt + " = " + rc + "; " +
               tt + "->" + field + " = " + big_op + "((sp_Bigint *)" + tt + "->" + field + ", " + rhs_big + "); }")
          return
        end
 # Bitwise ops (& | ^ << >>): unbox to mrb_int, apply C op, re-box.
        if op == "&" || op == "|" || op == "^" || op == "<<" || op == ">>"
          rhs_int = rhs_t == "bigint" ? "sp_bigint_to_int(" + rhs_big + ")" : "(" + val + ")"
          emit("  { sp_" + cname + " *" + tt + " = " + rc + "; " +
               tt + "->" + field + " = sp_bigint_new_int(sp_bigint_to_int((sp_Bigint *)" + tt + "->" + field + ") " + op + " " + rhs_int + "); }")
          return
        end
      end
      if op == "%"
        emit("  { sp_" + cname + " *" + tt + " = " + rc + "; " +
             tt + "->" + field + " = sp_imod(" + tt + "->" + field + ", (" + val + ")); }")
      else
        emit("  { sp_" + cname + " *" + tt + " = " + rc + "; " +
             tt + "->" + field + " = " + tt + "->" + field + " " + op + " (" + val + "); }")
      end
      return
    end
    if kind == "And"
      emit("  { sp_" + cname + " *" + tt + " = " + rc + "; " +
           "if (" + tt + "->" + field + ") " + tt + "->" + field + " = (" + val + "); }")
      return
    end
    if kind == "Or"
      emit("  { sp_" + cname + " *" + tt + " = " + rc + "; " +
           "if (!" + tt + "->" + field + ") " + tt + "->" + field + " = (" + val + "); }")
      return
    end
  end

 # `a[i] &&= val` -- read once, conditionally write once. Mirrors
 # compile_index_op_assign's per-receiver-type dispatch but routes
 # the new value through a C `if (cur)` guard instead of an
 # arithmetic op. The temp pattern keeps `a` and `i` evaluated
 # exactly once, matching CRuby's `a[i] = a[i] && val` evaluation
 # order.
  def compile_index_and_assign(nid)
    recv = @nd_receiver[nid]
    args_id = @nd_arguments[nid]
    arg_ids = args_id >= 0 ? get_args(args_id) : []
    return if arg_ids.length < 1
    rt = infer_type(recv)
    rc = compile_expr_gc_rooted(recv)
    idx = compile_expr(arg_ids[0])
    idx_int_ia = idx
    if infer_type(arg_ids[0]) == "bigint"
      @needs_bigint = 1
      idx_int_ia = "sp_bigint_to_int((sp_Bigint *)" + idx + ")"
    end
 # Note: defer compile_expr(@nd_expression[nid]) to inside each
 # if-branch so RHS side effects only fire when the get is truthy
 # (Ruby `&&=` short-circuit semantics).

    if rt == "float_array" || rt == "int_array"
      pfx = array_c_prefix(rt)
      tt = new_temp
      ti = new_temp
      emit("  { sp_" + pfx + " *" + tt + " = " + rc + "; mrb_int " + ti + " = " + idx_int_ia + ";")
      emit("    if (sp_" + pfx + "_get(" + tt + ", " + ti + ")) {")
      val = compile_expr(@nd_expression[nid])
      emit("      sp_" + pfx + "_set(" + tt + ", " + ti + ", (" + val + "));")
      emit("    }")
      emit("  }")
      return
    end
    if rt == "str_int_hash"
      tt = new_temp
      ti = new_temp
      idx_s = compile_expr_as_string(arg_ids[0])
      emit("  { sp_StrIntHash *" + tt + " = " + rc + "; const char *" + ti + " = " + idx_s + ";")
      emit("    if (sp_StrIntHash_get(" + tt + ", " + ti + ")) {")
      val = compile_expr(@nd_expression[nid])
      emit("      sp_StrIntHash_set(" + tt + ", " + ti + ", (" + val + "));")
      emit("    }")
      emit("  }")
      return
    end
    if rt == "int_str_hash"
      tt = new_temp
      ti = new_temp
      emit("  { sp_IntStrHash *" + tt + " = " + rc + "; mrb_int " + ti + " = " + idx + ";")
      emit("    if (sp_IntStrHash_get(" + tt + ", " + ti + ")) {")
      val = compile_expr(@nd_expression[nid])
      emit("      sp_IntStrHash_set(" + tt + ", " + ti + ", (" + val + "));")
      emit("    }")
      emit("  }")
      return
    end
    if rt == "sym_int_hash"
      tt = new_temp
      ti = new_temp
      emit("  { sp_SymIntHash *" + tt + " = " + rc + "; sp_sym " + ti + " = " + idx + ";")
      emit("    if (sp_SymIntHash_get(" + tt + ", " + ti + ")) {")
      val = compile_expr(@nd_expression[nid])
      emit("      sp_SymIntHash_set(" + tt + ", " + ti + ", (" + val + "));")
      emit("    }")
      emit("  }")
      return
    end
  end

 # `a[i] ||= val` -- read once, write only if current is falsy.
 # Same C-truthy vs Ruby-truthy gap as the LocalVariable/Global/
 # Class compound forms (numeric 0 is C-falsy; documented in
 # test/global_var_or_write.rb). For string-valued slots (NULL
 # falsy, anything else truthy) the C and Ruby semantics agree.
  def compile_index_or_assign(nid)
    recv = @nd_receiver[nid]
    args_id = @nd_arguments[nid]
    arg_ids = args_id >= 0 ? get_args(args_id) : []
    return if arg_ids.length < 1
    rt = infer_type(recv)
    rc = compile_expr_gc_rooted(recv)
    idx = compile_expr(arg_ids[0])
    idx_int_or = idx
    if infer_type(arg_ids[0]) == "bigint"
      @needs_bigint = 1
      idx_int_or = "sp_bigint_to_int((sp_Bigint *)" + idx + ")"
    end
 # Note: defer compile_expr(@nd_expression[nid]) to inside each
 # if-branch so RHS side effects only fire when the get is falsy
 # (Ruby `||=` short-circuit semantics).

    if rt == "float_array" || rt == "int_array"
      pfx = array_c_prefix(rt)
      tt = new_temp
      ti = new_temp
      emit("  { sp_" + pfx + " *" + tt + " = " + rc + "; mrb_int " + ti + " = " + idx_int_or + ";")
      emit("    if (!sp_" + pfx + "_get(" + tt + ", " + ti + ")) {")
      val = compile_expr(@nd_expression[nid])
      emit("      sp_" + pfx + "_set(" + tt + ", " + ti + ", (" + val + "));")
      emit("    }")
      emit("  }")
      return
    end
    if rt == "str_int_hash"
      tt = new_temp
      ti = new_temp
      idx_s = compile_expr_as_string(arg_ids[0])
      emit("  { sp_StrIntHash *" + tt + " = " + rc + "; const char *" + ti + " = " + idx_s + ";")
      emit("    if (!sp_StrIntHash_get(" + tt + ", " + ti + ")) {")
      val = compile_expr(@nd_expression[nid])
      emit("      sp_StrIntHash_set(" + tt + ", " + ti + ", (" + val + "));")
      emit("    }")
      emit("  }")
      return
    end
    if rt == "int_str_hash"
      tt = new_temp
      ti = new_temp
      emit("  { sp_IntStrHash *" + tt + " = " + rc + "; mrb_int " + ti + " = " + idx + ";")
      emit("    if (!sp_IntStrHash_get(" + tt + ", " + ti + ")) {")
      val = compile_expr(@nd_expression[nid])
      emit("      sp_IntStrHash_set(" + tt + ", " + ti + ", (" + val + "));")
      emit("    }")
      emit("  }")
      return
    end
    if rt == "sym_int_hash"
      tt = new_temp
      ti = new_temp
      emit("  { sp_SymIntHash *" + tt + " = " + rc + "; sp_sym " + ti + " = " + idx + ";")
      emit("    if (!sp_SymIntHash_get(" + tt + ", " + ti + ")) {")
      val = compile_expr(@nd_expression[nid])
      emit("      sp_SymIntHash_set(" + tt + ", " + ti + ", (" + val + "));")
      emit("    }")
      emit("  }")
      return
    end
    if rt == "poly_poly_hash"
 # Lower `h[k] ||= v` to a get-then-set pair on the boxed key.
 # The expression-form lifts the temp out of a block scope so
 # callers can read the result; here we ignore the value but reuse
 # the same emitter for symmetry.
      compile_poly_poly_index_or_assign_to_temp(nid, rc, arg_ids)
      return
    end
    if rt == "sym_poly_hash" || rt == "str_poly_hash"
      compile_typed_poly_hash_index_or_assign_to_temp(nid, rc, arg_ids, rt)
      return
    end
    if rt == "poly_array"
      compile_typed_array_index_or_assign_to_temp(nid, rc, arg_ids, rt)
      return
    end
    if rt == "poly"
      compile_poly_value_array_index_or_assign_to_temp(nid, rc)
      return
    end
  end

 # Emit the get-then-set body for `recv[k] ||= v` against a
 # poly_poly_hash receiver and return the C name of the sp_RbVal temp
 # holding the resulting value (existing on hit, freshly-stored rhs on
 # miss). Caller is responsible for using or discarding the temp.
  def compile_poly_poly_index_or_assign_to_temp(nid, rc, arg_ids)
    tt = new_temp
    tk = new_temp
    tg = new_temp
    key_boxed = box_expr_to_poly(arg_ids[0])
    emit("  sp_PolyPolyHash *" + tt + " = " + rc + ";")
    emit("  sp_RbVal " + tk + " = " + key_boxed + ";")
    emit("  sp_RbVal " + tg + " = sp_PolyPolyHash_get(" + tt + ", " + tk + ");")
    val_boxed = chained_or_assign_rhs_box(@nd_expression[nid])
    emit("  if (" + tg + ".tag == SP_TAG_NIL) {")
    emit("    " + tg + " = " + val_boxed + ";")
    emit("    sp_PolyPolyHash_set(" + tt + ", " + tk + ", " + tg + ");")
    emit("  }")
    tg
  end

 # Same shape as `compile_poly_poly_index_or_assign_to_temp` for
 # sym_poly_hash / str_poly_hash receivers — the keys are bare
 # `sp_sym` / `const char *` (not boxed sp_RbVal) but the value
 # slot is poly so the get-then-set still pivots on the
 # `tag == SP_TAG_NIL` miss probe.
  def compile_typed_poly_hash_index_or_assign_to_temp(nid, rc, arg_ids, recv_type)
    tt = new_temp
    tk = new_temp
    tg = new_temp
    if recv_type == "sym_poly_hash"
      hash_c = "sp_SymPolyHash"
      key_t = "sp_sym"
      key_expr = compile_expr(arg_ids[0])
    else
      hash_c = "sp_StrPolyHash"
      key_t = "const char *"
      key_expr = compile_expr_as_string(arg_ids[0])
    end
    emit("  " + hash_c + " *" + tt + " = " + rc + ";")
    emit("  " + key_t + " " + tk + " = " + key_expr + ";")
    emit("  sp_RbVal " + tg + " = " + hash_c + "_get(" + tt + ", " + tk + ");")
    val_boxed = chained_or_assign_rhs_box(@nd_expression[nid])
    emit("  if (" + tg + ".tag == SP_TAG_NIL) {")
    emit("    " + tg + " = " + val_boxed + ";")
    emit("    " + hash_c + "_set(" + tt + ", " + tk + ", " + tg + ");")
    emit("  }")
    tg
  end

 # Box the rhs of an `||=` whose lhs is a poly-element slot. For
 # ArrayNode literals — `[]`, `[nil, nil]`, … — promote to
 # poly_array (boxed) so the slot carries a uniformly poly shape;
 # subsequent chain levels can then inspect the value's cls_id
 # against `SP_BUILTIN_POLY_ARRAY` reliably. Without the promote,
 # `[]` would lower to `sp_box_int_array(sp_IntArray_new())`, the
 # next chain level's `cls_id == POLY_ARRAY` check would fail, and
 # the back-set would skip silently. Non-ArrayNode rhs falls back
 # to the existing `box_expr_to_poly` machinery.
  def chained_or_assign_rhs_box(rhs_id)
    if rhs_id >= 0 && @nd_type[rhs_id] == "ArrayNode"
      @needs_rb_value = 1
      @needs_gc = 1
      return "sp_box_poly_array(" + compile_array_literal_as_poly(rhs_id) + ")"
    end
    box_expr_to_poly(rhs_id)
  end

 # `recv[i] ||= v` against a typed-array receiver whose element
 # slot is a boxed sp_RbVal — i.e. poly_array. The miss probe is
 # the same `tag == SP_TAG_NIL` pivot used by the *_poly_hash
 # forms, but indexed access has two extra wrinkles:
 #
 # - the key must be in-bounds before `_get` is safe to call
 # (sp_PolyArray_get reads `data[i]` without a length check),
 # - on miss the slot may be beyond `len`, so before `_set` we
 # pad the array with nil entries up to `i` inclusive.
 #
 # Mirrors CRuby's `arr[i] = v` auto-grow semantics for the gap.
 # Scalar-element typed arrays (int_array, float_array, …) need a
 # different probe (out-of-bounds check, no SP_TAG_NIL) and are
 # not handled here; the caller falls back to the existing stmt
 # path for those.
  def compile_typed_array_index_or_assign_to_temp(nid, rc, arg_ids, recv_type)
    tt = new_temp
    ti = new_temp
    tg = new_temp
    arr_c = "sp_PolyArray"
    emit("  " + arr_c + " *" + tt + " = " + rc + ";")
    idx_taio = compile_expr(arg_ids[0])
    if arg_ids[0] >= 0 && (infer_type(arg_ids[0]) == "bigint" || expr_emit_is_bigint(arg_ids[0]) == 1)
      @needs_bigint = 1
      idx_taio = "sp_bigint_to_int((sp_Bigint *)" + idx_taio + ")"
    end
    emit("  mrb_int " + ti + " = " + idx_taio + ";")
    emit("  sp_RbVal " + tg + " = sp_box_nil();")
    emit("  if (" + ti + " >= 0 && " + ti + " < sp_" + arr_c.sub("sp_", "") + "_length(" + tt + ")) {")
    emit("    " + tg + " = " + arr_c + "_get(" + tt + ", " + ti + ");")
    emit("  }")
    val_boxed = chained_or_assign_rhs_box(@nd_expression[nid])
    emit("  if (" + tg + ".tag == SP_TAG_NIL) {")
    emit("    " + tg + " = " + val_boxed + ";")
    emit("    while (sp_" + arr_c.sub("sp_", "") + "_length(" + tt + ") <= " + ti + ") { " + arr_c + "_push(" + tt + ", sp_box_nil()); }")
    emit("    " + arr_c + "_set(" + tt + ", " + ti + ", " + tg + ");")
    emit("  }")
    tg
  end

 # `<poly>[i] ||= v` where the recv is an sp_RbVal carrying — at
 # runtime — a poly_array. Common in chains like
 # `(@h[k] ||= [])[i] ||= ...`: spinel types `(@h[k] ||= [])` as
 # poly because the hash leaf type is poly, and the inner `||=`
 # sees a poly recv even though the value is concretely a
 # poly_array.
 #
 # The miss probe needs an extra `tag == SP_TAG_OBJ &&
 # cls_id == SP_BUILTIN_POLY_ARRAY` guard so the runtime falls
 # through cleanly when the poly carries a non-array shape. The
 # body otherwise mirrors `compile_typed_array_index_or_assign_to_temp`.
  def compile_poly_value_array_index_or_assign_to_temp(nid, rc)
    tr = new_temp
    tp = new_temp
    ti = new_temp
    tg = new_temp
    args_id = @nd_arguments[nid]
    arg0 = args_id >= 0 ? get_args(args_id)[0] : -1
    emit("  sp_RbVal " + tr + " = " + rc + ";")
    emit("  sp_PolyArray *" + tp + " = (" + tr + ".tag == SP_TAG_OBJ && " + tr + ".cls_id == SP_BUILTIN_POLY_ARRAY) ? (sp_PolyArray *)" + tr + ".v.p : NULL;")
    idx_pvi = compile_expr(arg0)
    if arg0 >= 0 && (infer_type(arg0) == "bigint" || expr_emit_is_bigint(arg0) == 1)
      @needs_bigint = 1
      idx_pvi = "sp_bigint_to_int((sp_Bigint *)" + idx_pvi + ")"
    end
    emit("  mrb_int " + ti + " = " + idx_pvi + ";")
    emit("  sp_RbVal " + tg + " = sp_box_nil();")
    emit("  if (" + tp + " && " + ti + " >= 0 && " + ti + " < sp_PolyArray_length(" + tp + ")) {")
    emit("    " + tg + " = sp_PolyArray_get(" + tp + ", " + ti + ");")
    emit("  }")
    val_boxed = chained_or_assign_rhs_box(@nd_expression[nid])
    emit("  if (" + tg + ".tag == SP_TAG_NIL) {")
    emit("    " + tg + " = " + val_boxed + ";")
    emit("    if (" + tp + ") {")
    emit("      while (sp_PolyArray_length(" + tp + ") <= " + ti + ") { sp_PolyArray_push(" + tp + ", sp_box_nil()); }")
    emit("      sp_PolyArray_set(" + tp + ", " + ti + ", " + tg + ");")
    emit("    }")
    emit("  }")
    tg
  end

 # Return a C expression that evaluates to the inspected form of `val`
 # (a value of inferred Ruby type `at`), following Ruby's Object#inspect
 # contract. Returns "" when `at` has no inspect implementation yet, so
 # callers can fall back to their previous behaviour.
  def compile_inspect_for(at, val)
    if at == "int"
      return "sp_int_to_s(" + val + ")"
    end
    if at == "float"
      return "sp_float_inspect(" + val + ")"
    end
    if at == "string" || at == "string?"
      return "sp_str_inspect(" + val + ")"
    end
    if at == "mutable_str"
      return "sp_str_inspect(" + val + "->data)"
    end
    if at == "symbol"
      return "sp_str_concat(SPL(\":\"), sp_sym_to_s(" + val + "))"
    end
    if at == "bool"
      return "(" + val + " ? \"true\" : \"false\")"
    end
    if at == "nil"
      return "\"nil\""
    end
    if at == "int_array"
      @needs_int_array = 1
      return "sp_IntArray_inspect(" + val + ")"
    end
    if at == "float_array"
      @needs_float_array = 1
      return "sp_FloatArray_inspect(" + val + ")"
    end
    if at == "str_array"
      @needs_str_array = 1
      return "sp_StrArray_inspect(" + val + ")"
    end
    if at == "sym_array"
      @needs_int_array = 1
      return "sp_SymArray_inspect(" + val + ")"
    end
    if at == "poly_array"
      @needs_rb_value = 1
      return "sp_PolyArray_inspect(" + val + ")"
    end
    if at == "poly"
      @needs_rb_value = 1
      return "sp_poly_inspect(" + val + ")"
    end
 # Nested arrays: only the four T_array element shapes that already
 # have primitive inspect helpers . Other ptr_array
 # element types (obj_<C>, poly_array) fall through to the
 # puts-style default — they're separate scope.
    if at == "int_array_ptr_array"
      @needs_int_array = 1
      return "sp_IntArrayPtrArray_inspect(" + val + ")"
    end
    if at == "float_array_ptr_array"
      @needs_float_array = 1
      return "sp_FloatArrayPtrArray_inspect(" + val + ")"
    end
    if at == "str_array_ptr_array"
      @needs_str_array = 1
      return "sp_StrArrayPtrArray_inspect(" + val + ")"
    end
    if at == "sym_array_ptr_array"
      @needs_int_array = 1
      return "sp_SymArrayPtrArray_inspect(" + val + ")"
    end
 # Tuples produced by methods that return Ruby Arrays of fixed
 # arity (Integer#divmod, Array#minmax, etc.). Without an inspect
 # path here, `p arr.minmax` would fall through to printf("%lld",...)
 # and emit the struct pointer. Format as Ruby's "[a, b]" so the
 # output round-trips with CRuby.
    if at == "tuple:int,int"
      return "sp_sprintf(\"[%lld, %lld]\", (long long)" + val + "->_0, (long long)" + val + "->_1)"
    end
    if at == "tuple:int,float"
      return "sp_sprintf(\"[%lld, %s]\", (long long)" + val + "->_0, sp_float_inspect(" + val + "->_1))"
    end
    if at == "tuple:float,float"
      return "sp_sprintf(\"[%s, %s]\", sp_float_inspect(" + val + "->_0), sp_float_inspect(" + val + "->_1))"
    end
 # Generic tuple inspect for any other arity / element-type
 # combination. Build "[<e0>, <e1>, ...]" with per-element
 # formatters chosen by tuple_elem_type_at. Covers str
 # partition (`tuple:string,string,string`) and the other
 # tuple shapes that fell through before. Issues #724, #726.
    if is_tuple_type(at) == 1
      arity_ins = tuple_arity(at)
      fmt = "["
      args = ""
      i_ins = 0
      while i_ins < arity_ins
        et = tuple_elem_type_at(at, i_ins)
        sep = (i_ins == 0) ? "" : ", "
        field = val + "->_" + i_ins.to_s
        if et == "int"
          fmt = fmt + sep + "%lld"
          args = args + ", (long long)" + field
        elsif et == "float"
          fmt = fmt + sep + "%s"
          args = args + ", sp_float_inspect(" + field + ")"
        elsif et == "string" || et == "mutable_str"
          fmt = fmt + sep + "\\\"%s\\\""
          src = (et == "mutable_str") ? "(const char *)(" + field + "->data)" : field
          args = args + ", " + src
        elsif et == "symbol"
          fmt = fmt + sep + ":%s"
          args = args + ", sp_sym_name((sp_sym)" + field + ")"
        elsif et == "bool"
          fmt = fmt + sep + "%s"
          args = args + ", (" + field + ") ? \"true\" : \"false\""
        elsif et == "nil"
          fmt = fmt + sep + "nil"
        else
          fmt = fmt + sep + "?"
        end
        i_ins = i_ins + 1
      end
      fmt = fmt + "]"
      return "sp_sprintf(\"" + fmt + "\"" + args + ")"
    end
    if at == "sym_int_hash"
      @needs_sym_int_hash = 1
      return "sp_SymIntHash_inspect(" + val + ")"
    end
 # Issue #851: inspect for every typed-hash variant that ships
 # an inspect helper in the runtime.
    if at == "str_int_hash"
      @needs_str_int_hash = 1
      return "sp_StrIntHash_inspect(" + val + ")"
    end
    if at == "str_str_hash"
      return "sp_StrStrHash_inspect(" + val + ")"
    end
    if at == "sym_str_hash"
      return "sp_SymStrHash_inspect(" + val + ")"
    end
    if at == "int_str_hash"
      return "sp_IntStrHash_inspect(" + val + ")"
    end
    if at == "int_int_hash"
      return "sp_IntIntHash_inspect(" + val + ")"
    end
    if at == "str_poly_hash"
      @needs_rb_value = 1
      return "sp_StrPolyHash_inspect(" + val + ")"
    end
    if at == "sym_poly_hash"
      @needs_rb_value = 1
      return "sp_SymPolyHash_inspect(" + val + ")"
    end
    if at == "poly_poly_hash"
      @needs_rb_value = 1
      return "sp_PolyPolyHash_inspect(" + val + ")"
    end
    if at == "time"
      return "sp_time_inspect_v(" + val + ")"
    end
 # Issues #840 #841: Complex / Rational value types.
    if at == "complex"
      return "sp_complex_inspect(" + val + ")"
    end
    if at == "rational"
      return "sp_rational_inspect(" + val + ")"
    end
    ""
  end

 # Kernel#p: for each argument, prints `arg.inspect` followed by a
 # newline. Uses `compile_inspect_for` for types that implement inspect;
 # falls back to puts-style output for types that don't yet (e.g.
 # user-defined classes, ranges, hashes).
  def compile_p(nid)
    args_id = @nd_arguments[nid]
    if args_id < 0
      return
    end
    arg_ids = get_args(args_id)
    if arg_ids.length == 0
      return
    end
    k = 0
    while k < arg_ids.length
      aid = arg_ids[k]
      at = infer_type(aid)
      val = compile_expr(aid)
      ins = compile_inspect_for(at, val)
      if ins == ""
 # No inspect implementation for this type — keep the historic
 # behaviour so nothing regresses.
        compile_puts_single(aid, at, val)
      else
        emit("  fputs(" + ins + ", stdout); putchar('" + bsl_n + "');")
      end
      k = k + 1
    end
  end

 # Emit the puts-equivalent for a single arg (extracted for reuse from p).
 # Promote-mode stale-int: an attr_reader / method call returning
 # sp_Bigint * may infer as "int" because the @cls_meth_returns
 # entry was promoted after annotate_all_node_types cached the
 # int. compile_puts and compile_puts_single both run into this:
 # `printf("%lld", (long long)<sp_Bigint*>)` casts a pointer to
 # long long and prints the address. Detect via the unified emit
 # walker and route through the bigint puts arm instead.
  def upgrade_at_for_emit(aid, at)
    if at == "int" && aid >= 0 && expr_emit_is_bigint(aid) == 1
      return "bigint"
    end
    at
  end

  def compile_puts_single(aid, at, val)
    at = upgrade_at_for_emit(aid, at)
    if at == "poly"
      @needs_rb_value = 1
      emit("  sp_poly_puts(" + val + ");")
      return
    end
    if at == "mutable_str"
      emit("  { const char *_ps = (const char *)(" + val + "->data); if (_ps) { fputs(_ps, stdout); if (!*_ps || _ps[strlen(_ps)-1] != '" + bsl_n + "') putchar('" + bsl_n + "'); } else putchar('" + bsl_n + "'); }")
      return
    end
    if at == "bigint"
      @needs_bigint = 1
      emit("  { const char *_bs = sp_bigint_to_s((sp_Bigint *)" + val + "); fputs(_bs, stdout); putchar('" + bsl_n + "'); }")
      return
    end
    if at == "int"
      emit("  printf(\"%lld" + bsl_n + "\", (long long)" + val + ");")
      return
    end
    if at == "int?"
 # `puts nil` outputs an empty line in Ruby. The int? slot uses
 # SP_INT_NIL as the nil inhabitant; raw printf would emit
 # INT64_MIN's decimal instead. Bind val to a temp first so
 # the is_nil check and printf don't re-evaluate (#832: pop /
 # shift mutate the receiver -- double-eval ate the wrong slot).
      tmp_puts_int_opt = new_temp
      emit("  mrb_int " + tmp_puts_int_opt + " = " + val + ";")
      emit("  if (sp_int_is_nil(" + tmp_puts_int_opt + ")) { putchar('" + bsl_n + "'); } else { printf(\"%lld" + bsl_n + "\", (long long)" + tmp_puts_int_opt + "); }")
      return
    end
    if at == "float"
      emit("  { const char *_fs = sp_float_to_s(" + val + "); fputs(_fs, stdout); putchar('" + bsl_n + "'); }")
      return
    end
    if at == "bool"
      emit("  puts(" + val + " ? \"true\" : \"false\");")
      return
    end
    if at == "string" || at == "string?"
      emit("  { const char *_ps = (const char *)(" + val + "); if (_ps) { fputs(_ps, stdout); if (!*_ps || _ps[strlen(_ps)-1] != '" + bsl_n + "') putchar('" + bsl_n + "'); } else putchar('" + bsl_n + "'); }")
      return
    end
 # `puts <exc>` in Ruby implicitly calls .to_s -> message. Print
 # the sp_Exception's message field.
    if at == "exception"
      emit("  { const char *_ps = sp_exc_message(" + val + "); if (_ps) { fputs(_ps, stdout); if (!*_ps || _ps[strlen(_ps)-1] != '" + bsl_n + "') putchar('" + bsl_n + "'); } else putchar('" + bsl_n + "'); }")
      return
    end
 # `puts <cls>` on a value-type sp_Class -- render the name.
    if at == "class"
      @needs_class_table = 1
      emit("  puts(sp_class_to_s(" + val + "));")
      return
    end
    if at == "complex"
      emit("  { const char *_cs = sp_complex_inspect(" + val + "); fputs(_cs, stdout); putchar('" + bsl_n + "'); }")
      return
    end
    if at == "rational"
      emit("  { const char *_rs = sp_rational_inspect(" + val + "); fputs(_rs, stdout); putchar('" + bsl_n + "'); }")
      return
    end
    if at == "encoding"
      emit("  puts(sp_encoding_name(" + val + "));")
      return
    end
    if at == "time"
      emit("  { const char *_ts = sp_time_inspect_v(" + val + "); fputs(_ts, stdout); putchar('" + bsl_n + "'); }")
      return
    end
    emit("  printf(\"%lld" + bsl_n + "\", (long long)" + val + ");")
  end

  def compile_puts(nid)
    args_id = @nd_arguments[nid]
    if args_id < 0
      emit("  putchar('" + bsl_n + "');")
      return
    end
    arg_ids = get_args(args_id)
    if arg_ids.length == 0
      emit("  putchar('" + bsl_n + "');")
      return
    end
    k = 0
    while k < arg_ids.length
      aid = arg_ids[k]
      at = upgrade_at_for_emit(aid, infer_type(aid))
 # Issue #640: `puts cond ? :sym : int` ternary's unify_return_type
 # picks one arm's type (e.g. "symbol") and the other arm's emit
 # gets dispatched through the wrong puts variant — `sp_sym_to_s
 # (an_int)` prints garbage. Detect the mixed-type ternary at the
 # puts boundary and route through sp_poly_puts so each arm's
 # value is boxed to its real tag.
      mixed_ternary = 0
      if at != "poly" && aid >= 0 && @nd_type[aid] == "IfNode"
        if_then_t_pt = "nil"
        if_body_pt = @nd_body[aid]
        if if_body_pt >= 0
          if_stmts_pt = get_stmts(if_body_pt)
          if if_stmts_pt.length > 0
            if_then_t_pt = base_type(infer_type(if_stmts_pt.last))
          end
        end
        if_else_t_pt = "nil"
        if_sub_pt = @nd_subsequent[aid]
        if if_sub_pt >= 0 && @nd_type[if_sub_pt] == "ElseNode"
          eb_pt = @nd_body[if_sub_pt]
          if eb_pt >= 0
            es_pt = get_stmts(eb_pt)
            if es_pt.length > 0
              if_else_t_pt = base_type(infer_type(es_pt.last))
            end
          end
        end
        if if_then_t_pt != if_else_t_pt
 # Only fire when both arms have a concrete type. nil-arms are
 # the implicit `if cond; X; end` (no else) shape — leaving them
 # alone preserves the existing puts dispatch (`nil` on the
 # missing branch goes through the int/string fallback path).
          if if_then_t_pt != "nil" && if_else_t_pt != "nil" &&
             if_then_t_pt != "void" && if_else_t_pt != "void"
            mixed_ternary = 1
          end
        end
      end
      if mixed_ternary == 1
        @needs_rb_value = 1
        emit("  sp_poly_puts(" + box_expr_to_poly(aid) + ");")
        k = k + 1
        next
      end
      val = compile_expr(aid)
 # `puts hash[k]` where hash is a sym/str/int_poly_hash returns
 # sp_RbVal but `infer_type` can report stale "int". Detect the
 # CallNode `[]` against a poly-hash recv so we route through
 # the poly puts emit rather than the int `printf("%lld", ...)`
 # arm which would cast a struct to long long.
      if at != "poly" && aid >= 0 && @nd_type[aid] == "CallNode" && @nd_name[aid] == "[]"
        idx_recv_p = @nd_receiver[aid]
        if idx_recv_p >= 0
          recv_t_idx_p = base_type(infer_type(idx_recv_p))
          if recv_t_idx_p == "sym_poly_hash" || recv_t_idx_p == "str_poly_hash" || recv_t_idx_p == "int_poly_hash" || recv_t_idx_p == "poly_poly_hash" || recv_t_idx_p == "poly_array"
            at = "poly"
          end
        end
      end
      if at == "poly"
        @needs_rb_value = 1
        emit("  sp_poly_puts(" + val + ");")
        k = k + 1
        next
      end
      if at == "mutable_str"
        emit("  { const char *_ps = (const char *)(" + val + "->data); if (_ps) { fputs(_ps, stdout); if (!*_ps || _ps[strlen(_ps)-1] != '" + bsl_n + "') putchar('" + bsl_n + "'); } else putchar('" + bsl_n + "'); }")
        k = k + 1
        next
      end
      if at == "bigint"
        # Cast away volatile from bigint locals (see compile_bigint_arg).
        emit("  { const char *_bs = sp_bigint_to_s((sp_Bigint *)" + val + "); fputs(_bs, stdout); putchar('" + bsl_n + "'); }")
        k = k + 1
        next
      end
      if at == "symbol"
        emit("  puts(sp_sym_to_s(" + val + "));")
        k = k + 1
        next
      end
 # `puts <cls>` on a value-type sp_Class -- render the name via
 # the sp_class_names[] table (mirrors `"#{cls}"` interpolation).
      if at == "class"
        @needs_class_table = 1
        emit("  puts(sp_class_to_s(" + val + "));")
        k = k + 1
        next
      end
      if at == "encoding"
        emit("  puts(sp_encoding_name(" + val + "));")
        k = k + 1
        next
      end
 # `puts <exc>` -- print the message (CRuby calls to_s).
      if at == "exception"
        emit("  { const char *_ps = sp_exc_message(" + val + "); if (_ps) { fputs(_ps, stdout); if (!*_ps || _ps[strlen(_ps)-1] != '" + bsl_n + "') putchar('" + bsl_n + "'); } else putchar('" + bsl_n + "'); }")
        k = k + 1
        next
      end
      if at == "time"
        emit("  { const char *_ts = sp_time_inspect_v(" + val + "); fputs(_ts, stdout); putchar('" + bsl_n + "'); }")
        k = k + 1
        next
      end
      if at == "int"
        emit("  printf(\"%lld" + bsl_n + "\", (long long)" + val + ");")
      elsif at == "int?"
 # `puts nil` outputs an empty line in Ruby. The int? slot uses
 # SP_INT_NIL as the nil inhabitant; raw printf would emit
 # INT64_MIN's decimal instead. Bind to a temp so side-effecting
 # exprs (e.g. a.pop on int_array) don't double-eval (#832).
        tmp_pmsg_io = new_temp
        emit("  mrb_int " + tmp_pmsg_io + " = " + val + ";")
        emit("  if (sp_int_is_nil(" + tmp_pmsg_io + ")) { putchar('" + bsl_n + "'); } else { printf(\"%lld" + bsl_n + "\", (long long)" + tmp_pmsg_io + "); }")
      else
        if at == "float"
          emit("  { const char *_fs = sp_float_to_s(" + val + "); fputs(_fs, stdout); putchar('" + bsl_n + "'); }")
        else
          if at == "string" || at == "string?"
            emit("  { const char *_ps = (const char *)(" + val + "); if (_ps) { fputs(_ps, stdout); if (!*_ps || _ps[strlen(_ps)-1] != '" + bsl_n + "') putchar('" + bsl_n + "'); } else putchar('" + bsl_n + "'); }")
          else
            if at == "bool"
              emit("  puts(" + val + " ? \"true\" : \"false\");")
            else
              if is_obj_type(at) == 1
                cname = at[4, at.length - 4]
                owner = find_method_owner(find_class_idx(cname), "to_s")
                if owner != ""
                  sv = "sp_" + owner + "_to_s(" + (owner == cname ? val : "(sp_" + owner + " *)" + val) + ")"
                  emit("  { const char *_ps = (const char *)(" + sv + "); if (_ps) { fputs(_ps, stdout); if (!*_ps || _ps[strlen(_ps)-1] != '" + bsl_n + "') putchar('" + bsl_n + "'); } else putchar('" + bsl_n + "'); }")
                else
                  emit("  printf(\"%lld" + bsl_n + "\", (long long)(mrb_int)" + val + ");")
                end
              else
                if at == "str_array"
                  emit("  { sp_StrArray *_pa = " + val + "; for (mrb_int _pi = 0; _pi < _pa->len; _pi++) puts(_pa->data[_pi]); }")
                elsif at == "sym_array"
                  emit("  { sp_IntArray *_pa = " + val + "; for (mrb_int _pi = 0; _pi < _pa->len; _pi++) puts(sp_sym_to_s((sp_sym)_pa->data[_pa->start + _pi])); }")
                elsif at == "int_array"
                  emit("  { sp_IntArray *_pa = " + val + "; for (mrb_int _pi = 0; _pi < _pa->len; _pi++) printf(\"%lld" + bsl_n + "\", (long long)_pa->data[_pa->start + _pi]); }")
                elsif at == "float_array"
                  emit("  { sp_FloatArray *_pa = " + val + "; for (mrb_int _pi = 0; _pi < _pa->len; _pi++) { const char *_fs = sp_float_to_s(_pa->data[_pi]); fputs(_fs, stdout); putchar('" + bsl_n + "'); } }")
                elsif is_tuple_type(at) == 1
 # `puts tuple_val` splats Ruby Array elements one per line.
 # Tuples emerge from partition/divmod/minmax and similar.
 # Issue #854.
                  arity_pt = tuple_arity(at)
                  k_pt = 0
                  tmp_pt_val = new_temp
                  c_tuple_name = c_type(at)
                  emit("  " + c_tuple_name + " " + tmp_pt_val + " = " + val + ";")
                  while k_pt < arity_pt
                    et_pt = tuple_elem_type_at(at, k_pt)
                    field_pt = tmp_pt_val + "->_" + k_pt.to_s
                    if et_pt == "string"
                      emit("  { const char *_ps = (const char *)(" + field_pt + "); if (_ps) { fputs(_ps, stdout); if (!*_ps || _ps[strlen(_ps)-1] != '" + bsl_n + "') putchar('" + bsl_n + "'); } else putchar('" + bsl_n + "'); }")
                    elsif et_pt == "int"
                      emit("  printf(\"%lld" + bsl_n + "\", (long long)" + field_pt + ");")
                    elsif et_pt == "float"
                      emit("  { const char *_fs = sp_float_to_s(" + field_pt + "); fputs(_fs, stdout); putchar('" + bsl_n + "'); }")
                    else
                      emit("  printf(\"%lld" + bsl_n + "\", (long long)(mrb_int)" + field_pt + ");")
                    end
                    k_pt = k_pt + 1
                  end
                else
                  emit("  printf(\"%lld" + bsl_n + "\", (long long)" + val + ");")
                end
              end
            end
          end
        end
      end
      k = k + 1
    end
  end

  def compile_stderr_puts(nid)
    args_id = @nd_arguments[nid]
    if args_id < 0
      emit("  fputc('" + bsl_n + "', stderr);")
      return
    end
    arg_ids = get_args(args_id)
    k = 0
    while k < arg_ids.length
      at = infer_type(arg_ids[k])
      val = compile_expr(arg_ids[k])
      if at == "string"
        emit("  fprintf(stderr, \"%s" + bsl_n + "\", " + val + ");")
      elsif at == "encoding"
        emit("  fprintf(stderr, \"%s" + bsl_n + "\", sp_encoding_name(" + val + "));")
      else
        emit("  fprintf(stderr, \"%lld" + bsl_n + "\", (long long)" + val + ");")
      end
      k = k + 1
    end
  end

  def compile_printf(nid)
    args_id = @nd_arguments[nid]
    if args_id < 0
      return
    end
    arg_ids = get_args(args_id)
    if arg_ids.length < 1
      return
    end
 # Issue #751: cast int args as (long long) and rewrite integer format
 # specifiers (%d/%i/%x/%X/%o/%u) to include the `ll` length so
 # mrb_int (int64) isn't truncated to int. Same shape as the
 # String#% literal-format rewrite (line ~17729).
    fmt_expr = compile_expr(arg_ids[0])
    if @nd_type[arg_ids[0]] == "StringNode"
      lit_pf = @nd_unescaped[arg_ids[0]]
      if lit_pf == ""
        lit_pf = @nd_content[arg_ids[0]]
      end
      rewritten_pf = ""
      fi_pf = 0
      while fi_pf < lit_pf.length
        if lit_pf[fi_pf] == "%"
          rewritten_pf = rewritten_pf + "%"
          fi_pf = fi_pf + 1
          while fi_pf < lit_pf.length
            cp = lit_pf[fi_pf]
            if cp == "-" || cp == "+" || cp == " " || cp == "#" || cp == "0" || (cp >= "1" && cp <= "9") || cp == "."
              rewritten_pf = rewritten_pf + cp
              fi_pf = fi_pf + 1
            else
              fi_pf = fi_pf  # exit inner loop
              break
            end
          end
          if fi_pf < lit_pf.length
            cp = lit_pf[fi_pf]
            if cp == "d" || cp == "i"
              rewritten_pf = rewritten_pf + "lld"
            elsif cp == "x" || cp == "X" || cp == "o" || cp == "u"
              rewritten_pf = rewritten_pf + "ll" + cp
            else
              rewritten_pf = rewritten_pf + cp
            end
            fi_pf = fi_pf + 1
          end
        else
          rewritten_pf = rewritten_pf + lit_pf[fi_pf]
          fi_pf = fi_pf + 1
        end
      end
      fmt_expr = c_string_literal(rewritten_pf)
    end
    rest_args = ""
    k = 1
    while k < arg_ids.length
      at = infer_type(arg_ids[k])
      if at == "int"
        rest_args = rest_args + ", (long long)" + compile_expr(arg_ids[k])
      else
        rest_args = rest_args + ", " + compile_expr(arg_ids[k])
      end
      k = k + 1
    end
    emit("  printf(" + fmt_expr + rest_args + ");")
  end

  def compile_print(nid)
    args_id = @nd_arguments[nid]
    if args_id < 0
      return
    end
    arg_ids = get_args(args_id)
    k = 0
    while k < arg_ids.length
      aid = arg_ids[k]
 # Detect x.chr pattern and use putchar for binary-safe output
      if @nd_type[aid] == "CallNode"
        if @nd_name[aid] == "chr"
          if @nd_receiver[aid] >= 0
            rchr = compile_expr(@nd_receiver[aid])
            emit("  putchar((unsigned char)" + rchr + ");")
            k = k + 1
            next
          end
        end
      end
      at = infer_type(aid)
      val = compile_expr(aid)
      if at == "bigint"
        # Cast away volatile from bigint locals (see compile_bigint_arg).
        emit("  fputs(sp_bigint_to_s((sp_Bigint *)" + val + "), stdout);")
        k = k + 1
        next
      end
      if at == "symbol"
        emit("  fputs(sp_sym_to_s(" + val + "), stdout);")
        k = k + 1
        next
      end
      if at == "encoding"
        emit("  fputs(sp_encoding_name(" + val + "), stdout);")
        k = k + 1
        next
      end
      if at == "int"
        emit("  printf(\"%lld\", (long long)" + val + ");")
      elsif at == "mutable_str"
        emit("  fputs(" + val + "->data, stdout);")
      elsif at == "string" || at == "string?"
        emit("  if (" + val + ") fputs(" + val + ", stdout);")
      elsif at == "float"
        emit("  fputs(sp_float_to_s(" + val + "), stdout);")
      elsif at == "bool"
        emit("  fputs(" + val + " ? \"true\" : \"false\", stdout);")
      elsif at == "poly"
 # `print poly_local` -- route through sp_poly_to_s rather than
 # falling through to the `printf("%lld", (long long)val)` path,
 # which is a C-level type error (sp_RbVal is a struct; the cast
 # rejects). sp_poly_to_s switches on the tag and returns a
 # valid c-string for every variant, matching CRuby's
 # `print obj` -> `obj.to_s` semantics.
        @needs_rb_value = 1
        emit("  fputs(sp_poly_to_s(" + val + "), stdout);")
      else
        emit("  printf(\"%lld\", (long long)" + val + ");")
      end
      k = k + 1
    end
  end

  def get_block_param(nid, idx)
    blk = @nd_block[nid]
    if blk < 0
      return ""
    end
    params = @nd_parameters[blk]
    if params < 0
      return ""
    end
 # NumberedParametersNode ({ _1 + _2 }): params is the node itself,
 # and @nd_value holds the maximum (1 for _1, 2 for _2, etc.).
    if @nd_type[params] == "NumberedParametersNode"
      if idx < @nd_value[params]
        return "_" + (idx + 1).to_s
      end
      return ""
    end
    inner = @nd_parameters[params]
    if inner < 0
      return ""
    end
    reqs = parse_id_list(@nd_requireds[inner])
    if idx < reqs.length
      return @nd_name[reqs[idx]]
    end
    ""
  end

  def compile_each_slice_block(nid)
    old = @in_loop
    @in_loop = 1
    rt = infer_type(@nd_receiver[nid])
    rc = compile_expr_gc_rooted(@nd_receiver[nid])
    n = compile_arg0(nid)
    bp1 = get_block_param(nid, 0)
    if bp1 == ""
      bp1 = "_slice"
    end
    tmp_i = new_temp
    tmp_j = new_temp
    tmp_len = new_temp
    pfx = array_c_prefix(rt)
    @needs_gc = 1
    emit("  mrb_int " + tmp_len + " = sp_" + pfx + "_length(" + rc + ");")
    emit("  for (mrb_int " + tmp_i + " = 0; " + tmp_i + " < " + tmp_len + "; " + tmp_i + " += " + n + ") {")
 # When bp1 shadows an outer same-named local of a different C type, the
 # function-level lv_<bp1> has the outer type. Emit a block-scoped fresh
 # declaration with its own GC root so the slice survives allocations in
 # the user block body.
    outer_t = find_var_type(bp1)
    if outer_t != "" && outer_t != rt
      emit("    SP_GC_SAVE();")
      emit("    " + c_type(rt) + " lv_" + bp1 + " = sp_" + pfx + "_new();")
      emit("    SP_GC_ROOT(lv_" + bp1 + ");")
    else
      emit("    lv_" + bp1 + " = sp_" + pfx + "_new();")
    end
    emit("    for (mrb_int " + tmp_j + " = 0; " + tmp_j + " < " + n + " && " + tmp_i + " + " + tmp_j + " < " + tmp_len + "; " + tmp_j + "++)")
    emit("      sp_" + pfx + "_push(lv_" + bp1 + ", sp_" + pfx + "_get(" + rc + ", " + tmp_i + " + " + tmp_j + "));")
    @indent = @indent + 1
    push_scope
    declare_var(bp1, rt)
    redo_label = push_redo_label
    emit_redo_label(redo_label)
    compile_stmts_body(@nd_body[@nd_block[nid]])
    pop_redo_label
    pop_scope
    @indent = @indent - 1
    emit("  }")
    @in_loop = old
  end

  def compile_each_cons_block(nid)
    old = @in_loop
    @in_loop = 1
    rt = infer_type(@nd_receiver[nid])
    rc = compile_expr_gc_rooted(@nd_receiver[nid])
    n = compile_arg0(nid)
    pfx = array_c_prefix(rt)
    elem_t_ec = elem_type_of_array(rt)
    @needs_gc = 1

 # Multi-param block on each_cons(k) — bind one block param
 # per pair element instead of materialising a sub-array.
 # Detect by counting RequiredParameter slots and matching
 # against the literal numeric arg `k`.
    blk_id_ec = @nd_block[nid]
    n_int_ec = -1
    args_id_ec = @nd_arguments[nid]
    if args_id_ec >= 0
      a_list_ec = get_args(args_id_ec)
      if a_list_ec.length > 0 && @nd_type[a_list_ec[0]] == "IntegerNode"
        n_int_ec = @nd_value[a_list_ec[0]].to_i
      end
    end
    bp_params_ec = blk_id_ec >= 0 ? @nd_parameters[blk_id_ec] : -1
    inner_params_ec = bp_params_ec >= 0 ? @nd_parameters[bp_params_ec] : -1
    reqs_ec = inner_params_ec >= 0 ? parse_id_list(@nd_requireds[inner_params_ec]) : []
    can_destruct_ec = (n_int_ec > 0 && reqs_ec.length == n_int_ec && reqs_ec.length >= 2 && @nd_type[reqs_ec[0]] != "MultiTargetNode")

    tmp_i = new_temp
    tmp_j = new_temp
    tmp_len = new_temp
    emit("  mrb_int " + tmp_len + " = sp_" + pfx + "_length(" + rc + ");")
    emit("  for (mrb_int " + tmp_i + " = 0; " + tmp_i + " + " + n + " <= " + tmp_len + "; " + tmp_i + "++) {")

    if can_destruct_ec
      push_scope
      di_ec = 0
      while di_ec < reqs_ec.length
        bpn_ec = @nd_name[reqs_ec[di_ec]]
        emit("    " + c_type(elem_t_ec) + " lv_" + bpn_ec + " = sp_" + pfx + "_get(" + rc + ", " + tmp_i + " + " + di_ec.to_s + ");")
        declare_var(bpn_ec, elem_t_ec)
        di_ec = di_ec + 1
      end
      @indent = @indent + 1
      compile_stmts_body(@nd_body[blk_id_ec])
      @indent = @indent - 1
      pop_scope
    else
      bp1 = get_block_param(nid, 0)
      bp1 = "_cons" if bp1 == ""
      outer_t = find_var_type(bp1)
      if outer_t != "" && outer_t != rt
        emit("    SP_GC_SAVE();")
        emit("    " + c_type(rt) + " lv_" + bp1 + " = sp_" + pfx + "_new();")
        emit("    SP_GC_ROOT(lv_" + bp1 + ");")
      else
        emit("    lv_" + bp1 + " = sp_" + pfx + "_new();")
      end
      emit("    for (mrb_int " + tmp_j + " = 0; " + tmp_j + " < " + n + "; " + tmp_j + "++)")
      emit("      sp_" + pfx + "_push(lv_" + bp1 + ", sp_" + pfx + "_get(" + rc + ", " + tmp_i + " + " + tmp_j + "));")
      @indent = @indent + 1
      push_scope
      declare_var(bp1, rt)
      redo_label = push_redo_label
      emit_redo_label(redo_label)
      compile_stmts_body(@nd_body[blk_id_ec])
      pop_redo_label
      pop_scope
      @indent = @indent - 1
    end
    emit("  }")
    @in_loop = old
  end

  def compile_each_with_object_block(nid)
    old = @in_loop
    @in_loop = 1
    rt = infer_type(@nd_receiver[nid])
    rc = compile_expr_gc_rooted(@nd_receiver[nid])
 # Bind the seed to an outer-scope temp so the expression form can
 # surface the final accumulator. CallNode seeds get GC-rooted by
 # compile_expr_gc_rooted; literal/local seeds rely on the caller
 # already holding a reference for the duration of the loop.
    obj_ct = "mrb_int"
    obj_t = "int"
    obj_arg_nid = -1
    args_id = @nd_arguments[nid]
    if args_id >= 0
      aargs = get_args(args_id)
      if aargs.length > 0
        obj_arg_nid = aargs[0]
        obj_t = infer_type(obj_arg_nid)
        obj_ct = c_type(obj_t)
      end
    end
    obj_arg = compile_expr_gc_rooted(obj_arg_nid)
    bp1 = get_block_param(nid, 0)
    bp2 = get_block_param(nid, 1)
    if bp1 == ""
      bp1 = "_elem"
    end
    if bp2 == ""
      bp2 = "_obj"
    end
 # Outer-scope slot survives the inner `{}` so the expression form
 # of each_with_object can still observe the final accumulator.
    result = new_temp
    emit("  " + obj_ct + " " + result + " = " + obj_arg + ";")
    tmp_i = new_temp
    if is_array_type(rt) == 1
      pfx = array_c_prefix(rt)
      emit("  {")
      @indent = @indent + 1
      emit("  " + obj_ct + " lv_" + bp2 + " = " + result + ";")
      emit("  for (mrb_int " + tmp_i + " = 0; " + tmp_i + " < sp_" + pfx + "_length(" + rc + "); " + tmp_i + "++) {")
      emit("    " + c_type(elem_type_of_array(rt)) + " lv_" + bp1 + " = sp_" + pfx + "_get(" + rc + ", " + tmp_i + ");")
      @indent = @indent + 1
      push_scope
      declare_var(bp1, elem_type_of_array(rt))
      declare_var(bp2, obj_t)
      redo_label = push_redo_label
      emit_redo_label(redo_label)
      compile_stmts_body(@nd_body[@nd_block[nid]])
      pop_redo_label
      pop_scope
      @indent = @indent - 1
      emit("  }")
      emit("  " + result + " = lv_" + bp2 + ";")
      @indent = @indent - 1
      emit("  }")
    end
    @in_loop = old
    result
  end

  def compile_each_with_index_block(nid)
    old = @in_loop
    @in_loop = 1
    rt = infer_type(@nd_receiver[nid])
    rc = compile_expr_gc_rooted(@nd_receiver[nid])
    bp1 = get_block_param(nid, 0)
    bp2 = get_block_param(nid, 1)
    if bp1 == ""
      bp1 = "_v"
    end
    if bp2 == ""
      bp2 = "_idx"
    end
    tmp = new_temp
    pfx = array_c_prefix(rt)
    emit("  for (mrb_int " + tmp + " = 0; " + tmp + " < sp_" + pfx + "_length(" + rc + "); " + tmp + "++) {")
    emit("    " + c_type(elem_type_of_array(rt)) + " lv_" + bp1 + " = sp_" + pfx + "_get(" + rc + ", " + tmp + ");")
    emit("    mrb_int lv_" + bp2 + " = " + tmp + ";")
    @indent = @indent + 1
    push_scope
    declare_var(bp1, elem_type_of_array(rt))
    declare_var(bp2, "int")
    redo_label = push_redo_label
    emit_redo_label(redo_label)
    compile_stmts_body(@nd_body[@nd_block[nid]])
    pop_redo_label
    pop_scope
    @indent = @indent - 1
    emit("  }")
    @in_loop = old
  end

  def compile_group_by_each_fused(each_nid, gb_nid)
    @needs_gc = 1
    arr_nid = @nd_receiver[gb_nid]
    arr_type = infer_type(arr_nid)
    elem_type = elem_type_of_array(arr_type)
    arr_pfx = array_c_prefix(arr_type)

    bp_g = get_block_param(gb_nid, 0)
    if bp_g == ""
      bp_g = "_x"
    end
    bp_e0 = get_block_param(each_nid, 0)
    bp_e1 = get_block_param(each_nid, 1)

    rc = compile_expr_gc_rooted(arr_nid)

    tmp_h = new_temp
    tmp_o = new_temp
    tmp_i = new_temp
    tmp_k = new_temp
    tmp_a = new_temp
    tmp_j = new_temp

    emit("  sp_PolyPolyHash *" + tmp_h + " = sp_PolyPolyHash_new();")
    emit("  SP_GC_ROOT(" + tmp_h + ");")
    emit("  sp_PolyArray *" + tmp_o + " = sp_PolyArray_new();")
    emit("  SP_GC_ROOT(" + tmp_o + ");")

 # Phase 1: walk the input array, run the group-by block on each
 # element, append the element to the per-key accumulator.
    emit("  for (mrb_int " + tmp_i + " = 0; " + tmp_i + " < sp_" + arr_pfx + "_length(" + rc + "); " + tmp_i + "++) {")
    push_scope
    declare_var(bp_g, elem_type)
    emit("    " + c_type(elem_type) + " lv_" + bp_g + " = sp_" + arr_pfx + "_get(" + rc + ", " + tmp_i + ");")

    blk_g = @nd_block[gb_nid]
    body_g = @nd_body[blk_g]
    key_expr_unboxed = "0"
    key_type = "int"
    if body_g >= 0
      stmts_g = get_stmts(body_g)
      if stmts_g.length > 0
        k = 0
        while k < stmts_g.length - 1
          compile_stmt(stmts_g[k])
          k = k + 1
        end
        key_expr_unboxed = compile_expr(stmts_g.last)
        key_type = infer_type(stmts_g.last)
      end
    end
    key_boxed = box_value_to_poly(key_type, key_expr_unboxed)
    pop_scope

    emit("    sp_RbVal " + tmp_k + " = " + key_boxed + ";")
    emit("    sp_PolyArray *" + tmp_a + ";")
    emit("    if (sp_PolyPolyHash_has_key(" + tmp_h + ", " + tmp_k + ")) {")
    emit("      " + tmp_a + " = (sp_PolyArray *)sp_PolyPolyHash_get(" + tmp_h + ", " + tmp_k + ").v.p;")
    emit("    } else {")
    emit("      " + tmp_a + " = sp_PolyArray_new();")
    emit("      sp_PolyPolyHash_set(" + tmp_h + ", " + tmp_k + ", sp_box_obj((void *)" + tmp_a + ", SP_BUILTIN_POLY_ARRAY));")
    emit("      sp_PolyArray_push(" + tmp_o + ", " + tmp_k + ");")
    emit("    }")
    emit("    sp_PolyArray_push(" + tmp_a + ", " + box_value_to_poly(elem_type, "lv_" + bp_g) + ");")
    emit("  }")

 # Phase 2: iterate keys in insertion order, expose the per-key
 # accumulator to the each-block as a typed sp_PolyArray *.
    emit("  for (mrb_int " + tmp_j + " = 0; " + tmp_j + " < " + tmp_o + "->len; " + tmp_j + "++) {")
    push_scope
    if bp_e0 != ""
      declare_var(bp_e0, "poly")
      emit("    sp_RbVal lv_" + bp_e0 + " = sp_PolyArray_get(" + tmp_o + ", " + tmp_j + ");")
    end
    if bp_e1 != ""
      declare_var(bp_e1, "poly_array")
      emit("    sp_PolyArray *lv_" + bp_e1 + " = (sp_PolyArray *)sp_PolyPolyHash_get(" + tmp_h + ", lv_" + bp_e0 + ").v.p;")
    end

    blk_e = @nd_block[each_nid]
    body_e = @nd_body[blk_e]
    if body_e >= 0
      stmts_e = get_stmts(body_e)
      k = 0
      while k < stmts_e.length
        compile_stmt(stmts_e[k])
        k = k + 1
      end
    end
    pop_scope
    emit("  }")
  end

  def compile_each_block(nid)
    old = @in_loop
    @in_loop = 1
 # Fuse `<arr>.group_by { ... }.each do |k, rows| ... end`. The
 # natural codegen for these two calls would produce a Hash with
 # poly-boxed sp_PolyArray values, which would then leave `rows`
 # typed as `poly` in the each-body. Fusing into a single emit lets
 # us type `rows` as `sp_PolyArray *` directly, so the inner block
 # body can call existing poly_array dispatch arms (`.size`, `.sum`,
 # `.map { ... }`) without going through poly-recv unbox arms.
    recv_for_fuse = @nd_receiver[nid]
    if recv_for_fuse >= 0 && @nd_type[recv_for_fuse] == "CallNode" && @nd_name[recv_for_fuse] == "group_by" && @nd_block[recv_for_fuse] >= 0 && @nd_receiver[recv_for_fuse] >= 0
      compile_group_by_each_fused(nid, recv_for_fuse)
      @in_loop = old
      return
    end
 # Fuse hash.keys.each → direct order-array loop to avoid intermediate sp_IntArray allocation
    recv_nid = @nd_receiver[nid]
    if recv_nid >= 0 && @nd_type[recv_nid] == "CallNode" && @nd_name[recv_nid] == "keys"
      hash_nid = @nd_receiver[recv_nid]
      if hash_nid >= 0
        ht = infer_type(hash_nid)
        if ht == "int_str_hash" || ht == "str_int_hash" || ht == "str_str_hash" || ht == "sym_int_hash" || ht == "sym_str_hash" || ht == "sym_poly_hash" || ht == "str_poly_hash"
          hrc = compile_expr_gc_rooted(hash_nid)
          bp1 = get_block_param(nid, 0)
          has_bp = 1
          if bp1 == ""
            has_bp = 0
            bp1 = "_x"
          end
 # Pick the key type. Sym-keyed hashes store the sym id in
 # `order[]` as a plain mrb_int — cast to sp_sym so block-body
 # dispatchers see the right type.
          is_sym_key = 0
          if ht == "sym_int_hash" || ht == "sym_str_hash" || ht == "sym_poly_hash"
            is_sym_key = 1
          end
          is_str_key = 0
          if ht == "str_int_hash" || ht == "str_str_hash" || ht == "str_poly_hash"
            is_str_key = 1
          end
          key_type = "int"
          if is_sym_key == 1
            key_type = "symbol"
          elsif is_str_key == 1
            key_type = "string"
          end
          tmp = new_temp
          emit("  for (mrb_int " + tmp + " = 0; " + tmp + " < " + hrc + "->len; " + tmp + "++) {")
 # Inline-declare `lv_<bp1>` with the key's C type so a block
 # param that shadows an outer same-named local of a different
 # type compiles correctly (mirrors 's pattern).
          if has_bp == 1
            if is_sym_key == 1
              emit("    sp_sym lv_" + bp1 + " = (sp_sym)" + hrc + "->order[" + tmp + "];")
            else
              emit("    " + c_type(key_type) + " lv_" + bp1 + " = " + hrc + "->order[" + tmp + "];")
            end
          end
          @indent = @indent + 1
          push_scope
          if has_bp == 1
            declare_var(bp1, key_type)
          end
          redo_label = push_redo_label
          emit_redo_label(redo_label)
          compile_stmts_body(@nd_body[@nd_block[nid]])
          pop_redo_label
          pop_scope
          @indent = @indent - 1
          emit("  }")
          @in_loop = old
          return
        end
      end
    end
    rt = infer_type(@nd_receiver[nid])
    rc = compile_expr_gc_rooted(@nd_receiver[nid])
    bp1 = get_block_param(nid, 0)
    bp2 = get_block_param(nid, 1)
    has_bp = 1
    if bp1 == ""
      has_bp = 0
      bp1 = "_x"
    end

    if rt == "int_array" || rt == "str_array" || rt == "float_array"
      tmp = new_temp
      pfx = array_c_prefix(rt)
      emit("  for (mrb_int " + tmp + " = 0; " + tmp + " < sp_" + pfx + "_length(" + rc + "); " + tmp + "++) {")
      if has_bp == 1
        emit("    " + c_type(elem_type_of_array(rt)) + " lv_" + bp1 + " = sp_" + pfx + "_get(" + rc + ", " + tmp + ");")
      end
      @indent = @indent + 1
      push_scope
      if has_bp == 1
        declare_var(bp1, elem_type_of_array(rt))
      end
      redo_label = push_redo_label
      emit_redo_label(redo_label)
      compile_stmts_body(@nd_body[@nd_block[nid]])
      pop_redo_label
      pop_scope
      @indent = @indent - 1
      emit("  }")
    end
    if rt == "sym_array"
      tmp = new_temp
      emit("  for (mrb_int " + tmp + " = 0; " + tmp + " < sp_IntArray_length(" + rc + "); " + tmp + "++) {")
      if has_bp == 1
        emit("    lv_" + bp1 + " = (sp_sym)sp_IntArray_get(" + rc + ", " + tmp + ");")
      end
      @indent = @indent + 1
      push_scope
      if has_bp == 1
        declare_var(bp1, "symbol")
      end
      redo_label = push_redo_label
      emit_redo_label(redo_label)
      compile_stmts_body(@nd_body[@nd_block[nid]])
      pop_redo_label
      pop_scope
      @indent = @indent - 1
      emit("  }")
    end
    if is_ptr_array_type(rt) == 1
      elem_type = ptr_array_elem_type(rt)
      tmp = new_temp
      bp_tmp = new_temp
 # Detect numbered-params auto-destructure: `[[1,10]].each { _1; _2 }`
 # binds _1=1, _2=10 in Ruby. Trigger when the block uses
 # NumberedParametersNode with maximum >= 2 over an element that is
 # itself an array we know how to index.
      blk = @nd_block[nid]
      bp = blk >= 0 ? @nd_parameters[blk] : -1
      destruct_n = 0
      if bp >= 0 && @nd_type[bp] == "NumberedParametersNode"
        if @nd_value[bp] >= 2 && is_array_type(elem_type) == 1
          destruct_n = @nd_value[bp]
        end
      end
      emit("  for (mrb_int " + tmp + " = 0; " + tmp + " < sp_PtrArray_length(" + rc + "); " + tmp + "++) {")
      if destruct_n > 0
        elem_pfx = array_c_prefix(elem_type)
        emit("    " + c_type(elem_type) + " " + bp_tmp + " = (" + c_type(elem_type) + ")sp_PtrArray_get(" + rc + ", " + tmp + ");")
 # Bounds-check missing slots: when the yielded sub-array is shorter
 # than `destruct_n`, CRuby fills with nil; the typed-array codegen
 # has no nil so we default to 0 (the typed-zero analogue). Without
 # this guard the slot read is OOB into the sub-array's data buffer.
        dlen_tmp = new_temp
        emit("    mrb_int " + dlen_tmp + " = sp_" + elem_pfx + "_length(" + bp_tmp + ");")
        destruct_slot_box = (@int_overflow_mode == "promote" && elem_pfx == "IntArray") ? 1 : 0
        di = 0
        while di < destruct_n
          slot = "lv__" + (di + 1).to_s
 # promote-mode numbered destruct slot widened to bigint via the
 # scope_types sweep but the inner array is still IntArray; box
 # each get with sp_bigint_new_int (and use sp_bigint_new_int(0)
 # as the missing-slot default) so the slot's sp_Bigint* type
 # matches.
          if destruct_slot_box == 1
            @needs_bigint = 1
            emit("    " + slot + " = (" + dlen_tmp + " > " + di.to_s + ") ? sp_bigint_new_int(sp_" + elem_pfx + "_get(" + bp_tmp + ", " + di.to_s + ")) : sp_bigint_new_int(0);")
          else
            emit("    " + slot + " = (" + dlen_tmp + " > " + di.to_s + ") ? sp_" + elem_pfx + "_get(" + bp_tmp + ", " + di.to_s + ") : 0;")
          end
          di = di + 1
        end
      else
        if has_bp == 1
          emit("    " + c_type(elem_type) + " " + bp_tmp + " = (" + c_type(elem_type) + ")sp_PtrArray_get(" + rc + ", " + tmp + ");")
          emit("    lv_" + bp1 + " = " + bp_tmp + ";")
        end
      end
      @indent = @indent + 1
      push_scope
      if destruct_n > 0
        di = 0
        while di < destruct_n
 # promote-mode: each_with numbered destructuring slots boxed
 # to sp_Bigint* (see emit_destruct_box above). Declare the
 # codegen-side scope type as "bigint" so subsequent infer_type
 # calls inside the block body see bigint instead of int -- avoids
 # compile_bigint_arg double-wrapping `_1` with sp_bigint_new_int.
          d_decl_t = elem_type_of_array(elem_type)
          if destruct_slot_box == 1 && d_decl_t == "int"
            d_decl_t = "bigint"
          end
          declare_var("_" + (di + 1).to_s, d_decl_t)
          di = di + 1
        end
      else
        if has_bp == 1
          declare_var(bp1, elem_type)
        end
      end
      redo_label = push_redo_label
      emit_redo_label(redo_label)
      compile_stmts_body(@nd_body[@nd_block[nid]])
      pop_redo_label
      pop_scope
      @indent = @indent - 1
      emit("  }")
    end
    if rt == "str_int_hash"
      tmp = new_temp
      bp2_ot_si = bp2 != "" ? find_var_type(bp2) : ""
      emit("  for (mrb_int " + tmp + " = 0; " + tmp + " < " + rc + "->len; " + tmp + "++) {")
      emit("    lv_" + bp1 + " = " + rc + "->order[" + tmp + "];")
      if bp2 != ""
        emit_block_lv_assign_int(bp2, "sp_StrIntHash_get(" + rc + ", " + rc + "->order[" + tmp + "])")
      end
