      emit("      else if (" + poly_tmp + ".cls_id == SP_BUILTIN_POLY_ARRAY) " + val_tmp + " = sp_PolyArray_get((sp_PolyArray *)" + poly_tmp + ".v.p, " + idx_tmp + ");")
 # Hash per-iteration: pack the (key, value) pair as a
 # 2-element PolyArray so the splat-on-2-arg-block logic below
 # delivers `|k, v|`. For 1-arg block (`{ |pair| ... }`), bp1
 # receives the boxed PolyArray, matching CRuby's behaviour.
      @needs_poly_array = 1
      @needs_rb_value = 1
      @needs_gc = 1
      emit("      else if (" + poly_tmp + ".cls_id == SP_BUILTIN_STR_INT_HASH) { sp_StrIntHash *_sh = (sp_StrIntHash *)" + poly_tmp + ".v.p; sp_PolyArray *_kv = sp_PolyArray_new(); sp_PolyArray_push(_kv, sp_box_str(_sh->order[" + idx_tmp + "])); sp_PolyArray_push(_kv, sp_box_int(sp_StrIntHash_get(_sh, _sh->order[" + idx_tmp + "]))); " + val_tmp + " = sp_box_obj(_kv, SP_BUILTIN_POLY_ARRAY); }")
      emit("      else if (" + poly_tmp + ".cls_id == SP_BUILTIN_STR_STR_HASH) { sp_StrStrHash *_sh = (sp_StrStrHash *)" + poly_tmp + ".v.p; sp_PolyArray *_kv = sp_PolyArray_new(); sp_PolyArray_push(_kv, sp_box_str(_sh->order[" + idx_tmp + "])); sp_PolyArray_push(_kv, sp_box_str(sp_StrStrHash_get(_sh, _sh->order[" + idx_tmp + "]))); " + val_tmp + " = sp_box_obj(_kv, SP_BUILTIN_POLY_ARRAY); }")
      emit("      else if (" + poly_tmp + ".cls_id == SP_BUILTIN_INT_STR_HASH) { sp_IntStrHash *_sh = (sp_IntStrHash *)" + poly_tmp + ".v.p; sp_PolyArray *_kv = sp_PolyArray_new(); sp_PolyArray_push(_kv, sp_box_int(_sh->order[" + idx_tmp + "])); sp_PolyArray_push(_kv, sp_box_str(sp_IntStrHash_get(_sh, _sh->order[" + idx_tmp + "]))); " + val_tmp + " = sp_box_obj(_kv, SP_BUILTIN_POLY_ARRAY); }")
      emit("      else if (" + poly_tmp + ".cls_id == SP_BUILTIN_SYM_INT_HASH) { sp_SymIntHash *_sh = (sp_SymIntHash *)" + poly_tmp + ".v.p; sp_PolyArray *_kv = sp_PolyArray_new(); sp_PolyArray_push(_kv, sp_box_sym(_sh->order[" + idx_tmp + "])); sp_PolyArray_push(_kv, sp_box_int(sp_SymIntHash_get(_sh, _sh->order[" + idx_tmp + "]))); " + val_tmp + " = sp_box_obj(_kv, SP_BUILTIN_POLY_ARRAY); }")
      emit("      else if (" + poly_tmp + ".cls_id == SP_BUILTIN_SYM_STR_HASH) { sp_SymStrHash *_sh = (sp_SymStrHash *)" + poly_tmp + ".v.p; sp_PolyArray *_kv = sp_PolyArray_new(); sp_PolyArray_push(_kv, sp_box_sym(_sh->order[" + idx_tmp + "])); sp_PolyArray_push(_kv, sp_box_str(sp_SymStrHash_get(_sh, _sh->order[" + idx_tmp + "]))); " + val_tmp + " = sp_box_obj(_kv, SP_BUILTIN_POLY_ARRAY); }")
      emit("      else if (" + poly_tmp + ".cls_id == SP_BUILTIN_STR_POLY_HASH) { sp_StrPolyHash *_sh = (sp_StrPolyHash *)" + poly_tmp + ".v.p; sp_PolyArray *_kv = sp_PolyArray_new(); sp_PolyArray_push(_kv, sp_box_str(_sh->order[" + idx_tmp + "])); sp_PolyArray_push(_kv, sp_StrPolyHash_get(_sh, _sh->order[" + idx_tmp + "])); " + val_tmp + " = sp_box_obj(_kv, SP_BUILTIN_POLY_ARRAY); }")
      emit("      else if (" + poly_tmp + ".cls_id == SP_BUILTIN_SYM_POLY_HASH) { sp_SymPolyHash *_sh = (sp_SymPolyHash *)" + poly_tmp + ".v.p; sp_PolyArray *_kv = sp_PolyArray_new(); sp_PolyArray_push(_kv, sp_box_sym(_sh->order[" + idx_tmp + "])); sp_PolyArray_push(_kv, sp_SymPolyHash_get(_sh, _sh->order[" + idx_tmp + "])); " + val_tmp + " = sp_box_obj(_kv, SP_BUILTIN_POLY_ARRAY); }")
      emit("      else if (" + poly_tmp + ".cls_id == SP_BUILTIN_POLY_POLY_HASH) { sp_PolyPolyHash *_sh = (sp_PolyPolyHash *)" + poly_tmp + ".v.p; mrb_int _pk = _sh->order[" + idx_tmp + "]; sp_PolyArray *_kv = sp_PolyArray_new(); sp_PolyArray_push(_kv, _sh->keys[_pk]); sp_PolyArray_push(_kv, _sh->vals[_pk]); " + val_tmp + " = sp_box_obj(_kv, SP_BUILTIN_POLY_ARRAY); }")
      if has_bp == 1
        if bp2 != ""
 # Multi-param block over a poly receiver: CRuby auto-splats
 # when the yielded element is itself an Array. Mirror that:
 # if the runtime element is a typed array, distribute its
 # first two slots across bp1/bp2; otherwise bp1 takes the
 # whole element and bp2 stays nil.
          emit("      sp_RbVal lv_" + bp1 + " = sp_box_nil();")
          emit("      sp_RbVal lv_" + bp2 + " = sp_box_nil();")
          emit("      if (" + val_tmp + ".tag == SP_TAG_OBJ && " + val_tmp + ".cls_id == SP_BUILTIN_POLY_ARRAY) {")
          emit("        sp_PolyArray *_pa = (sp_PolyArray *)" + val_tmp + ".v.p;")
          emit("        if (sp_PolyArray_length(_pa) > 0) lv_" + bp1 + " = sp_PolyArray_get(_pa, 0);")
          emit("        if (sp_PolyArray_length(_pa) > 1) lv_" + bp2 + " = sp_PolyArray_get(_pa, 1);")
          emit("      } else if (" + val_tmp + ".tag == SP_TAG_OBJ && " + val_tmp + ".cls_id == SP_BUILTIN_INT_ARRAY) {")
          emit("        sp_IntArray *_ia = (sp_IntArray *)" + val_tmp + ".v.p;")
          emit("        if (sp_IntArray_length(_ia) > 0) lv_" + bp1 + " = sp_box_int(sp_IntArray_get(_ia, 0));")
          emit("        if (sp_IntArray_length(_ia) > 1) lv_" + bp2 + " = sp_box_int(sp_IntArray_get(_ia, 1));")
          emit("      } else {")
          emit("        lv_" + bp1 + " = " + val_tmp + ";")
          emit("      }")
        else
          emit("      sp_RbVal lv_" + bp1 + " = " + val_tmp + ";")
        end
      end
      @indent = @indent + 2
      push_scope
      if has_bp == 1
        declare_var(bp1, "poly")
        if bp2 != ""
          declare_var(bp2, "poly")
        end
      end
      redo_label = push_redo_label
      emit_redo_label(redo_label)
      compile_stmts_body(@nd_body[@nd_block[nid]])
      pop_redo_label
      pop_scope
      @indent = @indent - 2
      emit("    }")
      emit("  }")
    end
    @in_loop = old
  end

  def compile_times_block(nid)
    old = @in_loop
    @in_loop = 1
    rc_recv = @nd_receiver[nid]
    rc = compile_expr_gc_rooted(rc_recv)
    bp1 = get_block_param(nid, 0)
    tmp = new_temp
 # With promote mode the receiver of `times` is itself sp_Bigint *,
 # so the loop bound needs to be unboxed to mrb_int.
    if rc_recv >= 0 && infer_type(rc_recv) == "bigint"
      @needs_bigint = 1
      rc = "sp_bigint_to_int((sp_Bigint *)" + rc + ")"
    end
    emit("  for (mrb_int " + tmp + " = 0; " + tmp + " < " + rc + "; " + tmp + "++) {")
    bp_t_tb = bp1 != "" ? find_var_type(bp1) : ""
 # Under promote mode the block param slot is widened to bigint
 # at analyze time, but find_var_type returns "" when the bp's
 # scope hasn't been pushed yet (this call site reads before the
 # declare_var below). Default to bigint so the assignment matches
 # the slot's declared C type. Same shape as compile_map_expr's
 # bpn_t_mp peek; sort_by / each_cons fold the same way.
    if bp_t_tb == "" && @int_overflow_mode == "promote"
      bp_t_tb = "bigint"
    end
    if bp1 != ""
      if bp_t_tb == "bigint"
        @needs_bigint = 1
        emit("    lv_" + bp1 + " = sp_bigint_new_int(" + tmp + ");")
      else
        emit("    lv_" + bp1 + " = " + tmp + ";")
      end
    end
    @indent = @indent + 1
    push_scope
    if bp1 != ""
      declare_var(bp1, bp_t_tb == "bigint" ? "bigint" : "int")
    end
    redo_label = push_redo_label
    emit_redo_label(redo_label)
    compile_stmts_body(@nd_body[@nd_block[nid]])
    pop_redo_label
    pop_scope
    @indent = @indent - 1
    emit("  }")
    @in_loop = old
  end

 # `redo` label-stack helpers. Each loop emitter wraps its body
 # between push_redo_label / emit_redo_label / pop_redo_label so
 # `redo` knows which label to jump to. Labels are unique per loop
 # body via @redo_label_counter.
  def push_redo_label
    @redo_label_counter = @redo_label_counter + 1
    lbl = "sp_redo_" + @redo_label_counter.to_s
    @redo_label_stack.push(lbl)
    lbl
  end

  def pop_redo_label
    if @redo_label_stack.length > 0
      @redo_label_stack.pop
    end
  end

 # Emit the C label that `redo` jumps to. C requires labels to be
 # followed by a statement; `;` lets a subsequent `}` stay valid
 # even if the body is empty.
  def emit_redo_label(lbl)
    emit("    " + lbl + ": ;")
  end

  def compile_upto_block(nid)
    old = @in_loop
    @in_loop = 1
    rc = compile_expr_gc_rooted(@nd_receiver[nid])
    lim = compile_arg0(nid)
    bp1 = get_block_param(nid, 0)
    tmp = new_temp
    emit("  for (mrb_int " + tmp + " = " + rc + "; " + tmp + " <= " + lim + "; " + tmp + "++) {")
 # Block-param type: with `--int-overflow=promote`, the
 # enclosing function's local for the block param has been
 # rewritten to sp_Bigint *, but the upto counter is still
 # mrb_int (the range bounds are int-literal). Box on assignment
 # so the LV slot type matches its declaration.
    bp_t = bp1 != "" ? find_var_type(bp1) : ""
    if bp1 != ""
      if bp_t == "bigint"
        @needs_bigint = 1
        emit("    lv_" + bp1 + " = sp_bigint_new_int(" + tmp + ");")
      else
        emit("    lv_" + bp1 + " = " + tmp + ";")
      end
    end
    @indent = @indent + 1
    push_scope
    if bp1 != ""
      declare_var(bp1, bp_t == "bigint" ? "bigint" : "int")
    end
    redo_label = push_redo_label
    emit_redo_label(redo_label)
    compile_stmts_body(@nd_body[@nd_block[nid]])
    pop_redo_label
    pop_scope
    @indent = @indent - 1
    emit("  }")
    @in_loop = old
  end

  def compile_downto_block(nid)
    old = @in_loop
    @in_loop = 1
    rc_recv_d = @nd_receiver[nid]
    rc = compile_expr_gc_rooted(rc_recv_d)
    if rc_recv_d >= 0 && infer_type(rc_recv_d) == "bigint"
      @needs_bigint = 1
      rc = "sp_bigint_to_int((sp_Bigint *)" + rc + ")"
    end
    lim = compile_arg0_as_int(nid)
    bp1 = get_block_param(nid, 0)
    tmp = new_temp
    emit("  for (mrb_int " + tmp + " = " + rc + "; " + tmp + " >= " + lim + "; " + tmp + "--) {")
    bp_t_dd = bp1 != "" ? find_var_type(bp1) : ""
    if bp1 != ""
      if bp_t_dd == "bigint"
        @needs_bigint = 1
        emit("    lv_" + bp1 + " = sp_bigint_new_int(" + tmp + ");")
      else
        emit("    lv_" + bp1 + " = " + tmp + ";")
      end
    end
    @indent = @indent + 1
    push_scope
    if bp1 != ""
      declare_var(bp1, bp_t_dd == "bigint" ? "bigint" : "int")
    end
    redo_label = push_redo_label
    emit_redo_label(redo_label)
    compile_stmts_body(@nd_body[@nd_block[nid]])
    pop_redo_label
    pop_scope
    @indent = @indent - 1
    emit("  }")
    @in_loop = old
  end

  def compile_tap_expr(nid)
 # Execute block with receiver bound to block param, return receiver.
 # Open a C block so the param is a fresh local that shadows any
 # outer same-named lv_<bp> without clobbering its value or type.
    rt = infer_type(@nd_receiver[nid])
    rc = compile_expr_gc_rooted(@nd_receiver[nid])
    bp = get_block_param(nid, 0)
    if bp == ""
      bp = "_x"
    end
    tmp = new_temp
    emit("  " + c_type(rt) + " " + tmp + " = " + rc + ";")
    emit("  {")
    emit("    " + c_type(rt) + " lv_" + bp + " = " + tmp + ";")
    @indent = @indent + 1
    push_scope
    declare_var(bp, rt)
    blk = @nd_block[nid]
    bbody = @nd_body[blk]
    if bbody >= 0
      bs = get_stmts(bbody)
      k = 0
      while k < bs.length
        compile_stmt(bs[k])
        k = k + 1
      end
    end
    pop_scope
    @indent = @indent - 1
    emit("  }")
    tmp
  end

  def compile_then_expr(nid)
 # Execute block with receiver bound to block param, return block result.
 # Open a C block so the param is a fresh local that shadows any outer
 # same-named lv_<bp>. The block's last-expression value is funneled
 # through a result tmp declared in the enclosing scope so callers can
 # still consume it after the C block closes.
    rt = infer_type(@nd_receiver[nid])
    rc = compile_expr_gc_rooted(@nd_receiver[nid])
    bp = get_block_param(nid, 0)
    if bp == ""
      bp = "_x"
    end
    blk = @nd_block[nid]
    bbody = @nd_body[blk]

 # Peek at the last expression's type under the inner binding so the
 # result tmp is declared with the type that infer_type sees inside
 # the block, not the type of any outer same-named local.
    ret_t = "int"
    bs = []
    if bbody >= 0
      bs = get_stmts(bbody)
      if bs.length > 0
        push_scope
        declare_var(bp, rt)
        ret_t = infer_type(bs.last)
        pop_scope
      end
    end

    result_tmp = new_temp
    emit("  " + c_type(ret_t) + " " + result_tmp + " = " + c_default_val(ret_t) + ";")
    emit("  {")
    emit("    " + c_type(rt) + " lv_" + bp + " = " + rc + ";")
    @indent = @indent + 1
    push_scope
    declare_var(bp, rt)
    if bs.length > 0
      k = 0
      while k < bs.length - 1
        compile_stmt(bs[k])
        k = k + 1
      end
      last_expr = compile_expr(bs.last)
      emit("  " + result_tmp + " = " + last_expr + ";")
    end
    pop_scope
    @indent = @indent - 1
    emit("  }")
    result_tmp
  end

 # Emit the loop-open lines for iterating over a receiver expression.
 # Supports range and all array-like types. After calling this helper,
 # the caller emits the block body and a closing '}'. idx_var holds
 # the loop counter (position or value for range); elem_var gets the
 # current element.
  def emit_iter_open(rc, recv_type, elem_var, idx_var)
 # `--int-overflow=promote` may have widened the block param's
 # declared slot to sp_Bigint *, but the underlying iterator
 # (sp_IntArray_get, range counter, ...) yields a raw mrb_int.
 # Detect the widening via find_var_type on the stripped-`lv_`
 # name and wrap the get with sp_bigint_new_int so the assign
 # is typed-clean.
    iter_elem_t = iter_elem_type(recv_type)
    needs_big_wrap = 0
    if elem_var.start_with?("lv_") && iter_elem_t == "int"
      slot_t_iter = find_var_type(elem_var[3, elem_var.length - 3])
      if slot_t_iter == "bigint"
        needs_big_wrap = 1
        @needs_bigint = 1
      end
    end
    if recv_type == "range"
      rtmp = new_temp
      emit("  sp_Range " + rtmp + " = " + rc + ";")
      emit("  for (mrb_int " + idx_var + " = " + rtmp + ".first; " + idx_var + " <= " + rtmp + ".last; " + idx_var + "++) {")
      if needs_big_wrap == 1
        emit("    " + elem_var + " = sp_bigint_new_int(" + idx_var + ");")
      else
        emit("    " + elem_var + " = " + idx_var + ";")
      end
      return
    end
    pfx = array_c_prefix(recv_type)
    emit("  for (mrb_int " + idx_var + " = 0; " + idx_var + " < sp_" + pfx + "_length(" + rc + "); " + idx_var + "++) {")
    if needs_big_wrap == 1
      emit("    " + elem_var + " = sp_bigint_new_int(sp_" + pfx + "_get(" + rc + ", " + idx_var + "));")
    else
      emit("    " + elem_var + " = sp_" + pfx + "_get(" + rc + ", " + idx_var + ");")
    end
  end

 # Element type of an iterable (for block param type inference).
  def iter_elem_type(recv_type)
    if recv_type == "range"
      return "int"
    end
    elem_type_of_array(recv_type)
  end

  def compile_array_sum_block(nid, rc, recv_type)
    bp1 = get_block_param(nid, 0)
    if bp1 == ""
      bp1 = "_x"
    end
    tmp_sum = new_temp
    tmp_i = new_temp
    if recv_type == "float_array"
      emit("  mrb_float " + tmp_sum + " = " + compile_arg0_as_float(nid) + ";")
    else
      emit("  mrb_int " + tmp_sum + " = " + compile_arg0_as_int(nid) + ";")
    end
    emit_iter_open(rc, recv_type, "lv_" + bp1, tmp_i)
    push_scope
 # promote-mode-widened block param: keep the inner scope in
 # agreement with the C-level decl so `x * 2` lowers via
 # sp_bigint_mul, not sp_int_mul. find_var_type before the
 # push_scope reads the outer (declare_method_locals) entry.
    bp1_t_sum = find_var_type(bp1)
    if bp1_t_sum != "bigint"
      bp1_t_sum = iter_elem_type(recv_type)
    end
    declare_var(bp1, bp1_t_sum)
    blk = @nd_block[nid]
    bexpr = "0"
    if @nd_body[blk] >= 0
      bs = get_stmts(@nd_body[blk])
      if bs.length > 0
        k = 0
        while k < bs.length - 1
          compile_stmt(bs[k])
          k = k + 1
        end
        bexpr = compile_expr(bs.last)
      end
    end
    if bp1_t_sum == "bigint"
      @needs_bigint = 1
      emit("    " + tmp_sum + " += sp_bigint_to_int((sp_Bigint *)" + bexpr + ");")
    else
      emit("    " + tmp_sum + " += " + bexpr + ";")
    end
    pop_scope
    emit("  }")
    tmp_sum
  end

  def compile_array_count_block(nid, rc, recv_type)
    bp1 = get_block_param(nid, 0)
    if bp1 == ""
      bp1 = "_x"
    end
    tmp_cnt = new_temp
    tmp_i = new_temp
    emit("  mrb_int " + tmp_cnt + " = 0;")
    emit_iter_open(rc, recv_type, "lv_" + bp1, tmp_i)
    push_scope
    bp1_t_cnt = find_var_type(bp1)
    if bp1_t_cnt != "bigint"
      bp1_t_cnt = iter_elem_type(recv_type)
    end
    declare_var(bp1, bp1_t_cnt)
    blk = @nd_block[nid]
    bexpr = "0"
    if @nd_body[blk] >= 0
      bs = get_stmts(@nd_body[blk])
      if bs.length > 0
        k = 0
        while k < bs.length - 1
          compile_stmt(bs[k])
          k = k + 1
        end
        bexpr = compile_expr(bs.last)
      end
    end
    emit("    if (" + bexpr + ") " + tmp_cnt + "++;")
    pop_scope
    emit("  }")
    tmp_cnt
  end

  def compile_array_min_max_block(nid, rc, recv_type, mname)
    bp1 = get_block_param(nid, 0)
    if bp1 == ""
      bp1 = "_x"
    end
    elem_type = "int"
    if recv_type == "str_array"
      elem_type = "string"
    elsif recv_type == "float_array"
      elem_type = "float"
    end
    tmp_res = new_temp
    tmp_key = new_temp
    tmp_i = new_temp
    bp_tmp = new_temp
    emit("  " + c_type(elem_type) + " " + tmp_res + " = " + c_default_val(elem_type) + ";")
    emit("  mrb_int " + tmp_key + " = 0;")
    emit("  " + c_type(elem_type) + " " + bp_tmp + " = " + c_default_val(elem_type) + ";")
    emit_iter_open(rc, recv_type, "lv_" + bp1, tmp_i)
    emit("    " + bp_tmp + " = lv_" + bp1 + ";")
    push_scope
    declare_var(bp1, elem_type)
    blk = @nd_block[nid]
    bexpr = "0"
    if @nd_body[blk] >= 0
      bs = get_stmts(@nd_body[blk])
      if bs.length > 0
        k = 0
        while k < bs.length - 1
          compile_stmt(bs[k])
          k = k + 1
        end
        bexpr = compile_expr(bs.last)
      end
    end
    cmp = ">"
    if mname == "min"
      cmp = "<"
    end
    emit("    mrb_int _k = " + bexpr + ";")
    emit("    if (" + tmp_i + " == 0 || _k " + cmp + " " + tmp_key + ") { " + tmp_res + " = " + bp_tmp + "; " + tmp_key + " = _k; }")
    pop_scope
    emit("  }")
    tmp_res
  end

  def compile_array_filter_map(nid, rc, recv_type)
    bp1 = get_block_param(nid, 0)
    if bp1 == ""
      bp1 = "_x"
    end
    elem_t = iter_elem_type(recv_type)
    push_scope
    declare_var(bp1, elem_t)
    blk = @nd_block[nid]
    block_ret = "int"
    if blk >= 0
      bbody = @nd_body[blk]
      if bbody >= 0
        bbs = get_stmts(bbody)
        if bbs.length > 0
          block_ret = infer_type(bbs.last)
        end
      end
    end
    if block_ret == "string"
      result_type = "str_array"
    elsif block_ret == "float"
      result_type = "float_array"
    else
      result_type = "int_array"
    end
    pfx_dst = array_c_prefix(result_type)
    @needs_gc = 1
    tmp_arr = new_temp
    tmp_i = new_temp
    tmp_val = new_temp
    emit("  " + c_type(result_type) + " " + tmp_arr + " = sp_" + pfx_dst + "_new();")
    emit_iter_open(rc, recv_type, "lv_" + bp1, tmp_i)
    @indent = @indent + 1
    bexpr = "0"
    if blk >= 0
      bbody2 = @nd_body[blk]
      if bbody2 >= 0
        bs = get_stmts(bbody2)
        if bs.length > 0
          k = 0
          while k < bs.length - 1
            compile_stmt(bs[k])
            k = k + 1
          end
          bexpr = compile_expr(bs.last)
        end
      end
    end
    emit("  " + c_type(block_ret) + " " + tmp_val + " = " + bexpr + ";")
    emit("  if (" + tmp_val + ") sp_" + pfx_dst + "_push(" + tmp_arr + ", " + tmp_val + ");")
    @indent = @indent - 1
    pop_scope
    emit("  }")
    tmp_arr
  end

  def compile_array_find_block(nid, rc, recv_type)
    bp1 = get_block_param(nid, 0)
    if bp1 == ""
      bp1 = "_x"
    end
    elem_type = iter_elem_type(recv_type)
    tmp_res = new_temp
    tmp_i = new_temp
    emit("  " + c_type(elem_type) + " " + tmp_res + " = " + c_default_val(elem_type) + ";")
    emit_iter_open(rc, recv_type, "lv_" + bp1, tmp_i)
    push_scope
    declare_var(bp1, elem_type)
    blk = @nd_block[nid]
    bbody = @nd_body[blk]
    bexpr = "0"
    if bbody >= 0
      bs = get_stmts(bbody)
      if bs.length > 0
        k = 0
        while k < bs.length - 1
          compile_stmt(bs[k])
          k = k + 1
        end
        bexpr = compile_expr(bs.last)
      end
    end
    emit("    if (" + bexpr + ") { " + tmp_res + " = lv_" + bp1 + "; break; }")
    pop_scope
    emit("  }")
    tmp_res
  end

 # Array#find_index { block } -- returns the FIRST index where
 # the block is truthy, nil otherwise. Mirrors compile_array_find_block
 # but captures the index instead of the element. Result is int?
 # (SP_INT_NIL sentinel for nil). Issue #864.
  def compile_array_find_index_block(nid, rc, recv_type)
    bp1 = get_block_param(nid, 0)
    if bp1 == ""
      bp1 = "_x"
    end
    elem_type = iter_elem_type(recv_type)
    tmp_res = new_temp
    tmp_i = new_temp
    emit("  mrb_int " + tmp_res + " = SP_INT_NIL;")
    emit_iter_open(rc, recv_type, "lv_" + bp1, tmp_i)
    push_scope
    declare_var(bp1, elem_type)
    blk = @nd_block[nid]
    bbody = @nd_body[blk]
    bexpr = "0"
    if bbody >= 0
      bs = get_stmts(bbody)
      if bs.length > 0
        k = 0
        while k < bs.length - 1
          compile_stmt(bs[k])
          k = k + 1
        end
        bexpr = compile_expr(bs.last)
      end
    end
    emit("    if (" + bexpr + ") { " + tmp_res + " = " + tmp_i + "; break; }")
    pop_scope
    emit("  }")
    tmp_res
  end

  def compile_array_predicate_block(nid, rc, recv_type, mname)
 # Implements any?/all?/none? with block by short-circuit loop
    bp1 = get_block_param(nid, 0)
    if bp1 == ""
      bp1 = "_x"
    end
    tmp_res = new_temp
    tmp_i = new_temp
    init_val = "FALSE"
    if mname == "all?" || mname == "none?"
      init_val = "TRUE"
    end
    emit("  mrb_bool " + tmp_res + " = " + init_val + ";")
    emit_iter_open(rc, recv_type, "lv_" + bp1, tmp_i)
    push_scope
    bp1_t_pred = find_var_type(bp1)
    if bp1_t_pred != "bigint"
      bp1_t_pred = iter_elem_type(recv_type)
    end
    declare_var(bp1, bp1_t_pred)
    blk = @nd_block[nid]
    bbody = @nd_body[blk]
    bexpr = "0"
    if bbody >= 0
      bs = get_stmts(bbody)
      if bs.length > 0
        k = 0
        while k < bs.length - 1
          compile_stmt(bs[k])
          k = k + 1
        end
        bexpr = compile_expr(bs.last)
      end
    end
    if mname == "any?"
      emit("    if (" + bexpr + ") { " + tmp_res + " = TRUE; break; }")
    elsif mname == "all?"
      emit("    if (!(" + bexpr + ")) { " + tmp_res + " = FALSE; break; }")
    elsif mname == "one?"
      emit("    if (" + bexpr + ") { if (" + tmp_res + ") { " + tmp_res + " = FALSE; break; } " + tmp_res + " = TRUE; }")
    else
 # none?
      emit("    if (" + bexpr + ") { " + tmp_res + " = FALSE; break; }")
    end
    pop_scope
    emit("  }")
    tmp_res
  end

 # Per-variant lookup: returns a dispatch struct describing how to
 # iterate a hash, read keys/values, declare block-param locals, and
 # build a same-type result. Index [0]=ctor, [1]=getter, [2]=setter,
 # [3]=key_type_label, [4]=val_type_label, [5]=key_iter_expr_fmt
 # (where %RC% is the receiver and %I% the index var).
 # Issue #802.
  def hash_variant_info(ht)
    if ht == "str_int_hash"
      @needs_str_int_hash = 1
      return ["sp_StrIntHash_new", "sp_StrIntHash_get", "sp_StrIntHash_set", "string", "int", "%RC%->order[%I%]"]
    end
    if ht == "str_str_hash"
      @needs_str_str_hash = 1
      return ["sp_StrStrHash_new", "sp_StrStrHash_get", "sp_StrStrHash_set", "string", "string", "%RC%->order[%I%]"]
    end
    if ht == "sym_int_hash"
      @needs_sym_int_hash = 1
      return ["sp_SymIntHash_new", "sp_SymIntHash_get", "sp_SymIntHash_set", "symbol", "int", "%RC%->order[%I%]"]
    end
    if ht == "sym_str_hash"
      @needs_sym_str_hash = 1
      return ["sp_SymStrHash_new", "sp_SymStrHash_get", "sp_SymStrHash_set", "symbol", "string", "%RC%->order[%I%]"]
    end
    if ht == "int_str_hash"
      @needs_int_str_hash = 1
      return ["sp_IntStrHash_new", "sp_IntStrHash_get", "sp_IntStrHash_set", "int", "string", "%RC%->order[%I%]"]
    end
    if ht == "str_poly_hash"
      @needs_str_poly_hash = 1
      @needs_rb_value = 1
      return ["sp_StrPolyHash_new", "sp_StrPolyHash_get", "sp_StrPolyHash_set", "string", "poly", "%RC%->order[%I%]"]
    end
    if ht == "sym_poly_hash"
      @needs_rb_value = 1
      return ["sp_SymPolyHash_new", "sp_SymPolyHash_get", "sp_SymPolyHash_set", "symbol", "poly", "%RC%->order[%I%]"]
    end
    if ht == "poly_poly_hash"
      @needs_poly_poly_hash = 1
      @needs_rb_value = 1
      return ["sp_PolyPolyHash_new", "sp_PolyPolyHash_get", "sp_PolyPolyHash_set", "poly", "poly", "%RC%->keys[%RC%->order[%I%]]"]
    end
    nil
  end

  def hash_key_iter_expr(info, rc, itmp)
    fmt = info[5]
    fmt = fmt.gsub("%RC%", rc)
    fmt = fmt.gsub("%I%", itmp)
    fmt
  end

  def compile_hash_select_reject(nid, hash_type, rc, mname)
 # Build a new hash by filtering entries using the block. Block
 # params (lv_<k>, lv_<v>) are re-declared scope-locally inside
 # the for body so the C type matches this variant's key/value
 # ABI even when the same Ruby block-param name was used earlier
 # at a different variant (the function-level decl picks one).
    info = hash_variant_info(hash_type)
    if info.nil?
      return "0"
    end
    bp1 = get_block_param(nid, 0)
    bp2 = get_block_param(nid, 1)
    if bp1 == ""
      bp1 = "_k"
    end
    if bp2 == ""
      bp2 = "_v"
    end
    ctor = info[0]
    getter = info[1]
    setter = info[2]
    key_type = info[3]
    val_type = info[4]
    @needs_gc = 1
    tmp = new_temp
    itmp = new_temp
    emit("  " + c_type(hash_type) + tmp + " = " + ctor + "();")
    emit("  for (mrb_int " + itmp + " = 0; " + itmp + " < " + rc + "->len; " + itmp + "++) {")
    key_expr = hash_key_iter_expr(info, rc, itmp)
    emit("    " + c_type(key_type) + " lv_" + bp1 + " = " + key_expr + ";")
    emit("    " + c_type(val_type) + " lv_" + bp2 + " = " + getter + "(" + rc + ", lv_" + bp1 + ");")
    push_scope
    declare_var(bp1, key_type)
    declare_var(bp2, val_type)
    blk = @nd_block[nid]
    bbody = @nd_body[blk]
    bexpr = "0"
    if bbody >= 0
      bs = get_stmts(bbody)
      if bs.length > 0
        k = 0
        while k < bs.length - 1
          compile_stmt(bs[k])
          k = k + 1
        end
        bexpr = compile_expr(bs.last)
      end
    end
    cond = bexpr
    if mname == "reject"
      cond = "!(" + bexpr + ")"
    end
    emit("    if (" + cond + ") " + setter + "(" + tmp + ", lv_" + bp1 + ", lv_" + bp2 + ");")
    pop_scope
    emit("  }")
    tmp
  end

  def compile_hash_block_predicate(nid, hash_type, rc, mname)
    info = hash_variant_info(hash_type)
    if info.nil?
      return "0"
    end
    bp1 = get_block_param(nid, 0)
    bp2 = get_block_param(nid, 1)
    if bp1 == ""
      bp1 = "_k"
    end
    if bp2 == ""
      bp2 = "_v"
    end
    getter = info[1]
    key_type = info[3]
    val_type = info[4]
    push_scope
    declare_var(bp1, key_type)
    declare_var(bp2, val_type)
    itmp = new_temp
    key_expr = hash_key_iter_expr(info, rc, itmp)
    blk = @nd_block[nid]
    bbody = @nd_body[blk]
    bexpr = "0"
    if mname == "count"
      tmp_c = new_temp
      emit("  mrb_int " + tmp_c + " = 0;")
      emit("  for (mrb_int " + itmp + " = 0; " + itmp + " < " + rc + "->len; " + itmp + "++) {")
      emit("    " + c_type(key_type) + " lv_" + bp1 + " = " + key_expr + ";")
      emit("    " + c_type(val_type) + " lv_" + bp2 + " = " + getter + "(" + rc + ", lv_" + bp1 + ");")
      if bbody >= 0
        bs = get_stmts(bbody)
        k = 0
        while k < bs.length - 1
          compile_stmt(bs[k])
          k = k + 1
        end
        if bs.length > 0
          bexpr = compile_expr(bs.last)
        end
      end
      emit("    if (" + bexpr + ") " + tmp_c + "++;")
      emit("  }")
      pop_scope
      return tmp_c
    end
    if mname == "any?"
      tmp_r = new_temp
      emit("  mrb_bool " + tmp_r + " = FALSE;")
      emit("  for (mrb_int " + itmp + " = 0; " + itmp + " < " + rc + "->len; " + itmp + "++) {")
      emit("    " + c_type(key_type) + " lv_" + bp1 + " = " + key_expr + ";")
      emit("    " + c_type(val_type) + " lv_" + bp2 + " = " + getter + "(" + rc + ", lv_" + bp1 + ");")
      if bbody >= 0
        bs = get_stmts(bbody)
        k = 0
        while k < bs.length - 1
          compile_stmt(bs[k])
          k = k + 1
        end
        if bs.length > 0
          bexpr = compile_expr(bs.last)
        end
      end
      emit("    if (" + bexpr + ") { " + tmp_r + " = TRUE; break; }")
      emit("  }")
      pop_scope
      return tmp_r
    end
    if mname == "all?"
      tmp_r = new_temp
      emit("  mrb_bool " + tmp_r + " = TRUE;")
      emit("  for (mrb_int " + itmp + " = 0; " + itmp + " < " + rc + "->len; " + itmp + "++) {")
      emit("    " + c_type(key_type) + " lv_" + bp1 + " = " + key_expr + ";")
      emit("    " + c_type(val_type) + " lv_" + bp2 + " = " + getter + "(" + rc + ", lv_" + bp1 + ");")
      if bbody >= 0
        bs = get_stmts(bbody)
        k = 0
        while k < bs.length - 1
          compile_stmt(bs[k])
          k = k + 1
        end
        if bs.length > 0
          bexpr = compile_expr(bs.last)
        end
      end
      emit("    if (!(" + bexpr + ")) { " + tmp_r + " = FALSE; break; }")
      emit("  }")
      pop_scope
      return tmp_r
    end
 # find / detect -- key-only result (CRuby returns [k,v] array;
 # spinel emits the key for the str variants today, keep that
 # shape for consistency. Restricted to string-keyed variants
 # because the return type is currently committed to const char *
 # by the analyzer.
    if mname == "find" || mname == "detect"
      if key_type != "string"
        pop_scope
        return "0"
      end
      tmp_r = new_temp
      emit("  const char *" + tmp_r + " = \"\";")
      emit("  for (mrb_int " + itmp + " = 0; " + itmp + " < " + rc + "->len; " + itmp + "++) {")
      emit("    " + c_type(key_type) + " lv_" + bp1 + " = " + key_expr + ";")
      emit("    " + c_type(val_type) + " lv_" + bp2 + " = " + getter + "(" + rc + ", lv_" + bp1 + ");")
      if bbody >= 0
        bs = get_stmts(bbody)
        k = 0
        while k < bs.length - 1
          compile_stmt(bs[k])
          k = k + 1
        end
        if bs.length > 0
          bexpr = compile_expr(bs.last)
        end
      end
      emit("    if (" + bexpr + ") { " + tmp_r + " = lv_" + bp1 + "; break; }")
      emit("  }")
      pop_scope
      return tmp_r
    end
    pop_scope
    "0"
  end

  def compile_flat_map_expr(nid)
 # flat_map: for each element, block returns an array; concat all results
    rt = infer_type(@nd_receiver[nid])
    rc = compile_expr_gc_rooted(@nd_receiver[nid])
    bp1 = get_block_param(nid, 0)
    if bp1 == ""
      bp1 = "_x"
    end
    elem_type = "int"
    if rt == "str_array"
      elem_type = "string"
    elsif rt == "float_array"
      elem_type = "float"
    elsif rt == "poly_array"
      elem_type = "poly"
    elsif is_ptr_array_type(rt) == 1
      elem_type = ptr_array_elem_type(rt)
    end
    push_scope
    declare_var(bp1, elem_type)
    blk = @nd_block[nid]
    block_ret = "int_array"
    if blk >= 0
      bbody = @nd_body[blk]
      if bbody >= 0
        bbs = get_stmts(bbody)
        if bbs.length > 0
          block_ret = infer_type(bbs.last)
        end
      end
    end
 # Fall back to receiver type if block doesn't return an array
    if is_array_type(block_ret) == 0
      block_ret = rt
    end
    @needs_gc = 1
    pfx_src = array_c_prefix(rt)
    pfx_dst = array_c_prefix(block_ret)
    tmp_arr = new_temp
    tmp_i = new_temp
    tmp_inner = new_temp
    tmp_j = new_temp
    emit("  " + c_type(block_ret) + tmp_arr + " = sp_" + pfx_dst + "_new();")
    emit("  for (mrb_int " + tmp_i + " = 0; " + tmp_i + " < sp_" + pfx_src + "_length(" + rc + "); " + tmp_i + "++) {")
    emit("    lv_" + bp1 + " = sp_" + pfx_src + "_get(" + rc + ", " + tmp_i + ");")
    @indent = @indent + 1
    bbody2 = @nd_body[blk]
    if bbody2 >= 0
      bbs2 = get_stmts(bbody2)
 # Compile all but last statement
      k = 0
      while k < bbs2.length - 1
        compile_stmt(bbs2[k])
        k = k + 1
      end
      last = bbs2.last
      val = compile_expr(last)
      emit("  " + c_type(block_ret) + tmp_inner + " = " + val + ";")
      emit("  for (mrb_int " + tmp_j + " = 0; " + tmp_j + " < sp_" + pfx_dst + "_length(" + tmp_inner + "); " + tmp_j + "++)")
      emit("    sp_" + pfx_dst + "_push(" + tmp_arr + ", sp_" + pfx_dst + "_get(" + tmp_inner + ", " + tmp_j + "));")
    end
    @indent = @indent - 1
    emit("  }")
    pop_scope
    tmp_arr
  end

 # An empty `map {}` block yields nil per iteration in CRuby —
 # the result array's length still matches the receiver. Without
 # an explicit push the typed accumulator stays short and
 # downstream `.length` / `[i]` on the result is wrong. Push a
 # type-appropriate default (0 / 0.0 / "" / sp_box_nil) so
 # length is preserved across all map dispatches.
  def emit_map_default_push(target, container_type)
    if container_type == "str_array"
      emit("  sp_StrArray_push(" + target + ", \"\");")
    elsif container_type == "float_array"
      emit("  sp_FloatArray_push(" + target + ", 0.0);")
    elsif container_type == "poly_array"
      @needs_rb_value = 1
      emit("  sp_PolyArray_push(" + target + ", sp_box_nil());")
    elsif container_type == "ptr_array"
      emit("  sp_PtrArray_push(" + target + ", NULL);")
    else
      emit("  sp_IntArray_push(" + target + ", 0);")
    end
  end

  def compile_map_expr(nid, precomputed_rc = "")
 # N.times.map { |i| ... } -> loop 0..N-1 building an array
    recv_n = @nd_receiver[nid]
    if recv_n >= 0 && @nd_type[recv_n] == "CallNode" && @nd_name[recv_n] == "times" && @nd_block[recv_n] < 0
      @needs_gc = 1
      ncount = compile_expr(@nd_receiver[recv_n])
      bpn = get_block_param(nid, 0)
      res_type = "int"
      blk_n = @nd_block[nid]
 # Block param type: under promote mode the analyzer widens int
 # LVs to bigint. Default to "int" but bump to "bigint" under
 # promote so the inline assignment / arithmetic dispatches
 # consistently.
      bpn_decl_t = (@int_overflow_mode == "promote") ? "bigint" : "int"
      push_scope
      if bpn != ""
        declare_var(bpn, bpn_decl_t)
      end
      if blk_n >= 0
        body_n = @nd_body[blk_n]
        if body_n >= 0
          stmts_n = get_stmts(body_n)
          if stmts_n.length > 0
            res_type = infer_type(stmts_n.last)
 # Stale-int cache: block's `i + 1` may cache as int even when
 # the bp `i` was widened to bigint at scope_types time. Re-walk
 # the expr emit at the result-type peek.
            if res_type == "int" && expr_emit_is_bigint(stmts_n.last) == 1
              res_type = "bigint"
            end
          end
        end
      end
      tmp_arrn = new_temp
      tmp_in = new_temp
 # When the block body returns an array (or any pointer-shaped
 # value), the outer .map collects them into a sp_PtrArray
 # rather than sp_IntArray (which would pun the IntArray
 # pointers as mrb_int and trip -Wint-conversion). Issue #553:
 # `2.times.map { gets.split.map &:to_i }` builds an
 # array-of-IntArrays; static type is int_array_ptr_array
 # and inspect knows how to render it.
      nested_arr_outer = 0
      times_use_poly = 0
      if res_type == "string"
        @needs_str_array = 1
        emit("  sp_StrArray *" + tmp_arrn + " = sp_StrArray_new();")
      elsif res_type == "float"
        emit("  sp_FloatArray *" + tmp_arrn + " = sp_FloatArray_new();")
      elsif res_type == "int_array" || res_type == "str_array" || res_type == "float_array" || res_type == "sym_array" || res_type == "poly_array" || res_type.end_with?("_ptr_array")
        @needs_gc = 1
        nested_arr_outer = 1
        emit("  sp_PtrArray *" + tmp_arrn + " = sp_PtrArray_new();")
      elsif res_type == "bigint"
 # Under promote mode the analyzer's infer_call_type widens
 # N.times.map { bigint_expr } to poly_array. Match that on the
 # codegen side -- build a PolyArray boxing each value -- so the
 # downstream chain (e.g. .each_cons) reads the right runtime
 # type. Without this, the chain saw IntArray-cast-to-PolyArray.
        @needs_rb_value = 1
        times_use_poly = 1
        emit("  sp_PolyArray *" + tmp_arrn + " = sp_PolyArray_new();")
      else
        @needs_int_array = 1
        emit("  sp_IntArray *" + tmp_arrn + " = sp_IntArray_new();")
      end
 # Root the accumulator so a GC pass triggered by an
 # allocation inside the block (e.g. string interpolation)
 # doesn't free the half-built array. Same reasoning as the
 # int_array / str_array branches further down.
      emit("  SP_GC_ROOT(" + tmp_arrn + ");")
      emit("  for (mrb_int " + tmp_in + " = 0; " + tmp_in + " < " + ncount + "; " + tmp_in + "++) {")
      if bpn != ""
        bpn_t_mp = find_var_type(bpn)
        if bpn_t_mp == "bigint"
          @needs_bigint = 1
          emit("    lv_" + bpn + " = sp_bigint_new_int(" + tmp_in + ");")
        else
          emit("    lv_" + bpn + " = " + tmp_in + ";")
        end
      end
      @indent = @indent + 1
      if blk_n >= 0
        body_n2 = @nd_body[blk_n]
        stmts_n2 = body_n2 >= 0 ? get_stmts(body_n2) : []
        n_container = res_type == "string" ? "str_array" : (res_type == "float" ? "float_array" : "int_array")
        if stmts_n2.length > 0
          k = 0
          while k < stmts_n2.length - 1
            compile_stmt(stmts_n2[k])
            k = k + 1
          end
          lastv = compile_expr(stmts_n2.last)
          if res_type == "string"
            emit("  sp_StrArray_push(" + tmp_arrn + ", " + lastv + ");")
          elsif res_type == "float"
            emit("  sp_FloatArray_push(" + tmp_arrn + ", " + lastv + ");")
          elsif nested_arr_outer == 1
            emit("  sp_PtrArray_push(" + tmp_arrn + ", " + lastv + ");")
          elsif times_use_poly == 1
 # PolyArray accumulator for promote-mode bigint block return.
 # Box each value to sp_box_int after unboxing the bigint.
            @needs_bigint = 1
            emit("  sp_PolyArray_push(" + tmp_arrn + ", sp_box_int(sp_bigint_to_int((sp_Bigint *)" + lastv + ")));")
          else
 # promote-mode block tail returning bigint into IntArray;
 # unbox before pushing.
            if infer_type(stmts_n2.last) == "bigint"
              @needs_bigint = 1
              lastv = "sp_bigint_to_int((sp_Bigint *)" + lastv + ")"
            end
            emit("  sp_IntArray_push(" + tmp_arrn + ", " + lastv + ");")
          end
        else
          emit_map_default_push(tmp_arrn, n_container)
        end
      end
      @indent = @indent - 1
      emit("  }")
      pop_scope
      return tmp_arrn
    end
 # arr.each_cons(n)[.with_index(off)].map { ... } -- fuse the 2-
 # or 3-step chain into a single C loop. Without `.with_index`
 # the block sees `|pair|` (sub-array of recv's element type) or
 # `|(a, b, ...)|` (destructured slots). With `.with_index` the
 # block additionally sees a counter as the trailing param. The
 # outer .map's accumulator type tracks `infer_type(body_last)`:
 # scalar bodies collect into the matching typed-array; array
 # bodies collect into sp_PtrArray.
    ec_call_n = -1
    ec_with_index = 0
    ec_off_expr = "0"
    ec_is_slice = 0
    if recv_n >= 0 && @nd_type[recv_n] == "CallNode" && @nd_name[recv_n] == "with_index" && @nd_block[recv_n] < 0
      wi_inner_n = @nd_receiver[recv_n]
      if wi_inner_n >= 0 && @nd_type[wi_inner_n] == "CallNode" && (@nd_name[wi_inner_n] == "each_cons" || @nd_name[wi_inner_n] == "each_slice") && @nd_block[wi_inner_n] < 0
        ec_call_n = wi_inner_n
        ec_with_index = 1
        ec_is_slice = (@nd_name[wi_inner_n] == "each_slice") ? 1 : 0
        wi_args_id = @nd_arguments[recv_n]
        if wi_args_id >= 0
          wi_aargs = get_args(wi_args_id)
          if wi_aargs.length > 0
            ec_off_expr = compile_arg0(recv_n)
          end
        end
      end
    elsif recv_n >= 0 && @nd_type[recv_n] == "CallNode" && (@nd_name[recv_n] == "each_cons" || @nd_name[recv_n] == "each_slice") && @nd_block[recv_n] < 0
      ec_call_n = recv_n
      ec_is_slice = (@nd_name[recv_n] == "each_slice") ? 1 : 0
    end
    if ec_call_n >= 0
      @needs_gc = 1
      ec_inner_n = @nd_receiver[ec_call_n]
      ec_inner_t = infer_type(ec_inner_n)
      if is_array_type(ec_inner_t) == 1
        ec_inner_pfx = array_c_prefix(ec_inner_t)
        ec_elem_t = elem_type_of_array(ec_inner_t)
        ec_inner_rc = compile_expr_gc_rooted(ec_inner_n)
        ec_n_expr = compile_arg0(ec_call_n)
        ec_blk_n = @nd_block[nid]
 # Detect `|(a, b, ...)|` destructure: MultiTargetNode at the
 # first required slot. parse_id_list(@nd_targets[mt_id]) gives
 # the inner RequiredParameterNode ids; their `name` field is
 # the local to bind. Without this, the block sees the window
 # as a sub-array.
        ec_destruct_names = "".split(",", -1)
        ec_bp_node = -1
        if ec_blk_n >= 0
          ec_bp_node = @nd_parameters[ec_blk_n]
        end
        ec_inner_params = -1
        if ec_bp_node >= 0
          ec_inner_params = @nd_parameters[ec_bp_node]
        end
        ec_reqs = []
        if ec_inner_params >= 0
          ec_reqs = parse_id_list(@nd_requireds[ec_inner_params])
        end
        if ec_reqs.length >= 1 && @nd_type[ec_reqs[0]] == "MultiTargetNode"
          ec_lefts = parse_id_list(@nd_targets[ec_reqs[0]])
          ec_li = 0
          while ec_li < ec_lefts.length
            ec_destruct_names.push(@nd_name[ec_lefts[ec_li]])
            ec_li = ec_li + 1
          end
        else
 # Issue #829: auto-destructure when block params count matches
 # the yielded sub-array's length. `n` from each_cons/each_slice
 # decides; `|pair, i|` against each_cons(2).with_index (reqs=2,
 # need n+1=3) stays a pair.
          ec_n_int = -1
          ec_args_n_id = @nd_arguments[ec_call_n]
          if ec_args_n_id >= 0
            ec_n_args_l = get_args(ec_args_n_id)
            if ec_n_args_l.length > 0 && @nd_type[ec_n_args_l[0]] == "IntegerNode"
              ec_n_int = @nd_value[ec_n_args_l[0]].to_i
            end
          end
          ec_expected = ec_n_int + ec_with_index
          if ec_n_int > 0 && ec_reqs.length == ec_expected && ec_reqs.length >= 2
            ec_destruct_count = ec_n_int
            ec_li2 = 0
            while ec_li2 < ec_destruct_count
              ec_destruct_names.push(@nd_name[ec_reqs[ec_li2]])
              ec_li2 = ec_li2 + 1
            end
          end
        end
 # Result accumulator type from body's last-expression type.
        ec_res_type = "int"
        if ec_blk_n >= 0
          ec_body_n = @nd_body[ec_blk_n]
          if ec_body_n >= 0
            ec_stmts_n = get_stmts(ec_body_n)
            if ec_stmts_n.length > 0
              ec_res_type = infer_type(ec_stmts_n.last)
            end
          end
        end
        ec_tmp_arr = new_temp
        ec_nested = 0
        ec_use_poly = 0
        if ec_res_type == "string"
          @needs_str_array = 1
          emit("  sp_StrArray *" + ec_tmp_arr + " = sp_StrArray_new();")
        elsif ec_res_type == "float"
          emit("  sp_FloatArray *" + ec_tmp_arr + " = sp_FloatArray_new();")
        elsif ec_res_type == "poly_array" || is_ptr_array_type(ec_res_type) == 1
 # Block returns a deeper-nested array (poly_array or
 # *_ptr_array): under promote mode the literal `[bigint, bigint]`
 # cached as poly_array, so the outer accumulator must itself be
 # PolyArray to keep the cls_id tag chain. Default-mode tests
 # don't reach this arm (their block returns a concrete typed
 # array and falls into the next branch).
          @needs_rb_value = 1
          ec_use_poly = 1
          emit("  sp_PolyArray *" + ec_tmp_arr + " = sp_PolyArray_new();")
        elsif is_array_type(ec_res_type) == 1
          ec_nested = 1
          emit("  sp_PtrArray *" + ec_tmp_arr + " = sp_PtrArray_new();")
        elsif ec_res_type == "bigint" || ec_res_type == "poly"
 # Promote-mode block returning bigint (or any cached poly):
 # the analyzer's infer_call_type widens the outer map result
 # to poly_array, so build a PolyArray boxing each value. Keeps
 # caller-side `p` / `.inspect` dispatch consistent with the
 # type signature.
          @needs_rb_value = 1
          ec_use_poly = 1
          emit("  sp_PolyArray *" + ec_tmp_arr + " = sp_PolyArray_new();")
        else
          @needs_int_array = 1
          emit("  sp_IntArray *" + ec_tmp_arr + " = sp_IntArray_new();")
        end
        emit("  SP_GC_ROOT(" + ec_tmp_arr + ");")
        ec_i = new_temp
        ec_j = new_temp
        ec_len = new_temp
        ec_idx_var = ""
        if ec_with_index == 1
          ec_idx_var = new_temp
          emit("  mrb_int " + ec_idx_var + " = (" + ec_off_expr + ");")
        end
        emit("  mrb_int " + ec_len + " = sp_" + ec_inner_pfx + "_length(" + ec_inner_rc + ");")
 # Issue #829: each_slice steps by n (fixed chunks); each_cons
 # slides one element at a time. Short tails are dropped — Ruby's
 # each_slice yields them but typed-array destructure can't bind
 # missing positions safely.
        ec_step = (ec_is_slice == 1) ? ec_n_expr : "1"
        emit("  for (mrb_int " + ec_i + " = 0; " + ec_i + " + " + ec_n_expr + " <= " + ec_len + "; " + ec_i + " += " + ec_step + ") {")
        push_scope
        ec_pair_bp = ""
        if ec_destruct_names.length > 0
 # Destructure: bind each inner name directly to a window slot;
 # no sub-array allocation. Under promote mode the analyzer widens
 # scope LVs int->bigint so the block body's arithmetic dispatches
 # via sp_bigint_*. Box each IntArray element to sp_Bigint* at the
 # bind so the codegen and analyzer agree.
          ec_destruct_promote = (@int_overflow_mode == "promote" && ec_elem_t == "int") ? 1 : 0
          ec_di = 0
          while ec_di < ec_destruct_names.length
            ec_slot = "lv_" + ec_destruct_names[ec_di]
            ec_get_e = "sp_" + ec_inner_pfx + "_get(" + ec_inner_rc + ", " + ec_i + " + " + ec_di.to_s + ")"
            if ec_destruct_promote == 1
              @needs_bigint = 1
              emit("    sp_Bigint * " + ec_slot + " = sp_bigint_new_int(" + ec_get_e + ");")
              declare_var(ec_destruct_names[ec_di], "bigint")
            else
              emit("    " + c_type(ec_elem_t) + " " + ec_slot + " = " + ec_get_e + ";")
              declare_var(ec_destruct_names[ec_di], ec_elem_t)
            end
            ec_di = ec_di + 1
          end
        else
 # Non-destructure: build the window sub-array as the block param.
          ec_pair_bp = get_block_param(nid, 0)
          if ec_pair_bp == ""
            ec_pair_bp = "_pair"
          end
          emit("    " + c_type(ec_inner_t) + " lv_" + ec_pair_bp + " = sp_" + ec_inner_pfx + "_new();")
          emit("    SP_GC_ROOT(lv_" + ec_pair_bp + ");")
          emit("    for (mrb_int " + ec_j + " = 0; " + ec_j + " < " + ec_n_expr + "; " + ec_j + "++)")
          emit("      sp_" + ec_inner_pfx + "_push(lv_" + ec_pair_bp + ", sp_" + ec_inner_pfx + "_get(" + ec_inner_rc + ", " + ec_i + " + " + ec_j + "));")
          declare_var(ec_pair_bp, ec_inner_t)
        end
        if ec_with_index == 1
          ec_idx_bp = get_block_param(nid, 1)
          if ec_idx_bp == ""
            ec_idx_bp = "_idx"
          end
 # Under promote mode the analyzer widens scope LVs int->bigint
 # globally, including the with_index counter param. Match that
 # on the codegen side so the block body's arithmetic on the
 # counter dispatches via sp_bigint_* helpers consistently with
 # the cached @nd_inferred_type entries.
          if @int_overflow_mode == "promote"
            @needs_bigint = 1
            emit("    sp_Bigint * lv_" + ec_idx_bp + " = sp_bigint_new_int(" + ec_idx_var + ");")
            declare_var(ec_idx_bp, "bigint")
          else
            emit("    mrb_int lv_" + ec_idx_bp + " = " + ec_idx_var + ";")
            declare_var(ec_idx_bp, "int")
          end
        end
        @indent = @indent + 1
        if ec_blk_n >= 0
          ec_body_n2 = @nd_body[ec_blk_n]
          ec_stmts_n2 = get_stmts(ec_body_n2)
          if ec_stmts_n2.length > 0
            ec_k = 0
            while ec_k < ec_stmts_n2.length - 1
              compile_stmt(ec_stmts_n2[ec_k])
              ec_k = ec_k + 1
            end
            ec_lastv = compile_expr(ec_stmts_n2.last)
            if ec_res_type == "string"
              emit("  sp_StrArray_push(" + ec_tmp_arr + ", " + ec_lastv + ");")
            elsif ec_res_type == "float"
              emit("  sp_FloatArray_push(" + ec_tmp_arr + ", " + ec_lastv + ");")
            elsif ec_nested == 1
              emit("  sp_PtrArray_push(" + ec_tmp_arr + ", " + ec_lastv + ");")
            elsif ec_use_poly == 1
 # PolyArray accumulator: box each element. If the block returns
 # a deeper-nested poly_array (literal array of bigints in
 # promote mode), wrap with sp_box_poly_array; otherwise the
 # element is a scalar bigint (or stale-int bigint emit) and
 # boxes via sp_box_int(sp_bigint_to_int(...)).
              if ec_res_type == "poly_array" || is_ptr_array_type(ec_res_type) == 1
                @needs_rb_value = 1
                emit("  sp_PolyArray_push(" + ec_tmp_arr + ", sp_box_poly_array(" + ec_lastv + "));")
              else
                @needs_bigint = 1
                emit("  sp_PolyArray_push(" + ec_tmp_arr + ", sp_box_int(sp_bigint_to_int((sp_Bigint *)" + ec_lastv + ")));")
              end
            else
 # Only wrap with sp_bigint_to_int when the compiled expression
 # actually produces an sp_Bigint *. The cached infer_type can lag
 # the emit (in promote mode arith CallNodes get annotated bigint
 # but the codegen-side compile_operator_expr still emits sp_int_add
 # when both operands' compile-time C type is mrb_int) -- wrapping
 # an mrb_int expr with sp_bigint_to_int((sp_Bigint *)...) casts
 # the int to a pointer and dereferences garbage.
              if (ec_lastv.start_with?("sp_bigint_") || ec_lastv.start_with?("(sp_Bigint *)"))
                @needs_bigint = 1
                ec_lastv = "sp_bigint_to_int((sp_Bigint *)" + ec_lastv + ")"
              end
              emit("  sp_IntArray_push(" + ec_tmp_arr + ", " + ec_lastv + ");")
            end
          end
        end
        if ec_with_index == 1
          emit("  " + ec_idx_var + "++;")
        end
        @indent = @indent - 1
        pop_scope
        emit("  }")
        return ec_tmp_arr
      end
    end
    rt = infer_type(@nd_receiver[nid])
 # Strip the nullable `?` suffix so int_array? / str_array? /
 # etc. map through the same per-container arms. The nil case
 # is left to the caller (the unconditional iteration would
 # deref NULL); in practice the recv is non-nil here because
 # a typical map call site already nil-guards above.
    if is_nullable_type(rt) == 1
      rt = rt[0, rt.length - 1]
    end
 # `precomputed_rc` comes from compile_call_expr's pre-compute
 # (issue #540). When non-empty it's already a typed-and-rooted
 # temp from compile_expr_gc_rooted; reusing it avoids a second
 # compile_expr of the recv chain. When empty we're on the
 # compile_body_return tail path (or another caller that hasn't
 # pre-compiled) and have to compile the recv ourselves.
    if precomputed_rc != ""
 # compile_expr_gc_rooted only roots when the recv is a CallNode;
 # an ArrayNode recv (e.g. `[10,20,30,40].map { ... }`) reaches
 # us as an unrooted temp. Re-root here so a GC mid-loop (the
 # block body's nested allocations cross the threshold) can't
 # sweep the array literal. Idempotent for already-rooted temps.
      rc_tmp = precomputed_rc
      if type_needs_transient_root(rt) == 1
        @needs_gc = 1
        emit("  SP_GC_ROOT(" + rc_tmp + ");")
      end
      rc = rc_tmp
    else
      rc_expr = compile_expr(@nd_receiver[nid])
 # Store receiver in a temp to avoid re-evaluation, and root it
 # when the type is a GC-allocated pointer. Without the root, an
 # array-literal receiver (`[1,2,3].map { ... }`) is held only as
 # a C-stack local; a sp_gc_collect inside the block (e.g. when
 # the block body itself does .map and grows allocations enough
 # to cross the threshold) frees the receiver mid-loop, and the
 # next `sp_*Array_length(rc)` reads a recycled IntArray's len.
      rc_tmp = new_temp
      emit("  " + c_type(rt) + " " + rc_tmp + " = " + rc_expr + ";")
      if type_needs_transient_root(rt) == 1
        @needs_gc = 1
        emit("  SP_GC_ROOT(" + rc_tmp + ");")
      end
      rc = rc_tmp
    end
    bp1 = get_block_param(nid, 0)
    if bp1 == ""
      bp1 = "_x"
    end
    tmp_arr = new_temp
    tmp_i = new_temp
 # Range#map: iterate i from first to last (inclusive when ..,
 # exclusive when ...). The receiver isn't a Range value-type
 # we can hold in a temp the way arrays are — recompile the
 # endpoints directly. ParenthesesNode (e.g. `(1..8).map {...}`)
 # is unwrapped first, since it parses as
 # CallNode(recv=ParenthesesNode(stmt=RangeNode), name=map).
    if rt == "range"
      block_ret_r = "int"
      blk_r = @nd_block[nid]
      if blk_r >= 0
        body_r = @nd_body[blk_r]
        if body_r >= 0
          stmts_r = get_stmts(body_r)
          if stmts_r.length > 0
            block_ret_r = infer_type(stmts_r.last)
          end
        end
      end
 # Scalar block returns push into the matching typed array.
 # Array-returning blocks (`(0..n).map { |i| [...] }`) produce
 # an array-of-arrays — store each block result as a pointer
 # in `<X>_ptr_array`. Block return types we can't express
 # fall through to a "0" placeholder.
      block_is_typed_array = (block_ret_r == "int_array" || block_ret_r == "str_array" ||
                              block_ret_r == "float_array" || block_ret_r == "sym_array" ||
                              is_ptr_array_type(block_ret_r) == 1 || block_ret_r == "poly_array")
      if block_ret_r != "int" && block_ret_r != "string" && block_ret_r != "float" && block_ret_r != "poly" && block_ret_r != "bigint" && block_is_typed_array == false
        return "0"
      end
      @needs_int_array = 1
      @needs_gc = 1
      ret_is_arr = false
      if block_ret_r == "string"
        @needs_str_array = 1
        emit("  sp_StrArray *" + tmp_arr + " = sp_StrArray_new();")
      elsif block_ret_r == "float"
        @needs_float_array = 1
        emit("  sp_FloatArray *" + tmp_arr + " = sp_FloatArray_new();")
      elsif block_ret_r == "poly"
 # Block returns a generic poly value (e.g. `entries[key]`
 # over a str_poly_hash) — accumulator must be PolyArray
 # since IntArray would lose the cls_id tag on the value.
        @needs_rb_value = 1
        emit("  sp_PolyArray *" + tmp_arr + " = sp_PolyArray_new();")
      elsif block_is_typed_array
 # Array-of-<X>: 1D-block-return uses PtrArray (matches
 # the inferred `<bret>_ptr_array` type). Deeper nesting
 # (block already returns ptr_array / poly_array) uses
 # PolyArray with `box_value_to_poly` boxing — the
 # cls_id chain stays tagged for `arr[i][j][k]...`
 # dispatch.
        if is_ptr_array_type(block_ret_r) == 1 || block_ret_r == "poly_array"
          @needs_rb_value = 1
          emit("  sp_PolyArray *" + tmp_arr + " = sp_PolyArray_new();")
        else
          emit("  sp_PtrArray *" + tmp_arr + " = sp_PtrArray_new();")
        end
      else
        emit("  sp_IntArray *" + tmp_arr + " = sp_IntArray_new();")
      end
 # Root the accumulator so a GC pass triggered by an
 # allocation inside the block (e.g. string interpolation)
 # doesn't free the half-built array. Same reasoning as the
 # int_array / str_array branches further down.
      emit("  SP_GC_ROOT(" + tmp_arr + ");")
 # Walk through ParenthesesNode wrappers to find a literal
 # RangeNode (so we can read its exclude_end flag and its raw
 # endpoint expressions). If the receiver is a variable holding
 # a Range — `r = 1..3; r.map {...}` — there's no AST RangeNode
 # to consult, so fall back to the runtime sp_Range value held
 # by `rc` and conservatively treat the range as inclusive
 # (sp_Range doesn't track exclude_end at runtime; see the same
 # limitation at the .each / .step paths).
      rng_id = @nd_receiver[nid]
      while rng_id >= 0 && @nd_type[rng_id] == "ParenthesesNode"
        body_pn = @nd_body[rng_id]
        if body_pn >= 0
          ps = get_stmts(body_pn)
          if ps.length > 0
            rng_id = ps.last
          else
            rng_id = -1
          end
        else
          rng_id = -1
        end
      end
      if rng_id >= 0 && @nd_type[rng_id] == "RangeNode"
        first_e = compile_expr(@nd_left[rng_id])
        last_e = compile_expr(@nd_right[rng_id])
        excl = range_excl_end(rng_id) == 1 ? "<" : "<="
      else
        rng_tmp = new_temp
        emit("  sp_Range " + rng_tmp + " = " + rc + ";")
        first_e = rng_tmp + ".first"
        last_e = rng_tmp + ".last"
        excl = "<="
      end
      emit("  for (mrb_int " + tmp_i + " = " + first_e + "; " + tmp_i + " " + excl + " " + last_e + "; " + tmp_i + "++) {")
      have_bp_r = (get_block_param(nid, 0) != "")
      if have_bp_r
        bp1_t_rng = find_var_type(bp1)
        if bp1_t_rng != "bigint"
          bp1_t_rng = "int"
        end
        declare_var(bp1, bp1_t_rng)
        if bp1_t_rng == "bigint"
          @needs_bigint = 1
          emit("    lv_" + bp1 + " = sp_bigint_new_int(" + tmp_i + ");")
        else
          emit("    lv_" + bp1 + " = " + tmp_i + ";")
        end
      end
      @indent = @indent + 1
      if blk_r >= 0
        body_r2 = @nd_body[blk_r]
        stmts_r2 = body_r2 >= 0 ? get_stmts(body_r2) : []
        r_container = block_ret_r == "string" ? "str_array" : (block_ret_r == "float" ? "float_array" : "int_array")
        k_r = 0
        while k_r < stmts_r2.length - 1
          compile_stmt(stmts_r2[k_r])
          k_r = k_r + 1
        end
        if stmts_r2.length > 0
          lastv_r = compile_expr(stmts_r2.last)
          if block_ret_r == "string"
            emit("  sp_StrArray_push(" + tmp_arr + ", " + lastv_r + ");")
          elsif block_ret_r == "float"
            emit("  sp_FloatArray_push(" + tmp_arr + ", " + lastv_r + ");")
          elsif block_ret_r == "poly"
            emit("  sp_PolyArray_push(" + tmp_arr + ", " + lastv_r + ");")
          elsif block_is_typed_array
            if is_ptr_array_type(block_ret_r) == 1 || block_ret_r == "poly_array"
              emit("  sp_PolyArray_push(" + tmp_arr + ", " + box_value_to_poly(block_ret_r, lastv_r) + ");")
            else
              emit("  sp_PtrArray_push(" + tmp_arr + ", (void *)" + lastv_r + ");")
            end
          else
 # promote-mode block tail returning bigint into IntArray;
 # unbox before pushing.
            if infer_type(stmts_r2.last) == "bigint" || expr_emit_is_bigint(stmts_r2.last) == 1
              @needs_bigint = 1
              lastv_r = "sp_bigint_to_int((sp_Bigint *)" + lastv_r + ")"
            end
            emit("  sp_IntArray_push(" + tmp_arr + ", " + lastv_r + ");")
          end
        else
          emit_map_default_push(tmp_arr, r_container)
        end
      end
      @indent = @indent - 1
      emit("  }")
      return tmp_arr
    end
    if rt == "int_array" || rt == "sym_array"
      @needs_int_array = 1
      @needs_gc = 1
      bp_t = elem_type_of_array(rt)
 # Check if block param is used as lambda (elements are lambda pointers in IntArray)
      blk = @nd_block[nid]
      bp_is_lambda = 0
      if blk >= 0
        bp_is_lambda = param_used_as_lambda(bp1, @nd_body[blk])
      end
 # Also check if bp is passed to a function expecting lambda
      if bp_is_lambda == 0
        if blk >= 0
          body2 = @nd_body[blk]
          if body2 >= 0
            stmts2 = get_stmts(body2)
            k2 = 0
            while k2 < stmts2.length
              if @nd_type[stmts2[k2]] == "CallNode"
                cn2 = @nd_name[stmts2[k2]]
                fmi2 = find_method_idx(cn2)
                if fmi2 >= 0
                  fpt2 = @meth_param_types[fmi2].split(",", -1)
                  if fpt2.length > 0
                    if fpt2[0] == "lambda"
                      bp_is_lambda = 1
                    end
                  end
                end
              end
              k2 = k2 + 1
            end
          end
        end
      end
      if bp_is_lambda == 1
        bp_t = "lambda"
      end
      push_scope
      declare_var(bp1, bp_t)
      block_ret = "int"
      if blk >= 0
        body = @nd_body[blk]
        if body >= 0
          stmts = get_stmts(body)
          if stmts.length > 0
            block_ret = infer_type(stmts.last)
          end
        end
      end
      if block_ret == "string"
        @needs_str_array = 1
        emit("  sp_StrArray *" + tmp_arr + " = sp_StrArray_new();")
 # Root the accumulator: a nested map block (e.g. each
 # iteration allocates many inner objects via sp_*_new) can
 # trigger GC between pushes; without rooting, the outer
 # accumulator is collected mid-loop and the next push
 # corrupts the freed buffer.
        emit("  SP_GC_ROOT(" + tmp_arr + ");")
        emit("  for (mrb_int " + tmp_i + " = 0; " + tmp_i + " < sp_IntArray_length(" + rc + "); " + tmp_i + "++) {")
        if bp_is_lambda == 1
          emit("    sp_Val * lv_" + bp1 + " = (sp_Val *)sp_IntArray_get(" + rc + ", " + tmp_i + ");")
        else
          emit("    mrb_int lv_" + bp1 + " = sp_IntArray_get(" + rc + ", " + tmp_i + ");")
        end
        @indent = @indent + 1
        blk2 = @nd_block[nid]
        if blk2 >= 0
          body3 = @nd_body[blk2]
          stmts3 = body3 >= 0 ? get_stmts(body3) : []
          if stmts3.length > 0
            last = stmts3[stmts3.length - 1]
            val = compile_expr(last)
            emit("  sp_StrArray_push(" + tmp_arr + ", " + val + ");")
          else
            emit_map_default_push(tmp_arr, "str_array")
          end
        end
        @indent = @indent - 1
        emit("  }")
        pop_scope
        return tmp_arr
      elsif block_ret == "mutable_str"
 # Block returns sp_String* (`String.new` or a local
 # widened via `s = ""; s << ...`). Sibling to #519's array-
 # literal arm: accumulate into a sp_PtrArray of sp_String*.
        @needs_ptr_array = 1
        emit("  sp_PtrArray *" + tmp_arr + " = sp_PtrArray_new();")
        emit("  SP_GC_ROOT(" + tmp_arr + ");")
        emit("  for (mrb_int " + tmp_i + " = 0; " + tmp_i + " < sp_IntArray_length(" + rc + "); " + tmp_i + "++) {")
        if bp_is_lambda == 1
          emit("    sp_Val * lv_" + bp1 + " = (sp_Val *)sp_IntArray_get(" + rc + ", " + tmp_i + ");")
        else
          emit("    mrb_int lv_" + bp1 + " = sp_IntArray_get(" + rc + ", " + tmp_i + ");")
        end
        @indent = @indent + 1
        blk2 = @nd_block[nid]
        if blk2 >= 0
          body3 = @nd_body[blk2]
          stmts3 = body3 >= 0 ? get_stmts(body3) : []
          if stmts3.length > 0
            last = stmts3[stmts3.length - 1]
            val = compile_expr(last)
            emit("  sp_PtrArray_push(" + tmp_arr + ", (void *)(" + val + "));")
          else
            emit_map_default_push(tmp_arr, "ptr_array")
          end
        end
        @indent = @indent - 1
        emit("  }")
        pop_scope
        return tmp_arr
      else
 # Block returning a homogeneous typed array (e.g.
 # `[1, 6].map { (0..n).map { ... } }`) — accumulator must
 # be a PtrArray so GC keeps each element alive (an IntArray
 # accumulator with pointer-payload mrb_ints would let the
 # inner arrays be collected). Deeper nesting (block_ret is
 # already a ptr_array / poly_array) uses PolyArray boxing
 # so the cls_id chain stays tagged for `arr[i][j][k]...`.
        ret_is_arr2 = (block_ret == "int_array" || block_ret == "float_array" || block_ret == "str_array" || block_ret == "sym_array")
        ret_is_deep_arr2 = (is_ptr_array_type(block_ret) == 1 || block_ret == "poly_array")
        if ret_is_deep_arr2
          @needs_rb_value = 1
          emit("  sp_PolyArray *" + tmp_arr + " = sp_PolyArray_new();")
        elsif ret_is_arr2
          @needs_ptr_array = 1
          emit("  sp_PtrArray *" + tmp_arr + " = sp_PtrArray_new();")
        else
          emit("  sp_IntArray *" + tmp_arr + " = sp_IntArray_new();")
        end
        emit("  SP_GC_ROOT(" + tmp_arr + ");")
        emit("  for (mrb_int " + tmp_i + " = 0; " + tmp_i + " < sp_IntArray_length(" + rc + "); " + tmp_i + "++) {")
        if bp_is_lambda == 1
          emit("    sp_Val * lv_" + bp1 + " = (sp_Val *)sp_IntArray_get(" + rc + ", " + tmp_i + ");")
        else
          emit("    mrb_int lv_" + bp1 + " = sp_IntArray_get(" + rc + ", " + tmp_i + ");")
        end
        @indent = @indent + 1
        blk2 = @nd_block[nid]
        if blk2 >= 0
          body3 = @nd_body[blk2]
          stmts3 = body3 >= 0 ? get_stmts(body3) : []
          if stmts3.length > 0
            last = stmts3[stmts3.length - 1]
            val = compile_expr(last)
            if ret_is_deep_arr2
 # The block returns a typed `<X>_ptr_array` (e.g.
 # `int_array_ptr_array`). The static type carries
 # elem-type info but `sp_box_ptr_array(val)` would
 # erase it (cls_id PTR_ARRAY only). Convert to
 # PolyArray inline so each inner element gets its
 # proper `sp_box_<elem>` tag — `arr[i][j][k]`
 # dispatch then chains correctly.
              if is_ptr_array_type(block_ret) == 1
                inner_t = ptr_array_elem_type(block_ret)
                conv = new_temp
                ii = new_temp
                emit("  sp_PolyArray *" + conv + " = sp_PolyArray_new();")
                emit("  for (mrb_int " + ii + " = 0; " + ii + " < sp_PtrArray_length(" + val + "); " + ii + "++) {")
                inner_get = "(" + c_type(inner_t) + ")sp_PtrArray_get(" + val + ", " + ii + ")"
                emit("    sp_PolyArray_push(" + conv + ", " + box_value_to_poly(inner_t, inner_get) + ");")
                emit("  }")
                emit("  sp_PolyArray_push(" + tmp_arr + ", sp_box_poly_array(" + conv + "));")
              else
                emit("  sp_PolyArray_push(" + tmp_arr + ", " + box_value_to_poly(block_ret, val) + ");")
              end
            elsif ret_is_arr2
              emit("  sp_PtrArray_push(" + tmp_arr + ", (void *)(" + val + "));")
            else
              emit("  sp_IntArray_push(" + tmp_arr + ", " + val + ");")
            end
          else
            emit_map_default_push(tmp_arr, ret_is_arr2 ? "ptr_array" : "int_array")
          end
        end
        @indent = @indent - 1
        emit("  }")
        pop_scope
        return tmp_arr
      end
    end
    if rt == "str_array"
 # str_array.map { |s| ... } produced no result branch before, so
 # `tt = foo.map { ... }` silently became `lv_tt = 0` and the
 # subsequent iteration crashed. .
      @needs_gc = 1
      push_scope
      declare_var(bp1, "string")
      block_ret = "string"
      blk = @nd_block[nid]
      if blk >= 0
        body = @nd_body[blk]
        if body >= 0
          stmts = get_stmts(body)
          if stmts.length > 0
            block_ret = infer_type(stmts.last)
          end
        end
      end
      if block_ret == "int"
        @needs_int_array = 1
        emit("  sp_IntArray *" + tmp_arr + " = sp_IntArray_new();")
        emit("  SP_GC_ROOT(" + tmp_arr + ");")
        emit("  for (mrb_int " + tmp_i + " = 0; " + tmp_i + " < sp_StrArray_length(" + rc + "); " + tmp_i + "++) {")
 # Declare lv_<bp> with the block-local type inside the for body
 # so it C-shadows any outer same-named local (Ruby block-local
 # parameter scope: i in `foo.map { |i| ... }` is independent of
 # any outer i).
        emit("    const char *lv_" + bp1 + " = sp_StrArray_get(" + rc + ", " + tmp_i + ");")
        @indent = @indent + 1
        if blk >= 0
          body3 = @nd_body[blk]
          stmts3 = body3 >= 0 ? get_stmts(body3) : []
          if stmts3.length > 0
            k = 0
            while k < stmts3.length - 1
              compile_stmt(stmts3[k])
              k = k + 1
            end
            val = compile_expr(stmts3.last)
            emit("  sp_IntArray_push(" + tmp_arr + ", " + val + ");")
          else
            emit_map_default_push(tmp_arr, "int_array")
          end
        end
        @indent = @indent - 1
        emit("  }")
        pop_scope
        return tmp_arr
      end
 # Issue #830: str_array.map { |s| <float expr> } -- the
 # canonical shape is `str.split.map(&:to_f)` which lowers
 # to `{ |s| s.to_f }`. Without this branch the accumulator
 # is sp_StrArray and the push attempts to store a double
 # into a const char * slot.
      if block_ret == "float"
        emit("  sp_FloatArray *" + tmp_arr + " = sp_FloatArray_new();")
        emit("  SP_GC_ROOT(" + tmp_arr + ");")
        emit("  for (mrb_int " + tmp_i + " = 0; " + tmp_i + " < sp_StrArray_length(" + rc + "); " + tmp_i + "++) {")
        emit("    const char *lv_" + bp1 + " = sp_StrArray_get(" + rc + ", " + tmp_i + ");")
        @indent = @indent + 1
        if blk >= 0
          body3 = @nd_body[blk]
          stmts3 = body3 >= 0 ? get_stmts(body3) : []
          if stmts3.length > 0
            k = 0
            while k < stmts3.length - 1
              compile_stmt(stmts3[k])
              k = k + 1
            end
            val = compile_expr(stmts3.last)
            emit("  sp_FloatArray_push(" + tmp_arr + ", " + val + ");")
          else
            emit_map_default_push(tmp_arr, "float_array")
          end
        end
        @indent = @indent - 1
        emit("  }")
        pop_scope
        return tmp_arr
      end
      @needs_str_array = 1
      emit("  sp_StrArray *" + tmp_arr + " = sp_StrArray_new();")
      emit("  SP_GC_ROOT(" + tmp_arr + ");")
      emit("  for (mrb_int " + tmp_i + " = 0; " + tmp_i + " < sp_StrArray_length(" + rc + "); " + tmp_i + "++) {")
 # Block-local C decl, see note in the int-block branch above.
      emit("    const char *lv_" + bp1 + " = sp_StrArray_get(" + rc + ", " + tmp_i + ");")
      @indent = @indent + 1
      if blk >= 0
        body3 = @nd_body[blk]
        stmts3 = body3 >= 0 ? get_stmts(body3) : []
        if stmts3.length > 0
          k = 0
          while k < stmts3.length - 1
            compile_stmt(stmts3[k])
            k = k + 1
          end
          val = compile_expr(stmts3.last)
          emit("  sp_StrArray_push(" + tmp_arr + ", " + val + ");")
        else
          emit_map_default_push(tmp_arr, "str_array")
        end
      end
      @indent = @indent - 1
      emit("  }")
      pop_scope
      return tmp_arr
    end
 # poly recv #map: arr typed sp_RbVal (e.g. `def f(arr = nil)`
 # widens the param to poly). At runtime arr is a PolyArray /
 # IntArray / StrArray / etc. Without this branch the call
 # falls through to `"0"` and the join on the resulting NULL
 # StrArray segfaults (issue #654). Multi-tag dispatch: peek
 # cls_id and route through the matching `_get`. We always
 # build a PolyArray accumulator so the result is poly-shaped;
 # downstream emits unbox via .v.s / .v.i as needed.
    if rt == "poly"
      @needs_gc = 1
      @needs_rb_value = 1
      block_ret_pp = ""
      blk_pp = @nd_block[nid]
      bp1_pp = get_block_param(nid, 0)
      if bp1_pp == ""
        bp1_pp = "_x"
      end
      tmp_arr_pp = new_temp
      tmp_i_pp = new_temp
      tmp_len_pp = new_temp
      tmp_elem_pp = new_temp
      if blk_pp >= 0
        body_pp = @nd_body[blk_pp]
        if body_pp >= 0
          stmts_pp = get_stmts(body_pp)
          if stmts_pp.length > 0
            block_ret_pp = infer_type(stmts_pp.last)
          end
        end
      end
      push_scope
 # Build a StrArray accumulator when the block returns string
 # (matches the common `.map { ... }.join(",")` shape); else
 # PolyArray.
      if block_ret_pp == "string"
        @needs_str_array = 1
        emit("  sp_StrArray *" + tmp_arr_pp + " = sp_StrArray_new();")
      elsif block_ret_pp == "int" || block_ret_pp == "bool" || block_ret_pp == "bigint"
        @needs_int_array = 1
        emit("  sp_IntArray *" + tmp_arr_pp + " = sp_IntArray_new();")
      elsif block_ret_pp == "float"
        @needs_float_array = 1
        emit("  sp_FloatArray *" + tmp_arr_pp + " = sp_FloatArray_new();")
      else
        emit("  sp_PolyArray *" + tmp_arr_pp + " = sp_PolyArray_new();")
      end
      emit("  SP_GC_ROOT(" + tmp_arr_pp + ");")
 # Runtime length + per-tag elem fetch.
      emit("  mrb_int " + tmp_len_pp + " = 0;")
      emit("  if ((" + rc + ").cls_id == SP_BUILTIN_POLY_ARRAY) " + tmp_len_pp + " = sp_PolyArray_length((sp_PolyArray *)(" + rc + ").v.p);")
      emit("  else if ((" + rc + ").cls_id == SP_BUILTIN_INT_ARRAY) " + tmp_len_pp + " = sp_IntArray_length((sp_IntArray *)(" + rc + ").v.p);")
      emit("  else if ((" + rc + ").cls_id == SP_BUILTIN_STR_ARRAY) " + tmp_len_pp + " = sp_StrArray_length((sp_StrArray *)(" + rc + ").v.p);")
      emit("  else if ((" + rc + ").cls_id == SP_BUILTIN_FLT_ARRAY) " + tmp_len_pp + " = sp_FloatArray_length((sp_FloatArray *)(" + rc + ").v.p);")
      emit("  for (mrb_int " + tmp_i_pp + " = 0; " + tmp_i_pp + " < " + tmp_len_pp + "; " + tmp_i_pp + "++) {")
      declare_var(bp1_pp, "poly")
      emit("    sp_RbVal lv_" + bp1_pp + ";")
      emit("    if ((" + rc + ").cls_id == SP_BUILTIN_POLY_ARRAY) lv_" + bp1_pp + " = sp_PolyArray_get((sp_PolyArray *)(" + rc + ").v.p, " + tmp_i_pp + ");")
      emit("    else if ((" + rc + ").cls_id == SP_BUILTIN_INT_ARRAY) lv_" + bp1_pp + " = sp_box_int(sp_IntArray_get((sp_IntArray *)(" + rc + ").v.p, " + tmp_i_pp + "));")
      emit("    else if ((" + rc + ").cls_id == SP_BUILTIN_STR_ARRAY) lv_" + bp1_pp + " = sp_box_str(sp_StrArray_get((sp_StrArray *)(" + rc + ").v.p, " + tmp_i_pp + "));")
      emit("    else if ((" + rc + ").cls_id == SP_BUILTIN_FLT_ARRAY) lv_" + bp1_pp + " = sp_box_float(sp_FloatArray_get((sp_FloatArray *)(" + rc + ").v.p, " + tmp_i_pp + "));")
      emit("    else lv_" + bp1_pp + " = sp_box_nil();")
      @indent = @indent + 1
      if blk_pp >= 0
        body_pp = @nd_body[blk_pp]
        stmts_pp = body_pp >= 0 ? get_stmts(body_pp) : []
        k_pp = 0
        while k_pp < stmts_pp.length - 1
          compile_stmt(stmts_pp[k_pp])
          k_pp = k_pp + 1
        end
        if stmts_pp.length > 0
          lastv_pp = compile_expr(stmts_pp.last)
          if block_ret_pp == "string"
            emit("  sp_StrArray_push(" + tmp_arr_pp + ", " + lastv_pp + ");")
          elsif block_ret_pp == "int" || block_ret_pp == "bool"
            emit("  sp_IntArray_push(" + tmp_arr_pp + ", " + lastv_pp + ");")
          elsif block_ret_pp == "bigint"
            @needs_bigint = 1
            emit("  sp_IntArray_push(" + tmp_arr_pp + ", sp_bigint_to_int((sp_Bigint *)" + lastv_pp + "));")
          elsif block_ret_pp == "float"
            emit("  sp_FloatArray_push(" + tmp_arr_pp + ", " + lastv_pp + ");")
          else
            emit("  sp_PolyArray_push(" + tmp_arr_pp + ", " + box_value_to_poly(block_ret_pp, lastv_pp) + ");")
          end
        end
      end
      @indent = @indent - 1
      emit("  }")
      pop_scope
      return tmp_arr_pp
    end
    if rt == "poly_array"
      @needs_gc = 1
 # Empty / missing block leaves block_ret_p as "" so the
 # accumulator falls into the catch-all PolyArray branch —
 # matches infer_type's "poly_array" prediction for
 # poly_array.map with no expression in the block.
      block_ret_p = ""
      blk_p = @nd_block[nid]
      if blk_p >= 0
        body_p = @nd_body[blk_p]
        if body_p >= 0
          stmts_p = get_stmts(body_p)
          if stmts_p.length > 0
            block_ret_p = infer_type(stmts_p.last)
 # `_1[:k]` on a poly param infers to "int" via the generic
 # poly-dispatch fallback, but the emit returns sp_RbVal
 # (the hash-variant dispatch boxes results from
 # `sp_SymIntHash_get` for type-uniformity). An IntArray
 # accumulator would then take an sp_RbVal push — a hard
 # type error. Switch to the PolyArray catch-all when the
 # last stmt is a `[]` call on a poly receiver so the
 # accumulator matches what compile_expr actually emits.
            if block_ret_p == "int" || block_ret_p == "bool"
              last_p = stmts_p.last
              if @nd_type[last_p] == "CallNode" && @nd_name[last_p] == "[]" && @nd_receiver[last_p] >= 0
                rcv_p = @nd_receiver[last_p]
                rcv_is_bp = (@nd_type[rcv_p] == "LocalVariableReadNode" && @nd_name[rcv_p] == bp1)
                rcv_t_check = infer_type(rcv_p)
 # `_1[]` on the map block's own param: bp is poly here
 # (it's the elem of a poly_array recv), but infer_type
 # hasn't seen the not-yet-pushed scope entry, so the
 # default "int" answer would let codegen pick an int_array
 # accumulator that can't take the sp_RbVal push. Forcing
 # poly here matches the analyzer's parallel heuristic.
                if rcv_is_bp || rcv_t_check == "poly"
                  block_ret_p = "poly"
                end
              end
            end
          end
        end
      end
      push_scope
      if block_ret_p == "string"
        @needs_str_array = 1
        emit("  sp_StrArray *" + tmp_arr + " = sp_StrArray_new();")
      elsif block_ret_p == "float"
        @needs_float_array = 1
        emit("  sp_FloatArray *" + tmp_arr + " = sp_FloatArray_new();")
      elsif block_ret_p == "int" || block_ret_p == "bool"
        @needs_int_array = 1
        emit("  sp_IntArray *" + tmp_arr + " = sp_IntArray_new();")
      else
 # Heterogeneous / pointer-typed block return: keep the
 # poly shape so any element type round-trips through
 # sp_RbVal.
        emit("  sp_PolyArray *" + tmp_arr + " = sp_PolyArray_new();")
      end
      emit("  SP_GC_ROOT(" + tmp_arr + ");")
      emit("  for (mrb_int " + tmp_i + " = 0; " + tmp_i + " < sp_PolyArray_length(" + rc + "); " + tmp_i + "++) {")
      declare_var(bp1, "poly")
 # Inline C declaration (shadows any outer lv_<bp1>) — covers
 # the synthetic `_x` placeholder when the block has no param,
 # which has no spinel-side declaration to reach this scope.
      emit("    sp_RbVal lv_" + bp1 + " = sp_PolyArray_get(" + rc + ", " + tmp_i + ");")
      @indent = @indent + 1
      if blk_p >= 0
        body_p2 = @nd_body[blk_p]
        stmts_p2 = body_p2 >= 0 ? get_stmts(body_p2) : []
        p_container = (block_ret_p == "string") ? "str_array" : ((block_ret_p == "float") ? "float_array" : ((block_ret_p == "int" || block_ret_p == "bool") ? "int_array" : "poly_array"))
        k_p = 0
        while k_p < stmts_p2.length - 1
          compile_stmt(stmts_p2[k_p])
          k_p = k_p + 1
        end
        if stmts_p2.length > 0
          lastv_p = compile_expr(stmts_p2.last)
          if block_ret_p == "string"
            emit("  sp_StrArray_push(" + tmp_arr + ", " + lastv_p + ");")
          elsif block_ret_p == "float"
            emit("  sp_FloatArray_push(" + tmp_arr + ", " + lastv_p + ");")
          elsif block_ret_p == "int" || block_ret_p == "bool"
            if infer_type(stmts_p2.last) == "bigint"
              @needs_bigint = 1
              lastv_p = "sp_bigint_to_int((sp_Bigint *)" + lastv_p + ")"
            end
            emit("  sp_IntArray_push(" + tmp_arr + ", " + lastv_p + ");")
          else
            emit("  sp_PolyArray_push(" + tmp_arr + ", " + box_value_to_poly(block_ret_p, lastv_p) + ");")
          end
        else
          emit_map_default_push(tmp_arr, p_container)
        end
      end
      @indent = @indent - 1
      emit("  }")
      pop_scope
      return tmp_arr
    end
 # ptr_array recv #map: iterate sp_PtrArray_get and build a fresh
 # accumulator. Like poly_array (handled above), master fell
 # through to "0" for ptr_array recv, so any `.map { ... }` on a
 # typed `obj_X[]` ivar/local got NULL-derefed downstream.
    if is_ptr_array_type(rt) == 1
      @needs_gc = 1
      @needs_ptr_array = 1
      elem_t = ptr_array_elem_type(rt)
      cast_t = c_type(elem_t)
 # Empty / missing block leaves block_ret_p as "" so the
 # accumulator falls into the catch-all PtrArray branch —
 # matches infer_type's prediction for ptr_array.map with no
 # expression in the block.
      block_ret_p = ""
      blk_p = @nd_block[nid]
      if blk_p >= 0
        body_p = @nd_body[blk_p]
        if body_p >= 0
          stmts_p = get_stmts(body_p)
          if stmts_p.length > 0
            block_ret_p = infer_type(stmts_p.last)
          end
        end
      end
      push_scope
      p_container = ""
      if block_ret_p == "string"
        @needs_str_array = 1
        emit("  sp_StrArray *" + tmp_arr + " = sp_StrArray_new();")
        p_container = "str_array"
      elsif block_ret_p == "float"
        @needs_float_array = 1
        emit("  sp_FloatArray *" + tmp_arr + " = sp_FloatArray_new();")
        p_container = "float_array"
      elsif block_ret_p == "int" || block_ret_p == "bool"
        @needs_int_array = 1
        emit("  sp_IntArray *" + tmp_arr + " = sp_IntArray_new();")
        p_container = "int_array"
      elsif block_ret_p == "bigint"
 # Promote-mode bigint block return: mirror the analyzer's
 # poly_array result type. PolyArray boxes each bigint pointer
 # via sp_box_int(sp_bigint_to_int(...)) so downstream reads
 # see ints (matching default-mode int_array semantics for the
 # same source code).
        @needs_rb_value = 1
        @needs_bigint = 1
        emit("  sp_PolyArray *" + tmp_arr + " = sp_PolyArray_new();")
        p_container = "poly_array"
      else
 # obj/ptr/poly block return: keep a PtrArray of the result.
        emit("  sp_PtrArray *" + tmp_arr + " = sp_PtrArray_new();")
        p_container = "ptr_array"
      end
      emit("  SP_GC_ROOT(" + tmp_arr + ");")
      emit("  for (mrb_int " + tmp_i + " = 0; " + tmp_i + " < sp_PtrArray_length(" + rc + "); " + tmp_i + "++) {")
      declare_var(bp1, elem_t)
 # Inline C declaration so the synthetic `_x` placeholder (no
 # spinel-side block param) gets a typed binding inside the
 # for-loop body.
      emit("    " + cast_t + " lv_" + bp1 + " = (" + cast_t + ")sp_PtrArray_get(" + rc + ", " + tmp_i + ");")
      @indent = @indent + 1
      if blk_p >= 0
        body_p2 = @nd_body[blk_p]
        stmts_p2 = body_p2 >= 0 ? get_stmts(body_p2) : []
        k_p = 0
        while k_p < stmts_p2.length - 1
          compile_stmt(stmts_p2[k_p])
          k_p = k_p + 1
        end
        if stmts_p2.length > 0
          lastv_p = compile_expr(stmts_p2.last)
          if block_ret_p == "string"
            emit("  sp_StrArray_push(" + tmp_arr + ", " + lastv_p + ");")
          elsif block_ret_p == "float"
            emit("  sp_FloatArray_push(" + tmp_arr + ", " + lastv_p + ");")
          elsif block_ret_p == "int" || block_ret_p == "bool"
            emit("  sp_IntArray_push(" + tmp_arr + ", " + lastv_p + ");")
          elsif block_ret_p == "bigint"
            @needs_bigint = 1
            emit("  sp_PolyArray_push(" + tmp_arr + ", sp_box_int(sp_bigint_to_int((sp_Bigint *)" + lastv_p + ")));")
          else
            emit("  sp_PtrArray_push(" + tmp_arr + ", (void *)(" + lastv_p + "));")
          end
        else
          emit_map_default_push(tmp_arr, p_container)
        end
      end
      @indent = @indent - 1
      emit("  }")
      pop_scope
      return tmp_arr
    end
    "0"
  end

  def compile_select_expr(nid)
    rt = infer_type(@nd_receiver[nid])
    rc = compile_expr_gc_rooted(@nd_receiver[nid])
    bp1 = get_block_param(nid, 0)
    if bp1 == ""
      bp1 = "_x"
    end
    tmp_arr = new_temp
    tmp_i = new_temp
    if rt == "int_array" || rt == "sym_array"
      @needs_int_array = 1
      @needs_gc = 1
      bp_t = elem_type_of_array(rt)
      emit("  sp_IntArray *" + tmp_arr + " = sp_IntArray_new();")
      emit("  for (mrb_int " + tmp_i + " = 0; " + tmp_i + " < sp_IntArray_length(" + rc + "); " + tmp_i + "++) {")
      emit("    mrb_int lv_" + bp1 + " = sp_IntArray_get(" + rc + ", " + tmp_i + ");")
      @indent = @indent + 1
      push_scope
      declare_var(bp1, bp_t)
      blk = @nd_block[nid]
      if blk >= 0
        body = @nd_body[blk]
        if body >= 0
          stmts = get_stmts(body)
          if stmts.length > 0
            last = stmts.last
            cond = compile_expr(last)
            emit("  if (" + cond + ") sp_IntArray_push(" + tmp_arr + ", lv_" + bp1 + ");")
          end
        end
      end
      pop_scope
      @indent = @indent - 1
      emit("  }")
      return tmp_arr
    end
    "0"
  end

  def compile_reduce_expr(nid)
    compile_reduce_block(nid)
  end

  def compile_reduce_block(nid)
    old = @in_loop
    @in_loop = 1
    @needs_gc = 1
    rc = compile_expr_gc_rooted(@nd_receiver[nid])
 # Hold on to the seed AST nid so we can `infer_type` it later for
 # the accumulator's inner-scope registration.
    seed_nid = -1
    args_id = @nd_arguments[nid]
    if args_id >= 0
      aargs = get_args(args_id)
      if aargs.length > 0
        seed_nid = aargs[0]
      end
    end
    init_val = compile_expr_gc_rooted(seed_nid)
    bp1 = get_block_param(nid, 0)
    bp2 = get_block_param(nid, 1)
    if bp1 == ""
      bp1 = "_acc"
    end
    if bp2 == ""
      bp2 = "_x"
    end
    rt = infer_type(@nd_receiver[nid])
    pfx = array_c_prefix(rt)
    elem_t = elem_type_of_array(rt)
 # bp1 takes the seed's type. Seed-less form is currently treated as
 # 0-seeded (init_val resolves to "0" via compile_expr(-1)); seed_t
 # falls back to elem_t to keep the type system consistent. This is
 # not true Ruby first-element seeding — known limitation.
    seed_t = elem_t
    if seed_nid >= 0
      seed_t = infer_type(seed_nid)
    end
 # See compile_each_slice_block for the typed-shadow + SP_GC_ROOT
 # technique inside a C block scope. reduce additionally needs
 # result_tmp because it's expression-form: the final value must
 # survive past the inner scope's `}` for the caller to consume.
    outer_t = find_var_type(bp1)
    shadowed = 0
    if outer_t != "" && outer_t != seed_t
      shadowed = 1
    end
    acc_expr = "lv_" + bp1
    if shadowed == 1
      result_tmp = new_temp
      seed_ct = c_type(seed_t)
 # Evaluate init_val once and share it between result_tmp and the
 # shadowed lv_<bp1>; some seed expressions (ArrayNode/HashNode
 # literals) are not lifted to a temp by compile_expr_gc_rooted.
      emit("  " + seed_ct + " " + result_tmp + " = " + init_val + ";")
      emit("  {")
      @indent = @indent + 1
      emit("  SP_GC_SAVE();")
      emit("  " + seed_ct + " lv_" + bp1 + " = " + result_tmp + ";")
      if type_is_pointer(seed_t) == 1
        emit("  SP_GC_ROOT(lv_" + bp1 + ");")
      end
      acc_expr = result_tmp
    else
      emit("  lv_" + bp1 + " = " + init_val + ";")
    end
    tmp = new_temp
    emit("  for (mrb_int " + tmp + " = 0; " + tmp + " < sp_" + pfx + "_length(" + rc + "); " + tmp + "++) {")
    emit("    " + c_type(elem_t) + " lv_" + bp2 + " = sp_" + pfx + "_get(" + rc + ", " + tmp + ");")
    @indent = @indent + 1
    push_scope
    declare_var(bp1, seed_t)
    declare_var(bp2, elem_t)
    blk = @nd_block[nid]
    if blk >= 0
      body = @nd_body[blk]
      if body >= 0
        stmts = get_stmts(body)
        if stmts.length > 0
          last = stmts.last
          val = compile_expr(last)
          emit("  lv_" + bp1 + " = " + val + ";")
        end
      end
    end
    pop_scope
    @indent = @indent - 1
    emit("  }")
    if shadowed == 1
      emit("  " + acc_expr + " = lv_" + bp1 + ";")
      @indent = @indent - 1
      emit("  }")
    end
    @in_loop = old
    acc_expr
  end

  def compile_reject_expr(nid)
    rc = compile_expr_gc_rooted(@nd_receiver[nid])
    bp1 = get_block_param(nid, 0)
    if bp1 == ""
      bp1 = "_x"
    end
    rt = infer_type(@nd_receiver[nid])
    if rt == "int_array" || rt == "sym_array"
      @needs_int_array = 1
      bp_t = elem_type_of_array(rt)
      tmp_arr = new_temp
      emit("  sp_IntArray *" + tmp_arr + " = sp_IntArray_new();")
      tmp_i = new_temp
      emit("  for (mrb_int " + tmp_i + " = 0; " + tmp_i + " < sp_IntArray_length(" + rc + "); " + tmp_i + "++) {")
      emit("    mrb_int lv_" + bp1 + " = sp_IntArray_get(" + rc + ", " + tmp_i + ");")
      @indent = @indent + 1
      push_scope
      declare_var(bp1, bp_t)
      blk = @nd_block[nid]
      if blk >= 0
        body = @nd_body[blk]
        if body >= 0
          stmts = get_stmts(body)
          if stmts.length > 0
            last = stmts.last
            cond = compile_expr(last)
            emit("  if (!(" + cond + ")) sp_IntArray_push(" + tmp_arr + ", lv_" + bp1 + ");")
          end
        end
      end
      pop_scope
      @indent = @indent - 1
      emit("  }")
      return tmp_arr
    end
    "0"
  end

  def compile_reject_block(nid)
    rc = compile_expr_gc_rooted(@nd_receiver[nid])
    bp1 = get_block_param(nid, 0)
    if bp1 == ""
      bp1 = "_x"
    end
    rt = infer_type(@nd_receiver[nid])
    if rt == "int_array"
      @needs_int_array = 1
      tmp_arr = new_temp
      emit("  sp_IntArray *" + tmp_arr + " = sp_IntArray_new();")
      tmp_i = new_temp
      emit("  for (mrb_int " + tmp_i + " = 0; " + tmp_i + " < sp_IntArray_length(" + rc + "); " + tmp_i + "++) {")
      emit("    mrb_int lv_" + bp1 + " = sp_IntArray_get(" + rc + ", " + tmp_i + ");")
      @indent = @indent + 1
      push_scope
      declare_var(bp1, "int")
      blk = @nd_block[nid]
      if blk >= 0
        body = @nd_body[blk]
        if body >= 0
          stmts = get_stmts(body)
          if stmts.length > 0
            last = stmts.last
            cond = compile_expr(last)
            emit("  if (!(" + cond + ")) sp_IntArray_push(" + tmp_arr + ", lv_" + bp1 + ");")
          end
        end
      end
      pop_scope
      @indent = @indent - 1
      emit("  }")
    end
  end

  def compile_sprintf_call(nid)
    args_id = @nd_arguments[nid]
    if args_id < 0
      return "\"\""
    end
    arg_ids = get_args(args_id)
    if arg_ids.length == 0
      return "\"\""
    end
 # First arg is format string, rest are values
    fmt = compile_expr(arg_ids[0])
    result = "sp_sprintf(" + fmt
    k = 1
    while k < arg_ids.length
      at = infer_type(arg_ids[k])
      if at == "float"
        result = result + ", " + compile_expr(arg_ids[k])
      else
        result = result + ", " + compile_expr(arg_ids[k])
      end
      k = k + 1
    end
    result + ")"
  end

  def compile_catch_expr(nid)
    @needs_setjmp = 1
    tag = compile_str_arg0(nid)
    blk = @nd_block[nid]
    tmp = new_temp

    emit("  mrb_int " + tmp + " = 0;")
    emit("  sp_catch_tag[sp_catch_top] = " + tag + ";")
    emit("  sp_catch_top++;")
    emit("  if (setjmp(sp_catch_stack[sp_catch_top-1]) == 0) {")
    @indent = @indent + 1
    if blk >= 0
      body = @nd_body[blk]
      if body >= 0
        stmts = get_stmts(body)
 # Compile all but last as statements
        k = 0
        while k < stmts.length - 1
          compile_stmt(stmts[k])
          k = k + 1
        end
        if stmts.length > 0
          last = stmts.last
          emit("  " + tmp + " = " + compile_expr(last) + ";")
        end
      end
    end
    @indent = @indent - 1
    emit("    sp_catch_top--;")
    emit("  } else {")
    emit("    sp_catch_top--;")
    emit("    " + tmp + " = sp_catch_val[sp_catch_top];")
    emit("  }")
    tmp
  end

  def compile_catch_stmt(nid)
    @needs_setjmp = 1
 # catch(:tag) do ... end
    tag = compile_str_arg0(nid)
    blk = @nd_block[nid]
    emit("  sp_catch_tag[sp_catch_top] = " + tag + ";")
    emit("  sp_catch_top++;")
    emit("  if (setjmp(sp_catch_stack[sp_catch_top-1]) == 0) {")
    @indent = @indent + 1
    if blk >= 0
      compile_stmts_body(@nd_body[blk])
    end
    @indent = @indent - 1
    emit("    sp_catch_top--;")
    emit("  } else {")
    emit("    sp_catch_top--;")
    emit("  }")
  end

  def compile_throw_stmt(nid)
    @needs_setjmp = 1
    args_id = @nd_arguments[nid]
    arg_ids = []
    if args_id >= 0
      arg_ids = get_args(args_id)
    end
    tag = "\"\""
    val = "0"
    if arg_ids.length >= 1
      tag = compile_expr_as_string(arg_ids[0])
    end
    if arg_ids.length >= 2
      val = compile_expr(arg_ids[1])
    end
    emit("  sp_throw(" + tag + ", " + val + ");")
  end

  def compile_begin_stmt(nid)
    @needs_setjmp = 1
    has_rescue = @nd_rescue_clause[nid] >= 0
    has_ensure = @nd_ensure_clause[nid] >= 0

 # Check if rescue body has retry
    has_retry = 0
    rc = @nd_rescue_clause[nid]
    if rc >= 0
      if body_has_retry(@nd_body[rc]) == 1
        has_retry = 1
      end
    end

 # Outer setjmp wraps the body (and any rescue chain) so the ensure
 # clause runs on the exception path too. Without this, a `raise`
 # from inside the body would unwind past us with `ensure` skipped.
    ensure_cls_var = ""
    ensure_msg_var = ""
    if has_ensure
      @ensure_emit_depth = @ensure_emit_depth + 1
      ensure_cls_var = "_ensure_cls_" + @ensure_emit_depth.to_s
      ensure_msg_var = "_ensure_msg_" + @ensure_emit_depth.to_s
      emit("  const char *" + ensure_cls_var + " = (const char *)0;")
      emit("  const char *" + ensure_msg_var + " = (const char *)0;")
      emit("  sp_exc_top++;")
      emit("  if (setjmp(sp_exc_stack[sp_exc_top-1]) == 0) {")
      @indent = @indent + 1
      @setjmp_depth = @setjmp_depth + 1
      @ensure_stack.push(@nd_ensure_clause[nid].to_s)
    end

    if has_retry == 1
      emit("  for (;;) {")
      @indent = @indent + 1
    end

    if has_rescue
      emit("  sp_exc_top++;")
      @setjmp_depth = @setjmp_depth + 1
      emit("  if (setjmp(sp_exc_stack[sp_exc_top-1]) == 0) {")
      @indent = @indent + 1
      compile_stmts_body(@nd_body[nid])
 # `begin..rescue..else..end`: the else body runs only when the
 # body completed without exception. Place it inside the
 # setjmp-success branch, after the body. The exception path
 # (`else { ... rescue ... }` below) doesn't run else.
      else_id_b = @nd_else_clause[nid]
      if else_id_b >= 0
        else_body_b = @nd_body[else_id_b]
        if else_body_b >= 0
          compile_stmts_body(else_body_b)
        end
      end
      @indent = @indent - 1
      emit("    sp_exc_top--;")
      if has_retry == 1
        emit("    break;")
      end

      rc = @nd_rescue_clause[nid]
      if rc >= 0
        emit("  } else {")
        emit("    sp_exc_top--;")
        @indent = @indent + 1
 # Check for multiple rescue clauses with exception types
        compile_rescue_chain(rc, has_retry)
        @indent = @indent - 1
      end
      emit("  }")
      @setjmp_depth = @setjmp_depth - 1
    else
      compile_stmts_body(@nd_body[nid])
    end

    if has_retry == 1
      @indent = @indent - 1
      emit("  }")
    end

    if has_ensure
      @ensure_stack.pop
 # End of the if-success branch: pop our setjmp and close the
 # brace. After this the codegen is conceptually back at the
 # surrounding scope — drop the depth bump even though more
 # code (the else branch and fall-through ensure) is still
 # being emitted; both run with sp_exc_top already restored.
      emit("  sp_exc_top--;")
      @indent = @indent - 1
      @setjmp_depth = @setjmp_depth - 1
      emit("  } else {")
      @indent = @indent + 1
 # Exception path: pop our setjmp, snapshot the in-flight
 # exception (because nested raises inside the ensure body
 # would clobber sp_last_exc_cls / sp_exc_msg), run the
 # ensure body, then re-raise so the exception keeps
 # propagating. If the ensure body contains its own `return`,
 # the re-raise becomes dead code — that's the explicit
 # "ensure overrides exception with return" semantics.
      emit("  sp_exc_top--;")
      emit("  " + ensure_cls_var + " = (const char *)sp_last_exc_cls;")
      emit("  " + ensure_msg_var + " = sp_exc_msg[sp_exc_top];")
      ec = @nd_ensure_clause[nid]
      if ec >= 0
        compile_stmts_body(@nd_body[ec])
      end
      emit("  sp_raise_cls(" + ensure_cls_var + ", " + ensure_msg_var + ");")
      @indent = @indent - 1
      emit("  }")
 # Normal-path ensure (fall-through after success branch).
      if ec >= 0
        compile_stmts_body(@nd_body[ec])
      end
      @ensure_emit_depth = @ensure_emit_depth - 1
    end
  end

 # Replay all in-scope ensure bodies inline (innermost-first) ahead
 # of an early-exit `return`. Each ensure is popped from the stack
 # *before* its body is emitted, so a nested `return` inside the
 # ensure body sees only the *outer* ensures still active and
 # doesn't replay the same ensure recursively. Stack is restored
 # afterwards so the caller continues with the same view.
 #
 # @setjmp_depth is stashed to 0 during the replay because the
 # caller is responsible for emitting `sp_exc_top -= N` *once*
 # before the replays — a nested `return` inside an ensure body
 # would otherwise re-emit that decrement and over-pop the stack.
  def emit_ensure_replays
    if @ensure_stack.length == 0
      return
    end
    saved_setjmp_depth = @setjmp_depth
    @setjmp_depth = 0
    popped = "".split(",", -1)
    while @ensure_stack.length > 0
      ec_str = @ensure_stack.pop
      popped.push(ec_str)
      compile_stmts_body(@nd_body[ec_str.to_i])
    end
    while popped.length > 0
      @ensure_stack.push(popped.pop)
    end
    @setjmp_depth = saved_setjmp_depth
  end

 # Emit the `sp_exc_top -= N;` that an early `return` needs in
 # order to leave sp_exc_top balanced. Called immediately before
 # `emit_ensure_replays` at every `return` emission site.
  def emit_setjmp_depth_unwind
    if @setjmp_depth > 0
      emit("  sp_exc_top -= " + @setjmp_depth.to_s + ";")
    end
  end

  def compile_rescue_chain(rc, has_retry)
 # Check for exception type matching
    exc_types = parse_id_list(@nd_exceptions[rc])
    ref = @nd_reference[rc]
 # Snapshot the in-flight exception BEFORE the type-check `if` so
 # that the else-branch (re-raise / propagation) can also reference
 # the snapshot. Bare `raise` inside this body re-raises with the
 # original class+message even if the body itself triggers (and
 # catches) a nested raise that would otherwise clobber
 # sp_last_exc_cls / sp_exc_msg[sp_exc_top].
    @rescue_depth = @rescue_depth + 1
    saved_cls = "_rescue_cls_" + @rescue_depth.to_s
    saved_msg = "_rescue_msg_" + @rescue_depth.to_s
    emit("  const char *" + saved_cls + " = (const char *)sp_last_exc_cls;")
    emit("  const char *" + saved_msg + " = sp_exc_msg[sp_exc_top];")
    @rescue_cls_stack.push(saved_cls)
    @rescue_msg_stack.push(saved_msg)
    has_type_check = 0
    if exc_types.length > 0
      has_type_check = 1
 # Build condition: sp_exc_class_le(sp_last_exc_cls, "ClassName")
 # walks the class-name parent chain so `rescue ParentClass`
 # catches a raised subclass. Issue #627.
      @needs_exc_class_hierarchy = 1
      cond = ""
      k = 0
      while k < exc_types.length
        if k > 0
          cond = cond + " || "
        end
        cond = cond + "sp_exc_class_le((const char*)sp_last_exc_cls, \"" + @nd_name[exc_types[k]] + "\")"
        k = k + 1
      end
      emit("  if (" + cond + ") {")
      @indent = @indent + 1
    end
    bound_rname = ""
    if ref >= 0
      bound_rname = @nd_name[ref]
 # Bind `e` to a first-class sp_Exception *. saved_cls / saved_msg
 # snapshot the in-flight exception above; wrap them in sp_exc_new
 # so the LV holds a typed object that dispatch / re-raise can use.
      emit("  lv_" + bound_rname + " = sp_exc_new(" + saved_cls + ", " + saved_msg + ");")
    end
    compile_rescue_body(@nd_body[rc], has_retry)
    @rescue_cls_stack.pop
    @rescue_msg_stack.pop
    @rescue_depth = @rescue_depth - 1
    if has_type_check == 1
      @indent = @indent - 1
 # Check for subsequent rescue
      sub = @nd_subsequent[rc]
      if sub >= 0
        emit("  } else {")
        @indent = @indent + 1
        compile_rescue_chain(sub, has_retry)
        @indent = @indent - 1
      else
 # No subsequent clause and the type check missed: re-raise
 # using the snapshotted class+message so an enclosing handler
 # can match it (or the program terminates with the original
 # diagnostic). Without this the exception was silently dropped.
        emit("  } else {")
        emit("    sp_raise_cls(" + saved_cls + ", " + saved_msg + ");")
      end
      emit("  }")
    end
 # Bare rescue catches all, so any subsequent clause is unreachable
 # and we deliberately don't recurse.
    0
  end

  def compile_rescue_body(nid, has_retry)
    if nid < 0
      return
    end
    stmts = get_stmts(nid)
    k = 0
    while k < stmts.length
      compile_stmt(stmts[k])
      k = k + 1
    end
    if has_retry == 1
 # If we get here without a retry (continue), break out of the loop
      emit("  break;")
    end
  end

  def body_has_retry(nid)
    if nid < 0
      return 0
    end
    if @nd_type[nid] == "RetryNode"
      return 1
    end
    stmts = parse_id_list(@nd_stmts[nid])
    k = 0
    while k < stmts.length
      if body_has_retry(stmts[k]) == 1
        return 1
      end
      k = k + 1
    end
    if @nd_body[nid] >= 0
      if body_has_retry(@nd_body[nid]) == 1
        return 1
      end
    end
    if @nd_subsequent[nid] >= 0
      if body_has_retry(@nd_subsequent[nid]) == 1
        return 1
      end
    end
    0
  end

  def compile_yield_stmt(nid)
    args_id = @nd_arguments[nid]
    emitted = "".split(",", -1)
 # Per-position projected block param types from analyze. When the
 # slot is "bigint", coerce int args to sp_bigint_new_int so the
 # call matches the widened `_block(sp_Bigint *, ...)` sig emitted
 # by yield_params_suffix. Symmetric int<-bigint coerce covers
 # methods whose projection didn't widen but a body site emitted
 # a bigint expression.
    bpt_arr = "".split(",", -1)
    if @current_method_blk_param_types != ""
      bpt_arr = @current_method_blk_param_types.split("|", -1)
    end
    if args_id >= 0
      aids = get_args(args_id)
      k = 0
      while k < aids.length
        val_y = compile_expr(aids[k])
        arg_t_y = infer_type(aids[k])
        slot_t_y = k < bpt_arr.length ? bpt_arr[k] : ""
 # `expr_emit_is_bigint` catches the case where the cache says
 # "int" but the actual C emit picked sp_bigint_*; without it the
 # `arg_t_y == "int"` branch double-wraps with sp_bigint_new_int.
        emit_is_bigint = expr_emit_is_bigint(aids[k]) == 1
        if slot_t_y == "bigint" && arg_t_y != "bigint" && !emit_is_bigint
          @needs_bigint = 1
          if arg_t_y == "int" || arg_t_y == "" || arg_t_y == "nil"
            val_y = "sp_bigint_new_int(" + val_y + ")"
          end
        elsif slot_t_y != "" && slot_t_y != "bigint" && (arg_t_y == "bigint" || emit_is_bigint)
          @needs_bigint = 1
          val_y = "sp_bigint_to_int((sp_Bigint *)" + val_y + ")"
        end
        emitted.push(val_y)
        k = k + 1
      end
    end
 # Pad to the enclosing method's max yield arity so the call matches
 # the function-pointer signature emitted by yield_params_suffix.
 # Bigint slots need `sp_bigint_new_int(0)` not raw `0` so the
 # pad value's C type matches the widened sig.
    while emitted.length < @current_method_yield_arity
      pad_slot_t = emitted.length < bpt_arr.length ? bpt_arr[emitted.length] : ""
      if pad_slot_t == "bigint"
        @needs_bigint = 1
        emitted.push("sp_bigint_new_int(0)")
      else
        emitted.push("0")
      end
    end
 # When the enclosing method declares `&block`, fall back to invoking the
 # captured proc if the yield-ABI slot is empty. This matches Ruby semantics
 # (yield and `block.call` drive the same proc) and lets `&block_arg` call
 # sites work even when the call emit fills lv_block but leaves _block NULL.
    if @current_method_block_param != ""
      bp = "lv_" + @current_method_block_param
      emit("  if (_block) _block(" + emitted.join(", ") + ", _benv);")
      emit("  else if (" + bp + ") sp_proc_call(" + bp + ", (mrb_int[]){" + emitted.join(", ") + "});")
    else
      emit("  if (_block) _block(" + emitted.join(", ") + ", _benv);")
    end
  end

  def compile_yield_call_stmt(nid, mi)
 # Call a yield-using top-level function with a block
 # Inline the function body, replacing yield with block body
    blk = @nd_block[nid]
    if blk < 0
      return
    end

 # Get block params
    bp_names = "".split(",", -1)
    bp = @nd_parameters[blk]
    if bp >= 0
      inner = @nd_parameters[bp]
      if inner >= 0
        reqs = parse_id_list(@nd_requireds[inner])
        k = 0
        while k < reqs.length
          bp_names.push(@nd_name[reqs[k]])
          k = k + 1
        end
      end
    end

    args_id = @nd_arguments[nid]
    arg_ids = []
    if args_id >= 0
      arg_ids = get_args(args_id)
    end

 # Declare and set the function's params as new temp vars
    pnames = @meth_param_names[mi].split(",", -1)
    ptypes = @meth_param_types[mi].split(",", -1)
 # Create unique temp names for function params to avoid collision
    @block_counter = @block_counter + 1
    suffix = "_y" + @block_counter.to_s
    param_map_from = "".split(",", -1)
    param_map_to = "".split(",", -1)
    k = 0
    while k < pnames.length
      pt = "int"
      if k < ptypes.length
        pt = ptypes[k]
      end
      tname = pnames[k] + suffix
      val = c_default_val(pt)
      if k < arg_ids.length
        val = compile_expr(arg_ids[k])
        arg_t_inline = infer_type(arg_ids[k])
        if base_type(pt) == "bigint" && arg_t_inline == "int"
          @needs_bigint = 1
          val = "sp_bigint_new_int(" + val + ")"
        elsif base_type(pt) == "int" && arg_t_inline == "bigint"
          @needs_bigint = 1
          val = "sp_bigint_to_int((sp_Bigint *)" + val + ")"
        end
      end
      emit("  " + c_type(pt) + " lv_" + tname + " = " + val + ";")
      param_map_from.push(pnames[k])
      param_map_to.push(tname)
      declare_var(tname, pt)
 # Also expose the original name so infer_type's scope lookup
 # inside the inlined body (which still sees the AST's
 # LocalVariableReadNode "x", not "x_y1") finds the right type.
      declare_var(pnames[k], pt)
      k = k + 1
    end

 # Also need to declare the function's local vars
    bid = @meth_body_ids[mi]
    if bid >= 0
      flocals_n = "".split(",", -1)
      flocals_t = "".split(",", -1)
      sn_f = @nd_scope_names[bid]
      if sn_f != ""
        flocals_n = sn_f.split("|", -1)
        flocals_t = @nd_scope_types[bid].split("|", -1)
      end
      k = 0
      while k < flocals_n.length
        tname = flocals_n[k] + suffix
        emit("  " + c_type(flocals_t[k]) + " lv_" + tname + " = " + c_default_val(flocals_t[k]) + ";")
        param_map_from.push(flocals_n[k])
        param_map_to.push(tname)
        declare_var(tname, flocals_t[k])
 # Also expose the original local name so the body emit's
 # find_var_type lookup (via the unrenamed AST node) returns
 # the right type. Mirrors the param declare pair above.
        declare_var(flocals_n[k], flocals_t[k])
        k = k + 1
      end
    end

 # Compile function body, replacing yield with block body
 # and renaming function locals to temp names. Stash the rename
 # map for fiber_var_ref (/).
    saved_in_rmf = @inline_rename_map_from
    saved_in_rmt = @inline_rename_map_to
    @inline_rename_map_from = param_map_from
    @inline_rename_map_to = param_map_to
    saved_iyb = @inline_yield_blk
    saved_iybp = @inline_yield_bp_names
    @inline_yield_blk = blk
    @inline_yield_bp_names = bp_names
    if bid >= 0
      stmts = get_stmts(bid)
      k = 0
      while k < stmts.length
        compile_stmt_with_block(stmts[k], blk, bp_names, param_map_from, param_map_to)
        k = k + 1
      end
    end
    @inline_rename_map_from = saved_in_rmf
    @inline_rename_map_to = saved_in_rmt
    @inline_yield_blk = saved_iyb
    @inline_yield_bp_names = saved_iybp
  end

 # expression-context counterpart of compile_yield_call_stmt.
 # `x = measure { puts "block" }` where measure has `yield` in its body
 # previously fell through to compile_no_recv_call_expr's default, which
 # emitted `sp_measure(, NULL, NULL)` -- empty leading arg slot + 1 trailing
 # NULL too many. Mirror the inlining the stmt-form does, but capture the
 # body's last expression into a result temp and return that as the
 # expression value.
  def compile_yield_call_expr(nid, mi)
    blk = @nd_block[nid]
    if blk < 0
      return "0"
    end
    bp_names = "".split(",", -1)
    bp = @nd_parameters[blk]
    if bp >= 0
      inner = @nd_parameters[bp]
      if inner >= 0
        reqs = parse_id_list(@nd_requireds[inner])
        kbp = 0
        while kbp < reqs.length
          bp_names.push(@nd_name[reqs[kbp]])
          kbp = kbp + 1
        end
      end
    end
    args_id_yc = @nd_arguments[nid]
    arg_ids_yc = []
    if args_id_yc >= 0
      arg_ids_yc = get_args(args_id_yc)
    end
    pnames = @meth_param_names[mi].split(",", -1)
    ptypes = @meth_param_types[mi].split(",", -1)
    @block_counter = @block_counter + 1
    suffix = "_y" + @block_counter.to_s
    param_map_from = "".split(",", -1)
    param_map_to = "".split(",", -1)
    kp = 0
    while kp < pnames.length
      pt_yc = "int"
      if kp < ptypes.length
        pt_yc = ptypes[kp]
      end
      tname = pnames[kp] + suffix
      val_yc = c_default_val(pt_yc)
      if kp < arg_ids_yc.length
        val_yc = compile_expr(arg_ids_yc[kp])
        arg_t_yc = infer_type(arg_ids_yc[kp])
        if base_type(pt_yc) == "bigint" && arg_t_yc == "int"
          @needs_bigint = 1
          val_yc = "sp_bigint_new_int(" + val_yc + ")"
        elsif base_type(pt_yc) == "int" && arg_t_yc == "bigint"
          @needs_bigint = 1
          val_yc = "sp_bigint_to_int((sp_Bigint *)" + val_yc + ")"
        end
      end
      emit("  " + c_type(pt_yc) + " lv_" + tname + " = " + val_yc + ";")
      param_map_from.push(pnames[kp])
      param_map_to.push(tname)
      declare_var(tname, pt_yc)
      kp = kp + 1
    end
    bid = @meth_body_ids[mi]
    if bid >= 0
      flocals_n = "".split(",", -1)
      flocals_t = "".split(",", -1)
      sn_yc = @nd_scope_names[bid]
      if sn_yc != ""
        flocals_n = sn_yc.split("|", -1)
        flocals_t = @nd_scope_types[bid].split("|", -1)
      end
      kf = 0
      while kf < flocals_n.length
        tname = flocals_n[kf] + suffix
        emit("  " + c_type(flocals_t[kf]) + " lv_" + tname + " = " + c_default_val(flocals_t[kf]) + ";")
        param_map_from.push(flocals_n[kf])
        param_map_to.push(tname)
        declare_var(tname, flocals_t[kf])
 # Also expose the original name so find_var_type lookups in
 # the inlined body (which sees the unrenamed AST node) find
 # the right type — mirrors compile_yield_call_stmt /
 # compile_yield_method_call_stmt.
        declare_var(flocals_n[kf], flocals_t[kf])
        kf = kf + 1
      end
    end
    rt_yc = @meth_return_types[mi]
    result_tmp = new_temp
    emit("  " + c_type(rt_yc) + " " + result_tmp + " = " + c_return_default(rt_yc) + ";")
    saved_in_rmf = @inline_rename_map_from
    saved_in_rmt = @inline_rename_map_to
    @inline_rename_map_from = param_map_from
    @inline_rename_map_to = param_map_to
    saved_iyb = @inline_yield_blk
    saved_iybp = @inline_yield_bp_names
    @inline_yield_blk = blk
    @inline_yield_bp_names = bp_names
    if bid >= 0
      stmts = get_stmts(bid)
      n = stmts.length
      ks = 0
      while ks < n - 1
        compile_stmt_with_block(stmts[ks], blk, bp_names, param_map_from, param_map_to)
        ks = ks + 1
      end
      if n > 0
        last_y = stmts.last
        last_t = @nd_type[last_y]
        if last_t == "YieldNode"
 # `def f; yield; end` shape: the yield IS the return value. The
 # generic stmt-shaped path would drop the block body's value;
 # inline the yield and capture the block body's last expr into
 # result_tmp so `f { 99 }` returns 99 instead of 0.
          compile_yield_inline_capture(last_y, blk, bp_names, param_map_from, param_map_to, result_tmp, rt_yc)
        elsif last_t == "IfNode" || last_t == "CaseNode" ||
           last_t == "WhileNode" || last_t == "BeginNode" || last_t == "ReturnNode" ||
           last_t == "LocalVariableWriteNode" || last_t == "InstanceVariableWriteNode" ||
           last_t == "ClassVariableWriteNode" || last_t == "GlobalVariableWriteNode"
 # Statement-shaped last expression: emit as stmt; result_tmp
 # keeps its default value.
          compile_stmt_with_block(last_y, blk, bp_names, param_map_from, param_map_to)
        else
 # Expression-shaped: capture the value via compile_expr_remap.
          last_val_yc = compile_expr_remap(last_y, param_map_from, param_map_to)
          last_t_yc = infer_type(last_y)
          if base_type(rt_yc) == "bigint" && last_t_yc == "int"
            @needs_bigint = 1
            last_val_yc = "sp_bigint_new_int(" + last_val_yc + ")"
          elsif base_type(rt_yc) == "int" && last_t_yc == "bigint"
            @needs_bigint = 1
            last_val_yc = "sp_bigint_to_int((sp_Bigint *)" + last_val_yc + ")"
          end
          emit("  " + result_tmp + " = " + last_val_yc + ";")
        end
      end
    end
    @inline_rename_map_from = saved_in_rmf
    @inline_rename_map_to = saved_in_rmt
    @inline_yield_blk = saved_iyb
    @inline_yield_bp_names = saved_iybp
    result_tmp
  end

 # Yield in expression position (as a sub-expression of any
 # statement / expression in the inlined body). Returns the C
 # expression that holds the block body's last value. Emits the
 # block-param assignment and the block body's non-last stmts as
 # side effects.
  def compile_yield_inline_expr(yield_nid, blk, bp_names, map_from, map_to)
    args_id_ye = @nd_arguments[yield_nid]
    assigned_ye = 0
    if args_id_ye >= 0
      aids_ye = get_args(args_id_ye)
      kye = 0
      while kye < aids_ye.length
        if kye < bp_names.length
          bp_t_ye = find_var_type(bp_names[kye])
          arg_v_ye = compile_expr_remap(aids_ye[kye], map_from, map_to)
          arg_t_ye = infer_type(aids_ye[kye])
          arg_emit_bigint_ye = expr_emit_is_bigint(aids_ye[kye]) == 1
          if bp_t_ye == "bigint" && arg_t_ye == "int" && !arg_emit_bigint_ye
            @needs_bigint = 1
            arg_v_ye = "sp_bigint_new_int(" + arg_v_ye + ")"
          elsif bp_t_ye == "int" && (arg_t_ye == "bigint" || arg_emit_bigint_ye)
            @needs_bigint = 1
            arg_v_ye = "sp_bigint_to_int((sp_Bigint *)" + arg_v_ye + ")"
          end
          emit("  lv_" + bp_names[kye] + " = " + arg_v_ye + ";")
          assigned_ye = assigned_ye + 1
        end
        kye = kye + 1
      end
    end
    while assigned_ye < bp_names.length
      bp_rt_ye = find_var_type(bp_names[assigned_ye])
      if bp_rt_ye == "bigint"
        @needs_bigint = 1
        emit("  lv_" + bp_names[assigned_ye] + " = sp_bigint_new_int(0);")
      else
        emit("  lv_" + bp_names[assigned_ye] + " = 0;")
      end
      assigned_ye = assigned_ye + 1
    end
    body_ye = @nd_body[blk]
    if body_ye < 0
      return "0"
    end
    bstmts_ye = get_stmts(body_ye)
    bn_ye = bstmts_ye.length
    if bn_ye == 0
      return "0"
    end
    bk_ye = 0
    while bk_ye < bn_ye - 1
      compile_stmt(bstmts_ye[bk_ye])
      bk_ye = bk_ye + 1
    end
    last_be = bstmts_ye.last
    last_bet = @nd_type[last_be]
    if last_bet == "IfNode" || last_bet == "CaseNode" ||
       last_bet == "WhileNode" || last_bet == "BeginNode" || last_bet == "ReturnNode" ||
       last_bet == "LocalVariableWriteNode" || last_bet == "InstanceVariableWriteNode" ||
       last_bet == "ClassVariableWriteNode" || last_bet == "GlobalVariableWriteNode"
      compile_stmt(last_be)
      return "0"
    end
    last_be_t = infer_type(last_be)
    res_ye = new_temp
    emit("  " + c_type(last_be_t) + " " + res_ye + " = " + compile_expr(last_be) + ";")
    res_ye
  end

 # Yield in expression position when it is the inlined method body's
 # last statement: emit the block-param assignment for the yielded
 # args (same as the YieldNode arm in compile_stmt_with_block), then
 # walk the block body emitting each stmt except the last as a stmt,
 # and capture the last expression into `result_tmp`. Coerces the
 # captured value if rt_yc is bigint and the expr is plain int (and
 # the inverse), matching the coercion the expression-shaped branch
 # of compile_yield_call_expr already does.
  def compile_yield_inline_capture(yield_nid, blk, bp_names, map_from, map_to, result_tmp, rt_yc)
 # Pure stmt helper (only emit() side effects, no value). Explicit
 # `return 0` on every exit so spinel doesn't widen the function's
 # inferred return type to the union of `compile_stmt`'s returns
 # (which trips a -Wint-conversion on Windows when an if-branch's
 # tail call to compile_stmt becomes the function's implicit return).
    args_id_yic = @nd_arguments[yield_nid]
    assigned_yic = 0
    if args_id_yic >= 0
      aids_yic = get_args(args_id_yic)
      kyic = 0
      while kyic < aids_yic.length
        if kyic < bp_names.length
          bp_t_yic = find_var_type(bp_names[kyic])
          arg_v_yic = compile_expr_remap(aids_yic[kyic], map_from, map_to)
          arg_t_yic = infer_type(aids_yic[kyic])
          arg_emit_bigint_yic = expr_emit_is_bigint(aids_yic[kyic]) == 1
          if bp_t_yic == "bigint" && arg_t_yic == "int" && !arg_emit_bigint_yic
            @needs_bigint = 1
            arg_v_yic = "sp_bigint_new_int(" + arg_v_yic + ")"
          elsif bp_t_yic == "int" && (arg_t_yic == "bigint" || arg_emit_bigint_yic)
            @needs_bigint = 1
            arg_v_yic = "sp_bigint_to_int((sp_Bigint *)" + arg_v_yic + ")"
          end
          emit("  lv_" + bp_names[kyic] + " = " + arg_v_yic + ";")
          assigned_yic = assigned_yic + 1
        end
        kyic = kyic + 1
      end
    end
    while assigned_yic < bp_names.length
      bp_rt_yic = find_var_type(bp_names[assigned_yic])
      if bp_rt_yic == "bigint"
        @needs_bigint = 1
        emit("  lv_" + bp_names[assigned_yic] + " = sp_bigint_new_int(0);")
      else
        emit("  lv_" + bp_names[assigned_yic] + " = 0;")
      end
      assigned_yic = assigned_yic + 1
    end
    body_yic = @nd_body[blk]
    if body_yic >= 0
      bstmts = get_stmts(body_yic)
      bn = bstmts.length
      bk = 0
      while bk < bn - 1
        compile_stmt(bstmts[bk])
        bk = bk + 1
      end
      if bn > 0
        last_b = bstmts.last
        last_bt = @nd_type[last_b]
        if last_bt == "IfNode" || last_bt == "CaseNode" ||
           last_bt == "WhileNode" || last_bt == "BeginNode" || last_bt == "ReturnNode" ||
           last_bt == "LocalVariableWriteNode" || last_bt == "InstanceVariableWriteNode" ||
           last_bt == "ClassVariableWriteNode" || last_bt == "GlobalVariableWriteNode"
          compile_stmt(last_b)
        else
          last_v_yic = compile_expr(last_b)
          last_et = infer_type(last_b)
          if base_type(rt_yc) == "bigint" && last_et == "int"
            @needs_bigint = 1
            last_v_yic = "sp_bigint_new_int(" + last_v_yic + ")"
          elsif base_type(rt_yc) == "int" && last_et == "bigint"
            @needs_bigint = 1
            last_v_yic = "sp_bigint_to_int((sp_Bigint *)" + last_v_yic + ")"
          end
          emit("  " + result_tmp + " = " + last_v_yic + ";")
        end
      end
    end
    0
  end

  def compile_stmt_with_block(nid, blk, bp_names, map_from, map_to)
    if nid < 0
      return
    end
    t = @nd_type[nid]
    if t == "YieldNode"
 # Replace yield with the block body
      args_id = @nd_arguments[nid]
      assigned = 0
      if args_id >= 0
        aids = get_args(args_id)
        k = 0
        while k < aids.length
          if k < bp_names.length
 # Coerce when the block param's slot type differs from the
 # yielded value's type (the canonical promote-mode shape
 # `yield 1, 2` against bigint-widened block params).
            bp_t_yarg = find_var_type(bp_names[k])
            arg_v_yarg = compile_expr_remap(aids[k], map_from, map_to)
            arg_t_yarg = infer_type(aids[k])
 # Stale `arg_t_yarg == "int"` when the actual emit is sp_bigint_*
 # (arith on a bigint LV via compile_expr_remap). expr_emit_is_bigint
 # walks the AST shape so we don't double-wrap.
            arg_emit_bigint_y = expr_emit_is_bigint(aids[k]) == 1
            if bp_t_yarg == "bigint" && arg_t_yarg == "int" && !arg_emit_bigint_y
              @needs_bigint = 1
              arg_v_yarg = "sp_bigint_new_int(" + arg_v_yarg + ")"
            elsif bp_t_yarg == "int" && (arg_t_yarg == "bigint" || arg_emit_bigint_y)
              @needs_bigint = 1
              arg_v_yarg = "sp_bigint_to_int((sp_Bigint *)" + arg_v_yarg + ")"
            end
            emit("  lv_" + bp_names[k] + " = " + arg_v_yarg + ";")
            assigned = assigned + 1
          end
          k = k + 1
        end
      end
 # Reset any block params that didn't receive a yield arg so a
 # later smaller-arity yield in the same method doesn't leak the
 # previous yield's values. Mirrors compile_yield_stmt's "0"
 # padding on the function-pointer dispatch path.
      while assigned < bp_names.length
        bp_reset_t = find_var_type(bp_names[assigned])
        if bp_reset_t == "bigint"
          @needs_bigint = 1
          emit("  lv_" + bp_names[assigned] + " = sp_bigint_new_int(0);")
        else
          emit("  lv_" + bp_names[assigned] + " = 0;")
        end
        assigned = assigned + 1
      end
      body = @nd_body[blk]
      if body >= 0
        stmts = get_stmts(body)
        sk = 0
        while sk < stmts.length
          compile_stmt(stmts[sk])
          sk = sk + 1
        end
      end
      return
    end
    if t == "LocalVariableWriteNode"
      lname = @nd_name[nid]
      rname = remap_local(lname, map_from, map_to)
      val = compile_expr_remap(@nd_expression[nid], map_from, map_to)
 # Type-coerce the RHS to match the declared local type. Mirrors
 # compile_stmt's LocalVariableWriteNode arm: a `content = nil`
 # against a poly-typed `content` slot must lower to
 # `lv_content = sp_box_nil()`, not `lv_content = 0` (which gcc
 # rejects -- can't assign int to sp_RbVal struct). The inline
 # body emit reached here through compile_stmt_with_block;
 # without the boxing parity the inlined version's assignment
 # type-mismatches even when the outer function's version was
 # correctly emitting boxed values via the main LV-write arm.
      vt_lv = find_var_type(lname)
      rhs_t_lv = infer_type(@nd_expression[nid])
      if vt_lv == "poly" && rhs_t_lv != "" && rhs_t_lv != "poly"
        val = box_value_to_poly(rhs_t_lv, val)
      end
      if vt_lv == "bigint" && rhs_t_lv == "int"
        @needs_bigint = 1
        val = "sp_bigint_new_int(" + val + ")"
      end
      if vt_lv == "int" && rhs_t_lv == "bigint"
        @needs_bigint = 1
        val = "sp_bigint_to_int((sp_Bigint *)" + val + ")"
      end
      emit("  lv_" + rname + " = " + val + ";")
      return
    end
    if t == "LocalVariableOperatorWriteNode"
      lname = @nd_name[nid]
      rname = remap_local(lname, map_from, map_to)
      op = @nd_binop[nid]
      val = compile_expr_remap(@nd_expression[nid], map_from, map_to)
      vt_lvo = find_var_type(lname)
 # promote-mode-widened slot: route through sp_bigint_*.
      if vt_lvo == "bigint"
        @needs_bigint = 1
        rhs_t_lvo = infer_type(@nd_expression[nid])
        rhs_big_lvo = rhs_t_lvo == "bigint" ? "(sp_Bigint *)(" + val + ")" : "sp_bigint_new_int(" + val + ")"
        if op == "+"
          emit("  lv_" + rname + " = sp_bigint_add((sp_Bigint *)lv_" + rname + ", " + rhs_big_lvo + ");")
          return
        end
        if op == "-"
          emit("  lv_" + rname + " = sp_bigint_sub((sp_Bigint *)lv_" + rname + ", " + rhs_big_lvo + ");")
          return
        end
        if op == "*"
          emit("  lv_" + rname + " = sp_bigint_mul((sp_Bigint *)lv_" + rname + ", " + rhs_big_lvo + ");")
          return
        end
      end
      if op == "+"
        emit("  lv_" + rname + " += " + val + ";")
      end
      if op == "-"
        emit("  lv_" + rname + " -= " + val + ";")
      end
      if op == "*"
        emit("  lv_" + rname + " *= " + val + ";")
      end
      return
    end
    if t == "WhileNode"
      old = @in_loop
      @in_loop = 1
      cond = compile_expr_remap(@nd_predicate[nid], map_from, map_to)
      emit("  while (" + cond + ") {")
      @indent = @indent + 1
      redo_label = push_redo_label
      emit_redo_label(redo_label)
      body = @nd_body[nid]
      if body >= 0
        stmts = get_stmts(body)
        sk = 0
        while sk < stmts.length
          compile_stmt_with_block(stmts[sk], blk, bp_names, map_from, map_to)
          sk = sk + 1
        end
      end
      pop_redo_label
      @indent = @indent - 1
      emit("  }")
      @in_loop = old
      return
    end
    if t == "IfNode"
      cond = compile_expr_remap(@nd_predicate[nid], map_from, map_to)
      emit("  if (" + cond + ") {")
      @indent = @indent + 1
 # Mirror compile_if_stmt's is_a? narrow push so the y1-inlined
 # then-arm of `if x.is_a?(C) ... end` sees `x` as the narrowed
 # type. Without this, the LV-read inside the inlined body
 # emits the raw poly local where the typed callee
 # (sp_re_escape, sp_re_match_p, %s interpolation) wants the
 # unboxed primitive. Issue #624.
      isa_info_wb = parse_is_a_predicate(@nd_predicate[nid])
      isa_pushed_wb = 0
      if isa_info_wb[0] != ""
        push_type_narrow(isa_info_wb[0], isa_info_wb[1])
        isa_pushed_wb = 1
      end
      body = @nd_body[nid]
      if body >= 0
        stmts = get_stmts(body)
        sk = 0
        while sk < stmts.length
          compile_stmt_with_block(stmts[sk], blk, bp_names, map_from, map_to)
          sk = sk + 1
        end
      end
      if isa_pushed_wb == 1
        pop_type_narrow
      end
      @indent = @indent - 1
      sub = @nd_subsequent[nid]
      if sub >= 0
        if @nd_type[sub] == "ElseNode"
          emit("  } else {")
          @indent = @indent + 1
          eb = @nd_body[sub]
          if eb >= 0
            estmts = get_stmts(eb)
            sk = 0
            while sk < estmts.length
              compile_stmt_with_block(estmts[sk], blk, bp_names, map_from, map_to)
              sk = sk + 1
            end
          end
          @indent = @indent - 1
        else
          emit("  } else")
          compile_stmt_with_block(sub, blk, bp_names, map_from, map_to)
          return
        end
      end
      emit("  }")
      return
    end
    if t == "CallNode"
 # Check if block_given? with remap
      if @nd_name[nid] == "block_given?"
        recv_bg = @nd_receiver[nid]
        if recv_bg < 0 || (recv_bg >= 0 && @nd_type[recv_bg] == "SelfNode")
 # In inlined context, block IS given, do nothing
          return
        end
      end
 # Handle nested each/times with yield inside block
      if @nd_block[nid] >= 0
        mname2 = @nd_name[nid]
        if mname2 == "each"
 # Compile the each loop, but inside the block body, recurse with yield replacement
          compile_each_with_yield_inline(nid, blk, bp_names, map_from, map_to)
          return
        end
 # Nested call to a user yield-method while we're already inlining
 # the surrounding caller. The classic shape is `outer do |x| yield x*2 end`
 # inside `inner`, where `inner` was inlined into main and `outer` is
 # itself a yield-using top-level method. Pre-fix the call fell through
 # to compile_expr_remap, which emitted a real `sp_outer(...)` call —
 # but inlined locals like `lv_x_y2` were never reachable from that
 # generated function. Inline outer's body in place; its `yield` becomes
 # the do/end body, and any `yield` *inside* that do/end body still
 # refers to the surrounding caller's block (the `blk` we already have).
 # Issue #664.
        if @nd_receiver[nid] < 0 && find_method_idx(mname2) >= 0
          inner_mi = find_method_idx(mname2)
          if inner_mi >= 0 && inner_mi < @meth_has_yield.length && @meth_has_yield[inner_mi] == 1
            compile_nested_yield_call_inline(nid, inner_mi, blk, bp_names, map_from, map_to)
            return
          end
        end
      end
 # Compile call with remapping for args
      val = compile_expr_remap(nid, map_from, map_to)
      if val != "0"
        emit("  " + val + ";")
      end
      return
    end
    if t == "ReturnNode"
 # In inlined context, return becomes a value assignment
 # but for simplicity, just skip
      return
    end
    if t == "UnlessNode"
 # `raise X unless Y` previously fell through to
 # compile_expr_remap's default, which emitted the cond as a
 # no-op ternary AND the raise unconditionally as a separate
 # statement. Inline as `if (!cond) { body } [else { else }]`.
      cond = compile_expr_remap(@nd_predicate[nid], map_from, map_to)
      emit("  if (!(" + cond + ")) {")
      @indent = @indent + 1
      body = @nd_body[nid]
      if body >= 0
        bs = get_stmts(body)
        bk = 0
        while bk < bs.length
          compile_stmt_with_block(bs[bk], blk, bp_names, map_from, map_to)
          bk = bk + 1
        end
      end
      @indent = @indent - 1
      ec = @nd_else_clause[nid]
      if ec >= 0
        emit("  } else {")
        @indent = @indent + 1
        es = get_stmts(@nd_body[ec])
        ek = 0
        while ek < es.length
          compile_stmt_with_block(es[ek], blk, bp_names, map_from, map_to)
          ek = ek + 1
        end
        @indent = @indent - 1
      end
      emit("  }")
      return
    end
 # Default: for expression statements, use remap
    val = compile_expr_remap(nid, map_from, map_to)
    if val != "0"
      emit("  " + val + ";")
    end
  end

  def remap_local(name, map_from, map_to)
    k = 0
    while k < map_from.length
      if map_from[k] == name
        return map_to[k]
      end
      k = k + 1
    end
    name
  end

  def compile_expr_remap(nid, map_from, map_to)
    if nid < 0
      return "0"
    end
    t = @nd_type[nid]
    if t == "YieldNode" && @inline_yield_blk >= 0
 # Yield used as a sub-expression inside an inlined yield-using
 # method body (e.g. `arr.push(yield)`, `yield * 2`). Pre-emit the
 # block-param assignment + the block body's non-last stmts, then
 # capture the block body's last expr into a temp and return that
 # temp. compile_yield_inline_expr handles all the bookkeeping.
      return compile_yield_inline_expr(nid, @inline_yield_blk, @inline_yield_bp_names, map_from, map_to)
    end
    if t == "LocalVariableReadNode"
      rname = remap_local(@nd_name[nid], map_from, map_to)
 # Mirror compile_expr's LocalVariableReadNode unbox arm so a
 # poly-typed inlined local narrowed via `if x.is_a?(C) ... end`
 # in the source body emits the matching `.v.s` / `.v.i` / ...
 # unbox inside the y1 specialization. Without this, the inlined
 # copy lands `lv_content_y1` raw where `const char *` is expected
 # (sp_re_escape / sp_re_match_p / interpolation) and trips a C
 # compile. Issue #624. The narrow stack uses the original AST
 # name; the declared-type lookup needs the renamed local so it
 # sees the y1 scope's poly slot.
      orig_name = @nd_name[nid]
      narrow_t = find_var_type(orig_name)
      declared_t = find_var_declared_type(rname)
      if declared_t == "poly"
        if narrow_t == "int"
          return "(lv_" + rname + ").v.i"
        end
        if narrow_t == "string" || narrow_t == "mutable_str"
          return "(lv_" + rname + ").v.s"
        end
        if narrow_t == "float"
          return "(lv_" + rname + ").v.f"
        end
        if narrow_t == "bool"
          return "(lv_" + rname + ").v.b"
        end
        if narrow_t == "symbol"
          return "(sp_sym)(lv_" + rname + ").v.i"
        end
      end
      return "lv_" + rname
    end
    if t == "InstanceVariableReadNode"
 # Remap self to the _yself variable
      self_name = remap_local("_self_", map_from, map_to)
      return self_name + "->" + sanitize_ivar(@nd_name[nid])
    end
    if t == "SelfNode"
      return remap_local("_self_", map_from, map_to)
    end
    if t == "CallNode"
      if @nd_name[nid] == "block_given?"
        recv_bg = @nd_receiver[nid]
        if recv_bg < 0 || (recv_bg >= 0 && @nd_type[recv_bg] == "SelfNode")
          return "1"
        end
      end
 # For operators with remapped locals
      mname = @nd_name[nid]
      recv = @nd_receiver[nid]
      if recv >= 0
 # promote-mode-widened recv: route arith / cmp through the
 # sp_bigint_* helpers. Mirrors compile_operator_expr's bigint
 # branch but for the remapped (inlined yield body) emit path.
        recv_t_rm = base_type(infer_type(recv))
        if recv_t_rm == "bigint" && (mname == "+" || mname == "-" || mname == "*" || mname == "/" || mname == "%" || mname == "<" || mname == ">" || mname == "<=" || mname == ">=" || mname == "==" || mname == "!=")
          @needs_bigint = 1
          rc_b_rm = "(sp_Bigint *)" + compile_expr_remap(recv, map_from, map_to)
          args_id_rm = @nd_arguments[nid]
          arg_b_rm = "sp_bigint_new_int(0)"
          if args_id_rm >= 0
            arg_ids_rm = get_args(args_id_rm)
            if arg_ids_rm.length > 0
              arg_raw_rm = compile_expr_remap(arg_ids_rm[0], map_from, map_to)
              arg_t_rm = infer_type(arg_ids_rm[0])
              if arg_t_rm == "bigint"
                arg_b_rm = "(sp_Bigint *)" + arg_raw_rm
              else
                arg_b_rm = "sp_bigint_new_int(" + arg_raw_rm + ")"
              end
            end
          end
          if mname == "+"
            return "sp_bigint_add(" + rc_b_rm + ", " + arg_b_rm + ")"
          end
          if mname == "-"
            return "sp_bigint_sub(" + rc_b_rm + ", " + arg_b_rm + ")"
          end
          if mname == "*"
            return "sp_bigint_mul(" + rc_b_rm + ", " + arg_b_rm + ")"
          end
          if mname == "/"
            return "sp_bigint_div(" + rc_b_rm + ", " + arg_b_rm + ")"
          end
          if mname == "%"
            return "sp_bigint_mod(" + rc_b_rm + ", " + arg_b_rm + ")"
          end
          if mname == "<"
            return "(sp_bigint_cmp(" + rc_b_rm + ", " + arg_b_rm + ") < 0)"
          end
          if mname == ">"
            return "(sp_bigint_cmp(" + rc_b_rm + ", " + arg_b_rm + ") > 0)"
          end
          if mname == "<="
            return "(sp_bigint_cmp(" + rc_b_rm + ", " + arg_b_rm + ") <= 0)"
          end
          if mname == ">="
            return "(sp_bigint_cmp(" + rc_b_rm + ", " + arg_b_rm + ") >= 0)"
          end
          if mname == "=="
            return "(sp_bigint_cmp(" + rc_b_rm + ", " + arg_b_rm + ") == 0)"
          end
          if mname == "!="
            return "(sp_bigint_cmp(" + rc_b_rm + ", " + arg_b_rm + ") != 0)"
          end
        end
        if mname == "+"
          return "(" + compile_expr_remap(recv, map_from, map_to) + " + " + compile_expr_remap_arg0(nid, map_from, map_to) + ")"
        end
        if mname == "-"
          args_id = @nd_arguments[nid]
          if args_id < 0
            return "(-" + compile_expr_remap(recv, map_from, map_to) + ")"
          end
          return "(" + compile_expr_remap(recv, map_from, map_to) + " - " + compile_expr_remap_arg0(nid, map_from, map_to) + ")"
        end
        if mname == "*"
          return "(" + compile_expr_remap(recv, map_from, map_to) + " * " + compile_expr_remap_arg0(nid, map_from, map_to) + ")"
        end
        if mname == "/"
          return "sp_idiv(" + compile_expr_remap(recv, map_from, map_to) + ", " + compile_expr_remap_arg0(nid, map_from, map_to) + ")"
        end
        if mname == "%"
          return "sp_imod(" + compile_expr_remap(recv, map_from, map_to) + ", " + compile_expr_remap_arg0(nid, map_from, map_to) + ")"
        end
        if mname == "<"
          return "(" + compile_expr_remap(recv, map_from, map_to) + " < " + compile_expr_remap_arg0(nid, map_from, map_to) + ")"
        end
        if mname == ">"
          return "(" + compile_expr_remap(recv, map_from, map_to) + " > " + compile_expr_remap_arg0(nid, map_from, map_to) + ")"
        end
        if mname == "<="
          return "(" + compile_expr_remap(recv, map_from, map_to) + " <= " + compile_expr_remap_arg0(nid, map_from, map_to) + ")"
        end
        if mname == ">="
          return "(" + compile_expr_remap(recv, map_from, map_to) + " >= " + compile_expr_remap_arg0(nid, map_from, map_to) + ")"
        end
        if mname == "=="
          return "(" + compile_expr_remap(recv, map_from, map_to) + " == " + compile_expr_remap_arg0(nid, map_from, map_to) + ")"
        end
        if mname == "!="
          return "(" + compile_expr_remap(recv, map_from, map_to) + " != " + compile_expr_remap_arg0(nid, map_from, map_to) + ")"
        end
 # `[]` / `[]=` / `length` / `size` on a remapped local: compute
 # the receiver's type so the dispatch picks the right runtime
 # accessor, then emit with the remapped receiver expression.
 # without this `arr[i]` inside the inlined body
 # falls through to compile_expr below, which doesn't see the
 # remap and emits `lv_i` instead of `lv_i_y1`.
        if mname == "[]" || mname == "length" || mname == "size"
          rt_r = infer_type(recv)
          rc_r = compile_expr_remap(recv, map_from, map_to)
          if rt_r == "str_array" && mname == "[]"
            arg_r = compile_expr_remap_arg0(nid, map_from, map_to)
            args_id_sr = @nd_arguments[nid]
            if args_id_sr >= 0
              aa_sr = get_args(args_id_sr)
              if aa_sr.length > 0 && infer_type(aa_sr[0]) == "bigint"
                @needs_bigint = 1
                arg_r = "sp_bigint_to_int((sp_Bigint *)" + arg_r + ")"
              end
            end
            return "sp_StrArray_get(" + rc_r + ", " + arg_r + ")"
          end
          if rt_r == "int_array" && mname == "[]"
            arg_r = compile_expr_remap_arg0(nid, map_from, map_to)
 # Unbox bigint index — promote mode may have widened the
 # iter counter local to sp_Bigint *.
            args_id_ir = @nd_arguments[nid]
            if args_id_ir >= 0
              aa_ir = get_args(args_id_ir)
              if aa_ir.length > 0 && infer_type(aa_ir[0]) == "bigint"
                @needs_bigint = 1
                arg_r = "sp_bigint_to_int((sp_Bigint *)" + arg_r + ")"
              end
            end
            return "sp_IntArray_get(" + rc_r + ", " + arg_r + ")"
          end
          if rt_r == "float_array" && mname == "[]"
            arg_r = compile_expr_remap_arg0(nid, map_from, map_to)
            args_id_fr = @nd_arguments[nid]
            if args_id_fr >= 0
              aa_fr = get_args(args_id_fr)
              if aa_fr.length > 0 && infer_type(aa_fr[0]) == "bigint"
                @needs_bigint = 1
                arg_r = "sp_bigint_to_int((sp_Bigint *)" + arg_r + ")"
              end
            end
            return "sp_FloatArray_get(" + rc_r + ", " + arg_r + ")"
          end
          if (rt_r == "str_array" || rt_r == "int_array" || rt_r == "sym_array") && (mname == "length" || mname == "size")
            pfx_r = "IntArray"
            if rt_r == "str_array"
              pfx_r = "StrArray"
            end
            return "sp_" + pfx_r + "_length(" + rc_r + ")"
          end
          if rt_r == "float_array" && (mname == "length" || mname == "size")
            return "sp_FloatArray_length(" + rc_r + ")"
          end
        end
      end
    end
 # Fallback: compile normally
    compile_expr(nid)
  end

  def compile_expr_remap_arg0(nid, map_from, map_to)
    args_id = @nd_arguments[nid]
    if args_id >= 0
      arg_ids = get_args(args_id)
      if arg_ids.length > 0
        return compile_expr_remap(arg_ids[0], map_from, map_to)
      end
    end
    "0"
  end

 # Tries the yield-method or instance_eval-trampoline dispatch
 # against a single class index. Returns 1 if dispatch fired (caller
 # should return immediately), 0 otherwise (caller falls through to
 # the next gate, e.g. parent class). Shared by the direct-class and
 # parent-class branches in compile_no_recv_call_expr.
  def try_yield_or_trampoline_dispatch(nid, recv, cls_idx, mname)
    midx = cls_find_method_direct(cls_idx, mname)
    if midx < 0
      return 0
    end
    if cls_method_has_yield(cls_idx, midx) == 1
      compile_yield_method_call_stmt(nid, cls_idx, midx, mname)
      return 1
    end
    if is_instance_eval_trampoline(cls_idx, midx) == 1
      compile_instance_eval_inlined_stmt(nid, recv)
      return 1
    end
    0
  end

 # Splice the statements of a block body in place with `self`
 # rebound to self_var (typed as cname). Saves and restores the
 # rebound-self ivars (@instance_eval_self_var / _type) so nested
 # splices compose. compile_no_recv_call_expr's instance_eval-self
 # branch reads these to dispatch receiverless calls inside the
 # splice against the rebound class. Reusable by future
 # rebind-and-splice features (e.g. instance_exec, tap-shape
 # trampolines).
  def splice_block_with_self_rebound(body, self_var, cname)
    prev_self_var = @instance_eval_self_var
    prev_self_type = @instance_eval_self_type
    @instance_eval_self_var = self_var
    @instance_eval_self_type = cname
    if body >= 0
      stmts = get_stmts(body)
      k = 0
      while k < stmts.length
        compile_stmt(stmts[k])
        k = k + 1
      end
    end
    @instance_eval_self_var = prev_self_var
    @instance_eval_self_type = prev_self_type
  end

 # Inlines a `recv.m { body }` call when `m` is an arity-0
 # instance_eval trampoline. The entire method body is the call
 # `instance_eval(&block)`, so we splice the block body in place
 # with self rebound to the receiver. Modeled on
 # compile_yield_method_call_stmt but simpler — the trampoline body
 # has no locals/params to remap.
  def compile_instance_eval_inlined_stmt(nid, recv)
    blk = @nd_block[nid]
    if blk < 0
      return
    end
    rtype = infer_type(recv)
    cname = ""
    if is_obj_type(rtype) == 1
      cname = rtype[4, rtype.length - 4]
    end
    if cname == ""
      return
    end
    rc = compile_expr_gc_rooted(recv)
    self_var = new_temp
    emit("  sp_" + cname + " *" + self_var + " = (sp_" + cname + " *)" + rc + ";")
    if @in_gc_scope == 1
      emit("  SP_GC_ROOT(" + self_var + ");")
    end
    splice_block_with_self_rebound(@nd_body[blk], self_var, cname)
  end

  def compile_yield_method_call_stmt(nid, cci, midx, mname)
 # Call a yield-using class method with a block - inline the method body
    blk = @nd_block[nid]
    if blk < 0
      return
    end
    bp_names = "".split(",", -1)
    bp = @nd_parameters[blk]
    if bp >= 0
      inner = @nd_parameters[bp]
      if inner >= 0
        reqs = parse_id_list(@nd_requireds[inner])
        k = 0
        while k < reqs.length
          bp_names.push(@nd_name[reqs[k]])
          k = k + 1
        end
      end
    end

    recv = @nd_receiver[nid]
    if recv < 0
 # Implicit self (bare `m { ... }` inside another method body
 # of the same class).
      rc = "self"
    else
      rc = compile_expr_gc_rooted(recv)
    end

    bodies = @cls_meth_bodies[cci].split(";", -1)
    bid = -1
    if midx < bodies.length
      bid = bodies[midx].to_i
    end

    saved_ci = @current_class_idx
    @current_class_idx = cci

 # route ivar reads / writes that fall through to
 # compile_expr (rather than through compile_expr_remap's remap
 # table) to the receiver instead of the literal `self`. Without
 # this, a `@keys` reference inside the inlined body would emit
 # `self->iv_keys` -- but the inlining happens at a call site
 # whose enclosing function may not have `self` declared (e.g.
 # main()).
 #
 # Wrap the override with a cast to the callee's class pointer
 # when the enclosing function's `self` is a different (subclass)
 # type. Without the cast, inlined calls to other inherited
 # methods inside the body emit `sp_<owner>_<m>(self, ...)`
 # which gcc rejects on a `sp_<subclass> *` self. Skip the cast
 # when the recv expression is already a pointer to cci's class
 # (explicit recv compiled to a typed expr) or when cci is a
 # value type (struct, not pointer).
    saved_self_override = @self_override
    if cci >= 0 && cci < @cls_is_value_type.length && @cls_is_value_type[cci] != 1
      @self_override = "((sp_" + @cls_names[cci] + " *)" + rc + ")"
    else
      @self_override = rc
    end

    @block_counter = @block_counter + 1
    suffix = "_y" + @block_counter.to_s

 # For the method params and locals, create remapped names
    pnames = cls_meth_pnames_get(cci, midx)
    ptypes = cls_meth_ptypes_get(cci, midx)

    map_from = "".split(",", -1)
    map_to = "".split(",", -1)

 # Map self to the receiver expression
    map_from.push("_self_")
    map_to.push(rc)

    args_id = @nd_arguments[nid]
    arg_ids = []
    if args_id >= 0
      arg_ids = get_args(args_id)
    end

    k = 0
    while k < pnames.length
      pt = "int"
      if k < ptypes.length
        pt = ptypes[k]
      end
      tname = pnames[k] + suffix
 # Pick a type-correct default when the caller omitted this arg
 # so the local's C type and the initializer agree (`sp_RbVal x = 0`
 # is invalid C; `sp_RbVal x = sp_box_nil()` is correct).
      val = c_default_val(pt)
      if k < arg_ids.length
        val = compile_expr(arg_ids[k])
        arg_t_ym = infer_type(arg_ids[k])
        if base_type(pt) == "bigint" && arg_t_ym == "int"
          @needs_bigint = 1
          val = "sp_bigint_new_int(" + val + ")"
        elsif base_type(pt) == "int" && arg_t_ym == "bigint"
          @needs_bigint = 1
          val = "sp_bigint_to_int((sp_Bigint *)" + val + ")"
        end
      end
      emit("  " + c_type(pt) + " lv_" + tname + " = " + val + ";")
      map_from.push(pnames[k])
      map_to.push(tname)
      declare_var(tname, pt)
 # Also declare the ORIGINAL name with the same type. Body
 # emission reads the AST's `LocalVariableReadNode "selector"`
 # (original name) through compile_expr_remap, which maps the
 # *emitted text* to "selector_y1" -- but infer_type during the
 # same emit consults the scope by the original name. Without
 # this, `selector[/regex/]` inside the inlined body misses
 # the string-typed scope entry, falls through to the int
 # default, and lowers to bit-extract on a const char *.
      declare_var(pnames[k], pt)
      k = k + 1
    end

 # Declare function locals
    if bid >= 0
      flocals_n = "".split(",", -1)
      flocals_t = "".split(",", -1)
      sn_f = @nd_scope_names[bid]
      if sn_f != ""
        flocals_n = sn_f.split("|", -1)
        flocals_t = @nd_scope_types[bid].split("|", -1)
      end
      k = 0
      while k < flocals_n.length
        tname = flocals_n[k] + suffix
        emit("  " + c_type(flocals_t[k]) + " lv_" + tname + " = " + c_default_val(flocals_t[k]) + ";")
        map_from.push(flocals_n[k])
        map_to.push(tname)
        declare_var(tname, flocals_t[k])
        declare_var(flocals_n[k], flocals_t[k])
        k = k + 1
      end
    end

 # Compile the method body inline with yield -> block body.
 # Stash the rename map in @inline_rename_map_* so fiber_var_ref
 # picks up the renamed locals when a CallNode falls through to
 # compile_expr (/).
    saved_in_rmf = @inline_rename_map_from
    saved_in_rmt = @inline_rename_map_to
    @inline_rename_map_from = map_from
    @inline_rename_map_to = map_to
    if bid >= 0
      stmts = get_stmts(bid)
      k = 0
      while k < stmts.length
        compile_stmt_with_block(stmts[k], blk, bp_names, map_from, map_to)
        k = k + 1
      end
    end
    @inline_rename_map_from = saved_in_rmf
    @inline_rename_map_to = saved_in_rmt

    @self_override = saved_self_override
    @current_class_idx = saved_ci
  end

 # Two-level yield inline: `outer do |x| yield x*2 end` appearing
 # inside an already-inlined caller (`inner`) where `outer` is itself a
 # yield-using top-level method. The callee body's yield gets replaced
 # by THIS call's literal block body (the do |x| ... end on this call),
 # and the surrounding `blk` / `bp_names` / `map_from` / `map_to` carry
 # the inner-most yields back to the original caller's block. Used by
 # compile_stmt_with_block's CallNode arm. Issue #664.
  def compile_nested_yield_call_inline(nid, callee_mi, outer_blk, outer_bp_names, map_from, map_to)
    call_blk = @nd_block[nid]
    if call_blk < 0
      return
    end
    cb_names = "".split(",", -1)
    cb_params = @nd_parameters[call_blk]
    if cb_params >= 0
      cb_inner = @nd_parameters[cb_params]
      if cb_inner >= 0
        cb_reqs = parse_id_list(@nd_requireds[cb_inner])
        kcb = 0
        while kcb < cb_reqs.length
          cb_names.push(@nd_name[cb_reqs[kcb]])
          kcb = kcb + 1
        end
      end
    end
 # Bind callee's params from the call's args. Args are evaluated in the
 # currently-inlined scope so they go through compile_expr_remap. The
 # callee's locals get a unique suffix to avoid colliding with outer
 # scope names (e.g. `lv_x` both from `inner` body and `outer`).
    pnames_n = @meth_param_names[callee_mi].split(",", -1)
    ptypes_n = @meth_param_types[callee_mi].split(",", -1)
    args_id_n = @nd_arguments[nid]
    arg_ids_n = []
    if args_id_n >= 0
      arg_ids_n = get_args(args_id_n)
    end
    @block_counter = @block_counter + 1
    suffix_n = "_n" + @block_counter.to_s
    nested_from = "".split(",", -1)
    nested_to = "".split(",", -1)
    kp_n = 0
    while kp_n < pnames_n.length
      pt_n = "int"
      if kp_n < ptypes_n.length
        pt_n = ptypes_n[kp_n]
      end
      tname_n = pnames_n[kp_n] + suffix_n
      val_n = c_default_val(pt_n)
      if kp_n < arg_ids_n.length
        val_n = compile_expr_remap(arg_ids_n[kp_n], map_from, map_to)
      end
      emit("  " + c_type(pt_n) + " lv_" + tname_n + " = " + val_n + ";")
      nested_from.push(pnames_n[kp_n])
      nested_to.push(tname_n)
      declare_var(tname_n, pt_n)
      kp_n = kp_n + 1
    end
 # Declare the call-block's params under their original names so the
 # callee body's `yield x*2` resolves x in this scope. They were
 # already added to scope_names by scan_locals on the inlined caller,
 # so we don't re-declare lv_x — just route through nested_from/to so
 # the value lookup in compile_stmt_with_block lands on the right name.
    bid_n = @meth_body_ids[callee_mi]
    if bid_n >= 0
      flocals_n = "".split(",", -1)
      flocals_t = "".split(",", -1)
      sn_n = @nd_scope_names[bid_n]
      if sn_n != ""
        flocals_n = sn_n.split("|", -1)
        flocals_t = @nd_scope_types[bid_n].split("|", -1)
      end
      kf_n = 0
      while kf_n < flocals_n.length
        tname_lv_n = flocals_n[kf_n] + suffix_n
        emit("  " + c_type(flocals_t[kf_n]) + " lv_" + tname_lv_n + " = " + c_default_val(flocals_t[kf_n]) + ";")
        nested_from.push(flocals_n[kf_n])
        nested_to.push(tname_lv_n)
        declare_var(tname_lv_n, flocals_t[kf_n])
        declare_var(flocals_n[kf_n], flocals_t[kf_n])
        kf_n = kf_n + 1
      end
    end
 # Walk callee body. A YieldNode in the callee body becomes "bind
 # call-block params + run call-block body". Within call-block body,
 # any further YieldNode refers to the *original* outer block, so we
 # pass outer_blk + outer_bp_names + map_from + map_to through.
    if bid_n >= 0
      stmts_n = get_stmts(bid_n)
      ks_n = 0
      while ks_n < stmts_n.length
        compile_nested_callee_stmt(stmts_n[ks_n], call_blk, cb_names,
                                    nested_from, nested_to,
                                    outer_blk, outer_bp_names, map_from, map_to)
        ks_n = ks_n + 1
      end
    end
  end

 # Helper for compile_nested_yield_call_inline. Walks the callee body
 # (e.g. outer's `yield 1`) translating a YieldNode into the call's
 # do/end body, and routing other statements through compile_stmt_with_block
 # so their LV reads see nested_from/to renames.
  def compile_nested_callee_stmt(nid, call_blk, cb_names,
                                  nested_from, nested_to,
                                  outer_blk, outer_bp_names, map_from, map_to)
    if nid < 0
      return
    end
    if @nd_type[nid] == "YieldNode"
 # Bind call-block params from yield args (evaluated in the nested
 # callee scope, so use nested_from/to for renaming). The block
 # param's storage name in the surrounding inlined caller goes
 # through map_from/to — `x` in the source becomes `x_y2` in main
 # after scan_locals' rename, so we must route the destination
 # through remap_local too.
      yargs = @nd_arguments[nid]
      if yargs >= 0
        yaids = get_args(yargs)
        yk = 0
        while yk < yaids.length
          if yk < cb_names.length
            v_y = compile_expr_remap(yaids[yk], nested_from, nested_to)
            dst = remap_local(cb_names[yk], map_from, map_to)
 # Promote mode widens block params to bigint; an `int`-typed
 # yield arg needs sp_bigint_new_int boxing before assignment
 # so the destination slot's bigint pointer type matches.
            dst_t = find_var_type(dst)
            arg_t = infer_type(yaids[yk])
 # Stale `arg_t == "int"` cache when the emitted expr is already
 # sp_Bigint * (arith on a bigint LV). expr_emit_is_bigint walks
 # the shape so we don't double-wrap with sp_bigint_new_int.
            arg_emit_bigint = expr_emit_is_bigint(yaids[yk]) == 1
            if base_type(dst_t) == "bigint" && arg_t == "int" && !arg_emit_bigint
              @needs_bigint = 1
              v_y = "sp_bigint_new_int(" + v_y + ")"
            elsif base_type(dst_t) == "int" && (arg_t == "bigint" || arg_emit_bigint)
              @needs_bigint = 1
              v_y = "sp_bigint_to_int((sp_Bigint *)" + v_y + ")"
            end
            emit("  lv_" + dst + " = " + v_y + ";")
          end
          yk = yk + 1
        end
      end
 # Run the call's do/end body. yields inside it refer to the
 # original outer block, so use outer_blk / outer_bp_names /
 # map_from / map_to (the surrounding inlined caller's scope).
      cb_body = @nd_body[call_blk]
      if cb_body >= 0
        cb_stmts = get_stmts(cb_body)
        kb = 0
        while kb < cb_stmts.length
          compile_stmt_with_block(cb_stmts[kb], outer_blk, outer_bp_names, map_from, map_to)
          kb = kb + 1
        end
      end
      return
    end
 # Non-yield statements in callee body: emit through the standard
 # walker but with nested_from/to so LV reads see the suffix rename.
    compile_stmt_with_block(nid, call_blk, cb_names, nested_from, nested_to)
  end

  def compile_each_with_yield_inline(nid, outer_blk, outer_bp_names, map_from, map_to)
 # An each call on an array inside an inlined yield function
 # The each block contains yield statements that should be replaced with outer block body
    recv = @nd_receiver[nid]
    recv_expr = compile_expr_remap(recv, map_from, map_to)
    rt = infer_type(recv)
 # If recv is remapped, get the actual type
    if @nd_type[recv] == "InstanceVariableReadNode"
      if @current_class_idx >= 0
        rt = cls_ivar_type(@current_class_idx, @nd_name[recv])
      end
    end

    inner_bp1 = get_block_param(nid, 0)
    if inner_bp1 == ""
      inner_bp1 = "_ex"
    end
 # The inner block param might collide with outer names, so remap it
    inner_bp_remapped = remap_local(inner_bp1, map_from, map_to)

    old = @in_loop
    @in_loop = 1
    tmp = new_temp

    if rt == "int_array"
      emit("  for (mrb_int " + tmp + " = 0; " + tmp + " < sp_IntArray_length(" + recv_expr + "); " + tmp + "++) {")
      inner_bp_t_eyi = find_var_type(inner_bp_remapped)
      if inner_bp_t_eyi == "bigint"
        @needs_bigint = 1
        emit("    lv_" + inner_bp_remapped + " = sp_bigint_new_int(sp_IntArray_get(" + recv_expr + ", " + tmp + "));")
      else
        emit("    lv_" + inner_bp_remapped + " = sp_IntArray_get(" + recv_expr + ", " + tmp + ");")
      end
      @indent = @indent + 1
      redo_label = push_redo_label
      emit_redo_label(redo_label)
 # Compile inner block body, replacing yield with outer block body
      inner_blk = @nd_block[nid]
      if inner_blk >= 0
        ibody = @nd_body[inner_blk]
        if ibody >= 0
          istmts = get_stmts(ibody)
          sk = 0
          while sk < istmts.length
 # In the inner block, yield should be replaced with outer block body
            inner_nid = istmts[sk]
            if @nd_type[inner_nid] == "YieldNode"
 # yield x -> set outer bp from inner bp, then run outer block body
              yargs = @nd_arguments[inner_nid]
              if yargs >= 0
                yaids = get_args(yargs)
                yk = 0
                while yk < yaids.length
                  if yk < outer_bp_names.length
                    yarg_v_eyi = compile_expr_remap(yaids[yk], map_from, map_to)
                    yarg_t_eyi = infer_type(yaids[yk])
                    outer_bp_t_eyi = find_var_type(outer_bp_names[yk])
                    if outer_bp_t_eyi == "bigint" && yarg_t_eyi == "int"
                      @needs_bigint = 1
                      yarg_v_eyi = "sp_bigint_new_int(" + yarg_v_eyi + ")"
                    elsif outer_bp_t_eyi == "int" && yarg_t_eyi == "bigint"
                      @needs_bigint = 1
                      yarg_v_eyi = "sp_bigint_to_int((sp_Bigint *)" + yarg_v_eyi + ")"
                    end
                    emit("  lv_" + outer_bp_names[yk] + " = " + yarg_v_eyi + ";")
                  end
                  yk = yk + 1
                end
              end
              obody = @nd_body[outer_blk]
              if obody >= 0
                ostmts = get_stmts(obody)
                ok = 0
                while ok < ostmts.length
                  compile_stmt(ostmts[ok])
                  ok = ok + 1
                end
              end
            else
              compile_stmt_with_block(inner_nid, outer_blk, outer_bp_names, map_from, map_to)
            end
            sk = sk + 1
          end
        end
      end
      pop_redo_label
      @indent = @indent - 1
      emit("  }")
    end
    @in_loop = old
  end

  def compile_map_block(nid)
    @needs_int_array = 1
    @needs_gc = 1
    old = @in_loop
    @in_loop = 1
 # N.times.map { |i| ... } -> build int_array with block body; param = index
    recv = @nd_receiver[nid]
    times_recv = 0
    if recv >= 0
      if @nd_type[recv] == "CallNode"
        if @nd_name[recv] == "times"
          if @nd_block[recv] < 0
            times_recv = 1
          end
        end
      end
    end
    if times_recv == 1
      ncount = compile_expr(@nd_receiver[recv])
      bpn = get_block_param(nid, 0)
      tmp_arrn = new_temp
      tmp_in = new_temp
      push_scope
      if bpn != ""
        declare_var(bpn, "int")
      end
      res_type = "int"
      blk_n = @nd_block[nid]
      if blk_n >= 0
        body_n = @nd_body[blk_n]
        if body_n >= 0
          stmts_n = get_stmts(body_n)
          if stmts_n.length > 0
            res_type = infer_type(stmts_n.last)
          end
        end
      end
      if res_type == "string"
        @needs_str_array = 1
        emit("  sp_StrArray *" + tmp_arrn + " = sp_StrArray_new();")
      elsif res_type == "float"
        emit("  sp_FloatArray *" + tmp_arrn + " = sp_FloatArray_new();")
      else
        emit("  sp_IntArray *" + tmp_arrn + " = sp_IntArray_new();")
      end
      emit("  for (mrb_int " + tmp_in + " = 0; " + tmp_in + " < " + ncount + "; " + tmp_in + "++) {")
      if bpn != ""
        emit("    lv_" + bpn + " = " + tmp_in + ";")
      end
      @indent = @indent + 1
      if blk_n >= 0
        body_n2 = @nd_body[blk_n]
        if body_n2 >= 0
          stmts_n2 = get_stmts(body_n2)
          if stmts_n2.length > 0
            k = 0
            while k < stmts_n2.length - 1
              compile_stmt(stmts_n2[k])
              k = k + 1
            end
            lastv = compile_expr(stmts_n2.last)
            if res_type == "string"
              emit("  sp_StrArray_push(" + tmp_arrn + ", " + lastv + ");")
            elsif res_type == "float"
              emit("  sp_FloatArray_push(" + tmp_arrn + ", " + lastv + ");")
            else
 # promote-mode block tail emits a bigint expr; unbox before
 # pushing into the int_array accumulator.
              if infer_type(stmts_n2.last) == "bigint"
                @needs_bigint = 1
                lastv = "sp_bigint_to_int((sp_Bigint *)" + lastv + ")"
              end
              emit("  sp_IntArray_push(" + tmp_arrn + ", " + lastv + ");")
            end
          end
        end
      end
      @indent = @indent - 1
      emit("  }")
      pop_scope
      @in_loop = old
      return
    end
    rt = infer_type(@nd_receiver[nid])
    rc = compile_expr_gc_rooted(@nd_receiver[nid])
    bp1 = get_block_param(nid, 0)
    if bp1 == ""
      bp1 = "_x"
    end
    tmp_arr = new_temp
    tmp_i = new_temp
    if rt == "int_array"
      emit("  sp_IntArray *" + tmp_arr + " = sp_IntArray_new();")
      emit("  for (mrb_int " + tmp_i + " = 0; " + tmp_i + " < sp_IntArray_length(" + rc + "); " + tmp_i + "++) {")
      emit("    mrb_int lv_" + bp1 + " = sp_IntArray_get(" + rc + ", " + tmp_i + ");")
      @indent = @indent + 1
      push_scope
      declare_var(bp1, "int")
      blk = @nd_block[nid]
      if blk >= 0
        body = @nd_body[blk]
        if body >= 0
          stmts = get_stmts(body)
          if stmts.length > 0
            last = stmts.last
            val = compile_expr(last)
            emit("  sp_IntArray_push(" + tmp_arr + ", " + val + ");")
          end
        end
      end
      pop_scope
      @indent = @indent - 1
      emit("  }")
    end
    if rt == "str_array"
      @needs_str_array = 1
      emit("  sp_StrArray *" + tmp_arr + " = sp_StrArray_new();")
      emit("  for (mrb_int " + tmp_i + " = 0; " + tmp_i + " < sp_StrArray_length(" + rc + "); " + tmp_i + "++) {")
      emit("    const char *lv_" + bp1 + " = sp_StrArray_get(" + rc + ", " + tmp_i + ");")
      @indent = @indent + 1
      push_scope
      declare_var(bp1, "string")
      blk = @nd_block[nid]
      if blk >= 0
        body = @nd_body[blk]
        if body >= 0
          stmts = get_stmts(body)
          if stmts.length > 0
            last = stmts.last
            val = compile_expr(last)
            emit("  sp_StrArray_push(" + tmp_arr + ", " + val + ");")
          end
        end
      end
      pop_scope
      @indent = @indent - 1
      emit("  }")
    end
    @in_loop = old
  end

  def compile_select_block(nid)
    @needs_int_array = 1
    @needs_gc = 1
    old = @in_loop
    @in_loop = 1
    rt = infer_type(@nd_receiver[nid])
    rc = compile_expr_gc_rooted(@nd_receiver[nid])
    bp1 = get_block_param(nid, 0)
    if bp1 == ""
      bp1 = "_x"
    end
    tmp_arr = new_temp
    tmp_i = new_temp
    if rt == "int_array" || rt == "sym_array"
      bp_t = elem_type_of_array(rt)
      emit("  sp_IntArray *" + tmp_arr + " = sp_IntArray_new();")
      emit("  for (mrb_int " + tmp_i + " = 0; " + tmp_i + " < sp_IntArray_length(" + rc + "); " + tmp_i + "++) {")
      emit("    mrb_int lv_" + bp1 + " = sp_IntArray_get(" + rc + ", " + tmp_i + ");")
      @indent = @indent + 1
      push_scope
      declare_var(bp1, bp_t)
      blk = @nd_block[nid]
      if blk >= 0
        body = @nd_body[blk]
        if body >= 0
          stmts = get_stmts(body)
          if stmts.length > 0
            last = stmts.last
            cond = compile_expr(last)
            emit("  if (" + cond + ") sp_IntArray_push(" + tmp_arr + ", lv_" + bp1 + ");")
          end
        end
      end
      pop_scope
      @indent = @indent - 1
      emit("  }")
    end
    @in_loop = old
  end

  def compile_stmts_body(nid)
    if nid < 0
      return
    end
    stmts = get_stmts(nid)
    k = 0
    while k < stmts.length
      compile_stmt(stmts[k])
      k = k + 1
    end
  end

  # Helper for method-level begin/rescue: compiles the statements of a
  # body, emitting all-but-last as stmts and assigning the last expr's
  # value into ret_tmp. Used so that `def f; X; rescue; Y; end` returns
  # X's value on the success path and Y's value on the rescue path.
  def compile_body_into(body_id, ret_tmp, return_type)
    if body_id < 0
      return
    end
    stmts = get_stmts(body_id)
    if stmts.length == 0
      return
    end
    i = 0
    while i < stmts.length - 1
      compile_stmt(stmts[i])
      i = i + 1
    end
    last = stmts.last
    lt = @nd_type[last]
    if lt == "ReturnNode" || lt == "WhileNode" || lt == "UntilNode" || lt == "BreakNode" || lt == "NextNode"
      compile_stmt(last)
      return
    end
    if return_type == "void"
      compile_stmt(last)
      return
    end
    # IO-shaped intrinsics (puts/print/p/printf/warn/pp) have no
    # expression form in spinel codegen — compile_call_expr would
    # warn "cannot resolve" and return the literal "0", silently
    # dropping the side effect. Force statement form for these.
    if lt == "CallNode" && @nd_receiver[last] < 0
      cn = @nd_name[last]
      if cn == "puts" || cn == "print" || cn == "p" || cn == "pp" || cn == "printf" || cn == "warn"
        compile_stmt(last)
        return
      end
    end
    expr = compile_expr(last)
    last_t_cbi = infer_type(last)
    if base_type(return_type) == "bigint" && last_t_cbi == "int"
      @needs_bigint = 1
      expr = "sp_bigint_new_int(" + expr + ")"
    elsif base_type(return_type) == "int" && last_t_cbi == "bigint"
      @needs_bigint = 1
      expr = "sp_bigint_to_int((sp_Bigint *)" + expr + ")"
    elsif base_type(return_type) == "poly" && last_t_cbi != "poly" && last_t_cbi != ""
      expr = box_value_to_poly(last_t_cbi, expr)
    end
    emit("  " + ret_tmp + " = " + expr + ";")
  end

  # Mirror of compile_rescue_chain that captures the rescue body's last
  # expression into ret_tmp instead of dropping it. Used by the
  # method-level BeginNode arm in compile_body_return.
  def compile_rescue_chain_into(rc, ret_tmp, return_type)
    exc_types = parse_id_list(@nd_exceptions[rc])
    ref = @nd_reference[rc]
    # Snapshot the in-flight exception BEFORE the type-check `if` so
    # the else-branch (re-raise / propagation) can also reference it.
    @rescue_depth = @rescue_depth + 1
    saved_cls = "_rescue_cls_" + @rescue_depth.to_s
    saved_msg = "_rescue_msg_" + @rescue_depth.to_s
    emit("  const char *" + saved_cls + " = (const char *)sp_last_exc_cls;")
    emit("  const char *" + saved_msg + " = sp_exc_msg[sp_exc_top];")
    @rescue_cls_stack.push(saved_cls)
    @rescue_msg_stack.push(saved_msg)
    has_type_check = 0
    if exc_types.length > 0
      has_type_check = 1
 # See compile_rescue_chain for sp_exc_class_le rationale (#627).
      @needs_exc_class_hierarchy = 1
      cond = ""
      k = 0
      while k < exc_types.length
        if k > 0
          cond = cond + " || "
        end
        cond = cond + "sp_exc_class_le((const char*)sp_last_exc_cls, \"" + @nd_name[exc_types[k]] + "\")"
        k = k + 1
      end
      emit("  if (" + cond + ") {")
      @indent = @indent + 1
    end
    bound_rname = ""
    if ref >= 0
      bound_rname = @nd_name[ref]
 # See compile_rescue_chain -- same sp_Exception * lower.
      emit("  lv_" + bound_rname + " = sp_exc_new(" + saved_cls + ", " + saved_msg + ");")
    end
    compile_body_into(@nd_body[rc], ret_tmp, return_type)
    @rescue_cls_stack.pop
    @rescue_msg_stack.pop
    @rescue_depth = @rescue_depth - 1
    if has_type_check == 1
      @indent = @indent - 1
      sub = @nd_subsequent[rc]
      if sub >= 0
        emit("  } else {")
        @indent = @indent + 1
        compile_rescue_chain_into(sub, ret_tmp, return_type)
        @indent = @indent - 1
      else
        emit("  } else {")
        emit("    sp_raise_cls(" + saved_cls + ", " + saved_msg + ");")
      end
      emit("  }")
    end
    0
  end

 # Wrapper: snapshots the narrow-stack depth, delegates to the
 # inner emit (which pushes raise-guard narrows for #493 in its
 # stmt loop), then pops everything pushed during the body emit.
 # The inner has many early-return paths; counting at the
 # baseline lets each path leave without explicit cleanup.
  def compile_body_return(body_id, return_type)
    narrow_baseline_cbr = @type_narrow_names.length
    compile_body_return_inner(body_id, return_type)
    while @type_narrow_names.length > narrow_baseline_cbr
      pop_type_narrow
    end
  end

 # `--int-overflow=promote` widens return slots to bigint while
 # some surrounding slots (cvars, gvars, lvars in arms that don't
 # carry through the promotion) stay int. Coerce when the value's
 # source type differs from the function's declared return type.
  def maybe_bigint_coerce(c_expr, src_t, ret_t)
    if base_type(ret_t) == "bigint" && src_t == "int"
      @needs_bigint = 1
      return "sp_bigint_new_int(" + c_expr + ")"
    end
    if base_type(ret_t) == "int" && src_t == "bigint"
      @needs_bigint = 1
      return "sp_bigint_to_int((sp_Bigint *)" + c_expr + ")"
    end
    c_expr
  end

 # Returns 1 if `nid` is a `<typed_hash>.fetch(k, nil)` CallNode --
 # the shape that motivates the issue #671 return-site coerce. Only
 # fires for int-leaf hash variants (str_int_hash / sym_int_hash):
 # for those, the ternary's get arm returns mrb_int and a nil default
 # also lowers to 0, so the whole expression is "int" but the
 # surrounding method may have an RBS-pinned nullable-pointer return.
  def fetch_with_nil_default?(nid)
    if nid < 0 || @nd_type[nid] != "CallNode"
      return 0
    end
    return 0 if @nd_name[nid] != "fetch"
    recv_fn = @nd_receiver[nid]
    return 0 if recv_fn < 0
    rt_fn = infer_type(recv_fn)
    return 0 if rt_fn != "str_int_hash" && rt_fn != "sym_int_hash"
    args_id_fn = @nd_arguments[nid]
    return 0 if args_id_fn < 0
    aargs_fn = get_args(args_id_fn)
    return 0 if aargs_fn.length < 2
    @nd_type[aargs_fn[1]] == "NilNode" ? 1 : 0
  end

  def compile_body_return_inner(body_id, return_type)
    if body_id < 0
      if return_type != "void"
        emit("  return " + c_return_default(return_type) + ";")
      end
      return
    end
    stmts = get_stmts(body_id)
    if stmts.length == 0
      if return_type != "void"
        emit("  return " + c_return_default(return_type) + ";")
      end
      return
    end
 # All but last. Sibling-scope narrow for
 # `raise unless x.is_a?(C)` guards: when a guard appears at
 # stmts[i], the rest of the body (i+1..N including `last`)
 # sees `x` as the narrowed type via find_var_type. Pops happen
 # via the compile_body_return wrapper's baseline tracking
 # below, after every internal return path. Issue #493.
    i = 0
    while i < stmts.length - 1
      compile_stmt(stmts[i])
      rg_p_cbr = parse_raise_guard_narrow(stmts[i])
      if rg_p_cbr[0] != ""
        push_type_narrow(rg_p_cbr[0], rg_p_cbr[1])
      end
 # Sibling: `return X if h.nil?` after a writer that revealed
 # h as int-or-nil (e.g. `s.index(needle)`). Issue #550.
      ng_var_cbr = parse_nil_guard_var(stmts[i])
      if ng_var_cbr != ""
        ng_narrow_cbr = scan_back_writer_narrow_for(stmts, i, ng_var_cbr)
        if ng_narrow_cbr != ""
          push_type_narrow(ng_var_cbr, ng_narrow_cbr)
        end
      end
      i = i + 1
    end
    last = stmts.last
    if @nd_type[last] == "ReturnNode"
      compile_return_stmt(last)
      return
    end
    if @nd_type[last] == "IfNode"
      compile_if_return(last, return_type)
      return
    end
    if @nd_type[last] == "UnlessNode"
      compile_unless_return(last, return_type)
      return
    end
    if @nd_type[last] == "CaseNode"
      compile_case_return(last, return_type)
      return
    end
    if @nd_type[last] == "WhileNode"
      compile_while_stmt(last)
      if return_type != "void"
        emit("  return " + c_return_default(return_type) + ";")
      end
      return
    end
    if @nd_type[last] == "ForNode"
      compile_for_stmt(last)
      if return_type != "void"
        emit("  return " + c_return_default(return_type) + ";")
      end
      return
    end
    if @nd_type[last] == "YieldNode"
      compile_yield_stmt(last)
      if return_type != "void"
        emit("  return " + c_return_default(return_type) + ";")
      end
      return
    end
    if @nd_type[last] == "BeginNode"
      rc_id = @nd_rescue_clause[last]
      ec_id = @nd_ensure_clause[last]
      has_rescue_local = 0
      if rc_id >= 0
        has_rescue_local = 1
      end
      has_retry_local = 0
      if has_rescue_local == 1 && body_has_retry(@nd_body[rc_id]) == 1
        has_retry_local = 1
      end
      if has_rescue_local == 0 || has_retry_local == 1 || ec_id >= 0
        # No rescue / has retry / has ensure: fall back to legacy stmt-form.
        # compile_begin_stmt's 2-setjmp ensure pattern correctly replays the
        # ensure body on both the explicit-return path and the propagation
        # path; the return-value-capture form below uses a single setjmp and
        # would skip ensure on explicit returns out of the rescue body.
        compile_begin_stmt(last)
        if return_type != "void"
          emit("  return " + c_return_default(return_type) + ";")
        end
        return
      end
      # Method-level begin/rescue with return-value capture: bind the
      # last expression of the begin body and of each rescue body into
      # a return slot, then return the slot after the optional ensure.
      @needs_setjmp = 1
      ret_tmp = new_temp
      if return_type != "void"
        emit("  " + c_type(return_type) + " " + ret_tmp + " = " + c_default_val(return_type) + ";")
      end
      emit("  sp_exc_top++;")
      emit("  if (setjmp(sp_exc_stack[sp_exc_top-1]) == 0) {")
      @indent = @indent + 1
 # Method-level begin..rescue..else: when else is present, the
 # begin body's value is discarded -- Ruby semantics says the
 # else body's last expression becomes the method's return.
 # Run begin body as a void-shaped block, then else body with
 # ret_tmp capture.
      else_id_bri = @nd_else_clause[last]
      if else_id_bri >= 0
        compile_stmts_body(@nd_body[last])
        else_body_bri = @nd_body[else_id_bri]
        if else_body_bri >= 0
          compile_body_into(else_body_bri, ret_tmp, return_type)
        end
      else
        compile_body_into(@nd_body[last], ret_tmp, return_type)
      end
      emit("  sp_exc_top--;")
      @indent = @indent - 1
      emit("  } else {")
      @indent = @indent + 1
      emit("  sp_exc_top--;")
      compile_rescue_chain_into(rc_id, ret_tmp, return_type)
      @indent = @indent - 1
      emit("  }")
      if ec_id >= 0
        compile_stmts_body(@nd_body[ec_id])
      end
      if return_type != "void"
        emit("  return " + ret_tmp + ";")
      end
      return
    end
    if @nd_type[last] == "CaseMatchNode"
      compile_case_match_return(last, return_type)
      return
    end
 # If last statement is a CallNode with a block, handle map/select as expressions
    if @nd_type[last] == "CallNode"
      if @nd_block[last] >= 0
        lmname = @nd_name[last]
        if lmname == "map"
          if return_type != "void"
            val = compile_map_expr(last)
            emit("  return " + val + ";")
            return
          end
        end
        if lmname == "select"
          if return_type != "void"
            val = compile_select_expr(last)
            emit("  return " + val + ";")
            return
          end
        end
        if lmname == "sum"
          if return_type != "void"
            rtype_sum = infer_type(@nd_receiver[last])
            rc_sum = compile_expr(@nd_receiver[last])
            val = compile_array_sum_block(last, rc_sum, rtype_sum)
            emit("  return " + val + ";")
            return
          end
        end
        if lmname == "count"
          if return_type != "void"
            rtype_cnt = infer_type(@nd_receiver[last])
            rc_cnt = compile_expr(@nd_receiver[last])
            val = compile_array_count_block(last, rc_cnt, rtype_cnt)
            emit("  return " + val + ";")
            return
          end
        end
        if lmname == "proc"
          if return_type != "void"
            val = compile_proc_literal(last)
            emit("  return " + val + ";")
            return
          end
        end
 # Constructor-with-block: `Array.new(n) { ... }`,
 # `Hash.new { ... }`, etc. compile_expr already builds the
 # collection into a temp and returns its name; the catch-all
 # below would fall through to `compile_stmt + return default`,
 # discard the temp, and return NULL — which segfaults on the
 # next call site that reads from the result. Route through
 # compile_expr so the temp name is the function's return value.
        if lmname == "new"
          if return_type != "void"
            val = compile_expr(last)
            emit("  return " + val + ";")
            return
          end
        end
        compile_stmt(last)
        if return_type != "void"
          emit("  return " + c_return_default(return_type) + ";")
        end
        return
      end
    end
 # For statement-like nodes as last expression, compile as stmt then return default
    lt = @nd_type[last]
    if lt == "CallNode"
      lm = @nd_name[last]
      if lm == "[]=" || lm == "push" || lm == "pop" || lm == "<<" || lm == "emit" || lm == "emit_raw" || lm == "puts" || lm == "print" || lm == "p" || lm == "printf" || lm == "warn" || lm == "raise" || lm == "exit" || lm == "abort" || lm == "sleep" || lm == "delete" || lm == "clear" || lm == "concat" || lm == "prepend" || lm == "fill" || lm == "insert" || lm == "update" || lm == "merge!" || lm == "store" || lm == "reverse!" || lm == "sort!" || lm == "each" || lm == "times" || lm == "upto" || lm == "downto"
 # The hardcoded list above is meant to catch builtin Array/Hash
 # mutators conventionally called for side-effect. But several of
 # these names (update, clear, concat, delete, each, pop, push, ...)
 # are equally plausible on user classes — and there returning the
 # call's value is the only correct behavior. If the receiver
 # resolves to a user class and that class defines a method with
 # the same name, treat the call as an ordinary expression.
        last_recv = @nd_receiver[last]
        is_user_method = 0
        if last_recv < 0
          if @current_class_idx >= 0
            if cls_find_method_direct(@current_class_idx, lm) >= 0
              is_user_method = 1
            end
          end
        else
          last_rt = base_type(infer_type(last_recv))
          if is_obj_type(last_rt) == 1
            recv_ci = find_class_idx(last_rt[4, last_rt.length - 4])
            if recv_ci >= 0
              if cls_find_method_direct(recv_ci, lm) >= 0
                is_user_method = 1
              end
            end
          end
        end
        if is_user_method == 0
          compile_stmt(last)
          if return_type != "void"
            emit("  return " + c_return_default(return_type) + ";")
          end
          return
        end
      end
 # Receiver-based setter calls (obj.attr = val)
      if lm.end_with?("=") && lm != "==" && lm != "!=" && lm != "<=" && lm != ">="
        compile_stmt(last)
        if return_type != "void"
          emit("  return " + c_return_default(return_type) + ";")
        end
        return
      end
    end
    if lt == "InstanceVariableWriteNode"
      compile_stmt(last)
      if return_type != "void"
        emit("  return " + c_return_default(return_type) + ";")
      end
      return
    end
    if lt == "InstanceVariableOperatorWriteNode"
      compile_stmt(last)
      if return_type != "void"
        emit("  return " + c_return_default(return_type) + ";")
      end
      return
    end
    if lt == "ClassVariableWriteNode" || lt == "ClassVariableOperatorWriteNode" || lt == "ClassVariableOrWriteNode" || lt == "ClassVariableAndWriteNode"
      compile_stmt(last)
      if return_type != "void"
        qname_cv = cvar_qname(@current_class_idx, @nd_name[last])
        cv_slot_t = "int"
        ci_cv = find_cvar_idx(qname_cv)
        if ci_cv >= 0
          cv_slot_t = @cvar_types[ci_cv]
        end
        emit("  return " + maybe_bigint_coerce("cvar_" + qname_cv, cv_slot_t, return_type) + ";")
      end
      return
    end
    if lt == "GlobalVariableWriteNode"
      compile_stmt(last)
      if return_type != "void"
        gname_cv = @nd_name[last]
        gv_slot_t = "int"
        gi_cv = 0
        while gi_cv < @gvar_names.length
          if @gvar_names[gi_cv] == gname_cv
            gv_slot_t = @gvar_types[gi_cv]
            gi_cv = @gvar_names.length
          else
            gi_cv = gi_cv + 1
          end
        end
        emit("  return " + maybe_bigint_coerce(sanitize_gvar(gname_cv), gv_slot_t, return_type) + ";")
      end
      return
    end
    if lt == "LocalVariableWriteNode"
      compile_stmt(last)
      if return_type != "void"
        lv_slot_t = find_var_type(@nd_name[last])
        emit("  return " + maybe_bigint_coerce("lv_" + @nd_name[last], lv_slot_t, return_type) + ";")
      end
      return
    end
    if lt == "LocalVariableOperatorWriteNode"
      compile_stmt(last)
      if return_type != "void"
        lv_slot_t = find_var_type(@nd_name[last])
        emit("  return " + maybe_bigint_coerce("lv_" + @nd_name[last], lv_slot_t, return_type) + ";")
      end
      return
    end
    if lt == "MultiWriteNode"
      compile_stmt(last)
      if return_type != "void"
        emit("  return " + c_return_default(return_type) + ";")
      end
      return
    end
    if lt == "IndexOrWriteNode" || lt == "IndexAndWriteNode" || lt == "IndexOperatorWriteNode"
 # `h[k] ||= v` returns the resulting value (existing-or-rhs).
 # Lower as a statement, then re-read `h[k]` for the return —
 # one extra hash lookup per call site, but the alternative would
 # need to thread a temp through compile_index_or_assign's
 # branches. Acceptable for the use case (single-cache lookup
 # paths like optcarrot's @peeks/@pokes dedup, called at init).
      compile_stmt(last)
      if return_type != "void"
        recv_iow = @nd_receiver[last]
        args_iow = @nd_arguments[last]
        if recv_iow >= 0 && args_iow >= 0
          rt_iow = infer_type(recv_iow)
          rc_iow = compile_expr(recv_iow)
          a_iow = get_args(args_iow)[0]
          if rt_iow == "poly_poly_hash"
            ret = "sp_PolyPolyHash_get(" + rc_iow + ", " + box_expr_to_poly(a_iow) + ")"
            if return_type == "poly"
              emit("  return " + ret + ";")
            else
 # caller expects unboxed; the cache use case only flows
 # poly back, but keep a sane default.
              emit("  return " + c_return_default(return_type) + ";")
            end
            return
          end
        end
        emit("  return " + c_return_default(return_type) + ";")
      end
      return
    end
    if return_type != "void"
      if return_type == "poly"
        ret_expr = box_expr_to_poly(last)
        if @in_gc_scope == 1
          tmp = new_temp
          emit("  sp_RbVal " + tmp + " = " + ret_expr + ";")
          emit("  SP_GC_RESTORE();")
          emit("  return " + tmp + ";")
        else
          emit("  return " + ret_expr + ";")
        end
        return
      end
      val = compile_expr(last)
      expr_type = infer_type(last)
 # Peek arith/bitop operands to upgrade a stale "int" expr_type
 # into bigint when the actual emit produces bigint — mirrors
 # the other call sites (compile_bigint_arg, compile_operator
 # _expr, LV op-write). The unified `expr_emit_is_bigint` walker
 # covers arith, bitop, unary `~` / `-@`, parens, and user
 # method calls whose return slot was promoted.
      if expr_type != "bigint" && expr_emit_is_bigint(last) == 1
        expr_type = "bigint"
      end
      if expr_type != "bigint" && @nd_type[last] == "CallNode"
        ml_ret = @nd_name[last]
        if ml_ret == "+" || ml_ret == "-" || ml_ret == "*" || ml_ret == "/" || ml_ret == "%" || ml_ret == "**"
          ml_recv = @nd_receiver[last]
          if ml_recv >= 0 && base_type(infer_type(ml_recv)) == "bigint"
            expr_type = "bigint"
          else
            ml_args = @nd_arguments[last]
            if ml_args >= 0
              ma_ret = get_args(ml_args)
              if ma_ret.length > 0 && base_type(infer_type(ma_ret[0])) == "bigint"
                expr_type = "bigint"
              end
            end
          end
        end
 # Generic poly.method: when every user class defining `mname`
 # returns bigint, the dispatcher result is bigint. Walk the
 # whole class set instead of relying on the narrow-set ivar
 # heuristic (which requires the recv to be an ivar read).
        if expr_type != "bigint"
          ml_recv2 = @nd_receiver[last]
          if ml_recv2 >= 0 && infer_type(ml_recv2) == "poly"
            all_bigint_pm = 0
            any_defines_pm = 0
            cic_pm = 0
            while cic_pm < @cls_names.length
              if cls_find_method(cic_pm, ml_ret) >= 0
                if any_defines_pm == 0
                  all_bigint_pm = 1
                end
                any_defines_pm = 1
                rt_pm = cls_method_return(cic_pm, ml_ret)
                if base_type(rt_pm) != "bigint"
                  all_bigint_pm = 0
                  cic_pm = @cls_names.length
                end
              end
              cic_pm = cic_pm + 1
            end
            if any_defines_pm == 1 && all_bigint_pm == 1
              expr_type = "bigint"
            end
          end
        end
      end
      if expr_type == "lambda"
        if return_type == "int"
          emit("  return sp_lam_to_int(" + val + ");")
        else
          if return_type == "bool"
            emit("  return (" + val + ")->u.bval;")
          else
            emit("  return " + val + ";")
          end
        end
      elsif expr_type == "poly" && base_type(return_type) == "bigint"
 # poly bitop helpers / dispatchers can return sp_RbVal with
 # SP_TAG_INT into a bigint-promoted return slot. Unbox + rebox.
        @needs_rb_value = 1
        @needs_bigint = 1
        emit("  return sp_bigint_new_int((" + val + ").v.i);")
      elsif expr_type == "poly" && (base_type(return_type) == "string" || base_type(return_type) == "mutable_str")
 # Issue #655: RBS-declared `-> String` return where body
 # produces a poly value (e.g. `@hash[k] || ""` where @hash's
 # value type defaulted to Int because no writes were
 # observed). Unbox the poly through `.v.s` so the
 # const-char-*-typed return signature matches.
        @needs_rb_value = 1
        emit("  return (" + val + ").v.s;")
      elsif expr_type == "mutable_str" && base_type(return_type) == "string"
 # Body builds an sp_String * via `<<` chain (the `io = ""; io
 # << "..."; io;` idiom) but the function's declared return
 # type is `const char *`. Read the underlying buffer via
 # `->data` so the return value matches the sig.
        emit("  return (" + val + ")->data;")
      elsif is_hash_type(expr_type) == 1 && is_hash_type(base_type(return_type)) == 1 && expr_type != base_type(return_type)
 # Body builds a wider hash variant (e.g. str_poly_hash from
 # `result["k"] = nullable_str` where the slot widens to poly)
 # but the RBS-declared return is a narrower variant
 # (`Hash[String, String]` -> sp_StrStrHash *). The user-level
 # `if !@x.nil?` guard ensures only non-nil values reach the
 # hash, so the wider variant's runtime contents satisfy the
 # narrower variant's element type. Convert at the boundary.
        conv_ret = hash_variant_convert(expr_type, base_type(return_type), val)
        if conv_ret != ""
          emit("  return " + conv_ret + ";")
        else
          emit("  return (" + c_type(return_type) + ")(" + val + ");")
        end
      elsif (expr_type == "int" || expr_type == "nil") && is_nullable_pointer_type(return_type) == 1 && fetch_with_nil_default?(last) == 1
 # Issue #671: `hash.fetch(k, nil)` against an int-leaf hash
 # (typically empty `@slots = {}`) returns int but the
 # surrounding method's RBS-pinned return type is a nullable
 # pointer (`String?`). The int hash can't carry pointer
 # values, so the only RBS-consistent outcome is NULL. Limit to
 # the actual return site (not every assignment site) so an
 # int-typed LV using the same fetch doesn't get the pointer
 # NULL emit -- the #674 regression.
        emit("  return NULL;")
      else
 # `--int-overflow=promote` promotes int slots (incl. return
 # type) to bigint at analyze time, so a literal/int-typed
 # fall-through last expression must be wrapped before return.
 # The reverse direction covers callers that still want mrb_int.
 # When the body raises (sets @needs_setjmp) the LV slot may be
 # declared `volatile T *`; the non-volatile return signature
 # rejects without an explicit cast. cast_away_volatile_arg
 # detects this shape and emits the `(T *)` strip.
        emit("  return " + maybe_bigint_coerce(cast_away_volatile_arg(last, val), expr_type, return_type) + ";")
      end
    else
      compile_stmt(last)
    end
    return
  end

 # Shared lowering for if- and unless-modifier-as-last-expr.
 # `is_unless == 1` inverts the predicate and reads
 # @nd_else_clause; the if path also threads elsif chains
 # (subsequent IfNode) through a wrapping `else { ... }` to keep
 # poly-is_a? predicate prologues from leaking declarations.
  def compile_cond_return(nid, rt, is_unless)
    cond = compile_cond_expr(@nd_predicate[nid])
    if is_unless == 1
      cond = "!(" + cond + ")"
    end
    emit("  if (" + cond + ") {")
    @indent = @indent + 1
 # Mirror compile_if_stmt's is_a? narrow push so the then-arm of
 # a tail-position `if x.is_a?(C) ... end` sees `x` as the
 # narrowed type. Without this, a poly-typed `x` flowing into a
 # typed callee (sp_re_escape, sp_re_match_p's string arg,
 # `%s` interpolation, ...) inside the body emits the raw
 # sp_RbVal and trips a C compile -- the canonical #612 shape.
 # The narrow is popped after the body so the else / fall-through
 # emit sees the un-narrowed type.
    isa_info_cr = is_unless == 0 ? parse_is_a_predicate(@nd_predicate[nid]) : ["", ""]
    isa_pushed_cr = 0
    if isa_info_cr[0] != ""
      push_type_narrow(isa_info_cr[0], isa_info_cr[1])
      isa_pushed_cr = 1
    end
    body = @nd_body[nid]
    if body >= 0
      compile_body_return(body, rt)
    else
      if rt != "void"
        emit("  return " + c_return_default(rt) + ";")
      end
    end
    if isa_pushed_cr == 1
      pop_type_narrow
    end
    @indent = @indent - 1
    if is_unless == 1
      sub = @nd_else_clause[nid]
    else
      sub = @nd_subsequent[nid]
    end
    if sub >= 0
      if is_unless == 0 && @nd_type[sub] != "ElseNode"
        emit("  } else {")
        @indent = @indent + 1
        compile_cond_return(sub, rt, 0)
        @indent = @indent - 1
        emit("  }")
        return
      end
      emit("  } else {")
      @indent = @indent + 1
      eb = @nd_body[sub]
      if eb >= 0
        compile_body_return(eb, rt)
      else
        if rt != "void"
          emit("  return " + c_return_default(rt) + ";")
        end
      end
      @indent = @indent - 1
    else
      if rt != "void"
        emit("  } else {")
        emit("    return " + c_return_default(rt) + ";")
      end
    end
    emit("  }")
  end

  def compile_if_return(nid, rt)
    compile_cond_return(nid, rt, 0)
  end

  def compile_unless_return(nid, rt)
    compile_cond_return(nid, rt, 1)
  end

  def compile_case_match_return(nid, rt)
    pred = @nd_predicate[nid]
    pred_type = infer_type(pred)
    pred_val = compile_expr(pred)
    tmp = new_temp
    if pred_type == "poly"
      emit("  sp_RbVal " + tmp + " = " + pred_val + ";")
    else
      if pred_type == "string"
        emit("  const char *" + tmp + " = " + pred_val + ";")
      else
        if pred_type == "float"
          emit("  mrb_float " + tmp + " = " + pred_val + ";")
        elsif pred_type == "bigint"
          @needs_bigint = 1
          emit("  mrb_int " + tmp + " = sp_bigint_to_int((sp_Bigint *)" + pred_val + ");")
          pred_type = "int"
        else
          emit("  mrb_int " + tmp + " = " + pred_val + ";")
        end
      end
    end
    conds = parse_id_list(@nd_conditions[nid])
    k = 0
    while k < conds.length
      inid = conds[k]
      if @nd_type[inid] == "InNode"
        kw = "if"
        if k > 0
          kw = "} else if"
        end
        pat = @nd_pattern[inid]
        cond_str = compile_in_pattern(pat, tmp, pred_type)
        emit("  " + kw + " (" + cond_str + ") {")
        @indent = @indent + 1
        compile_body_return(@nd_body[inid], rt)
        @indent = @indent - 1
      end
      k = k + 1
    end
    ec = @nd_else_clause[nid]
    if ec >= 0
      emit("  } else {")
      @indent = @indent + 1
      compile_body_return(@nd_body[ec], rt)
      @indent = @indent - 1
    end
    if conds.length > 0
      emit("  }")
    end
  end

  def compile_case_return(nid, rt)
    pred = @nd_predicate[nid]
    if pred >= 0
      pred_type = infer_type(pred)
      pred_val = compile_expr(pred)
      tmp = new_temp
      if pred_type == "string"
        emit("  const char *" + tmp + " = " + pred_val + ";")
      elsif pred_type == "poly"
 # `case <poly> when ...` -- mirror compile_case_stmt's
 # poly arm. .
        emit("  sp_RbVal " + tmp + " = " + pred_val + ";")
      elsif is_obj_type(pred_type) == 1
        bt_cr = base_type(pred_type)
        cn_cr = bt_cr[4, bt_cr.length - 4]
        emit("  sp_" + cn_cr + " *" + tmp + " = " + pred_val + ";")
      elsif pred_type == "bigint"
        @needs_bigint = 1
        emit("  mrb_int " + tmp + " = sp_bigint_to_int((sp_Bigint *)" + pred_val + ");")
        pred_type = "int"
      else
        emit("  mrb_int " + tmp + " = " + pred_val + ";")
      end
      conds = parse_id_list(@nd_conditions[nid])
      k = 0
      while k < conds.length
        wid = conds[k]
        if @nd_type[wid] == "WhenNode"
          kw = "if"
          if k > 0
            kw = "} else if"
          end
          cond_str = compile_when_conds(wid, tmp, pred_type)
          emit("  " + kw + " (" + cond_str + ") {")
          @indent = @indent + 1
          compile_body_return(@nd_body[wid], rt)
          @indent = @indent - 1
        end
        k = k + 1
      end
    else
      conds = parse_id_list(@nd_conditions[nid])
      k = 0
      while k < conds.length
        wid = conds[k]
        kw = "if"
        if k > 0
          kw = "} else if"
        end
        wconds = parse_id_list(@nd_conditions[wid])
        cexpr = "0"
        if wconds.length > 0
          cexpr = compile_expr(wconds.first)
        end
        emit("  " + kw + " (" + cexpr + ") {")
        @indent = @indent + 1
        compile_body_return(@nd_body[wid], rt)
        @indent = @indent - 1
        k = k + 1
      end
    end
    ec = @nd_else_clause[nid]
    if ec >= 0
      emit("  } else {")
      @indent = @indent + 1
      compile_body_return(@nd_body[ec], rt)
      @indent = @indent - 1
    end
    emit("  }")
  end

 # ============================================================
 # Analysis IR: serializer and loader
 # ============================================================
 #
 # The IR captures everything `analyze_phase` populates so that a
 # codegen-only step can pick up where analysis stopped without
 # re-running the whole-program inference fixpoint. The format is
 # line-oriented:
 #
 # SPINEL-IR v1
 # <tag> <name> <encoded payload>
 #
 # Tags:
 # INT <ivar> <integer> scalar int ivar
 # SA <ivar> <pipe-joined> Array<String> (each element percent-encoded)
 # IA <ivar> <comma-joined> Array<Int>
 # T <node_id> <type> per-AST-node inferred type cache
 #
 # All string payloads are percent-encoded for space/newline/tab/
 # percent/pipe so the line-and-pipe split is unambiguous. The MVP
 # dumps the analysis-bearing instance variables directly. A
 # follow-up should replace this with entity records (M / C / CONST
 # / FFI_FUNC / …) — those are the real interface — but for now this
 # gets the bootstrap pipeline running end to end.


 # Issue #771: return -1 for non-hex chars so ir_unescape can detect
 # a malformed `%XX` and pass the bytes through verbatim instead of
 # silently injecting a NUL byte into the decoded type string.
  def ir_hex_digit(c)
    if c == "0" then return 0 end
    if c == "1" then return 1 end
    if c == "2" then return 2 end
    if c == "3" then return 3 end
    if c == "4" then return 4 end
    if c == "5" then return 5 end
    if c == "6" then return 6 end
    if c == "7" then return 7 end
    if c == "8" then return 8 end
    if c == "9" then return 9 end
    if c == "A" then return 10 end
    if c == "B" then return 11 end
    if c == "C" then return 12 end
    if c == "D" then return 13 end
    if c == "E" then return 14 end
    if c == "F" then return 15 end
    if c == "a" then return 10 end
    if c == "b" then return 11 end
    if c == "c" then return 12 end
    if c == "d" then return 13 end
    if c == "e" then return 14 end
    if c == "f" then return 15 end
    -1
  end

  def ir_unescape(s)
    result = ""
    i = 0
    n = s.length
    while i < n
      ch = s[i]
      if ch == "%" && i + 2 < n
        d1 = ir_hex_digit(s[i + 1])
        d2 = ir_hex_digit(s[i + 2])
        if d1 >= 0 && d2 >= 0
          v = d1 * 16 + d2
          result = result + v.chr
          i = i + 3
        else
 # Malformed escape -- pass `%` through verbatim, advance one
 # char, and let the next iteration handle the following byte.
          result = result + ch
          i = i + 1
        end
      else
        result = result + ch
        i = i + 1
      end
    end
    result
  end



 # The ir_emit_* helpers return the appended-to buffer rather than
 # mutating in place. spinel's type inference doesn't (yet) handle
 # passing an sp_String* through a method-parameter slot the body
 # then `<<`-mutates — the param ends up typed `const char*` at the
 # callsite, which fails at the cc step. Returning a new string and
 # rebinding `buf = ir_emit_*(buf, …)` keeps every value typed as
 # `const char*` through the pipeline.




 # Restore the analysis state from a buffer produced by
 # dump_analysis_buf. Caller is responsible for having read the
 # parsed AST first (read_text_ast) so the @nd_inferred_type cache
 # has slots to populate.
  def load_analysis_buf(data)
    lines = data.split(10.chr)
    i = 0
    while i < lines.length
      line = lines[i]
      if line != "" && line != "SPINEL-IR v1"
        ir_load_record(line)
      end
      i = i + 1
    end
  end

  def ir_load_record(line)
    sp1 = line.index(" ")
    if sp1 == nil
      return
    end
    tag = line[0, sp1]
    if tag == "T"
      rest = line[sp1 + 1, line.length - sp1 - 1]
      sp2 = rest.index(" ")
      if sp2 == nil
        return
      end
      nid = rest[0, sp2].to_i
      type_str = ir_unescape(rest[sp2 + 1, rest.length - sp2 - 1])
      if nid >= 0 && nid < @nd_count
        @nd_inferred_type[nid] = type_str
      end
      return
    end
    if tag == "NM"
 # Per-node @nd_name override (rewrite_instance_eval_calls output).
      rest = line[sp1 + 1, line.length - sp1 - 1]
      sp2 = rest.index(" ")
      if sp2 == nil
        return
      end
      nid = rest[0, sp2].to_i
      new_name = ir_unescape(rest[sp2 + 1, rest.length - sp2 - 1])
      if nid >= 0 && nid < @nd_count
        @nd_name[nid] = new_name
      end
      return
    end
    if tag == "NB"
 # Per-node @nd_block override (rewrite_instance_eval_calls clears
 # the block on rewritten call sites).
      rest = line[sp1 + 1, line.length - sp1 - 1]
      sp2 = rest.index(" ")
      if sp2 == nil
        return
      end
      nid = rest[0, sp2].to_i
      new_block = rest[sp2 + 1, rest.length - sp2 - 1].to_i
      if nid >= 0 && nid < @nd_count
        @nd_block[nid] = new_block
      end
      return
    end
    if tag == "SN"
 # Per-scope local-decl names (pipe-joined). analyze precomputes
 # scan_locals + multi-pass refinement results so codegen can
 # declare locals without re-running the whole scope-setup tree.
      rest = line[sp1 + 1, line.length - sp1 - 1]
      sp2 = rest.index(" ")
      if sp2 == nil
        return
      end
      nid = rest[0, sp2].to_i
      val = ir_unescape(rest[sp2 + 1, rest.length - sp2 - 1])
      if nid >= 0 && nid < @nd_count
        @nd_scope_names[nid] = val
      end
      return
    end
    if tag == "ST"
 # Per-scope local-decl types (pipe-joined). Paired with SN.
      rest = line[sp1 + 1, line.length - sp1 - 1]
      sp2 = rest.index(" ")
      if sp2 == nil
        return
      end
      nid = rest[0, sp2].to_i
      val = ir_unescape(rest[sp2 + 1, rest.length - sp2 - 1])
      if nid >= 0 && nid < @nd_count
        @nd_scope_types[nid] = val
      end
      return
    end
    rest = line[sp1 + 1, line.length - sp1 - 1]
    sp2 = rest.index(" ")
    name = rest
    payload = ""
    if sp2 != nil
      name = rest[0, sp2]
      payload = rest[sp2 + 1, rest.length - sp2 - 1]
    end
    if tag == "INT"
      ir_set_int_ivar(name, payload.to_i)
    elsif tag == "STR"
      ir_set_str_ivar(name, ir_unescape(payload))
    elsif tag == "SA"
 # Payload is "<length> <pipe-joined>". Split off the count so
 # we can distinguish [] from [""] (both serialize to the same
 # pipe-joined form).
      sp3 = payload.index(" ")
      n_str = payload
      body = ""
      if sp3 != nil
        n_str = payload[0, sp3]
        body = payload[sp3 + 1, payload.length - sp3 - 1]
      end
      n = n_str.to_i
      ir_set_sa_ivar(name, ir_split_strs_n(body, n))
    elsif tag == "IA"
      sp3 = payload.index(" ")
      n_str = payload
      body = ""
      if sp3 != nil
        n_str = payload[0, sp3]
        body = payload[sp3 + 1, payload.length - sp3 - 1]
      end
      n = n_str.to_i
      ir_set_ia_ivar(name, ir_split_ints_n(body, n))
    end
  end

 # Length-prefixed split: returns exactly `n` elements. Distinguishes
 # `[]` (n==0) from `[""]` (n==1, body=="") so empty string elements
 # round-trip correctly.
  def ir_split_strs_n(s, n)
    result = "".split(",", -1)
    if n == 0
      return result
    end
    parts = s.split("|", -1)
    i = 0
    while i < parts.length
      result.push(ir_unescape(parts[i]))
      i = i + 1
    end
 # `"".split("|", -1)` returns [], so a single empty element appears
 # as length 0. Pad up to the recorded count with empty strings.
    while result.length < n
      result.push("")
    end
    result
  end

  def ir_split_ints_n(s, n)
    result = []
    if n == 0
      return result
    end
    parts = s.split(",", -1)
    i = 0
    while i < parts.length
      result.push(parts[i].to_i)
      i = i + 1
    end
    while result.length < n
      result.push(0)
    end
    result
  end

